enum FundOperationKind: Equatable {
    case deposit
    case withdraw

    var referenceImageName: String {
        switch self {
        case .deposit:
            return "DepositReference"
        case .withdraw:
            return "WithdrawReference"
        }
    }

    var enabledReferenceImageName: String {
        switch self {
        case .deposit:
            return "DepositReferenceEnabled"
        case .withdraw:
            return "WithdrawReferenceEnabled"
        }
    }

    var cashierSceneCode: String {
        switch self {
        case .deposit:
            return "DEPOSIT"
        case .withdraw:
            return "WITHDRAW"
        }
    }
    }

enum FundOperationPresentation: Equatable {
