private let aiCashSingleTransferInBillTitle = "爱存-单次转入"

private func normalizedAssetChangeSceneCode(_ raw: String) -> String {
    raw.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
}

private func isAiCashTransferInSceneCode(_ sceneCode: String) -> Bool {
    let normalized = normalizedAssetChangeSceneCode(sceneCode)
    return normalized.contains("FUND_SUBSCRIBE")
        || normalized.contains("AICASH_TRANSFER_IN")
        || normalized.contains("AICASH_TRANSFER_IN")
}

private func isAiCashTransferInChange(_ change: AssetChangeItemData) -> Bool {
    isAiCashTransferInSceneCode(change.businessSceneCode)
}

