    private var homeCitySelectionMode: HomeCitySelectionMode {
        get {
            HomeCitySelectionMode(rawValue: savedHomeCitySelectionModeRawValue) ?? .auto
        }
        nonmutating set {
            savedHomeCitySelectionModeRawValue = newValue.rawValue
        }
    }

    private var currentHomeCityText: String {
        let normalized = normalizedHomeDisplayCityName(savedHomeSelectedCityName)
        return normalized.isEmpty ? Self.homeDefaultCityName : normalized
    }

    private var shouldShowTopStatusMaskOverlay: Bool {
        switch currentPage {
        case .cashier,
             .homeSearch,
             .video,
             .loanAccountHome,
             .creditHome,
             .creditBillDetail,
             .repayCashier,
             .repaySuccess,
             .mobileHallCashier,
             .balanceChangeDetail,
             .bill,
             .transferHistory,
             .totalAsset,
             .aiCash,
             .personalInfo,
             .nicknameEditor,
             .avatarEditor,
             .avatarCropEditor,
             .certificate,
             .myCard,
             .bankCards,
             .settingsCopyright,
             .redPacketCashier,
             .redPacketShareChat,
             .redPacketShareSendDialog:
            return false
        default:
            return true
        }
    }

    private var isRefreshingAiCashSnapshot: Bool {
        activeAiCashSnapshotRefreshCount > 0
    }

    private var homeCitySections: [HomeCitySection] {
        let grouped = Dictionary(grouping: Self.homeAllCityOptions, by: Self.homeCityIndexTitle(for:))
        return Self.homeCityIndexTitles.compactMap { title in
            guard let rawCities = grouped[title], !rawCities.isEmpty else {
                return nil
            }
            let cities = rawCities.sorted(by: Self.homeCitySort)
            return HomeCitySection(id: "home_city_section_\(title)", title: title, cities: cities)
        }
    }

    private static func homeCitySort(_ lhs: String, _ rhs: String) -> Bool {
        let lhsKey = homeCitySortKey(lhs)
        let rhsKey = homeCitySortKey(rhs)
        if lhsKey == rhsKey {
            return lhs < rhs
        }
        return lhsKey < rhsKey
    }

    private static func homeCityIndexTitle(for city: String) -> String {
        let key = homeCitySortKey(city)
        guard let letter = key.first(where: { $0.isLetter }) else {
            return "#"
        }
        return String(letter)
    }

    private static func homeCitySortKey(_ city: String) -> String {
        let mutable = NSMutableString(string: city) as CFMutableString
        CFStringTransform(mutable, nil, kCFStringTransformToLatin, false)
        CFStringTransform(mutable, nil, kCFStringTransformStripCombiningMarks, false)
        return (mutable as String)
            .uppercased()
            .replacingOccurrences(of: " ", with: "")
    }

    @MainActor
    private func ensureHomeCityResolvedIfNeeded(force: Bool = false) {
        if !Self.homeLocationAutoCheckEnabled && !force {
            return
        }
        let authorizationStatus = homeCityLocationService.authorizationStatus
        if authorizationStatus == .notDetermined {
            homeCityLocationService.requestCurrentCity(force: true)
            return
        }
        if force {
            homeCitySelectionMode = .auto
        }
        guard homeCitySelectionMode == .auto else {
            return
        }
        syncAutoHomeCityFallbackIfNeeded(for: authorizationStatus)
        homeCityLocationService.requestCurrentCity(force: force)
    }

    @MainActor
    private func refreshHomeCityOnAppActivation() {
        guard Self.homeLocationAutoCheckEnabled else {
            return
        }
        guard currentPage == .home else {
            return
        }

        if homeCitySelectionMode != .auto {
            homeCitySelectionMode = .auto
        }

        let authorizationStatus = homeCityLocationService.refreshAuthorizationStatus()
        switch authorizationStatus {
        case .authorizedWhenInUse, .authorizedAlways:
            let fallbackCityName = normalizedHomeDisplayCityName(Self.homeDefaultCityName)
            let savedCityName = normalizedHomeDisplayCityName(savedHomeSelectedCityName)
            let resolvedCityName = normalizedHomeDisplayCityName(homeCityLocationService.resolvedCityName)
            if savedCityName == fallbackCityName || resolvedCityName.isEmpty || savedCityName != resolvedCityName {
                homeCityLocationService.requestCurrentCity(force: true)
            }
        case .restricted, .denied:
            syncAutoHomeCityFallbackIfNeeded(for: authorizationStatus)
        case .notDetermined:
            homeCityLocationService.requestCurrentCity(force: true)
        @unknown default:
            break
        }
    }

    private func applyManualHomeCity(_ cityName: String) {
        let normalized = normalizedHomeDisplayCityName(cityName)
        guard !normalized.isEmpty else {
            return
        }
        savedHomeSelectedCityName = normalized
        homeCitySelectionMode = .manual
        isHomeCitySelectorPresented = false
    }

    private func syncResolvedHomeCity(_ cityName: String) {
        let normalized = normalizedHomeDisplayCityName(cityName)
        guard homeCitySelectionMode == .auto, !normalized.isEmpty else {
            return
        }
        savedHomeSelectedCityName = normalized
    }

    private func syncAutoHomeCityFallbackIfNeeded(for authorizationStatus: CLAuthorizationStatus) {
        guard homeCitySelectionMode == .auto else {
            return
        }
        guard authorizationStatus == .denied || authorizationStatus == .restricted else {
            return
        }
        let fallbackCityName = normalizedHomeDisplayCityName(Self.homeDefaultCityName)
        guard !fallbackCityName.isEmpty else {
            return
        }
        if normalizedHomeDisplayCityName(savedHomeSelectedCityName) != fallbackCityName {
            savedHomeSelectedCityName = fallbackCityName
        }
    }

