    private func openTransferFlow(from page: Page) {
        transferEntryPage = page
        currentPage = .transferList
    }

    @MainActor
    private func openTransferFromConversation(_ conversation: MessageConversationItem) async {
        transferEntryPage = .conversationDetail
        transferDraftAmountText = ""
        transferDraftRemark = ""
        confirmedTransferAmount = .zero
        confirmedTransferRemark = ""
        confirmedTransferPaymentMethodText = "账户余额"

        await loadRecentContactsIfNeeded()

        if let matchedContact = recentContacts.first(where: { $0.payeeUserId == conversation.peerUserId }) {
            selectedTransferContact = matchedContact
        } else {
            selectedTransferContact = TransferRecentContact(conversation: conversation)
        }
        currentPage = .transferDetail
    }

    @MainActor
    private func openContactDetail(from conversation: MessageConversationItem) async {
        contactDetailBackPage = .conversationDetail

        await loadRedPacketFriendContactsIfNeeded()
        let resolvedContact = redPacketFriendContacts.first(where: { $0.payeeUserId == conversation.peerUserId })
            ?? recentContacts.first(where: { $0.payeeUserId == conversation.peerUserId })
            ?? TransferRecentContact(conversation: conversation)

        selectedContactDetailContext = ContactDetailContext(
            contact: resolvedContact,
            conversation: conversation
        )
        currentPage = .contactDetail
    }

    @MainActor
    private func openContactDetail(from contact: TransferRecentContact, backPage: Page) {
        contactDetailBackPage = backPage
        let matchedConversation = messageConversations.first(where: {
            !$0.isMock && $0.peerUserId == contact.payeeUserId
        }) ?? messageConversations.first(where: {
            $0.peerUserId == contact.payeeUserId
        })

        selectedContactDetailContext = ContactDetailContext(
            contact: contact,
            conversation: matchedConversation
        )
        currentPage = .contactDetail
    }

    private func resolveConversationForContact(
        _ contact: TransferRecentContact,
        preferred: MessageConversationItem?
    ) -> MessageConversationItem? {
        if let preferred, preferred.peerUserId == contact.payeeUserId {
            return preferred
        }
        if let matchedRealConversation = messageConversations.first(where: {
            !$0.isMock && $0.peerUserId == contact.payeeUserId
        }) {
            return matchedRealConversation
        }
        return messageConversations.first(where: {
            $0.peerUserId == contact.payeeUserId
        })
    }

    @MainActor
    private func openConversationFromContactDetail(_ context: ContactDetailContext) {
        let contact = context.contact
        let resolvedConversation: MessageConversationItem
        if let existingConversation = resolveConversationForContact(contact, preferred: context.conversation) {
            resolvedConversation = existingConversation
        } else {
            let transientConversation = MessageConversationItem(contact: contact)
            resolvedConversation = transientConversation
        }

        if !messageConversations.contains(where: {
            $0.conversationNo == resolvedConversation.conversationNo && $0.peerUserId == resolvedConversation.peerUserId
        }) {
            messageConversations.insert(resolvedConversation, at: 0)
        }

        selectedContactDetailContext = ContactDetailContext(
            contact: contact,
            conversation: resolvedConversation
        )
        selectedMessageConversation = resolvedConversation
        conversationBackPage = .contactDetail
        currentPage = .conversationDetail
    }

    @MainActor
    private func cleanupTransientConversationIfNeeded(_ conversation: MessageConversationItem) {
        guard conversation.isTransient else {
            return
        }
        messageConversations.removeAll(where: {
            $0.isTransient
                && $0.conversationNo == conversation.conversationNo
                && $0.peerUserId == conversation.peerUserId
        })

        if selectedMessageConversation?.conversationNo == conversation.conversationNo,
           selectedMessageConversation?.peerUserId == conversation.peerUserId {
            selectedMessageConversation = nil
        }

        if let context = selectedContactDetailContext,
           context.contact.payeeUserId == conversation.peerUserId {
            let refreshedConversation = resolveConversationForContact(context.contact, preferred: nil)
            selectedContactDetailContext = ContactDetailContext(
                contact: context.contact,
                conversation: refreshedConversation
            )
        }
    }

    @MainActor
    private func handleConversationTransferSucceeded(_ message: MessageData) async {
        await loadMessageConversationsIfNeeded(force: true)

        if let refreshedConversation = messageConversations.first(where: { $0.conversationNo == message.conversationNo }) {
            selectedMessageConversation = refreshedConversation
        }

        transferDraftAmountText = ""
        transferDraftRemark = ""
        confirmedTransferAmount = .zero
        confirmedTransferRemark = ""
        currentPage = .conversationDetail
    }

    @MainActor
    private func submitConversationTransferMessage(
        _ request: CashierTransferSubmitRequest,
        contact: TransferRecentContact
    ) async throws -> MessageData {
        let extPayload = conversationTransferExtPayload(contact: contact, remark: request.remark)
        return try await APIClient.shared.sendTransferMessage(
            senderUserId: request.payerUserId,
            receiverUserId: request.payeeUserId,
            amount: request.amount,
            paymentMethod: request.paymentMethod,
            paymentToolCode: request.paymentToolCode,
            remark: request.remark,
            extPayload: extPayload
        )
    }

    private func conversationTransferExtPayload(contact: TransferRecentContact, remark: String) -> String? {
        var payload: [String: Any] = [
            "source": "ios-conversation-transfer",
            "cardStyle": "chat-transfer-v1",
            "recipientDisplayName": contact.displayName
        ]
        let maskedName = preferredConversationTransferMaskedName(for: contact)
        if !maskedName.isEmpty {
            payload["recipientMaskedName"] = maskedName
        }
        let normalizedRemark = remark.trimmingCharacters(in: .whitespacesAndNewlines)
        if !normalizedRemark.isEmpty {
            payload["remark"] = normalizedRemark
        }
        guard let data = try? JSONSerialization.data(withJSONObject: payload) else {
            return nil
        }
        return String(data: data, encoding: .utf8)
    }

    private func preferredConversationTransferMaskedName(for contact: TransferRecentContact) -> String {
        let maskedRealName = contact.maskedRealName?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if !maskedRealName.isEmpty {
            return maskedRealName
        }
        let trimmedDisplayName = contact.displayName.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmedDisplayName.isEmpty else {
            return ""
        }
        guard let lastCharacter = trimmedDisplayName.last else {
            return ""
        }
        let maskCount = max(2, trimmedDisplayName.count - 1)
        return String(repeating: "*", count: maskCount) + String(lastCharacter)
    }

    @MainActor
    private func openTransferFromAiPayPersonalCode(targetUserId: Int64) async -> String? {
        guard let currentUserId = currentUserTransferUserId, currentUserId > 0 else {
            return "未找到当前登录用户"
        }
        guard targetUserId > 0 else {
            return "个人二维码无效"
        }
        guard targetUserId != currentUserId else {
            return "不能给自己转账"
        }

        do {
            let profile = try await APIClient.shared.fetchUserProfile(userId: targetUserId)
            let contact = TransferRecentContact(profile: profile)
            selectedTransferContact = contact
            if !recentContacts.contains(where: { $0.payeeUserId == contact.payeeUserId }) {
                recentContacts.insert(contact, at: 0)
            }
            transferDraftAmountText = ""
            transferDraftRemark = ""
            transferEntryPage = .scan
            currentPage = .transferDetail
            return nil
        } catch {
            if isCancellationLikeError(error) {
                return "操作已取消"
            }
            return userFacingErrorMessage(error)
        }
    }

    @MainActor
    private func applyFriendRequestFromAiPayPersonalCode(targetUserId: Int64) async -> String {
        guard let requesterUserId = currentUserTransferUserId, requesterUserId > 0 else {
            return "未找到当前登录用户"
        }
        guard targetUserId > 0 else {
            return "个人二维码无效"
        }
        guard targetUserId != requesterUserId else {
            return "不能添加自己为好友"
        }

        let applyMessage = "我是\(currentUserProfileName)，想加你为好友"
        do {
            try await APIClient.shared.applyFriendRequest(
                requesterUserId: requesterUserId,
                targetUserId: targetUserId,
                applyMessage: applyMessage
            )
            return "好友申请已发送"
        } catch {
            if isCancellationLikeError(error) {
                return "操作已取消"
            }
            return userFacingErrorMessage(error)
        }
    }

    private func openMobileHallCashier(amount: Decimal) {
        guard normalizedMainlandMobileLoginId(mobileHallPhoneDigits) != nil else {
            showNotice("请输入正确的手机号")
            isMobileHallPhoneFocused = true
            return
        }
        mobileHallSelectedRechargeAmount = amount
        confirmedMobileHallRechargeAmount = amount
        confirmedMobileHallPaymentMethodText = "爱花"
        confirmedMobileHallCouponDiscountAmount = .zero
        mobileHallTopUpResultState = .succeeded
        mobileHallTopUpProcessingStartedAt = nil
        currentPage = .mobileHallCashier
        Task { @MainActor in
            await refreshMobileTopUpRewardCouponsIfNeeded()
        }
    }

    private func beginMobileHallTopUpProcessing(
        amount: Decimal,
        paymentMethodText: String,
        couponDiscountAmount: Decimal = .zero
    ) {
        confirmedMobileHallRechargeAmount = amount
        confirmedMobileHallPaymentMethodText = paymentMethodText
        confirmedMobileHallCouponDiscountAmount = max(couponDiscountAmount, .zero)
        mobileHallTopUpResultState = .processing
        mobileHallTopUpProcessingStartedAt = Date()
        currentPage = .mobileHallTopUpSuccess
    }

    private func finishMobileHallTopUp(
        amount: Decimal,
        paymentMethodText: String,
        resultState: DepositResultState,
        couponDiscountAmount: Decimal = .zero
    ) {
        confirmedMobileHallRechargeAmount = amount
        confirmedMobileHallPaymentMethodText = paymentMethodText
        confirmedMobileHallCouponDiscountAmount = max(couponDiscountAmount, .zero)

        switch resultState {
        case .processing:
            beginMobileHallTopUpProcessing(
                amount: amount,
                paymentMethodText: paymentMethodText,
                couponDiscountAmount: couponDiscountAmount
            )
        case .succeeded:
            let processingStartedAt = mobileHallTopUpProcessingStartedAt ?? Date()
            Task { @MainActor in
                let minimumProcessingDuration: TimeInterval = 2.0
                let elapsed = Date().timeIntervalSince(processingStartedAt)
                let remaining = max(0, minimumProcessingDuration - elapsed)
                if remaining > 0 {
                    try? await Task.sleep(nanoseconds: UInt64((remaining * 1_000_000_000).rounded()))
                }
                mobileHallTopUpResultState = .succeeded
                mobileHallTopUpProcessingStartedAt = nil
            }
        case .failed:
            mobileHallTopUpResultState = resultState
            mobileHallTopUpProcessingStartedAt = nil
        }
    }

