    private static func initialLaunchPage() -> Page {
        let arguments = ProcessInfo.processInfo.arguments
        guard let flagIndex = arguments.firstIndex(of: "-OpenAiPayStartPage"),
              arguments.indices.contains(flagIndex + 1) else {
            return .home
        }
        let debugName = arguments[flagIndex + 1]
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased()
        return Page(debugName: debugName) ?? .home
    }

    private static var isDebugStartPageLaunch: Bool {
        ProcessInfo.processInfo.arguments.contains("-OpenAiPayStartPage")
    }

    private static func initialLaunchesCreditBillOverview() -> Bool {
        let arguments = ProcessInfo.processInfo.arguments
        guard let flagIndex = arguments.firstIndex(of: "-OpenAiPayStartPage"),
              arguments.indices.contains(flagIndex + 1) else {
            return false
        }
        let debugName = arguments[flagIndex + 1]
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased()
        return [
            "creditbilloverview",
            "credit-bill-overview",
            "credit_bill_overview",
            "aicredit-bill-overview",
            "aicredit_bill_overview",
            "aicredit-bill-overview"
        ].contains(debugName)
    }

