    private var currentUserProfile: UserProfile? {
        appState.session?.user
    }

    private var currentUserProfileName: String {
        if let nickname = normalizedProfileText(currentUserProfile?.nickname) {
            return nickname
        }
        if let maskedRealName = normalizedProfileText(currentUserProfile?.maskedRealName) {
            return maskedRealName
        }
        if let loginId = normalizedProfileText(currentUserProfile?.loginId) {
            return loginId
        }
        if let aipayUid = normalizedProfileText(currentUserProfile?.aipayUid) {
            return aipayUid
        }
        return "爱付用户"
    }

    private var currentUserReceiveDisplayName: String {
        let nickname = normalizedProfileText(currentUserProfile?.nickname)
        let maskedRealName = normalizedProfileText(currentUserProfile?.maskedRealName)

        if let nickname, !nickname.isEmpty {
            if let maskedRealName, !maskedRealName.isEmpty {
                let normalizedMaskedName = maskedRealName.replacingOccurrences(of: "*", with: "")
                if !normalizedMaskedName.isEmpty, nickname != maskedRealName, nickname != normalizedMaskedName {
                    return "\(nickname)(\(maskedRealName))"
                }
            }
            return nickname
        }
        if let maskedRealName, !maskedRealName.isEmpty {
            return maskedRealName
        }
        return currentUserProfileName
    }

    private var currentUserProfileMobile: String {
        let candidates = [
            currentUserProfile?.mobile,
            currentUserProfile?.loginId
        ]
        for candidate in candidates {
            if let fullMobile = normalizedMainlandMobileLoginId(candidate) {
                return fullMobile
            }
        }
        for candidate in candidates {
            if let masked = maskedMobileText(from: candidate) {
                return masked
            }
        }
        return "未绑定手机号"
    }

    private var currentUserProfileAvatarUrl: String? {
        normalizedProfileText(currentUserProfile?.avatarUrl)
    }

    private var isCurrentUserGuJun: Bool {
        if normalizedProfileText(currentUserProfile?.nickname) == "顾郡" {
            return true
        }
        return false
    }

    private var isCurrentUserQiXin: Bool {
        if normalizedProfileText(currentUserProfile?.nickname) == "祁欣" {
            return true
        }
        return false
    }

    private var currentUserForcedAvatarAssetName: String? {
        // Never infer a user's current avatar from nickname or mobile number.
        return nil
    }

    private var currentUserProfileAvatarAssetName: String? {
        demoAvatarAssetName(for: currentUserProfileAvatarUrl)
    }

    private var currentUserAvatarCacheTaskKey: String {
        let userIdPart = currentUserTransferUserId.map(String.init) ?? "0"
        let avatarUrlPart = currentUserProfileAvatarUrl ?? ""
        return userIdPart + "|" + avatarUrlPart
    }

    private var shouldUsePersistedCurrentUserAvatarImage: Bool {
        guard currentUserTransferUserId != nil else {
            return false
        }
        return currentUserForcedAvatarAssetName == nil && currentUserProfileAvatarAssetName == nil
    }

    private var currentUserProfileAvatarText: String {
        let trimmed = currentUserProfileName.trimmingCharacters(in: .whitespacesAndNewlines)
        if let first = trimmed.first {
            return String(first)
        }
        return "我"
    }

    private var currentUserProfileIdentityBadgeText: String? {
        if normalizedProfileText(currentUserProfile?.maskedRealName) != nil {
            return "已实名"
        }
        if let kycLevel = normalizedProfileText(currentUserProfile?.kycLevel),
           ["L1", "L2", "L3"].contains(kycLevel.uppercased()) {
            return "已认证"
        }
        return nil
    }

    private var currentUserPersonalInfoAccountText: String {
        let candidates = [
            normalizedProfileText(currentUserProfile?.loginId),
            normalizedProfileText(currentUserProfile?.mobile),
            normalizedProfileText(currentUserProfile?.aipayUid)
        ]
        for candidate in candidates {
            if let masked = maskedPersonalInfoAccount(candidate) {
