                requesterDigests: messageRequesterDigests,
                isLoading: isLoadingMessageReceivedFriendRequests,
                loadErrorMessage: messageReceivedFriendRequestLoadError,
                handlingRequestNo: handlingMessageFriendRequestNo,
                onBack: {
                    currentPage = messageFriendRequestsBackPage
                },
                onRefresh: {
                    await loadMessageReceivedFriendRequests(force: true)
                },
                onEnsureRequesterLoaded: { requesterUserId in
                    await loadMessageRequesterDigestIfNeeded(requesterUserId: requesterUserId)
                },
                onHandleRequest: { request, action in
                    await handleMessageFriendRequest(request: request, action: action)
                }
            )
        case .bankCards:
            BankCardsPageView(
                tools: bankCardsPageTools,
                isLoading: isLoadingBankCardsPageTools,
                errorMessage: bankCardsPageToolsErrorMessage,
                resolvedCardNumber: { tool in
                    resolvedBankCardNumber(for: tool)
                },
                onDeleteCard: { tool in
                    deleteBankCard(tool)
                },
                onEnsureLoaded: {
                    await loadBankCardsPageToolsIfNeeded()
                },
                onBack: {
                    currentPage = bankCardsBackPage
                },
                onAddCard: {
                    currentPage = .bankCardAdd
                },
                onRefresh: {
                    await loadBankCardsPageToolsIfNeeded(force: true)
                }
            )
        case .bankCardAdd:
            BankCardAddPageView(
                onBack: {
                    currentPage = .bankCards
                },
                onSubmit: { submission in
                    addBankCard(submission)
                }
            )
        case .settings:
            settingsPageView()
        case .settingsGeneral:
            self.settingsGeneralLanguageOnlyView()
        case .settingsLanguage:
            self.settingsLanguageView()
        case .settingsAbout:
            self.settingsAboutView()
        case .settingsCopyright:
            self.settingsCopyrightView()
        case .mobileHallCashier:
            ZStack {
                referenceModeView()
                    .allowsHitTesting(false)

                MobileHallCashierView(
                    userId: currentUserTransferUserId,
                    amount: mobileHallSelectedRechargeAmount,
                    topUpMobile: normalizedMainlandMobileLoginId(mobileHallPhoneDigits),
                    availableCoupons: mobileHallTopUpRewardCoupons,
                    selectedCouponNo: mobileHallTopUpRewardCoupon?.couponNo,
                    onSelectCoupon: { selectedCouponNo in
                        let normalized = selectedCouponNo?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                        guard !normalized.isEmpty else {
                            mobileHallTopUpRewardCoupon = nil
                            return
                        }
                        mobileHallTopUpRewardCoupon = mobileHallTopUpRewardCoupons.first(where: { $0.couponNo == normalized })
                    },
                    onBack: {
                        currentPage = .mobileHall
                    },
                    onCouponConsumed: { consumedCouponNo in
                        let normalized = consumedCouponNo.trimmingCharacters(in: .whitespacesAndNewlines)
                        guard !normalized.isEmpty else {
                            return
                        }
                        mobileHallTopUpRewardCoupons.removeAll(where: { $0.couponNo == normalized })
                        if mobileHallTopUpRewardCoupon?.couponNo == normalized {
                            mobileHallTopUpRewardCoupon = mobileHallTopUpRewardCoupons.first
                        }
                    },
                    onPaySubmitting: { amount, paymentMethodText, couponDiscountAmount in
                        beginMobileHallTopUpProcessing(
                            amount: amount,
                            paymentMethodText: paymentMethodText,
                            couponDiscountAmount: couponDiscountAmount
                        )
                    },
                    onPaySucceeded: { amount, paymentMethodText, couponDiscountAmount, _ in
                        balanceDataRefreshNonce += 1
                        finishMobileHallTopUp(
                            amount: amount,
                            paymentMethodText: paymentMethodText,
                            resultState: .succeeded,
                            couponDiscountAmount: couponDiscountAmount
                        )
                    },
                    onPayFailed: { amount, paymentMethodText, message in
                        finishMobileHallTopUp(
                            amount: amount,
                            paymentMethodText: paymentMethodText,
                            resultState: .failed(message)
                        )
                    }
                )
            }
        case .mobileHallTopUpSuccess:
            MobileHallTopUpSuccessView(
                rechargeAmount: confirmedMobileHallRechargeAmount,
                paymentMethodText: confirmedMobileHallPaymentMethodText,
                couponDiscountAmount: confirmedMobileHallCouponDiscountAmount,
                resultState: mobileHallTopUpResultState,
                onBackHome: {
                    currentPage = .home
                },
                onDone: {
                    currentPage = .mobileHall
                }
            )
        case .productSuggestion:
            ProductSuggestionView(
                userId: currentUserTransferUserId,
                onBack: {
                    currentPage = productSuggestionBackPage
                }
            )
        case .scan:
            ScanPageView(
                currentUserId: currentUserTransferUserId,
                onBack: {
                    currentPage = scanEntryPage
                },
                onOpenPayCode: {
                    payCodeEntryPage = .scan
                    currentPage = .payCode
