                onOpenAiPayPersonalTransfer: { userId in
                    await openTransferFromAiPayPersonalCode(targetUserId: userId)
                },
                onApplyAiPayFriendRequest: { userId in
                    await applyFriendRequestFromAiPayPersonalCode(targetUserId: userId)
                }
