                    onConversationChanged: {
                        Task { @MainActor in
                            let targetPeerUserId = selectedMessageConversation.peerUserId
                            await self.loadMessageConversationsIfNeeded(force: true)
                            if let refreshedConversation = self.messageConversations.first(where: {
                                !$0.isMock && $0.peerUserId == targetPeerUserId
                            }) {
                                self.selectedMessageConversation = refreshedConversation
                            }
                        }
                    },
                    onBack: { shouldCleanupTransientConversation in
                        if shouldCleanupTransientConversation {
                            self.cleanupTransientConversationIfNeeded(selectedMessageConversation)
                        }
                        let selectedConversationNo = self.selectedMessageConversation?.conversationNo
                        currentPage = conversationBackPage
                        Task { @MainActor in
                            await self.loadMessageConversationsIfNeeded(force: true)
                            if let selectedConversationNo,
                               let refreshedConversation = self.messageConversations.first(where: {
                                   $0.conversationNo == selectedConversationNo
                               }) {
                                self.selectedMessageConversation = refreshedConversation
                            }
                        }
                    },
                    onOpenContactDetail: {
                        Task { @MainActor in
