                    confirmedWithdrawResultAmounts = WithdrawResultAmounts(
                        feeAmount: max(feeAmount ?? confirmedWithdrawResultAmounts.feeAmount, .zero),
                        settleAmount: max(settleAmount ?? confirmedWithdrawResultAmounts.settleAmount, .zero)
                    )
                    withdrawResultState = .succeeded
                },
                onDepositFailed: { message in
                    withdrawResultState = .failed(message)
                }
            )
        case .withdrawSuccess:
            DepositSuccessView(
                presentation: .withdraw,
                depositAmount: confirmedWithdrawAmount,
                paymentMethodText: confirmedWithdrawMethodText,
                feeAmount: confirmedWithdrawResultAmounts.feeAmount,
                actualArrivedAmount: confirmedWithdrawResultAmounts.settleAmount,
                resultState: withdrawResultState,
                onBackHome: {
                    currentPage = .home
                },
                onDone: {
                    switch withdrawResultState {
                    case .failed:
                        currentPage = .withdraw
                    case .processing, .succeeded:
                        if withdrawReturnPage == .balance {
                            balanceDataRefreshNonce += 1
                        }
                        currentPage = withdrawReturnPage
                    }
                }
            )
        case .aiCashWithdraw:
            DepositView(
                presentation: .aiCashTransferOut,
                userId: currentUserTransferUserId,
                withdrawAvailableBalanceOverride: aiCashSnapshot.backingHoldingAmount,
                onBack: {
                    currentPage = aiCashWithdrawBackPage
                },
                onDepositSubmitting: { amount, methodText, _, _ in
                    confirmedAiCashWithdrawAmount = amount
                    confirmedAiCashWithdrawMethodText = methodText
                    aiCashWithdrawResultState = .processing
                    currentPage = .aiCashWithdrawSuccess
                },
                onDepositSucceeded: { _, _ in
                    applyAiCashWithdrawLocally(amount: confirmedAiCashWithdrawAmount, destinationDisplayText: confirmedAiCashWithdrawMethodText)
                    aiCashWithdrawResultState = .succeeded
                },
                onDepositFailed: { message in
                    aiCashWithdrawResultState = .failed(message)
                }
            )
        case .aiCashWithdrawSuccess:
            DepositSuccessView(
                presentation: .aiCashTransferOut,
                depositAmount: confirmedAiCashWithdrawAmount,
                paymentMethodText: confirmedAiCashWithdrawMethodText,
                feeAmount: nil,
                actualArrivedAmount: nil,
                resultState: aiCashWithdrawResultState,
                onBackHome: {
                    currentPage = .home
                },
                onDone: {
                    switch aiCashWithdrawResultState {
                    case .failed:
                        currentPage = .aiCashWithdraw
                    case .processing, .succeeded:
                        currentPage = .aiCash
                    }
                }
            )
        case .transferList:
            transferListPageView()
        case .transferDetail:
            if let selectedTransferContact {
                TransferDetailView(
                    contact: selectedTransferContact,
                    amountText: $transferDraftAmountText,
                    remarkText: $transferDraftRemark,
                    onBack: {
                        currentPage = transferReturnPage
                    },
                    onOpenHistory: {
                        transferHistoryBackPage = .transferDetail
                        currentPage = .transferHistory
                    },
                    onTransfer: { amount, remark in
                        confirmedTransferAmount = amount
                        let normalizedDraftRemark = transferDraftRemark
                            .trimmingCharacters(in: .whitespacesAndNewlines)
                        let normalizedConfirmRemark = (remark ?? "")
                            .trimmingCharacters(in: .whitespacesAndNewlines)
                        confirmedTransferRemark = normalizedConfirmRemark.isEmpty
                            ? normalizedDraftRemark
                            : normalizedConfirmRemark
                        confirmedTransferPaymentMethodText = "账户余额"
                        currentPage = .cashier
                    }
                )
            } else {
                transferListPageView()
            }
        case .transferHistory:
            TransferHistoryView(
                userId: currentUserTransferUserId,
                syntheticChanges: transferHistorySyntheticChanges,
                onBack: {
                    currentPage = transferHistoryBackPage
                }
            )
        case .cashier:
            if let selectedTransferContact {
                ZStack {
                    TransferDetailView(
                        contact: selectedTransferContact,
                        amountText: .constant(transferDraftAmountText),
                        remarkText: .constant(transferDraftRemark),
                        onBack: {},
                        onOpenHistory: nil,
                        onTransfer: { _, _ in },
                        autoFocusAmount: false
                    )
                    .allowsHitTesting(false)

                    CashierView(
                        contact: selectedTransferContact,
                        payerUserId: currentUserTransferUserId,
                        payerDisplayName: appState.session?.user.nickname ?? "当前账户",
                        transferAmount: confirmedTransferAmount,
                        transferRemark: confirmedTransferRemark.isEmpty
                            ? transferDraftRemark
                            : confirmedTransferRemark,
                        submitTransferAction: transferEntryPage == .conversationDetail ? { request in
                            try await self.submitConversationTransferMessage(request, contact: selectedTransferContact)
                        } : nil,
                        onBack: {
                            currentPage = .transferDetail
                        },
                        onPaySucceeded: { paymentMethodText, sentMessage in
                            confirmedTransferPaymentMethodText = paymentMethodText
                            appendLocalTransferHistoryChangeIfNeeded(
                                amount: confirmedTransferAmount,
                                contact: selectedTransferContact
                            )
                            if transferEntryPage == .conversationDetail, let sentMessage {
                                Task { @MainActor in
                                    await self.handleConversationTransferSucceeded(sentMessage)
                                }
                            } else {
                                currentPage = .transferSuccess
                            }
                        }
                    )
                }
            } else {
                transferListPageView()
            }
        case .transferSuccess:
            if let selectedTransferContact {
                TransferSuccessView(
                    contact: selectedTransferContact,
                    transferAmount: confirmedTransferAmount,
                    transferRemark: confirmedTransferRemark,
                    paymentMethodText: confirmedTransferPaymentMethodText,
                    onBackHome: {
                        currentPage = .home
                    },
                    onDone: {
                        currentPage = transferSuccessDonePage
                    }
                )
            } else {
                transferListPageView()
            }
        }
    }

