    }

    private func openHomeSearch() {
        homeSearchHistory = HomeSearchHistoryStore.load(userId: currentUserTransferUserId)
        homeSearchKeyword = ""
        homeSearchSections = []
        isLoadingHomeSearch = false
        homeSearchLoadError = nil
        homeSearchActiveKeyword = ""
        currentPage = .homeSearch
    }

    private func homeSearchPageView() -> some View {
        HomeSearchPageView(
            keyword: $homeSearchKeyword,
            historyKeywords: homeSearchHistory,
            sections: homeSearchSections,
            isLoading: isLoadingHomeSearch,
            loadErrorMessage: homeSearchLoadError,
            onBack: {
                currentPage = .home
            },
            onCommitKeyword: { keyword in
                saveHomeSearchHistoryKeyword(keyword)
            },
            onDeleteHistoryKeyword: { keyword in
                deleteHomeSearchHistoryKeyword(keyword)
            },
            onSearch: { keyword in
                await performHomeSearch(keyword: keyword)
            },
            onSelectResult: { item in
                await handleHomeSearchSelection(item)
            }
        )
    }

    @MainActor
    private func performHomeSearch(keyword: String) async {
        let normalizedKeyword = keyword.trimmingCharacters(in: .whitespacesAndNewlines)
        homeSearchActiveKeyword = normalizedKeyword

        guard !normalizedKeyword.isEmpty else {
            isLoadingHomeSearch = false
            homeSearchLoadError = nil
            homeSearchSections = []
            return
        }

        guard let userId = currentUserTransferUserId, userId > 0 else {
            isLoadingHomeSearch = false
            homeSearchSections = []
            homeSearchLoadError = "未找到当前登录用户"
            return
        }

        // 历史记录与搜索命中解耦：只要触发有效搜索就写入历史（即使结果为空）。
        saveHomeSearchHistoryKeyword(normalizedKeyword)

        isLoadingHomeSearch = true
        homeSearchLoadError = nil
        do {
            let response = try await APIClient.shared.fetchSearchResults(
                userId: userId,
                keyword: normalizedKeyword,
                limit: 10
            )
            guard homeSearchActiveKeyword == normalizedKeyword else {
                return
            }
            homeSearchSections = response.sections.filter { !$0.items.isEmpty }
            homeSearchLoadError = nil
            isLoadingHomeSearch = false
        } catch {
            guard !Task.isCancelled, !isCancellationLikeError(error) else {
                return
            }
            guard homeSearchActiveKeyword == normalizedKeyword else {
                return
            }
            homeSearchSections = []
            homeSearchLoadError = userFacingErrorMessage(error)
            isLoadingHomeSearch = false
        }
    }

    @MainActor
    private func handleHomeSearchSelection(_ item: SearchResultItemData) async {
        homeSearchLoadError = nil

        if item.isContactResult {
            await openHomeSearchConversation(item)
            return
        }

        if let route = item.route {
            openHomeSearchFeature(route: route)
        } else {
            homeSearchLoadError = "搜索结果路由缺失，请稍后重试"
        }
    }

    @MainActor
    private func openHomeSearchConversation(_ item: SearchResultItemData) async {
        guard let peerUserId = item.resolvedUserId, peerUserId > 0 else {
            homeSearchLoadError = "联系人数据异常，请稍后重试"
            return
        }

        await loadMessageConversationsIfNeeded(force: true)

        if let existingConversation = messageConversations.first(where: { !$0.isMock && $0.peerUserId == peerUserId }) {
            selectedMessageConversation = existingConversation
        } else {
            selectedMessageConversation = MessageConversationItem(searchResult: item)
        }
        conversationBackPage = .homeSearch
        currentPage = .conversationDetail
    }

    @MainActor
    private func openHomeSearchFeature(route: SearchRouteData) {
        let normalizedPage = route.page?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !normalizedPage.isEmpty else {
            homeSearchLoadError = "功能路由缺失，请稍后重试"
            return
        }

        switch normalizedPage.lowercased() {
        case "transferlist", "transfer-list", "transfer_list":
            openTransferFlow(from: .homeSearch)
        case "redpacket", "red-packet", "hongbao":
            redPacketEntryPage = .homeSearch
            redPacketSelectedRecipient = nil
            redPacketAmountText = ""
            redPacketBlessingText = ""
            redPacketSelectedCover = RedPacketCoverOption.defaultOption
            currentPage = .redPacket
        case "aicash":
            openAiCashEntry(from: .homeSearch, entryFromProfile: false)
        case "aicashdeposit", "aicash-deposit", "aicash_deposit":
            aiCashDepositBackPage = .homeSearch
            currentPage = .aiCashDeposit
        case "aicashwithdraw", "aicash-withdraw", "aicash_withdraw":
            aiCashWithdrawBackPage = .homeSearch
            currentPage = .aiCashWithdraw
        default:
            guard let page = Page(debugName: normalizedPage) else {
                homeSearchLoadError = "暂不支持打开该功能，请稍后重试"
                return
            }
            switch page {
            case .bankCards:
                bankCardsBackPage = .homeSearch
            case .messageContacts:
                messageContactsBackPage = .homeSearch
            case .redPacketHistory:
                redPacketEntryPage = .homeSearch
            case .settings, .settingsGeneral, .settingsLanguage, .settingsAbout, .settingsCopyright:
                settingsBackPage = .homeSearch
            case .productSuggestion:
                productSuggestionBackPage = .homeSearch
            case .personalInfo:
                personalInfoBackPage = .homeSearch
            case .myCard:
                myCardBackPage = .homeSearch
            case .totalAsset:
                totalAssetBackPage = .homeSearch
            case .balance:
                balanceBackPage = .homeSearch
            case .balanceChangeDetail:
                balanceChangeDetailBackPage = .homeSearch
            case .bill:
                billBackPage = .homeSearch
            case .creditHome:
                creditHomeBackPage = .homeSearch
                openCreditHome(from: .homeSearch)
                return
            case .creditRepay:
                creditRepayEntrySource = .creditHome
                creditRepayBillMode = .current
                creditRepayBackPageOverride = .homeSearch
                shouldReturnToCreditBillOverviewAfterRepay = false
                creditRepayPrefilledAmount = nil
                creditRepayLayoutMode = .repayForm
                repayResultState = .succeeded
            case .transferHistory:
                transferHistoryBackPage = .homeSearch
            case .scan:
                scanEntryPage = .homeSearch
            case .payCode:
                payCodeEntryPage = .homeSearch
            case .receiveHome:
                receiveEntryPage = .homeSearch
            default:
                break
            }
            currentPage = page
        }
    }

    private func openCreditHome(from backPage: Page) {
        creditHomeBackPage = backPage
        creditHomeEntryNonce += 1
        currentPage = .creditHome
    }

    private func openAiCashEntry(from backPage: Page, entryFromProfile: Bool) {
        aiCashEntryFromProfile = entryFromProfile
        aiCashBackPage = backPage
        aiCashEntryRoutingTask?.cancel()
        aiCashEntryRoutingTask = Task { @MainActor in
            defer { aiCashEntryRoutingTask = nil }
            await routeAiCashEntryDestination()
        }
    }

    @MainActor
    private func routeAiCashEntryDestination() async {
        guard let userId = currentUserTransferUserId, userId > 0 else {
            aiCashSnapshot = .empty()
            hasLoadedAiCashSnapshotFromBackend = false
            aiCashOpenFlagState = .unknown
            aiCashOpenFlagStateUserId = nil
            currentPage = .aiCashOpen
            return
        }

        // 首次进入首页时已预取开通标识；若用户在预取完成前点击，则这里兜底再查一次，避免先进入爱存页再跳开通页。
        if aiCashOpenFlagStateUserId != userId || aiCashOpenFlagState == .unknown {
            await prefetchAiCashOpenFlagIfNeeded(force: true)
        }

        if aiCashOpenFlagStateUserId == userId, aiCashOpenFlagState == .unopened {
            aiCashSnapshot = .empty()
            hasLoadedAiCashSnapshotFromBackend = false
            currentPage = .aiCashOpen
            return
        }

        // 先用本地快照秒开页面，再由页面 task 后台刷新远端数据，避免点击后等待网络再跳转。
        if let persistedSnapshot = AiCashAccountSnapshot.resolvedFromPersistedState(userId: userId) {
            aiCashSnapshot = persistedSnapshot
            hasLoadedAiCashSnapshotFromBackend = true
        } else if !hasLoadedAiCashSnapshotFromBackend {
            aiCashSnapshot = .empty()
        }
        currentPage = .aiCash
    }

    @MainActor
    private func prefetchAiCashOpenFlagIfNeeded(force: Bool = false) async {
        guard let userId = currentUserTransferUserId, userId > 0 else {
            aiCashOpenFlagState = .unknown
            aiCashOpenFlagStateUserId = nil
            return
        }

        if !force,
           aiCashOpenFlagStateUserId == userId,
           aiCashOpenFlagState != .unknown {
            return
        }

        await refreshAiCashSnapshot()
    }

    @MainActor
    private func openAiCashAccountFromOpenPage() async {
        guard !isOpeningAiCashAccount else {
            return
        }
        guard let userId = currentUserTransferUserId, userId > 0 else {
            showNotice("未找到当前登录用户")
            return
        }

        isOpeningAiCashAccount = true
        defer {
            isOpeningAiCashAccount = false
        }
        aiCashOpenResultState = .processing
        showAiCashOpenSuccessAlert = false

        do {
            try await APIClient.shared.createFundAccount(
                userId: userId,
                fundCode: "AICASH",
                currencyCode: "CNY"
            )
            await refreshAiCashSnapshot()
            aiCashOpenResultState = .succeeded
            showAiCashOpenSuccessAlert = true
        } catch {
            guard !isCancellationLikeError(error) else {
                return
            }
            if isFundAccountAlreadyExistsError(error) {
                await refreshAiCashSnapshot()
                aiCashOpenResultState = .succeeded
                showAiCashOpenSuccessAlert = true
                return
            }
            let message = userFacingErrorMessage(error)
            aiCashOpenResultState = .failed(message)
            showNotice(message)
        }
    }

    private func isFundAccountNotFoundError(_ error: Error) -> Bool {
        var candidates: [String] = [error.localizedDescription, userFacingErrorMessage(error)]
        if let apiError = error as? APIClientError,
           case let .businessError(message) = apiError {
            candidates.append(message)
        }
        let normalizedCandidates = candidates.map { message in
            message.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        }
        return normalizedCandidates.contains { message in
            message.contains("fund account not found") || message.contains("未找到爱存账户")
        }
    }

    private func isFundAccountAlreadyExistsError(_ error: Error) -> Bool {
        var candidates: [String] = [error.localizedDescription, userFacingErrorMessage(error)]
        if let apiError = error as? APIClientError,
           case let .businessError(message) = apiError {
            candidates.append(message)
        }
        let normalizedCandidates = candidates.map { message in
            message.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        }
        return normalizedCandidates.contains { message in
            message.contains("fund account already exists") || message.contains("爱存账户已存在")
        }
    }

    private func saveHomeSearchHistoryKeyword(_ rawKeyword: String) {
        let normalizedKeyword = rawKeyword.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedKeyword.isEmpty else {
            return
        }

        homeSearchHistory.removeAll { existingKeyword in
            existingKeyword.caseInsensitiveCompare(normalizedKeyword) == .orderedSame
        }
        homeSearchHistory.insert(normalizedKeyword, at: 0)
        if homeSearchHistory.count > 20 {
            homeSearchHistory = Array(homeSearchHistory.prefix(20))
        }

        HomeSearchHistoryStore.save(homeSearchHistory, userId: currentUserTransferUserId)
    }

    private func deleteHomeSearchHistoryKeyword(_ rawKeyword: String) {
        let normalizedKeyword = rawKeyword.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedKeyword.isEmpty else {
            return
        }

        homeSearchHistory.removeAll { existingKeyword in
            existingKeyword.caseInsensitiveCompare(normalizedKeyword) == .orderedSame
        }
        HomeSearchHistoryStore.save(homeSearchHistory, userId: currentUserTransferUserId)
    }

    @MainActor
    private func handleCurrentPageTask() async {
        if currentPage == .home {
            if Self.homeLocationAutoCheckEnabled, homeCitySelectionMode != .auto {
                homeCitySelectionMode = .auto
            }
            ensureHomeCityResolvedIfNeeded(force: Self.homeLocationAutoCheckEnabled)
            await loadHomeDeliverBannerIfNeeded()
            await prefetchRecentContactsIfNeeded()
            await prefetchAiCashOpenFlagIfNeeded()
            prefetchMessageHomeIfNeeded()
        } else if currentPage == .bankCards {
            await loadBankCardsPageToolsIfNeeded()
        } else if currentPage == .transferList {
            async let loadRecentTask: Void = loadRecentContactsIfNeeded()
            async let loadFriendTask: Void = loadTransferFriendContactsIfNeeded()
            _ = await (loadRecentTask, loadFriendTask)
        } else if currentPage == .redPacketSelectRecipient {
            await loadRecentContactsIfNeeded()
            await loadRedPacketFriendContactsIfNeeded()
        } else if currentPage == .redPacketHistory {
            await loadRedPacketHistoryIfNeeded()
        } else if currentPage == .message {
            showMessageQuickMenu = false
            isLoadingMessageHomeBundle = messageConversations.isEmpty
            await loadMessageConversationsIfNeeded()
            isLoadingMessageHomeBundle = false
            Task { @MainActor in
                await loadMessageReceivedFriendRequestCount()
            }
        } else if currentPage == .totalAsset {
            await refreshTotalAssetPageData()
        } else if currentPage == .aiCash || currentPage == .aiCashDeposit || currentPage == .aiCashWithdraw {
            await refreshAiCashSnapshot()
        } else if currentPage == .loanAccountRecord {
            await refreshLoanRecordBillEntriesIfNeeded(force: true)
        }
    }

    var body: some View {
        currentPageBody
        .task(id: currentPage) {
            await handleCurrentPageTask()
        }
        .task(id: currentUserTransferUserId) {
            restoreLastSeenMessageBadgeSignature(for: currentUserTransferUserId)
            if currentUserTransferUserId != nil,
               currentPage != .home,
               !Self.isDebugStartPageLaunch {
                currentPage = .home
            }
            if currentPage == .bankCards {
                await loadBankCardsPageToolsIfNeeded(force: true)
            }
            await prefetchAiCashOpenFlagIfNeeded(force: true)
            if currentPage == .totalAsset {
                await refreshTotalAssetPageData()
            }
            prefetchMessageHomeIfNeeded()
        }
        .task(id: currentUserAvatarCacheTaskKey) {
            await syncCurrentUserAvatarCacheIfNeeded()
        }
        .onReceive(homeDeliverBannerRotationTicker) { now in
            rotateHomeDeliverBannerIfNeeded(now: now)
        }
        .onReceive(messageBadgeRefreshTicker) { _ in
            guard shouldPollMessageBadgeOnCurrentPage else {
                return
            }
            Task { @MainActor in
                prefetchMessageHomeIfNeeded()
            }
        }
        .onReceive(NotificationCenter.default.publisher(for: UIApplication.didBecomeActiveNotification)) { _ in
            Task { @MainActor in
                refreshHomeCityOnAppActivation()
                prefetchMessageHomeIfNeeded()
            }
        }
        .onChange(of: appState.session?.user.userId) { _, newUserId in
            handleCurrentUserChanged(newUserId)
        }
        .onChange(of: normalizedMessageSearchKeyword) { _, newKeyword in
            guard currentPage == .message else {
                return
            }
            let trimmedKeyword = newKeyword.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !trimmedKeyword.isEmpty else {
                return
            }
            Task { @MainActor in
                async let recentTask: Void = loadRecentContactsIfNeeded(showFailureNotice: false)
                async let friendTask: Void = loadTransferFriendContactsIfNeeded()
                _ = await (recentTask, friendTask)
            }
        }
        .onChange(of: currentPage) { _, newPage in
            if newPage != .message {
                showMessageQuickMenu = false
                messageSearchKeyword = ""
                isMessageSearchFieldFocused = false
            } else {
                consumeMessageTabRedDot()
            }
            if newPage != .nicknameEditor {
                isNicknameFieldFocused = false
            }
            if newPage == .mobileHall {
                ensureMobileHallPhoneDigitsSeeded()
                Task {
                    await refreshMobileTopUpRewardCouponsIfNeeded()
                }
            } else {
                isMobileHallPhoneFocused = false
            }
            if newPage == .home {
                if Self.homeLocationAutoCheckEnabled, homeCitySelectionMode != .auto {
                    homeCitySelectionMode = .auto
                }
                ensureHomeCityResolvedIfNeeded(force: Self.homeLocationAutoCheckEnabled)
            }
            if newPage == .bankCards {
                if bankCardsPageTools.isEmpty {
                    bankCardsPageTools = Self.initialBankCardsPageTools(for: .bankCards)
                }
                Task {
                    await loadBankCardsPageToolsIfNeeded()
                }
            }
        }
        .onChange(of: selectedAvatarPhotoItem) { _, newValue in
            guard let newValue else {
                return
            }
            Task {
                await handlePickedAvatarPhoto(item: newValue)
            }
        }
        .photosPicker(isPresented: $showAvatarPhotoPicker, selection: $selectedAvatarPhotoItem, matching: .images)
        .fullScreenCover(isPresented: $showAvatarCameraPicker) {
            CameraCapturePicker(
                onCapture: { image in
                    showAvatarCameraPicker = false
                    handleCapturedAvatarPhoto(image)
                },
                onCancel: {
                    showAvatarCameraPicker = false
                }
            )
            .ignoresSafeArea()
        }
        .alert(
            "当前版本提示",
            isPresented: Binding(
                get: { avatarEditorHintMessage != nil },
                set: { isPresented in
                    if !isPresented {
                        avatarEditorHintMessage = nil
                    }
                }
            )
        ) {
            Button("知道了") {
                avatarEditorHintMessage = nil
            }
        } message: {
            Text(avatarEditorHintMessage ?? "")
        }
        .ignoresSafeArea()
        .overlay(alignment: .top) {
            ZStack(alignment: .top) {
                if shouldShowTopStatusMaskOverlay {
                    ScreenshotStatusMaskView(
                        referenceAssetName: statusMaskReferenceAssetName,
                        maskHeight: currentPage == .conversationDetail ? 68 : 48
                    )
                }

                if let homeNoticeMessage, !homeNoticeMessage.isEmpty {
                    homeNoticeToast(text: homeNoticeMessage)
                        .padding(.top, 88)
                }
            }
        }
        .overlay {
            homeBannerRewardAlertOverlay
        }
        .onChange(of: homeCityLocationService.resolvedCityName) { _, newValue in
            syncResolvedHomeCity(newValue)
        }
        .onChange(of: homeCityLocationService.authorizationStatus) { _, newValue in
            syncAutoHomeCityFallbackIfNeeded(for: newValue)
            guard Self.homeLocationAutoCheckEnabled else {
                return
            }
            guard currentPage == .home, homeCitySelectionMode == .auto else {
                return
            }
            switch newValue {
            case .authorizedWhenInUse, .authorizedAlways:
                ensureHomeCityResolvedIfNeeded(force: true)
            case .restricted, .denied, .notDetermined:
                break
            @unknown default:
                break
            }
        }
    }

    @ViewBuilder
    private var homeBannerRewardAlertOverlay: some View {
        if let lines = resolvedHomeBannerRewardAlertLines() {
            ZStack {
                Color.black.opacity(0.28)
                    .ignoresSafeArea()

                VStack(spacing: 0) {
                    VStack(spacing: 0) {
                        Text(lines.primaryLine)
                            .font(.system(size: 14, weight: .regular))
                            .foregroundStyle(Color.red)
                            .multilineTextAlignment(.center)

                        if let secondaryLine = lines.secondaryLine, !secondaryLine.isEmpty {
                            Color.clear
                                .frame(height: 14)

                            Text(secondaryLine)
                                .font(.system(size: 12, weight: .regular))
                                .foregroundStyle(Color(red: 0.58, green: 0.58, blue: 0.60))
                                .multilineTextAlignment(.center)
                        }
                    }
                    .padding(.horizontal, 20)
                    .padding(.top, 18)
                    .padding(.bottom, 16)

                    Rectangle()
                        .fill(Color(red: 0.90, green: 0.91, blue: 0.92))
                        .frame(height: 1 / UIScreen.main.scale)

                    Button("确认") {
                        homeBannerRewardAlertMessage = nil
                    }
                    .buttonStyle(.plain)
                    .font(.system(size: 17, weight: .regular))
                    .foregroundStyle(Color(red: 0.19, green: 0.56, blue: 0.99))
                    .frame(maxWidth: .infinity)
                    .frame(height: 44)
                }
                .frame(width: 270)
                .background(
                    RoundedRectangle(cornerRadius: 14, style: .continuous)
                        .fill(Color.white)
                )
                .offset(y: -50)
            }
            .transition(.opacity)
        }
    }

    private func resolvedHomeBannerRewardAlertLines() -> (primaryLine: String, secondaryLine: String?)? {
        let raw = homeBannerRewardAlertMessage?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !raw.isEmpty else {
            return nil
        }
        let lines = raw
            .split(separator: "\n", omittingEmptySubsequences: false)
            .map { String($0).trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }

        guard let primaryLine = lines.first else {
            return nil
        }
        if lines.count > 1 {
            return (primaryLine, lines.dropFirst().joined(separator: "\n"))
        }
        return (primaryLine, nil)
    }

