    @MainActor
    private func loadHomeDeliverBannerIfNeeded(force: Bool = false) async {
        if isLoadingHomeDeliverBanner {
            return
        }
        if !force && homeDeliverBanner != nil {
            return
        }
        isLoadingHomeDeliverBanner = true
        homeDeliverBannerLoadError = nil
        do {
            homeDeliverBanner = try await APIClient.shared.fetchHomeDeliverBanner(userId: currentUserTransferUserId)
            resetHomeDeliverBannerRotation()
        } catch {
            homeDeliverBanner = nil
            homeDeliverBannerLoadError = userFacingErrorMessage(error)
            resetHomeDeliverBannerRotation()
        }
        isLoadingHomeDeliverBanner = false
    }

    @MainActor
    private func loadBankCardsPageToolsIfNeeded(force: Bool = false) async {
        guard let userId = currentUserTransferUserId, userId > 0 else {
            bankCardsPageRemoteTools = []
            if bankCardsPageTools.isEmpty {
                bankCardsPageTools = Self.initialBankCardsPageTools(for: .bankCards)
            }
            isLoadingBankCardsPageTools = false
            hasLoadedBankCardsPageTools = false
            bankCardsPageQueryFailed = false
            bankCardsPageToolsErrorMessage = bankCardsPageTools.isEmpty ? "未找到当前登录用户" : nil
            return
        }
        if isLoadingBankCardsPageTools {
            return
        }
        if !force && hasLoadedBankCardsPageTools {
            return
        }

        isLoadingBankCardsPageTools = true
        bankCardsPageToolsErrorMessage = nil
        bankCardsPageQueryFailed = false
        defer {
            isLoadingBankCardsPageTools = false
        }

        do {
            let tools = try await APIClient.shared.fetchCashierPayTools(
                userId: userId,
                sceneCode: "TRANSFER"
            )
            bankCardsPageRemoteTools = CashierPresentationHelper.filteredBankTools(tools, policy: .allCards)
            bankCardsPageTools = resolvedBankCardsPageTools(userId: userId)
            hasLoadedBankCardsPageTools = true
            bankCardsPageQueryFailed = false
            bankCardsPageToolsErrorMessage = bankCardsPageTools.isEmpty ? "暂无银行卡" : nil
        } catch {
            if isCancellationLikeError(error) {
                bankCardsPageTools = resolvedBankCardsPageTools(userId: userId)
                if bankCardsPageTools.isEmpty && !hasLoadedBankCardsPageTools {
                    bankCardsPageQueryFailed = true
                    bankCardsPageToolsErrorMessage = "加载失败，请下拉重试"
                } else {
                    bankCardsPageQueryFailed = false
                }
                return
            }
            bankCardsPageRemoteTools = []
            bankCardsPageTools = resolvedBankCardsPageTools(userId: userId)
            hasLoadedBankCardsPageTools = !bankCardsPageTools.isEmpty
            bankCardsPageQueryFailed = bankCardsPageTools.isEmpty
            bankCardsPageToolsErrorMessage = bankCardsPageTools.isEmpty ? userFacingErrorMessage(error) : nil
        }
    }

    private func resolvedBankCardsPageTools(userId: Int64?) -> [CashierPayToolData] {
        let syntheticTools = BankCardSyntheticStore.loadPayTools(userId: userId)
        let hiddenToolCodes = BankCardSyntheticStore.hiddenToolCodes(userId: userId)
        var resolvedTools: [CashierPayToolData] = syntheticTools
        var seenToolCodes = Set(syntheticTools.map(\.toolCode))

        for tool in bankCardsPageRemoteTools
        where !seenToolCodes.contains(tool.toolCode) && !hiddenToolCodes.contains(tool.toolCode) {
            resolvedTools.append(tool)
            seenToolCodes.insert(tool.toolCode)
        }

        return resolvedTools
    }

    private func addBankCard(_ submission: BankCardAddSubmission) -> String? {
        guard let userId = currentUserTransferUserId, userId > 0 else {
            return "未找到当前登录用户"
        }
        guard BankCardSyntheticStore.save(submission, userId: userId) != nil else {
            return "添加银行卡失败，请稍后重试"
        }

        bankCardsPageTools = resolvedBankCardsPageTools(userId: userId)
        hasLoadedBankCardsPageTools = true
        bankCardsPageQueryFailed = false
        bankCardsPageToolsErrorMessage = bankCardsPageTools.isEmpty ? "暂无银行卡" : nil
        return nil
    }

    private func deleteBankCard(_ tool: CashierPayToolData) -> String? {
        guard let userId = currentUserTransferUserId, userId > 0 else {
            return "未找到当前登录用户"
        }
        guard BankCardSyntheticStore.delete(tool: tool, userId: userId) else {
            return "删除银行卡失败，请稍后重试"
        }

        bankCardsPageRemoteTools.removeAll { $0.toolCode == tool.toolCode }
        bankCardsPageTools = resolvedBankCardsPageTools(userId: userId)
        hasLoadedBankCardsPageTools = true
        bankCardsPageQueryFailed = false
        bankCardsPageToolsErrorMessage = bankCardsPageTools.isEmpty ? "暂无银行卡" : nil
        return nil
    }

    private func resolvedBankCardNumber(for tool: CashierPayToolData) -> String {
        BankCardSyntheticStore.resolvedCardNumber(for: tool, userId: currentUserTransferUserId)
    }

