    private var homeDeliverBannerCreatives: [DeliverCreativeData] {
        if let homeDeliverBanner,
           !homeDeliverBanner.creativeList.isEmpty {
            return homeDeliverBanner.creativeList
        }
        return bundledHomeDeliverBannerCreatives
    }

    private var displayedHomeDeliverCreative: DeliverCreativeData? {
        let creatives = homeDeliverBannerCreatives
        guard !creatives.isEmpty else {
            return nil
        }
        return creatives[normalizedHomeDeliverBannerIndex(in: creatives)]
    }

    private var homeDeliverBannerSlideInterval: TimeInterval {
        TimeInterval(max(homeDeliverBanner?.slideInterval ?? 5, 5))
    }

    private func resetHomeDeliverBannerRotation() {
        homeDeliverBannerIndex = 0
        homeDeliverBannerLastRotatedAt = Date()
    }

    private func normalizedHomeDeliverBannerIndex(in creatives: [DeliverCreativeData]) -> Int {
        guard !creatives.isEmpty else {
            return 0
        }
        return homeDeliverBannerIndex >= 0 ? homeDeliverBannerIndex % creatives.count : 0
    }

    private func rotateHomeDeliverBannerIfNeeded(now: Date) {
        guard currentPage == .home else {
            homeDeliverBannerLastRotatedAt = now
            return
        }
        let creatives = homeDeliverBannerCreatives
        guard creatives.count > 1 else {
            return
        }
        guard now.timeIntervalSince(homeDeliverBannerLastRotatedAt) >= homeDeliverBannerSlideInterval else {
            return
        }
        withAnimation(.easeInOut(duration: 0.35)) {
            homeDeliverBannerIndex = (normalizedHomeDeliverBannerIndex(in: creatives) + 1) % creatives.count
        }
        homeDeliverBannerLastRotatedAt = now
    }

    private func homeDeliverBannerThemeKey(for creative: DeliverCreativeData?) -> String {
        [creative?.creativeCode, creative?.materialCode, creative?.materialTitle, creative?.previewImage, creative?.imageUrl]
            .compactMap { $0?.uppercased() }
            .joined(separator: " ")
    }

    private func homeDeliverBannerFallbackAssetName(for creative: DeliverCreativeData?) -> String {
        let themeKey = homeDeliverBannerThemeKey(for: creative)
        if themeKey.contains("WARM") || themeKey.contains("COUPON") {
            return "HomeDeliverBannerFallbackWarm"
        }
        if themeKey.contains("BLUE")
            || themeKey.contains("FINTECH")
            || themeKey.contains("AICASH")
            || themeKey.contains("AICASH") {
            return "HomeDeliverBannerFallbackBlue"
        }
        return "HomeDeliverBannerFallback"
    }

    private func homeDeliverBannerBackgroundColor(for creative: DeliverCreativeData?) -> Color {
        let themeKey = homeDeliverBannerThemeKey(for: creative)
        if themeKey.contains("WARM") || themeKey.contains("COUPON") {
            return Color(red: 1.0, green: 227.0 / 255.0, blue: 191.0 / 255.0)
        }
        if themeKey.contains("BLUE")
            || themeKey.contains("FINTECH")
            || themeKey.contains("AICASH")
            || themeKey.contains("AICASH") {
            return Color(red: 31.0 / 255.0, green: 88.0 / 255.0, blue: 1.0)
        }
        return Color(red: 1.0, green: 95.0 / 255.0, blue: 87.0 / 255.0)
    }

