        let pageTopBackgroundColor = Color(red: 247.0 / 255.0, green: 250.0 / 255.0, blue: 251.0 / 255.0)
        let fontScale = min(scaleX, scaleY)
        let commonSectionOffsetY: CGFloat = 10.0 / 3.0
        let bannerShiftY: CGFloat = 6
        let bannerWidth = 390 * scaleX
        let bannerHeight = 114 * scaleY
        let bannerCenterX = 201 * scaleX
        let bannerCenterY = (389 + commonSectionOffsetY + bannerShiftY) * scaleY
