        let bottomInset = max(UIApplication.shared.activeKeyWindow?.safeAreaInsets.bottom ?? 0, 12)

        return ScrollViewReader { proxy in
            ZStack(alignment: .trailing) {
                Color(red: 247 / 255, green: 248 / 255, blue: 250 / 255)
