                                .scaleEffect(0.84)
                        }
                    }
                    .padding(.horizontal, 16 * scaleX)
                    .padding(.top, topInset + 6 * scaleY)
                    .padding(.bottom, 14 * scaleY)
                    .background(Color.white.opacity(0.98))

                    ScrollView(showsIndicators: false) {
