    @ViewBuilder
    private func homeDeliverBannerCarouselView(creatives: [DeliverCreativeData],
                                               cardWidth: CGFloat,
                                               cardHeight: CGFloat,
                                               fontScale: CGFloat) -> some View {
        let selection = Binding<Int>(
            get: {
                normalizedHomeDeliverBannerIndex(in: creatives)
            },
            set: { newValue in
                guard !creatives.isEmpty else {
                    return
                }
                homeDeliverBannerIndex = min(max(newValue, 0), creatives.count - 1)
                homeDeliverBannerLastRotatedAt = Date()
            }
        )

        ZStack(alignment: .bottom) {
            TabView(selection: selection) {
                ForEach(Array(creatives.enumerated()), id: \.offset) { index, creative in
                    Button {
                        openHomeDeliverBanner(for: creative, bannerIndex: index)
                    } label: {
                        homeDeliverBannerCardView(
                            creative: creative,
                            cardWidth: cardWidth,
                            cardHeight: cardHeight
                        )
                    }
                    .buttonStyle(.plain)
                    .tag(index)
                }
            }
            .tabViewStyle(.page(indexDisplayMode: .never))

            if creatives.count > 1 {
                HStack(spacing: 6 * fontScale) {
                    ForEach(0..<creatives.count, id: \.self) { index in
                        Capsule(style: .continuous)
                            .fill(index == normalizedHomeDeliverBannerIndex(in: creatives)
                                  ? Color.white.opacity(0.95)
                                  : Color.white.opacity(0.36))
                            .frame(
                                width: index == normalizedHomeDeliverBannerIndex(in: creatives)
                                ? 14 * fontScale
                                : 6 * fontScale,
                                height: 6 * fontScale
                            )
                    }
                }
                .padding(.bottom, 10 * fontScale)
            }

        }
        .frame(width: cardWidth, height: cardHeight)
        .clipShape(Rectangle())
    }

    @ViewBuilder
    private func homeDeliverBannerCardView(creative: DeliverCreativeData,
                                           cardWidth: CGFloat,
                                           cardHeight: CGFloat) -> some View {
        homeDeliverBannerImageView(
            creative: creative,
