    }

    @ViewBuilder
    private func homeDeliverBannerImageView(creative: DeliverCreativeData,
                                            cardWidth: CGFloat,
                                            cardHeight: CGFloat) -> some View {
        let fallbackAssetName = homeDeliverBannerFallbackAssetName(for: creative)
        if let imageUrl = creative.imageUrl,
           let url = URL(string: imageUrl) {
            AsyncImage(url: url) { phase in
                switch phase {
                case .success(let image):
                    image
                        .resizable()
                        .scaledToFit()
                case .empty, .failure:
                    Image(fallbackAssetName)
                        .resizable()
                        .scaledToFit()
                @unknown default:
                    Image(fallbackAssetName)
                        .resizable()
                        .scaledToFit()
                }
            }
            .frame(width: cardWidth, height: cardHeight, alignment: .top)
            .clipShape(Rectangle())
        } else {
            Image(fallbackAssetName)
                .resizable()
                .scaledToFit()
                .frame(width: cardWidth, height: cardHeight, alignment: .top)
                .clipShape(Rectangle())
        }
    }

    private enum HomeDeliverBannerRouteAction {
        case stayHome
        case openTransferList
        case openAiCash
        case openExternal(URL)
    }

    private func rescuePlanBannerURL(for creative: DeliverCreativeData?) -> URL? {
        let candidateTexts = [
            creative?.creativeName,
            creative?.materialTitle,
            creative?.creativeCode,
            creative?.materialCode
        ]
        .compactMap { $0?.trimmingCharacters(in: .whitespacesAndNewlines) }
        .filter { !$0.isEmpty }

        let containsRescuePlan = candidateTexts.contains { text in
            text.contains("挽救计划")
        }
        guard containsRescuePlan else {
            let creativeCode = creative?.creativeCode.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() ?? ""
            let materialCode = creative?.materialCode?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() ?? ""
            let isRescueFallbackCreative = creativeCode == "CRT_HOME_BANNER_RED" || materialCode == "MAT_HOME_BANNER_RED"
            guard isRescueFallbackCreative else {
                return nil
            }
            return URL(string: "https://movie.douban.com/subject/35010610/")
        }
        return URL(string: "https://movie.douban.com/subject/35010610/")
    }

    private func secondHomeBannerURL(for creative: DeliverCreativeData?) -> URL? {
        let creativeCode = creative?.creativeCode.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() ?? ""
        let materialCode = creative?.materialCode?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() ?? ""
        let isSecondBannerCreative = creativeCode == "CRT_HOME_BANNER_WARM" || materialCode == "MAT_HOME_BANNER_WARM"
        guard isSecondBannerCreative else {
            return nil
        }
        return URL(string: "https://detail.damai.cn/item.htm?id=1024242223900")
    }

    private func externalLandingURL(for creative: DeliverCreativeData?) -> URL? {
        guard let rawLandingURL = creative?.landingUrl?.trimmingCharacters(in: .whitespacesAndNewlines),
              !rawLandingURL.isEmpty,
              let url = URL(string: rawLandingURL),
              let scheme = url.scheme?.lowercased(),
              scheme == "http" || scheme == "https" else {
            return nil
        }
        return url
    }

    private func homeDeliverBannerRouteAction(for creative: DeliverCreativeData?) -> HomeDeliverBannerRouteAction {
        if let rescuePlanURL = rescuePlanBannerURL(for: creative) {
            return .openExternal(rescuePlanURL)
        }
        if let secondBannerURL = secondHomeBannerURL(for: creative) {
            return .openExternal(secondBannerURL)
        }
        if let externalLandingURL = externalLandingURL(for: creative) {
            return .openExternal(externalLandingURL)
        }

        if hasHomeDeliverBannerFeatureFlag(in: creative?.landingUrl) {
            return .stayHome
        }

        let schemaAction = parsedHomeDeliverBannerSchemaAction(from: creative?.schemaJson)
        if schemaAction == "stay-on-home" || schemaAction == "open-home-campaign" {
            return .stayHome
        }
        if schemaAction == "open-aicash" || schemaAction == "open-aicash" {
            return .openAiCash
        }
        if schemaAction == "open-transfer-list" {
            return .openTransferList
        }

        let landingUrl = creative?.landingUrl?.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() ?? ""
        if landingUrl.contains("aicash") || landingUrl.contains("aicash") {
            return .openAiCash
        }
        if landingUrl.contains("transferlist") {
            return .openTransferList
        }
        return .stayHome
    }

    private func hasHomeDeliverBannerFeatureFlag(in landingUrl: String?) -> Bool {
        guard let rawLandingUrl = landingUrl?.trimmingCharacters(in: .whitespacesAndNewlines),
              !rawLandingUrl.isEmpty,
              let components = URLComponents(string: rawLandingUrl) else {
            return false
        }
        return components.queryItems?.contains(where: { item in
            item.name.caseInsensitiveCompare("feature") == .orderedSame
                && (item.value?.caseInsensitiveCompare("deliver-home-banner") == .orderedSame)
        }) == true
    }

    private func parsedHomeDeliverBannerSchemaAction(from schemaJson: String?) -> String? {
        guard let rawSchemaJson = schemaJson?.trimmingCharacters(in: .whitespacesAndNewlines),
              !rawSchemaJson.isEmpty,
              let data = rawSchemaJson.data(using: .utf8),
              let jsonObject = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
              let action = jsonObject["action"] as? String else {
            return nil
        }
        let normalizedAction = action.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        return normalizedAction.isEmpty ? nil : normalizedAction
    }

    private func openHomeDeliverBanner(for creative: DeliverCreativeData? = nil, bannerIndex: Int? = nil) {
        let selectedCreative = creative ?? displayedHomeDeliverCreative
        Task {
            try? await APIClient.shared.reportDeliverClick(
                userId: currentUserTransferUserId,
                positionCode: homeDeliverBanner?.positionCode ?? "HOME_COMMON_BANNER",
                unitCode: selectedCreative?.unitCode,
                creativeCode: selectedCreative?.creativeCode
            )
        }

        if isMobileTopUpRewardBanner(creative: selectedCreative, bannerIndex: bannerIndex) {
            Task { @MainActor in
                await claimMobileTopUpRewardFromBanner()
            }
            currentPage = .home
            return
        }

        switch homeDeliverBannerRouteAction(for: selectedCreative) {
        case .stayHome:
            currentPage = .home
        case .openTransferList:
            openTransferFlow(from: .home)
        case .openAiCash:
            openAiCashEntry(from: .home, entryFromProfile: false)
        case let .openExternal(url):
            UIApplication.shared.open(url)
        }
    }

    private func isMobileTopUpRewardBanner(creative: DeliverCreativeData?, bannerIndex: Int?) -> Bool {
        if bannerIndex == 2 {
            return true
        }
        let creativeCode = creative?.creativeCode.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() ?? ""
        let materialCode = creative?.materialCode?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() ?? ""
        return creativeCode == "CRT_HOME_BANNER_BLUE" || materialCode == "MAT_HOME_BANNER_BLUE"
    }

    @MainActor
    private func claimMobileTopUpRewardFromBanner() async {
        guard let userId = currentUserTransferUserId, userId > 0 else {
            showNotice("请先登录后领取话费红包")
            return
        }
        let businessNo = "HOME_TOPUP_BANNER_\(userId)_\(Int64((Date().timeIntervalSince1970 * 1000).rounded()))"
        do {
            let reward = try await APIClient.shared.claimMobileTopUpRewardCoupon(
                userId: userId,
                businessNo: businessNo
            )
            let rewardAmount = max(reward.couponAmount, .zero)
            let normalizedCouponNo = reward.couponNo.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !normalizedCouponNo.isEmpty, rewardAmount > .zero else {
                showNotice("话费红包领取失败，请稍后重试")
                return
            }
            await refreshMobileTopUpRewardCouponsIfNeeded(force: true, preferredCouponNo: normalizedCouponNo)
            if mobileHallTopUpRewardCoupons.isEmpty {
                let fallbackCoupon = MobileTopUpRewardCoupon(
                    couponNo: normalizedCouponNo,
                    amount: rewardAmount,
                    expireDateText: nil
                )
                mobileHallTopUpRewardCoupons = [fallbackCoupon]
                mobileHallTopUpRewardCoupon = fallbackCoupon
            }
            homeBannerRewardAlertMessage = mobileTopUpRewardClaimAlertMessage(
                rewardAmount: rewardAmount,
                todayClaimedCount: reward.todayClaimedCount,
                dailyClaimLimit: reward.dailyClaimLimit
            )
        } catch {
            let message = userFacingErrorMessage(error)
            if message.contains("一天最多领取五次") || message.contains("您已领取") {
                homeBannerRewardAlertMessage = message.replacingOccurrences(of: "，您已领取", with: "，\n您已领取")
                return
            }
            showNotice(message)
        }
    }

    private func mobileTopUpRewardClaimAlertMessage(
        rewardAmount: Decimal,
        todayClaimedCount: Int,
        dailyClaimLimit: Int
    ) -> String {
        let normalizedTodayClaimedCount = max(todayClaimedCount, 0)
        let normalizedDailyLimit = dailyClaimLimit > 0 ? dailyClaimLimit : 5
        return "您已领取\(formatTopUpRewardAmount(rewardAmount))元话费充值立减红包\n话费充值红包一天最多领取\(normalizedDailyLimit)次，\n您已领取\(normalizedTodayClaimedCount)次"
    }

    @MainActor
    private func refreshMobileTopUpRewardCouponsIfNeeded(
        force: Bool = false,
        preferredCouponNo: String? = nil
    ) async {
        if !force, !mobileHallTopUpRewardCoupons.isEmpty {
            return
        }
        guard let userId = currentUserTransferUserId, userId > 0 else {
            mobileHallTopUpRewardCoupons = []
            mobileHallTopUpRewardCoupon = nil
            return
        }

        do {
            let issues = try await APIClient.shared.fetchMobileTopUpRewardCoupons(userId: userId)
            let coupons = issues
                .compactMap { mapMobileTopUpRewardCoupon(from: $0) }
                .sorted(by: compareMobileTopUpRewardCoupon)
            mobileHallTopUpRewardCoupons = coupons
            mobileHallTopUpRewardCoupon = resolveMobileTopUpRewardSelection(
                from: coupons,
                preferredCouponNo: preferredCouponNo
            )
        } catch {
            if force {
                showNotice("话费红包加载失败，可稍后重试")
            }
        }
    }

    private func mapMobileTopUpRewardCoupon(from issue: MobileTopUpRewardCouponIssueData) -> MobileTopUpRewardCoupon? {
        let normalizedCouponNo = issue.couponNo.trimmingCharacters(in: .whitespacesAndNewlines)
        let amount = max(issue.couponAmount, .zero)
        guard !normalizedCouponNo.isEmpty, amount > .zero else {
            return nil
        }
        return MobileTopUpRewardCoupon(
            couponNo: normalizedCouponNo,
            amount: amount,
            expireDateText: resolveMobileTopUpRewardExpireDateText(expireDate: issue.expireDate, expireAt: issue.expireAt)
        )
    }

    private func compareMobileTopUpRewardCoupon(_ lhs: MobileTopUpRewardCoupon, _ rhs: MobileTopUpRewardCoupon) -> Bool {
        if lhs.amount != rhs.amount {
            return lhs.amount > rhs.amount
        }
        let lhsDate = lhs.expireDateText ?? "9999-12-31"
        let rhsDate = rhs.expireDateText ?? "9999-12-31"
        if lhsDate != rhsDate {
            return lhsDate < rhsDate
        }
        return lhs.couponNo < rhs.couponNo
    }

    private func resolveMobileTopUpRewardSelection(
        from coupons: [MobileTopUpRewardCoupon],
        preferredCouponNo: String?
    ) -> MobileTopUpRewardCoupon? {
        let normalizedPreferred = preferredCouponNo?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if !normalizedPreferred.isEmpty,
           let matched = coupons.first(where: { $0.couponNo == normalizedPreferred }) {
            return matched
        }
        let currentSelectedCouponNo = mobileHallTopUpRewardCoupon?.couponNo ?? ""
        if !currentSelectedCouponNo.isEmpty,
           let matched = coupons.first(where: { $0.couponNo == currentSelectedCouponNo }) {
            return matched
        }
        return coupons.first
    }

    private func resolveMobileTopUpRewardExpireDateText(expireDate: String?, expireAt: String?) -> String? {
        let normalizedExpireDate = expireDate?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if !normalizedExpireDate.isEmpty {
            return String(normalizedExpireDate.prefix(10))
        }
        let normalizedExpireAt = expireAt?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if normalizedExpireAt.isEmpty {
            return nil
        }
        if let range = normalizedExpireAt.range(of: "T") {
            let prefix = String(normalizedExpireAt[..<range.lowerBound])
            return prefix.isEmpty ? nil : prefix
        }
        return String(normalizedExpireAt.prefix(10))
    }

    private func formatTopUpRewardAmount(_ amount: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = false
        formatter.minimumFractionDigits = 0
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSDecimalNumber(decimal: amount)) ?? "0"
    }

    private var effectiveMobileHallTopUpRewardCoupon: MobileTopUpRewardCoupon? {
        if let selected = mobileHallTopUpRewardCoupon, selected.amount > .zero {
            return selected
        }
        return mobileHallTopUpRewardCoupons.first(where: { $0.amount > .zero })
    }

    private func discountedMobileHallRechargeAmount(for amount: Decimal) -> Decimal? {
        guard amount > .zero,
              let coupon = effectiveMobileHallTopUpRewardCoupon else {
            return nil
        }
        let discountedAmount = max(amount - coupon.amount, .zero)
        return discountedAmount < amount ? discountedAmount : nil
    }

