    @MainActor
    private func saveNicknameChanges() async {
        guard !isSavingNickname else {
            return
        }

        let normalizedNickname = nicknameDraftText.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedNickname.isEmpty else {
            avatarEditorHintMessage = "昵称不能为空"
            return
        }
        guard let userId = currentUserTransferUserId else {
            avatarEditorHintMessage = "用户标识无效"
            return
        }

        let persistedNickname = normalizedProfileText(currentUserProfile?.nickname) ?? ""
        if normalizedNickname == persistedNickname {
            closeNicknameEditor()
            return
        }

        let fallbackProfile = currentUserProfile
        isSavingNickname = true
        defer {
            isSavingNickname = false
        }

        do {
            try await APIClient.shared.updateUserNickname(userId: userId, nickname: normalizedNickname)

            if let refreshedProfile = try? await APIClient.shared.fetchUserProfile(userId: userId) {
                appState.updateCurrentUserProfile(refreshedProfile)
            } else if let fallbackProfile {
                appState.updateCurrentUserProfile(updatedUserProfile(fallbackProfile, nickname: normalizedNickname))
            }

            nicknameDraftText = normalizedNickname
            closeNicknameEditor()
        } catch {
            avatarEditorHintMessage = userFacingErrorMessage(error)
        }
    }

