    @ViewBuilder
    private func avatarCropCanvas(cropSide: CGFloat) -> some View {
        if let avatarCropSourceImage {
            let liveZoom = min(max(avatarCropCommittedZoom * avatarCropGestureZoom, 1), 4)
            let effectiveScale = avatarCropEffectiveScale(
                for: avatarCropSourceImage,
                cropSide: cropSide,
                zoom: liveZoom
            )
            let liveOffset = avatarCropClampedOffset(
                CGSize(
                    width: avatarCropCommittedOffset.width + avatarCropGestureOffset.width,
                    height: avatarCropCommittedOffset.height + avatarCropGestureOffset.height
                ),
                imageSize: avatarCropSourceImage.size,
                cropSide: cropSide,
                effectiveScale: effectiveScale
            )

            ZStack {
                Image(uiImage: avatarCropSourceImage)
                    .resizable()
                    .aspectRatio(contentMode: .fill)
                    .frame(
                        width: avatarCropSourceImage.size.width * effectiveScale,
                        height: avatarCropSourceImage.size.height * effectiveScale
                    )
                    .offset(liveOffset)

                VStack(spacing: 0) {
                    Rectangle()
                        .fill(Color.black.opacity(0.22))
                        .frame(height: cropSide * 0.105)
                    Spacer(minLength: 0)
                    ZStack(alignment: .bottomTrailing) {
                        Rectangle()
                            .fill(Color.black.opacity(0.30))
                            .frame(height: cropSide * 0.20)
                        Text("重置 AI 生成")
                            .font(.system(size: 10, weight: .regular))
                            .foregroundStyle(Color.white.opacity(0.56))
                            .padding(.trailing, 10)
                            .padding(.bottom, 8)
                    }
                }
                .allowsHitTesting(false)

                Rectangle()
                    .stroke(Color.white.opacity(0.72), lineWidth: 1)
                    .allowsHitTesting(false)
            }
            .frame(width: cropSide, height: cropSide)
            .clipped()
            .contentShape(Rectangle())
            .allowsHitTesting(!isSavingAvatar)
            .gesture(
                SimultaneousGesture(
                    DragGesture(minimumDistance: 0)
                        .updating($avatarCropGestureOffset) { value, state, _ in
                            state = value.translation
                        }
                        .onEnded { value in
                            avatarCropCommittedOffset = avatarCropClampedOffset(
                                CGSize(
                                    width: avatarCropCommittedOffset.width + value.translation.width,
                                    height: avatarCropCommittedOffset.height + value.translation.height
                                ),
                                imageSize: avatarCropSourceImage.size,
                                cropSide: cropSide,
                                effectiveScale: avatarCropEffectiveScale(
                                    for: avatarCropSourceImage,
                                    cropSide: cropSide,
                                    zoom: avatarCropCommittedZoom
                                )
                            )
                            avatarCropOffset = avatarCropCommittedOffset
                        },
                    MagnificationGesture()
                        .updating($avatarCropGestureZoom) { value, state, _ in
                            state = value
                        }
                        .onEnded { value in
                            let resolvedZoom = min(max(avatarCropCommittedZoom * value, 1), 4)
                            avatarCropCommittedZoom = resolvedZoom
                            avatarCropZoom = resolvedZoom
                            let clamped = avatarCropClampedOffset(
                                avatarCropCommittedOffset,
                                imageSize: avatarCropSourceImage.size,
                                cropSide: cropSide,
                                effectiveScale: avatarCropEffectiveScale(
                                    for: avatarCropSourceImage,
                                    cropSide: cropSide,
                                    zoom: resolvedZoom
                                )
                            )
                            avatarCropCommittedOffset = clamped
                            avatarCropOffset = clamped
                        }
                )
            )
            .onChange(of: liveZoom) { _, newValue in
                avatarCropZoom = newValue
                let clamped = avatarCropClampedOffset(
                    liveOffset,
                    imageSize: avatarCropSourceImage.size,
                    cropSide: cropSide,
                    effectiveScale: avatarCropEffectiveScale(
                        for: avatarCropSourceImage,
                        cropSide: cropSide,
                        zoom: newValue
                    )
                )
                avatarCropOffset = clamped
            }
        } else {
            Rectangle()
                .fill(Color.white.opacity(0.08))
                .frame(width: cropSide, height: cropSide)
        }
    }

