    private let settingsLanguageOptions: [SettingsLanguageOption] = [
        SettingsLanguageOption(code: "zh-Hans", title: "简体中文"),
        SettingsLanguageOption(code: "zh-Hant-TW", title: "繁体中文 (台湾)"),
        SettingsLanguageOption(code: "zh-Hant-HK", title: "繁体中文 (香港)"),
        SettingsLanguageOption(code: "en", title: "English")
    ]

    private var normalizedSavedSettingsLanguageCode: String {
        normalizedSettingsLanguageCode(savedSettingsLanguageCode)
    }

    private var normalizedDraftSettingsLanguageCode: String {
        normalizedSettingsLanguageCode(settingsLanguageDraftCode)
    }

    private var isSettingsLanguageSaveEnabled: Bool {
        normalizedDraftSettingsLanguageCode != normalizedSavedSettingsLanguageCode
    }

    private func isSettingsLanguageSelectable(_ code: String) -> Bool {
        normalizedSettingsLanguageCode(code) == "zh-Hans"
    }

    private var settingsLanguagePendingText: String {
        "待开发"
    }

    private func normalizedSettingsLanguageCode(_ code: String) -> String {
        let normalized = code.trimmingCharacters(in: .whitespacesAndNewlines)
        if settingsLanguageOptions.contains(where: { $0.code == normalized }) {
            return normalized
        }
        return "zh-Hans"
    }

