    private func openSettingsLanguagePage() {
        let normalized = normalizedSavedSettingsLanguageCode
        if savedSettingsLanguageCode != normalized {
            savedSettingsLanguageCode = normalized
        }
        settingsLanguageDraftCode = isSettingsLanguageSelectable(normalized) ? normalized : "zh-Hans"
        currentPage = .settingsLanguage
    }

    private func closeSettingsLanguagePageWithoutSaving() {
        settingsLanguageDraftCode = normalizedSavedSettingsLanguageCode
        currentPage = .settingsGeneral
    }

    private func saveSettingsLanguagePage() {
        let normalized = normalizedDraftSettingsLanguageCode
        savedSettingsLanguageCode = normalized
        settingsLanguageDraftCode = normalized
        currentPage = .settingsGeneral
    }

