    private func settingsCopyrightView() -> some View {
        GeometryReader { proxy in
            let scaleX = proxy.size.width / baseWidth
            let scaleY = proxy.size.height / baseHeight
            let fontScale = min(scaleX, scaleY)
            let pageBackground = Color.white
            let rowBackground = Color.white
            let separatorColor = Color(red: 0.87, green: 0.87, blue: 0.89)
            let linkColor = AppTheme.palette.brandPrimary
            let trailingColor = Color(red: 0.54, green: 0.54, blue: 0.56)
            let navigationCenterY = 71 * scaleY
            let navigationHeight = 98 * scaleY

            ZStack(alignment: .top) {
                pageBackground
                    .ignoresSafeArea()

                VStack(spacing: 0) {
                    ZStack {
                        pageBackground
                            .frame(width: proxy.size.width, height: navigationHeight)

                        Text(settingsCopyrightTitleText)
                            .font(.system(size: 17 * fontScale, weight: .semibold))
                            .foregroundStyle(Color(red: 0.12, green: 0.12, blue: 0.12))
                            .position(x: proxy.size.width / 2, y: navigationCenterY)

                        HStack {
                            Image(systemName: "chevron.left")
                                .font(.system(size: 20 * fontScale, weight: .medium))
                                .foregroundStyle(Color(red: 0.33, green: 0.33, blue: 0.35))
                            Spacer()
                        }
                        .frame(width: proxy.size.width - (24 * scaleX))
                        .padding(.leading, 12 * scaleX)
                        .position(x: proxy.size.width / 2, y: navigationCenterY)
                    }
                    .frame(width: proxy.size.width, height: navigationHeight)
                    .background(pageBackground)

                    Rectangle()
                        .fill(separatorColor)
                        .frame(width: proxy.size.width, height: max(1 * scaleY, 0.5))

                    ScrollView(showsIndicators: false) {
                        LazyVStack(spacing: 0) {
                            ForEach(Array(settingsOpenSourceLicenseItems.enumerated()), id: \.element.id) { index, item in
                                HStack(alignment: .top, spacing: 10 * scaleX) {
                                    Text(item.name)
                                        .font(.system(size: 13 * fontScale, weight: .regular))
                                        .foregroundStyle(linkColor)
                                        .frame(width: 135 * scaleX, alignment: .leading)
                                        .lineLimit(2)
                                        .multilineTextAlignment(.leading)
                                        .fixedSize(horizontal: false, vertical: true)

                                    Text(item.license)
                                        .font(.system(size: 13 * fontScale, weight: .regular))
                                        .foregroundStyle(linkColor)
                                        .frame(width: 140 * scaleX, alignment: .leading)
                                        .lineLimit(2)
                                        .multilineTextAlignment(.leading)
                                        .fixedSize(horizontal: false, vertical: true)

                                    Spacer(minLength: 0)

                                    Text(item.modified ? settingsOpenSourceLicenseYesText : settingsOpenSourceLicenseNoText)
                                        .font(.system(size: 13 * fontScale, weight: .regular))
                                        .foregroundStyle(trailingColor)
                                        .padding(.top, 3 * scaleY)
                                }
                                .padding(.leading, 10 * scaleX)
                                .padding(.trailing, 17 * scaleX)
                                .padding(.vertical, 11 * scaleY)
                                .frame(width: proxy.size.width, alignment: .leading)
                                .background(rowBackground)

                                if index != settingsOpenSourceLicenseItems.count - 1 {
                                    Rectangle()
                                        .fill(separatorColor)
                                        .frame(width: proxy.size.width, height: max(1 * scaleY, 0.5))
                                }
                            }
                        }
                    }
                }

                tabHotspot(
                    identifier: "settings_copyright_back",
                    centerX: 23 * scaleX,
                    centerY: 76 * scaleY,
                    width: 66 * scaleX,
                    height: 54 * scaleY
                ) {
                    currentPage = .settingsAbout
                }
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
