    @ViewBuilder
    private func settingsMenuRow(
        iconBackground: Color,
        symbolName: String,
        title: String,
        trailingText: String?,
        centerY: CGFloat,
        scaleX: CGFloat,
        scaleY: CGFloat,
        fontScale: CGFloat,
        titleOffsetX: CGFloat = 0,
        useOutlinedGeneralIcon: Bool = false,
        useFeedbackComplaintIcon: Bool = false,
        useAboutTouchIcon: Bool = false,
        showsChevron: Bool = true
    ) -> some View {
        ZStack {
            if useOutlinedGeneralIcon {
                ZStack {
                    Image(systemName: "gearshape")
                        .font(.system(size: 20 * fontScale, weight: .regular))
                        .foregroundStyle(Color(red: 0.20, green: 0.18, blue: 0.20))

                    Circle()
                        .stroke(Color(red: 0.88, green: 0.34, blue: 0.26), lineWidth: 2.1 * fontScale)
                        .frame(width: 10 * scaleX, height: 10 * scaleY)
                }
                .frame(width: 24 * scaleX, height: 24 * scaleY)
                .position(x: 31 * scaleX, y: centerY * scaleY)
            } else if useFeedbackComplaintIcon {
                settingsFeedbackComplaintIcon(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale, centerY: centerY)
            } else if useAboutTouchIcon {
                settingsAboutTouchIcon(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale, centerY: centerY)
            } else {
                RoundedRectangle(cornerRadius: 8 * fontScale, style: .continuous)
                    .fill(iconBackground)
                    .frame(width: 24 * scaleX, height: 24 * scaleY)
                    .position(x: 31 * scaleX, y: centerY * scaleY)

                Image(systemName: symbolName)
                    .font(.system(size: 14 * fontScale, weight: .semibold))
                    .foregroundStyle(Color.white)
                    .position(x: 31 * scaleX, y: centerY * scaleY)
            }

            HStack(spacing: 0) {
                Text(title)
                    .font(.system(size: 17 * fontScale, weight: .regular))
                    .foregroundStyle(Color(red: 0.20, green: 0.20, blue: 0.22))

                Spacer(minLength: 8 * scaleX)

                if let trailingText {
                    Text(trailingText)
                        .font(.system(size: 15 * fontScale, weight: .regular))
                        .foregroundStyle(Color(red: 0.62, green: 0.62, blue: 0.65))
                        .lineLimit(1)
                }

                if showsChevron {
                    Image(systemName: "chevron.right")
                        .font(.system(size: 15 * fontScale, weight: .medium))
                        .foregroundStyle(Color(red: 0.76, green: 0.76, blue: 0.79))
                        .padding(.leading, 8 * scaleX)
                }
            }
            .frame(width: 322 * scaleX, height: 56 * scaleY)
            .position(x: (206 * scaleX) + (titleOffsetX * scaleX), y: centerY * scaleY)
        }
    }

    @ViewBuilder
    private func settingsFeedbackComplaintIcon(
        scaleX: CGFloat,
        scaleY: CGFloat,
        fontScale: CGFloat,
        centerY: CGFloat
    ) -> some View {
        ZStack {
            RoundedRectangle(cornerRadius: 8 * fontScale, style: .continuous)
                .fill(Color.white)
                .frame(width: 25 * scaleX, height: 25 * scaleY)

            RoundedRectangle(cornerRadius: 4.8 * fontScale, style: .continuous)
                .fill(Color(red: 0.98, green: 0.80, blue: 0.38))
                .frame(width: 18.2 * scaleX, height: 13.8 * scaleY)
                .offset(x: -0.6 * scaleX, y: 0.5 * scaleY)

            Path { path in
                path.move(to: CGPoint(x: -1.8 * scaleX, y: 6.5 * scaleY))
                path.addLine(to: CGPoint(x: 1.2 * scaleX, y: 10.6 * scaleY))
                path.addLine(to: CGPoint(x: 4.0 * scaleX, y: 6.5 * scaleY))
                path.closeSubpath()
            }
            .fill(Color(red: 0.98, green: 0.80, blue: 0.38))
            .offset(x: -4.1 * scaleX, y: 0.8 * scaleY)

            Rectangle()
                .fill(Color(red: 1.00, green: 0.33, blue: 0.36))
                .frame(width: 9.4 * scaleX, height: 1.5 * scaleY)
                .offset(x: -3.1 * scaleX, y: -2.8 * scaleY)

            Rectangle()
                .fill(Color(red: 1.00, green: 0.33, blue: 0.36))
                .frame(width: 7.1 * scaleX, height: 1.5 * scaleY)
