    private var bankCardsPageCountText: String {
        if bankCardsPageQueryFailed {
            return "-"
        }
        return String(bankCardsPageTools.count)
    }

    private var bankCardsFallbackMetaLabels: [String] {
        [
            "信用卡 0",
            "信用卡 0",
            "储蓄卡 0"
        ]
    }

    private var bankCardsVisibleMetaLabels: [String] {
        let visibleCount = bankCardsFallbackMetaLabels.count
        var labels = Array(bankCardsPageTools.prefix(visibleCount)).map(bankCardsMetaLabelText(for:))
        if labels.count < visibleCount {
            labels.append(contentsOf: bankCardsFallbackMetaLabels.dropFirst(labels.count))
        }
        return labels
    }

    private func bankCardsMetaLabelText(for tool: CashierPayToolData) -> String {
        let cardTypeText: String
        switch CashierPresentationHelper.normalizedCardType(for: tool) {
        case "CREDIT":
            cardTypeText = "信用卡"
        case "DEBIT":
            cardTypeText = "储蓄卡"
        default:
            cardTypeText = "银行卡"
        }

        let rawName = tool.toolName
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .replacingOccurrences(of: "（", with: "(")
            .replacingOccurrences(of: "）", with: ")")
        var tail = ""
        if let range = rawName.range(of: "(尾号"),
           let closeIndex = rawName[range.upperBound...].firstIndex(of: ")") {
            let inner = rawName[range.upperBound..<closeIndex]
            tail = inner.replacingOccurrences(of: "\\D", with: "", options: .regularExpression)
        } else if let openIndex = rawName.lastIndex(of: "("),
                  let closeIndex = rawName[openIndex...].firstIndex(of: ")"),
                  openIndex < closeIndex {
            let inner = rawName[rawName.index(after: openIndex)..<closeIndex]
            tail = inner.replacingOccurrences(of: "\\D", with: "", options: .regularExpression)
        }
        if tail.count >= 4 && tail.contains(where: { $0 != "0" }) {
            tail = String(tail.suffix(4))
        } else {
            tail = ""
        }
        return tail.isEmpty ? "\(cardTypeText) 0" : "\(cardTypeText) \(tail)"
    }

