    private var currentUserAssetLookupId: String {
        guard let userId = currentUserTransferUserId else {
            return ""
        }
        return String(userId)
    }

    private var currentUserTransferUserId: Int64? {
        guard let userId = appState.session?.user.userId, userId > 0 else {
            return nil
        }
        return userId
    }

    private var resolvedTotalAssetWalletAmount: Decimal? {
        guard let totalAssetWalletAvailableAmount else {
            return nil
        }
        return max(.zero, totalAssetWalletAvailableAmount + walletAvailableAmountDelta)
    }

    private var resolvedTotalAssetAmount: Decimal? {
        guard let walletAmount = resolvedTotalAssetWalletAmount else {
            return nil
        }
        let aiCashAmount = aiCashSnapshot.hasTotalAmount ? max(.zero, aiCashSnapshot.totalAmount) : .zero
        return max(.zero, walletAmount + aiCashAmount)
    }

    private var resolvedLatestLoanBorrowResult: LoanAccountBorrowResult? {
        latestLoanBorrowResult ?? LoanAccountSyntheticSnapshotStore.loadBorrowResult(userId: currentUserTransferUserId)
    }

    private var resolvedLoanBorrowResults: [LoanAccountBorrowResult] {
        LoanAccountSyntheticSnapshotStore.loadBorrowResults(userId: currentUserTransferUserId)
    }

    private var resolvedLoanRecordBorrowItems: [LoanAccountRecordBorrowItem] {
        var mergedItems = Dictionary(uniqueKeysWithValues: LoanAccountRecordHistoryStore.loadBorrowItems(userId: currentUserTransferUserId).map { ($0.id, $0) })

        for borrowResult in resolvedLoanBorrowResults {
            let item = loanAccountRecordBorrowItem(from: borrowResult)
            mergedItems[item.id] = item
        }

        if let previewBorrowResult = resolvedLatestLoanBorrowResult, previewBorrowResult.isProcessing {
            let item = loanAccountRecordBorrowItem(from: previewBorrowResult)
            mergedItems[item.id] = item
        }

        return mergedItems.values.sorted { $0.occurredAt > $1.occurredAt }
    }

    private var resolvedLoanRecordRepaymentItems: [LoanAccountRecordRepaymentItem] {
        LoanAccountRecordHistoryStore.loadRepaymentItems(userId: currentUserTransferUserId)
    }

    @MainActor
    private func refreshLoanRecordBillEntriesIfNeeded(force: Bool = false) async {
        guard let userId = currentUserTransferUserId, userId > 0 else {
            return
        }
        if isLoadingLoanRecordBillEntries {
            return
        }
        if !force, let lastSyncedAt = lastLoanRecordBillSyncAt, Date().timeIntervalSince(lastSyncedAt) < 8 {
            return
        }

        isLoadingLoanRecordBillEntries = true
        defer {
            isLoadingLoanRecordBillEntries = false
        }

        do {
            var mergedBillItems: [AssetBillEntryItemData] = []
            var requestPageNo = 1
            var requestCursor: String? = nil
            var pageGuard = 0
            while pageGuard < 20 {
                pageGuard += 1
                let billEntries = try await APIClient.shared.fetchAssetBillEntries(
                    userId: String(userId),
                    limit: 100,
                    pageNo: requestPageNo,
                    businessDomainCode: "AILOAN",
                    cursor: requestCursor
                )
                mergedBillItems.append(contentsOf: billEntries.items)

                let currentCursor = requestCursor?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                let nextCursor = billEntries.nextCursor?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                if !nextCursor.isEmpty, nextCursor != currentCursor {
                    requestCursor = nextCursor
                    requestPageNo = max((billEntries.nextPageNo ?? (requestPageNo + 1)), requestPageNo + 1)
                    if billEntries.items.isEmpty {
                        break
                    }
                    continue
                }

                if billEntries.hasMore == true, let nextPageNo = billEntries.nextPageNo, nextPageNo > requestPageNo {
                    requestPageNo = nextPageNo
                    requestCursor = nil
                    if billEntries.items.isEmpty {
                        break
                    }
                    continue
                }
                break
            }
            syncLoanRecordHistoryFromBillEntries(mergedBillItems, userId: userId)
            lastLoanRecordBillSyncAt = Date()
        } catch {
            return
        }
    }

    private func syncLoanRecordHistoryFromBillEntries(_ entries: [AssetBillEntryItemData], userId: Int64) {
        guard !entries.isEmpty else {
            return
        }

        let outstandingBorrowResults = LoanAccountSyntheticSnapshotStore.loadBorrowResults(userId: userId)
            .filter { $0.outstandingPrincipalAmount > .zero }
        var existingBorrowRecords = LoanAccountRecordHistoryStore.loadBorrowItems(userId: userId)
        var existingRepaymentRecords = LoanAccountRecordHistoryStore.loadRepaymentItems(userId: userId)

        for entry in entries {
            let amount = normalizedBillDecimal(entry.amount)
            guard amount > .zero else {
                continue
            }

            let occurredAt = parseBillTradeTime(entry.tradeTime)
            let businessType = entry.businessType.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
            let displayTitle = entry.displayTitle.trimmingCharacters(in: .whitespacesAndNewlines)
            let tradeNo = entry.tradeNo.trimmingCharacters(in: .whitespacesAndNewlines)
            let bizOrderNo = entry.bizOrderNo.trimmingCharacters(in: .whitespacesAndNewlines)
            let stableSeed = !bizOrderNo.isEmpty ? bizOrderNo : (!tradeNo.isEmpty ? tradeNo : UUID().uuidString)

            if isLoanRepaymentBillEntry(businessType: businessType, displayTitle: displayTitle) {
                if existingRepaymentRecords.contains(where: { loanRecordExists(amount: amount, occurredAt: occurredAt, candidateAmount: $0.amount, candidateDate: $0.occurredAt) }) {
                    continue
                }
                let repaymentId = "bill_repay_\(stableSeed)"
                LoanAccountRecordHistoryStore.recordRepayment(
                    userId: userId,
                    repaymentId: repaymentId,
                    borrowId: nil,
                    amount: amount,
                    occurredAt: occurredAt,
                    statusText: "已还款"
                )
                existingRepaymentRecords.append(
                    LoanAccountRecordRepaymentItem(
                        id: repaymentId,
                        amount: amount,
                        occurredAt: occurredAt,
                        statusText: "已还款"
                    )
                )
                continue
            }

            if !isLoanBorrowBillEntry(businessType: businessType, displayTitle: displayTitle) {
                continue
            }
            if existingBorrowRecords.contains(where: { loanRecordExists(amount: amount, occurredAt: occurredAt, candidateAmount: $0.amount, candidateDate: $0.occurredAt) }) {
                continue
            }

            let borrowId = "bill_borrow_\(stableSeed)"
            let hasOutstandingMatch = outstandingBorrowResults.contains { result in
                loanRecordExists(
                    amount: amount,
                    occurredAt: occurredAt,
                    candidateAmount: result.amount,
                    candidateDate: result.borrowedAt
                )
            }
            let statusText = hasOutstandingMatch ? "待还款" : "已结清"
            LoanAccountRecordHistoryStore.recordBorrow(
                userId: userId,
                borrowId: borrowId,
                amount: amount,
                borrowedAt: occurredAt,
                statusText: statusText
            )
            existingBorrowRecords.append(
                LoanAccountRecordBorrowItem(
                    id: borrowId,
                    amount: amount,
                    occurredAt: occurredAt,
                    statusText: statusText
                )
            )
        }
    }

    private func isLoanBorrowBillEntry(businessType: String, displayTitle: String) -> Bool {
        if businessType.contains("LOAN_DRAW") {
            return true
        }
        if businessType.contains("LOAN") && !businessType.contains("REPAY") {
            return true
        }
        return displayTitle.contains("借款")
    }

    private func isLoanRepaymentBillEntry(businessType: String, displayTitle: String) -> Bool {
        if businessType.contains("REPAY") {
            return true
        }
        return displayTitle.contains("还款")
    }

    private func loanRecordExists(
        amount: Decimal,
        occurredAt: Date,
        candidateAmount: Decimal,
        candidateDate: Date
    ) -> Bool {
        let amountGap = abs(NSDecimalNumber(decimal: amount - candidateAmount).doubleValue)
        let timeGap = abs(candidateDate.timeIntervalSince(occurredAt))
        return amountGap < 0.01 && timeGap <= 600
    }

    private func parseBillTradeTime(_ raw: String) -> Date {
        let normalized = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalized.isEmpty else {
            return Date()
        }

        let isoFormatter = ISO8601DateFormatter()
        isoFormatter.formatOptions = [.withInternetDateTime, .withFractionalSeconds]
        if let date = isoFormatter.date(from: normalized) {
            return date
        }
        isoFormatter.formatOptions = [.withInternetDateTime]
        if let date = isoFormatter.date(from: normalized) {
            return date
        }

        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.timeZone = TimeZone(identifier: "Asia/Shanghai") ?? .current
        let formats = [
            "yyyy-MM-dd'T'HH:mm:ss.SSS",
            "yyyy-MM-dd'T'HH:mm:ss",
            "yyyy-MM-dd HH:mm:ss"
        ]
        for format in formats {
            formatter.dateFormat = format
            if let date = formatter.date(from: normalized) {
                return date
            }
        }
        return Date()
    }

    private func normalizedBillDecimal(_ raw: String) -> Decimal {
        let normalized = raw
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .replacingOccurrences(of: ",", with: "")
        guard !normalized.isEmpty else {
            return .zero
        }
        return Decimal(string: normalized, locale: Locale(identifier: "en_US_POSIX")) ?? .zero
    }

    private func loanAccountRecordBorrowItem(from borrowResult: LoanAccountBorrowResult) -> LoanAccountRecordBorrowItem {
        let statusText: String
        if borrowResult.isProcessing {
            statusText = "处理中"
        } else if borrowResult.outstandingPrincipalAmount > .zero {
            statusText = "待还款"
        } else {
            statusText = "已结清"
        }

        return LoanAccountRecordBorrowItem(
            id: borrowResult.borrowId,
            amount: borrowResult.amount,
            occurredAt: borrowResult.borrowedAt,
            statusText: statusText
        )
    }

    private var activeLoanRepayBorrowResult: LoanAccountBorrowResult? {
        LoanAccountSyntheticSnapshotStore.loadBorrowResult(
            userId: currentUserTransferUserId,
            borrowId: activeLoanRepayBorrowId
        )
    }

    private var reopenedLoanBorrowDetailResult: LoanAccountBorrowResult? {
        LoanAccountSyntheticSnapshotStore.loadBorrowResult(
            userId: currentUserTransferUserId,
            borrowId: loanAccountReopenBorrowDetailId
        )
    }

    private func updateLatestLoanBorrowResult(_ result: LoanAccountBorrowResult) {
        if result.status == .succeeded {
            LoanAccountSyntheticSnapshotStore.recordBorrow(result, userId: currentUserTransferUserId)
            LoanAccountRecordHistoryStore.recordBorrow(
                userId: currentUserTransferUserId,
                borrowId: result.borrowId,
                amount: result.amount,
                borrowedAt: result.borrowedAt,
                statusText: "待还款"
            )
            let storedLatest = LoanAccountSyntheticSnapshotStore.loadBorrowResult(userId: currentUserTransferUserId)
            latestLoanBorrowResult = storedLatest
            activeLoanRepayBorrowId = storedLatest?.borrowId
        } else {
            LoanAccountSyntheticSnapshotStore.saveBorrowResult(result, userId: currentUserTransferUserId)
            latestLoanBorrowResult = result
            activeLoanRepayBorrowId = result.borrowId
        }
    }

    private func applyLoanAccountRepaymentSnapshot(_ settlement: LoanAccountRepaymentSettlement) {
        let repaidBorrowResult = activeLoanRepayBorrowResult
        let targetBorrowId = repaidBorrowResult?.borrowId ?? activeLoanRepayBorrowId
        let normalizedTotalAmount = max(.zero, settlement.totalAmount)

        LoanAccountSyntheticSnapshotStore.applyRepayment(
            settlement: settlement,
            borrowId: targetBorrowId,
            userId: currentUserTransferUserId
        )

        let updatedBorrowResult = LoanAccountSyntheticSnapshotStore.loadBorrowResult(
            userId: currentUserTransferUserId,
            borrowId: targetBorrowId
        )
        if let borrowForRecord = updatedBorrowResult ?? repaidBorrowResult {
            let hasOutstandingPrincipal = (updatedBorrowResult?.outstandingPrincipalAmount ?? .zero) > .zero
            LoanAccountRecordHistoryStore.recordBorrow(
                userId: currentUserTransferUserId,
                borrowId: borrowForRecord.borrowId,
                amount: borrowForRecord.amount,
                borrowedAt: borrowForRecord.borrowedAt,
                statusText: hasOutstandingPrincipal ? "待还款" : "已结清"
            )
        }

        if normalizedTotalAmount > .zero {
            let repaymentId = "loan_repay_\(Int64((settlement.occurredAt.timeIntervalSince1970 * 1000).rounded()))_\(NSDecimalNumber(decimal: normalizedTotalAmount).stringValue.replacingOccurrences(of: ".", with: "_"))"
            LoanAccountRecordHistoryStore.recordRepayment(
                userId: currentUserTransferUserId,
                repaymentId: repaymentId,
                borrowId: targetBorrowId,
                amount: normalizedTotalAmount,
                occurredAt: settlement.occurredAt,
                statusText: "已还款"
            )
        }

        latestLoanBorrowResult = LoanAccountSyntheticSnapshotStore.loadBorrowResult(userId: currentUserTransferUserId)
        if let activeLoanRepayBorrowId,
           LoanAccountSyntheticSnapshotStore.loadBorrowResult(
                userId: currentUserTransferUserId,
                borrowId: activeLoanRepayBorrowId
           ) == nil {
            self.activeLoanRepayBorrowId = resolvedLoanBorrowResults.first?.borrowId
        }
    }

    private var withdrawReturnPage: Page {
        switch withdrawEntrySource {
        case .balance:
            return .balance
        case .transferList:
            return .transferList
        }
    }

    @MainActor
    private func refreshAiCashSnapshot() async {
        activeAiCashSnapshotRefreshCount += 1
        defer {
            activeAiCashSnapshotRefreshCount = max(activeAiCashSnapshotRefreshCount - 1, 0)
        }

        guard let userId = currentUserTransferUserId, userId > 0 else {
            aiCashSnapshot = .empty()
            hasLoadedAiCashSnapshotFromBackend = false
            aiCashOpenFlagState = .unknown
            aiCashOpenFlagStateUserId = nil
            return
        }

        do {
            let account = try await APIClient.shared.fetchFundAccount(userId: userId)
            aiCashSnapshot = .resolved(account: account, userId: userId)
            hasLoadedAiCashSnapshotFromBackend = true
            aiCashOpenFlagState = .opened
            aiCashOpenFlagStateUserId = userId
        } catch {
            if isFundAccountNotFoundError(error) {
                aiCashSnapshot = .empty()
                hasLoadedAiCashSnapshotFromBackend = false
                aiCashOpenFlagState = .unopened
                aiCashOpenFlagStateUserId = userId
                if currentPage == .aiCash {
                    currentPage = .aiCashOpen
                }
                return
            }
            if let persistedSnapshot = AiCashAccountSnapshot.resolvedFromPersistedState(userId: userId) {
                aiCashSnapshot = persistedSnapshot
                hasLoadedAiCashSnapshotFromBackend = true
                aiCashOpenFlagState = .opened
                aiCashOpenFlagStateUserId = userId
            } else if !hasLoadedAiCashSnapshotFromBackend {
                aiCashSnapshot = .empty()
                aiCashOpenFlagState = .unknown
                aiCashOpenFlagStateUserId = userId
            }
        }
    }

    @MainActor
    private func refreshTotalAssetPageData() async {
        isTotalAssetQuerying = true
        defer {
            isTotalAssetQuerying = false
        }
        totalAssetLoadErrorMessage = nil
        async let aiCashResult: Bool = refreshAiCashSnapshotForTotalAsset()
        async let walletResult: Bool = refreshTotalAssetWalletAvailableAmount()
        let (aiCashLoaded, walletLoaded) = await (aiCashResult, walletResult)
        let hasDisplayableData = resolvedTotalAssetAmount != nil
        if !hasDisplayableData && (!aiCashLoaded || !walletLoaded) {
            totalAssetLoadErrorMessage = "查询失败，请稍后重试"
        }
    }

    @MainActor
    private func refreshAiCashSnapshotForTotalAsset() async -> Bool {
        let previousSnapshot = aiCashSnapshot
        let previousLoadedFlag = hasLoadedAiCashSnapshotFromBackend
        await refreshAiCashSnapshot()

        if aiCashSnapshot.hasTotalAmount && aiCashSnapshot.hasYesterdayIncome {
            return true
        }
        if previousSnapshot.hasTotalAmount && previousSnapshot.hasYesterdayIncome {
            aiCashSnapshot = previousSnapshot
            hasLoadedAiCashSnapshotFromBackend = previousLoadedFlag
            return true
        }
        return false
    }

    @MainActor
    private func refreshTotalAssetWalletAvailableAmount() async -> Bool {
        guard let userId = currentUserTransferUserId, userId > 0 else {
            totalAssetWalletAvailableAmount = nil
            return false
        }

        let previousAmount = totalAssetWalletAvailableAmount
        do {
            let overview = try await APIClient.shared.fetchAssetOverview(userId: String(userId))
            if let parsedAmount = parseTotalAssetAmount(overview.availableAmount) {
                totalAssetWalletAvailableAmount = parsedAmount
                return true
            }
            if let previousAmount {
                totalAssetWalletAvailableAmount = previousAmount
                return true
            }
            totalAssetWalletAvailableAmount = nil
            return false
        } catch {
            if let previousAmount {
                totalAssetWalletAvailableAmount = previousAmount
                return true
            }
            totalAssetWalletAvailableAmount = nil
            return false
        }
    }

    private func parseTotalAssetAmount(_ raw: String?) -> Decimal? {
        let normalized = raw?
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .replacingOccurrences(of: ",", with: "") ?? ""
        guard !normalized.isEmpty else {
            return nil
        }
        return Decimal(string: normalized, locale: Locale(identifier: "en_US_POSIX"))
    }

    private func applyAiCashWithdrawLocally(amount: Decimal, destinationDisplayText: String) {
        let normalizedAmount = max(amount, .zero)
        guard normalizedAmount > .zero else {
            return
        }
        aiCashSnapshot = aiCashSnapshot.applyingTransferOut(normalizedAmount)
        AiCashSyntheticSnapshotStore.save(aiCashSnapshot, userId: currentUserTransferUserId)
        let destination = destinationDisplayText.trimmingCharacters(in: .whitespacesAndNewlines)
        if destination == "余额" {
            walletAvailableAmountDelta += normalizedAmount
        }
    }

    private func applyAiCashDepositLocally(amount: Decimal, sourceDisplayText: String, tradeNo: String) {
        let normalizedAmount = max(amount, .zero)
        guard normalizedAmount > .zero else {
            return
        }
        aiCashSnapshot = aiCashSnapshot.applyingTransferIn(normalizedAmount)
        AiCashSyntheticSnapshotStore.save(aiCashSnapshot, userId: currentUserTransferUserId)
        let source = sourceDisplayText.trimmingCharacters(in: .whitespacesAndNewlines)
        if source.contains("余额") {
            walletAvailableAmountDelta -= normalizedAmount
        }
    }

    private func openWithdraw(from source: WithdrawEntrySource, preferredToolCode: String? = nil) {
        withdrawEntrySource = source
        preferredWithdrawToolCode = normalizedPreferredWithdrawToolCode(preferredToolCode)
        currentPage = .withdraw
    }

    private func appendLocalTransferHistoryChangeIfNeeded(amount: Decimal, contact: TransferRecentContact) {
        let normalizedAmount = max(amount, .zero)
        guard normalizedAmount > .zero else {
            return
        }

        let occurredAt = currentOccurredAtText()
        let tradeNo = "LOCAL_TRANSFER_\(Int64((Date().timeIntervalSince1970 * 1000).rounded()))"
        let displayName = contact.displayName.trimmingCharacters(in: .whitespacesAndNewlines)
        let displayTitle = displayName.isEmpty ? "转账" : "向\(displayName)转账"
        let counterpartyUserId = contact.payeeUserId > 0 ? String(contact.payeeUserId) : nil
        let counterpartyNickname = displayName.isEmpty ? nil : displayName

        let localChange = AssetChangeItemData(
            tradeNo: tradeNo,
            tradeType: "TRANSFER",
            businessSceneCode: "TRANSFER",
            direction: "DEBIT",
            signedAmount: amountTextForAssetChange(normalizedAmount),
            currencyCode: "CNY",
            counterpartyUserId: counterpartyUserId,
            counterpartyNickname: counterpartyNickname,
            counterpartyAvatarUrl: contact.avatarUrl,
            displayTitle: displayTitle,
            bankCode: nil,
            bankName: nil,
            bankCardTailNo: nil,
            occurredAt: occurredAt
        )

        transferHistorySyntheticChanges.removeAll { change in
            let title = change.displayTitle.trimmingCharacters(in: .whitespacesAndNewlines)
            let amountText = change.signedAmount.trimmingCharacters(in: .whitespacesAndNewlines)
            let counterparty = (change.counterpartyUserId ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
            return title == localChange.displayTitle
                && amountText == localChange.signedAmount
                && counterparty == (localChange.counterpartyUserId ?? "")
        }
        transferHistorySyntheticChanges.insert(localChange, at: 0)
        if transferHistorySyntheticChanges.count > 120 {
            transferHistorySyntheticChanges = Array(transferHistorySyntheticChanges.prefix(120))
        }
    }

    private func currentOccurredAtText() -> String {
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.dateFormat = "yyyy-MM-dd HH:mm:ss"
        return formatter.string(from: Date())
    }

    private func amountTextForAssetChange(_ amount: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = false
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        let number = NSDecimalNumber(decimal: amount)
        return formatter.string(from: number) ?? number.stringValue
    }

    private func normalizedPreferredWithdrawToolCode(_ toolCode: String?) -> String? {
        let normalized = toolCode?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        return normalized.isEmpty ? nil : normalized
    }

    private func preferredWithdrawToolCode(for card: CashierPayToolData) -> String? {
        let normalizedCardType = card.cardType?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() ?? ""
        if !normalizedCardType.isEmpty && normalizedCardType != "DEBIT" {
            return nil
        }
        return normalizedPreferredWithdrawToolCode(card.toolCode)
    }

    @MainActor
    private func loadRecentContactsIfNeeded(force: Bool = false, showFailureNotice: Bool = true) async {
        if isLoadingRecentContacts {
            return
        }
        guard let userId = currentUserTransferUserId, userId > 0 else {
            recentContacts = []
            recentContactLoadError = "未找到当前登录用户"
            hasLoadedRecentContactsFromNetwork = false
            return
        }
        let requestLimit = max(1, min(recentContactsRequestedLimit, 100))
        hydrateCachedRecentContactsIfNeeded(userId: userId, requestLimit: requestLimit)
        if !force && hasLoadedRecentContactsFromNetwork && !recentContacts.isEmpty && recentContacts.allSatisfy(\.hasReadableName) {
            return
        }

        isLoadingRecentContacts = true
        recentContactLoadError = nil
        defer {
            isLoadingRecentContacts = false
        }
        do {
            let items = try await APIClient.shared.fetchRecentContacts(userId: userId, limit: requestLimit)
            applyRecentContactItems(items, requestLimit: requestLimit)
            TransferRecentContactCacheStore.save(items, userId: userId)
            hasLoadedRecentContactsFromNetwork = true
        } catch {
            if isCancellationLikeError(error) {
                return
            }
            let message = userFacingErrorMessage(error)
            recentContactsCanLoadMore = false
            hasLoadedRecentContactsFromNetwork = false
            hydrateCachedRecentContactsIfNeeded(userId: userId, requestLimit: requestLimit)
            if recentContacts.isEmpty {
                recentContactLoadError = message
                if showFailureNotice {
                    showNotice("最近联系人加载失败：\(message)")
                }
            } else {
                recentContactLoadError = nil
                if showFailureNotice {
                    showNotice("最近联系人加载失败，已显示上次结果")
                }
            }
        }
    }

    @MainActor
    private func loadMoreRecentContacts() async {
        guard !isLoadingRecentContacts else {
            return
        }
        guard recentContactsCanLoadMore else {
            return
        }
        let nextLimit = min(100, recentContactsRequestedLimit + 20)
        guard nextLimit > recentContactsRequestedLimit else {
            recentContactsCanLoadMore = false
            return
        }
        recentContactsRequestedLimit = nextLimit
        await loadRecentContactsIfNeeded(force: true)
    }

    private var hasMoreRecentContacts: Bool {
        recentContactsCanLoadMore
    }

    private var displayRecentTransferContacts: [TransferRecentContact] {
        guard !transferFriendContacts.isEmpty else {
            return recentContacts
        }
        let friendMap = Dictionary(uniqueKeysWithValues: transferFriendContacts.map { ($0.payeeUserId, $0) })
        return recentContacts.map { contact in
            guard let friendContact = friendMap[contact.payeeUserId] else {
                return contact
            }
            return contact.applyingDirectoryPresentation(from: friendContact)
        }
    }

    @MainActor
    private func prefetchRecentContactsIfNeeded() async {
        guard currentPage == .home,
              !isLoadingRecentContacts,
              !hasLoadedRecentContactsFromNetwork,
              recentContacts.isEmpty,
              currentUserTransferUserId != nil else {
            return
        }
        await loadRecentContactsIfNeeded(showFailureNotice: false)
    }

    @MainActor
    private func hydrateCachedRecentContactsIfNeeded(userId: Int64, requestLimit: Int) {
        guard recentContacts.isEmpty else {
            return
        }
        let cachedItems = TransferRecentContactCacheStore.load(userId: userId)
        guard !cachedItems.isEmpty else {
            return
        }
        applyRecentContactItems(cachedItems, requestLimit: requestLimit)
        if recentContactLoadError == "暂无最近联系人" {
            recentContactLoadError = nil
        }
    }

    @MainActor
    private func applyRecentContactItems(_ items: [RecentContactData], requestLimit: Int) {
        let displayItems = Self.displayRecentContactItems(from: items)
        recentContacts = Array(displayItems.prefix(requestLimit)).map(TransferRecentContact.init(data:))
        recentContactsCanLoadMore = requestLimit < 100 && displayItems.count >= requestLimit
        recentContactLoadError = recentContacts.isEmpty ? "暂无最近联系人" : nil
    }

    private static func displayRecentContactItems(from items: [RecentContactData]) -> [RecentContactData] {
        let sortedItems = items
            .sorted { lhs, rhs in
                let lhsDate = lhs.lastInteractionAt ?? ""
                let rhsDate = rhs.lastInteractionAt ?? ""
                if lhsDate != rhsDate {
                    return lhsDate > rhsDate
                }
                if lhs.interactionCount != rhs.interactionCount {
                    return lhs.interactionCount > rhs.interactionCount
                }
                return lhs.contactUserId < rhs.contactUserId
            }
        let transferItems = sortedItems.filter { Self.isTransferLikeRecentContactScene($0.interactionSceneCode) }
        return transferItems.isEmpty ? sortedItems : transferItems
    }

    private static func isTransferLikeRecentContactScene(_ sceneCode: String) -> Bool {
        let normalized = sceneCode.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        guard !normalized.isEmpty else {
            return false
        }
        return normalized.contains("TRANSFER")
    }

    @MainActor
    private func loadTransferFriendContactsIfNeeded(force: Bool = false) async {
        if isLoadingTransferFriendContacts {
            return
        }
        if !force && !transferFriendContacts.isEmpty && transferFriendContacts.allSatisfy(\.hasReadableName) {
            return
        }
        guard let userId = currentUserTransferUserId, userId > 0 else {
            transferFriendContacts = []
            transferFriendContactLoadError = "未找到当前登录用户"
            return
        }

        isLoadingTransferFriendContacts = true
        transferFriendContactLoadError = nil
        defer {
            isLoadingTransferFriendContacts = false
        }
        do {
            let friendItems = try await APIClient.shared.fetchFriends(userId: userId, limit: 200)
            let recentMap = Dictionary(uniqueKeysWithValues: recentContacts.map { ($0.payeeUserId, $0) })
            var seenFriendUserIds = Set<Int64>()

            transferFriendContacts = friendItems.compactMap { friend in
                guard seenFriendUserIds.insert(friend.friendUserId).inserted else {
                    return nil
                }
                let friendContact = TransferRecentContact(friend: friend)
                if let recentContact = recentMap[friend.friendUserId] {
                    return recentContact.applyingDirectoryPresentation(from: friendContact)
                }
                return friendContact
            }

            if let selected = selectedTransferContact {
                selectedTransferContact = transferFriendContacts.first(where: {
                    $0.payeeUserId == selected.payeeUserId
                }) ?? selected
            }

            if transferFriendContacts.isEmpty {
                transferFriendContactLoadError = "暂无好友"
            }
        } catch {
            if isCancellationLikeError(error) {
                return
            }
            transferFriendContacts = []
            transferFriendContactLoadError = userFacingErrorMessage(error)
        }
    }

    @MainActor
    private func loadRedPacketFriendContactsIfNeeded(force: Bool = false) async {
        if isLoadingRedPacketFriendContacts {
            return
        }
        if !force && !redPacketFriendContacts.isEmpty && redPacketFriendContacts.allSatisfy(\.hasReadableName) {
            return
        }
        guard let userId = currentUserTransferUserId, userId > 0 else {
            redPacketFriendContacts = []
            redPacketFriendContactLoadError = "未找到当前登录用户"
            return
        }

        isLoadingRedPacketFriendContacts = true
        redPacketFriendContactLoadError = nil
        defer {
            isLoadingRedPacketFriendContacts = false
        }
        do {
            let friendItems = try await APIClient.shared.fetchFriends(userId: userId, limit: 200)
            let recentMap = Dictionary(uniqueKeysWithValues: recentContacts.map { ($0.payeeUserId, $0) })
            var seenFriendUserIds = Set<Int64>()

            redPacketFriendContacts = friendItems.compactMap { friend in
                guard seenFriendUserIds.insert(friend.friendUserId).inserted else {
                    return nil
                }
                let friendContact = TransferRecentContact(friend: friend)
                if let recentContact = recentMap[friend.friendUserId] {
                    return recentContact.applyingDirectoryPresentation(from: friendContact)
                }
                return friendContact
            }

            if let selected = redPacketSelectedRecipient {
                redPacketSelectedRecipient = redPacketFriendContacts.first(where: {
                    $0.payeeUserId == selected.payeeUserId
                })
            }

            if redPacketFriendContacts.isEmpty {
                redPacketFriendContactLoadError = "暂无好友"
            }
        } catch {
            if isCancellationLikeError(error) {
                return
            }
            redPacketFriendContacts = []
            redPacketFriendContactLoadError = userFacingErrorMessage(error)
        }
    }

    @MainActor
    private func loadMessageReceivedFriendRequestCount(force: Bool = false) async {
        await loadMessageReceivedFriendRequests(force: force)
    }

    @MainActor
    private func loadMessageReceivedFriendRequests(force: Bool = false) async {
        if isLoadingMessageReceivedFriendRequests {
            return
        }
        if !force,
           isRecentlyLoaded(lastMessageReceivedFriendRequestLoadedAt, within: 20),
           !messageReceivedFriendRequests.isEmpty {
            messageReceivedFriendRequestCount = pendingFriendRequestCount(in: messageReceivedFriendRequests)
            refreshMessageTabRedDotIfNeeded()
            return
        }
        guard let userId = currentUserTransferUserId, userId > 0 else {
            messageReceivedFriendRequests = []
            messageReceivedFriendRequestLoadError = "未找到当前登录用户"
            messageReceivedFriendRequestCount = 0
            refreshMessageTabRedDotIfNeeded()
            return
        }

        isLoadingMessageReceivedFriendRequests = true
        messageReceivedFriendRequestLoadError = nil
        defer {
            isLoadingMessageReceivedFriendRequests = false
        }

        do {
            let requests = try await APIClient.shared.fetchReceivedFriendRequests(targetUserId: userId, limit: 50)
            messageReceivedFriendRequests = requests
            messageReceivedFriendRequestCount = pendingFriendRequestCount(in: requests)
            messageReceivedFriendRequestLoadError = nil
            lastMessageReceivedFriendRequestLoadedAt = Date()
            refreshMessageTabRedDotIfNeeded()
        } catch {
            if isCancellationLikeError(error) {
                return
            }
            if force { messageReceivedFriendRequests = [] }
            messageReceivedFriendRequestLoadError = userFacingErrorMessage(error)
            messageReceivedFriendRequestCount = pendingFriendRequestCount(in: messageReceivedFriendRequests)
            refreshMessageTabRedDotIfNeeded()
        }
    }

    @MainActor
    private func loadMessageRequesterDigestIfNeeded(requesterUserId: Int64) async {
        guard requesterUserId > 0 else {
            return
        }
        if messageRequesterDigests[requesterUserId] != nil {
            return
        }
        if messageRequesterProfileLoadingUserIds.contains(requesterUserId) {
            return
        }
        if messageRequesterProfileFailedUserIds.contains(requesterUserId) {
            return
        }

        messageRequesterProfileLoadingUserIds.insert(requesterUserId)
        defer {
            messageRequesterProfileLoadingUserIds.remove(requesterUserId)
        }

        do {
            let profile = try await APIClient.shared.fetchUserProfile(userId: requesterUserId)
            messageRequesterDigests[requesterUserId] = profile
            messageRequesterProfileFailedUserIds.remove(requesterUserId)
            return
        } catch {
            if isCancellationLikeError(error) {
                return
            }
        }

        guard let ownerUserId = currentUserTransferUserId, ownerUserId > 0 else {
            messageRequesterProfileFailedUserIds.insert(requesterUserId)
            return
        }

        do {
            let fallbackResults = try await APIClient.shared.searchContacts(
                ownerUserId: ownerUserId,
                keyword: String(requesterUserId),
                limit: 8
            )
            if let fallbackProfile = messageRequesterFallbackProfile(
                requesterUserId: requesterUserId,
                candidates: fallbackResults
            ) {
                messageRequesterDigests[requesterUserId] = fallbackProfile
                messageRequesterProfileFailedUserIds.remove(requesterUserId)
                return
            }
        } catch {
            if isCancellationLikeError(error) {
                return
            }
        }

        messageRequesterProfileFailedUserIds.insert(requesterUserId)
    }

    private func messageRequesterFallbackProfile(
        requesterUserId: Int64,
        candidates: [ContactSearchData]
    ) -> UserProfile? {
        let matched = candidates.first(where: { $0.userId == requesterUserId }) ?? candidates.first
        guard let matched else {
            return nil
        }
        let fallbackNickname = [
            matched.nickname,
            matched.maskedRealName,
            maskedMobileText(matched.mobile),
            matched.mobile,
            matched.aipayUid,
            String(matched.userId)
        ]
            .compactMap { value -> String? in
                let trimmed = value?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                return trimmed.isEmpty ? nil : trimmed
            }
            .first ?? "爱付用户"
        let loginId = [
            matched.mobile,
            matched.aipayUid,
            String(matched.userId)
        ]
            .compactMap { value -> String? in
                let trimmed = value?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                return trimmed.isEmpty ? nil : trimmed
            }
            .first ?? String(matched.userId)
        let aipayUid = {
            let trimmed = matched.aipayUid?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            return trimmed.isEmpty ? String(matched.userId) : trimmed
        }()

        return UserProfile(
            userId: matched.userId,
            aipayUid: aipayUid,
            loginId: loginId,
            accountStatus: "ACTIVE",
            kycLevel: "L0",
            nickname: fallbackNickname,
            avatarUrl: matched.avatarUrl,
            countryCode: nil,
            mobile: matched.mobile,
            maskedRealName: matched.maskedRealName,
            idCardNo: nil,
            gender: nil,
            region: nil,
            birthday: nil
        )
    }

    private func maskedMobileText(_ rawMobile: String?) -> String? {
        guard let rawMobile else {
            return nil
        }
        let digits = rawMobile.filter(\.isNumber)
        guard digits.count >= 7 else {
            return nil
        }
        let prefix = digits.prefix(3)
        let suffix = digits.suffix(4)
        return "\(prefix)****\(suffix)"
    }

    @MainActor
    private func handleMessageFriendRequest(request: ContactRequestData, action: String) async -> String? {
        guard let operatorUserId = currentUserTransferUserId, operatorUserId > 0 else {
            return "未找到当前登录用户"
        }
        let normalizedRequestNo = request.requestNo.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedRequestNo.isEmpty else {
            return "申请编号无效"
        }
        if handlingMessageFriendRequestNo == normalizedRequestNo {
            return nil
        }

        handlingMessageFriendRequestNo = normalizedRequestNo
        defer {
            handlingMessageFriendRequestNo = nil
        }

        do {
            try await APIClient.shared.handleFriendRequest(
                operatorUserId: operatorUserId,
                requestNo: normalizedRequestNo,
                action: action
            )
            if action == "ACCEPT" {
                await loadRedPacketFriendContactsIfNeeded(force: true)
                await loadTransferFriendContactsIfNeeded(force: true)
            }
            await loadMessageReceivedFriendRequests(force: true)
            if action == "ACCEPT" {
                await openConversationForAcceptedRequest(request)
            }
            return nil
        } catch {
            if isCancellationLikeError(error) {
                return nil
            }
            return userFacingErrorMessage(error)
        }
    }

    @MainActor
    private func openConversationForAcceptedRequest(_ request: ContactRequestData) async {
        let requesterUserId = request.requesterUserId
        guard requesterUserId > 0 else {
            return
        }

        await loadMessageConversationsIfNeeded(force: true)

        let resolvedConversation = messageConversations.first(where: {
            !$0.isMock && $0.peerUserId == requesterUserId
        }) ?? messageConversations.first(where: {
            $0.peerUserId == requesterUserId
        })

        let targetConversation: MessageConversationItem
        if let resolvedConversation {
            targetConversation = resolvedConversation
        } else {
            guard let fallbackContact = contactForAcceptedRequest(request) else {
                return
            }
            let transientConversation = MessageConversationItem(contact: fallbackContact)
            if !messageConversations.contains(where: {
                $0.conversationNo == transientConversation.conversationNo
                    && $0.peerUserId == transientConversation.peerUserId
            }) {
                messageConversations.insert(transientConversation, at: 0)
            }
            targetConversation = transientConversation
        }

        selectedMessageConversation = targetConversation
        conversationBackPage = currentPage
        currentPage = .conversationDetail
    }

    private func contactForAcceptedRequest(_ request: ContactRequestData) -> TransferRecentContact? {
        if let digest = messageRequesterDigests[request.requesterUserId] {
            return TransferRecentContact(profile: digest)
        }

        let fallbackNickname = [
            request.requesterNickname,
            request.requesterMaskedRealName,
            request.requesterMobileMasked
        ]
            .compactMap { value -> String? in
                let trimmed = value?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                return trimmed.isEmpty ? nil : trimmed
            }
            .first ?? "爱付用户"
        let fallbackAccountHint = request.requesterMobileMasked?
            .trimmingCharacters(in: .whitespacesAndNewlines)
            ?? ""
        let fallbackProfile = UserProfile(
            userId: request.requesterUserId,
            aipayUid: String(request.requesterUserId),
            loginId: fallbackAccountHint.isEmpty ? String(request.requesterUserId) : fallbackAccountHint,
            accountStatus: "ACTIVE",
            kycLevel: "L0",
            nickname: fallbackNickname,
            avatarUrl: request.requesterAvatarUrl?.trimmingCharacters(in: .whitespacesAndNewlines),
            countryCode: nil,
            mobile: nil,
            maskedRealName: request.requesterMaskedRealName?.trimmingCharacters(in: .whitespacesAndNewlines),
            idCardNo: nil,
            gender: nil,
            region: nil,
            birthday: nil
        )
        return TransferRecentContact(profile: fallbackProfile)
    }

    private func pendingFriendRequestCount(in requests: [ContactRequestData]) -> Int {
        let count = requests.reduce(into: 0) { partialResult, request in
            if request.status.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() == "PENDING" {
                partialResult += 1
            }
        }
        return max(0, count)
    }

    @MainActor
    private func openRedPacketFromConversation(_ conversation: MessageConversationItem) async {
        redPacketEntryPage = .conversationDetail
        redPacketAmountText = ""
        redPacketBlessingText = ""
        redPacketSelectedCover = RedPacketCoverOption.defaultOption

        await loadRedPacketFriendContactsIfNeeded()

        if let matchedContact = redPacketFriendContacts.first(where: { $0.payeeUserId == conversation.peerUserId }) {
            redPacketSelectedRecipient = matchedContact
            currentPage = .redPacket
            return
        }
        redPacketSelectedRecipient = nil
        currentPage = .redPacketSelectRecipient
    }

    @MainActor
    private func markConversationAsReadLocally(_ conversation: MessageConversationItem) {
        guard !conversation.isMock, !conversation.isTransient else {
            return
        }
        guard conversation.unreadCount > 0 else {
            return
        }

        messageConversations = messageConversations.map { item in
            guard item.conversationNo == conversation.conversationNo else {
                return item
            }
            return item.updatingUnreadCount(0)
        }
        if let selected = selectedMessageConversation,
           selected.conversationNo == conversation.conversationNo {
            selectedMessageConversation = selected.updatingUnreadCount(0)
        }
        refreshMessageTabRedDotIfNeeded()
    }

    @MainActor
    private func persistConversationReadIfNeeded(_ conversation: MessageConversationItem) {
        guard !conversation.isMock, !conversation.isTransient else {
            return
        }
        guard let userId = currentUserTransferUserId, userId > 0 else {
            return
        }
        Task {
            do {
                try await APIClient.shared.markConversationRead(
                    userId: userId,
                    conversationNo: conversation.conversationNo,
                    lastReadMessageId: nil
                )
                await MainActor.run {
                    self.scheduleMessageConversationLoad(force: true)
                }
            } catch {
                // ignore: unread badge local state already consumed, backend state will be corrected on next refresh
            }
        }
    }

    @MainActor
    private func handleRedPacketSendSucceeded(_ message: MessageData) async {
        redPacketHistoryData = nil
        redPacketHistoryLoadError = nil
        await loadMessageConversationsIfNeeded(force: true)

        if let refreshedConversation = messageConversations.first(where: {
            $0.conversationNo == message.conversationNo || $0.peerUserId == message.receiverUserId
        }) {
            selectedMessageConversation = refreshedConversation
        }

        if redPacketEntryPage == .conversationDetail {
            currentPage = .conversationDetail
        } else {
            currentPage = .redPacketPacked
        }
    }

