    @MainActor
    private func scheduleMessageConversationLoad(force: Bool = false) {
        if force {
            messageConversationLoadTask?.cancel()
            messageConversationLoadTask = nil
        } else if messageConversationLoadTask != nil || isLoadingMessageConversations {
            return
        }

        messageConversationLoadTask = Task { @MainActor in
            defer {
                messageConversationLoadTask = nil
            }
            await loadMessageConversationsIfNeeded(force: force)
        }
    }

    @MainActor
    private func prefetchMessageHomeIfNeeded(force: Bool = false) {
        guard currentUserTransferUserId != nil else {
            return
        }

        let shouldRefreshConversations = force || shouldForceRefreshMessageConversations || messageConversations.isEmpty
        if shouldRefreshConversations {
            scheduleMessageConversationLoad(force: force)
        }

        let shouldRefreshFriendRequests = force
            || shouldForceRefreshMessageFriendRequests
            || messageReceivedFriendRequests.isEmpty
        guard shouldRefreshFriendRequests else {
            return
        }

        Task { @MainActor in
            await loadMessageReceivedFriendRequestCount(force: force)
        }
    }

    @MainActor
    private func loadMessageConversationsIfNeeded(force: Bool = false) async {
        if isLoadingMessageConversations {
            return
        }
        let existingRealConversations = messageConversations.filter { !$0.isMock }
        if !force,
           !existingRealConversations.isEmpty,
           existingRealConversations.allSatisfy(\.hasReadableTitle),
           isRecentlyLoaded(lastMessageConversationLoadedAt, within: 12) {
            return
        }
        guard let userId = currentUserTransferUserId, userId > 0 else {
            messageConversations = []
            messageConversationLoadError = "未找到当前登录用户"
            refreshMessageTabRedDotIfNeeded()
            return
        }

        messageConversationEnrichmentTask?.cancel()
        messageConversationEnrichmentTask = nil
        isLoadingMessageConversations = true
        messageConversationLoadError = nil
        do {
            let items = try await APIClient.shared.fetchConversations(userId: userId, limit: 50)
            let normalizedItems = deduplicatedConversationData(items)
            let serverItems = normalizedItems.map(MessageConversationItem.init(data:))
            messageConversations = withDemoConversations(baseItems: serverItems, ownerUserId: userId)
            lastMessageConversationLoadedAt = Date()
            if messageConversations.isEmpty {
                messageConversationLoadError = "暂无消息会话"
            }
            refreshMessageTabRedDotIfNeeded()
            isLoadingMessageConversations = false

            guard !normalizedItems.isEmpty else {
                return
            }

            guard serverItems.contains(where: { !$0.hasReadableTitle }) else {
                return
            }

            messageConversationEnrichmentTask = Task {
                async let friendItemsTask: [ContactFriendData] = {
                    (try? await APIClient.shared.fetchFriends(userId: userId, limit: 200)) ?? []
                }()
                async let recentItemsTask: [RecentContactData] = {
                    (try? await APIClient.shared.fetchRecentContacts(userId: userId, limit: 100)) ?? []
                }()
                let (friendItems, recentItems) = await (friendItemsTask, recentItemsTask)
                if Task.isCancelled || (friendItems.isEmpty && recentItems.isEmpty) {
                    return
                }

                let friendMap = Dictionary(uniqueKeysWithValues: friendItems.map { ($0.friendUserId, $0) })
                let recentMap = Dictionary(uniqueKeysWithValues: recentItems.map { ($0.contactUserId, $0) })
                let enrichedItems = normalizedItems.map {
                    MessageConversationItem(
                        data: $0,
                        friend: friendMap[$0.peerUserId],
                        recent: recentMap[$0.peerUserId]
                    )
                }

                await MainActor.run {
                    guard !Task.isCancelled, currentUserTransferUserId == userId else {
                        return
                    }
                    messageConversations = withDemoConversations(baseItems: enrichedItems, ownerUserId: userId)
                    refreshMessageTabRedDotIfNeeded()
                }
            }
        } catch {
            if isCancellationLikeError(error) {
                isLoadingMessageConversations = false
                return
            }

            let demoItems = withDemoConversations(baseItems: [], ownerUserId: userId)
            if messageConversations.isEmpty {
                messageConversations = demoItems
            }
            messageConversationLoadError = messageConversations.isEmpty ? userFacingErrorMessage(error) : nil
            refreshMessageTabRedDotIfNeeded()
            isLoadingMessageConversations = false
        }
    }

    private var shouldPollMessageBadgeOnCurrentPage: Bool {
        guard currentUserTransferUserId != nil else {
            return false
        }
        switch currentPage {
        case .home, .finance, .video, .travel, .fund, .profile:
            return true
        case .message:
            return false
        default:
            return false
        }
    }

    private func messageUnreadConversationBadgeKeys() -> [String] {
        messageConversations
            .filter { !$0.isMock && !$0.isTransient && $0.unreadCount > 0 }
            .sorted { lhs, rhs in
                if lhs.conversationNo != rhs.conversationNo {
                    return lhs.conversationNo < rhs.conversationNo
                }
                return lhs.timestampText < rhs.timestampText
            }
            .map { item in
                let normalizedSubtitle = item.subtitle.trimmingCharacters(in: .whitespacesAndNewlines)
                return "\(item.conversationNo)#\(item.unreadCount)#\(item.timestampText)#\(normalizedSubtitle)"
            }
    }

    private func messagePendingFriendRequestBadgeKeys() -> [String] {
        messageReceivedFriendRequests
            .filter { request in
                request.status.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() == "PENDING"
            }
            .map { request in
                let requestNo = request.requestNo.trimmingCharacters(in: .whitespacesAndNewlines)
                if !requestNo.isEmpty {
                    return requestNo
                }
                return "PENDING#\(request.requesterUserId)"
            }
            .sorted()
    }

    private func messageBadgeSignature() -> String {
        let unreadKeys = messageUnreadConversationBadgeKeys()
        let pendingRequestKeys = messagePendingFriendRequestBadgeKeys()
        if unreadKeys.isEmpty && pendingRequestKeys.isEmpty {
            return ""
        }
        return "U[\(unreadKeys.joined(separator: "|"))]R[\(pendingRequestKeys.joined(separator: "|"))]"
    }

    @MainActor
    private func restoreLastSeenMessageBadgeSignature(for userId: Int64?) {
        guard let userId, userId > 0 else {
            lastSeenMessageBadgeSignature = ""
            return
        }
        let key = "\(Self.messageBadgeSeenSignatureStoragePrefix).\(userId)"
        let normalized = (UserDefaults.standard.string(forKey: key) ?? "")
            .trimmingCharacters(in: .whitespacesAndNewlines)
        lastSeenMessageBadgeSignature = normalized
    }

    @MainActor
    private func updateLastSeenMessageBadgeSignature(_ signature: String, persist: Bool) {
        lastSeenMessageBadgeSignature = signature
        guard persist, let userId = currentUserTransferUserId, userId > 0 else {
            return
        }
        let key = "\(Self.messageBadgeSeenSignatureStoragePrefix).\(userId)"
        if signature.isEmpty {
            UserDefaults.standard.removeObject(forKey: key)
        } else {
            UserDefaults.standard.set(signature, forKey: key)
        }
    }

    @MainActor
    private func consumeMessageTabRedDot() {
        messageTabHasRedDot = false
        updateLastSeenMessageBadgeSignature(messageBadgeSignature(), persist: true)
    }

    @MainActor
    private func refreshMessageTabRedDotIfNeeded() {
        let signature = messageBadgeSignature()
        if currentPage == .message {
            messageTabHasRedDot = false
            updateLastSeenMessageBadgeSignature(signature, persist: true)
            return
        }
        guard !signature.isEmpty else {
            messageTabHasRedDot = false
            updateLastSeenMessageBadgeSignature("", persist: true)
            return
        }
        if lastSeenMessageBadgeSignature.isEmpty {
            messageTabHasRedDot = true
            updateLastSeenMessageBadgeSignature(signature, persist: false)
            return
        }
        if signature != lastSeenMessageBadgeSignature {
            messageTabHasRedDot = true
            updateLastSeenMessageBadgeSignature(signature, persist: false)
        }
    }

    private func deduplicatedConversationData(_ items: [ConversationData]) -> [ConversationData] {
        if items.isEmpty {
            return []
        }
        let sorted = items.sorted { lhs, rhs in
            let lhsOrder = normalizedConversationSortText(lhs.lastMessageAt ?? lhs.updatedAt)
            let rhsOrder = normalizedConversationSortText(rhs.lastMessageAt ?? rhs.updatedAt)
            if lhsOrder != rhsOrder {
                return lhsOrder > rhsOrder
            }
            return lhs.conversationNo > rhs.conversationNo
        }
        var result: [ConversationData] = []
        var seen = Set<String>()
        for item in sorted {
            let key = conversationDedupKey(for: item)
            if seen.insert(key).inserted {
                result.append(item)
            }
        }
        return result
    }

    private func conversationDedupKey(for item: ConversationData) -> String {
        let normalizedType = item.conversationType
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .uppercased()
        if normalizedType == "PRIVATE", item.peerUserId > 0 {
            return "PRIVATE:\(item.peerUserId)"
        }
        let normalizedConversationNo = item.conversationNo.trimmingCharacters(in: .whitespacesAndNewlines)
        if !normalizedConversationNo.isEmpty {
            return "CONVERSATION:\(normalizedConversationNo)"
        }
        return "\(normalizedType):\(item.userId):\(item.peerUserId)"
    }

    private var shouldForceRefreshMessageConversations: Bool {
        !isRecentlyLoaded(lastMessageConversationLoadedAt, within: 12)
    }

    private var shouldForceRefreshMessageFriendRequests: Bool {
        !isRecentlyLoaded(lastMessageReceivedFriendRequestLoadedAt, within: 20)
    }

    private func isRecentlyLoaded(_ date: Date?, within seconds: TimeInterval) -> Bool {
        guard let date else {
            return false
        }
        return Date().timeIntervalSince(date) < seconds
    }

    private func normalizedConversationSortText(_ raw: String?) -> String {
        let trimmed = raw?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if trimmed.isEmpty {
            return ""
        }
        return trimmed
            .replacingOccurrences(of: "T", with: " ")
            .replacingOccurrences(of: "Z", with: "")
    }

    private func withDemoConversations(
        baseItems: [MessageConversationItem],
        ownerUserId: Int64
    ) -> [MessageConversationItem] {
        _ = ownerUserId
        return baseItems
    }

    private var normalizedMessageSearchKeyword: String {
        messageSearchKeyword.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private var messageConversationSearchPool: [TransferRecentContact] {
        var contacts: [TransferRecentContact] = []
        var seenPeerUserIds = Set<Int64>()

        for contact in transferFriendContacts where contact.payeeUserId > 0 {
            guard seenPeerUserIds.insert(contact.payeeUserId).inserted else {
                continue
            }
            contacts.append(contact)
        }

        for contact in displayRecentTransferContacts where contact.payeeUserId > 0 {
            guard seenPeerUserIds.insert(contact.payeeUserId).inserted else {
                continue
            }
            contacts.append(contact)
        }

        for conversation in messageConversations where conversation.peerUserId > 0 {
            guard seenPeerUserIds.insert(conversation.peerUserId).inserted else {
                continue
            }
            contacts.append(TransferRecentContact(conversation: conversation))
        }

        return contacts
    }

    private var visibleMessageConversations: [MessageConversationItem] {
        let keyword = normalizedMessageSearchKeyword
        guard !keyword.isEmpty else {
            return messageConversations
        }

        var result: [MessageConversationItem] = []
        var seenPeerUserIds = Set<Int64>()

        for conversation in messageConversations where messageConversationMatchesKeyword(conversation, keyword: keyword) {
            result.append(conversation)
            if conversation.peerUserId > 0 {
                seenPeerUserIds.insert(conversation.peerUserId)
            }
        }

        for contact in messageConversationSearchPool where messageContactMatchesKeyword(contact, keyword: keyword) {
            guard seenPeerUserIds.insert(contact.payeeUserId).inserted else {
                continue
            }
            if let existingConversation = messageConversations.first(where: { $0.peerUserId == contact.payeeUserId }) {
                result.append(existingConversation)
            } else {
                result.append(MessageConversationItem(contact: contact))
            }
        }

        return result
    }

    private var messageConversationEmptyText: String {
        if !normalizedMessageSearchKeyword.isEmpty {
            return isLoadingTransferFriendContacts ? "正在搜索好友..." : "未找到匹配好友"
        }
        return messageConversationLoadError ?? "暂无消息"
    }

    private func messageConversationMatchesKeyword(_ conversation: MessageConversationItem, keyword: String) -> Bool {
        if conversation.title.localizedCaseInsensitiveContains(keyword) {
            return true
        }
        if conversation.subtitle.localizedCaseInsensitiveContains(keyword) {
            return true
        }
        return String(conversation.peerUserId).contains(keyword)
    }

    private func messageContactMatchesKeyword(_ contact: TransferRecentContact, keyword: String) -> Bool {
        if contact.displayName.localizedCaseInsensitiveContains(keyword) {
            return true
        }
        if contact.listDisplayName.localizedCaseInsensitiveContains(keyword) {
            return true
        }
        if let maskedRealName = contact.maskedRealName,
           maskedRealName.localizedCaseInsensitiveContains(keyword) {
            return true
        }
        if contact.accountHint.localizedCaseInsensitiveContains(keyword) {
            return true
        }
        if contact.summary.localizedCaseInsensitiveContains(keyword) {
            return true
        }
        return String(contact.payeeUserId).contains(keyword)
    }

