    private func messageConversationOverlay(scaleX: CGFloat, scaleY: CGFloat) -> some View {
        let panelTop = 96 * scaleY
        let panelBottom = 798 * scaleY
        let panelHeight = max(0, panelBottom - panelTop)
        let visibleItems = visibleMessageConversations
        let hasConversationItems = !visibleItems.isEmpty
        let showFriendRequestEntry = normalizedMessageSearchKeyword.isEmpty
        let showMessageHomeBundleLoading = normalizedMessageSearchKeyword.isEmpty
            && isLoadingMessageHomeBundle
            && !hasConversationItems

        return ZStack(alignment: .topLeading) {
            Color(red: 0.96, green: 0.96, blue: 0.96)
                .frame(width: baseWidth * scaleX, height: panelHeight)
                .position(x: 201 * scaleX, y: panelTop + panelHeight / 2)

            if showMessageHomeBundleLoading {
                AILoadingIndicator(text: "正在加载消息")
                    .frame(width: baseWidth * scaleX, height: panelHeight)
                    .position(x: 201 * scaleX, y: panelTop + panelHeight / 2)
                    .allowsHitTesting(false)
            } else if hasConversationItems || showFriendRequestEntry {
                ScrollView(showsIndicators: false) {
                    LazyVStack(spacing: 0) {
                        if showFriendRequestEntry {
                            messageFriendRequestEntryRow(scaleX: scaleX, scaleY: scaleY)
                        }
                        ForEach(visibleItems) { item in
                            Button(action: {
                                showMessageQuickMenu = false
                                isMessageSearchFieldFocused = false
                                markConversationAsReadLocally(item)
                                persistConversationReadIfNeeded(item)
                                selectedMessageConversation = item.unreadCount > 0 ? item.updatingUnreadCount(0) : item
                                conversationBackPage = .message
                                currentPage = .conversationDetail
                            }) {
                                MessageConversationRow(item: item)
                            }
                            .buttonStyle(.plain)
                        }
                    }
                }
                .frame(width: baseWidth * scaleX, height: panelHeight, alignment: .top)
                .position(x: 201 * scaleX, y: panelTop + panelHeight / 2)
            } else if isLoadingMessageConversations {
                AILoadingIndicator(text: "正在加载消息")
                    .frame(width: baseWidth * scaleX, height: panelHeight)
                    .position(x: 201 * scaleX, y: panelTop + panelHeight / 2)
                    .allowsHitTesting(false)
            } else if visibleItems.isEmpty {
                Text(messageConversationEmptyText)
                    .font(.system(size: 14 * min(scaleX, scaleY), weight: .regular))
                    .foregroundStyle(Color(red: 0.53, green: 0.53, blue: 0.53))
                    .frame(width: baseWidth * scaleX, height: panelHeight)
                    .position(x: 201 * scaleX, y: panelTop + panelHeight / 2)
            }

            if isLoadingMessageConversations && normalizedMessageSearchKeyword.isEmpty && hasConversationItems {
                HStack(spacing: 8 * scaleX) {
                    ProgressView()
                        .progressViewStyle(.circular)
                        .tint(Color(red: 0.48, green: 0.49, blue: 0.53))
                        .scaleEffect(min(scaleX, scaleY) * 0.72)

                    Text("消息同步中")
                        .font(.system(size: 12 * min(scaleX, scaleY), weight: .medium))
                        .foregroundStyle(Color(red: 0.41, green: 0.42, blue: 0.46))
                }
                .padding(.horizontal, 12 * scaleX)
                .frame(height: 28 * scaleY)
                .background(
                    Capsule(style: .continuous)
                        .fill(Color.white.opacity(0.92))
                )
                .overlay(
                    Capsule(style: .continuous)
                        .stroke(Color.black.opacity(0.04), lineWidth: 0.8)
                )
                .position(x: 201 * scaleX, y: (panelTop + 18) * scaleY)
                .allowsHitTesting(false)
            }
        }
    }

