    private func preferredChineseFont(size: CGFloat) -> Font {
        let candidates = [
            "MicrosoftYaHei",
            "Microsoft YaHei",
            "MicrosoftYaHei-Light",
            "MicrosoftYaHeiUI",
            "Microsoft YaHei UI",
            "PingFangSC-Regular",
            "微软雅黑"
        ]
        for name in candidates where UIFont(name: name, size: size) != nil {
            return .custom(name, size: size)
        }
        return .system(size: size, weight: .regular)
    }

    private func sanitizeMobileHallPhoneDigits(_ raw: String?) -> String {
        let digits = (raw ?? "").filter(\.isNumber)
        guard !digits.isEmpty else {
            return ""
        }
        return digits.count > 11 ? String(digits.prefix(11)) : digits
    }

    private func formattedMobileHallPhoneText(from digits: String) -> String {
        let trimmed = String(digits.prefix(11))
        switch trimmed.count {
        case 0...3:
            return trimmed
        case 4...7:
            return String(trimmed.prefix(3)) + " " + String(trimmed.dropFirst(3))
        default:
            let prefix = String(trimmed.prefix(3))
            let middleStart = trimmed.index(trimmed.startIndex, offsetBy: 3)
            let middleEnd = trimmed.index(trimmed.startIndex, offsetBy: min(7, trimmed.count))
            let middle = String(trimmed[middleStart..<middleEnd])
            let suffix = String(trimmed.dropFirst(min(7, trimmed.count)))
            return suffix.isEmpty ? prefix + " " + middle : prefix + " " + middle + " " + suffix
        }
    }

    private func seededMobileHallPhoneDigits() -> String {
        let candidates = [
            currentUserProfile?.mobile,
            currentUserProfile?.loginId
        ]
        for candidate in candidates {
            let digits = sanitizeMobileHallPhoneDigits(candidate)
            if digits.count >= 11 {
                return digits
            }
        }
        return "13900000000"
    }

    private func ensureMobileHallPhoneDigitsSeeded() {
        if mobileHallPhoneDigits.isEmpty {
            mobileHallPhoneDigits = seededMobileHallPhoneDigits()
        }
    }

    private var mobileHallPhoneTextBinding: Binding<String> {
        Binding(
            get: { formattedMobileHallPhoneText(from: mobileHallPhoneDigits) },
            set: { mobileHallPhoneDigits = sanitizeMobileHallPhoneDigits($0) }
        )
    }

