           UIImage(named: assetName) != nil {
            profileHeaderAvatarImage(Image(assetName), size: size)
        } else if let raw = currentUserProfileAvatarUrl,
                  let url = URL(string: raw) {
            AvatarRemoteImage(url: url) { image in
                profileHeaderAvatarImage(image, size: size)
