    @MainActor
    private func saveMyCardImage() {
        let authorizationStatus = PHPhotoLibrary.authorizationStatus(for: .addOnly)
        switch authorizationStatus {
        case .authorized, .limited:
            persistMyCardImageToPhotoLibrary()
        case .notDetermined:
            PHPhotoLibrary.requestAuthorization(for: .addOnly) { newStatus in
                Task { @MainActor in
                    switch newStatus {
                    case .authorized, .limited:
                        persistMyCardImageToPhotoLibrary()
                    default:
                        avatarEditorHintMessage = "未获得相册权限"
                    }
                }
            }
        default:
            avatarEditorHintMessage = "未获得相册权限"
        }
    }

    @MainActor
    private func persistMyCardImageToPhotoLibrary() {
        guard let renderedImage = renderMyCardShareImage(),
              let imageData = renderedImage.pngData() else {
            avatarEditorHintMessage = "生成名片图片失败"
            return
        }

        PHPhotoLibrary.shared().performChanges({
            let creationRequest = PHAssetCreationRequest.forAsset()
            creationRequest.addResource(with: .photo, data: imageData, options: nil)
        }) { success, _ in
            Task { @MainActor in
                avatarEditorHintMessage = success ? "名片图片已保存到相册" : "保存失败，请稍后重试"
            }
        }
    }

    @MainActor
    private func renderMyCardShareImage() -> UIImage? {
        let renderer = ImageRenderer(
            content: MyCardSaveImageView(
                userId: currentUserTransferUserId,
                displayName: currentUserProfileName,
                accountText: currentUserMyCardAccountText,
                avatarImage: myCardSnapshotAvatarImage,
                avatarUrl: currentUserProfileAvatarUrl,
                avatarAssetName: myCardSnapshotAvatarAssetName,
                avatarText: currentUserProfileAvatarText,
                avatarColor: AppTheme.palette.brandPrimaryLight,
                codeTimestamp: Date()
            )
        )
        renderer.scale = UIScreen.main.scale
        return renderer.uiImage
    }

    @MainActor
    private func handlePickedAvatarPhoto(item: PhotosPickerItem) async {
        defer {
            selectedAvatarPhotoItem = nil
        }

        do {
            guard let rawData = try await item.loadTransferable(type: Data.self),
                  let image = UIImage(data: rawData) else {
                throw APIClientError.businessError(message: "读取头像图片失败")
            }
            prepareAvatarCropEditor(with: image)
        } catch {
            avatarEditorHintMessage = userFacingErrorMessage(error)
        }
    }

    private func handleCapturedAvatarPhoto(_ image: UIImage) {
        prepareAvatarCropEditor(with: image)
    }

    @MainActor
    private func prepareAvatarCropEditor(with image: UIImage) {
        avatarCropSourceImage = normalizedAvatarEditingImage(image)
        avatarCropZoom = 1
        avatarCropCommittedZoom = 1
        avatarCropOffset = .zero
        avatarCropCommittedOffset = .zero
        currentPage = .avatarCropEditor
    }

    private func cancelAvatarCropEditing() {
        avatarCropSourceImage = nil
        avatarCropZoom = 1
        avatarCropCommittedZoom = 1
        avatarCropOffset = .zero
        avatarCropCommittedOffset = .zero
        currentPage = .avatarEditor
    }

    @MainActor
    private func applyAvatarCrop(cropSide: CGFloat) {
        guard let sourceImage = avatarCropSourceImage else {
            currentPage = .avatarEditor
            return
        }

        let effectiveScale = avatarCropEffectiveScale(for: sourceImage, cropSide: cropSide)
        let clampedOffset = avatarCropClampedOffset(
            avatarCropOffset,
            imageSize: sourceImage.size,
            cropSide: cropSide,
            effectiveScale: effectiveScale
        )
        let sourceCropSide = cropSide / effectiveScale
        let maxOriginX = max(0, sourceImage.size.width - sourceCropSide)
        let maxOriginY = max(0, sourceImage.size.height - sourceCropSide)
        let originX = min(max((sourceImage.size.width - sourceCropSide) / 2 - clampedOffset.width / effectiveScale, 0), maxOriginX)
        let originY = min(max((sourceImage.size.height - sourceCropSide) / 2 - clampedOffset.height / effectiveScale, 0), maxOriginY)
        let cropRect = CGRect(x: originX, y: originY, width: sourceCropSide, height: sourceCropSide)

        let format = UIGraphicsImageRendererFormat.default()
        format.scale = 1
        format.opaque = true
        let outputSize = CGSize(width: 720, height: 720)
        let cropped = UIGraphicsImageRenderer(size: outputSize, format: format).image { _ in
            sourceImage.draw(
                in: CGRect(
                    x: -cropRect.minX * outputSize.width / cropRect.width,
                    y: -cropRect.minY * outputSize.height / cropRect.height,
                    width: sourceImage.size.width * outputSize.width / cropRect.width,
                    height: sourceImage.size.height * outputSize.height / cropRect.height
                )
            )
        }

        Task {
            await persistAvatarCropResult(cropped)
        }
    }

    @MainActor
    private func persistAvatarCropResult(_ cropped: UIImage) async {
        guard let userId = currentUserTransferUserId else {
            currentPage = .avatarEditor
            avatarEditorHintMessage = "用户标识无效"
            return
        }
        guard let imageData = cropped.jpegData(compressionQuality: 0.92), !imageData.isEmpty else {
            currentPage = .avatarEditor
            avatarEditorHintMessage = "头像图片保存失败"
            return
        }

        isSavingAvatar = true
        defer {
            isSavingAvatar = false
        }

        do {
            let persistedUserId = try await resolvedAvatarPersistUserId(from: userId)
            let previousAvatarURL = currentUserProfileAvatarUrl
            let uploadedAsset = try await APIClient.shared.uploadImage(
                ownerUserId: persistedUserId,
                imageData: imageData,
                fileName: "avatar-\(persistedUserId).jpg",
                mimeType: "image/jpeg"
            )
            let persistedAvatarUrl = avatarPersistedContentURLString(from: uploadedAsset)
            try await APIClient.shared.updateUserAvatar(userId: persistedUserId, avatarUrl: persistedAvatarUrl)
            persistedCurrentUserAvatarImage = savePersistedCurrentUserAvatarImage(
                cropped,
                for: persistedUserId,
                avatarUrl: persistedAvatarUrl
            )
            AvatarImageCacheStore.shared.replaceAvatar(
                oldURLString: previousAvatarURL,
                newURLString: persistedAvatarUrl,
                newImage: cropped
            )
            avatarDraftImage = cropped
            let fallbackUpdatedProfile = currentUserProfile.map {
                updatedUserProfile($0, userId: persistedUserId, avatarUrl: persistedAvatarUrl)
            }
            currentPage = .personalInfo
            avatarCropSourceImage = nil
            avatarCropZoom = 1
            avatarCropCommittedZoom = 1
            avatarCropOffset = .zero
            avatarCropCommittedOffset = .zero

            Task {
                if let refreshedProfile = try? await APIClient.shared.fetchUserProfile(userId: persistedUserId) {
                    await MainActor.run {
                        appState.updateCurrentUserProfile(refreshedProfile)
                    }
                } else if let fallbackUpdatedProfile {
                    await MainActor.run {
                        appState.updateCurrentUserProfile(fallbackUpdatedProfile)
                    }
                }
            }
        } catch {
            avatarEditorHintMessage = avatarSaveUserFacingErrorMessage(error)
        }
    }

    private func avatarSaveUserFacingErrorMessage(_ error: Error) -> String {
        let normalized = userFacingErrorMessage(error).trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalized.isEmpty else {
            return "头像保存失败，请稍后重试"
        }
        let lowered = normalized.lowercased()
        if normalized.contains("账单服务")
            || normalized.contains("服务暂不可用")
            || normalized.contains("无法连接服务")
            || lowered.contains("upload image failed")
            || normalized.contains("上传图片失败") {
            return "头像保存失败，服务暂不可用，请稍后重试"
        }
        return normalized
    }

    private func avatarPersistedContentURLString(from asset: MediaAssetData) -> String {
        let trimmedContentUrl = asset.contentUrl?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if !trimmedContentUrl.isEmpty {
            return trimmedContentUrl
        }
        if let absoluteContentURL = APIClient.shared.mediaContentURL(mediaId: asset.mediaId)?.absoluteString,
           !absoluteContentURL.isEmpty {
            return absoluteContentURL
        }
        return "/bff/media/\(asset.mediaId)/content"
    }

    private func persistedCurrentUserAvatarFileURL(for userId: Int64, avatarUrl: String?) -> URL? {
        guard userId > 0 else {
            return nil
        }
        let baseFolder = FileManager.default.urls(for: .applicationSupportDirectory, in: .userDomainMask).first
            ?? FileManager.default.urls(for: .cachesDirectory, in: .userDomainMask).first
            ?? URL(fileURLWithPath: NSTemporaryDirectory(), isDirectory: true)
        let folder = baseFolder.appendingPathComponent("UserAvatarCache", isDirectory: true)
        let normalizedAvatarUrl = avatarUrl?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let versionToken = normalizedAvatarUrl.isEmpty ? "default" : stableAvatarCacheVersionToken(for: normalizedAvatarUrl)
        return folder.appendingPathComponent("avatar-\(userId)-\(versionToken).jpg")
    }

    private func stableAvatarCacheVersionToken(for raw: String) -> String {
        var hash: UInt64 = 1_469_598_103_934_665_603
        for byte in raw.utf8 {
            hash ^= UInt64(byte)
            hash &*= 1_099_511_628_211
        }
        return String(hash, radix: 16)
    }

    private func loadPersistedCurrentUserAvatarImage(for userId: Int64, avatarUrl: String?) -> UIImage? {
        guard let fileURL = persistedCurrentUserAvatarFileURL(for: userId, avatarUrl: avatarUrl),
              FileManager.default.fileExists(atPath: fileURL.path) else {
            return nil
        }
        return UIImage(contentsOfFile: fileURL.path)
    }

    private func savePersistedCurrentUserAvatarImage(_ image: UIImage, for userId: Int64, avatarUrl: String?) -> UIImage? {
        guard let fileURL = persistedCurrentUserAvatarFileURL(for: userId, avatarUrl: avatarUrl) else {
            return nil
        }
        let folderURL = fileURL.deletingLastPathComponent()
        do {
            try FileManager.default.createDirectory(at: folderURL, withIntermediateDirectories: true)
            guard let data = image.jpegData(compressionQuality: 0.92) else {
                return image
            }
            try data.write(to: fileURL, options: .atomic)
            return UIImage(data: data) ?? image
        } catch {
            return image
        }
    }

    @MainActor
    private func syncCurrentUserAvatarCacheIfNeeded() async {
        guard let userId = currentUserTransferUserId, userId > 0 else {
            persistedCurrentUserAvatarImage = nil
            return
        }

        if !shouldUsePersistedCurrentUserAvatarImage {
            persistedCurrentUserAvatarImage = nil
            return
        }

        if let localImage = loadPersistedCurrentUserAvatarImage(for: userId, avatarUrl: currentUserProfileAvatarUrl) {
            persistedCurrentUserAvatarImage = localImage
            AvatarImageCacheStore.shared.store(image: localImage, forURLString: currentUserProfileAvatarUrl)
            return
        }

        guard let rawAvatarURL = currentUserProfileAvatarUrl,
              let avatarURL = URL(string: rawAvatarURL),
              let scheme = avatarURL.scheme?.lowercased(),
              scheme == "http" || scheme == "https" else {
            persistedCurrentUserAvatarImage = nil
            return
        }

        do {
            let (data, response) = try await URLSession.shared.data(from: avatarURL)
            if let http = response as? HTTPURLResponse, !(200..<300).contains(http.statusCode) {
                persistedCurrentUserAvatarImage = nil
                return
            }
            guard let downloadedImage = UIImage(data: data) else {
                persistedCurrentUserAvatarImage = nil
                return
            }
            persistedCurrentUserAvatarImage = savePersistedCurrentUserAvatarImage(
                downloadedImage,
                for: userId,
                avatarUrl: currentUserProfileAvatarUrl
            )
            AvatarImageCacheStore.shared.store(image: downloadedImage, forURLString: currentUserProfileAvatarUrl)
        } catch {
            persistedCurrentUserAvatarImage = nil
        }
    }

