    private func resolvedAvatarPersistUserId(from currentUserId: Int64) async throws -> Int64 {
        do {
            _ = try await APIClient.shared.fetchUserProfile(userId: currentUserId)
            return currentUserId
        } catch {
            guard isUserNotFoundError(error) else {
                throw error
            }
            guard let profile = currentUserProfile else {
                throw error
            }
            let normalizedLoginId = normalizedMainlandMobileLoginId(profile.loginId)
                ?? normalizedMainlandMobileLoginId(profile.mobile)
            guard let normalizedLoginId else {
                throw error
            }

            if let existingProfile = try? await APIClient.shared.fetchUserProfile(loginId: normalizedLoginId) {
                appState.updateCurrentUserProfile(existingProfile)
                return existingProfile.userId
            }

            let nickname = normalizedProfileText(profile.nickname) ?? currentUserProfileName
            let maskedRealName = normalizedProfileText(profile.maskedRealName)
            let idCardNo = normalizedProfileText(profile.idCardNo)?.uppercased()

            do {
                let newUserId = try await APIClient.shared.createRegisteredUser(
                    loginId: normalizedLoginId,
                    nickname: nickname,
                    mobile: normalizedLoginId,
                    loginPassword: "888888",
                    realName: maskedRealName,
                    idCardNo: idCardNo
                )
                if let refreshedProfile = try? await APIClient.shared.fetchUserProfile(userId: newUserId) {
                    appState.updateCurrentUserProfile(refreshedProfile)
                } else {
                    appState.updateCurrentUserProfile(
                        updatedUserProfile(profile, userId: newUserId)
                    )
                }
                return newUserId
            } catch let createError {
                guard isUserAlreadyExistsError(createError) else {
                    throw createError
                }
                if let existingProfile = try? await APIClient.shared.fetchUserProfile(loginId: normalizedLoginId) {
                    appState.updateCurrentUserProfile(existingProfile)
                    return existingProfile.userId
                }
                let session = try await APIClient.shared.mobileVerifyLogin(
                    loginId: normalizedLoginId,
                    deviceId: appState.deviceId
                )
                appState.onLoginSuccess(session)
                return session.user.userId
            }
        }
    }

    private func isUserNotFoundError(_ error: Error) -> Bool {
        let normalized = userFacingErrorMessage(error)
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased()
        if normalized.contains("未找到用户")
            || normalized.contains("未找到user")
            || normalized.contains("未找到 user")
            || normalized.contains("user not found")
            || normalized.contains("用户不存在") {
            return true
        }
        return error.localizedDescription.lowercased().contains("user not found")
    }

    private func isUserAlreadyExistsError(_ error: Error) -> Bool {
        let normalized = userFacingErrorMessage(error)
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased()
        if normalized.contains("已存在")
            || normalized.contains("already exists")
            || normalized.contains("duplicate entry") {
            return true
        }
        return error.localizedDescription.lowercased().contains("duplicate entry")
    }

    private func normalizedMainlandMobileLoginId(_ raw: String?) -> String? {
        guard let raw else {
            return nil
        }
        let trimmed = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else {
            return nil
        }

        var converted = ""
        for scalar in trimmed.unicodeScalars {
            if scalar.value >= 0xFF10 && scalar.value <= 0xFF19,
               let asciiScalar = UnicodeScalar(scalar.value - 0xFF10 + 0x30) {
                converted.unicodeScalars.append(asciiScalar)
            } else {
                converted.unicodeScalars.append(scalar)
            }
        }

        var digits = converted.replacingOccurrences(of: "[^0-9]", with: "", options: .regularExpression)
        if digits.count == 13 && digits.hasPrefix("86") {
            digits = String(digits.dropFirst(2))
        } else if digits.count == 15 && digits.hasPrefix("0086") {
            digits = String(digits.dropFirst(4))
        }
        guard digits.range(of: "^1[3-9][0-9]{9}$", options: .regularExpression) != nil else {
            return nil
        }
        return digits
    }

    private func avatarCropViewportSide(containerSize: CGSize) -> CGFloat {
        let horizontal = max(240, containerSize.width - 46)
        let vertical = max(240, containerSize.height - 310)
        return min(horizontal, vertical)
    }

    private func avatarCropEffectiveScale(for image: UIImage, cropSide: CGFloat, zoom: CGFloat? = nil) -> CGFloat {
        let resolvedZoom = zoom ?? avatarCropZoom
        guard image.size.width > 0, image.size.height > 0 else {
            return resolvedZoom
        }
        let fillScale = max(cropSide / image.size.width, cropSide / image.size.height)
        return fillScale * resolvedZoom
    }

    private func avatarCropClampedOffset(
        _ proposed: CGSize,
        imageSize: CGSize,
        cropSide: CGFloat,
        effectiveScale: CGFloat
    ) -> CGSize {
        let displayedWidth = imageSize.width * effectiveScale
        let displayedHeight = imageSize.height * effectiveScale
        let maxOffsetX = max((displayedWidth - cropSide) / 2, 0)
        let maxOffsetY = max((displayedHeight - cropSide) / 2, 0)
        return CGSize(
            width: min(max(proposed.width, -maxOffsetX), maxOffsetX),
            height: min(max(proposed.height, -maxOffsetY), maxOffsetY)
        )
    }

    private func normalizedAvatarEditingImage(_ image: UIImage) -> UIImage {
        guard image.imageOrientation != .up else {
            return image
        }
        let format = UIGraphicsImageRendererFormat.default()
        format.scale = 1
        format.opaque = true
        return UIGraphicsImageRenderer(size: image.size, format: format).image { _ in
            image.draw(in: CGRect(origin: .zero, size: image.size))
        }
    }

