    private func normalizedProfileText(_ raw: String?) -> String? {
        let trimmed = raw?.trimmingCharacters(in: .whitespacesAndNewlines)
        if let trimmed, !trimmed.isEmpty {
            return trimmed
        }
        return nil
    }

    private func maskedMobileText(from raw: String?) -> String? {
        guard let normalized = normalizedProfileText(raw) else {
            return nil
        }
        if normalized.contains("*") {
            return normalized
        }

        let allowedCharacters = CharacterSet.decimalDigits.union(CharacterSet(charactersIn: "+- ()"))
        if normalized.rangeOfCharacter(from: allowedCharacters.inverted) != nil {
            return nil
        }

        let digits = normalized.filter(\.isNumber)
        guard digits.count >= 7 else {
            return nil
        }

        let mobile = digits.count >= 11 ? String(digits.suffix(11)) : digits
        let prefix = String(mobile.prefix(3))
        let suffix = String(mobile.suffix(2))
        let starCount = max(4, mobile.count - 5)
        return prefix + String(repeating: "*", count: starCount) + suffix
    }

    private func maskedPersonalInfoAccount(_ raw: String?) -> String? {
        guard let normalized = normalizedProfileText(raw) else {
            return nil
        }
        if normalized.contains("*") {
            return normalized
        }
        if let atIndex = normalized.firstIndex(of: "@") {
            let localPart = String(normalized[..<atIndex])
            let domainPart = String(normalized[normalized.index(after: atIndex)...])
            guard !localPart.isEmpty, !domainPart.isEmpty else {
                return normalized
            }
            let prefixCount = min(3, max(1, localPart.count - 1))
            return String(localPart.prefix(prefixCount)) + "***@" + domainPart
        }

        let digits = normalized.filter(\.isNumber)
        if digits.count >= 7 && digits.count <= 11, let maskedMobile = maskedMobileText(from: normalized) {
            return maskedMobile
        }

        if normalized.count > 8 {
            return String(normalized.prefix(4)) + "***" + String(normalized.suffix(4))
        }
        if normalized.count > 4 {
            return String(normalized.prefix(2)) + "***" + String(normalized.suffix(2))
        }
        return normalized
    }

