private struct HomeSearchPageView: View {
    @Binding var keyword: String
    let historyKeywords: [String]
    let sections: [SearchSectionData]
    let isLoading: Bool
    let loadErrorMessage: String?
    let onBack: () -> Void
    let onCommitKeyword: (String) -> Void
    let onDeleteHistoryKeyword: (String) -> Void
    let onSearch: @MainActor (String) async -> Void
    let onSelectResult: @MainActor (SearchResultItemData) async -> Void

    @FocusState private var isSearchFieldFocused: Bool
    @State private var didAutoFocus = false
    @State private var isHistoryEditing = false

    private var normalizedKeyword: String {
        keyword.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    var body: some View {
        GeometryReader { proxy in
            let topInset = max(proxy.safeAreaInsets.top, 44)

            ZStack(alignment: .top) {
                LinearGradient(
                    colors: [
                        Color(red: 0.94, green: 0.97, blue: 1.00),
                        Color(red: 0.98, green: 0.99, blue: 1.00)
                    ],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
                .ignoresSafeArea()

                VStack(spacing: 0) {
                    topBar(topInset: topInset)
                    content
                }
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .task(id: normalizedKeyword) {
            if normalizedKeyword.isEmpty {
                await onSearch("")
                return
            }
            try? await Task.sleep(nanoseconds: 250_000_000)
            guard !Task.isCancelled else {
                return
            }
            await onSearch(normalizedKeyword)
        }
        .task {
            guard !didAutoFocus else {
                return
            }
            didAutoFocus = true
            try? await Task.sleep(nanoseconds: 120_000_000)
            isSearchFieldFocused = true
        }
        .onChange(of: historyKeywords.count) { _, newCount in
            if newCount == 0 {
                isHistoryEditing = false
            }
        }
    }

    private func topBar(topInset: CGFloat) -> some View {
        HStack(spacing: 10) {
            HStack(spacing: 8) {
                Image(systemName: "magnifyingglass")
                    .font(.system(size: 15, weight: .medium))
                    .foregroundStyle(Color(red: 0.49, green: 0.54, blue: 0.62))

                TextField("搜索联系人或功能", text: $keyword)
                    .font(.system(size: 16, weight: .regular))
                    .textInputAutocapitalization(.never)
                    .disableAutocorrection(true)
                    .submitLabel(.search)
                    .focused($isSearchFieldFocused)
                    .onSubmit {
                        let submittedKeyword = normalizedKeyword
                        if !submittedKeyword.isEmpty {
                            onCommitKeyword(submittedKeyword)
                        }
                        Task {
                            await onSearch(submittedKeyword)
                        }
                    }

                if isLoading {
                    ProgressView()
                        .controlSize(.small)
                        .tint(AppTheme.palette.brandPrimary)
                } else if !keyword.isEmpty {
                    Button(action: {
                        keyword = ""
                    }) {
                        Image(systemName: "xmark.circle.fill")
                            .font(.system(size: 16, weight: .regular))
                            .foregroundStyle(Color(red: 0.74, green: 0.76, blue: 0.80))
                    }
                    .buttonStyle(.plain)
                }
            }
            .padding(.horizontal, 12)
            .frame(height: 40)
            .background(
                RoundedRectangle(cornerRadius: 20, style: .continuous)
                    .fill(Color.white.opacity(0.96))
            )
            .overlay(
                RoundedRectangle(cornerRadius: 20, style: .continuous)
                    .stroke(Color.black.opacity(0.05), lineWidth: 0.8)
            )

            Button(action: onBack) {
                Text("取消")
                    .font(.system(size: 16, weight: .regular))
                    .foregroundStyle(Color(red: 0.24, green: 0.27, blue: 0.33))
            }
            .buttonStyle(.plain)
        }
        .padding(.top, topInset + 4)
        .padding(.horizontal, 14)
        .padding(.bottom, 12)
        .background(
            LinearGradient(
                colors: [
                    AppTheme.palette.brandPrimaryPressed,
                    AppTheme.palette.brandPrimary
                ],
                startPoint: .leading,
                endPoint: .trailing
            )
            .opacity(0.94)
        )
    }

    @ViewBuilder
    private var content: some View {
        if normalizedKeyword.isEmpty {
            historyContent
        } else if isLoading && sections.isEmpty {
            VStack(spacing: 12) {
                ProgressView()
                    .controlSize(.regular)
                    .tint(AppTheme.palette.brandPrimary)
                Text("正在搜索“\(normalizedKeyword)”")
                    .font(.system(size: 14, weight: .regular))
                    .foregroundStyle(Color(red: 0.45, green: 0.49, blue: 0.56))
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity)
        } else if let loadErrorMessage, sections.isEmpty {
            VStack(spacing: 12) {
                Image(systemName: "exclamationmark.bubble")
                    .font(.system(size: 30, weight: .medium))
                    .foregroundStyle(Color(red: 0.87, green: 0.53, blue: 0.29))
                Text(loadErrorMessage)
                    .font(.system(size: 14, weight: .regular))
                    .foregroundStyle(Color(red: 0.46, green: 0.49, blue: 0.55))
                    .multilineTextAlignment(.center)
                    .padding(.horizontal, 28)
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity)
        } else if sections.isEmpty {
            VStack(spacing: 12) {
                Image(systemName: "magnifyingglass.circle")
                    .font(.system(size: 30, weight: .regular))
                    .foregroundStyle(Color(red: 0.55, green: 0.61, blue: 0.70))
                Text("没有找到“\(normalizedKeyword)”相关结果")
                    .font(.system(size: 15, weight: .medium))
                    .foregroundStyle(Color(red: 0.25, green: 0.29, blue: 0.35))
                Text("可以试试联系人姓名、昵称、手机号，或常用功能名称。")
                    .font(.system(size: 13, weight: .regular))
                    .foregroundStyle(Color(red: 0.54, green: 0.58, blue: 0.64))
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity)
        } else {
            ScrollView(showsIndicators: false) {
                LazyVStack(alignment: .leading, spacing: 16) {
                    ForEach(sections) { section in
                        sectionCard(section)
                    }
                }
                .padding(.horizontal, 16)
