                                Text("完成")
                                    .font(.system(size: 14, weight: .medium))
                                    .foregroundStyle(Color(red: 0.26, green: 0.31, blue: 0.39))
                            } else {
                                Image(systemName: "trash")
                                    .font(.system(size: 15, weight: .medium))
                                    .foregroundStyle(Color(red: 0.52, green: 0.57, blue: 0.65))
