    private func historyChip(_ historyKeyword: String) -> some View {
        HStack(spacing: 3) {
            Text(historyKeyword)
                .font(.system(size: 14, weight: .regular))
                .foregroundStyle(Color(red: 0.24, green: 0.27, blue: 0.33))
                .lineLimit(nil)
                .multilineTextAlignment(.leading)
                .fixedSize(horizontal: false, vertical: true)

            if isHistoryEditing {
                Button(action: {
                    onDeleteHistoryKeyword(historyKeyword)
                }) {
                    Image(systemName: "xmark.circle.fill")
                        .font(.system(size: 14, weight: .regular))
                        .foregroundStyle(Color(red: 0.72, green: 0.75, blue: 0.79))
                }
                .buttonStyle(.plain)
                .accessibilityIdentifier("home_search_history_delete_\(historyKeyword)")
            }
        }
        .padding(.horizontal, 8)
        .padding(.vertical, 6)
        .frame(minHeight: 30)
        .background(
            Capsule(style: .continuous)
                .fill(Color.white.opacity(0.95))
        )
        .overlay(
            Capsule(style: .continuous)
                .stroke(Color.black.opacity(0.05), lineWidth: 0.6)
        )
        .contentShape(Capsule(style: .continuous))
        .onTapGesture {
            guard !isHistoryEditing else {
                return
            }
            keyword = historyKeyword
            onCommitKeyword(historyKeyword)
            Task {
                await onSearch(historyKeyword)
            }
        }
        .accessibilityIdentifier("home_search_history_item_\(historyKeyword)")
    }

