                        Capsule(style: .continuous)
                            .fill(Color(red: 0.92, green: 0.96, blue: 1.00))
                    )
            }

            VStack(spacing: 0) {
                ForEach(Array(section.items.enumerated()), id: \.element.id) { index, item in
                    Button(action: {
                        if !normalizedKeyword.isEmpty {
