    private func resultRow(_ item: SearchResultItemData) -> some View {
        HStack(alignment: .center, spacing: 12) {
            if item.isContactResult {
                ContactAvatarView(
                    avatarUrl: item.avatarUrl,
                    avatarAssetName: seededContactAvatarAssetName(seed: item.resolvedUserId ?? 0),
                    avatarText: avatarFallbackText(for: item.title),
                    avatarColor: searchAvatarColor(seed: item.resolvedUserId ?? 0),
                    size: 44
                )
            } else {
                ZStack {
                    Circle()
                        .fill(featureIconBackgroundColor(item.icon))
                        .frame(width: 44, height: 44)

                    Image(systemName: featureIconName(item.icon))
                        .font(.system(size: 18, weight: .semibold))
                        .foregroundStyle(.white)
                }
            }

            VStack(alignment: .leading, spacing: 5) {
                HStack(spacing: 8) {
                    Text(item.title)
                        .font(.system(size: 16, weight: .medium))
                        .foregroundStyle(Color(red: 0.19, green: 0.21, blue: 0.26))
                        .lineLimit(1)

                    if let badgeText = matchedBadgeText(for: item) {
                        Text(badgeText)
                            .font(.system(size: 11, weight: .medium))
                            .foregroundStyle(
                                badgeText == "功能直达"
                                    ? Color(red: 0.86, green: 0.38, blue: 0.24)
                                    : Color(red: 0.17, green: 0.52, blue: 0.34)
                            )
                            .padding(.horizontal, 8)
                            .padding(.vertical, 2)
                            .background(
                                Capsule(style: .continuous)
                                    .fill(
                                        badgeText == "功能直达"
                                            ? Color(red: 1.00, green: 0.95, blue: 0.91)
                                            : Color(red: 0.90, green: 0.97, blue: 0.92)
                                    )
                            )
                    }
                }

                if let subtitle = item.subtitle, !subtitle.isEmpty {
                    Text(subtitle)
                        .font(.system(size: 13, weight: .regular))
                        .foregroundStyle(Color(red: 0.53, green: 0.56, blue: 0.61))
                        .lineLimit(2)
                }
            }

            Spacer(minLength: 0)

            Image(systemName: "chevron.right")
                .font(.system(size: 14, weight: .semibold))
                .foregroundStyle(Color(red: 0.76, green: 0.78, blue: 0.82))
        }
        .padding(.horizontal, 14)
        .padding(.vertical, 12)
    }

    private func matchedBadgeText(for item: SearchResultItemData) -> String? {
        if item.isFeatureResult {
            return "功能直达"
        }

        switch (item.matchedField ?? "").lowercased() {
        case "remark":
            return "匹配备注"
        case "nickname":
            return "匹配昵称"
        case "real_name":
            return "匹配实名"
        case "mobile":
            return "匹配手机号"
        default:
            return nil
        }
    }

    private func avatarFallbackText(for title: String) -> String {
        if let first = title.trimmingCharacters(in: .whitespacesAndNewlines).first {
            return String(first)
        }
        return "友"
    }

    private func searchAvatarColor(seed: Int64) -> Color {
        let normalized = abs(seed) % 360
        let hue = Double(normalized) / 360.0
        return Color(hue: hue, saturation: 0.54, brightness: 0.88)
    }

