}

private struct HomeSearchHistoryFlowLayout: Layout {
    var itemSpacing: CGFloat
    var rowSpacing: CGFloat

    init(itemSpacing: CGFloat = 4, rowSpacing: CGFloat = 4) {
        self.itemSpacing = itemSpacing
        self.rowSpacing = rowSpacing
    }

    func sizeThatFits(
        proposal: ProposedViewSize,
        subviews: Subviews,
        cache: inout Void
    ) -> CGSize {
        guard !subviews.isEmpty else {
            return .zero
        }

        let maxRowWidth = proposal.width ?? .greatestFiniteMagnitude
        let itemProposal = ProposedViewSize(
            width: maxRowWidth.isFinite ? maxRowWidth : nil,
            height: nil
        )
        var rowWidth: CGFloat = 0
        var rowHeight: CGFloat = 0
        var contentWidth: CGFloat = 0
        var contentHeight: CGFloat = 0

        for subview in subviews {
            let size = subview.sizeThatFits(itemProposal)
            let itemWidth = size.width
            let itemHeight = size.height

            if rowWidth > 0, rowWidth + itemSpacing + itemWidth > maxRowWidth {
                contentWidth = max(contentWidth, rowWidth)
                contentHeight += rowHeight + rowSpacing
                rowWidth = itemWidth
                rowHeight = itemHeight
            } else {
                rowWidth = rowWidth == 0 ? itemWidth : rowWidth + itemSpacing + itemWidth
                rowHeight = max(rowHeight, itemHeight)
            }
        }

        contentWidth = max(contentWidth, rowWidth)
        contentHeight += rowHeight

        let resolvedWidth = maxRowWidth.isFinite ? maxRowWidth : contentWidth
        return CGSize(width: resolvedWidth, height: contentHeight)
    }

    func placeSubviews(
        in bounds: CGRect,
        proposal: ProposedViewSize,
        subviews: Subviews,
        cache: inout Void
    ) {
        guard !subviews.isEmpty else {
            return
        }

        var currentX = bounds.minX
        var currentY = bounds.minY
        var currentRowHeight: CGFloat = 0
        let itemProposal = ProposedViewSize(width: bounds.width, height: nil)

        for subview in subviews {
            let size = subview.sizeThatFits(itemProposal)
            let itemWidth = size.width
            let itemHeight = size.height

            if currentX > bounds.minX, currentX + itemWidth > bounds.maxX {
                currentX = bounds.minX
                currentY += currentRowHeight + rowSpacing
                currentRowHeight = 0
            }

            subview.place(
                at: CGPoint(x: currentX, y: currentY),
                proposal: ProposedViewSize(width: itemWidth, height: itemHeight)
            )

            currentX += itemWidth + itemSpacing
            currentRowHeight = max(currentRowHeight, itemHeight)
        }
    }
}

private struct MessageMenuTriangle: Shape {
    func path(in rect: CGRect) -> Path {
        var path = Path()
        path.move(to: CGPoint(x: rect.midX, y: 0))
        path.addLine(to: CGPoint(x: rect.maxX, y: rect.maxY))
        path.addLine(to: CGPoint(x: rect.minX, y: rect.maxY))
        path.closeSubpath()
        return path
    }
    }

private func seededContactAvatarAssetName(seed: Int64) -> String {
    let avatarCount = 60
    let normalizedIndex = Int(seed.magnitude % UInt64(avatarCount)) + 1
    if normalizedIndex < 10 {
        return "ChatAvatar0\(normalizedIndex)"
    }
    return "ChatAvatar\(normalizedIndex)"
    }

private func demoAvatarAssetName(for avatarUrl: String?) -> String? {
    let normalized = avatarUrl?.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() ?? ""
    guard !normalized.isEmpty else {
        return nil
    }
    if normalized.hasSuffix("/demo-avatar/gujun.png") || normalized.contains("/demo-avatar/gujun.png?") {
        return "ProfileAvatarGuJun"
    }
    if normalized.hasSuffix("/demo-avatar/qixin.png") || normalized.contains("/demo-avatar/qixin.png?") {
        return "ProfileAvatarQiXin"
    }
    for avatarIndex in 1...60 {
        let suffix = String(format: "/demo-avatar/chat-avatar-%02d.jpg", avatarIndex)
        if normalized.hasSuffix(suffix) || normalized.contains("\(suffix)?") {
            return String(format: "ChatAvatar%02d", avatarIndex)
        }
    }
    return nil
}

private enum ContactDisplayNameResolver {
    static func preferredName(_ values: [String?], fallback: String) -> String {
        let normalizedValues = values.compactMap(normalized)
        if let readable = normalizedValues.first(where: isReadableName) {
            return readable
        }
        return normalizedValues.first ?? fallback
    }

    static func normalized(_ raw: String?) -> String? {
        let trimmed = raw?.trimmingCharacters(in: .whitespacesAndNewlines)
        if let trimmed, !trimmed.isEmpty {
            return trimmed
        }
        return nil
    }

    static func isReadableName(_ raw: String?) -> Bool {
        guard let value = normalized(raw) else {
            return false
        }
        if value.hasPrefix("用户") {
            let suffix = value.dropFirst(2)
            if !suffix.isEmpty && suffix.allSatisfy({ $0.isNumber }) {
                return false
            }
        }
        let compactValue = value.replacingOccurrences(of: " ", with: "")
        if compactValue.count >= 8 && compactValue.allSatisfy({ $0.isNumber }) {
            return false
        }
        return true
    }
}

private struct MessageConversationItem: Identifiable {
    let id: String
    let conversationNo: String
    let peerUserId: Int64
    let title: String
    let subtitle: String
    let timestampText: String
    let unreadCount: Int64
    let avatarUrl: String?
    let avatarAssetName: String?
    let avatarText: String
    let avatarColor: Color
    let isMock: Bool
    let isTransient: Bool
    var hasReadableTitle: Bool {
        ContactDisplayNameResolver.isReadableName(title)
    }

    init(data: ConversationData) {
        self.init(data: data, friend: nil, recent: nil)
    }

    init(data: ConversationData, friend: ContactFriendData?, recent: RecentContactData?) {
        let resolvedPeerUserId = Self.resolvedUserId(
            primary: data.peerUserId,
            alternative: data.peerAipayUid
        )
        self.id = data.conversationNo
        self.conversationNo = data.conversationNo
        self.peerUserId = resolvedPeerUserId

        let resolvedTitle = ContactDisplayNameResolver.preferredName(
            [
                data.peerNickname,
                friend?.nickname,
                friend?.remark,
                recent?.contactNickname,
                recent?.contactDisplayName,
                recent?.contactMaskedRealName,
                data.peerAipayUid
            ],
            fallback: "联系人"
        )
        self.title = resolvedTitle

        let preview = Self.normalized(data.lastMessagePreview)
        self.subtitle = preview ?? "[暂无消息]"

        self.timestampText = Self.toDisplayTime(data.lastMessageAt ?? data.updatedAt)
        self.unreadCount = max(0, data.unreadCount)
        self.avatarUrl = Self.normalized(data.peerAvatarUrl)
        self.avatarAssetName = nil
        self.avatarText = Self.avatarText(name: resolvedTitle)
        self.avatarColor = Self.avatarColor(seed: resolvedPeerUserId)
        self.isMock = false
        self.isTransient = false
    }

    init(mockIndex: Int, ownerUserId: Int64) {
        let peerId = 8_801_240_301_200_000 + Int64(mockIndex)
        let demoConversationNo = "mock_conversation_\(ownerUserId)_\(mockIndex)"
        let demoName = Self.demoNames[(mockIndex - 1) % Self.demoNames.count]

        self.id = demoConversationNo
        self.conversationNo = demoConversationNo
        self.peerUserId = peerId
        self.title = demoName
        self.subtitle = Self.demoPreviews[(mockIndex - 1) % Self.demoPreviews.count]
        self.timestampText = Self.demoTimestamp(offset: mockIndex)
        self.unreadCount = Int64((mockIndex % 4 == 0) ? 0 : (mockIndex % 8) + 1)
        self.avatarUrl = "https://api.dicebear.com/9.x/adventurer-neutral/png?seed=\(peerId)"
        self.avatarAssetName = nil
        self.avatarText = Self.avatarText(name: demoName)
        self.avatarColor = Self.avatarColor(seed: peerId)
        self.isMock = true
        self.isTransient = false
    }

    init(searchResult: SearchResultItemData) {
        let resolvedPeerUserId = searchResult.resolvedUserId ?? 0
        let conversationNo = "search_conversation_\(searchResult.id)"
        let resolvedTitle = ContactDisplayNameResolver.preferredName(
            [searchResult.title, searchResult.subtitle, searchResult.aipayUid],
            fallback: "联系人"
        )

        self.id = conversationNo
        self.conversationNo = conversationNo
        self.peerUserId = resolvedPeerUserId
        self.title = resolvedTitle
        self.subtitle = searchResult.subtitle ?? "[暂无消息]"
        self.timestampText = ""
        self.unreadCount = 0
        self.avatarUrl = searchResult.avatarUrl
        self.avatarAssetName = nil
        self.avatarText = Self.avatarText(name: resolvedTitle)
        self.avatarColor = Self.avatarColor(seed: resolvedPeerUserId == 0 ? Int64(abs(searchResult.id.hashValue)) : resolvedPeerUserId)
        self.isMock = false
        self.isTransient = true
    }

    init(contact: TransferRecentContact) {
        let resolvedTitle = ContactDisplayNameResolver.preferredName(
            [contact.displayName, contact.listDisplayName, contact.maskedRealName],
            fallback: "联系人"
        )
        let resolvedSubtitle = ContactDisplayNameResolver.preferredName(
            [contact.summary, contact.accountHint],
            fallback: "发起聊天"
        )
        let resolvedConversationNo = "friend_conversation_\(contact.payeeUserId)"

        self.id = resolvedConversationNo
        self.conversationNo = resolvedConversationNo
        self.peerUserId = contact.payeeUserId
        self.title = resolvedTitle
        self.subtitle = resolvedSubtitle
        self.timestampText = ""
        self.unreadCount = 0
        self.avatarUrl = contact.avatarUrl
        self.avatarAssetName = contact.avatarAssetName
        self.avatarText = contact.avatarText
        self.avatarColor = contact.avatarColor
        self.isMock = false
        self.isTransient = true
    }

    private init(
        id: String,
        conversationNo: String,
        peerUserId: Int64,
        title: String,
        subtitle: String,
        timestampText: String,
        unreadCount: Int64,
        avatarUrl: String?,
        avatarAssetName: String?,
        avatarText: String,
        avatarColor: Color,
        isMock: Bool,
        isTransient: Bool
    ) {
        self.id = id
        self.conversationNo = conversationNo
        self.peerUserId = peerUserId
        self.title = title
        self.subtitle = subtitle
        self.timestampText = timestampText
        self.unreadCount = max(0, unreadCount)
        self.avatarUrl = avatarUrl
        self.avatarAssetName = avatarAssetName
        self.avatarText = avatarText
        self.avatarColor = avatarColor
        self.isMock = isMock
        self.isTransient = isTransient
    }

    func updatingUnreadCount(_ unreadCount: Int64) -> MessageConversationItem {
        MessageConversationItem(
            id: id,
            conversationNo: conversationNo,
            peerUserId: peerUserId,
            title: title,
            subtitle: subtitle,
            timestampText: timestampText,
            unreadCount: unreadCount,
            avatarUrl: avatarUrl,
            avatarAssetName: avatarAssetName,
            avatarText: avatarText,
            avatarColor: avatarColor,
            isMock: isMock,
            isTransient: isTransient
        )
    }

    private static func normalized(_ raw: String?) -> String? {
        let trimmed = raw?.trimmingCharacters(in: .whitespacesAndNewlines)
        if let trimmed, !trimmed.isEmpty {
            return trimmed
        }
        return nil
    }

    private static func avatarText(name: String) -> String {
        if let first = name.trimmingCharacters(in: .whitespacesAndNewlines).first {
            return String(first)
        }
        return "友"
    }

    private static func avatarColor(seed: Int64) -> Color {
        let palette: [Color] = [
            Color(red: 0.64, green: 0.67, blue: 0.72),
            Color(red: 0.36, green: 0.49, blue: 0.73),
            Color(red: 0.72, green: 0.56, blue: 0.38),
            Color(red: 0.41, green: 0.62, blue: 0.57),
            Color(red: 0.56, green: 0.48, blue: 0.74)
        ]
        let index = Int(seed.magnitude % UInt64(palette.count))
        return palette[index]
    }

    private static func resolvedUserId(primary: Int64, alternative: String?) -> Int64 {
        let trimmedAlternative = alternative?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if let parsed = Int64(trimmedAlternative), parsed > 0 {
            return parsed
        }
        return primary
    }

    private static func toDisplayTime(_ raw: String?) -> String {
        let trimmed = raw?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !trimmed.isEmpty else {
            return ""
        }

        let datePart: String
        if let separatorIndex = trimmed.firstIndex(of: "T") {
            datePart = String(trimmed[..<separatorIndex])
        } else if trimmed.count >= 10 {
            datePart = String(trimmed.prefix(10))
        } else {
            return trimmed
        }

        let components = datePart.split(separator: "-", omittingEmptySubsequences: false)
        guard components.count == 3,
              let year = Int(components[0]),
              let month = Int(components[1]),
              let day = Int(components[2]) else {
            return trimmed
        }
        return "\(year % 100)/\(month)/\(day)"
    }

    private static let demoNames: [String] = [
        "林小米", "陈阿泽", "张沫沫", "许安然", "赵一诺",
        "周可可", "孙雨晴", "吴子墨", "钱乐乐", "郑明轩",
        "冯婉儿", "何嘉宁", "高小川", "郭星野", "马文昊",
        "罗雅琪", "梁北辰", "韩知夏", "宋嘉禾", "唐以宁"
    ]

    private static let demoPreviews: [String] = [
        "晚点一起吃火锅吗",
        "我把图片发你了",
        "收到的话回个表情",
        "今天的进度我整理好了",
        "明早九点线上开会",
        "这条先帮我看下",
        "那我先去处理一下",
        "可以，稍后给你回复"
    ]

    private static func demoTimestamp(offset: Int) -> String {
        let date = Date().addingTimeInterval(Double(-offset * 3600))
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "zh_CN")
        formatter.timeZone = TimeZone.current
        formatter.dateFormat = "yy/M/d"
        return formatter.string(from: date)
    }
    }

private struct MessageTabView: View {
