            Color.clear
                .frame(width: width, height: height)
                .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
        .position(x: centerX, y: centerY)
    }

    private func bottomActionHotspot(
        centerX: CGFloat,
        centerY: CGFloat,
        width: CGFloat,
        height: CGFloat,
        action: @escaping () -> Void
    ) -> some View {
        Button(action: action) {
            Color.clear
                .frame(width: width, height: height)
                .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
        .position(x: centerX, y: centerY)
    }

    private var primaryDisplayName: String {
        let values = [
            context.contact.displayName,
            profile?.nickname,
            context.conversation?.title,
            context.contact.listDisplayName
        ]
        return firstNonBlank(values) ?? "联系人"
    }

    private var nicknameText: String {
        firstNonBlank([profile?.nickname, context.contact.displayName, context.conversation?.title]) ?? "未设置"
    }

    private var accountText: String {
        if let resolved = firstNonBlank([masked(profile?.mobile), masked(profile?.loginId), masked(profile?.aipayUid)]) {
            return resolved
        }
        if let hint = sanitizedFallbackAccountHint {
            return hint
        }
        return isLoadingProfile ? "加载中" : "暂未公开"
    }

    private var realNameText: String {
        firstNonBlank([profile?.maskedRealName, context.contact.maskedRealName]) ?? "未实名"
    }

    private var resolvedAvatarURL: String? {
        firstNonBlank([profile?.avatarUrl, context.contact.avatarUrl])
    }

    private var sanitizedFallbackAccountHint: String? {
        guard let hint = firstNonBlank([context.contact.accountHint]) else {
            return nil
        }
        let lowercased = hint.lowercased()
        if lowercased.contains("conversation") || lowercased.contains("mock_") {
            return nil
        }
        return hint
    }

    private func firstNonBlank(_ values: [String?]) -> String? {
        for value in values {
            let trimmed = value?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            if !trimmed.isEmpty {
                return trimmed
            }
        }
        return nil
    }

    private func masked(_ raw: String?) -> String? {
        let trimmed = raw?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !trimmed.isEmpty else {
            return nil
        }

        let digits = trimmed.filter(\.isNumber)
        if digits.count >= 11 {
            let prefix = String(digits.prefix(3))
            let suffix = String(digits.suffix(2))
            return "\(prefix)******\(suffix)"
        }

        if trimmed.contains("@") {
            let parts = trimmed.split(separator: "@", maxSplits: 1, omittingEmptySubsequences: false)
            if parts.count == 2 {
                let local = String(parts[0])
                let domain = String(parts[1])
                let prefix = String(local.prefix(2))
                return "\(prefix)***@\(domain)"
            }
        }

        if trimmed.count >= 8 {
            let prefix = String(trimmed.prefix(3))
            let suffix = String(trimmed.suffix(2))
            return "\(prefix)******\(suffix)"
        }

        return trimmed
    }

    @MainActor
    private func loadProfile() async {
        guard !isLoadingProfile else {
            return
        }
        isLoadingProfile = true
        defer {
            isLoadingProfile = false
        }
        profile = try? await APIClient.shared.fetchUserProfile(userId: context.contact.payeeUserId)
    }
}

private struct ConversationDetailView: View {
