    let onBack: (_ shouldCleanupTransientConversation: Bool) -> Void
    let onOpenContactDetail: () -> Void
    let onOpenRedPacket: () -> Void
    let onOpenTransfer: () -> Void

    @State private var messages: [ConversationMessageItem] = []
    @State private var draftText: String = ""
    @State private var isLoading = false
    @State private var isSending = false
    @State private var isUploadingImage = false
    @State private var isVoiceInputMode = false
    @State private var isVoicePressing = false
    @State private var isRecordingVoice = false
