    @State private var currentVoiceFileURL: URL?
    @State private var showEmojiPanel = false
    @State private var showPlusPanel = false
    @State private var selectedPhotoItem: PhotosPickerItem?
    @State private var showCameraPicker = false
    @State private var loadErrorMessage: String?
    @State private var featureHintToken = UUID()
    @State private var scrollTargetId: String?
    @State private var keyboardInset: CGFloat = 0
    @State private var activeRedPacketDetail: RedPacketDetailData?
    @State private var activeRedPacketPreview: ConversationRedPacketPreview?
    @State private var isShowingRedPacketDetail = false
    @State private var isLoadingRedPacketDetail = false
    @State private var isClaimingRedPacket = false
    @State private var isRefreshingMessagesSilently = false
    @State private var isDraftInputFocused = false
    @State private var selectedEmojiCategory: EmojiCategory = .smile
    @State private var recentEmojis: [String] = ["😀", "😂", "😅", "😊", "😉", "😘", "😍", "🥳", "👍", "❤️", "🎉", "🙏"]
    private let messageRefreshTicker = Timer.publish(every: 2.0, on: .main, in: .common).autoconnect()

    init(
        conversation: MessageConversationItem,
        currentUserId: Int64,
        currentUserAvatarImage: UIImage?,
        currentUserAvatarUrl: String?,
        currentUserAvatarAssetName: String?,
        currentUserAvatarText: String,
        currentUserAvatarColor: Color,
        onConversationChanged: @escaping () -> Void,
        onBack: @escaping (_ shouldCleanupTransientConversation: Bool) -> Void,
        onOpenContactDetail: @escaping () -> Void,
        onOpenRedPacket: @escaping () -> Void,
        onOpenTransfer: @escaping () -> Void
    ) {
        self.conversation = conversation
        self.currentUserId = currentUserId
        self.currentUserAvatarImage = currentUserAvatarImage
        self.currentUserAvatarUrl = currentUserAvatarUrl
        self.currentUserAvatarAssetName = currentUserAvatarAssetName
        self.currentUserAvatarText = currentUserAvatarText
        self.currentUserAvatarColor = currentUserAvatarColor
        self.onConversationChanged = onConversationChanged
        self.onBack = onBack
        self.onOpenContactDetail = onOpenContactDetail
        self.onOpenRedPacket = onOpenRedPacket
        self.onOpenTransfer = onOpenTransfer
    }

    var body: some View {
        ZStack {
            Color(red: 0.93, green: 0.93, blue: 0.93)
                .ignoresSafeArea()

            VStack(spacing: 0) {
                topBar
                messageList
                    .padding(.top, 12)
            }
        }
        .ignoresSafeArea(.keyboard, edges: .bottom)
        .safeAreaInset(edge: .bottom) {
            VStack(spacing: 0) {
                if let loadErrorMessage, !loadErrorMessage.isEmpty {
                    statusHintBar(text: loadErrorMessage)
                }
                inputBar
                if showEmojiPanel {
                    emojiPanel
                } else if showPlusPanel {
                    plusActionPanel
                }
            }
            .padding(.bottom, composerBottomPadding)
        }
        .task(id: conversation.conversationNo) {
            await loadMessages()
        }
        .onChange(of: selectedPhotoItem) { _, newValue in
            guard let newValue else {
                return
            }
            Task {
                await handlePickedPhoto(item: newValue)
            }
        }
        .onReceive(NotificationCenter.default.publisher(for: UIResponder.keyboardWillChangeFrameNotification)) { notification in
            updateKeyboardInset(notification: notification)
        }
        .onReceive(NotificationCenter.default.publisher(for: UIResponder.keyboardWillHideNotification)) { notification in
            updateKeyboardInset(notification: notification)
        }
        .onReceive(messageRefreshTicker) { _ in
            Task { @MainActor in
                await refreshMessagesSilentlyIfNeeded()
            }
        }
        .onDisappear {
            Task {
                await finishVoiceRecording(send: false)
            }
        }
        .fullScreenCover(isPresented: $showCameraPicker) {
            CameraCapturePicker(
                onCapture: { image in
                    showCameraPicker = false
                    Task {
                        await handleCapturedPhoto(image)
                    }
                },
                onCancel: {
                    showCameraPicker = false
                }
            )
            .ignoresSafeArea()
        }
        .fullScreenCover(isPresented: $isShowingRedPacketDetail) {
            if let activeRedPacketDetail {
                ConversationRedPacketOpenView(
                    detail: activeRedPacketDetail,
                    currentUserId: currentUserId,
                    coverOption: RedPacketCoverOption.option(for: activeRedPacketDetail.coverId),
                    isClaiming: isClaimingRedPacket,
                    onClose: {
                        closeActiveRedPacketDetail()
                    },
                    onOpen: {
                        Task {
                            await claimActiveRedPacket()
                        }
                    }
                )
            } else if let activeRedPacketPreview {
                ConversationRedPacketLoadingView(
                    preview: activeRedPacketPreview,
                    onClose: {
                        closeActiveRedPacketDetail()
                    }
