                        .font(.system(size: 14, weight: .regular))
                        .foregroundStyle(Color(red: 0.54, green: 0.54, blue: 0.54))
                        .padding(.top, 48)
                } else if messages.isEmpty {
                    VStack(spacing: 10) {
                        Text("还没有聊天记录")
                            .font(.system(size: 16, weight: .semibold))
                            .foregroundStyle(Color(red: 0.28, green: 0.28, blue: 0.28))
                        Text("发一条消息，开始和\(conversation.title)聊天")
                            .font(.system(size: 13, weight: .regular))
                            .foregroundStyle(Color(red: 0.58, green: 0.58, blue: 0.58))
                    }
                    .padding(.top, 64)
                } else {
                    LazyVStack(spacing: 0) {
                        ForEach(Array(messages.enumerated()), id: \.element.id) { index, item in
                            VStack(spacing: 8) {
                                if shouldShowTime(index: index) {
                                    Text(item.timestampLabel)
                                        .font(.system(size: 11, weight: .regular))
                                        .foregroundStyle(Color(red: 0.58, green: 0.58, blue: 0.58))
                                        .padding(.top, index == 0 ? 14 : 10)
                                }

                                ConversationMessageRow(
                                    item: item,
                                    outgoingAvatarImage: currentUserAvatarImage,
                                    outgoingAvatarUrl: currentUserAvatarUrl,
                                    outgoingAvatarAssetName: currentUserAvatarAssetName,
                                    outgoingAvatarText: currentUserAvatarText,
                                    outgoingAvatarColor: currentUserAvatarColor,
                                    peerAvatarUrl: conversation.avatarUrl,
                                    peerAvatarAssetName: conversation.avatarAssetName,
                                    peerAvatarText: conversation.avatarText,
                                    peerAvatarColor: conversation.avatarColor,
                                    onTapPeerAvatar: {
                                        onOpenContactDetail()
                                    },
                                    onTapRedPacket: {
                                        Task {
                                            await openRedPacketDetail(item)
                                        }
                                    }
                                )
                                .id(item.id)
                            }
                        }
                    }
                    .padding(.bottom, 10)
                }
            }
            .onChange(of: scrollTargetId) { _, newValue in
                guard let newValue else {
                    return
                }
                withAnimation(.easeOut(duration: 0.18)) {
                    proxy.scrollTo(newValue, anchor: .bottom)
                }
            }
        }
    }

    private var inputBar: some View {
        HStack(alignment: .center, spacing: 10) {
            Button(action: {
                dismissFeatureInProgressHintIfNeeded()
                withAnimation(.easeOut(duration: 0.18)) {
                    isVoiceInputMode.toggle()
                    if isVoiceInputMode {
                        keyboardInset = 0
                        isDraftInputFocused = false
                        showEmojiPanel = false
                        showPlusPanel = false
                    } else {
                        isDraftInputFocused = true
                        if isRecordingVoice {
                            Task {
                                await finishVoiceRecording(send: false)
                            }
                        }
                    }
                }
            }) {
                Image(systemName: isVoiceInputMode ? "keyboard" : "waveform")
                    .font(.system(size: 16, weight: .medium))
                    .foregroundStyle(Color(red: 0.30, green: 0.30, blue: 0.30))
                    .frame(width: 32, height: 32)
                    .overlay(
                        Circle()
                            .stroke(Color(red: 0.62, green: 0.62, blue: 0.62), lineWidth: 1.4)
                    )
            }
            .buttonStyle(.plain)

            HStack(spacing: 6) {
                if isVoiceInputMode {
                    Text(isVoicePressing ? "松开发送语音" : "按住 说话")
                        .font(.system(size: 15, weight: .medium))
                        .foregroundStyle(Color(red: 0.22, green: 0.22, blue: 0.22))
                        .frame(maxWidth: .infinity)
                        .frame(height: 36)
                        .contentShape(Rectangle())
                        .gesture(
                            DragGesture(minimumDistance: 0)
                                .onChanged { _ in
                                    guard !isVoicePressing else {
                                        return
                                    }
                                    isVoicePressing = true
                                    Task {
                                        await beginVoiceRecording()
                                    }
                                }
                                .onEnded { _ in
                                    guard isVoicePressing else {
                                        return
                                    }
                                    isVoicePressing = false
                                    Task {
                                        await finishVoiceRecording(send: true)
                                    }
                                }
                        )
                } else {
                    VerticallyCenteredTextField(
                        text: $draftText,
                        isFocused: Binding(
                            get: { isDraftInputFocused },
                            set: { isDraftInputFocused = $0 }
                        ),
                        font: .systemFont(ofSize: 16, weight: .regular),
                        textColor: UIColor(red: 0.16, green: 0.16, blue: 0.18, alpha: 1),
                        placeholder: "发消息",
                        tintColor: UIColor(red: 0.31, green: 0.31, blue: 0.31, alpha: 1),
                        keyboardType: .default,
                        returnKeyType: .send,
                        autocapitalizationType: .sentences,
                        autocorrectionType: .yes,
                        spellCheckingType: .yes,
                        textAlignment: .left,
                        textInsets: .zero,
                        showsAccessoryToolbar: false,
                        shouldResignOnSubmit: false,
                        onSubmit: {
                            isDraftInputFocused = true
                            Task {
                                await sendTextMessage()
                            }
                        }
                    )
                        .frame(maxWidth: .infinity, minHeight: 36, alignment: .leading)
                        .simultaneousGesture(TapGesture().onEnded {
                            dismissFeatureInProgressHintIfNeeded()
                            showEmojiPanel = false
                            showPlusPanel = false
                            isDraftInputFocused = true
                        })

                    Button(action: {}) {
                        Image(systemName: "mic")
                            .font(.system(size: 14, weight: .regular))
                            .foregroundStyle(Color(red: 0.56, green: 0.56, blue: 0.56))
                    }
                }
            }
            .padding(.horizontal, 12)
            .frame(height: 36)
            .background(
                RoundedRectangle(cornerRadius: 7, style: .continuous)
                    .fill(Color.white)
            )
            .contentShape(Rectangle())
            .simultaneousGesture(TapGesture().onEnded {
                guard !isVoiceInputMode else {
                    return
                }
                dismissFeatureInProgressHintIfNeeded()
                showEmojiPanel = false
                showPlusPanel = false
                isDraftInputFocused = true
            })

            Button(action: {
                dismissFeatureInProgressHintIfNeeded()
                withAnimation(.easeOut(duration: 0.18)) {
                    if showEmojiPanel {
                        showEmojiPanel = false
                        if !isVoiceInputMode {
                            isDraftInputFocused = true
                        }
                    } else {
                        keyboardInset = 0
                        showPlusPanel = false
                        isDraftInputFocused = false
                        showEmojiPanel = true
                    }
                }
            }) {
                Image(systemName: "face.smiling")
                    .font(.system(size: 22, weight: .regular))
                    .foregroundStyle(Color(red: 0.31, green: 0.31, blue: 0.31))
                    .frame(width: 24, height: 24)
            }
            .buttonStyle(.plain)

            Button(action: {
                dismissFeatureInProgressHintIfNeeded()
                withAnimation(.easeOut(duration: 0.18)) {
                    if showPlusPanel {
                        showPlusPanel = false
                        if !isVoiceInputMode {
                            isDraftInputFocused = true
                        }
                    } else {
                        keyboardInset = 0
                        isDraftInputFocused = false
                        showEmojiPanel = false
                        showPlusPanel = true
                    }
                }
            }) {
                Image(systemName: "plus.circle")
                    .font(.system(size: 24, weight: .regular))
                    .foregroundStyle(Color(red: 0.31, green: 0.31, blue: 0.31))
                    .frame(width: 24, height: 24)
            }
            .buttonStyle(.plain)
        }
        .padding(.horizontal, 8)
        .padding(.vertical, 8)
        .frame(height: 54)
        .background(
            Color(red: 0.95, green: 0.95, blue: 0.95)
                .overlay(alignment: .top) {
                    Rectangle()
                        .fill(Color.black.opacity(0.06))
                        .frame(height: 0.6)
                }
        )
    }

    private enum EmojiCategory: String, CaseIterable {
        case recent
        case smile
        case gesture
        case animal
        case food
        case activity
        case travel
        case object
        case symbol
        case flag

        var iconName: String {
            switch self {
            case .recent:
                return "clock.arrow.circlepath"
            case .smile:
                return "face.smiling"
            case .gesture:
                return "hand.raised"
            case .animal:
                return "pawprint"
            case .food:
                return "fork.knife"
            case .activity:
                return "gamecontroller"
            case .travel:
                return "car"
            case .object:
                return "lightbulb"
            case .symbol:
                return "numbersign.circle"
            case .flag:
                return "flag"
            }
        }
    }

