    private func showFeatureInProgressHint(_ message: String) {
        let token = UUID()
        featureHintToken = token
        loadErrorMessage = message

        Task {
            try? await Task.sleep(nanoseconds: 5_000_000_000)
            await MainActor.run {
                guard featureHintToken == token, loadErrorMessage == message else {
                    return
                }
                loadErrorMessage = nil
            }
        }
    }

    private func dismissFeatureInProgressHintIfNeeded() {
        featureHintToken = UUID()
        guard let loadErrorMessage, loadErrorMessage.contains("功能开发中") else {
            return
        }
        self.loadErrorMessage = nil
    }

    private func plusActionTile(iconName: String, title: String) -> some View {
