            RoundedRectangle(cornerRadius: 11, style: .continuous)
                .fill(Color(red: 0.90, green: 0.90, blue: 0.90))
                .frame(width: 64, height: 64)
                .overlay {
                    Image(systemName: iconName)
                        .font(.system(size: 26, weight: .regular))
                        .foregroundStyle(Color(red: 0.34, green: 0.34, blue: 0.34))
                }
            Text(title)
                .font(.system(size: 13, weight: .regular))
                .foregroundStyle(Color(red: 0.49, green: 0.49, blue: 0.49))
        }
        .frame(width: 72)
    }

    private func appendEmoji(_ emoji: String) {
        dismissFeatureInProgressHintIfNeeded()
        draftText.append(emoji)
        if let index = recentEmojis.firstIndex(of: emoji) {
            recentEmojis.remove(at: index)
        }
        recentEmojis.insert(emoji, at: 0)
        if recentEmojis.count > 40 {
            recentEmojis.removeLast(recentEmojis.count - 40)
        }
    }

    private func removeLastCharacter() {
        dismissFeatureInProgressHintIfNeeded()
        guard !draftText.isEmpty else {
            return
        }
        draftText.removeLast()
    }

    private func emojis(for category: EmojiCategory) -> [String] {
        switch category {
        case .recent:
            return recentEmojis
        case .smile:
            return mergeEmojiGroups([
                emojiScalars(in: 0x1F600...0x1F64F),
                ["😶‍🌫️", "🥹", "🫠", "🫡", "🤫", "🤭", "🤗", "🤔", "🫢", "🫣", "🫨", "🥰", "😘", "😗", "😙", "😚", "😋", "😛", "😝", "😜", "🤪", "🤨", "🧐", "🤓", "😎"]
            ])
        case .gesture:
            return mergeEmojiGroups([
                emojiScalars(in: 0x1F440...0x1F64F),
                emojiScalars(in: 0x1F90C...0x1F93A),
                ["🫶", "🫰", "🫱", "🫲", "🤝", "💪", "🦾", "🧠", "👀", "🦻", "🦿", "🙏", "👏", "🙌", "🫸", "🫷"]
