                emojiScalars(in: 0x1F40A...0x1F42A),
                ["🐉", "🐲", "🦖", "🦕", "🦄", "🦭", "🪼", "🦩", "🦚", "🦜", "🐠", "🐟", "🐡", "🦈", "🐬", "🐳", "🐋"]
            ])
        case .food:
            return mergeEmojiGroups([
                emojiScalars(in: 0x1F330...0x1F37F),
