                ["🫕", "🫗", "🧋", "🍱", "🍲", "🍜", "🍣", "🍤", "🍛", "🍝", "🍕", "🍔", "🍟", "🌭", "🥪", "🌮", "🌯", "🥗", "🍿", "🍩", "🍪", "🎂", "🍰", "🍺", "🥂", "🍷", "☕️"]
