            ]
        }
    }

    private func emojiScalars(in range: ClosedRange<Int>) -> [String] {
        range.compactMap { value in
            guard let scalar = UnicodeScalar(value) else {
                return nil
            }
            let props = scalar.properties
            guard props.isEmoji, !props.isEmojiModifier else {
                return nil
            }
            if props.isEmojiPresentation || (0x2600...0x27BF).contains(value) {
                return String(scalar)
            }
            return nil
        }
    }

    private func mergeEmojiGroups(_ groups: [[String]]) -> [String] {
        var seen = Set<String>()
        var result: [String] = []
        for group in groups {
            for emoji in group where seen.insert(emoji).inserted {
                result.append(emoji)
            }
        }
        return result
    }

    private func shouldShowTime(index: Int) -> Bool {
        if index == 0 {
            return true
        }
        guard index < messages.count else {
            return false
        }
        guard let previousDate = messages[index - 1].createdDate,
              let currentDate = messages[index].createdDate else {
            return false
        }
        return currentDate.timeIntervalSince(previousDate) >= 300
    }

    @MainActor
    private func loadMessages() async {
        if isLoading {
            return
        }
        isLoading = true
        loadErrorMessage = nil

        if conversation.isTransient {
            messages = []
            scrollTargetId = nil
            isLoading = false
            return
        }

        if conversation.isMock {
            if messages.isEmpty {
                let now = Date()
                messages = [
                    ConversationMessageItem.localText(
                        content: "这是演示会话，你可以测试发送文字、emoji 和图片。",
                        isOutgoing: false,
                        timestamp: now.addingTimeInterval(-1200)
                    ),
                    ConversationMessageItem.localText(
                        content: "试试发一条消息给我～",
                        isOutgoing: false,
                        timestamp: now.addingTimeInterval(-900)
                    )
                ]
            }
            scrollTargetId = messages.last?.id
            isLoading = false
            return
        }

        do {
            let payload = try await APIClient.shared.fetchConversationMessages(
                userId: currentUserId,
                conversationNo: conversation.conversationNo,
                limit: 120
            )
            messages = payload.map { data in
                ConversationMessageItem(data: data, currentUserId: currentUserId)
            }
            scrollTargetId = messages.last?.id
            if let lastMessageId = messages.last?.id {
                try? await APIClient.shared.markConversationRead(
                    userId: currentUserId,
                    conversationNo: conversation.conversationNo,
                    lastReadMessageId: lastMessageId
                )
                onConversationChanged()
            }
        } catch {
            messages = []
            loadErrorMessage = userFacingErrorMessage(error)
        }
        isLoading = false
    }

    @MainActor
    private func refreshMessagesSilentlyIfNeeded() async {
        guard UIApplication.shared.applicationState == .active else {
            return
        }
        guard !conversation.isTransient, !conversation.isMock else {
            return
        }
        guard !isLoading, !isRefreshingMessagesSilently else {
            return
        }
        guard !isSending, !isUploadingImage, !isRecordingVoice else {
            return
        }

        isRefreshingMessagesSilently = true
        defer {
            isRefreshingMessagesSilently = false
        }

        do {
            let payload = try await APIClient.shared.fetchConversationMessages(
                userId: currentUserId,
                conversationNo: conversation.conversationNo,
                limit: 120
            )
            let refreshedItems = payload.map { data in
                ConversationMessageItem(data: data, currentUserId: currentUserId)
            }

            let currentFingerprint = conversationMessageFingerprint(messages)
            let refreshedFingerprint = conversationMessageFingerprint(refreshedItems)
            guard currentFingerprint != refreshedFingerprint else {
                return
            }

            let previousLastMessageId = messages.last?.id
            messages = refreshedItems

            guard let latestMessageId = refreshedItems.last?.id else {
                onConversationChanged()
                return
            }

            if latestMessageId != previousLastMessageId {
                scrollTargetId = latestMessageId
                await markConversationReadIfNeeded(lastReadMessageId: latestMessageId)
            }
            onConversationChanged()
        } catch {
            if isCancellationLikeError(error) {
                return
            }
            // keep silent: avoid interrupting current input when periodic sync fails
        }
    }

    private func conversationMessageFingerprint(_ items: [ConversationMessageItem]) -> String {
        guard !items.isEmpty else {
            return ""
        }
        return items.map { item in
            [
                item.id,
                item.messageType,
                item.renderText,
                item.timestampLabel,
                item.redPacketStatus ?? "",
                item.redPacketNo ?? "",
                item.transferAmountText
            ].joined(separator: "|")
        }
        .joined(separator: "||")
    }

    @MainActor
    private func openRedPacketDetail(_ item: ConversationMessageItem) async {
        dismissFeatureInProgressHintIfNeeded()
        guard item.isRedPacketMessage else {
            return
        }
        guard let redPacketNo = item.redPacketNo?.trimmingCharacters(in: .whitespacesAndNewlines),
              !redPacketNo.isEmpty else {
            loadErrorMessage = "红包数据缺失，请稍后重试"
            return
        }
        if isLoadingRedPacketDetail {
            return
        }
        activeRedPacketPreview = buildRedPacketPreview(for: item)
        activeRedPacketDetail = nil
        isShowingRedPacketDetail = true
        await Task.yield()
        isLoadingRedPacketDetail = true
        defer {
            isLoadingRedPacketDetail = false
        }

        do {
            let detail = try await APIClient.shared.fetchRedPacketDetail(
                redPacketNo: redPacketNo,
                userId: currentUserId
            )
            guard isShowingRedPacketDetail else {
                return
            }
            activeRedPacketDetail = detail
            isShowingRedPacketDetail = true
            loadErrorMessage = nil
        } catch {
            closeActiveRedPacketDetail()
            loadErrorMessage = userFacingErrorMessage(error)
        }
    }

    @MainActor
    private func claimActiveRedPacket() async {
        guard let detail = activeRedPacketDetail else {
            return
        }
        if !detail.claimableByViewer || isClaimingRedPacket {
            return
        }
        isClaimingRedPacket = true
        defer {
            isClaimingRedPacket = false
        }

        do {
            let claimedDetail = try await APIClient.shared.claimRedPacket(
                redPacketNo: detail.redPacketNo,
                userId: currentUserId
            )
            activeRedPacketDetail = claimedDetail
            loadErrorMessage = nil
            await loadMessages()
            onConversationChanged()
        } catch {
            loadErrorMessage = userFacingErrorMessage(error)
        }
    }

    @MainActor
    private func closeActiveRedPacketDetail() {
        isShowingRedPacketDetail = false
        activeRedPacketDetail = nil
        activeRedPacketPreview = nil
        isClaimingRedPacket = false
    }

    @MainActor
    private func buildRedPacketPreview(for item: ConversationMessageItem) -> ConversationRedPacketPreview {
        let presenterName = conversation.title.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
            ? "好友"
            : conversation.title.trimmingCharacters(in: .whitespacesAndNewlines)
        return ConversationRedPacketPreview(
            presenterName: presenterName,
            avatarUrl: conversation.avatarUrl,
            avatarAssetName: conversation.avatarAssetName,
            avatarText: conversation.avatarText,
            avatarColor: conversation.avatarColor,
            coverOption: RedPacketCoverOption.option(for: item.redPacketCoverId),
            blessingText: item.redPacketBlessingText
        )
    }

    @MainActor
    private func sendTextMessage() async {
        dismissFeatureInProgressHintIfNeeded()
        let trimmedText = draftText.trimmingCharacters(in: .whitespacesAndNewlines)
        if trimmedText.isEmpty || isSending {
            return
        }
        let shouldKeepDraftFocus = !isVoiceInputMode && !showEmojiPanel && !showPlusPanel
        if shouldKeepDraftFocus {
            isDraftInputFocused = true
        }

        if conversation.isMock {
            isSending = true
            let appended = ConversationMessageItem.localText(
                content: trimmedText,
                isOutgoing: true,
                timestamp: Date()
            )
            messages.append(appended)
            draftText = ""
            loadErrorMessage = "当前为演示会话，本条消息仅本地展示，未写入后端。"
            scrollTargetId = appended.id
            isSending = false
            restoreDraftFocusIfNeeded(shouldKeepDraftFocus)
            await appendMockAutoReply(trigger: trimmedText)
            return
        }

        let optimisticMessage = ConversationMessageItem.localText(
            content: trimmedText,
            isOutgoing: true,
            timestamp: Date()
        )
        let optimisticMessageId = optimisticMessage.id
        messages.append(optimisticMessage)
        draftText = ""
        loadErrorMessage = nil
        scrollTargetId = optimisticMessageId
        restoreDraftFocusIfNeeded(shouldKeepDraftFocus)

        isSending = true
        do {
            let sent = try await APIClient.shared.sendTextMessage(
                senderUserId: currentUserId,
                receiverUserId: conversation.peerUserId,
                contentText: trimmedText,
                extPayload: "{\"source\":\"ios-conversation\"}"
            )
            let appended = ConversationMessageItem(data: sent, currentUserId: currentUserId)
            if let index = messages.lastIndex(where: { $0.id == optimisticMessageId }) {
                messages[index] = appended
            } else {
                messages.append(appended)
            }
            loadErrorMessage = nil
            scrollTargetId = appended.id
            await markConversationReadIfNeeded(lastReadMessageId: appended.id)
            onConversationChanged()
        } catch {
            let reason = userFacingErrorMessage(error).trimmingCharacters(in: .whitespacesAndNewlines)
            loadErrorMessage = reason.isEmpty
                ? "消息发送失败，已本地展示。"
                : "消息发送失败，已本地展示：\(reason)"
        }
        isSending = false
        restoreDraftFocusIfNeeded(shouldKeepDraftFocus)
    }

    @MainActor
    private func restoreDraftFocusIfNeeded(_ shouldKeepDraftFocus: Bool) {
        guard shouldKeepDraftFocus else {
            return
        }
        Task { @MainActor in
            await Task.yield()
            guard !isVoiceInputMode, !showEmojiPanel, !showPlusPanel else {
                return
            }
            isDraftInputFocused = true
        }
    }

    @MainActor
    private func appendMockAutoReply(trigger: String) async {
        let trimmed = trigger.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else {
            return
        }
        try? await Task.sleep(nanoseconds: 450_000_000)
        let reply = ConversationMessageItem.localText(
            content: "收到：\(trimmed.prefix(12)) \(trimmed.count > 12 ? "…" : "")",
            isOutgoing: false,
            timestamp: Date()
        )
        messages.append(reply)
        scrollTargetId = reply.id
    }

    @MainActor
    private func beginVoiceRecording() async {
        dismissFeatureInProgressHintIfNeeded()
        if !isVoiceInputMode || isRecordingVoice || isUploadingImage || isSending {
            return
        }

        let microphoneUsage = (Bundle.main.object(forInfoDictionaryKey: "NSMicrophoneUsageDescription") as? String)?
            .trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !microphoneUsage.isEmpty else {
            loadErrorMessage = "当前安装包缺少麦克风权限配置，请重装最新版本。"
            return
        }

        let granted = await requestMicrophonePermission()
        guard granted else {
            loadErrorMessage = "请在系统设置中开启麦克风权限后再试。"
            return
        }

        do {
            let audioSession = AVAudioSession.sharedInstance()
            try audioSession.setCategory(.playAndRecord, mode: .voiceChat, options: [.defaultToSpeaker, .allowBluetooth])
            try audioSession.setActive(true, options: .notifyOthersOnDeactivation)

            let fileURL = makeVoiceRecordFileURL()
            let settings: [String: Any] = [
                AVFormatIDKey: Int(kAudioFormatMPEG4AAC),
                AVSampleRateKey: 16000,
                AVNumberOfChannelsKey: 1,
                AVEncoderAudioQualityKey: AVAudioQuality.medium.rawValue
            ]
            let recorder = try AVAudioRecorder(url: fileURL, settings: settings)
            recorder.prepareToRecord()
            guard recorder.record() else {
                throw APIClientError.businessError(message: "无法启动录音")
            }

            voiceRecorder = recorder
            currentVoiceFileURL = fileURL
            voiceRecordStartTime = Date()
            isRecordingVoice = true
            loadErrorMessage = "正在录音，松开发送。"
        } catch {
            voiceRecorder = nil
            currentVoiceFileURL = nil
            voiceRecordStartTime = nil
            isRecordingVoice = false
            loadErrorMessage = "录音失败：\(userFacingErrorMessage(error))"
            try? AVAudioSession.sharedInstance().setActive(false, options: .notifyOthersOnDeactivation)
        }
    }

    @MainActor
    private func finishVoiceRecording(send: Bool) async {
        guard isRecordingVoice else {
            return
        }

        voiceRecorder?.stop()
        let startTime = voiceRecordStartTime ?? Date()
        let duration = max(1, Int(round(Date().timeIntervalSince(startTime))))
        let fileURL = currentVoiceFileURL

        voiceRecorder = nil
        voiceRecordStartTime = nil
        isRecordingVoice = false

        try? AVAudioSession.sharedInstance().setActive(false, options: .notifyOthersOnDeactivation)

        guard send else {
            if let fileURL {
                try? FileManager.default.removeItem(at: fileURL)
            }
            loadErrorMessage = nil
            return
        }

        await sendRecordedVoiceMessage(durationSeconds: duration, localFileURL: fileURL)
    }

    @MainActor
    private func sendRecordedVoiceMessage(durationSeconds: Int, localFileURL: URL?) async {
        let durationSeconds = max(1, durationSeconds)

        if conversation.isMock {
            let localMessage = ConversationMessageItem.localVoice(
                durationSeconds: durationSeconds,
                isOutgoing: true,
                timestamp: Date(),
                localAudioURL: localFileURL
            )
            messages.append(localMessage)
            scrollTargetId = localMessage.id
            loadErrorMessage = "当前为演示会话，语音仅本地展示，未上传到后端。"
            await appendMockAutoReply(trigger: "语音")
            return
        }

        if isSending {
            return
        }
        isSending = true
        defer {
            isSending = false
        }

        let extPayload: String? = {
            let payload: [String: Any] = [
                "source": "ios-conversation",
                "voiceDurationSec": durationSeconds,
                "voiceLocalFile": localFileURL?.lastPathComponent ?? ""
            ]
            guard let data = try? JSONSerialization.data(withJSONObject: payload),
                  let text = String(data: data, encoding: .utf8) else {
                return nil
            }
            return text
        }()

        do {
            let sent = try await APIClient.shared.sendTextMessage(
                senderUserId: currentUserId,
                receiverUserId: conversation.peerUserId,
                contentText: "[语音]",
                extPayload: extPayload
            )
            let appended = ConversationMessageItem.localVoice(
                id: sent.messageId,
                durationSeconds: durationSeconds,
                isOutgoing: true,
                timestamp: Date(),
                localAudioURL: localFileURL
            )
            messages.append(appended)
            scrollTargetId = appended.id
            loadErrorMessage = nil
            await markConversationReadIfNeeded(lastReadMessageId: sent.messageId)
            onConversationChanged()
        } catch {
            let fallback = ConversationMessageItem.localVoice(
                durationSeconds: durationSeconds,
                isOutgoing: true,
                timestamp: Date(),
                localAudioURL: localFileURL
            )
            messages.append(fallback)
            scrollTargetId = fallback.id
            loadErrorMessage = "语音后端发送失败，已本地展示：\(userFacingErrorMessage(error))"
        }
    }

    private func makeVoiceRecordFileURL() -> URL {
        let folder = FileManager.default.urls(for: .cachesDirectory, in: .userDomainMask).first
            ?? URL(fileURLWithPath: NSTemporaryDirectory(), isDirectory: true)
        return folder.appendingPathComponent("voice-\(UUID().uuidString).m4a")
    }

    private func requestMicrophonePermission() async -> Bool {
        let usageText = (Bundle.main.object(forInfoDictionaryKey: "NSMicrophoneUsageDescription") as? String)?
            .trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !usageText.isEmpty else {
            return false
        }

        return await withCheckedContinuation { continuation in
            if #available(iOS 17.0, *) {
                AVAudioApplication.requestRecordPermission { granted in
                    continuation.resume(returning: granted)
                }
            } else {
                AVAudioSession.sharedInstance().requestRecordPermission { granted in
                    continuation.resume(returning: granted)
                }
            }
        }
    }

    @MainActor
    private func handlePickedPhoto(item: PhotosPickerItem) async {
        dismissFeatureInProgressHintIfNeeded()
        if isUploadingImage || isSending {
            return
        }
        isUploadingImage = true
        loadErrorMessage = nil
        defer {
            isUploadingImage = false
            selectedPhotoItem = nil
        }

        var pickedImage: UIImage?
        do {
            guard let rawData = try await item.loadTransferable(type: Data.self),
                  let image = UIImage(data: rawData) else {
                throw APIClientError.businessError(message: "读取图片失败")
            }
            pickedImage = image
            let jpegData = image.jpegData(compressionQuality: 0.85) ?? rawData

            if conversation.isMock {
                let localMessage = ConversationMessageItem.localImage(
                    image: image,
                    isOutgoing: true,
                    timestamp: Date()
                )
                messages.append(localMessage)
                loadErrorMessage = "当前为演示会话，图片仅本地展示，未上传到后端。"
                scrollTargetId = localMessage.id
                await appendMockAutoReply(trigger: "图片")
                return
            }

            let uploaded = try await APIClient.shared.uploadImage(
                ownerUserId: currentUserId,
                imageData: jpegData,
                fileName: "ios-chat-\(Int(Date().timeIntervalSince1970)).jpg",
                mimeType: "image/jpeg"
            )
            let sent = try await APIClient.shared.sendImageMessage(
                senderUserId: currentUserId,
                receiverUserId: conversation.peerUserId,
                mediaId: uploaded.mediaId,
                extPayload: "{\"source\":\"ios-conversation\"}"
            )
            let appended = ConversationMessageItem(data: sent, currentUserId: currentUserId)
            messages.append(appended)
            scrollTargetId = appended.id
            await markConversationReadIfNeeded(lastReadMessageId: appended.id)
            onConversationChanged()
        } catch {
            if let pickedImage {
                let localMessage = ConversationMessageItem.localImage(
                    image: pickedImage,
                    isOutgoing: true,
                    timestamp: Date()
                )
                messages.append(localMessage)
                scrollTargetId = localMessage.id
            }
            loadErrorMessage = imageSendErrorMessage(
                from: error,
                didAppendLocalPreview: pickedImage != nil
            )
        }
    }

    @MainActor
    private func handleCapturedPhoto(_ image: UIImage) async {
        dismissFeatureInProgressHintIfNeeded()
        if isUploadingImage || isSending {
            return
        }
        isUploadingImage = true
        loadErrorMessage = nil
        defer {
            isUploadingImage = false
        }

        let jpegData = image.jpegData(compressionQuality: 0.85)
            ?? image.pngData()
            ?? Data()

        if jpegData.isEmpty {
            loadErrorMessage = "拍摄失败，请重试。"
            return
        }

        if conversation.isMock {
            let localMessage = ConversationMessageItem.localImage(
                image: image,
                isOutgoing: true,
                timestamp: Date()
            )
            messages.append(localMessage)
            loadErrorMessage = "当前为演示会话，图片仅本地展示，未上传到后端。"
            scrollTargetId = localMessage.id
            await appendMockAutoReply(trigger: "图片")
            return
        }

        do {
            let uploaded = try await APIClient.shared.uploadImage(
                ownerUserId: currentUserId,
                imageData: jpegData,
                fileName: "ios-camera-\(Int(Date().timeIntervalSince1970)).jpg",
                mimeType: "image/jpeg"
            )
            let sent = try await APIClient.shared.sendImageMessage(
                senderUserId: currentUserId,
                receiverUserId: conversation.peerUserId,
                mediaId: uploaded.mediaId,
                extPayload: "{\"source\":\"ios-conversation\",\"from\":\"camera\"}"
            )
            let appended = ConversationMessageItem(data: sent, currentUserId: currentUserId)
            messages.append(appended)
            scrollTargetId = appended.id
            await markConversationReadIfNeeded(lastReadMessageId: appended.id)
            onConversationChanged()
        } catch {
            let localMessage = ConversationMessageItem.localImage(
                image: image,
                isOutgoing: true,
                timestamp: Date()
            )
            messages.append(localMessage)
            scrollTargetId = localMessage.id
            loadErrorMessage = imageSendErrorMessage(from: error, didAppendLocalPreview: true)
        }
    }

    private func imageSendErrorMessage(from error: Error, didAppendLocalPreview: Bool) -> String {
        let rawMessage = userFacingErrorMessage(error).trimmingCharacters(in: .whitespacesAndNewlines)
        let fallbackMessage = rawMessage.isEmpty ? "图片发送失败" : rawMessage

        if fallbackMessage.localizedCaseInsensitiveContains("required request parameter"),
           fallbackMessage.contains("ownerUser") {
            return didAppendLocalPreview
                ? "图片上传参数未被服务端识别，已本地展示。请确认图片上传接口参数后重试。"
                : "图片上传参数未被服务端识别，请稍后重试。"
        }

        if fallbackMessage.localizedCaseInsensitiveContains("required part"),
           fallbackMessage.localizedCaseInsensitiveContains("file") {
            return didAppendLocalPreview
                ? "图片文件未被服务端识别，已本地展示。已触发直连重试，请再发送一次。"
                : "图片文件未被服务端识别，请稍后重试。"
        }

        if didAppendLocalPreview {
            return "图片发送失败，已本地展示：\(fallbackMessage)"
        }
        return fallbackMessage
    }

    @MainActor
    private func markConversationReadIfNeeded(lastReadMessageId: String) async {
        guard !conversation.isTransient else {
            return
        }
        try? await APIClient.shared.markConversationRead(
            userId: currentUserId,
            conversationNo: conversation.conversationNo,
            lastReadMessageId: lastReadMessageId
        )
    }

    private func updateKeyboardInset(notification: Notification) {
        guard let userInfo = notification.userInfo else {
            return
        }
        let duration = (userInfo[UIResponder.keyboardAnimationDurationUserInfoKey] as? Double) ?? 0.25
        let rawKeyboardFrame = (userInfo[UIResponder.keyboardFrameEndUserInfoKey] as? CGRect) ?? .zero
        let activeWindow = UIApplication.shared.activeKeyWindow
        let keyboardFrame = activeWindow?.convert(rawKeyboardFrame, from: nil) ?? rawKeyboardFrame
        let containerHeight = activeWindow?.bounds.height ?? UIScreen.main.bounds.height
        let overlap = max(0, containerHeight - keyboardFrame.minY)
        let shouldCancelVoiceRecord = overlap > 0 && isRecordingVoice
        let shouldTrackKeyboard = isDraftInputFocused && !isVoiceInputMode && !showEmojiPanel && !showPlusPanel
        withAnimation(.easeOut(duration: duration)) {
            keyboardInset = shouldTrackKeyboard && overlap > 0 ? overlap + 14 : 0
            if overlap > 0 {
                showEmojiPanel = false
                showPlusPanel = false
                isVoicePressing = false
            }
        }
        if shouldCancelVoiceRecord {
            Task {
                await finishVoiceRecording(send: false)
            }
        }
    }

    private var composerBottomPadding: CGFloat {
        if isDraftInputFocused && !isVoiceInputMode && !showEmojiPanel && !showPlusPanel && keyboardInset > 0 {
            return keyboardInset
        }
        return 15
    }

    private var shouldCleanupTransientConversationOnExit: Bool {
        guard conversation.isTransient else {
            return false
        }
        let hasDraftInput = !draftText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
        return messages.isEmpty && !hasDraftInput
    }
    }

private struct ProductSuggestionView: View {
    let userId: Int64?
    let onBack: () -> Void

    @State private var content = ""
    @State private var contactMobile = ""
    @State private var attachments: [AttachmentItem] = []
    @State private var selectedPhotoItem: PhotosPickerItem?
    @State private var isPhotoPickerPresented = false
    @State private var isSubmitting = false
    @State private var noticeMessage: String?
    @State private var noticeToken = UUID()
    @State private var showSuccessAlert = false
    @State private var submittedFeedbackNo: String?
    @State private var mobileKeyboardInset: CGFloat = 0
    @FocusState private var focusedField: FocusField?

    private enum FocusField {
        case content
        case mobile
    }

    private struct AttachmentItem: Identifiable {
        let id = UUID()
        let image: UIImage
    }

    private let baseWidth: CGFloat = 402
    private let baseHeight: CGFloat = 874

    private var normalizedContent: String {
        content.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private var normalizedContentCount: Int {
        normalizedContent.count
    }

    private var isContentInputActive: Bool {
        focusedField == .content || !content.isEmpty
    }

    private var isMobileInputActive: Bool {
        focusedField == .mobile || !contactMobile.isEmpty
    }

    private var showsMobileKeyboardConfirmBar: Bool {
        false
    }

    private var mobileContactTextBinding: Binding<String> {
        Binding(
            get: { contactMobile },
            set: { contactMobile = sanitizeMobile($0) }
        )
    }

    private var mobileFieldFocusBinding: Binding<Bool> {
        Binding(
            get: { focusedField == .mobile },
            set: { focusedField = $0 ? .mobile : nil }
        )
    }

    var body: some View {
        GeometryReader { proxy in
            let scaleX = proxy.size.width / baseWidth
            let scaleY = proxy.size.height / baseHeight
            let fontScale = min(scaleX, scaleY)

            ZStack {
                Image("ProductSuggestionScreen")
                    .resizable()
                    .interpolation(.high)
                    .aspectRatio(contentMode: .fill)
                    .frame(width: proxy.size.width, height: proxy.size.height)
                    .clipped()
                    .contentShape(Rectangle())
                    .onTapGesture {
                        focusedField = nil
                    }

                if isContentInputActive {
                    Rectangle()
                        .fill(Color.white)
                        .frame(width: 402 * scaleX, height: 170 * scaleY)
                        .position(x: 201 * scaleX, y: 230 * scaleY)
                        .allowsHitTesting(false)
                }

                if !attachments.isEmpty {
                    attachmentOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                }

                if isMobileInputActive {
                    Rectangle()
                        .fill(Color.white)
                        .frame(width: 380 * scaleX, height: 30 * scaleY)
                        .position(x: 201 * scaleX, y: 548 * scaleY)
                        .allowsHitTesting(false)
                }

                if isContentInputActive {
                    Text("\(content.count)/200")
                        .font(.system(size: 13 * fontScale, weight: .regular))
                        .foregroundStyle(Color(red: 0.72, green: 0.72, blue: 0.73))
                        .frame(width: 64 * scaleX, alignment: .trailing)
                        .position(x: 370 * scaleX, y: 265 * scaleY)
                        .allowsHitTesting(false)
                }

                pageTitleOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)

                if isSubmitting {
                    submitLoadingOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                }

                contentEditor(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                contactField(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                contentFocusHotspot(scaleX: scaleX, scaleY: scaleY)
                contactFocusHotspot(scaleX: scaleX, scaleY: scaleY)
                dismissFocusHotspots(scaleX: scaleX, scaleY: scaleY)
                attachmentEntryHotspots(scaleX: scaleX, scaleY: scaleY)
                pageHotspots(scaleX: scaleX, scaleY: scaleY)

                if let noticeMessage, !noticeMessage.isEmpty {
                    noticeToast(text: noticeMessage)
                        .padding(.top, 88 * scaleY)
                }
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .ignoresSafeArea()
        .ignoresSafeArea(.keyboard, edges: .bottom)
        .toolbar {
            ToolbarItemGroup(placement: .keyboard) {
                if focusedField == .mobile {
                    Spacer()
                    Button {
                        focusedField = nil
                    } label: {
                        Text("确认")
                            .font(.system(size: 15, weight: .semibold))
                            .foregroundStyle(AppTheme.palette.brandPrimary)
                            .padding(.horizontal, 16)
                            .padding(.vertical, 7)
                            .background(
                                Capsule()
                                    .fill(Color(red: 0.88, green: 0.94, blue: 1.0))
                            )
                    }
                }
            }
        }
        .safeAreaInset(edge: .bottom) {
            if showsMobileKeyboardConfirmBar {
                ZStack(alignment: .top) {
                    Color(red: 0.90, green: 0.90, blue: 0.92)
                        .frame(height: 44)
                        .offset(y: 15)

                    mobileKeyboardConfirmBar
                        .offset(y: 20)
                }
                .padding(.bottom, max(mobileKeyboardInset - 30, 0))
            }
        }
        .photosPicker(isPresented: $isPhotoPickerPresented, selection: $selectedPhotoItem, matching: .images)
        .onChange(of: selectedPhotoItem) { _, newValue in
            guard let newValue else {
                return
            }
            Task {
                await handlePickedPhoto(item: newValue)
            }
        }
        .onReceive(NotificationCenter.default.publisher(for: UIResponder.keyboardWillChangeFrameNotification)) { notification in
            updateMobileKeyboardInset(notification: notification)
        }
        .onReceive(NotificationCenter.default.publisher(for: UIResponder.keyboardWillHideNotification)) { notification in
            updateMobileKeyboardInset(notification: notification)
        }
        .alert("提交成功", isPresented: $showSuccessAlert) {
            Button("知道了") {
                onBack()
            }
        } message: {
            if let submittedFeedbackNo, !submittedFeedbackNo.isEmpty {
                Text("已收到你的反馈与投诉，工单号：\(submittedFeedbackNo)")
            } else {
                Text("已收到你的反馈与投诉。")
            }
        }
    }

