    @MainActor
    private func handlePickedPhoto(item: PhotosPickerItem) async {
        defer {
            selectedPhotoItem = nil
        }
        guard attachments.count < 4 else {
            showNotice("最多上传4张图片")
            return
        }
        guard let data = try? await item.loadTransferable(type: Data.self),
              let image = UIImage(data: data) else {
            showNotice("读取图片失败")
            return
        }
        attachments.append(AttachmentItem(image: image))
    }

    @MainActor
    private func submitFeedback() async {
        guard let userId, userId > 0 else {
            showNotice("用户标识无效")
            return
        }
        if normalizedContentCount < 10 {
            showNotice("问题描述至少填写10个字")
            return
        }
        if normalizedContentCount > 200 {
            showNotice("问题描述不能超过200个字")
            return
        }
        if let sanitizedMobile = sanitizedOptionalMobile(contactMobile),
           !isValidMainlandMobile(sanitizedMobile) {
            showNotice("请输入正确的手机号")
            focusedField = .mobile
            return
        }

        isSubmitting = true
        defer {
            isSubmitting = false
        }

        do {
            let attachmentUrls = try await uploadAttachments(userId: userId)
            let ticket = try await APIClient.shared.submitFeedbackTicket(
                userId: userId,
                content: normalizedContent,
                contactMobile: sanitizedOptionalMobile(contactMobile),
                attachmentUrls: attachmentUrls
            )
            submittedFeedbackNo = ticket.feedbackNo
            showSuccessAlert = true
        } catch {
            showNotice(userFacingErrorMessage(error))
        }
    }

    private func uploadAttachments(userId: Int64) async throws -> [String] {
        var urls: [String] = []
        for (index, attachment) in attachments.enumerated() {
            guard let imageData = attachment.image.jpegData(compressionQuality: 0.86), !imageData.isEmpty else {
                continue
            }
            let uploaded = try await APIClient.shared.uploadImage(
                ownerUserId: userId,
                imageData: imageData,
                fileName: "feedback-\(userId)-\(index + 1).jpg",
                mimeType: "image/jpeg"
            )
            let contentUrl = feedbackAttachmentURLString(from: uploaded)
            if !contentUrl.isEmpty {
                urls.append(contentUrl)
            }
        }
        return urls
    }

    private func feedbackAttachmentURLString(from asset: MediaAssetData) -> String {
        let trimmedContentUrl = asset.contentUrl?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if !trimmedContentUrl.isEmpty {
            return trimmedContentUrl
        }
        if let absoluteContentURL = APIClient.shared.mediaContentURL(mediaId: asset.mediaId)?.absoluteString,
           !absoluteContentURL.isEmpty {
            return absoluteContentURL
        }
        return "/bff/media/\(asset.mediaId)/content"
    }

    private func sanitizeMobile(_ raw: String?) -> String {
        let digits = (raw ?? "").filter(\.isNumber)
        if digits.count <= 11 {
            return digits
        }
        return String(digits.prefix(11))
    }

    private func sanitizedOptionalMobile(_ raw: String) -> String? {
        let digits = sanitizeMobile(raw)
        return digits.isEmpty ? nil : digits
    }

    private func isValidMainlandMobile(_ mobile: String) -> Bool {
        guard mobile.count == 11 else {
            return false
        }
        let pattern = #"^1[3-9]\d{9}$"#
        return mobile.range(of: pattern, options: .regularExpression) != nil
    }

private func updateMobileKeyboardInset(notification: Notification) {
    guard let userInfo = notification.userInfo else {
        return
    }
    let duration = (userInfo[UIResponder.keyboardAnimationDurationUserInfoKey] as? Double) ?? 0.25
    let rawKeyboardFrame = (userInfo[UIResponder.keyboardFrameEndUserInfoKey] as? CGRect) ?? .zero
    let activeWindow = UIApplication.shared.activeKeyWindow
    let keyboardFrame = activeWindow?.convert(rawKeyboardFrame, from: nil) ?? rawKeyboardFrame
    let containerHeight = activeWindow?.bounds.height ?? UIScreen.main.bounds.height
    let overlap = max(0, containerHeight - keyboardFrame.minY)
    withAnimation(.easeOut(duration: duration)) {
        mobileKeyboardInset = overlap
    }
}

    @MainActor
    private func showNotice(_ message: String) {
        let trimmed = message.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else {
            return
        }
        noticeMessage = trimmed
        noticeToken = UUID()
        let currentToken = noticeToken
        DispatchQueue.main.asyncAfter(deadline: .now() + 2.0) {
            guard noticeToken == currentToken else {
                return
            }
            noticeMessage = nil
        }
    }
}

private struct CameraCapturePicker: UIViewControllerRepresentable {

    let onCapture: (UIImage) -> Void
    let onCancel: () -> Void

    func makeCoordinator() -> Coordinator {
        Coordinator(parent: self)
    }

    func makeUIViewController(context: Context) -> UIImagePickerController {
        let picker = UIImagePickerController()
        picker.sourceType = .camera
        picker.cameraCaptureMode = .photo
        picker.allowsEditing = false
        picker.delegate = context.coordinator
        return picker
    }

    func updateUIViewController(_ uiViewController: UIImagePickerController, context: Context) {}

    final class Coordinator: NSObject, UINavigationControllerDelegate, UIImagePickerControllerDelegate {
        private let parent: CameraCapturePicker

        init(parent: CameraCapturePicker) {
            self.parent = parent
        }

        func imagePickerControllerDidCancel(_ picker: UIImagePickerController) {
            parent.onCancel()
        }

        func imagePickerController(
            _ picker: UIImagePickerController,
            didFinishPickingMediaWithInfo info: [UIImagePickerController.InfoKey: Any]
        ) {
            if let edited = info[.editedImage] as? UIImage {
                parent.onCapture(edited)
                return
            }
            if let original = info[.originalImage] as? UIImage {
                parent.onCapture(original)
                return
            }
            parent.onCancel()
        }
    }
    }

private struct ConversationMessageRow: View {
    let item: ConversationMessageItem
    let outgoingAvatarImage: UIImage?
    let outgoingAvatarUrl: String?
    let outgoingAvatarAssetName: String?
    let outgoingAvatarText: String
    let outgoingAvatarColor: Color
    let peerAvatarUrl: String?
    let peerAvatarAssetName: String?
    let peerAvatarText: String
    let peerAvatarColor: Color
    let onTapPeerAvatar: () -> Void
    let onTapRedPacket: () -> Void

    var body: some View {
        HStack(alignment: .bottom, spacing: 8) {
            if item.isOutgoing {
                Spacer(minLength: 44)
                bubbleContent
                chatAvatar(
                    avatarImage: outgoingAvatarImage,
                    avatarUrl: outgoingAvatarUrl,
                    avatarAssetName: outgoingAvatarAssetName,
                    avatarText: outgoingAvatarText,
                    avatarColor: outgoingAvatarColor,
                    size: 38
                )
            } else {
                Button(action: onTapPeerAvatar) {
                    chatAvatar(
                        avatarImage: nil,
                        avatarUrl: peerAvatarUrl,
                        avatarAssetName: peerAvatarAssetName,
                        avatarText: peerAvatarText,
                        avatarColor: peerAvatarColor,
                        size: 38
                    )
                }
                .buttonStyle(.plain)
                bubbleContent
                Spacer(minLength: 44)
            }
        }
        .padding(.horizontal, 8)
        .padding(.vertical, 4)
    }

    @ViewBuilder
    private func chatAvatar(
        avatarImage: UIImage?,
        avatarUrl: String?,
        avatarAssetName: String?,
        avatarText: String,
        avatarColor: Color,
        size: CGFloat
    ) -> some View {
        let normalizedAssetName = avatarAssetName?.trimmingCharacters(in: .whitespacesAndNewlines)
        let resolvedAssetName: String? = {
            if let normalizedAssetName, !normalizedAssetName.isEmpty {
                return normalizedAssetName
            }
            return demoAvatarAssetName(for: avatarUrl)
        }()
        if let avatarImage {
            Image(uiImage: avatarImage)
                .resizable()
                .aspectRatio(contentMode: .fill)
                .frame(width: size, height: size)
                .clipShape(RoundedRectangle(cornerRadius: 7, style: .continuous))
        } else if let resolvedAssetName,
           UIImage(named: resolvedAssetName) != nil {
            Image(resolvedAssetName)
                .resizable()
                .aspectRatio(contentMode: .fill)
                .frame(width: size, height: size)
                .clipShape(RoundedRectangle(cornerRadius: 7, style: .continuous))
        } else if let raw = avatarUrl?.trimmingCharacters(in: .whitespacesAndNewlines),
           !raw.isEmpty,
           let url = URL(string: raw) {
            AvatarRemoteImage(url: url) { image in
                image
                    .resizable()
                    .aspectRatio(contentMode: .fill)
                    .frame(width: size, height: size)
                    .clipShape(RoundedRectangle(cornerRadius: 7, style: .continuous))
            } placeholder: {
                avatarFallback(text: avatarText, color: avatarColor, size: size)
            }
        } else {
            avatarFallback(text: avatarText, color: avatarColor, size: size)
        }
    }

    private func avatarFallback(text: String, color: Color, size: CGFloat) -> some View {
        RoundedRectangle(cornerRadius: 7, style: .continuous)
            .fill(color)
            .frame(width: size, height: size)
            .overlay(
                Text(text)
                    .font(.system(size: max(12, size * 0.36), weight: .bold))
                    .foregroundStyle(.white)
            )
    }

    @ViewBuilder
    private var bubbleContent: some View {
        if item.isRedPacketMessage {
            redPacketBubble
                .contentShape(RoundedRectangle(cornerRadius: 10, style: .continuous))
                .onTapGesture(perform: onTapRedPacket)
        } else if item.isTransferMessage {
            transferBubble
        } else if item.isImageMessage {
            imageBubble
        } else if item.isVoiceMessage {
            voiceBubble
        } else {
            textBubble
        }
    }

    private var redPacketCoverOption: RedPacketCoverOption {
        RedPacketCoverOption.option(for: item.redPacketCoverId)
    }

    private var redPacketBlessingDisplayText: String {
        if isClaimedRedPacket {
            return "已领取"
        }
        let blessing = item.redPacketBlessingText?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if !blessing.isEmpty {
            return blessing
        }
        return "快来领红包"
    }

    private var isClaimedRedPacket: Bool {
        item.redPacketStatus?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() == "CLAIMED"
    }

    private var redPacketBubble: some View {
        let bubbleScale: CGFloat = 0.7
        let bubbleWidth: CGFloat = 272 * bubbleScale
        let artworkHeight: CGFloat = 286 * bubbleScale
        let footerHeight: CGFloat = 124 * bubbleScale
        let openButtonSize: CGFloat = 84 * bubbleScale
        let bubbleCornerRadius: CGFloat = 16 * bubbleScale
        let footerTopSpacerHeight = isClaimedRedPacket ? 12 * bubbleScale : openButtonSize * 0.56

        return ZStack(alignment: .top) {
            RoundedRectangle(cornerRadius: bubbleCornerRadius, style: .continuous)
                .fill(Color.white)

            VStack(spacing: 0) {
                RedPacketGeneratedCoverArtworkView(
                    option: redPacketCoverOption,
                    compact: false,
                    fontScale: 0.78 * bubbleScale
                )
                .frame(width: bubbleWidth, height: artworkHeight)
                .clipped()

                ZStack(alignment: .top) {
                    Rectangle()
                        .fill(Color(red: 0.98, green: 0.24, blue: 0.19))

                    VStack(spacing: 0) {
                        Spacer()
                            .frame(height: footerTopSpacerHeight)

                        Text(redPacketBlessingDisplayText)
                            .font(.system(size: 16 * bubbleScale, weight: .medium))
                            .foregroundStyle(Color.white)
                            .lineLimit(1)
                            .minimumScaleFactor(0.72)
                            .padding(.horizontal, 18 * bubbleScale)
                            .padding(.top, 10 * bubbleScale)

                        Rectangle()
                            .fill(Color.white.opacity(0.18))
                            .frame(height: 0.8)
                            .padding(.horizontal, 18 * bubbleScale)
                            .padding(.top, 14 * bubbleScale)

                        HStack(spacing: 7 * bubbleScale) {
                            redPacketBadgeIcon(size: 10 * bubbleScale)

                            Text("红包")
                                .font(.system(size: 11.5 * bubbleScale, weight: .regular))
                                .foregroundStyle(Color.white.opacity(0.88))

                            Spacer(minLength: 0)
                        }
                        .padding(.horizontal, 18 * bubbleScale)
                        .padding(.top, 10 * bubbleScale)
                    }
                    .frame(width: bubbleWidth, height: footerHeight, alignment: .top)
                }
                .frame(width: bubbleWidth, height: footerHeight)
            }

            if !isClaimedRedPacket {
                Circle()
                    .fill(Color(red: 0.99, green: 0.84, blue: 0.62))
                    .frame(width: openButtonSize, height: openButtonSize)
                    .overlay(
                        Circle()
