                                Color(red: 0.86, green: 0.46, blue: 0.22),
                                lineWidth: 1
                            )
                    )
                    .overlay {
                        Text("開")
                            .font(.system(size: 34 * bubbleScale, weight: .bold))
                            .foregroundStyle(Color(red: 0.39, green: 0.13, blue: 0.08))
                            .offset(y: -1)
                    }
                    .offset(y: artworkHeight - openButtonSize / 2 - 2)
            }
        }
        .frame(width: bubbleWidth, height: artworkHeight + footerHeight)
        .clipShape(RoundedRectangle(cornerRadius: bubbleCornerRadius, style: .continuous))
        .shadow(color: Color.black.opacity(0.06), radius: 5 * bubbleScale, x: 0, y: 2 * bubbleScale)
    }

