private struct MessageBubbleTail: Shape {
    enum Direction {
        case left
        case right
    }

    let direction: Direction

    func path(in rect: CGRect) -> Path {
        var path = Path()
        switch direction {
        case .left:
            path.move(to: CGPoint(x: rect.maxX, y: rect.midY))
            path.addLine(to: CGPoint(x: rect.minX, y: rect.minY))
            path.addLine(to: CGPoint(x: rect.minX, y: rect.maxY))
        case .right:
            path.move(to: CGPoint(x: rect.minX, y: rect.midY))
            path.addLine(to: CGPoint(x: rect.maxX, y: rect.minY))
            path.addLine(to: CGPoint(x: rect.maxX, y: rect.maxY))
        }
        path.closeSubpath()
        return path
    }
    }

private struct ConversationMessageItem: Identifiable {
    let id: String
    let isOutgoing: Bool
    let renderText: String
    let timestampLabel: String
    let createdDate: Date?
    let messageType: String
    let remoteImageURL: String?
    let localImage: UIImage?
    let localAudioURL: URL?
    let voiceDurationSeconds: Int?
    let redPacketNo: String?
    let redPacketStatus: String?
    let redPacketCoverId: String?
    let redPacketCoverTitle: String?
    let redPacketBlessingText: String?
    let transferAmountText: String
    let transferRemarkText: String?
    let transferRecipientMaskedName: String?

    var isImageMessage: Bool {
        messageType == "IMAGE" || remoteImageURL != nil || localImage != nil
    }

    var isVoiceMessage: Bool {
        messageType == "VOICE" || voiceDurationSeconds != nil
    }

    var isRedPacketMessage: Bool {
        messageType == "RED_PACKET"
    }

    var isTransferMessage: Bool {
        messageType == "TRANSFER"
    }

    var redPacketFooterText: String {
        let normalizedStatus = redPacketStatus?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() ?? ""
        switch normalizedStatus {
        case "CLAIMED":
            return "已领取"
        case "PENDING_CLAIM":
            return isOutgoing ? "待领取" : "领取红包"
        default:
            return "红包消息"
        }
    }

    var transferSubtitleText: String {
        let remark = transferRemarkText?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if !remark.isEmpty {
            return remark
        }
        if isOutgoing {
            let maskedName = transferRecipientMaskedName?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            if !maskedName.isEmpty {
                return "转账给\(maskedName)"
            }
            return "转账给TA"
        }
        return "转账给你"
    }

    init(data: MessageData, currentUserId: Int64) {
        let parsedRedPacketPayload = Self.parseRedPacketPayload(data.extPayload)
        let parsedTransferPayload = Self.parseTransferPayload(data.extPayload)
        self.id = data.messageId
        self.isOutgoing = data.senderUserId == currentUserId
        self.createdDate = Self.parseDate(data.createdAt)
        self.timestampLabel = Self.formatTimestamp(self.createdDate)
        let baseType = data.messageType.uppercased()
        let voiceDuration = Self.resolveVoiceDuration(data: data)
        self.messageType = voiceDuration == nil ? baseType : "VOICE"
        self.remoteImageURL = Self.resolveRemoteImageURL(data: data)
        self.localImage = nil
        self.localAudioURL = nil
        self.voiceDurationSeconds = voiceDuration
        self.redPacketNo = parsedRedPacketPayload?.redPacketNo
        self.redPacketStatus = parsedRedPacketPayload?.status
        self.redPacketCoverId = parsedRedPacketPayload?.coverId
        self.redPacketCoverTitle = parsedRedPacketPayload?.coverTitle
        self.redPacketBlessingText = parsedRedPacketPayload?.blessingText
        self.transferAmountText = Self.formatMoney(data.amount)
        self.transferRemarkText = parsedTransferPayload?.remark
        self.transferRecipientMaskedName = parsedTransferPayload?.recipientMaskedName
        self.renderText = Self.buildRenderText(
            data: data,
            forcedMessageType: self.messageType,
            voiceDurationSeconds: voiceDuration
        )
    }

    init(
        id: String = "local_\(UUID().uuidString)",
        isOutgoing: Bool,
        renderText: String,
        timestamp: Date = Date(),
        messageType: String = "TEXT",
        remoteImageURL: String? = nil,
        localImage: UIImage? = nil,
        localAudioURL: URL? = nil,
        voiceDurationSeconds: Int? = nil
    ) {
        self.id = id
        self.isOutgoing = isOutgoing
        self.createdDate = timestamp
        self.timestampLabel = Self.formatTimestamp(timestamp)
        self.messageType = messageType
        self.remoteImageURL = remoteImageURL
        self.localImage = localImage
        self.localAudioURL = localAudioURL
        self.voiceDurationSeconds = voiceDurationSeconds
        self.redPacketNo = nil
        self.redPacketStatus = nil
        self.redPacketCoverId = nil
        self.redPacketCoverTitle = nil
        self.redPacketBlessingText = nil
        self.transferAmountText = "¥0.00"
        self.transferRemarkText = nil
        self.transferRecipientMaskedName = nil
        self.renderText = renderText
    }

    static func localText(content: String, isOutgoing: Bool, timestamp: Date) -> ConversationMessageItem {
        ConversationMessageItem(
            isOutgoing: isOutgoing,
            renderText: content.trimmingCharacters(in: .whitespacesAndNewlines),
            timestamp: timestamp,
            messageType: "TEXT"
        )
    }

    static func localImage(image: UIImage, isOutgoing: Bool, timestamp: Date) -> ConversationMessageItem {
        ConversationMessageItem(
            isOutgoing: isOutgoing,
            renderText: "[图片]",
            timestamp: timestamp,
            messageType: "IMAGE",
            remoteImageURL: nil,
            localImage: image
        )
    }

    static func localVoice(
        id: String = "local_\(UUID().uuidString)",
        durationSeconds: Int,
        isOutgoing: Bool,
        timestamp: Date,
        localAudioURL: URL? = nil
    ) -> ConversationMessageItem {
        let duration = max(1, durationSeconds)
        return ConversationMessageItem(
            id: id,
            isOutgoing: isOutgoing,
            renderText: "[语音 \(duration)'' ]",
            timestamp: timestamp,
            messageType: "VOICE",
            remoteImageURL: nil,
            localImage: nil,
            localAudioURL: localAudioURL,
            voiceDurationSeconds: duration
        )
    }

    private static func buildRenderText(
        data: MessageData,
        forcedMessageType: String? = nil,
        voiceDurationSeconds: Int? = nil
    ) -> String {
        let type = forcedMessageType ?? data.messageType.uppercased()
        switch type {
        case "IMAGE":
            return "[图片]"
        case "VOICE":
            let duration = max(1, voiceDurationSeconds ?? 1)
            return "[语音 \(duration)'' ]"
        case "TRANSFER":
            return "转账 \(formatMoney(data.amount))"
        case "RED_PACKET":
            return "红包 \(formatMoney(data.amount))"
        case "SYSTEM":
            let systemText = data.contentText?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            return systemText.isEmpty ? "[系统消息]" : systemText
        default:
            let text = data.contentText?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            return text.isEmpty ? "[消息]" : text
        }
    }

    private static func formatMoney(_ amount: MessageAmountData?) -> String {
        guard let amount = amount?.amount else {
            return "¥0.00"
        }
        let number = NSDecimalNumber(decimal: amount)
        return "¥" + String(format: "%.2f", number.doubleValue)
    }

    private static func resolveRemoteImageURL(data: MessageData) -> String? {
        let type = data.messageType.uppercased()
        guard type == "IMAGE" else {
            return nil
        }
        if let mediaId = data.mediaId?.trimmingCharacters(in: .whitespacesAndNewlines),
           !mediaId.isEmpty,
           let url = APIClient.shared.mediaContentURL(mediaId: mediaId) {
            return url.absoluteString
        }
        if let extPayload = data.extPayload,
           let value = parseImageURLFromExtPayload(extPayload) {
            return value
        }
        return nil
    }

    private static func resolveVoiceDuration(data: MessageData) -> Int? {
        let type = data.messageType.uppercased()
        if type == "VOICE" {
            if let value = parseVoiceDurationFromText(data.contentText) {
                return value
            }
            return 1
        }
        guard let extPayload = data.extPayload,
              let payloadData = extPayload.data(using: .utf8),
              let jsonObject = try? JSONSerialization.jsonObject(with: payloadData),
              let dict = jsonObject as? [String: Any] else {
            return nil
        }
        for key in ["voiceDurationSec", "voiceDurationSeconds", "durationSec", "duration"] {
            if let numeric = dict[key] as? NSNumber {
                return max(1, numeric.intValue)
            }
            if let text = dict[key] as? String,
               let parsed = Int(text.trimmingCharacters(in: .whitespacesAndNewlines)) {
                return max(1, parsed)
            }
        }
        if let text = data.contentText,
           text.contains("[语音]"),
           let value = parseVoiceDurationFromText(text) {
            return value
        }
        return nil
    }

    private static func parseVoiceDurationFromText(_ text: String?) -> Int? {
        guard let text else {
            return nil
        }
        let digits = text.filter(\.isNumber)
        guard let value = Int(digits), value > 0 else {
            return nil
        }
        return value
    }

    private static func parseImageURLFromExtPayload(_ extPayload: String) -> String? {
        guard let payloadData = extPayload.data(using: .utf8),
              let jsonObject = try? JSONSerialization.jsonObject(with: payloadData),
              let dict = jsonObject as? [String: Any] else {
            return nil
        }
        for key in ["contentUrl", "imageUrl", "url"] {
            if let value = dict[key] as? String {
                let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
                if !trimmed.isEmpty {
                    return trimmed
                }
            }
        }
        return nil
    }

    private static func parseRedPacketPayload(_ extPayload: String?) -> ParsedRedPacketPayload? {
        guard let extPayload,
              let payloadData = extPayload.data(using: .utf8),
              let jsonObject = try? JSONSerialization.jsonObject(with: payloadData),
              let dict = jsonObject as? [String: Any] else {
            return nil
        }
        let redPacketNo = firstNonBlank(
            stringValue(dict["redPacketNo"]),
            nestedStringValue(in: dict, candidateKeys: ["redPacketNo", "red_packet_no"])
        )
        let status = firstNonBlank(
            stringValue(dict["redPacketStatus"]),
            stringValue(dict["status"]),
            nestedStringValue(in: dict, candidateKeys: ["redPacketStatus", "status", "red_packet_status"])
        )
        let coverId = firstNonBlank(
            stringValue(dict["coverId"]),
            nestedStringValue(in: dict, candidateKeys: ["coverId", "cover_id"])
        )
        let coverTitle = firstNonBlank(
            stringValue(dict["coverTitle"]),
            nestedStringValue(in: dict, candidateKeys: ["coverTitle", "cover_title"])
        )
        let blessingText = firstNonBlank(
            stringValue(dict["blessingText"]),
            stringValue(dict["blessing"]),
            stringValue(dict["greeting"]),
            stringValue(dict["wishText"]),
            nestedStringValue(in: dict, candidateKeys: ["blessingText", "blessing", "greeting", "wishText", "blessing_text", "wish_text"])
        )
        if redPacketNo == nil && status == nil && coverId == nil && blessingText == nil {
            return nil
        }
        return ParsedRedPacketPayload(
            redPacketNo: redPacketNo,
            status: status,
            coverId: coverId,
            coverTitle: coverTitle,
            blessingText: blessingText
        )
    }

    private static func parseTransferPayload(_ extPayload: String?) -> ParsedTransferPayload? {
        guard let extPayload,
              let payloadData = extPayload.data(using: .utf8),
              let jsonObject = try? JSONSerialization.jsonObject(with: payloadData),
              let dict = jsonObject as? [String: Any] else {
            return nil
        }
        let remark = firstNonBlank(
            stringValue(dict["remark"]),
            stringValue(dict["memo"]),
            nestedStringValue(in: dict, candidateKeys: ["remark", "memo"])
        )
        let recipientMaskedName = firstNonBlank(
            stringValue(dict["recipientMaskedName"]),
            stringValue(dict["maskedRecipientName"]),
            nestedStringValue(in: dict, candidateKeys: ["recipientMaskedName", "maskedRecipientName", "recipient_masked_name"])
        )
        if remark == nil && recipientMaskedName == nil {
            return nil
        }
        return ParsedTransferPayload(
            remark: remark,
            recipientMaskedName: recipientMaskedName
        )
    }

    private static func firstNonBlank(_ values: String?...) -> String? {
        for value in values {
            let trimmed = value?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            if !trimmed.isEmpty {
                return trimmed
            }
        }
        return nil
    }

    private static func nestedStringValue(in raw: Any?, candidateKeys: [String]) -> String? {
        switch raw {
        case let dict as [String: Any]:
            for key in candidateKeys {
                if let value = stringValue(dict[key]) {
                    return value
                }
            }
            for value in dict.values {
                if let nested = nestedStringValue(in: value, candidateKeys: candidateKeys) {
                    return nested
                }
            }
        case let array as [Any]:
            for element in array {
                if let nested = nestedStringValue(in: element, candidateKeys: candidateKeys) {
                    return nested
                }
            }
        case let text as String:
            let trimmed = text.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !trimmed.isEmpty,
                  let data = trimmed.data(using: .utf8),
                  let jsonObject = try? JSONSerialization.jsonObject(with: data) else {
                return nil
            }
            return nestedStringValue(in: jsonObject, candidateKeys: candidateKeys)
        default:
            return nil
        }
        return nil
    }

    private static func stringValue(_ raw: Any?) -> String? {
        switch raw {
        case let value as String:
            let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
            return trimmed.isEmpty ? nil : trimmed
        case let value as NSNumber:
            return value.stringValue
        default:
            return nil
        }
    }

    private static func parseDate(_ raw: String?) -> Date? {
        guard let raw = raw?.trimmingCharacters(in: .whitespacesAndNewlines), !raw.isEmpty else {
            return nil
        }
        let parser = DateFormatter()
        parser.locale = Locale(identifier: "en_US_POSIX")
        parser.timeZone = TimeZone.current
        for format in [
            "yyyy-MM-dd'T'HH:mm:ss.SSSSSS",
            "yyyy-MM-dd'T'HH:mm:ss.SSS",
            "yyyy-MM-dd'T'HH:mm:ss"
        ] {
            parser.dateFormat = format
            if let date = parser.date(from: raw) {
                return date
            }
        }
        return nil
    }

    private static func formatTimestamp(_ date: Date?) -> String {
        guard let date else {
            return ""
        }
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "zh_CN")
        formatter.timeZone = TimeZone.current
        if Calendar.current.isDateInToday(date) {
            formatter.dateFormat = "HH:mm"
        } else {
            formatter.dateFormat = "M月d日 HH:mm"
        }
        return formatter.string(from: date)
    }
    }

struct TransferRecentContact: Identifiable {
    let id: String
    let payeeUserId: Int64
    let displayName: String
    let maskedRealName: String?
    let listDisplayName: String
    let summary: String
    let accountHint: String
    let detailText: String
    let interactionCount: Int64
    let lastInteractionAt: String?
    let avatarUrl: String?
    let avatarAssetName: String?
    let avatarText: String
    let avatarColor: Color

    private init(
        id: String,
        payeeUserId: Int64,
        displayName: String,
        maskedRealName: String?,
        listDisplayName: String,
        summary: String,
        accountHint: String,
        detailText: String,
        interactionCount: Int64,
        lastInteractionAt: String?,
        avatarUrl: String?,
        avatarAssetName: String?,
        avatarText: String,
        avatarColor: Color
    ) {
        self.id = id
        self.payeeUserId = payeeUserId
        self.displayName = displayName
        self.maskedRealName = maskedRealName
        self.listDisplayName = listDisplayName
        self.summary = summary
        self.accountHint = accountHint
        self.detailText = detailText
        self.interactionCount = interactionCount
        self.lastInteractionAt = lastInteractionAt
        self.avatarUrl = avatarUrl
        self.avatarAssetName = avatarAssetName
        self.avatarText = avatarText
        self.avatarColor = avatarColor
    }

    var hasReadableName: Bool {
        ContactDisplayNameResolver.isReadableName(displayName)
    }

    init(data: RecentContactData) {
        let resolvedPayeeUserId = Self.resolvedUserId(
            primary: data.contactUserId,
            alternative: data.contactAipayUid
        )
        let resolvedName = ContactDisplayNameResolver.preferredName(
            [
                data.contactNickname,
                data.contactDisplayName,
                data.contactMaskedRealName,
                data.contactAipayUid
            ],
            fallback: "爱付联系人"
        )
        let resolvedMaskedRealName = Self.normalized(data.contactMaskedRealName)

        self.id = "contact_\(resolvedPayeeUserId)"
        self.payeeUserId = resolvedPayeeUserId
        self.displayName = resolvedName
        self.maskedRealName = resolvedMaskedRealName
        self.listDisplayName = Self.listDisplayName(nickname: resolvedName, maskedRealName: resolvedMaskedRealName)
        self.summary = Self.summary(sceneCode: data.interactionSceneCode, remark: data.interactionRemark)
        self.accountHint = Self.firstNonBlank(data.contactMobileMasked, data.contactAipayUid, "未知账号")
        self.detailText = Self.detailText(lastInteractionAt: data.lastInteractionAt, summary: self.summary)
        self.interactionCount = max(0, data.interactionCount)
        self.lastInteractionAt = data.lastInteractionAt
        self.avatarUrl = Self.normalized(data.contactAvatarUrl)
        self.avatarAssetName = nil
        self.avatarText = Self.avatarText(name: resolvedName)
        self.avatarColor = Self.avatarColor(seed: resolvedPayeeUserId)
    }

    init(profile: UserProfile) {
        let resolvedPayeeUserId = Self.resolvedUserId(
            primary: profile.userId,
            alternative: profile.aipayUid
        )
        let resolvedMaskedRealName = Self.normalized(profile.maskedRealName)
        let resolvedName = ContactDisplayNameResolver.preferredName(
            [
                profile.nickname,
                resolvedMaskedRealName,
                profile.loginId,
                profile.aipayUid
            ],
            fallback: "爱付用户"
        )

        self.id = "contact_\(resolvedPayeeUserId)"
        self.payeeUserId = resolvedPayeeUserId
        self.displayName = resolvedName
        self.maskedRealName = resolvedMaskedRealName
        self.listDisplayName = Self.listDisplayName(nickname: resolvedName, maskedRealName: resolvedMaskedRealName)
        self.summary = "扫码转账"
        self.accountHint = Self.firstNonBlank(profile.mobile, profile.loginId, profile.aipayUid, "爱付账号")
        self.detailText = self.summary
        self.interactionCount = 0
        self.lastInteractionAt = nil
        self.avatarUrl = Self.normalized(profile.avatarUrl)
        self.avatarAssetName = demoAvatarAssetName(for: profile.avatarUrl)
        self.avatarText = Self.avatarText(name: resolvedName)
        self.avatarColor = Self.avatarColor(seed: resolvedPayeeUserId)
    }

    init(friend: ContactFriendData, recent: RecentContactData? = nil) {
        let resolvedPayeeUserId = Self.resolvedUserId(
            primary: friend.friendUserId,
            alternative: friend.aipayUid
        )
        let resolvedMaskedRealName = Self.firstNonBlank(
            Self.normalized(recent?.contactMaskedRealName),
            Self.normalized(friend.maskedRealName)
        )
        let resolvedName = ContactDisplayNameResolver.preferredName(
            [
                friend.nickname,
                recent?.contactNickname,
                recent?.contactDisplayName,
                resolvedMaskedRealName,
                friend.aipayUid,
                recent?.contactAipayUid
            ],
            fallback: "爱付好友"
        )
        let resolvedSummary: String
        if let recent {
            resolvedSummary = Self.summary(
                sceneCode: recent.interactionSceneCode,
                remark: recent.interactionRemark
            )
        } else {
            resolvedSummary = "爱付好友"
        }
        let resolvedAvatarUrl = Self.firstNonBlank(friend.avatarUrl, recent?.contactAvatarUrl)

        self.id = "contact_\(resolvedPayeeUserId)"
        self.payeeUserId = resolvedPayeeUserId
        self.displayName = resolvedName
        self.maskedRealName = resolvedMaskedRealName
        self.listDisplayName = Self.listDisplayName(nickname: resolvedName, maskedRealName: resolvedMaskedRealName)
        self.summary = resolvedSummary
        self.accountHint = Self.firstNonBlank(
            recent?.contactMobileMasked,
            friend.mobileMasked,
            friend.aipayUid,
            recent?.contactAipayUid,
            "爱付账号"
        )
        self.detailText = recent.map {
            Self.detailText(lastInteractionAt: $0.lastInteractionAt, summary: resolvedSummary)
        } ?? resolvedSummary
        self.interactionCount = max(0, recent?.interactionCount ?? 0)
        self.lastInteractionAt = recent?.lastInteractionAt ?? friend.createdAt
        self.avatarUrl = Self.normalized(resolvedAvatarUrl)
        self.avatarAssetName = demoAvatarAssetName(for: resolvedAvatarUrl)
        self.avatarText = Self.avatarText(name: resolvedName)
        self.avatarColor = Self.avatarColor(seed: resolvedPayeeUserId)
    }

    init(search: ContactSearchData) {
        let resolvedPayeeUserId = Self.resolvedUserId(
            primary: search.userId,
            alternative: search.aipayUid
        )
        let resolvedMaskedRealName = Self.normalized(search.maskedRealName)
        let resolvedName = ContactDisplayNameResolver.preferredName(
            [
                search.nickname,
                resolvedMaskedRealName,
                search.aipayUid,
                search.mobile
            ],
            fallback: "爱付用户"
        )

        self.id = "contact_\(resolvedPayeeUserId)"
        self.payeeUserId = resolvedPayeeUserId
        self.displayName = resolvedName
        self.maskedRealName = resolvedMaskedRealName
        self.listDisplayName = Self.listDisplayName(nickname: resolvedName, maskedRealName: resolvedMaskedRealName)
        self.summary = search.friend ? "爱付好友" : "可添加好友"
        self.accountHint = Self.firstNonBlank(
            TransferRecentContact.maskMobile(search.mobile),
            search.aipayUid,
            "爱付账号"
        )
        self.detailText = self.summary
        self.interactionCount = 0
        self.lastInteractionAt = nil
        self.avatarUrl = Self.normalized(search.avatarUrl)
        self.avatarAssetName = demoAvatarAssetName(for: search.avatarUrl)
        self.avatarText = Self.avatarText(name: resolvedName)
        self.avatarColor = Self.avatarColor(seed: resolvedPayeeUserId)
    }

    fileprivate init(conversation: MessageConversationItem) {
        let resolvedName = ContactDisplayNameResolver.preferredName(
            [conversation.title],
            fallback: "联系人"
        )
        let resolvedSummary: String = {
            let trimmedSubtitle = conversation.subtitle.trimmingCharacters(in: .whitespacesAndNewlines)
            return trimmedSubtitle == "[暂无消息]" ? "聊天会话" : trimmedSubtitle
        }()

        self.id = "contact_\(conversation.peerUserId)"
        self.payeeUserId = conversation.peerUserId
        self.displayName = resolvedName
        self.maskedRealName = nil
        self.listDisplayName = resolvedName
        self.summary = resolvedSummary
        self.accountHint = Self.firstNonBlank(conversation.conversationNo, "聊天会话")
        self.detailText = Self.detailText(lastInteractionAt: nil, summary: resolvedSummary)
        self.interactionCount = max(0, conversation.unreadCount)
        self.lastInteractionAt = nil
        self.avatarUrl = Self.normalized(conversation.avatarUrl)
        self.avatarAssetName = conversation.avatarAssetName
        self.avatarText = conversation.avatarText
        self.avatarColor = conversation.avatarColor
    }

    func applyingDirectoryPresentation(from source: TransferRecentContact) -> TransferRecentContact {
        let resolvedDisplayName = ContactDisplayNameResolver.preferredName(
            [
                source.displayName,
                self.displayName,
                source.maskedRealName,
                self.maskedRealName
            ],
            fallback: self.displayName
        )
        let resolvedMaskedRealName = Self.normalized(source.maskedRealName) ?? Self.normalized(self.maskedRealName)
        let resolvedAvatarUrl = Self.normalized(source.avatarUrl) ?? Self.normalized(self.avatarUrl)
        let resolvedAvatarAssetName = source.avatarAssetName ?? self.avatarAssetName

        return TransferRecentContact(
            id: id,
            payeeUserId: payeeUserId,
            displayName: resolvedDisplayName,
            maskedRealName: resolvedMaskedRealName,
            listDisplayName: Self.listDisplayName(nickname: resolvedDisplayName, maskedRealName: resolvedMaskedRealName),
            summary: summary,
            accountHint: accountHint,
            detailText: Self.detailText(lastInteractionAt: lastInteractionAt, summary: summary),
            interactionCount: interactionCount,
            lastInteractionAt: lastInteractionAt,
            avatarUrl: resolvedAvatarUrl,
            avatarAssetName: resolvedAvatarAssetName,
            avatarText: Self.avatarText(name: resolvedDisplayName),
            avatarColor: source.avatarColor
        )
    }

    private static func summary(sceneCode: String, remark: String?) -> String {
        let trimmedRemark = remark?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if !trimmedRemark.isEmpty {
            return trimmedRemark
        }
        switch sceneCode {
        case "APP_INTERNAL_TRANSFER":
            return "内部转账"
        case "MOBILE_TRANSFER":
            return "手机号转账"
        default:
            return "最近转账"
        }
    }

    private static func listDisplayName(nickname: String, maskedRealName: String?) -> String {
        let trimmedNickname = nickname.trimmingCharacters(in: .whitespacesAndNewlines)
        let trimmedMaskedRealName = maskedRealName?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !trimmedMaskedRealName.isEmpty else {
            return trimmedNickname
        }
        return "\(trimmedNickname)(\(trimmedMaskedRealName))"
    }

    private static func avatarText(name: String) -> String {
        let trimmed = name.trimmingCharacters(in: .whitespacesAndNewlines)
        if let first = trimmed.first {
            return String(first)
        }
        return "转"
    }

    private static func maskMobile(_ mobile: String?) -> String? {
        let digits = mobile?.filter(\.isNumber) ?? ""
        guard !digits.isEmpty else {
            return nil
        }
        if digits.count >= 11 {
            let prefix = String(digits.prefix(3))
            let suffix = String(digits.suffix(4))
            return "\(prefix)****\(suffix)"
        }
        if digits.count >= 7 {
            let prefix = String(digits.prefix(3))
            let suffix = String(digits.suffix(2))
            return "\(prefix)***\(suffix)"
        }
        return digits
    }

    private static func detailText(lastInteractionAt: String?, summary: String) -> String {
        let trimmedSummary = summary.trimmingCharacters(in: .whitespacesAndNewlines)
        let datePart = dateText(lastInteractionAt)
        if datePart.isEmpty {
            return trimmedSummary
        }
        if trimmedSummary.isEmpty {
            return datePart
        }
        return "\(datePart) \(trimmedSummary)"
    }

    private static func dateText(_ raw: String?) -> String {
        let trimmed = raw?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !trimmed.isEmpty else {
            return ""
        }
        if trimmed.count >= 10 {
            let start = trimmed.startIndex
            let end = trimmed.index(start, offsetBy: 10)
            let candidate = String(trimmed[start..<end])
            if candidate.filter({ $0 == "-" }).count == 2 {
                return candidate
            }
        }
        return ""
    }

    private static func normalized(_ raw: String?) -> String? {
        let trimmed = raw?.trimmingCharacters(in: .whitespacesAndNewlines)
        if let trimmed, !trimmed.isEmpty {
            return trimmed
        }
        return nil
    }

    private static func avatarColor(seed: Int64) -> Color {
        let palette: [Color] = [
            Color(red: 0.35, green: 0.35, blue: 0.35),
            Color(red: 0.27, green: 0.38, blue: 0.56),
            Color(red: 0.10, green: 0.10, blue: 0.10),
            Color(red: 0.10, green: 0.34, blue: 0.84),
            Color(red: 0.82, green: 0.57, blue: 0.22),
            Color(red: 0.42, green: 0.42, blue: 0.42)
        ]
        let index = Int(seed.magnitude % UInt64(palette.count))
        return palette[index]
    }

    private static func resolvedUserId(primary: Int64, alternative: String?) -> Int64 {
        let trimmedAlternative = alternative?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if let parsed = Int64(trimmedAlternative), parsed > 0 {
            return parsed
        }
        return primary
    }

    private static func firstNonBlank(_ values: String?...) -> String {
        for value in values {
            let trimmed = value?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            if !trimmed.isEmpty {
                return trimmed
            }
        }
        return ""
    }
}

private enum TransferRecentContactCacheStore {
    private static let defaults = UserDefaults.standard
    private static let encoder = JSONEncoder()
    private static let decoder = JSONDecoder()

    static func load(userId: Int64) -> [RecentContactData] {
        guard userId > 0,
              let data = defaults.data(forKey: key(for: userId)),
              let items = try? decoder.decode([RecentContactData].self, from: data) else {
            return []
        }
        return items
    }

    static func save(_ items: [RecentContactData], userId: Int64) {
        guard userId > 0 else {
            return
        }
        let cacheKey = key(for: userId)
        guard !items.isEmpty else {
            defaults.removeObject(forKey: cacheKey)
            return
        }
        guard let data = try? encoder.encode(items) else {
            return
        }
        defaults.set(data, forKey: cacheKey)
    }

    private static func key(for userId: Int64) -> String {
        "transfer.recent.contacts.\(userId)"
    }
}

private enum HomeSearchHistoryStore {
    private static let defaults = UserDefaults.standard
    private static let encoder = JSONEncoder()
    private static let decoder = JSONDecoder()
    private static let maxHistoryCount = 20

    static func load(userId: Int64?) -> [String] {
        guard let key = key(for: userId),
              let data = defaults.data(forKey: key),
              let rawItems = try? decoder.decode([String].self, from: data) else {
            return []
        }

        var dedupedItems: [String] = []
        for rawItem in rawItems {
            let normalizedItem = rawItem.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !normalizedItem.isEmpty else {
                continue
            }
            if dedupedItems.contains(where: { $0.caseInsensitiveCompare(normalizedItem) == .orderedSame }) {
                continue
            }
            dedupedItems.append(normalizedItem)
            if dedupedItems.count >= maxHistoryCount {
                break
            }
        }
        return dedupedItems
    }

    static func save(_ items: [String], userId: Int64?) {
        guard let key = key(for: userId) else {
            return
        }

        var normalizedItems: [String] = []
        for rawItem in items {
            let normalizedItem = rawItem.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !normalizedItem.isEmpty else {
                continue
            }
            if normalizedItems.contains(where: { $0.caseInsensitiveCompare(normalizedItem) == .orderedSame }) {
                continue
            }
            normalizedItems.append(normalizedItem)
            if normalizedItems.count >= maxHistoryCount {
                break
            }
        }

        guard !normalizedItems.isEmpty else {
            defaults.removeObject(forKey: key)
            return
        }

        guard let data = try? encoder.encode(normalizedItems) else {
            return
        }
        defaults.set(data, forKey: key)
    }

    private static func key(for userId: Int64?) -> String? {
        guard let userId, userId > 0 else {
            return nil
        }
        return "home.search.history.\(userId)"
    }
}

private struct MessageFriendRequestsDigestPageView: View {
    let requests: [ContactRequestData]
    let isLoading: Bool
    let loadErrorMessage: String?
    let handlingRequestNo: String?
    let displayNameForRequester: (Int64) -> String
    let subtitleForRequester: (Int64) -> String?
    let onBack: () -> Void
    let onRefresh: @MainActor () async -> Void
    let onEnsureRequesterLoaded: @MainActor (Int64) async -> Void
    let onHandleRequest: @MainActor (ContactRequestData, String) async -> String?

    @State private var noticeMessage: String?

    private let pageBackgroundColor = Color(red: 0.95, green: 0.95, blue: 0.96)

    var body: some View {
        GeometryReader { proxy in
            let topInset = max(proxy.safeAreaInsets.top, 44)
            let contentTopPadding = topInset + 62

            ZStack(alignment: .top) {
                pageBackgroundColor
                    .ignoresSafeArea()

                ScrollView(showsIndicators: false) {
                    VStack(spacing: 12) {
                        Color.clear
                            .frame(height: contentTopPadding)

                        if isLoading && requests.isEmpty {
                            ProgressView()
                                .progressViewStyle(.circular)
                                .tint(Color(red: 0.46, green: 0.48, blue: 0.52))
                                .padding(.top, 54)
                        } else if requests.isEmpty {
                            Text(loadErrorMessage ?? "暂无好友申请")
                                .font(.system(size: 14, weight: .regular))
                                .foregroundStyle(Color(red: 0.58, green: 0.59, blue: 0.62))
                                .frame(maxWidth: .infinity)
                                .padding(.top, 54)
                        } else {
                            LazyVStack(spacing: 10) {
                                ForEach(requests, id: \.requestNo) { request in
                                    requestRow(request)
                                        .onAppear {
                                            Task {
                                                await onEnsureRequesterLoaded(request.requesterUserId)
                                            }
                                        }
                                }
                            }
                        }

                        Color.clear
                            .frame(height: 24)
                    }
                    .padding(.horizontal, 10)
                }

                headerView(topInset: topInset)
            }
            .overlay(alignment: .top) {
                if let noticeMessage {
                    Text(noticeMessage)
                        .font(.system(size: 13, weight: .medium))
                        .foregroundStyle(Color.white)
                        .padding(.horizontal, 12)
                        .padding(.vertical, 7)
                        .background(
                            Capsule()
                                .fill(Color.black.opacity(0.72))
                        )
                        .padding(.top, topInset + 12)
                        .transition(.opacity)
                }
            }
        }
        .task {
            await onRefresh()
        }
    }

    private func requestRow(_ request: ContactRequestData) -> some View {
        let requestNo = request.requestNo.trimmingCharacters(in: .whitespacesAndNewlines)
        let isHandling = !requestNo.isEmpty && requestNo == handlingRequestNo
        let status = request.status.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let isPending = status == "PENDING"
        let requesterName = displayNameForRequester(request.requesterUserId)

        return VStack(spacing: 0) {
            HStack(alignment: .top, spacing: 10) {
                ContactAvatarView(
                    avatarUrl: nil,
                    avatarAssetName: nil,
                    avatarText: requesterName,
                    avatarColor: AppTheme.palette.brandPrimaryLight,
                    size: 44
                )

                VStack(alignment: .leading, spacing: 5) {
                    Text(requesterName)
                        .font(.system(size: 17, weight: .medium))
                        .foregroundStyle(Color(red: 0.18, green: 0.19, blue: 0.22))
                        .lineLimit(1)

                    if let subtitle = subtitleForRequester(request.requesterUserId), !subtitle.isEmpty {
                        Text(subtitle)
                            .font(.system(size: 13, weight: .regular))
                            .foregroundStyle(Color(red: 0.60, green: 0.61, blue: 0.64))
                            .lineLimit(1)
                    }

                    if let applyMessage = request.applyMessage?.trimmingCharacters(in: .whitespacesAndNewlines),
                       !applyMessage.isEmpty {
                        Text("验证消息：\(applyMessage)")
                            .font(.system(size: 13, weight: .regular))
                            .foregroundStyle(Color(red: 0.50, green: 0.51, blue: 0.55))
                            .lineLimit(2)
                    }
                }

                Spacer(minLength: 0)

                if !isPending {
                    Text(statusText(for: status))
                        .font(.system(size: 13, weight: .medium))
                        .foregroundStyle(Color(red: 0.53, green: 0.54, blue: 0.57))
                        .padding(.top, 2)
                }
            }
            .padding(.horizontal, 14)
            .padding(.top, 13)
            .padding(.bottom, isPending ? 10 : 14)

            if isPending {
                HStack(spacing: 8) {
                    Spacer(minLength: 0)

                    Button {
                        Task {
                            let errorMessage = await onHandleRequest(request, "REJECT")
                            await MainActor.run {
                                noticeMessage = errorMessage ?? "已忽略申请"
                            }
                        }
                    } label: {
                        Text("忽略")
                            .font(.system(size: 14, weight: .medium))
                            .foregroundStyle(Color(red: 0.43, green: 0.44, blue: 0.47))
                            .frame(width: 68, height: 31)
                            .background(
                                RoundedRectangle(cornerRadius: 15.5, style: .continuous)
                                    .fill(Color(red: 0.92, green: 0.93, blue: 0.95))
                            )
                    }
                    .buttonStyle(.plain)
                    .disabled(isHandling)

                    Button {
                        Task {
                            let errorMessage = await onHandleRequest(request, "ACCEPT")
                            await MainActor.run {
                                noticeMessage = errorMessage ?? "已同意申请"
                            }
                        }
                    } label: {
                        Text(isHandling ? "处理中" : "同意")
                            .font(.system(size: 14, weight: .semibold))
                            .foregroundStyle(Color.white)
                            .frame(width: 72, height: 31)
                            .background(
                                RoundedRectangle(cornerRadius: 15.5, style: .continuous)
                                    .fill(Color(red: 0.16, green: 0.62, blue: 0.31))
                            )
                    }
                    .buttonStyle(.plain)
                    .disabled(isHandling)
                }
                .padding(.horizontal, 14)
                .padding(.bottom, 12)
            }
        }
        .background(
            RoundedRectangle(cornerRadius: 16, style: .continuous)
                .fill(Color.white)
        )
    }

    private func statusText(for normalizedStatus: String) -> String {
        switch normalizedStatus {
        case "ACCEPT", "ACCEPTED":
            return "已同意"
        case "REJECT", "REJECTED":
            return "已忽略"
        default:
            return "处理中"
        }
    }

    private func headerView(topInset: CGFloat) -> some View {
        ZStack {
            HStack {
                Button(action: onBack) {
                    Image(systemName: "chevron.left")
                        .font(.system(size: 19, weight: .medium))
                        .foregroundStyle(Color(red: 0.26, green: 0.27, blue: 0.31))
                        .frame(width: 36, height: 36)
                        .contentShape(Rectangle())
                }
                .buttonStyle(.plain)

                Spacer(minLength: 0)
            }
            .padding(.horizontal, 12)
            .padding(.top, topInset + 2)

            Text("好友申请")
                .font(.system(size: 19, weight: .semibold))
                .foregroundStyle(Color(red: 0.20, green: 0.21, blue: 0.24))
                .padding(.top, topInset + 2)
        }
        .frame(maxWidth: .infinity, alignment: .top)
        .padding(.bottom, 10)
        .background(
            pageBackgroundColor
                .overlay(alignment: .top) {
                    Rectangle()
                        .fill(pageBackgroundColor)
                        .frame(height: topInset + 72)
                        .ignoresSafeArea(edges: .top)
                }
                .ignoresSafeArea(edges: .top)
        )
        .overlay(alignment: .bottom) {
            Rectangle()
                .fill(Color(red: 0.89, green: 0.90, blue: 0.92))
                .frame(height: 0.8)
        }
    }
}

private struct MessageContactsDirectoryPageView: View {
    let contacts: [TransferRecentContact]
    let isLoading: Bool
    let loadErrorMessage: String?
    let onBack: () -> Void
    let onAddFriend: () -> Void
    let onEnsureLoaded: @MainActor () async -> Void
    let onSelectContact: (TransferRecentContact) -> Void
    @State private var cachedSections: [SectionData] = []
    @State private var cachedSectionTitleSet: Set<String> = []

    private static let indexTitles = Array("ABCDEFGHIJKLMNOPQRSTUVWXYZ").map(String.init) + ["#"]
    private let pageBackgroundColor = Color(red: 0.95, green: 0.95, blue: 0.96)

    private struct SectionData: Identifiable {
        let id: String
        let title: String
        let contacts: [TransferRecentContact]
    }

    private var sectionBuildKey: Int {
        var hasher = Hasher()
        hasher.combine(contacts.count)
        contacts.forEach { contact in
            hasher.combine(contact.id)
            hasher.combine(contact.displayName)
        }
        return hasher.finalize()
    }

    @MainActor
    private func rebuildSections() {
        let sections = Self.buildSections(from: contacts)
        cachedSections = sections
        cachedSectionTitleSet = Set(sections.map(\.title))
    }

    private static func buildSections(from contacts: [TransferRecentContact]) -> [SectionData] {
        guard !contacts.isEmpty else {
            return []
        }

        var sortKeyMap: [String: String] = [:]
        sortKeyMap.reserveCapacity(contacts.count)
        contacts.forEach { contact in
            sortKeyMap[contact.id] = sortKey(for: contact.displayName)
        }

        let sortedContacts = contacts.sorted { lhs, rhs in
            let lhsKey = sortKeyMap[lhs.id] ?? sortKey(for: lhs.displayName)
            let rhsKey = sortKeyMap[rhs.id] ?? sortKey(for: rhs.displayName)
            if lhsKey == rhsKey {
                return lhs.displayName.localizedCompare(rhs.displayName) == .orderedAscending
            }
            return lhsKey < rhsKey
        }

        let grouped = Dictionary(grouping: sortedContacts) { contact in
            let key = sortKeyMap[contact.id] ?? sortKey(for: contact.displayName)
            return indexTitle(forSortKey: key)
        }

        return indexTitles.compactMap { title in
            guard let groupedContacts = grouped[title], !groupedContacts.isEmpty else {
                return nil
            }
            return SectionData(
                id: "message_contacts_section_\(title)",
                title: title,
                contacts: groupedContacts
            )
        }
    }

    var body: some View {
        GeometryReader { proxy in
            let topInset = max(proxy.safeAreaInsets.top, 44)
            let contentTopPadding = topInset + 57

            ZStack(alignment: .top) {
                pageBackgroundColor
                    .ignoresSafeArea()

                ScrollViewReader { scrollProxy in
                    ScrollView(showsIndicators: false) {
                        VStack(alignment: .leading, spacing: 14) {
                            Color.clear
                                .frame(height: contentTopPadding)

                            if isLoading && contacts.isEmpty {
                                loadingView
                            } else if cachedSections.isEmpty {
                                emptyView
                            } else {
                                ForEach(cachedSections) { section in
                                    VStack(alignment: .leading, spacing: 8) {
                                        Text(section.title)
                                            .font(.system(size: 13, weight: .medium))
                                            .foregroundStyle(Color(red: 0.60, green: 0.60, blue: 0.62))
                                            .padding(.leading, 8)

                                        VStack(spacing: 0) {
                                            ForEach(Array(section.contacts.enumerated()), id: \.element.id) { index, contact in
                                                contactRow(
                                                    contact: contact,
                                                    showDivider: index < section.contacts.count - 1
                                                )
                                                .frame(maxWidth: .infinity, alignment: .leading)
                                                .contentShape(Rectangle())
                                                .onTapGesture {
                                                    onSelectContact(contact)
                                                }
                                                .accessibilityIdentifier("message_contacts_row_\(contact.id)")
                                            }
                                        }
                                        .background(
                                            RoundedRectangle(cornerRadius: 16, style: .continuous)
                                                .fill(Color.white)
                                        )
                                    }
                                    .id(section.id)
                                }
                            }

                            Color.clear
                                .frame(height: 24)
                        }
                        .padding(.horizontal, 10)
                    }
                    .overlay(alignment: .trailing) {
                        indexBar(scrollProxy: scrollProxy, topInset: contentTopPadding)
                    }
                }

                headerView(topInset: topInset)
            }
        }
        .task {
            await onEnsureLoaded()
        }
        .task(id: sectionBuildKey) {
            rebuildSections()
        }
    }

    private var loadingView: some View {
        VStack(spacing: 12) {
            ProgressView()
                .progressViewStyle(.circular)
                .tint(Color(red: 0.49, green: 0.50, blue: 0.54))

            Text("通讯录加载中...")
                .font(.system(size: 14, weight: .regular))
                .foregroundStyle(Color(red: 0.58, green: 0.59, blue: 0.62))
        }
        .frame(maxWidth: .infinity)
        .padding(.top, 88)
    }

    private var emptyView: some View {
        Text(loadErrorMessage ?? "暂无联系人")
            .font(.system(size: 14, weight: .regular))
            .foregroundStyle(Color(red: 0.58, green: 0.59, blue: 0.62))
            .frame(maxWidth: .infinity)
            .padding(.top, 88)
    }

    private func headerView(topInset: CGFloat) -> some View {
        let headerVerticalOffset: CGFloat = 10

        return ZStack {
            HStack {
                Button(action: onBack) {
                    Image(systemName: "chevron.left")
                        .font(.system(size: 19, weight: .medium))
                        .foregroundStyle(Color(red: 0.26, green: 0.27, blue: 0.31))
                        .frame(width: 36, height: 36)
                        .contentShape(Rectangle())
                }
                .buttonStyle(.plain)

                Spacer()

                Button(action: onAddFriend) {
                    Text("添加朋友")
                        .font(.system(size: 17, weight: .regular))
                        .foregroundStyle(Color(red: 0.22, green: 0.23, blue: 0.27))
                }
                .buttonStyle(.plain)
            }
            .padding(.horizontal, 12)
            .padding(.top, topInset + 2 + headerVerticalOffset)

            Text("通讯录")
                .font(.system(size: 19, weight: .semibold))
                .foregroundStyle(Color(red: 0.20, green: 0.21, blue: 0.24))
                .padding(.top, topInset + 2 + headerVerticalOffset)
        }
        .frame(maxWidth: .infinity, alignment: .top)
        .padding(.bottom, 10)
        .background(
            pageBackgroundColor
                .overlay(alignment: .top) {
                    Rectangle()
                        .fill(pageBackgroundColor)
                        .frame(height: topInset + 72)
                        .ignoresSafeArea(edges: .top)
                }
                .ignoresSafeArea(edges: .top)
        )
        .overlay(alignment: .bottom) {
            Rectangle()
                .fill(Color(red: 0.89, green: 0.90, blue: 0.92))
                .frame(height: 0.8)
        }
    }

    private func indexBar(scrollProxy: ScrollViewProxy, topInset: CGFloat) -> some View {
        VStack(spacing: 1) {
            ForEach(Self.indexTitles, id: \.self) { title in
                let hasSection = cachedSectionTitleSet.contains(title)

                Button {
                    guard hasSection else {
                        return
                    }
                    withAnimation(.easeInOut(duration: 0.18)) {
                        scrollProxy.scrollTo("message_contacts_section_\(title)", anchor: .top)
                    }
                } label: {
                    Text(title)
                        .font(.system(size: 10, weight: .medium))
                        .foregroundStyle(
                            hasSection
                                ? Color(red: 0.40, green: 0.42, blue: 0.46)
                                : Color(red: 0.79, green: 0.80, blue: 0.83)
                        )
                        .frame(width: 18, height: 12)
                        .contentShape(Rectangle())
                }
                .buttonStyle(.plain)
            }
        }
        .padding(.trailing, 4)
        .padding(.top, topInset + 10)
    }

    private func contactRow(contact: TransferRecentContact, showDivider: Bool) -> some View {
        VStack(spacing: 0) {
            HStack(spacing: 12) {
                ContactAvatarView(
                    avatarUrl: contact.avatarUrl,
                    avatarAssetName: contact.avatarAssetName,
                    avatarText: contact.avatarText,
                    avatarColor: contact.avatarColor,
                    size: 42
                )

                VStack(alignment: .leading, spacing: 4) {
                    Text(contact.displayName)
                        .font(.system(size: 18, weight: .medium))
                        .foregroundStyle(Color(red: 0.17, green: 0.18, blue: 0.21))
                        .lineLimit(1)

                    Text(contact.maskedRealName ?? contact.summary)
                        .font(.system(size: 14, weight: .regular))
                        .foregroundStyle(Color(red: 0.63, green: 0.64, blue: 0.67))
                        .lineLimit(1)
                }

                Spacer(minLength: 0)
            }
            .padding(.horizontal, 14)
            .frame(height: 58)

            if showDivider {
                Rectangle()
                    .fill(Color(red: 0.91, green: 0.92, blue: 0.94))
                    .frame(height: 0.8)
                    .padding(.leading, 68)
            }
        }
    }

    private static func contactSort(_ lhs: TransferRecentContact, _ rhs: TransferRecentContact) -> Bool {
        let lhsKey = sortKey(for: lhs.displayName)
        let rhsKey = sortKey(for: rhs.displayName)
        if lhsKey == rhsKey {
            return lhs.displayName.localizedCompare(rhs.displayName) == .orderedAscending
        }
        return lhsKey < rhsKey
    }

    private static func indexTitle(for name: String) -> String {
        let key = sortKey(for: name)
        return indexTitle(forSortKey: key)
    }

    private static func indexTitle(forSortKey key: String) -> String {
        guard let letter = key.first(where: { $0.isLetter }) else {
            return "#"
        }
        let resolved = String(letter)
        return indexTitles.contains(resolved) ? resolved : "#"
    }

    private static func sortKey(for name: String) -> String {
        let mutable = NSMutableString(string: name) as CFMutableString
        CFStringTransform(mutable, nil, kCFStringTransformToLatin, false)
        CFStringTransform(mutable, nil, kCFStringTransformStripCombiningMarks, false)
        return (mutable as String)
            .uppercased()
            .replacingOccurrences(of: " ", with: "")
    }
}

