    @MainActor
    private func searchByPhone() async {
        let phone = normalizedPhoneDigits
        guard phone.count == 11 else {
            searchResult = nil
            searchMessage = "请输入完整的 11 位手机号"
            return
        }
        guard let ownerUserId, ownerUserId > 0 else {
            searchResult = nil
            searchMessage = "未找到当前登录用户"
            return
        }

        isSearching = true
        searchMessage = nil
        defer {
            isSearching = false
        }

        do {
            let results = try await APIClient.shared.searchContacts(
                ownerUserId: ownerUserId,
                keyword: phone,
                limit: 30
            )
            let matched = bestMatchedContact(in: results, by: phone)
            if let matched {
                if matched.userId == ownerUserId {
                    searchResult = nil
                    searchMessage = "不能添加自己为好友"
                    return
                }
                searchResult = matched
                searchMessage = nil
            } else {
                searchResult = nil
                searchMessage = "未搜索到该用户"
            }
        } catch {
            if isCancellationLikeError(error) {
                return
            }
            searchResult = nil
            searchMessage = userFacingErrorMessage(error)
        }
    }

    private func bestMatchedContact(in results: [ContactSearchData], by phone: String) -> ContactSearchData? {
        if results.isEmpty {
            return nil
        }
        if let exactMobile = results.first(where: {
            $0.mobile?.filter(\.isNumber) == phone
        }) {
            return exactMobile
        }
        return results.first
    }

    @MainActor
    private func submitFriendRequest(targetUserId: Int64, applyMessage: String) async -> Bool {
        func failInApplySheet(_ message: String) -> Bool {
            let normalizedMessage = normalizedApplySheetErrorMessage(message)
            applySheetErrorMessage = normalizedMessage
            searchMessage = normalizedMessage
            return false
        }

        guard let ownerUserId, ownerUserId > 0 else {
            return failInApplySheet("未找到当前登录用户")
        }
        guard targetUserId > 0 else {
            return failInApplySheet("目标用户无效")
        }
        guard targetUserId != ownerUserId else {
            return failInApplySheet("不能添加自己为好友")
        }
        if submittedUserIds.contains(targetUserId) {
            return false
        }

        applySheetErrorMessage = nil
        isSubmitting = true
        defer {
            isSubmitting = false
        }

        do {
            try await APIClient.shared.applyFriendRequest(
                requesterUserId: ownerUserId,
                targetUserId: targetUserId,
                applyMessage: applyMessage
            )
            submittedUserIds.insert(targetUserId)
            searchMessage = "好友申请已发送，对方可在消息列表中看到申请"
            await onRequestSubmitted()
            return true
        } catch {
            if isCancellationLikeError(error) {
                return false
            }
            return failInApplySheet(userFacingErrorMessage(error))
        }
    }

    private func openApplySheet(for result: ContactSearchData) {
        pendingApplyTarget = result
        applyMessageDraft = ""
        applySheetErrorMessage = nil
        isApplySheetPresented = true
        isInputFocused = false
    }

    private func closeApplySheet() {
        guard !isSubmitting else {
            return
        }
        isApplySheetPresented = false
        pendingApplyTarget = nil
        applyMessageDraft = ""
        applySheetErrorMessage = nil
    }

    private func normalizedApplySheetErrorMessage(_ raw: String) -> String {
        let trimmed = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else {
            return "发送好友申请失败，请稍后重试"
        }
        if trimmed.contains("用户鉴权失败") && trimmed.contains("请求用户与令牌不匹配") {
            return "用户鉴权失败，请求用户与令牌不匹配"
        }
        return trimmed
    }

    private var normalizedApplyMessageDraft: String {
        let trimmed = applyMessageDraft.trimmingCharacters(in: .whitespacesAndNewlines)
        return trimmed.isEmpty ? defaultApplyMessageForSubmit : trimmed
    }

