                ZStack(alignment: .leading) {
                    RoundedRectangle(cornerRadius: 9, style: .continuous)
                        .fill(Color(red: 0.97, green: 0.97, blue: 0.98))
                        .overlay(
                            RoundedRectangle(cornerRadius: 9, style: .continuous)
                                .stroke(
                                    Color(red: 0.86, green: 0.87, blue: 0.90),
                                    lineWidth: 1
                                )
                        )

                    TextField(
                        applyMessagePlaceholder,
                        text: Binding(
                            get: { applyMessageDraft },
                            set: { value in
                                applyMessageDraft = String(value.prefix(40))
                            }
                        )
                    )
                    .font(.system(size: 14, weight: .regular))
                    .foregroundStyle(Color(red: 0.24, green: 0.25, blue: 0.29))
                    .padding(.horizontal, 10)
                    .padding(.vertical, 9)
                }
                .frame(height: 38)
            }

            if let applySheetErrorMessage, !applySheetErrorMessage.isEmpty {
                Text(applySheetErrorMessage)
                    .font(.system(size: 12.5, weight: .regular))
                    .foregroundStyle(Color(red: 0.86, green: 0.28, blue: 0.26))
                    .frame(maxWidth: .infinity, alignment: .leading)
                    .fixedSize(horizontal: false, vertical: true)
            }

            HStack(spacing: 8) {
                Button(action: closeApplySheet) {
                    Text("取消")
                        .font(.system(size: 14, weight: .medium))
                        .foregroundStyle(Color(red: 0.50, green: 0.52, blue: 0.55))
                        .frame(maxWidth: .infinity)
                        .frame(height: 36)
                        .background(
                            RoundedRectangle(cornerRadius: 9, style: .continuous)
                                .fill(Color(red: 0.93, green: 0.94, blue: 0.96))
                        )
                }
                .buttonStyle(.plain)
                .disabled(isSubmitting)

                Button(action: {
                    guard let pendingApplyTarget else {
                        return
                    }
                    let targetUserId = pendingApplyTarget.userId
                    let submitApplyMessage = normalizedApplyMessageDraft
                    isApplySheetPresented = false
                    self.pendingApplyTarget = nil
                    applyMessageDraft = ""
                    applySheetErrorMessage = nil
                    Task {
                        _ = await submitFriendRequest(
                            targetUserId: targetUserId,
                            applyMessage: submitApplyMessage
                        )
                    }
                }) {
                    Text(isSubmitting ? "发送中..." : "发送")
                        .font(.system(size: 14, weight: .semibold))
                        .foregroundStyle(Color.white)
                        .frame(maxWidth: .infinity)
                        .frame(height: 36)
                        .background(
                            RoundedRectangle(cornerRadius: 9, style: .continuous)
                                .fill(AppTheme.palette.brandPrimaryLight)
                        )
                }
                .buttonStyle(.plain)
                .disabled(isSubmitting || pendingApplyTarget == nil)
            }
        }
        .padding(.horizontal, 12)
        .padding(.vertical, 12)
        .frame(maxWidth: 336)
        .background(
            RoundedRectangle(cornerRadius: 14, style: .continuous)
                .fill(Color.white)
        )
        .overlay(
            RoundedRectangle(cornerRadius: 14, style: .continuous)
                .stroke(Color(red: 0.89, green: 0.90, blue: 0.93), lineWidth: 0.8)
        )
        .shadow(color: Color.black.opacity(0.10), radius: 12, x: 0, y: 6)
    }
}

private struct MessageFriendRequestsPageView: View {
    let requests: [ContactRequestData]
    let requesterDigests: [Int64: UserProfile]
    let isLoading: Bool
    let loadErrorMessage: String?
    let handlingRequestNo: String?
    let onBack: () -> Void
    let onRefresh: @MainActor () async -> Void
    let onEnsureRequesterLoaded: (Int64) async -> Void
    let onHandleRequest: (ContactRequestData, String) async -> String?

    @State private var statusMessage: String?

    private let pageBackgroundColor = Color(red: 0.95, green: 0.95, blue: 0.96)

    private var orderedRequests: [ContactRequestData] {
        requests.sorted { lhs, rhs in
            let lhsTime = lhs.createdAt?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            let rhsTime = rhs.createdAt?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            if lhsTime == rhsTime {
                return lhs.requestNo > rhs.requestNo
            }
            return lhsTime > rhsTime
        }
    }

    var body: some View {
        GeometryReader { proxy in
            let topInset = max(proxy.safeAreaInsets.top, 44)

            ZStack(alignment: .top) {
                pageBackgroundColor
                    .ignoresSafeArea()

                VStack(spacing: 0) {
                    headerView(topInset: topInset)

                    if let statusMessage, !statusMessage.isEmpty {
                        Text(statusMessage)
                            .font(.system(size: 13, weight: .regular))
                            .foregroundStyle(Color(red: 0.10, green: 0.62, blue: 0.30))
                            .frame(maxWidth: .infinity, alignment: .leading)
                            .padding(.horizontal, 14)
                            .padding(.top, 10)
                    }

                    contentView
                        .padding(.top, statusMessage == nil ? 10 : 6)
                }
            }
        }
        .task {
            await onRefresh()
        }
    }

    @ViewBuilder
    private var contentView: some View {
        if isLoading && orderedRequests.isEmpty {
            VStack(spacing: 10) {
                ProgressView()
                    .progressViewStyle(.circular)
                    .tint(Color(red: 0.49, green: 0.50, blue: 0.54))
                Text("好友申请加载中...")
                    .font(.system(size: 14, weight: .regular))
                    .foregroundStyle(Color(red: 0.58, green: 0.59, blue: 0.62))
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .top)
            .padding(.top, 70)
        } else if orderedRequests.isEmpty {
            Text(loadErrorMessage ?? "暂无新的好友申请")
                .font(.system(size: 14, weight: .regular))
                .foregroundStyle(Color(red: 0.58, green: 0.59, blue: 0.62))
                .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .top)
                .padding(.top, 70)
        } else {
            ScrollView(showsIndicators: false) {
                VStack(spacing: 10) {
                    ForEach(orderedRequests, id: \.requestNo) { request in
                        requestCard(request)
                            .task {
                                await onEnsureRequesterLoaded(request.requesterUserId)
                            }
                    }
                    Color.clear
                        .frame(height: 20)
                }
                .padding(.horizontal, 12)
            }
        }
    }

    private func headerView(topInset: CGFloat) -> some View {
        ZStack {
            HStack(spacing: 0) {
                Button(action: onBack) {
                    Image(systemName: "chevron.left")
                        .font(.system(size: 19, weight: .medium))
                        .foregroundStyle(Color(red: 0.26, green: 0.27, blue: 0.31))
                        .frame(width: 36, height: 36)
                        .contentShape(Rectangle())
                }
                .buttonStyle(.plain)

                Spacer(minLength: 0)
            }
            .padding(.horizontal, 12)
            .padding(.top, topInset + 10)

            Text("好友申请")
                .font(.system(size: 19, weight: .semibold))
                .foregroundStyle(Color(red: 0.20, green: 0.21, blue: 0.24))
                .padding(.top, topInset + 10)
        }
        .padding(.bottom, 8)
        .background(
            pageBackgroundColor
                .overlay(alignment: .bottom) {
                    Rectangle()
                        .fill(Color(red: 0.89, green: 0.90, blue: 0.92))
                        .frame(height: 0.8)
                }
        )
    }

    private func requestCard(_ request: ContactRequestData) -> some View {
        let digest = requesterDigests[request.requesterUserId]
        let displayName = displayName(for: request, digest: digest)
        let subtitle = subtitleText(for: request, digest: digest, displayName: displayName)
        let requestNo = request.requestNo.trimmingCharacters(in: .whitespacesAndNewlines)
        let status = normalizedStatus(request.status)
        let isPending = status == "PENDING"
        let isHandling = handlingRequestNo == requestNo
        let avatarUrl = normalizedText(digest?.avatarUrl) ?? normalizedText(request.requesterAvatarUrl)

        return VStack(alignment: .leading, spacing: 10) {
            HStack(spacing: 12) {
                ContactAvatarView(
                    avatarUrl: avatarUrl,
                    avatarAssetName: nil,
                    avatarText: avatarText(for: displayName),
                    avatarColor: avatarColor(seed: request.requesterUserId),
                    size: 44
                )

                VStack(alignment: .leading, spacing: 3) {
                    Text(displayName)
                        .font(.system(size: 17, weight: .medium))
                        .foregroundStyle(Color(red: 0.17, green: 0.18, blue: 0.21))
                        .lineLimit(1)

                    Text(subtitle)
                        .font(.system(size: 13, weight: .regular))
                        .foregroundStyle(Color(red: 0.62, green: 0.63, blue: 0.66))
                        .lineLimit(1)
                }

                Spacer(minLength: 0)

                Text(statusLabel(for: status))
                    .font(.system(size: 12, weight: .regular))
                    .foregroundStyle(statusColor(for: status))
            }

            Text(request.applyMessage?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false
                ? (request.applyMessage ?? "")
                : "请求添加你为好友")
                .font(.system(size: 14, weight: .regular))
                .foregroundStyle(Color(red: 0.34, green: 0.35, blue: 0.38))
                .lineLimit(2)

            HStack(spacing: 10) {
                Text(dateText(request.createdAt))
                    .font(.system(size: 12, weight: .regular))
                    .foregroundStyle(Color(red: 0.70, green: 0.71, blue: 0.74))

                Spacer(minLength: 0)

                if isPending {
                    actionButton(
                        title: "拒绝",
                        fill: Color(red: 0.93, green: 0.94, blue: 0.96),
                        textColor: Color(red: 0.50, green: 0.52, blue: 0.55),
                        disabled: isHandling || requestNo.isEmpty
                    ) {
                        Task {
                            statusMessage = await onHandleRequest(request, "REJECT") ?? "已拒绝好友申请"
                        }
                    }

                    actionButton(
                        title: "同意",
                        fill: AppTheme.palette.brandPrimaryLight,
                        textColor: .white,
                        disabled: isHandling || requestNo.isEmpty
                    ) {
                        Task {
                            statusMessage = await onHandleRequest(request, "ACCEPT") ?? "已同意好友申请"
                        }
                    }
                }
            }
        }
        .padding(.horizontal, 14)
        .padding(.vertical, 12)
        .background(
            RoundedRectangle(cornerRadius: 14, style: .continuous)
                .fill(Color.white)
        )
    }

    private func actionButton(
        title: String,
        fill: Color,
        textColor: Color,
        disabled: Bool,
        action: @escaping () -> Void
    ) -> some View {
        Button(action: action) {
            Text(title)
                .font(.system(size: 14, weight: .medium))
                .foregroundStyle(disabled ? Color(red: 0.70, green: 0.71, blue: 0.74) : textColor)
                .frame(width: 60, height: 32)
                .background(
                    RoundedRectangle(cornerRadius: 8, style: .continuous)
                        .fill(disabled ? Color(red: 0.94, green: 0.95, blue: 0.97) : fill)
                )
        }
        .buttonStyle(.plain)
        .disabled(disabled)
    }

    private func displayName(for request: ContactRequestData, digest: UserProfile?) -> String {
        if let requesterNickname = normalizedText(request.requesterNickname) {
            return requesterNickname
        }
        if let nickname = digest?.nickname.trimmingCharacters(in: .whitespacesAndNewlines), !nickname.isEmpty {
            return nickname
        }
        if let requesterMaskedRealName = normalizedText(request.requesterMaskedRealName) {
            return requesterMaskedRealName
        }
        if let maskedRealName = digest?.maskedRealName?.trimmingCharacters(in: .whitespacesAndNewlines),
           !maskedRealName.isEmpty {
            return maskedRealName
        }
        if let requesterMobileMasked = normalizedText(request.requesterMobileMasked) {
            return requesterMobileMasked
        }
        if let mobile = digest?.mobile,
           let maskedMobile = maskMobile(mobile),
           !maskedMobile.isEmpty {
            return maskedMobile
        }
        return "爱付用户"
    }

    private func subtitleText(for request: ContactRequestData, digest: UserProfile?, displayName: String) -> String {
        if let requesterMaskedRealName = normalizedText(request.requesterMaskedRealName),
           requesterMaskedRealName != displayName {
            return requesterMaskedRealName
        }
        if let maskedRealName = digest?.maskedRealName?.trimmingCharacters(in: .whitespacesAndNewlines),
           !maskedRealName.isEmpty,
           maskedRealName != displayName {
            return maskedRealName
        }
        if let requesterMobileMasked = normalizedText(request.requesterMobileMasked),
           requesterMobileMasked != displayName {
            return requesterMobileMasked
        }
        if let mobile = digest?.mobile,
           let masked = maskMobile(mobile),
           masked != displayName {
            return masked
        }
        return "爱付用户"
    }

    private func normalizedText(_ raw: String?) -> String? {
        guard let raw else {
            return nil
        }
        let normalized = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        return normalized.isEmpty ? nil : normalized
    }

    private func avatarText(for name: String) -> String {
        let trimmed = name.trimmingCharacters(in: .whitespacesAndNewlines)
        if let first = trimmed.first {
            return String(first)
        }
        return "友"
    }

    private func normalizedStatus(_ raw: String?) -> String {
        raw?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() ?? "UNKNOWN"
    }

    private func statusLabel(for status: String) -> String {
        switch status {
        case "PENDING":
            return "待处理"
        case "ACCEPTED":
            return "已同意"
        case "REJECTED":
            return "已拒绝"
        case "CANCELED":
            return "已取消"
        default:
            return "未知状态"
        }
    }

    private func statusColor(for status: String) -> Color {
        switch status {
        case "PENDING":
            return Color(red: 0.95, green: 0.53, blue: 0.18)
        case "ACCEPTED":
            return Color(red: 0.10, green: 0.62, blue: 0.30)
        case "REJECTED", "CANCELED":
            return Color(red: 0.62, green: 0.63, blue: 0.66)
        default:
            return Color(red: 0.62, green: 0.63, blue: 0.66)
        }
    }

    private func dateText(_ raw: String?) -> String {
        let trimmed = raw?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !trimmed.isEmpty else {
            return ""
        }
        if trimmed.count >= 16 {
            let index = trimmed.index(trimmed.startIndex, offsetBy: 16)
            return String(trimmed[..<index])
        }
        return trimmed
    }

    private func maskMobile(_ mobile: String) -> String? {
        let digits = mobile.filter(\.isNumber)
        guard !digits.isEmpty else {
            return nil
        }
        if digits.count >= 11 {
            let prefix = String(digits.prefix(3))
            let suffix = String(digits.suffix(4))
            return "\(prefix)****\(suffix)"
        }
        if digits.count >= 7 {
            let prefix = String(digits.prefix(3))
            let suffix = String(digits.suffix(2))
            return "\(prefix)***\(suffix)"
        }
        return digits
    }

    private func avatarColor(seed: Int64) -> Color {
        let palettes: [Color] = [
            Color(red: 0.96, green: 0.56, blue: 0.50),
            AppTheme.palette.brandPrimaryLight,
            Color(red: 0.53, green: 0.78, blue: 0.63),
            Color(red: 0.95, green: 0.74, blue: 0.43),
            AppTheme.palette.brandPrimaryLight,
            Color(red: 0.94, green: 0.58, blue: 0.77)
        ]
        let index = Int(abs(seed) % Int64(palettes.count))
        return palettes[index]
    }
}

private final class AvatarImageCacheStore {
    static let shared = AvatarImageCacheStore()

    private let memoryCache = NSCache<NSString, UIImage>()
    private let ioQueue = DispatchQueue(label: "cn.openaipay.avatar.cache", qos: .utility)
    private let fileManager = FileManager.default
    private let authStore = AuthStore()
    private let folderURL: URL

    private init() {
        memoryCache.countLimit = 400
        memoryCache.totalCostLimit = 64 * 1024 * 1024
        let baseFolder = FileManager.default.urls(for: .cachesDirectory, in: .userDomainMask).first
            ?? URL(fileURLWithPath: NSTemporaryDirectory(), isDirectory: true)
        folderURL = baseFolder.appendingPathComponent("AvatarRemoteCache", isDirectory: true)
        ioQueue.sync {
            try? fileManager.createDirectory(at: folderURL, withIntermediateDirectories: true)
        }
    }

    func image(for url: URL) async -> UIImage? {
        guard let normalizedURL = normalizedURL(from: url) else {
            return nil
        }
        if let cached = cachedImage(for: normalizedURL) {
            return cached
        }
        var request = URLRequest(url: normalizedURL)
        request.cachePolicy = .returnCacheDataElseLoad
        request.timeoutInterval = 10
        if shouldAttachAuthorization(to: normalizedURL),
           let authorizationHeader = currentAuthorizationHeader() {
            request.setValue(authorizationHeader, forHTTPHeaderField: "Authorization")
        }
        do {
            let (data, response) = try await URLSession.shared.data(for: request)
            if let http = response as? HTTPURLResponse, !(200..<300).contains(http.statusCode) {
                return nil
            }
            guard let image = UIImage(data: data) else {
                return nil
            }
            store(image: image, rawData: data, for: normalizedURL)
            return image
        } catch {
            return nil
        }
    }

    func cachedImage(for url: URL) -> UIImage? {
        guard let normalizedURL = normalizedURL(from: url) else {
            return nil
        }
        let cacheKey = cacheKeyForURL(normalizedURL)
        if let cached = memoryCache.object(forKey: cacheKey as NSString) {
            return cached
        }
        let fileURL = cachedFileURL(for: cacheKey)
        var loadedImage: UIImage?
        ioQueue.sync {
            guard fileManager.fileExists(atPath: fileURL.path) else {
                return
            }
            loadedImage = UIImage(contentsOfFile: fileURL.path)
        }
        if let loadedImage {
            memoryCache.setObject(loadedImage, forKey: cacheKey as NSString, cost: imageMemoryCost(loadedImage))
        }
        return loadedImage
    }

    func store(image: UIImage, forURLString rawURL: String?) {
        guard let url = normalizedURL(from: rawURL) else {
            return
        }
        store(image: image, rawData: nil, for: url)
    }

    func replaceAvatar(oldURLString: String?, newURLString: String?, newImage: UIImage?) {
        let oldURL = normalizedURL(from: oldURLString)
        let newURL = normalizedURL(from: newURLString)
        if let oldURL, oldURL != newURL {
            invalidate(url: oldURL)
        }
        if let newImage {
            store(image: newImage, forURLString: newURLString)
        }
    }

    private func store(image: UIImage, rawData: Data?, for url: URL) {
        let cacheKey = cacheKeyForURL(url)
        memoryCache.setObject(image, forKey: cacheKey as NSString, cost: imageMemoryCost(image))
        let fileURL = cachedFileURL(for: cacheKey)
        let writeData = rawData ?? image.jpegData(compressionQuality: 0.9)
        guard let writeData, !writeData.isEmpty else {
            return
        }
        ioQueue.async {
            do {
                try self.fileManager.createDirectory(at: self.folderURL, withIntermediateDirectories: true)
                try writeData.write(to: fileURL, options: .atomic)
            } catch {
                return
            }
        }
    }

    private func invalidate(url: URL) {
        let cacheKey = cacheKeyForURL(url)
        memoryCache.removeObject(forKey: cacheKey as NSString)
        let fileURL = cachedFileURL(for: cacheKey)
        ioQueue.async {
            try? self.fileManager.removeItem(at: fileURL)
        }
    }

    private func normalizedURL(from rawURL: String?) -> URL? {
        let trimmed = rawURL?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !trimmed.isEmpty else {
            return nil
        }
        let absoluteText: String
        if trimmed.hasPrefix("http://") || trimmed.hasPrefix("https://") {
            absoluteText = trimmed
        } else if trimmed.hasPrefix("/bff/") {
            absoluteText = "\(AppRuntime.bffBaseURL)\(trimmed)"
        } else if trimmed.hasPrefix("/") {
            absoluteText = "\(AppRuntime.backendBaseURL)\(trimmed)"
        } else {
            absoluteText = trimmed
        }
        guard let url = URL(string: absoluteText) else {
            return nil
        }
        let scheme = url.scheme?.lowercased() ?? ""
        guard scheme == "http" || scheme == "https" else {
            return nil
        }
        return url
    }

    private func normalizedURL(from url: URL) -> URL? {
        let scheme = url.scheme?.lowercased() ?? ""
        if scheme == "http" || scheme == "https" {
            return url
        }
        return normalizedURL(from: url.absoluteString)
    }

    private func cachedFileURL(for cacheKey: String) -> URL {
        folderURL.appendingPathComponent("\(cacheKey).jpg")
    }

    private func cacheKeyForURL(_ url: URL) -> String {
        var components = URLComponents(url: url, resolvingAgainstBaseURL: false)
        components?.fragment = nil
        let normalized = components?.string ?? url.absoluteString
        let digest = SHA256.hash(data: Data(normalized.utf8))
        return digest.map { String(format: "%02x", $0) }.joined()
    }

    private func imageMemoryCost(_ image: UIImage) -> Int {
        let width = image.size.width * image.scale
        let height = image.size.height * image.scale
        return max(1, Int(width * height * 4))
    }

    private func shouldAttachAuthorization(to url: URL) -> Bool {
        let normalizedPath = url.path.lowercased()
        return normalizedPath.hasPrefix("/bff/") || normalizedPath.hasPrefix("/api/")
    }

    private func currentAuthorizationHeader() -> String? {
        guard let session = authStore.loadSession(expectedBffBaseURL: AppRuntime.bffBaseURL) else {
            return nil
        }
        let accessToken = session.accessToken.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !accessToken.isEmpty else {
            return nil
        }
        let tokenType = session.tokenType.trimmingCharacters(in: .whitespacesAndNewlines)
        if tokenType.isEmpty {
            return "Bearer \(accessToken)"
        }
        return "\(tokenType) \(accessToken)"
    }
}

private struct AvatarRemoteImage<Content: View, Placeholder: View>: View {
    let url: URL
    let content: (Image) -> Content
    let placeholder: () -> Placeholder

    @State private var loadedImage: UIImage?

    var body: some View {
        Group {
            if let loadedImage {
                content(Image(uiImage: loadedImage))
            } else {
                placeholder()
            }
        }
        .task(id: url.absoluteString) {
            if let cached = AvatarImageCacheStore.shared.cachedImage(for: url) {
                loadedImage = cached
                return
            }
            let downloaded = await AvatarImageCacheStore.shared.image(for: url)
            guard !Task.isCancelled else {
                return
            }
            loadedImage = downloaded
        }
    }
}

private struct ContactAvatarView: View {
    let avatarUrl: String?
    let avatarAssetName: String?
    let avatarText: String
    let avatarColor: Color
    let size: CGFloat

    var body: some View {
        if let finalAssetName = resolvedAvatarAssetName,
           UIImage(named: finalAssetName) != nil {
            Image(finalAssetName)
                .resizable()
                .aspectRatio(contentMode: .fill)
                .frame(width: size, height: size)
                .clipShape(Circle())
        } else if let raw = avatarUrl?.trimmingCharacters(in: .whitespacesAndNewlines),
                  !raw.isEmpty,
                  let url = URL(string: raw) {
            AvatarRemoteImage(url: url) { image in
                image
                    .resizable()
                    .aspectRatio(contentMode: .fill)
                    .frame(width: size, height: size)
                    .clipShape(Circle())
            } placeholder: {
                avatarFallback
            }
        } else {
            avatarFallback
        }
    }

    private var normalizedAvatarAssetName: String? {
        let raw = avatarAssetName?.trimmingCharacters(in: .whitespacesAndNewlines)
        if let raw, !raw.isEmpty {
            return raw
        }
        return nil
    }

    private var resolvedAvatarAssetName: String? {
        normalizedAvatarAssetName ?? demoAvatarAssetName(for: avatarUrl)
    }

    private var avatarFallback: some View {
        Circle()
            .fill(avatarColor)
            .frame(width: size, height: size)
            .overlay(
                Text(avatarText)
                    .font(.system(size: max(12, size * 0.38), weight: .bold))
                    .foregroundStyle(.white)
            )
    }
}

