        Rule(assetName: "BankLogoBCM", displayName: "交通银行", codes: ["BCM", "COMM", "BOCOM", "COMMCNSH"], names: ["交通银行", "交通", "交行"]),
        Rule(assetName: "BankLogoPSBC", displayName: "中国邮政储蓄银行", codes: ["PSBC", "POST", "PSBCHINA", "PSBCCNBJ"], names: ["中国邮政储蓄银行", "邮政储蓄银行", "邮政储蓄", "邮储银行", "邮储"]),
        Rule(assetName: "BankLogoSPDB", displayName: "上海浦东发展银行", codes: ["SPDB", "SPDBCNSH"], names: ["上海浦东发展银行", "浦发银行", "浦发"]),
        Rule(assetName: "BankLogoCIB", displayName: "兴业银行", codes: ["CIB", "FJIBCNBA"], names: ["兴业银行", "兴业"]),
        Rule(assetName: "BankLogoCMBC", displayName: "中国民生银行", codes: ["CMBC", "CMBCBANK"], names: ["中国民生银行", "民生银行", "民生"]),
        Rule(assetName: "BankLogoCITIC", displayName: "中信银行", codes: ["CITIC", "ECITIC", "CITICBANK"], names: ["中信银行", "中信"]),
        Rule(assetName: "BankLogoCEB", displayName: "中国光大银行", codes: ["CEB", "EVERBRIGHT", "CEBBANK"], names: ["中国光大银行", "光大银行", "光大"]),
        Rule(assetName: "BankLogoPAB", displayName: "平安银行", codes: ["PAB", "PINGAN", "SPABANK", "PAYH"], names: ["平安银行", "平安"]),
        Rule(assetName: "BankLogoCGB", displayName: "广发银行", codes: ["CGB", "GDB", "CGBCHINA"], names: ["广发银行", "广发"]),
        Rule(assetName: "BankLogoHXB", displayName: "华夏银行", codes: ["HXB", "HXBANK"], names: ["华夏银行", "华夏"]),
        Rule(assetName: "BankLogoBOB", displayName: "北京银行", codes: ["BOB", "BJBANK"], names: ["北京银行"]),
        Rule(assetName: "BankLogoBOS", displayName: "上海银行", codes: ["BOS", "SHBANK"], names: ["上海银行"]),
        Rule(assetName: "BankLogoNBCB", displayName: "宁波银行", codes: ["NBCB", "NBBANK"], names: ["宁波银行"]),
        Rule(assetName: "BankLogoHZB", displayName: "杭州银行", codes: ["HZB", "HZBANK"], names: ["杭州银行"]),
        Rule(assetName: "BankLogoJSB", displayName: "江苏银行", codes: ["JSB", "JSBANK"], names: ["江苏银行"]),
        Rule(assetName: "BankLogoNJCB", displayName: "南京银行", codes: ["NJCB", "NJBANK"], names: ["南京银行"]),
        Rule(assetName: "BankLogoCBHB", displayName: "渤海银行", codes: ["CBHB", "BOHAI"], names: ["渤海银行"]),
        Rule(assetName: "BankLogoCZB", displayName: "浙商银行", codes: ["CZB", "CZBANK"], names: ["浙商银行"]),
        Rule(assetName: "BankLogoHSB", displayName: "徽商银行", codes: ["HSB", "HUISHANG"], names: ["徽商银行"]),
        Rule(assetName: "BankLogoJXB", displayName: "江西银行", codes: ["JXB", "JXBANK"], names: ["江西银行"])
    ]

    static func assetName(bankCode: String?, bankName: String?) -> String? {
        let normalizedCode = bankCode?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() ?? ""
        let normalizedName = bankName?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""

        for rule in rules {
            let codeMatched = rule.codes.contains { candidate in
                !candidate.isEmpty && normalizedCode.contains(candidate)
            }
            let nameMatched = rule.names.contains { candidate in
                !candidate.isEmpty && normalizedName.contains(candidate)
            }
            if codeMatched || nameMatched {
                return rule.assetName
            }
        }
        return nil
    }

    static func fullDisplayName(bankCode: String?, bankName: String?) -> String {
        let normalizedCode = bankCode?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() ?? ""
        let normalizedName = bankName?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""

        for rule in rules {
            let codeMatched = rule.codes.contains { candidate in
                !candidate.isEmpty && normalizedCode.contains(candidate)
            }
            if codeMatched {
                if normalizedName.isEmpty {
                    return rule.displayName
                }
                if normalizedName.contains(rule.displayName) {
                    return normalizedName
                }
                for alias in rule.names.sorted(by: { $0.count > $1.count }) {
                    if alias == rule.displayName {
                        continue
                    }
                    if normalizedName.contains(alias) {
                        return normalizedName.replacingOccurrences(of: alias, with: rule.displayName)
                    }
                }
                return rule.displayName
            }
        }

        for rule in rules {
            if normalizedName.contains(rule.displayName) {
                return normalizedName
            }
            for alias in rule.names.sorted(by: { $0.count > $1.count }) {
                if alias == rule.displayName {
                    continue
                }
                if normalizedName.contains(alias) {
                    return normalizedName.replacingOccurrences(of: alias, with: rule.displayName)
                }
            }
        }

        return normalizedName.isEmpty ? "银行卡" : normalizedName
    }
}

