private enum MainlandBankCardType: String, CaseIterable, Identifiable {
    case debit = "DEBIT"
    case credit = "CREDIT"

    var id: String { rawValue }

    var title: String {
        switch self {
        case .debit:
            return "借记卡"
        case .credit:
            return "信用卡"
        }
    }

    var displayName: String {
        switch self {
        case .debit:
            return "储蓄卡"
        case .credit:
            return "信用卡"
        }
    }

    var helperText: String {
        switch self {
        case .debit:
            return "支持中国大陆银行发行的借记卡"
        case .credit:
            return "支持中国大陆银行发行的信用卡"
        }
    }
}

