private struct BankCardAddSubmission {
    let bank: MainlandBankOption
    let cardType: MainlandBankCardType
    let cardNumber: String
    let phoneNumber: String

    var cardTailNo: String {
        String(cardNumber.suffix(4))
    }

    var phoneTailNo: String? {
        let digits = phoneNumber.filter(\.isNumber)
        guard digits.count >= 4 else {
            return nil
        }
        return String(digits.suffix(4))
    }
}

private enum BankCardSyntheticStore {
    private struct PersistedCard: Codable {
        let toolCode: String
        let bankCode: String
        let bankName: String
        let cardType: String
        let holderName: String?
        let cardNumber: String?
        let cardTailNo: String
        let phoneTailNo: String?
        let createdAt: TimeInterval
    }

    private struct PersistedState: Codable {
        var cards: [PersistedCard]
        var hiddenToolCodes: [String]?
    }

    private static func key(for userId: Int64?) -> String? {
        guard let userId, userId > 0 else {
            return nil
        }
        return "cn.openaipay.synthetic.bank.cards.\(userId)"
    }

    static func loadPayTools(userId: Int64?) -> [CashierPayToolData] {
        guard let key = key(for: userId),
              let state = loadState(forKey: key) else {
            return []
        }

        return state.cards
            .sorted { $0.createdAt > $1.createdAt }
            .map(payTool(from:))
    }

    static func hiddenToolCodes(userId: Int64?) -> Set<String> {
        guard let key = key(for: userId),
              let state = loadState(forKey: key) else {
            return []
        }
        return Set(state.hiddenToolCodes ?? [])
    }

    @discardableResult
    static func save(_ submission: BankCardAddSubmission, userId: Int64?) -> CashierPayToolData? {
        guard let key = key(for: userId) else {
            return nil
        }

        var state = loadState(forKey: key) ?? PersistedState(cards: [], hiddenToolCodes: [])
        let phoneTailNo = submission.phoneTailNo
        let existingIndex = state.cards.firstIndex {
            $0.bankCode == submission.bank.code
                && $0.cardType == submission.cardType.rawValue
                && $0.cardTailNo == submission.cardTailNo
        }
        let toolCode = existingIndex.flatMap { state.cards[$0].toolCode }
            ?? generatedToolCode(userId: userId, bankCode: submission.bank.code, cardTailNo: submission.cardTailNo)
        let persistedCard = PersistedCard(
            toolCode: toolCode,
            bankCode: submission.bank.code,
            bankName: submission.bank.name,
            cardType: submission.cardType.rawValue,
            holderName: nil,
            cardNumber: submission.cardNumber,
            cardTailNo: submission.cardTailNo,
            phoneTailNo: phoneTailNo,
            createdAt: Date().timeIntervalSince1970
        )

        if let existingIndex {
            state.cards.remove(at: existingIndex)
        }
        state.cards.insert(persistedCard, at: 0)
        state.cards.sort { $0.createdAt > $1.createdAt }
        saveState(state, forKey: key)
        return payTool(from: persistedCard)
    }

    @discardableResult
    static func delete(tool: CashierPayToolData, userId: Int64?) -> Bool {
        guard let key = key(for: userId) else {
            return false
        }

        var state = loadState(forKey: key) ?? PersistedState(cards: [], hiddenToolCodes: [])
        let originalCount = state.cards.count
        state.cards.removeAll { $0.toolCode == tool.toolCode }

        if state.cards.count != originalCount {
            state.hiddenToolCodes = (state.hiddenToolCodes ?? []).filter { $0 != tool.toolCode }
            saveState(state, forKey: key)
            return true
        }

        let normalizedToolCode = tool.toolCode.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedToolCode.isEmpty else {
            return false
        }

        var hiddenToolCodes = Set(state.hiddenToolCodes ?? [])
        let inserted = hiddenToolCodes.insert(normalizedToolCode).inserted
        state.hiddenToolCodes = Array(hiddenToolCodes).sorted()
        saveState(state, forKey: key)
        return inserted
    }

    static func resolvedCardNumber(for tool: CashierPayToolData, userId: Int64?) -> String {
        if let key = key(for: userId),
           let state = loadState(forKey: key),
           let persistedCard = state.cards.first(where: { $0.toolCode == tool.toolCode }),
           let persistedNumber = normalizedDigits(from: persistedCard.cardNumber),
           persistedNumber.count >= 12 {
            return persistedNumber
        }
        return generatedDemoCardNumber(for: tool)
    }

    static func matchesCardBin(cardNumber: String, bankCode: String, cardType: String) -> Bool {
        let digits = normalizedDigits(from: cardNumber) ?? ""
        guard digits.count >= 6 else {
            return false
        }
        let prefixes = bankCardPrefixes(
            bankCode: bankCode,
            isCredit: cardType == MainlandBankCardType.credit.rawValue
        )
        guard !prefixes.isEmpty else {
            return true
        }
        return prefixes.contains { prefix in
            digits.hasPrefix(prefix)
        }
    }

    static func isValidCardNumber(_ cardNumber: String) -> Bool {
        let digits = normalizedDigits(from: cardNumber) ?? ""
        guard digits.count >= 12, digits.count <= 19 else {
            return false
        }

        let reversedDigits = digits.compactMap(\.wholeNumberValue).reversed()
        var sum = 0
        for (index, digit) in reversedDigits.enumerated() {
            if !index.isMultiple(of: 2) {
                let doubled = digit * 2
                sum += doubled > 9 ? doubled - 9 : doubled
            } else {
                sum += digit
            }
        }
        return sum % 10 == 0
    }

    private static func payTool(from card: PersistedCard) -> CashierPayToolData {
        let displayBankName = BankLogoCatalog.fullDisplayName(bankCode: card.bankCode, bankName: card.bankName)
        let normalizedHolderName = card.holderName?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        return CashierPayToolData(
            toolType: "BANK_CARD",
            toolCode: card.toolCode,
            toolName: "\(displayBankName)\(cardTypeDisplayName(card.cardType))(尾号\(card.cardTailNo))",
            toolDescription: normalizedHolderName.isEmpty ? "已添加到本机银行卡列表" : "持卡人\(normalizedHolderName)",
            defaultSelected: false,
            bankCode: card.bankCode,
            cardType: card.cardType,
            phoneTailNo: card.phoneTailNo
        )
    }

    private static func cardTypeDisplayName(_ rawType: String) -> String {
        rawType == MainlandBankCardType.credit.rawValue ? "信用卡" : "储蓄卡"
    }

    private static func generatedToolCode(userId: Int64?, bankCode: String, cardTailNo: String) -> String {
        let seed = Int(Date().timeIntervalSince1970)
        let safeUserId = userId ?? 0
        return "LOCAL_BANK_CARD_\(safeUserId)_\(bankCode)_\(cardTailNo)_\(seed)"
    }

    private static func generatedDemoCardNumber(for tool: CashierPayToolData) -> String {
        let isCredit = CashierPresentationHelper.normalizedCardType(for: tool) == "CREDIT"
        let totalLength = isCredit ? 16 : 19
        let prefix = bankCardPrefix(bankCode: tool.bankCode, isCredit: isCredit)
        let tailDigits = extractedTailDigits(for: tool)
        let bodyLength = max(0, totalLength - prefix.count - tailDigits.count - 1)
        let bodyDigits = repeatedDigits(seed: "\(tool.toolCode)|\(tool.toolName)|\(tool.bankCode ?? "")", count: bodyLength)
        let partial = prefix + bodyDigits + tailDigits
        let checkDigit = luhnCheckDigit(for: partial)
        return partial + String(checkDigit)
    }

    private static func bankCardPrefix(bankCode: String?, isCredit: Bool) -> String {
        bankCardPrefixes(bankCode: bankCode, isCredit: isCredit).first ?? "622202"
    }

    private static func bankCardPrefixes(bankCode: String?, isCredit: Bool) -> [String] {
        let normalized = bankCode?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() ?? ""
        let debitPrefixes: [String: [String]] = [
            "ICBC": ["622200", "621226"],
            "ABC": ["622848", "622845"],
            "CCB": ["621700", "436742"],
            "BOC": ["621661", "621660"],
            "CMB": ["621483", "622588"],
            "BCM": ["622260", "622262"],
            "PSBC": ["621098", "622150"],
            "SPDB": ["622521", "621792"],
            "CIB": ["622909", "622901"],
            "CMBC": ["622622", "622600"],
            "CITIC": ["622690", "622691"],
            "CEB": ["622666", "622662"],
            "PAB": ["622155", "621626"],
            "CGB": ["622568", "622581"],
            "HXB": ["622630", "622631"],
            "BOB": ["602969", "622163"],
            "BOS": ["622892", "601229"],
            "NBCB": ["622319", "622316"],
            "HZB": ["622878", "622873"],
            "JSB": ["622283", "622280"],
            "NJCB": ["622303", "621259"],
            "CBHB": ["622498", "622499"],
            "CZB": ["622188", "621777"],
            "HSB": ["622299", "621021"],
            "JXB": ["622428", "622429"]
        ]
        let creditPrefixes: [String: [String]] = [
            "ICBC": ["524047", "458441", "622206", "622230", "622231", "622232", "622233", "622234", "622235", "622236"],
            "ABC": ["622836", "520082"],
            "CCB": ["436728", "545324"],
            "BOC": ["409666", "438088"],
            "CMB": ["518710", "439188"],
            "BCM": ["458123", "521899"],
            "SPDB": ["456418", "515672"],
            "CIB": ["451289", "486493"],
            "CMBC": ["421869", "356859"],
            "CITIC": ["433670", "403391"],
            "CEB": ["303697", "356837"],
            "PAB": ["356869", "625362"],
            "CGB": ["406365", "433684"],
            "HXB": ["539867", "438125"],
            "CZB": ["622186", "622187"]
        ]
        if isCredit {
            return creditPrefixes[normalized] ?? []
        }
        return debitPrefixes[normalized] ?? []
    }

    private static func extractedTailDigits(for tool: CashierPayToolData) -> String {
        let source = "\(tool.toolName)|\(tool.toolCode)"
        let digits = normalizedDigits(from: source) ?? ""
        if digits.count >= 4 {
            return String(digits.suffix(4))
        }
        return repeatedDigits(seed: source, count: 4)
    }

    private static func normalizedDigits(from text: String?) -> String? {
        let digits = text?.filter(\.isNumber) ?? ""
        return digits.isEmpty ? nil : digits
    }

    private static func repeatedDigits(seed: String, count: Int) -> String {
        guard count > 0 else {
            return ""
        }
        let scalars = Array(seed.unicodeScalars)
        guard !scalars.isEmpty else {
            return String(repeating: "0", count: count)
        }

        var digits = ""
        var index = 0
        while digits.count < count {
            let scalar = scalars[index % scalars.count]
            let digit = Int(scalar.value % 10)
            digits.append(String(digit))
            index += 1
        }
        return digits
    }

    private static func luhnCheckDigit(for partial: String) -> Int {
        let digits = partial.compactMap(\.wholeNumberValue).reversed()
        var sum = 0
        for (index, digit) in digits.enumerated() {
            if index.isMultiple(of: 2) {
                let doubled = digit * 2
                sum += doubled > 9 ? doubled - 9 : doubled
            } else {
                sum += digit
            }
        }
        return (10 - (sum % 10)) % 10
    }

    private static func loadState(forKey key: String) -> PersistedState? {
        guard let data = UserDefaults.standard.data(forKey: key),
              let state = try? JSONDecoder().decode(PersistedState.self, from: data) else {
            return nil
        }
        return state
    }

    private static func saveState(_ state: PersistedState, forKey key: String) {
        guard let data = try? JSONEncoder().encode(state) else {
            return
        }
        UserDefaults.standard.set(data, forKey: key)
    }
}

