                                    .font(yaHeiRegularFont(size: 12.3 * fontScale))
                                    .foregroundStyle(Color(red: 0.48, green: 0.52, blue: 0.60))
                                    .padding(.horizontal, 4 * fontScale)
                            }
                            .padding(.horizontal, 16 * fontScale)
                            .padding(.top, 18 * fontScale)
                            .padding(.bottom, focusedField == nil ? max(28, safeBottomInset + 14) : max(320 * fontScale, safeBottomInset + 220 * fontScale))
                        }
                        .scrollDismissesKeyboard(.interactively)
                        .onChange(of: focusedField) { _, newValue in
                            guard let newValue else {
                                return
                            }
                            DispatchQueue.main.asyncAfter(deadline: .now() + 0.12) {
                                withAnimation(.easeInOut(duration: 0.22)) {
                                    scrollProxy.scrollTo(newValue, anchor: .center)
                                }
                            }
                        }
                    }
                }
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .ignoresSafeArea(.keyboard, edges: .bottom)
        .toolbar {
            ToolbarItemGroup(placement: .keyboard) {
                Spacer()
                Button("完成") {
                    focusedField = nil
                }
            }
        }
        .alert("添加成功", isPresented: $showSuccessAlert) {
            Button("完成") {
                onBack()
            }
        } message: {
            Text("银行卡已添加到列表")
        }
    }

    private var sanitizedCardNumber: String {
        cardNumber.filter(\.isNumber)
    }

    private var sanitizedPhoneNumber: String {
        phoneNumber.filter(\.isNumber)
    }

    private var canSubmit: Bool {
        validationMessage == nil
    }

    private var visibleValidationMessage: String? {
        if let submitMessage, !submitMessage.isEmpty {
            return submitMessage
        }
        let hasEdited = selectedBank != nil || !cardNumber.isEmpty || !phoneNumber.isEmpty
        if hasEdited {
            return validationMessage
        }
        return nil
    }

    private var validationMessage: String? {
        guard let selectedBank else {
            return "请选择发卡银行"
        }
        if sanitizedCardNumber.count < 12 || sanitizedCardNumber.count > 19 {
            return "请输入正确的银行卡号"
        }
        if !BankCardSyntheticStore.isValidCardNumber(sanitizedCardNumber) {
            return "银行卡号格式不正确"
        }
        if !BankCardSyntheticStore.matchesCardBin(
            cardNumber: sanitizedCardNumber,
            bankCode: selectedBank.code,
            cardType: cardType.rawValue
        ) {
            return "银行卡号与所选银行不匹配"
        }
        if sanitizedPhoneNumber.count != 11 || !sanitizedPhoneNumber.hasPrefix("1") {
            return "手机号格式不正确"
        }
        return nil
    }

    private func addCardHeader(topInset: CGFloat, fontScale: CGFloat) -> some View {
        ZStack {
            Text("添加银行卡")
                .font(.system(size: 19 * fontScale, weight: .semibold))
                .foregroundStyle(Color(red: 0.16, green: 0.18, blue: 0.22))

            HStack {
                Button(action: onBack) {
                    Image(systemName: "chevron.left")
                        .font(.system(size: 18 * fontScale, weight: .semibold))
                        .foregroundStyle(Color(red: 0.22, green: 0.24, blue: 0.28))
                        .frame(width: 34 * fontScale, height: 34 * fontScale)
                }
                .buttonStyle(.plain)

                Spacer()

                Color.clear
                    .frame(width: 34 * fontScale, height: 34 * fontScale)
            }
        }
        .padding(.horizontal, 16 * fontScale)
        .padding(.top, topInset + 6 * fontScale)
        .padding(.bottom, 14 * fontScale)
        .background(Color.white.opacity(0.96))
    }

    private func addCardPreview(fontScale: CGFloat) -> some View {
        let palette = cardType == .credit
            ? [Color(red: 191 / 255, green: 111 / 255, blue: 134 / 255), Color(red: 219 / 255, green: 161 / 255, blue: 175 / 255), Color(red: 141 / 255, green: 89 / 255, blue: 117 / 255)]
            : [Color(red: 74 / 255, green: 148 / 255, blue: 226 / 255), Color(red: 111 / 255, green: 170 / 255, blue: 226 / 255), Color(red: 61 / 255, green: 103 / 255, blue: 166 / 255)]
        let previewBank = selectedBank?.name ?? "请选择银行"
        let previewTail = sanitizedCardNumber.count >= 4 ? String(sanitizedCardNumber.suffix(4)) : "****"

        return ZStack(alignment: .topLeading) {
            RoundedRectangle(cornerRadius: 24 * fontScale, style: .continuous)
                .fill(
                    LinearGradient(colors: palette, startPoint: .topLeading, endPoint: .bottomTrailing)
                )
                .overlay(
                    RoundedRectangle(cornerRadius: 24 * fontScale, style: .continuous)
                        .stroke(Color.white.opacity(0.2), lineWidth: 1)
                )

            Circle()
                .fill(Color.white.opacity(0.12))
                .frame(width: 132 * fontScale, height: 132 * fontScale)
                .offset(x: 220 * fontScale, y: -14 * fontScale)

            VStack(alignment: .leading, spacing: 12 * fontScale) {
                Text(previewBank)
                    .font(.system(size: 21 * fontScale, weight: .semibold))
                    .foregroundStyle(.white)
                    .lineLimit(1)
                    .minimumScaleFactor(0.72)

                Text(cardType.displayName)
                    .font(yaHeiRegularFont(size: 13.2 * fontScale))
                    .foregroundStyle(Color.white.opacity(0.82))

                Spacer(minLength: 0)

                Text("尾号 \(previewTail)")
                    .font(.system(size: 28 * fontScale, weight: .bold, design: .rounded))
                    .foregroundStyle(Color.white.opacity(0.98))

                Text(cardType.helperText)
                    .font(yaHeiRegularFont(size: 12.2 * fontScale))
                    .foregroundStyle(Color.white.opacity(0.76))
            }
            .padding(20 * fontScale)
        }
        .frame(height: 176 * fontScale)
    }

    private func addCardForm(fontScale: CGFloat) -> some View {
        VStack(alignment: .leading, spacing: 16 * fontScale) {
            formCard(fontScale: fontScale) {
                VStack(alignment: .leading, spacing: 14 * fontScale) {
                    fieldTitle("银行卡类型", fontScale: fontScale)

                    Picker("银行卡类型", selection: $cardType) {
                        ForEach(MainlandBankCardType.allCases) { type in
                            Text(type.title).tag(type)
                        }
                    }
                    .pickerStyle(.segmented)
                }
            }

            formCard(fontScale: fontScale) {
                VStack(alignment: .leading, spacing: 14 * fontScale) {
                    fieldTitle("发卡银行", fontScale: fontScale)

                    Menu {
                        ForEach(MainlandBankOption.supported) { bank in
                            Button {
                                selectedBank = bank
                                submitMessage = nil
                            } label: {
                                if selectedBank == bank {
                                    Label(bank.name, systemImage: "checkmark")
                                } else {
                                    Text(bank.name)
                                }
                            }
                        }
                    } label: {
                        HStack(spacing: 10 * fontScale) {
                            BankLogoIconView(
                                bankCode: selectedBank?.code,
                                bankName: selectedBank?.name,
                                size: 32 * fontScale,
                                cornerRadius: 8 * fontScale,
                                backgroundColor: .white
                            )

                            Text(selectedBank?.name ?? "请选择银行")
                                .font(.system(size: 15 * fontScale, weight: .medium))
                                .foregroundStyle(selectedBank == nil ? Color(red: 0.60, green: 0.63, blue: 0.68) : Color(red: 0.18, green: 0.20, blue: 0.24))

                            Spacer(minLength: 8 * fontScale)

                            Image(systemName: "chevron.down")
                                .font(.system(size: 12 * fontScale, weight: .semibold))
                                .foregroundStyle(Color(red: 0.58, green: 0.61, blue: 0.66))
                        }
                        .padding(.horizontal, 14 * fontScale)
                        .frame(height: 48 * fontScale)
                        .background(
                            RoundedRectangle(cornerRadius: 14 * fontScale, style: .continuous)
                                .fill(Color(red: 0.97, green: 0.98, blue: 1.0))
                        )
                    }
                    .buttonStyle(.plain)
                }
            }

            formCard(fontScale: fontScale) {
                VStack(alignment: .leading, spacing: 14 * fontScale) {
                    fieldTitle("银行卡号", fontScale: fontScale)
                    addCardTextField(
                        placeholder: "请输入银行卡号",
                        text: Binding(
                            get: { cardNumber },
                            set: { value in
                                cardNumber = String(value.filter(\.isNumber).prefix(19))
                                submitMessage = nil
                            }
                        ),
                        fontScale: fontScale,
                        keyboardType: .numberPad
                    )
                    .id(Field.cardNumber)
                    .focused($focusedField, equals: .cardNumber)

                    fieldTitle("预留手机号", fontScale: fontScale)
                    addCardTextField(
                        placeholder: "请输入银行预留手机号",
                        text: Binding(
                            get: { phoneNumber },
                            set: { value in
                                phoneNumber = String(value.filter(\.isNumber).prefix(11))
                                submitMessage = nil
                            }
                        ),
                        fontScale: fontScale,
                        keyboardType: .numberPad
                    )
                    .id(Field.phoneNumber)
                    .focused($focusedField, equals: .phoneNumber)
                }
            }
        }
    }

    private func fieldTitle(_ title: String, fontScale: CGFloat) -> some View {
        Text(title)
            .font(yaHeiRegularFont(size: 13 * fontScale))
            .foregroundStyle(Color(red: 0.36, green: 0.39, blue: 0.45))
    }

    private func formCard<Content: View>(fontScale: CGFloat, @ViewBuilder content: () -> Content) -> some View {
        VStack(alignment: .leading, spacing: 0, content: content)
            .padding(16 * fontScale)
            .background(
                RoundedRectangle(cornerRadius: 20 * fontScale, style: .continuous)
                    .fill(Color.white)
            )
            .overlay(
                RoundedRectangle(cornerRadius: 20 * fontScale, style: .continuous)
                    .stroke(Color.black.opacity(0.04), lineWidth: 1)
            )
    }

    private func addCardTextField(
        placeholder: String,
        text: Binding<String>,
        fontScale: CGFloat,
        keyboardType: UIKeyboardType
    ) -> some View {
        TextField(placeholder, text: text)
            .font(.system(size: 16 * fontScale, weight: .medium))
            .foregroundStyle(Color(red: 0.17, green: 0.19, blue: 0.23))
            .keyboardType(keyboardType)
            .padding(.horizontal, 14 * fontScale)
            .frame(height: 48 * fontScale)
            .background(
                RoundedRectangle(cornerRadius: 14 * fontScale, style: .continuous)
                    .fill(Color(red: 0.97, green: 0.98, blue: 1.0))
            )
    }

    private func submit() {
        focusedField = nil
        if let validationMessage {
            submitMessage = validationMessage
            return
        }
        guard let selectedBank else {
            submitMessage = "请选择发卡银行"
            return
        }

        let submission = BankCardAddSubmission(
            bank: selectedBank,
            cardType: cardType,
            cardNumber: sanitizedCardNumber,
            phoneNumber: sanitizedPhoneNumber
        )
        submitMessage = onSubmit(submission)
        if submitMessage == nil {
            showSuccessAlert = true
        }
    }
}

private struct BankCardsPageView: View {
    let tools: [CashierPayToolData]
    let isLoading: Bool
    let errorMessage: String?
    let resolvedCardNumber: (CashierPayToolData) -> String
    let onDeleteCard: (CashierPayToolData) -> String?
    let onEnsureLoaded: @MainActor () async -> Void
    let onBack: () -> Void
    let onAddCard: () -> Void
    let onRefresh: @MainActor () async -> Void

    private struct RecommendedBankService: Identifiable {
        let id: String
        let bankCode: String?
        let bankName: String
    }

    private struct CardPalette {
        let leading: Color
        let center: Color
        let trailing: Color
        let glow: Color
        let actionBar: Color
    }

    private struct CardNumberDialogInfo: Identifiable {
        let id: String
        let bankName: String
        let cardNumber: String
    }

    private struct DeleteCardDialogInfo: Identifiable {
        let id: String
        let tool: CashierPayToolData
    }

    private let baseWidth: CGFloat = 402
    private let baseHeight: CGFloat = 874
    private let recommendedBanks: [RecommendedBankService] = [
        RecommendedBankService(id: "bank_service_ccb", bankCode: "CCB", bankName: "中国建设银行"),
        RecommendedBankService(id: "bank_service_czb", bankCode: "CZB", bankName: "浙商银行"),
        RecommendedBankService(id: "bank_service_icbc", bankCode: "ICBC", bankName: "中国工商银行"),
        RecommendedBankService(id: "bank_service_nbcb", bankCode: "NBCB", bankName: "宁波银行"),
        RecommendedBankService(id: "bank_service_mybank", bankCode: "MYBANK", bankName: "网商银行")
    ]
    @State private var activeCardNumberDialog: CardNumberDialogInfo?
    @State private var activeDeleteCardDialog: DeleteCardDialogInfo?
    @State private var toastMessage: String?

    private var orderedTools: [CashierPayToolData] { tools }
    private var showsLoadingPlaceholder: Bool {
        isLoading || (orderedTools.isEmpty && errorMessage == nil)
    }

    private var debitCount: Int {
        orderedTools.filter { CashierPresentationHelper.normalizedCardType(for: $0) == "DEBIT" }.count
    }

    private var creditCount: Int {
        orderedTools.filter { CashierPresentationHelper.normalizedCardType(for: $0) == "CREDIT" }.count
    }

    private var otherCount: Int {
        orderedTools.count - debitCount - creditCount
    }

    var body: some View {
        GeometryReader { proxy in
            let topInset = proxy.safeAreaInsets.top
            let windowTopInset = UIApplication.shared.activeKeyWindow?.safeAreaInsets.top ?? 0
            let windowBottomInset = UIApplication.shared.activeKeyWindow?.safeAreaInsets.bottom ?? 0
            let safeTopInset = max(topInset, windowTopInset, 44)
            let bottomInset = max(proxy.safeAreaInsets.bottom, windowBottomInset)
            let fontScale = min(proxy.size.width / baseWidth, proxy.size.height / baseHeight)

            ZStack(alignment: .top) {
                pageBackground

                ScrollView(.vertical, showsIndicators: false) {
                    LazyVStack(alignment: .leading, spacing: 16 * fontScale) {
                        Color.clear
                            .frame(height: safeTopInset + 54 * fontScale)

                        summaryCard(fontScale: fontScale)
                        cardListSection(fontScale: fontScale)

                        Color.clear
                            .frame(height: max(28, bottomInset + 8))
                    }
                    .padding(.horizontal, 16 * fontScale)
                }
                .refreshable {
                    await onRefresh()
                }

                headerBar(topInset: safeTopInset, fontScale: fontScale)

                if let toastMessage {
                    toastView(text: toastMessage)
                        .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .bottom)
                        .padding(.bottom, max(28, bottomInset + 18))
                        .transition(.opacity)
                        .zIndex(4)
                }
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .ignoresSafeArea()
        .alert(
            "银行卡号",
            isPresented: Binding(
                get: { activeCardNumberDialog != nil },
                set: { presented in
                    if !presented {
                        activeCardNumberDialog = nil
                    }
                }
            ),
            presenting: activeCardNumberDialog
        ) { dialog in
            Button("复制") {
                UIPasteboard.general.string = dialog.cardNumber
                activeCardNumberDialog = nil
                showToast("卡号已复制")
            }
            Button("完成", role: .cancel) {
                activeCardNumberDialog = nil
            }
        } message: { dialog in
            Text("\(dialog.bankName)\n\(formattedCardNumber(dialog.cardNumber))")
        }
        .alert(
            "确定要删除该卡？",
            isPresented: Binding(
                get: { activeDeleteCardDialog != nil },
                set: { presented in
                    if !presented {
                        activeDeleteCardDialog = nil
                    }
                }
            ),
            presenting: activeDeleteCardDialog
        ) { dialog in
            Button("确定", role: .destructive) {
                let tool = dialog.tool
                activeDeleteCardDialog = nil
                if let message = onDeleteCard(tool) {
                    showToast(message)
                } else {
                    showToast("已删除该卡")
                }
            }
            Button("取消", role: .cancel) {
                activeDeleteCardDialog = nil
            }
        }
        .task {
            await onEnsureLoaded()
        }
    }

    private var pageBackground: some View {
        ZStack {
            LinearGradient(
                colors: [
                    Color(red: 4 / 255, green: 16 / 255, blue: 74 / 255),
                    Color(red: 6 / 255, green: 14 / 255, blue: 88 / 255),
                    Color(red: 3 / 255, green: 9 / 255, blue: 52 / 255)
                ],
                startPoint: .topLeading,
                endPoint: .bottomTrailing
            )

            RadialGradient(
                colors: [
                    Color(red: 41 / 255, green: 87 / 255, blue: 206 / 255).opacity(0.75),
                    Color.clear
                ],
                center: .topLeading,
                startRadius: 8,
                endRadius: 320
            )

            RadialGradient(
                colors: [
                    Color(red: 82 / 255, green: 55 / 255, blue: 175 / 255).opacity(0.28),
                    Color.clear
                ],
                center: .topTrailing,
                startRadius: 10,
                endRadius: 260
            )

            LinearGradient(
                colors: [
                    Color.clear,
                    Color(red: 9 / 255, green: 20 / 255, blue: 84 / 255).opacity(0.28),
                    Color(red: 3 / 255, green: 9 / 255, blue: 45 / 255).opacity(0.55)
                ],
                startPoint: .top,
                endPoint: .bottom
            )
        }
    }

    private func headerBar(topInset: CGFloat, fontScale: CGFloat) -> some View {
        HStack(spacing: 10 * fontScale) {
            Button(action: onBack) {
                Image(systemName: "chevron.left")
                    .font(.system(size: 18 * fontScale, weight: .semibold))
                    .foregroundStyle(Color.white.opacity(0.98))
                    .frame(width: 34 * fontScale, height: 34 * fontScale)
                    .contentShape(Rectangle())
            }
            .buttonStyle(.plain)
            .accessibilityIdentifier("bank_cards_dynamic_back")

            Text("银行卡")
                .font(.system(size: 19 * fontScale, weight: .semibold))
                .foregroundStyle(Color.white.opacity(0.98))

            Spacer(minLength: 8 * fontScale)

            Button(action: onAddCard) {
                HStack(spacing: 5 * fontScale) {
                    Image(systemName: "plus.circle.fill")
                        .font(.system(size: 13 * fontScale, weight: .semibold))
                    Text("添加卡")
                        .font(.system(size: 13.2 * fontScale, weight: .semibold))
                }
                .foregroundStyle(Color.white.opacity(0.92))
                .padding(.horizontal, 12 * fontScale)
                .frame(height: 30 * fontScale)
                .background(
                    Capsule(style: .continuous)
                        .fill(Color.white.opacity(0.14))
                )
            }
            .buttonStyle(.plain)
            .accessibilityIdentifier("bank_cards_dynamic_add")
        }
        .padding(.horizontal, 16 * fontScale)
        .padding(.top, topInset + 6 * fontScale)
        .padding(.bottom, 10 * fontScale)
    }

    private func recommendedServicesSection(fontScale: CGFloat) -> some View {
        VStack(alignment: .leading, spacing: 11 * fontScale) {
            Text("推荐银行服务")
                .font(yaHeiRegularFont(size: 13 * fontScale))
                .foregroundStyle(Color.white.opacity(0.72))

            HStack(spacing: 18 * fontScale) {
                ForEach(recommendedBanks) { item in
                    VStack(spacing: 8 * fontScale) {
                        BankLogoIconView(
                            bankCode: item.bankCode,
                            bankName: item.bankName,
                            size: 42 * fontScale,
                            cornerRadius: 21 * fontScale,
                            backgroundColor: Color.white
                        )

                        Text(item.bankName)
                            .font(yaHeiRegularFont(size: 12.6 * fontScale))
                            .foregroundStyle(Color.white.opacity(0.92))
                            .lineLimit(1)
                            .minimumScaleFactor(0.72)
                    }
                    .frame(maxWidth: .infinity)
                }
            }
        }
    }

    private func summaryCard(fontScale: CGFloat) -> some View {
        let hasResolvedCards = !orderedTools.isEmpty
        let countText = (showsLoadingPlaceholder || !hasResolvedCards) ? "-" : String(orderedTools.count)
        return ZStack(alignment: .topLeading) {
            RoundedRectangle(cornerRadius: 26 * fontScale, style: .continuous)
                .fill(
                    LinearGradient(
                        colors: [
                            Color(red: 18 / 255, green: 66 / 255, blue: 184 / 255),
                            Color(red: 8 / 255, green: 17 / 255, blue: 113 / 255),
                            Color(red: 22 / 255, green: 18 / 255, blue: 94 / 255)
                        ],
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    )
                )
                .overlay(
                    RoundedRectangle(cornerRadius: 26 * fontScale, style: .continuous)
                        .stroke(Color.white.opacity(0.22), lineWidth: 1)
                )

            Circle()
                .fill(Color.white.opacity(0.08))
                .frame(width: 138 * fontScale, height: 138 * fontScale)
                .offset(x: 242 * fontScale, y: -26 * fontScale)

            VStack(alignment: .leading, spacing: 18 * fontScale) {
                HStack(alignment: .firstTextBaseline, spacing: 7 * fontScale) {
                    Text(countText)
                        .font(.system(size: 48 * fontScale, weight: .black))
                        .foregroundStyle(Color(red: 244 / 255, green: 227 / 255, blue: 196 / 255))
                        .lineLimit(1)
                        .minimumScaleFactor(0.62)

                    Text("张银行卡")
                        .font(.system(size: 18 * fontScale, weight: .medium))
                        .foregroundStyle(Color(red: 242 / 255, green: 227 / 255, blue: 205 / 255))
                        .lineLimit(1)

                    Spacer(minLength: 8 * fontScale)
                }

                HStack(spacing: 10 * fontScale) {
                    summaryMetric(
                        title: "储蓄卡",
                        value: (showsLoadingPlaceholder || !hasResolvedCards) ? "-" : "\(debitCount)张",
                        fontScale: fontScale
                    )
                    summaryMetric(
                        title: "信用卡",
                        value: (showsLoadingPlaceholder || !hasResolvedCards) ? "-" : "\(creditCount)张",
                        fontScale: fontScale
                    )
                    summaryMetric(
                        title: "其他",
                        value: (showsLoadingPlaceholder || !hasResolvedCards) ? "-" : "\(otherCount)张",
                        fontScale: fontScale
                    )
                }
            }
            .padding(.horizontal, 20 * fontScale)
            .padding(.vertical, 18 * fontScale)
        }
        .frame(height: 162 * fontScale)
    }

    private func summaryMetric(title: String, value: String, fontScale: CGFloat) -> some View {
        VStack(alignment: .leading, spacing: 6 * fontScale) {
            Text(title)
                .font(yaHeiRegularFont(size: 11.6 * fontScale))
                .foregroundStyle(Color.white.opacity(0.68))
            Text(value)
                .font(.system(size: 18 * fontScale, weight: .semibold))
                .foregroundStyle(Color.white.opacity(0.97))
                .lineLimit(1)
                .minimumScaleFactor(0.78)
        }
        .frame(maxWidth: .infinity, alignment: .leading)
        .padding(.horizontal, 12 * fontScale)
        .padding(.vertical, 11 * fontScale)
        .background(
            RoundedRectangle(cornerRadius: 16 * fontScale, style: .continuous)
                .fill(Color.white.opacity(0.09))
        )
    }

    @ViewBuilder
    private func cardListSection(fontScale: CGFloat) -> some View {
        VStack(alignment: .leading, spacing: 12 * fontScale) {
            HStack {
                Text("全部银行卡")
                    .font(.system(size: 18 * fontScale, weight: .semibold))
                    .foregroundStyle(Color.white.opacity(0.98))

                Spacer(minLength: 8 * fontScale)

                if !orderedTools.isEmpty {
                    Text("\(orderedTools.count)张")
                        .font(.system(size: 13 * fontScale, weight: .medium))
                        .foregroundStyle(Color.white.opacity(0.68))
                }
            }

            VStack(alignment: .leading, spacing: 24) {
                if showsLoadingPlaceholder {
                    ForEach(0..<4, id: \.self) { index in
                        loadingCard(fontScale: fontScale, index: index)
                    }
                } else if orderedTools.isEmpty {
                    emptyState(fontScale: fontScale)
                } else {
                    ForEach(Array(orderedTools.enumerated()), id: \.element.toolCode) { index, tool in
                        bankCardItem(tool, index: index, fontScale: fontScale)
                    }
                }
            }
        }
    }

    private func bankCardItem(_ tool: CashierPayToolData, index: Int, fontScale: CGFloat) -> some View {
        let cornerRadius = 24 * fontScale
        let cardShape = RoundedRectangle(cornerRadius: cornerRadius, style: .continuous)
        let palette = cardPalette(for: tool, index: index)
        let title = cardDisplayName(for: tool)
        let detail = cardDetailText(for: tool)
        let meta = cardMetaLabel(for: tool)
        let actions = actionTitles(for: tool)
        let watermarkAssetName = BankLogoCatalog.assetName(bankCode: tool.bankCode, bankName: tool.toolName)
        let metallicHighlight = metallicHighlightColor(for: tool)

        return ZStack(alignment: .topLeading) {
            cardShape
                .fill(
                    LinearGradient(
                        colors: [palette.leading, palette.center, palette.trailing],
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    )
                )
                .overlay(
                    cardShape
