        let chipShape = RoundedRectangle(cornerRadius: 6 * fontScale, style: .continuous)

        return ZStack {
            chipShape
                .fill(
                    LinearGradient(
                        colors: [
                            tintColor.opacity(0.92),
                            tintColor.opacity(0.68),
                            tintColor.opacity(0.86)
                        ],
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    )
                )

            chipShape
                .stroke(Color.white.opacity(0.22), lineWidth: 0.7)

            VStack(spacing: 0) {
                Rectangle()
                    .fill(Color.black.opacity(0.18))
                    .frame(height: 0.9 * fontScale)
                Spacer(minLength: 0)
                Rectangle()
                    .fill(Color.black.opacity(0.16))
                    .frame(height: 0.9 * fontScale)
                Spacer(minLength: 0)
                Rectangle()
                    .fill(Color.black.opacity(0.18))
                    .frame(height: 0.9 * fontScale)
            }
            .padding(.vertical, 4.5 * fontScale)
            .padding(.horizontal, 4.5 * fontScale)

            Rectangle()
                .fill(Color.white.opacity(0.22))
                .frame(width: 0.9 * fontScale, height: 17 * fontScale)
        }
        .frame(width: width, height: height)
    }

    private func metallicCardOverlay(fontScale: CGFloat, highlightColor: Color) -> some View {
        let cornerRadius = 24 * fontScale
        let cardShape = RoundedRectangle(cornerRadius: cornerRadius, style: .continuous)

        return ZStack {
            cardShape
                .fill(
                    LinearGradient(
                        stops: [
                            .init(color: Color.white.opacity(0.08), location: 0.00),
                            .init(color: highlightColor.opacity(0.16), location: 0.18),
                            .init(color: .clear, location: 0.40),
                            .init(color: highlightColor.opacity(0.07), location: 0.68),
                            .init(color: Color.black.opacity(0.11), location: 1.00)
                        ],
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    )
                )

            Rectangle()
                .fill(
                    LinearGradient(
                        colors: [
                            Color.white.opacity(0.22),
                            highlightColor.opacity(0.14),
                            .clear
                        ],
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    )
                )
                .frame(width: 112 * fontScale, height: 240 * fontScale)
                .rotationEffect(.degrees(16))
                .offset(x: -26 * fontScale, y: -42 * fontScale)
                .blur(radius: 10 * fontScale)
                .opacity(0.72)

            Canvas { context, size in
                let lineCount = max(16, Int(size.height / max(5, fontScale * 4.6)))
                let spacing = size.height / CGFloat(lineCount)

                for index in 0..<lineCount {
                    let y = CGFloat(index) * spacing + spacing * 0.58
                    var path = Path()
                    path.move(to: CGPoint(x: size.width * 0.07, y: y))
                    path.addLine(to: CGPoint(x: size.width * 0.93, y: y))

                    let brightOpacity = index.isMultiple(of: 2) ? 0.055 : 0.028
                    context.stroke(
                        path,
                        with: .linearGradient(
                            Gradient(colors: [
                                Color.white.opacity(brightOpacity * 0.34),
                                highlightColor.opacity(brightOpacity * 0.42),
                                Color.black.opacity(brightOpacity * 0.24)
                            ]),
                            startPoint: CGPoint(x: size.width * 0.07, y: y),
                            endPoint: CGPoint(x: size.width * 0.93, y: y)
                        ),
                        lineWidth: 0.85
                    )
                }
            }
            .opacity(0.20)
            .clipShape(cardShape)

            cardShape
                .stroke(
                    LinearGradient(
                        colors: [
                            Color.white.opacity(0.18),
                            highlightColor.opacity(0.24),
                            Color.black.opacity(0.14)
                        ],
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    ),
                    lineWidth: 1
                )
        }
        .clipShape(cardShape)
        .compositingGroup()
        .allowsHitTesting(false)
    }

