    private func cardPalette(for tool: CashierPayToolData, index: Int) -> CardPalette {
        let debitPalettes: [CardPalette] = [
            CardPalette(
                leading: Color(red: 43 / 255, green: 75 / 255, blue: 116 / 255),
                center: Color(red: 102 / 255, green: 144 / 255, blue: 190 / 255),
                trailing: Color(red: 160 / 255, green: 184 / 255, blue: 205 / 255),
                glow: Color(red: 217 / 255, green: 232 / 255, blue: 244 / 255),
                actionBar: Color(red: 28 / 255, green: 47 / 255, blue: 70 / 255).opacity(0.44)
            ),
            CardPalette(
                leading: Color(red: 41 / 255, green: 70 / 255, blue: 92 / 255),
                center: Color(red: 86 / 255, green: 129 / 255, blue: 157 / 255),
                trailing: Color(red: 155 / 255, green: 186 / 255, blue: 196 / 255),
                glow: Color(red: 222 / 255, green: 234 / 255, blue: 238 / 255),
                actionBar: Color(red: 26 / 255, green: 45 / 255, blue: 58 / 255).opacity(0.42)
            ),
            CardPalette(
                leading: Color(red: 52 / 255, green: 64 / 255, blue: 86 / 255),
                center: Color(red: 100 / 255, green: 124 / 255, blue: 156 / 255),
                trailing: Color(red: 177 / 255, green: 192 / 255, blue: 214 / 255),
                glow: Color(red: 229 / 255, green: 236 / 255, blue: 244 / 255),
                actionBar: Color(red: 31 / 255, green: 38 / 255, blue: 55 / 255).opacity(0.44)
            )
        ]

        let creditPalettes: [CardPalette] = [
            CardPalette(
                leading: Color(red: 29 / 255, green: 25 / 255, blue: 24 / 255),
                center: Color(red: 92 / 255, green: 70 / 255, blue: 42 / 255),
                trailing: Color(red: 188 / 255, green: 151 / 255, blue: 84 / 255),
                glow: Color(red: 227 / 255, green: 194 / 255, blue: 118 / 255),
                actionBar: Color(red: 22 / 255, green: 18 / 255, blue: 17 / 255).opacity(0.48)
            ),
            CardPalette(
                leading: Color(red: 24 / 255, green: 27 / 255, blue: 33 / 255),
                center: Color(red: 78 / 255, green: 77 / 255, blue: 89 / 255),
                trailing: Color(red: 174 / 255, green: 151 / 255, blue: 108 / 255),
                glow: Color(red: 223 / 255, green: 199 / 255, blue: 139 / 255),
                actionBar: Color(red: 18 / 255, green: 21 / 255, blue: 26 / 255).opacity(0.5)
            ),
            CardPalette(
                leading: Color(red: 20 / 255, green: 23 / 255, blue: 28 / 255),
                center: Color(red: 56 / 255, green: 50 / 255, blue: 42 / 255),
                trailing: Color(red: 151 / 255, green: 118 / 255, blue: 74 / 255),
                glow: Color(red: 217 / 255, green: 181 / 255, blue: 111 / 255),
                actionBar: Color(red: 17 / 255, green: 18 / 255, blue: 21 / 255).opacity(0.52)
            )
        ]

        let otherPalettes: [CardPalette] = [
            CardPalette(
                leading: Color(red: 51 / 255, green: 58 / 255, blue: 73 / 255),
                center: Color(red: 92 / 255, green: 106 / 255, blue: 132 / 255),
                trailing: Color(red: 152 / 255, green: 166 / 255, blue: 186 / 255),
                glow: Color(red: 226 / 255, green: 231 / 255, blue: 236 / 255),
                actionBar: Color(red: 31 / 255, green: 36 / 255, blue: 44 / 255).opacity(0.42)
            )
        ]

        let normalizedType = CashierPresentationHelper.normalizedCardType(for: tool)
        let seedSource = (tool.bankCode?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased().isEmpty == false
            ? tool.bankCode!
            : tool.toolCode)
        let seed = seedSource.unicodeScalars.reduce(index) { partialResult, scalar in
            partialResult + Int(scalar.value)
        }

        switch normalizedType {
        case "CREDIT":
            return creditPalettes[seed % creditPalettes.count]
        case "DEBIT":
            return debitPalettes[seed % debitPalettes.count]
        default:
            return otherPalettes[seed % otherPalettes.count]
        }
    }

    private func cardDisplayName(for tool: CashierPayToolData) -> String {
        var name = CashierPresentationHelper.bankDisplayName(
            for: tool,
            replaceDebitWithSavings: true,
            stripCardTypeWords: true
        )
        if let openIndex = name.lastIndex(of: "(") {
            name = String(name[..<openIndex])
        }
        name = name.trimmingCharacters(in: .whitespacesAndNewlines)
        return name.isEmpty ? "银行卡" : name
    }

    private func cardMetaLabel(for tool: CashierPayToolData) -> String {
        let cardTypeText: String
        switch CashierPresentationHelper.normalizedCardType(for: tool) {
        case "CREDIT":
            cardTypeText = "信用卡"
        case "DEBIT":
            cardTypeText = "储蓄卡"
        default:
            cardTypeText = "银行卡"
        }
        let tail = cardTailNo(for: tool)
        return tail.isEmpty ? "\(cardTypeText) -" : "\(cardTypeText) \(tail)"
    }

    private func cardTailNo(for tool: CashierPayToolData) -> String {
        let normalized = tool.toolName
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .replacingOccurrences(of: "（", with: "(")
            .replacingOccurrences(of: "）", with: ")")
        if let range = normalized.range(of: "(尾号"),
           let closeIndex = normalized[range.upperBound...].firstIndex(of: ")") {
            let inner = normalized[range.upperBound..<closeIndex]
            let digits = inner.replacingOccurrences(of: "\\D", with: "", options: .regularExpression)
            if digits.count >= 4 {
                return String(digits.suffix(4))
            }
        }
        if let openIndex = normalized.lastIndex(of: "("),
           let closeIndex = normalized[openIndex...].firstIndex(of: ")"),
           openIndex < closeIndex {
            let inner = normalized[normalized.index(after: openIndex)..<closeIndex]
            let digits = inner.replacingOccurrences(of: "\\D", with: "", options: .regularExpression)
            if digits.count >= 4 {
                return String(digits.suffix(4))
            }
        }
        return ""
    }

    private func cardDetailText(for tool: CashierPayToolData) -> String {
        let trimmedPhoneTail = tool.phoneTailNo?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let limitText = CashierPresentationHelper.singleLimitAmountText(from: tool)
        let description = tool.toolDescription.trimmingCharacters(in: .whitespacesAndNewlines)

        if !trimmedPhoneTail.isEmpty {
            return "预留手机号尾号\(trimmedPhoneTail)"
        }
        if limitText != "0" {
            return "银行单笔限额\(limitText)元"
        }
        if !description.isEmpty {
            return description
        }
        switch CashierPresentationHelper.normalizedCardType(for: tool) {
        case "CREDIT":
            return "支持还款与信用消费"
        case "DEBIT":
            return "支持转账、充值与支付"
        default:
            return "银行卡服务已开通"
        }
    }

    private func actionTitles(for tool: CashierPayToolData) -> [String] {
        switch CashierPresentationHelper.normalizedCardType(for: tool) {
        case "CREDIT":
            return ["查看卡号", "删除该卡"]
        case "DEBIT":
            return ["查看卡号", "删除该卡"]
        default:
            return ["查看卡号", "删除该卡"]
        }
    }

    private func handleAction(_ action: String, tool: CashierPayToolData) {
        switch action {
        case "查看卡号":
            activeCardNumberDialog = CardNumberDialogInfo(
                id: tool.toolCode,
                bankName: cardDisplayName(for: tool),
                cardNumber: resolvedCardNumber(tool)
            )
        case "删除该卡":
            activeDeleteCardDialog = DeleteCardDialogInfo(
                id: tool.toolCode,
                tool: tool
            )
        default:
            showToast("\(action)功能稍后开放")
        }
    }

    private func formattedCardNumber(_ cardNumber: String) -> String {
        let digits = cardNumber.filter(\.isNumber)
        guard !digits.isEmpty else {
            return cardNumber
        }

        var groups: [String] = []
        var startIndex = digits.startIndex
        while startIndex < digits.endIndex {
            let endIndex = digits.index(startIndex, offsetBy: 4, limitedBy: digits.endIndex) ?? digits.endIndex
            groups.append(String(digits[startIndex..<endIndex]))
            startIndex = endIndex
        }
        return groups.joined(separator: " ")
    }

    private func showToast(_ message: String) {
        withAnimation(.easeInOut(duration: 0.18)) {
            toastMessage = message
        }
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.6) {
            guard toastMessage == message else {
                return
            }
            withAnimation(.easeInOut(duration: 0.18)) {
                toastMessage = nil
            }
        }
    }

    private func toastView(text: String) -> some View {
        Text(text)
            .font(.system(size: 13, weight: .medium))
            .foregroundStyle(.white)
            .padding(.horizontal, 14)
            .padding(.vertical, 9)
            .background(Color.black.opacity(0.72))
            .clipShape(Capsule())
    }
}

private struct TransferListView: View {
    @Binding var selectedTab: TransferListTab
    let recentContacts: [TransferRecentContact]
    let addressBookContacts: [TransferRecentContact]
    let currentUserId: Int64?
    let isLoadingRecentContacts: Bool
    let isLoadingAddressBookContacts: Bool
    let recentLoadErrorMessage: String?
    let addressBookLoadErrorMessage: String?
    let hasMoreRecentContacts: Bool
    let onBack: () -> Void
    let onOpenTransferHistory: () -> Void
    let onLoadMoreRecentContacts: @MainActor () async -> Void
    let onEnsureRecentContactsLoaded: @MainActor () async -> Void
    let onEnsureAddressBookContactsLoaded: @MainActor () async -> Void
    let onSelectBankCard: (CashierPayToolData) -> Void
    let onSelect: (TransferRecentContact) -> Void

    @State private var searchKeyword: String = ""
    @State private var isSearchFocused = false
    @State private var isTriggeringLoadMore = false
    @State private var myBankCards: [CashierPayToolData] = []
    @State private var isLoadingMyBankCards = false
    @State private var myBankCardsErrorMessage: String?

    private let baseWidth: CGFloat = 402
    private let baseHeight: CGFloat = 874
    private let listCardWidth: CGFloat = 374
    private let rowFirstCenterY: CGFloat = 244
    private let listPanelOffsetY: CGFloat = 5
    private let contactRowHeight: CGFloat = 66
    private let contactRowSpacing: CGFloat = 0
    private let mineRowHeight: CGFloat = 74
    private let mineRowSpacing: CGFloat = 10
    private let rowMaskVerticalInset: CGFloat = 14
    private let rowBackgroundColor = Color.white
    private let rowDividerColor = Color(red: 0.88, green: 0.90, blue: 0.93)
    private let mineListPanelColor = Color(red: 245 / 255, green: 245 / 255, blue: 246 / 255)
    private let mineCardBorderColor = Color(red: 232 / 255, green: 235 / 255, blue: 239 / 255)

    private var normalizedSearchKeyword: String {
        searchKeyword.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private var allContactsOrdered: [TransferRecentContact] {
        addressBookContacts.sorted(by: { lhs, rhs in
            let lhsName = lhs.displayName.trimmingCharacters(in: .whitespacesAndNewlines)
            let rhsName = rhs.displayName.trimmingCharacters(in: .whitespacesAndNewlines)
            if lhsName != rhsName {
                return lhsName.localizedCompare(rhsName) == .orderedAscending
            }
            return lhs.payeeUserId < rhs.payeeUserId
        })
    }

    private var frequentContacts: [TransferRecentContact] {
        let sorted = recentContacts.sorted(by: { lhs, rhs in
            let lhsDate = lhs.lastInteractionAt ?? ""
            let rhsDate = rhs.lastInteractionAt ?? ""
            if lhsDate != rhsDate {
                return lhsDate > rhsDate
            }
            if lhs.interactionCount != rhs.interactionCount {
                return lhs.interactionCount > rhs.interactionCount
            }
            return lhs.payeeUserId < rhs.payeeUserId
        })
        return Array(sorted.prefix(4))
    }

    private var tabContacts: [TransferRecentContact] {
        switch selectedTab {
        case .recent:
            return recentContacts
        case .contacts:
            return allContactsOrdered
        case .mine:
            return []
        }
    }

    private var mineTabCards: [CashierPayToolData] {
        myBankCards.filter(isBankCardTool)
    }

    private var filteredContacts: [TransferRecentContact] {
        let keyword = normalizedSearchKeyword
        guard !keyword.isEmpty else {
            return tabContacts
        }
        return tabContacts.filter { contact in
            if contact.displayName.localizedCaseInsensitiveContains(keyword) {
                return true
            }
            if contact.listDisplayName.localizedCaseInsensitiveContains(keyword) {
                return true
            }
            if let maskedRealName = contact.maskedRealName,
               maskedRealName.localizedCaseInsensitiveContains(keyword) {
                return true
            }
            if contact.accountHint.localizedCaseInsensitiveContains(keyword) {
                return true
            }
            if contact.summary.localizedCaseInsensitiveContains(keyword) {
                return true
            }
            if matchesRawMobileKeyword(keyword, contact: contact) {
                return true
            }
            return String(contact.payeeUserId).contains(keyword)
        }
    }

    private var filteredMineCards: [CashierPayToolData] {
        let keyword = normalizedSearchKeyword
        guard !keyword.isEmpty else {
            return mineTabCards
        }
        return mineTabCards.filter { card in
            let title = bankCardTitle(card)
            let subtitle = bankCardSubtitle(card)
            if title.localizedCaseInsensitiveContains(keyword) {
                return true
            }
            if subtitle.localizedCaseInsensitiveContains(keyword) {
                return true
            }
            return card.toolCode.localizedCaseInsensitiveContains(keyword)
        }
    }

