                    identifier: "transfer_list_exit_circle",
                    centerX: 372 * scaleX,
                    centerY: 67 * scaleY,
                    width: 28 * scaleX,
                    height: 28 * scaleY,
                    action: onBack
                )

                if isCurrentTabLoading && isCurrentTabEmpty && selectedTab != .mine {
                    AILoadingIndicator(
                        text: "查询中",
