                }
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .ignoresSafeArea()
        .task(id: selectedTab) {
            if selectedTab == .mine {
                await loadMineBankCardsIfNeeded()
            } else if selectedTab == .contacts {
                await onEnsureAddressBookContactsLoaded()
            } else {
                await onEnsureRecentContactsLoaded()
            }
        }
        .task(id: currentUserId) {
            myBankCards = []
            myBankCardsErrorMessage = nil
            guard let currentUserId, currentUserId > 0 else {
                return
            }
            if selectedTab == .mine {
                await loadMineBankCardsIfNeeded(force: true)
            } else if selectedTab == .contacts {
                await onEnsureAddressBookContactsLoaded()
            } else {
                await onEnsureRecentContactsLoaded()
            }
        }
    }

