    private func contactListScrollOverlay(scaleX: CGFloat, scaleY: CGFloat) -> some View {
        let fontScale = min(scaleX, scaleY)
        let panelHeight = listPanelHeight * scaleY
        let panelCenterY = (listPanelTopY + listPanelHeight / 2) * scaleY

        return ScrollView(.vertical, showsIndicators: true) {
            LazyVStack(spacing: currentRowSpacing * scaleY) {
                if selectedTab == .mine {
                    if isLoadingMyBankCards && filteredMineCards.isEmpty {
                        ForEach(0..<8, id: \.self) { _ in
                            loadingSkeletonRow(fontScale: fontScale)
                                .frame(width: listCardWidth * scaleX, height: currentRowHeight * scaleY)
                        }
                    } else {
                        ForEach(Array(filteredMineCards.enumerated()), id: \.element.toolCode) { index, card in
                            Button(action: {
                                onSelectBankCard(card)
                            }) {
                                mineBankCardRow(
                                    card,
                                    fontScale: fontScale,
                                    showDivider: false
                                )
                                .frame(width: listCardWidth * scaleX, height: currentRowHeight * scaleY)
                            }
                            .buttonStyle(.plain)
                            .accessibilityIdentifier("transfer_mine_card_\(index)")
                        }
                    }
                } else {
                    if isCurrentTabLoading && filteredContacts.isEmpty {
                        ForEach(0..<8, id: \.self) { _ in
                            loadingSkeletonRow(fontScale: fontScale)
                                .frame(width: listCardWidth * scaleX, height: currentRowHeight * scaleY)
                        }
                    } else {
                        ForEach(Array(filteredContacts.enumerated()), id: \.element.id) { index, contact in
                            Button(action: {
                                onSelect(contact)
                            }) {
                                contactRow(
                                    contact,
                                    fontScale: fontScale,
                                    showDivider: index < filteredContacts.count - 1
                                )
                                .frame(width: listCardWidth * scaleX, height: currentRowHeight * scaleY)
                            }
                            .buttonStyle(.plain)
                            .accessibilityIdentifier("recent_contact_\(contact.id)")
                            .onAppear {
                                triggerLoadMoreIfNeeded(index: index)
                            }
                        }
                    }
                }
            }
            .padding(.top, rowMaskVerticalInset * scaleY)
            .padding(.bottom, 6 * scaleY)
        }
        .scrollIndicators(.visible)
        .refreshable {
            if selectedTab == .mine {
                await loadMineBankCardsIfNeeded(force: true)
                return
            }
            guard selectedTab == .recent else {
                return
            }
            guard hasMoreRecentContacts else {
                return
            }
            await onLoadMoreRecentContacts()
        }
        .frame(width: listCardWidth * scaleX, height: panelHeight)
        .position(x: 201 * scaleX, y: panelCenterY)
    }

    private func triggerLoadMoreIfNeeded(index: Int) {
        guard selectedTab == .recent else {
            return
        }
        guard hasMoreRecentContacts else {
            return
        }
        guard !isLoadingRecentContacts else {
            return
        }
        guard !isTriggeringLoadMore else {
            return
        }
        guard index >= max(filteredContacts.count - 2, 0) else {
            return
        }

        isTriggeringLoadMore = true
        Task {
            await onLoadMoreRecentContacts()
            await MainActor.run {
                isTriggeringLoadMore = false
            }
        }
    }

