    private func isBankCardTool(_ tool: CashierPayToolData) -> Bool {
        let normalizedType = tool.toolType.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        return normalizedType == "BANK_CARD"
    }

    private func matchesRawMobileKeyword(_ keyword: String, contact: TransferRecentContact) -> Bool {
        let keywordDigits = keyword.filter(\.isNumber)
        guard keywordDigits.count >= 7 else {
            return false
        }

        let candidates = [
            contact.accountHint
        ]
        for candidate in candidates {
            let pattern = normalizedMobilePattern(from: candidate)
            guard !pattern.isEmpty else {
                continue
            }
            if mobilePatternMatches(keywordDigits: keywordDigits, maskedPattern: pattern) {
                return true
            }
        }
        return false
    }

    private func normalizedMobilePattern(from text: String) -> String {
        let compact = text
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .replacingOccurrences(of: " ", with: "")
            .replacingOccurrences(of: "-", with: "")
            .replacingOccurrences(of: "（", with: "(")
            .replacingOccurrences(of: "）", with: ")")
        return String(compact.filter { $0.isNumber || $0 == "*" })
    }

    private func mobilePatternMatches(keywordDigits: String, maskedPattern: String) -> Bool {
        guard !keywordDigits.isEmpty, !maskedPattern.isEmpty else {
            return false
        }
        if !maskedPattern.contains("*") {
            return maskedPattern.contains(keywordDigits) || keywordDigits.contains(maskedPattern)
        }

        let patternLength = maskedPattern.count
        guard patternLength > 0, keywordDigits.count >= patternLength else {
            return false
        }
        if keywordDigits.count == patternLength {
            return wildcardPattern(maskedPattern, matches: keywordDigits)
        }

        let digitsArray = Array(keywordDigits)
        for start in 0...(digitsArray.count - patternLength) {
            let segment = String(digitsArray[start..<(start + patternLength)])
            if wildcardPattern(maskedPattern, matches: segment) {
                return true
            }
        }
        return false
    }

    private func wildcardPattern(_ pattern: String, matches digits: String) -> Bool {
        guard pattern.count == digits.count else {
            return false
        }
        return zip(pattern, digits).allSatisfy { patternChar, digitChar in
            patternChar == "*" || patternChar == digitChar
        }
    }

    private func bankCardTitle(_ card: CashierPayToolData) -> String {
        let compactName = simplifiedBankCardName(from: card.toolName)
        let tail = bankCardTailNo(from: card)
        if tail.isEmpty {
            return compactName
        }
        return compactName + "(\(tail))"
    }

    private func bankCardSubtitle(_ card: CashierPayToolData) -> String {
        let limit = bankSingleLimitAmountText(from: card)
        if !limit.isEmpty {
            return "银行单笔限额\(limit)元"
        }

        var parts: [String] = []
        let cardType = bankCardTypeText(from: card.cardType)
        if !cardType.isEmpty {
            parts.append(cardType)
        }
        let phoneTailNo = card.phoneTailNo?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if !phoneTailNo.isEmpty {
            parts.append("预留手机号尾号\(phoneTailNo)")
        }
        let description = card.toolDescription.trimmingCharacters(in: .whitespacesAndNewlines)
        if parts.isEmpty, !description.isEmpty {
            return description
        }
        if parts.isEmpty {
            return "银行卡"
        }
        return parts.joined(separator: " · ")
    }

    private func simplifiedBankCardName(from toolName: String) -> String {
        let normalized = toolName
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .replacingOccurrences(of: "（", with: "(")
            .replacingOccurrences(of: "）", with: ")")
        guard !normalized.isEmpty else {
            return "银行卡"
        }
        let original: String
        if let range = normalized.range(of: "(尾号") {
            original = String(normalized[..<range.lowerBound])
        } else {
            original = normalized
        }
        return BankLogoCatalog.fullDisplayName(bankCode: nil, bankName: original)
    }

    private func bankCardTailNo(from card: CashierPayToolData) -> String {
        let normalized = card.toolName
            .replacingOccurrences(of: "（", with: "(")
            .replacingOccurrences(of: "）", with: ")")
        if let range = normalized.range(of: "(尾号"),
           let closeIndex = normalized[range.upperBound...].firstIndex(of: ")") {
            let inner = normalized[range.upperBound..<closeIndex]
            let digits = inner.replacingOccurrences(of: "\\D", with: "", options: .regularExpression)
            if digits.count >= 4 {
                return String(digits.suffix(4))
            }
        }
        let codeDigits = card.toolCode.replacingOccurrences(of: "\\D", with: "", options: .regularExpression)
        if codeDigits.count >= 4 {
            return String(codeDigits.suffix(4))
        }
        return ""
    }

    private func bankSingleLimitAmountText(from card: CashierPayToolData) -> String {
        let description = card.toolDescription
        if let range = description.range(of: "单笔限额") {
            let suffix = description[range.upperBound...]
            let fragment = suffix.split(separator: "，", maxSplits: 1).first.map(String.init) ?? ""
            let number = fragment.replacingOccurrences(of: "^[^0-9]*([0-9]+(?:\\.[0-9]+)?)?.*$", with: "$1", options: .regularExpression)
            let trimmed = number.trimmingCharacters(in: .whitespacesAndNewlines)
            if !trimmed.isEmpty, let decimal = Decimal(string: trimmed) {
                let formatter = NumberFormatter()
                formatter.locale = Locale(identifier: "en_US_POSIX")
                formatter.numberStyle = .decimal
                formatter.usesGroupingSeparator = false
                formatter.minimumFractionDigits = 0
                formatter.maximumFractionDigits = 2
                let number = NSDecimalNumber(decimal: decimal)
                return formatter.string(from: number) ?? number.stringValue
            }
        }
        return ""
    }

    private func bankCardTypeText(from rawValue: String?) -> String {
        let normalized = rawValue?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() ?? ""
        switch normalized {
        case "DEBIT":
            return "储蓄卡"
        case "CREDIT":
            return "信用卡"
        default:
            return normalized.isEmpty ? "" : rawValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        }
    }

    private func yaHeiRegularFont(size: CGFloat) -> Font {
        let candidates = [
            "MicrosoftYaHei",
            "Microsoft YaHei",
            "MicrosoftYaHei-Light",
            "MicrosoftYaHeiUI",
            "Microsoft YaHei UI",
            "PingFangSC-Regular",
            "微软雅黑"
        ]
        for name in candidates where UIFont(name: name, size: size) != nil {
            return .custom(name, size: size)
        }
        return .system(size: size, weight: .regular)
    }

    @MainActor
    private func loadMineBankCardsIfNeeded(force: Bool = false) async {
        guard selectedTab == .mine else {
            return
        }
        guard let currentUserId, currentUserId > 0 else {
            myBankCards = []
            myBankCardsErrorMessage = "未找到当前登录用户"
            return
        }
        if isLoadingMyBankCards {
            return
        }
        if !force && !myBankCards.isEmpty {
            return
        }

        isLoadingMyBankCards = true
        myBankCardsErrorMessage = nil
        do {
            let tools = try await APIClient.shared.fetchCashierPayTools(userId: currentUserId, sceneCode: "TRANSFER")
            let cards = tools.filter(isBankCardTool)
            myBankCards = cards
            if cards.isEmpty {
                myBankCardsErrorMessage = "暂无我的银行卡"
            }
        } catch {
            myBankCards = []
            myBankCardsErrorMessage = userFacingErrorMessage(error)
        }
        isLoadingMyBankCards = false
    }

    private func loadingSkeletonRow(fontScale: CGFloat) -> some View {
        HStack(spacing: 12) {
            Circle()
                .fill(Color(red: 0.88, green: 0.89, blue: 0.91))
                .frame(width: 38, height: 38)

            VStack(alignment: .leading, spacing: 8) {
                RoundedRectangle(cornerRadius: 4, style: .continuous)
                    .fill(Color(red: 0.86, green: 0.87, blue: 0.89))
                    .frame(width: 132 * fontScale, height: 13 * fontScale)

                RoundedRectangle(cornerRadius: 4, style: .continuous)
                    .fill(Color(red: 0.90, green: 0.91, blue: 0.93))
                    .frame(width: 178 * fontScale, height: 11 * fontScale)
            }

            Spacer(minLength: 0)
        }
        .padding(.horizontal, 14)
        .padding(.vertical, 9)
        .background(
            rowBackgroundColor
        )
        .overlay(
            Rectangle()
                .fill(rowDividerColor)
                .frame(height: 1)
                .padding(.leading, 64),
            alignment: .bottom
        )
        .modifier(LoadingPulseModifier())
    }
    }

private struct LoadingPulseModifier: ViewModifier {
    @State private var reducedOpacity = false

    func body(content: Content) -> some View {
        content
            .opacity(reducedOpacity ? 0.55 : 1)
            .onAppear {
                withAnimation(.easeInOut(duration: 0.85).repeatForever(autoreverses: true)) {
                    reducedOpacity = true
                }
            }
    }
    }

private struct TransferDetailView: View {
    let contact: TransferRecentContact
    @Binding var amountText: String
    @Binding var remarkText: String
    let onBack: () -> Void
    let onOpenHistory: (() -> Void)?
    let onTransfer: (Decimal, String?) -> Void
    let autoFocusAmount: Bool
    let showPayeeSection: Bool
    let showFormSections: Bool
    let backdropMode: Bool
    @FocusState private var focusedField: Field?
    @State private var didTapSubmit = false

    private let baseWidth: CGFloat = 402
    private let baseHeight: CGFloat = 874
    private let quickRemarks: [String] = ["出借", "谢谢", "生活费", "房租", "代买", "还款"]

    private enum Field {
        case amount
        case remark
    }

    init(
        contact: TransferRecentContact,
        amountText: Binding<String>,
        remarkText: Binding<String>,
        onBack: @escaping () -> Void,
        onOpenHistory: (() -> Void)? = nil,
        onTransfer: @escaping (Decimal, String?) -> Void,
        autoFocusAmount: Bool = true,
        showPayeeSection: Bool = true,
        showFormSections: Bool = true,
        backdropMode: Bool = false
    ) {
        self.contact = contact
        self._amountText = amountText
        self._remarkText = remarkText
        self.onBack = onBack
        self.onOpenHistory = onOpenHistory
        self.onTransfer = onTransfer
        self.autoFocusAmount = autoFocusAmount
        self.showPayeeSection = showPayeeSection
        self.showFormSections = showFormSections
        self.backdropMode = backdropMode
    }

    var body: some View {
        GeometryReader { proxy in
            let scaleX = proxy.size.width / baseWidth
            let scaleY = proxy.size.height / baseHeight
            let fontScale = min(scaleX, scaleY)

            ZStack(alignment: .topLeading) {
                Color(
                    red: backdropMode ? 0.95 : 0.93,
                    green: backdropMode ? 0.95 : 0.93,
                    blue: backdropMode ? 0.95 : 0.94
                )
                    .ignoresSafeArea()

                header(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)

                if showPayeeSection {
                    payeeSection(fontScale: fontScale)
                        .frame(width: 378 * scaleX, height: 64 * scaleY)
                        .position(x: 201 * scaleX, y: 142 * scaleY)
                }

                if showFormSections {
                    amountSection(fontScale: fontScale)
                        .frame(width: 378 * scaleX, height: 160 * scaleY)
                        .position(x: 201 * scaleX, y: 243 * scaleY)

                    remarkSection(fontScale: fontScale)
                        .frame(width: 378 * scaleX, height: 138 * scaleY)
                        .position(x: 201 * scaleX, y: 399 * scaleY)

                    if let amountError {
                        Text(amountError)
                            .font(.system(size: 12 * fontScale, weight: .regular))
                            .foregroundStyle(Color(red: 0.82, green: 0.23, blue: 0.20))
                            .position(x: 201 * scaleX, y: 330 * scaleY)
                    }
                }
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
            .contentShape(Rectangle())
            .onTapGesture {
                focusedField = nil
            }
        }
        .onAppear {
            guard autoFocusAmount else {
                return
            }
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.2) {
                focusedField = .amount
            }
        }
        .toolbar {
            if autoFocusAmount && showFormSections {
                ToolbarItemGroup(placement: .keyboard) {
                    Button {
                        focusedField = nil
                    } label: {
                        Image(systemName: "keyboard.chevron.compact.down")
                    }
                    .accessibilityIdentifier("transfer_detail_keyboard_down")

                    Spacer()

                    Button("转账") {
                        submitTransfer()
                    }
                    .disabled(!canSubmit)
                    .accessibilityIdentifier("transfer_detail_submit")
                }
            }
        }
    }

    private func header(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        ZStack {
            Text("转账")
                .font(.system(size: 17 * fontScale, weight: .semibold))
                .foregroundStyle(Color(red: 0.24, green: 0.24, blue: 0.24))
                .position(x: 201 * scaleX, y: 84 * scaleY)

            Button {
                onBack()
            } label: {
                Color.clear
                    .frame(width: 40 * scaleX, height: 44 * scaleY)
                    .contentShape(Rectangle())
            }
            .buttonStyle(.plain)
            .accessibilityIdentifier("transfer_detail_back")
            .position(x: 17 * scaleX, y: 100 * scaleY)

            Image(systemName: "chevron.left")
                .font(.system(size: 20 * fontScale, weight: .medium))
                .foregroundStyle(Color(red: 0.35, green: 0.35, blue: 0.35))
                .position(x: 17 * scaleX, y: 84 * scaleY)
                .allowsHitTesting(false)

            Button {
                onOpenHistory?()
            } label: {
                Text("转账记录")
                    .font(.system(size: 16 * fontScale, weight: .medium))
                    .foregroundStyle(Color(red: 0.38, green: 0.38, blue: 0.38))
            }
            .buttonStyle(.plain)
            .accessibilityIdentifier("transfer_detail_history")
            .position(x: 358 * scaleX, y: 84 * scaleY)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .topLeading)
    }

    private func payeeSection(fontScale: CGFloat) -> some View {
        HStack(spacing: 10) {
            ContactAvatarView(
                avatarUrl: contact.avatarUrl,
                avatarAssetName: contact.avatarAssetName,
                avatarText: contact.avatarText,
                avatarColor: contact.avatarColor,
                size: 42
            )

            VStack(alignment: .leading, spacing: 2) {
                Text(contact.listDisplayName)
                    .font(.system(size: 16 * fontScale, weight: .semibold))
                    .foregroundStyle(Color(red: 0.20, green: 0.20, blue: 0.20))
                Text(contact.accountHint)
                    .font(.system(size: 14 * fontScale, weight: .regular))
                    .foregroundStyle(Color(red: 0.48, green: 0.48, blue: 0.48))
            }
            Spacer(minLength: 0)
        }
        .padding(.horizontal, 10 * max(1.0, fontScale))
        .padding(.vertical, 8 * max(1.0, fontScale))
    }

    private func amountSection(fontScale: CGFloat) -> some View {
        VStack(alignment: .leading, spacing: 8) {
            Text("转账金额")
                .font(.system(size: 14 * fontScale, weight: .semibold))
                .foregroundStyle(Color(red: 0.31, green: 0.31, blue: 0.31))

            HStack(alignment: .center, spacing: 4) {
                Text("¥")
                    .font(.system(size: 30 * fontScale, weight: .semibold))
                    .foregroundStyle(Color(red: 0.18, green: 0.18, blue: 0.18))

                TextField(
                    "",
                    text: $amountText,
                    prompt: Text("请输入金额")
                        .foregroundStyle(Color(red: 0.74, green: 0.74, blue: 0.74))
                )
                .keyboardType(.decimalPad)
                .focused($focusedField, equals: .amount)
                .font(.system(size: 33 * fontScale, weight: .semibold))
                .foregroundStyle(Color(red: 0.18, green: 0.18, blue: 0.18))
                .accessibilityIdentifier("transfer_detail_amount_input")
            }
            .frame(maxWidth: .infinity, minHeight: 96, alignment: .leading)
        }
        .padding(.horizontal, 12)
        .padding(.top, 8)
        .padding(.bottom, 12)
        .background(Color(red: 0.95, green: 0.95, blue: 0.95))
        .clipShape(RoundedRectangle(cornerRadius: 12, style: .continuous))
    }

    private func remarkSection(fontScale: CGFloat) -> some View {
        VStack(alignment: .leading, spacing: 10) {
            Text("转账留言")
                .font(.system(size: 14 * fontScale, weight: .semibold))
                .foregroundStyle(Color(red: 0.31, green: 0.31, blue: 0.31))

            TextField(
                "",
                text: $remarkText,
                prompt: Text("添加备注(50字以内)")
                    .foregroundStyle(Color(red: 0.74, green: 0.74, blue: 0.74))
            )
            .focused($focusedField, equals: .remark)
            .font(.system(size: 16 * fontScale, weight: .regular))
            .foregroundStyle(Color(red: 0.25, green: 0.25, blue: 0.25))
            .accessibilityIdentifier("transfer_detail_remark_input")
            .onChange(of: remarkText) { _, newValue in
                if newValue.count > 50 {
                    remarkText = String(newValue.prefix(50))
                }
            }

            HStack(spacing: 6) {
                ForEach(Array(quickRemarks.enumerated()), id: \.offset) { index, text in
                    Button {
                        remarkText = text
                        focusedField = .remark
                    } label: {
                        Text(text)
                            .font(.system(size: 13 * fontScale, weight: .medium))
                            .foregroundStyle(Color(red: 0.47, green: 0.47, blue: 0.47))
                            .padding(.horizontal, 10)
                            .padding(.vertical, 4)
                            .background(Color(red: 0.95, green: 0.95, blue: 0.95))
                            .clipShape(Capsule())
                            .overlay(
                                Capsule()
                                    .stroke(Color(red: 0.87, green: 0.87, blue: 0.87), lineWidth: 1)
                            )
                    }
                    .buttonStyle(.plain)
                    .accessibilityIdentifier("transfer_detail_quick_remark_\(index)")
                }
            }
        }
        .padding(.horizontal, 12)
        .padding(.top, 10)
        .padding(.bottom, 12)
        .background(Color(red: 0.95, green: 0.95, blue: 0.95))
        .clipShape(RoundedRectangle(cornerRadius: 12, style: .continuous))
    }

    private var canSubmit: Bool {
        normalizedAmount != nil
    }

    private var amountError: String? {
        guard didTapSubmit else {
            return nil
        }
        let trimmed = amountText.trimmingCharacters(in: .whitespacesAndNewlines)
        if trimmed.isEmpty {
            return "请输入转账金额"
        }
        if normalizedAmount == nil {
            return "金额格式不正确或不能小于 0.01"
        }
        return nil
    }

    private var normalizedAmount: Decimal? {
        let trimmed = amountText.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else {
            return nil
        }
        let normalizedText = trimmed.replacingOccurrences(of: ",", with: ".")
        guard let amount = Decimal(string: normalizedText), amount >= 0.01 else {
            return nil
        }
        return amount
    }

    private func submitTransfer() {
        didTapSubmit = true
        guard let amount = normalizedAmount else {
            return
        }
        let normalizedRemark = remarkText.trimmingCharacters(in: .whitespacesAndNewlines)
        onTransfer(amount, normalizedRemark.isEmpty ? nil : normalizedRemark)
    }
    }

private struct TransferHistoryView: View {
    let userId: Int64?
    let syntheticChanges: [AssetChangeItemData]
    let onBack: () -> Void

    @State private var records: [TransferHistoryRecord] = []
    @State private var isLoading = false
    @State private var loadErrorMessage: String?
    @State private var selectedFilter: TransferHistoryFilter = .all

    private enum TransferHistoryFilter: String, CaseIterable, Identifiable {
        case all
        case income
        case expense
        case toCard

        var id: String { rawValue }

        var title: String {
            switch self {
            case .all:
                return "全部"
            case .income:
                return "转入"
            case .expense:
                return "转出"
            case .toCard:
                return "转账到卡"
            }
        }
    }

    private struct TransferHistoryRecord: Identifiable {
        let id: String
        let monthKey: String
        let monthLabel: String
        let title: String
        let subtitle: String
        let timeText: String
        let signedAmount: Decimal
        let isIncome: Bool
        let isToCard: Bool
        let avatarUrl: String?
        let avatarText: String
        let avatarColor: Color
        let bankCode: String?
        let bankName: String?
    }

    private struct TransferHistorySection: Identifiable {
        let id: String
        let monthLabel: String
        let expenseTotal: Decimal
        let incomeTotal: Decimal
        let rows: [TransferHistoryRecord]
    }

    private static let posixLocale = Locale(identifier: "en_US_POSIX")
    private static let calendar = Calendar(identifier: .gregorian)
    private static let monthFormatter: DateFormatter = {
        let formatter = DateFormatter()
        formatter.locale = posixLocale
        formatter.timeZone = .current
        formatter.dateFormat = "yyyy-MM"
        return formatter
    }()
    private static let dateTimeFormatter: DateFormatter = {
        let formatter = DateFormatter()
        formatter.locale = posixLocale
        formatter.timeZone = .current
        formatter.dateFormat = "yyyy-MM-dd HH:mm:ss"
        return formatter
    }()
    private static let slashDateTimeFormatter: DateFormatter = {
        let formatter = DateFormatter()
        formatter.locale = posixLocale
        formatter.timeZone = .current
        formatter.dateFormat = "yyyy/MM/dd HH:mm:ss"
        return formatter
    }()
    private static let fallbackDateFormatter: ISO8601DateFormatter = {
        let formatter = ISO8601DateFormatter()
        formatter.formatOptions = [.withInternetDateTime, .withFractionalSeconds]
        formatter.timeZone = .current
        return formatter
    }()
    private static let shortDateTimeFormatter: DateFormatter = {
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "zh_CN")
        formatter.timeZone = .current
        formatter.dateFormat = "MM-dd HH:mm"
        return formatter
    }()
    private static let yesterdayTimeFormatter: DateFormatter = {
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "zh_CN")
        formatter.timeZone = .current
        formatter.dateFormat = "HH:mm"
        return formatter
    }()
    private static let monthLabelFormatter: DateFormatter = {
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "zh_CN")
        formatter.timeZone = .current
        formatter.dateFormat = "M月"
        return formatter
    }()
    private static let moneyFormatter: NumberFormatter = {
        let formatter = NumberFormatter()
        formatter.locale = posixLocale
        formatter.numberStyle = .decimal
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        formatter.groupingSeparator = ","
        formatter.usesGroupingSeparator = true
        return formatter
    }()

    private var displayedRecords: [TransferHistoryRecord] {
        switch selectedFilter {
        case .all:
            return records
        case .income:
            return records.filter { $0.isIncome && !$0.isToCard }
        case .expense:
            return records.filter { !$0.isIncome && !$0.isToCard }
        case .toCard:
            return records.filter(\.isToCard)
        }
    }

    private var sections: [TransferHistorySection] {
        let grouped = Dictionary(grouping: displayedRecords, by: \.monthKey)
        let keys = grouped.keys.sorted(by: >)
        return keys.compactMap { key in
            guard let rows = grouped[key], !rows.isEmpty else {
                return nil
            }
            var expenseTotal = Decimal.zero
            var incomeTotal = Decimal.zero
            rows.forEach { row in
                let absAmount = Self.absolute(row.signedAmount)
                if row.isIncome {
                    incomeTotal += absAmount
                } else {
                    expenseTotal += absAmount
                }
            }
            return TransferHistorySection(
                id: "transfer_history_\(key)",
                monthLabel: rows.first?.monthLabel ?? "--",
                expenseTotal: expenseTotal,
                incomeTotal: incomeTotal,
                rows: rows
            )
        }
    }

    var body: some View {
        GeometryReader { proxy in
            let windowTopInset = UIApplication.shared.activeKeyWindow?.safeAreaInsets.top ?? 0
            let windowBottomInset = UIApplication.shared.activeKeyWindow?.safeAreaInsets.bottom ?? 0
            let safeTopInset = max(proxy.safeAreaInsets.top, windowTopInset, 44)
            let safeBottomInset = max(proxy.safeAreaInsets.bottom, windowBottomInset)

            ZStack {
                Color(red: 245 / 255, green: 245 / 255, blue: 246 / 255)
                    .ignoresSafeArea()

                VStack(spacing: 0) {
                    navigationBar(topInset: safeTopInset)
                    filterBar

                    if isLoading && displayedRecords.isEmpty {
                        loadingView
                    } else if displayedRecords.isEmpty {
                        emptyView
                    } else {
                        ScrollView(showsIndicators: false) {
                            LazyVStack(spacing: 10) {
                                ForEach(sections) { section in
                                    sectionView(section)
                                }
                            }
                            .padding(.horizontal, 10)
                            .padding(.top, 8)
                            .padding(.bottom, max(safeBottomInset, 10) + 12)
                        }
                        .refreshable {
                            await loadRecords(force: true)
                        }
                    }
                }
            }
        }
        .task(id: userId) {
            await loadRecords(force: true)
        }
    }

    private func navigationBar(topInset: CGFloat) -> some View {
        VStack(spacing: 0) {
            HStack(spacing: 0) {
                Button(action: onBack) {
                    Image(systemName: "chevron.left")
                        .font(.system(size: 18, weight: .medium))
                        .foregroundStyle(Color(red: 0.19, green: 0.20, blue: 0.22))
                        .frame(width: 44, height: 44, alignment: .center)
                }
                .buttonStyle(.plain)

                Spacer(minLength: 0)

                Text("转账记录")
                    .font(.system(size: 18, weight: .semibold))
                    .foregroundStyle(Color(red: 0.16, green: 0.17, blue: 0.19))

                Spacer(minLength: 0)

                Color.clear
                    .frame(width: 44, height: 44)
            }
            .padding(.top, topInset + 2)
            .padding(.horizontal, 8)
            .background(Color.white)

            Rectangle()
                .fill(Color(red: 0.90, green: 0.91, blue: 0.93))
                .frame(height: 1 / UIScreen.main.scale)
        }
        .background(Color.white)
    }

    private var filterBar: some View {
        HStack(spacing: 8) {
            ForEach(TransferHistoryFilter.allCases) { filter in
                Button {
                    selectedFilter = filter
                } label: {
                    Text(filter.title)
                        .font(.system(size: 14, weight: selectedFilter == filter ? .semibold : .regular))
                        .foregroundStyle(
                            selectedFilter == filter
                                ? AppTheme.palette.brandPrimaryPressed
                                : Color(red: 0.46, green: 0.47, blue: 0.50)
                        )
                        .padding(.horizontal, 14)
                        .padding(.vertical, 6)
                        .background(
                            Capsule(style: .continuous)
                                .fill(selectedFilter == filter ? Color(red: 0.93, green: 0.96, blue: 1.0) : Color.white)
                        )
                }
                .buttonStyle(.plain)
            }
        }
        .padding(.horizontal, 10)
        .padding(.vertical, 8)
        .background(Color(red: 245 / 255, green: 245 / 255, blue: 246 / 255))
    }

    private var loadingView: some View {
        VStack(spacing: 10) {
            Spacer(minLength: 0)

            ProgressView()
                .progressViewStyle(.circular)
                .tint(Color(red: 0.46, green: 0.47, blue: 0.50))

            Text("加载中...")
                .font(.system(size: 14, weight: .medium))
                .foregroundStyle(Color(red: 0.56, green: 0.57, blue: 0.60))

            Spacer(minLength: 0)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    private var emptyView: some View {
        VStack(spacing: 10) {
            Spacer(minLength: 0)

            Text(loadErrorMessage ?? "暂无转账记录")
                .font(.system(size: 14, weight: .medium))
                .foregroundStyle(Color(red: 0.56, green: 0.57, blue: 0.60))
                .multilineTextAlignment(.center)
                .padding(.horizontal, 20)

            Spacer(minLength: 0)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    private func sectionView(_ section: TransferHistorySection) -> some View {
        VStack(spacing: 8) {
            VStack(alignment: .leading, spacing: 6) {
                HStack(spacing: 4) {
                    Text(section.monthLabel)
                        .font(.system(size: 28, weight: .bold))
                        .foregroundStyle(Color(red: 0.20, green: 0.21, blue: 0.24))
                }

                HStack(spacing: 16) {
                    Text("支出 ¥\(Self.formatMoney(section.expenseTotal))")
                        .font(.system(size: 14, weight: .regular))
                        .foregroundStyle(Color(red: 0.40, green: 0.42, blue: 0.45))
                    Text("收入 ¥\(Self.formatMoney(section.incomeTotal))")
                        .font(.system(size: 14, weight: .regular))
                        .foregroundStyle(Color(red: 0.40, green: 0.42, blue: 0.45))
                }
            }
            .frame(maxWidth: .infinity, alignment: .leading)
            .padding(.horizontal, 8)

            VStack(spacing: 0) {
                ForEach(Array(section.rows.enumerated()), id: \.element.id) { index, row in
                    recordRowView(row: row, showsDivider: index < section.rows.count - 1)
                }
            }
            .background(Color.white)
            .clipShape(RoundedRectangle(cornerRadius: 14, style: .continuous))
            .overlay(
                RoundedRectangle(cornerRadius: 14, style: .continuous)
                    .stroke(Color(red: 0.92, green: 0.93, blue: 0.95), lineWidth: 1)
            )
        }
    }

