    @MainActor
    private func loadRecords(force: Bool) async {
        guard !isLoading else {
            return
        }
        if !force && !records.isEmpty {
            return
        }
        guard let userId, userId > 0 else {
            records = []
            loadErrorMessage = nil
            return
        }

        isLoading = true
        loadErrorMessage = nil
        defer {
            isLoading = false
        }

        do {
            let items = try await APIClient.shared.fetchAssetChanges(userId: String(userId), limit: 80)
            let mergedItems = mergedTransferItems(remote: items)
            records = Self.buildRecords(from: mergedItems)
            if records.isEmpty {
                loadErrorMessage = nil
            }
        } catch {
            let mergedItems = mergedTransferItems(remote: [])
            records = Self.buildRecords(from: mergedItems)
            loadErrorMessage = nil
        }
    }

    private func mergedTransferItems(remote: [AssetChangeItemData]) -> [AssetChangeItemData] {
        let localTransfers = syntheticChanges.filter(Self.isTransferLikeItem)
        guard !localTransfers.isEmpty else {
            return remote
        }

        var merged: [AssetChangeItemData] = []
        var seenTradeNos = Set<String>()
        var seenSemanticKeys = Set<String>()

        for item in remote + localTransfers {
            let tradeNoKey = normalizedTradeNoKey(for: item)
            let semanticKey = semanticTransferKey(for: item)

            if !tradeNoKey.isEmpty, seenTradeNos.contains(tradeNoKey) {
                continue
            }
            if !semanticKey.isEmpty, seenSemanticKeys.contains(semanticKey) {
                continue
            }

            if !tradeNoKey.isEmpty {
                seenTradeNos.insert(tradeNoKey)
            }
            if !semanticKey.isEmpty {
                seenSemanticKeys.insert(semanticKey)
            }
            merged.append(item)
        }
        return merged
    }

    private func normalizedTradeNoKey(for item: AssetChangeItemData) -> String {
        item.tradeNo.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func semanticTransferKey(for item: AssetChangeItemData) -> String {
        let direction = item.direction.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let amountValue = Self.decimalValue(item.signedAmount) ?? .zero
        let normalizedAmount = Self.absolute(amountValue)
        let amountText = String(format: "%.2f", NSDecimalNumber(decimal: normalizedAmount).doubleValue)
        let counterpartyUserId = (item.counterpartyUserId ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
        let displayTitle = item.displayTitle.trimmingCharacters(in: .whitespacesAndNewlines)
        let occurredMinute = normalizedOccurredMinute(item.occurredAt)
        return [direction, amountText, counterpartyUserId, displayTitle, occurredMinute].joined(separator: "|")
    }

    private func normalizedOccurredMinute(_ raw: String) -> String {
        let normalized = raw
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .replacingOccurrences(of: "T", with: " ")
            .replacingOccurrences(of: "Z", with: "")
        if normalized.count >= 16 {
            return String(normalized.prefix(16))
        }
        return normalized
    }

    private static func buildRecords(from items: [AssetChangeItemData]) -> [TransferHistoryRecord] {
        let sorted = items
            .filter(isTransferLikeItem)
            .sorted(by: { lhs, rhs in
                let left = parseOccurredAt(lhs.occurredAt)
                let right = parseOccurredAt(rhs.occurredAt)
                switch (left, right) {
                case let (l?, r?):
                    return l > r
                case (.some, .none):
                    return true
                case (.none, .some):
                    return false
                default:
                    return lhs.tradeNo > rhs.tradeNo
                }
            })

        let realRecords = sorted.enumerated().map { index, item in
            let tradeType = item.tradeType.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
            let sceneCode = item.businessSceneCode.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
            let direction = item.direction.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
            let isToCard = tradeType == "WITHDRAW" || sceneCode.contains("WITHDRAW") || sceneCode.contains("TRANSFER_TO_CARD")
            let signedAmount = signedDecimalValue(amountText: item.signedAmount, direction: direction)
            let isIncome = signedAmount > .zero || (signedAmount == .zero && direction == "CREDIT")
            let occurredAt = parseOccurredAt(item.occurredAt)
            let monthKey = monthKeyText(occurredAt)
            let monthLabel = monthLabelText(occurredAt)
            let counterpartyName = resolveCounterpartyName(from: item)
            let avatarUrl = normalizedText(item.counterpartyAvatarUrl)
            let bankCode = normalizedText(item.bankCode)
            let bankName = normalizedText(item.bankName)
            let title = Self.resolveTitle(
                isToCard: isToCard,
                counterpartyName: counterpartyName,
                displayTitle: item.displayTitle,
                bankName: bankName,
                bankTailNo: normalizedText(item.bankCardTailNo)
            )
            let subtitle = resolveSubtitle(
                isToCard: isToCard,
                sceneCode: sceneCode,
                bankName: bankName,
                bankTailNo: normalizedText(item.bankCardTailNo)
            )
            let avatarText = avatarText(name: counterpartyName.isEmpty ? title : counterpartyName)
            let avatarColorSeed = Int64(abs((item.counterpartyUserId ?? item.tradeNo).hashValue))
            return TransferHistoryRecord(
                id: "\(item.tradeNo)_\(index)",
                monthKey: monthKey,
                monthLabel: monthLabel,
                title: title,
                subtitle: subtitle,
                timeText: timeText(occurredAt, raw: item.occurredAt),
                signedAmount: signedAmount,
                isIncome: isIncome,
                isToCard: isToCard,
                avatarUrl: avatarUrl,
                avatarText: avatarText,
                avatarColor: avatarColor(seed: avatarColorSeed),
                bankCode: bankCode,
                bankName: bankName
            )
        }
        return realRecords
    }

    private static func isTransferLikeItem(_ item: AssetChangeItemData) -> Bool {
        let tradeType = item.tradeType.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let sceneCode = item.businessSceneCode.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        if tradeType == "TRANSFER" || tradeType == "WITHDRAW" {
            return true
        }
        if sceneCode.contains("TRANSFER") || sceneCode.contains("WITHDRAW") || sceneCode.contains("RED_PACKET") {
            return true
        }
        return false
    }

    private static func resolveTitle(
        isToCard: Bool,
        counterpartyName: String,
        displayTitle: String,
        bankName: String?,
        bankTailNo: String?
    ) -> String {
        if isToCard {
            if let bankName, !bankName.isEmpty {
                return "转账到卡-\(bankName)"
            }
            return "转账到卡"
        }
        if !counterpartyName.isEmpty {
            return "转账-\(counterpartyName)"
        }
        let normalizedDisplayTitle = normalizedText(displayTitle)
        if let normalizedDisplayTitle, !normalizedDisplayTitle.isEmpty {
            return normalizedDisplayTitle
        }
        if let bankTailNo, !bankTailNo.isEmpty {
            return "转账-\(bankTailNo)"
        }
        return "转账记录"
    }

    private static func resolveSubtitle(
        isToCard: Bool,
        sceneCode: String,
        bankName: String?,
        bankTailNo: String?
    ) -> String {
        if isToCard {
            if let bankName, let bankTailNo, !bankTailNo.isEmpty {
                return "\(bankName)(\(bankTailNo))"
            }
            if let bankName {
                return bankName
            }
            return "转账到银行卡"
        }
        if sceneCode.contains("RED_PACKET") {
            return "转账红包-转账到户"
        }
        if sceneCode.contains("MOBILE") {
            return "手机转账-转账到户"
        }
        return "转账到户"
    }

    private static func resolveCounterpartyName(from item: AssetChangeItemData) -> String {
        if let nickname = normalizedText(item.counterpartyNickname), !nickname.isEmpty {
            return nickname
        }
        let title = item.displayTitle.trimmingCharacters(in: .whitespacesAndNewlines)
        if title.hasPrefix("向"), title.hasSuffix("转账"), title.count > 3 {
            let start = title.index(after: title.startIndex)
            let end = title.index(title.endIndex, offsetBy: -2)
            return String(title[start..<end])
        }
        if title.hasPrefix("收到"), title.hasSuffix("转账"), title.count > 4 {
            let start = title.index(title.startIndex, offsetBy: 2)
            let end = title.index(title.endIndex, offsetBy: -2)
            return String(title[start..<end])
        }
        if let fromRange = title.range(of: "来自"), let toRange = title.range(of: "的红包"), fromRange.upperBound < toRange.lowerBound {
            return String(title[fromRange.upperBound..<toRange.lowerBound])
        }
        return ""
    }

    private static func parseOccurredAt(_ raw: String) -> Date? {
        let trimmed = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else {
            return nil
        }
        let normalized = trimmed.replacingOccurrences(of: "T", with: " ").replacingOccurrences(of: "Z", with: "")
        if let parsed = dateTimeFormatter.date(from: normalized) {
            return parsed
        }
        if let parsed = slashDateTimeFormatter.date(from: normalized) {
            return parsed
        }
        if let parsed = fallbackDateFormatter.date(from: trimmed) {
            return parsed
        }
        return nil
    }

    private static func monthKeyText(_ date: Date?) -> String {
        guard let date else {
            return "0000-00"
        }
        return monthFormatter.string(from: date)
    }

    private static func monthLabelText(_ date: Date?) -> String {
        guard let date else {
            return "--"
        }
        return monthLabelFormatter.string(from: date)
    }

    private static func timeText(_ date: Date?, raw: String) -> String {
        guard let date else {
            let normalized = raw.trimmingCharacters(in: .whitespacesAndNewlines)
            return normalized.isEmpty ? "--" : normalized
        }
        if calendar.isDateInYesterday(date) {
            return "昨天 " + yesterdayTimeFormatter.string(from: date)
        }
        return shortDateTimeFormatter.string(from: date)
    }

    private static func decimalValue(_ raw: String) -> Decimal? {
        let normalized = raw
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .replacingOccurrences(of: ",", with: "")
        guard !normalized.isEmpty else {
            return nil
        }
        return Decimal(string: normalized, locale: posixLocale)
    }

    private static func signedDecimalValue(amountText: String, direction: String) -> Decimal {
        guard let parsed = decimalValue(amountText) else {
            return .zero
        }
        if parsed == .zero {
            return .zero
        }
        if parsed < .zero {
            return parsed
        }
        return direction == "DEBIT" ? -parsed : parsed
    }

    private static func normalizedText(_ raw: String?) -> String? {
        let trimmed = raw?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        return trimmed.isEmpty ? nil : trimmed
    }

    private static func absolute(_ value: Decimal) -> Decimal {
        value < .zero ? -value : value
    }

    private static func formatMoney(_ amount: Decimal) -> String {
        let absAmount = absolute(amount)
        let number = NSDecimalNumber(decimal: absAmount)
        return moneyFormatter.string(from: number) ?? String(describing: number)
    }

    private static func signedAmountText(for amount: Decimal) -> String {
        if amount == .zero {
            return "0.00"
        }
        let sign = amount > .zero ? "+" : "-"
        return sign + formatMoney(amount)
    }

    private static func avatarText(name: String) -> String {
        let trimmed = name.trimmingCharacters(in: .whitespacesAndNewlines)
        if let first = trimmed.first {
            return String(first)
        }
        return "账"
    }

    private static func avatarColor(seed: Int64) -> Color {
        let palette: [Color] = [
            Color(red: 0.98, green: 0.45, blue: 0.29),
            AppTheme.palette.brandPrimaryLight,
            Color(red: 0.35, green: 0.74, blue: 0.52),
            AppTheme.palette.brandPrimaryLight,
            Color(red: 0.96, green: 0.71, blue: 0.21),
            Color(red: 0.22, green: 0.71, blue: 0.75)
        ]
        let index = Int(abs(seed) % Int64(palette.count))
        return palette[index]
    }
}

