                .position(x: 367 * scaleX, y: 676 * scaleY)

            backgroundColor
                .frame(width: 120 * scaleX, height: 120 * scaleY)
                .position(x: 366 * scaleX, y: 801 * scaleY)
        }
    }

    private func dynamicChangeRows(scaleX: CGFloat, scaleY: CGFloat) -> some View {
        let fontScale = min(scaleX, scaleY)
        let lineHeight = max(1 / UIScreen.main.scale, 0.6 * min(scaleX, scaleY))
        let rows = renderedRows
        let rowBlockOffsetY: CGFloat = -116
        return Group {
            ForEach(Array(rows.enumerated()), id: \.element.id) { index, row in
                let rowOffset = CGFloat(index) * 72
                let titleY = (567 + rowOffset + rowBlockOffsetY) * scaleY + (5 * scaleY)
                let sublineY = (597 + rowOffset + rowBlockOffsetY) * scaleY - (2 * scaleY)
                let leftColumnCenterX = 162 * scaleX
                let rightColumnCenterX = 319 * scaleX
                ZStack {
                    if index > 0 {
                        Rectangle()
                            .fill(Color(red: 0.91, green: 0.92, blue: 0.94))
                            .frame(width: 330 * scaleX, height: lineHeight)
                            .position(x: 201 * scaleX, y: ((567 + rowOffset + rowBlockOffsetY) * scaleY) - (21 * scaleY))
                    }

                    Color.white
                        .frame(width: 46 * scaleX, height: 42 * scaleY)
                        .clipShape(Circle())
                        .position(x: 39 * scaleX, y: (583 + rowOffset + rowBlockOffsetY) * scaleY)

                    balanceChangeIconView(row: row, fontScale: fontScale)
                        .position(x: 39 * scaleX, y: (583 + rowOffset + rowBlockOffsetY) * scaleY)

                    Color.white
                        .frame(width: 198 * scaleX, height: 24 * scaleY)
                        .position(x: leftColumnCenterX, y: titleY)
                    Color.white
                        .frame(width: 198 * scaleX, height: 18 * scaleY)
                        .position(x: leftColumnCenterX, y: sublineY)
                    Color.white
                        .frame(width: 130 * scaleX, height: 24 * scaleY)
                        .position(x: rightColumnCenterX, y: titleY)
                    Color.white
                        .frame(width: 130 * scaleX, height: 18 * scaleY)
                        .position(x: rightColumnCenterX, y: sublineY)

                    if !row.title.isEmpty {
                        Text(row.title)
                            .font(yaHeiRegularFont(size: 15.5 * fontScale))
                            .foregroundStyle(Color(red: 0.24, green: 0.25, blue: 0.27))
                            .lineLimit(1)
                            .frame(width: 198 * scaleX, alignment: .leading)
                            .position(x: leftColumnCenterX, y: titleY)
                    }

                    if !row.occurredAtText.isEmpty {
                        Text(row.occurredAtText)
                            .font(.system(size: 11.8 * fontScale, weight: .regular))
                            .foregroundStyle(Color(red: 0.62, green: 0.63, blue: 0.65))
                            .lineLimit(1)
                            .frame(width: 198 * scaleX, alignment: .leading)
                            .position(x: leftColumnCenterX, y: sublineY)
                    }

                    if !row.signedAmountText.isEmpty {
                        Text(row.signedAmountText)
                            .font(.system(size: 16.2 * fontScale, weight: .semibold))
                            .foregroundStyle(Color(red: 0.23, green: 0.24, blue: 0.26))
                            .lineLimit(1)
                            .minimumScaleFactor(0.8)
                            .frame(width: 126 * scaleX, alignment: .trailing)
                            .position(x: rightColumnCenterX, y: titleY)
                    }

                    if !row.balanceAfterText.isEmpty {
                        Text("余额 \(row.balanceAfterText)元")
                            .font(.system(size: 11.8 * fontScale, weight: .regular))
                            .foregroundStyle(Color(red: 0.62, green: 0.63, blue: 0.65))
                            .lineLimit(1)
                            .minimumScaleFactor(0.8)
                            .frame(width: 126 * scaleX, alignment: .trailing)
                            .position(x: rightColumnCenterX, y: sublineY)
                    }
                }
            }
        }
    }

