    private var isAvailableAmountLoading: Bool {
        isAmountVisible && isLoading && effectiveAvailableAmount == nil
    }

    private func loadingAvailableAmountText(at date: Date) -> String {
        let dotPattern = [0, 1, 2, 3, 2, 1]
        let step = Int(date.timeIntervalSinceReferenceDate / 0.45)
        let dotCount = dotPattern[step % dotPattern.count]
        return "余额查询中" + String(repeating: ".", count: dotCount)
    }

    private var availableAmountText: String {
        if !isAmountVisible {
            return "****"
        }
        if let availableAmount = effectiveAvailableAmount {
            return formatMoney(availableAmount, useGrouping: true, forceSign: false)
        }
        if let errorMessage,
           !errorMessage.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            return "查询失败"
        }
        return "余额查询中"
    }

    private var renderedRows: [BalanceChangeRow] {
        var rows: [BalanceChangeRow] = []
        let visibleChanges = Array(changes.prefix(6))
        var runningBalance = effectiveAvailableAmount
        let shouldShowEmptyPlaceholder = !isLoading && changes.isEmpty

        for (index, change) in visibleChanges.enumerated() {
            let signedValue = signedDecimalValue(amountText: change.signedAmount, direction: change.direction)
            let balanceAfter = runningBalance ?? Decimal.zero
            rows.append(
                BalanceChangeRow(
                    id: "\(change.tradeNo)_\(index)",
                    tradeType: change.tradeType.uppercased(),
                    counterpartyUserId: change.counterpartyUserId ?? "",
                    counterpartyName: resolveCounterpartyName(from: change),
                    counterpartyAvatarUrl: normalizedURLText(change.counterpartyAvatarUrl),
                    bankCode: normalizedText(change.bankCode),
                    bankName: normalizedText(change.bankName),
                    bankCardTailNo: normalizedText(change.bankCardTailNo),
                    title: resolveDisplayTitle(from: change),
                    occurredAtText: normalizeOccurredAt(change.occurredAt),
                    signedAmountText: formatSignedMoney(signedValue),
                    balanceAfterText: formatMoney(balanceAfter, useGrouping: false, forceSign: false)
                )
            )
            if var current = runningBalance {
                current -= signedValue
                runningBalance = current
            }
        }

        while rows.count < 6 {
            let placeholderIndex = rows.count + 1
            rows.append(
                BalanceChangeRow(
                    id: "balance_change_placeholder_\(placeholderIndex)",
                    tradeType: "UNKNOWN",
                    counterpartyUserId: "",
                    counterpartyName: "",
                    counterpartyAvatarUrl: nil,
                    bankCode: nil,
                    bankName: nil,
                    bankCardTailNo: nil,
                    title: rows.isEmpty && shouldShowEmptyPlaceholder ? "暂无余额变动记录" : "",
                    occurredAtText: "",
                    signedAmountText: "",
                    balanceAfterText: ""
                )
            )
        }
        return rows
    }

