    private func yaHeiRegularFont(size: CGFloat) -> Font {
        let candidates = [
            "MicrosoftYaHei",
            "Microsoft YaHei",
            "MicrosoftYaHei-Light",
            "MicrosoftYaHeiUI",
            "Microsoft YaHei UI",
            "微软雅黑"
        ]
        for name in candidates where UIFont(name: name, size: size) != nil {
            return .custom(name, size: size)
        }
        return .system(size: size, weight: .regular)
    }

    private func resolveCounterpartyName(from change: AssetChangeItemData) -> String {
        if let nickname = normalizedText(change.counterpartyNickname) {
            return nickname
        }
        let title = normalizeTitle(change.displayTitle)
        if title.hasPrefix("向"), title.hasSuffix("转账"), title.count > 3 {
            let start = title.index(after: title.startIndex)
            let end = title.index(title.endIndex, offsetBy: -2)
            return String(title[start..<end])
        }
        if title.hasPrefix("收到"), title.hasSuffix("转账"), title.count > 4 {
            let start = title.index(title.startIndex, offsetBy: 2)
            let end = title.index(title.endIndex, offsetBy: -2)
            return String(title[start..<end])
        }
        return ""
    }

    private func resolveDisplayTitle(from change: AssetChangeItemData) -> String {
        let title = normalizeTitle(change.displayTitle)
        let tradeType = change.tradeType.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let sceneCode = change.businessSceneCode.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        if isAiCashTransferInSceneCode(sceneCode) {
            return aiCashSingleTransferInBillTitle
        }
        if sceneCode == "FUND_FAST_REDEEM" {
            return title
        }
        if tradeType.contains("WITHDRAW") || sceneCode.contains("WITHDRAW") {
            let bankCode = normalizedText(change.bankCode)
            let bankName = normalizedText(change.bankName)
            if bankCode != nil || bankName != nil {
                let fullBankName = BankLogoCatalog.fullDisplayName(bankCode: bankCode, bankName: bankName)
                if fullBankName != "银行卡" {
                    return "提现到\(fullBankName)"
                }
            }
            if let bankTailNo = normalizedText(change.bankCardTailNo) {
                return "提现到尾号\(bankTailNo)"
            }
            return "余额提现"
        }
        if sceneCode == "CHAT_RED_PACKET_CLAIM" {
            let counterpartyName = resolveCounterpartyName(from: change)
            if !counterpartyName.isEmpty {
                return "收到来自\(counterpartyName)的红包"
            }
            return "收到红包"
        }
        return title
    }

    private func avatarText(for name: String) -> String {
        let trimmed = name.trimmingCharacters(in: .whitespacesAndNewlines)
        if let first = trimmed.first {
            return String(first)
        }
        return "账"
    }

    private func avatarColorSeed(from row: BalanceChangeRow) -> Int64 {
        if let parsed = Int64(row.counterpartyUserId), parsed > 0 {
            return parsed
        }
        return Int64(abs(row.id.hashValue % 9973))
    }

    private func avatarColor(seed: Int64) -> Color {
        let palette: [Color] = [
            Color(red: 0.98, green: 0.45, blue: 0.29),
            AppTheme.palette.brandPrimaryLight,
            Color(red: 0.35, green: 0.74, blue: 0.52),
            AppTheme.palette.brandPrimaryLight,
            Color(red: 0.96, green: 0.71, blue: 0.21),
            Color(red: 0.22, green: 0.71, blue: 0.75)
        ]
        let index = Int(abs(seed) % Int64(palette.count))
        return palette[index]
    }

    private func normalizedText(_ raw: String?) -> String? {
        let trimmed = raw?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        return trimmed.isEmpty ? nil : trimmed
    }

    private func normalizedURLText(_ raw: String?) -> String? {
        let trimmed = raw?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !trimmed.isEmpty else {
            return nil
        }
        guard trimmed.hasPrefix("http://") || trimmed.hasPrefix("https://") else {
            return nil
        }
        return trimmed
    }

    @MainActor
    private func refreshBalanceData(showLoading: Bool) async {
        let normalizedUserId = userId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedUserId.isEmpty else {
            overview = nil
            changes = []
            errorMessage = "未找到用户标识"
            isLoading = false
            return
        }

        let hasCachedOverview = overview != nil
        let hasCachedChanges = !changes.isEmpty
        if showLoading {
            isLoading = true
            errorMessage = nil
        }
        var overviewFetchError: Error?
        do {
            overview = try await APIClient.shared.fetchAssetOverview(
                userId: normalizedUserId,
                timeoutInterval: balanceRequestTimeout
            )
        } catch {
            overviewFetchError = error
            if showLoading && !hasCachedOverview {
                overview = nil
            }
        }

        do {
            let latestChanges = try await APIClient.shared.fetchAssetChanges(
                userId: normalizedUserId,
                limit: 6,
                timeoutInterval: balanceRequestTimeout
            )
            changes = mergedChanges(remote: latestChanges)
        } catch {
            if showLoading || !hasCachedChanges {
                changes = mergedChanges(remote: [])
            } else {
                changes = mergedChanges(remote: changes)
            }
        }

        if let overviewFetchError {
            errorMessage = balanceQueryErrorMessage(for: overviewFetchError)
        } else {
            errorMessage = nil
        }
        if showLoading {
            isLoading = false
        }
    }

    private func balanceQueryErrorMessage(for error: Error) -> String {
        if shouldUseBalanceQueryFailureFallback(for: error) {
            return "查询失败，请稍后重试"
        }
        return userFacingErrorMessage(error)
    }

    private func shouldUseBalanceQueryFailureFallback(for error: Error) -> Bool {
        if let urlError = error as? URLError {
            switch urlError.code {
            case .timedOut, .cannotConnectToHost, .cannotFindHost, .networkConnectionLost, .notConnectedToInternet, .dnsLookupFailed:
                return true
            default:
                break
            }
        }
        if case let APIClientError.businessError(message)? = (error as? APIClientError),
           message.contains("无法连接服务器") {
            return true
        }
        let normalizedMessage = userFacingErrorMessage(error).lowercased()
        return normalizedMessage.contains("timeout")
            || normalizedMessage.contains("timed out")
            || normalizedMessage.contains("超时")
    }

    private func mergedChanges(remote: [AssetChangeItemData]) -> [AssetChangeItemData] {
        guard !remote.isEmpty else {
            return []
        }
        var seenExactKeys = Set<String>()
        var seenSemanticKeys = Set<String>()
        var deduplicatedRemote: [AssetChangeItemData] = []

        for change in remote {
            let exactKey = changeDedupKey(for: change)
            if seenExactKeys.contains(exactKey) {
                continue
            }

            let semanticKey = changeSemanticDedupKey(for: change)
            if seenSemanticKeys.contains(semanticKey) {
                continue
            }

            seenExactKeys.insert(exactKey)
            seenSemanticKeys.insert(semanticKey)
            deduplicatedRemote.append(change)
        }

        return deduplicatedRemote.sorted { lhs, rhs in
            let leftDate = parseOccurredAt(lhs.occurredAt)
            let rightDate = parseOccurredAt(rhs.occurredAt)
            switch (leftDate, rightDate) {
            case let (l?, r?):
                return l > r
            case (.some, .none):
                return true
            case (.none, .some):
                return false
            default:
                return lhs.tradeNo > rhs.tradeNo
            }
        }
    }

    private func recentSyntheticBalanceChanges() -> [AssetChangeItemData] {
        []
    }

    private func filterDuplicatedGenericWithdrawChanges(
        remote: [AssetChangeItemData],
        synthetic: [AssetChangeItemData]
    ) -> [AssetChangeItemData] {
        let syntheticWithdraws = synthetic.filter { isSpecificSyntheticWithdrawChange($0) }
        guard !syntheticWithdraws.isEmpty else {
            return remote
        }

        var matchedSyntheticIndices = Set<Int>()
        return remote.enumerated().filter { _, remoteChange in
            guard isGenericRemoteWithdrawChange(remoteChange) else {
                return true
            }
            guard let remoteAmount = normalizedWithdrawAmount(remoteChange),
                  let remoteDate = parseOccurredAt(remoteChange.occurredAt) else {
                return true
            }

            for (syntheticIndex, syntheticChange) in syntheticWithdraws.enumerated() {
                if matchedSyntheticIndices.contains(syntheticIndex) {
                    continue
                }
                guard let syntheticAmount = normalizedWithdrawAmount(syntheticChange),
                      decimalsClose(remoteAmount, syntheticAmount),
                      let syntheticDate = parseOccurredAt(syntheticChange.occurredAt) else {
                    continue
                }

                let timeDelta = abs(remoteDate.timeIntervalSince(syntheticDate))
                if timeDelta <= 300 {
                    matchedSyntheticIndices.insert(syntheticIndex)
                    return false
                }
            }
            return true
        }.map(\.element)
    }

    private func isSpecificSyntheticWithdrawChange(_ change: AssetChangeItemData) -> Bool {
        let tradeNo = change.tradeNo.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        guard tradeNo.hasPrefix("LOCAL_WITHDRAW_") else {
            return false
        }
        return normalizeTitle(change.displayTitle).contains("提现到")
    }

    private func isGenericRemoteWithdrawChange(_ change: AssetChangeItemData) -> Bool {
        let tradeNo = change.tradeNo.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        if tradeNo.hasPrefix("LOCAL_WITHDRAW_") {
            return false
        }
        return isWithdrawChange(change)
    }

    private func isWithdrawChange(_ change: AssetChangeItemData) -> Bool {
        let tradeType = normalizedTradeType(for: change)
        if tradeType.contains("WITHDRAW") {
            return true
        }
        return normalizeTitle(change.displayTitle).contains("提现")
    }

    private func normalizedWithdrawAmount(_ change: AssetChangeItemData) -> Decimal? {
        let signed = signedDecimalValue(amountText: change.signedAmount, direction: change.direction)
        return abs(signed)
    }

    private func filterDuplicatedGenericDepositChanges(
        remote: [AssetChangeItemData],
        synthetic: [AssetChangeItemData]
    ) -> [AssetChangeItemData] {
        let syntheticDeposits = synthetic.filter { isSpecificSyntheticDepositChange($0) }
        guard !syntheticDeposits.isEmpty else {
            return remote
        }

        var matchedSyntheticIndices = Set<Int>()
        return remote.enumerated().filter { _, remoteChange in
            guard isGenericRemoteDepositChange(remoteChange) else {
                return true
            }
            guard let remoteAmount = normalizedDepositAmount(remoteChange),
                  let remoteDate = parseOccurredAt(remoteChange.occurredAt) else {
                return true
            }

            for (syntheticIndex, syntheticChange) in syntheticDeposits.enumerated() {
                if matchedSyntheticIndices.contains(syntheticIndex) {
                    continue
                }
                guard let syntheticAmount = normalizedDepositAmount(syntheticChange),
                      decimalsClose(remoteAmount, syntheticAmount),
                      let syntheticDate = parseOccurredAt(syntheticChange.occurredAt) else {
                    continue
                }

                let timeDelta = abs(remoteDate.timeIntervalSince(syntheticDate))
                if timeDelta <= 300 {
                    matchedSyntheticIndices.insert(syntheticIndex)
                    return false
                }
            }
            return true
        }.map(\.element)
    }

    private func isSpecificSyntheticDepositChange(_ change: AssetChangeItemData) -> Bool {
        let tradeNo = change.tradeNo.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        guard tradeNo.hasPrefix("LOCAL_DEPOSIT_") else {
            return false
        }
        let direction = change.direction.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        return direction == "CREDIT"
    }

    private func isGenericRemoteDepositChange(_ change: AssetChangeItemData) -> Bool {
        let tradeNo = change.tradeNo.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        if tradeNo.hasPrefix("LOCAL_DEPOSIT_") || tradeNo.hasPrefix("LOCAL_AICASH_SUBSCRIBE_") {
            return false
        }
        guard isDepositChange(change) else {
            return false
        }
        let direction = change.direction.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        guard direction == "CREDIT" else {
            return false
        }

        let title = normalizeTitle(change.displayTitle)
        let upperTitle = title.uppercased()
        return title == "余额充值"
            || title == "银行卡充值"
            || title == "充值"
            || title == "资金转入"
            || title == "转入余额"
            || title == "转入"
            || upperTitle.hasPrefix("APP_DEPOSIT")
            || upperTitle == "DEPOSIT"
    }

    private func isDepositChange(_ change: AssetChangeItemData) -> Bool {
        let tradeType = normalizedTradeType(for: change)
        if tradeType.contains("DEPOSIT") {
            return true
        }
        let sceneCode = change.businessSceneCode.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        if sceneCode.contains("DEPOSIT") || sceneCode.contains("RECHARGE") {
            return true
        }
        let title = normalizeTitle(change.displayTitle)
        return title.contains("充值") || title.contains("转入")
    }

    private func normalizedDepositAmount(_ change: AssetChangeItemData) -> Decimal? {
        let signed = signedDecimalValue(amountText: change.signedAmount, direction: change.direction)
        return abs(signed)
    }

    private func decimalsClose(_ lhs: Decimal, _ rhs: Decimal) -> Bool {
        let epsilon = Decimal(string: "0.005") ?? Decimal(0.005)
        return abs(lhs - rhs) < epsilon
    }

    private func changeDedupKey(for change: AssetChangeItemData) -> String {
        let tradeNo = change.tradeNo.trimmingCharacters(in: .whitespacesAndNewlines)
        if !tradeNo.isEmpty {
            return tradeNo
        }
        return [
            change.tradeType.trimmingCharacters(in: .whitespacesAndNewlines),
            change.direction.trimmingCharacters(in: .whitespacesAndNewlines),
            change.signedAmount.trimmingCharacters(in: .whitespacesAndNewlines),
            change.occurredAt.trimmingCharacters(in: .whitespacesAndNewlines),
            change.displayTitle.trimmingCharacters(in: .whitespacesAndNewlines)
        ].joined(separator: "|")
    }

    private func changeSemanticDedupKey(for change: AssetChangeItemData) -> String {
        let tradeType = normalizedTradeType(for: change)
        let direction = change.direction.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let signedAmount = formatMoney(
            signedDecimalValue(amountText: change.signedAmount, direction: change.direction),
            useGrouping: false,
            forceSign: false
        )
        let occurredMinute = normalizedOccurredMinute(change.occurredAt)
        let bankTailNo = change.bankCardTailNo?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        return [tradeType, direction, signedAmount, occurredMinute, bankTailNo].joined(separator: "|")
    }

    private func normalizedTradeType(for change: AssetChangeItemData) -> String {
        let tradeType = change.tradeType.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let sceneCode = change.businessSceneCode.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()

        if tradeType.contains("WITHDRAW") || sceneCode.contains("WITHDRAW") {
            return "WITHDRAW"
        }
        if tradeType.contains("DEPOSIT") || sceneCode.contains("DEPOSIT") {
            return "DEPOSIT"
        }
        if !tradeType.isEmpty {
            return tradeType
        }
        return sceneCode
    }

    private func normalizedOccurredMinute(_ value: String) -> String {
        let occurredAt = normalizeOccurredAt(value)
        if occurredAt.count >= 16 {
            return String(occurredAt.prefix(16))
        }
        return occurredAt
    }

    private func parseOccurredAt(_ value: String) -> Date? {
        let normalized = normalizeOccurredAt(value)
        guard normalized != "--" else {
            return nil
        }
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.timeZone = TimeZone(identifier: "Asia/Shanghai")
        formatter.dateFormat = "yyyy-MM-dd HH:mm:ss"
        if let date = formatter.date(from: normalized) {
            return date
        }
        formatter.dateFormat = "yyyy-MM-dd HH:mm"
        return formatter.date(from: normalized)
    }

    private func normalizeTitle(_ title: String) -> String {
        let trimmed = title.trimmingCharacters(in: .whitespacesAndNewlines)
        if trimmed.isEmpty {
            return "余额变动"
        }
        return trimmed
    }

    private func normalizeOccurredAt(_ value: String) -> String {
        let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
        if trimmed.isEmpty {
            return "--"
        }
        let normalized = trimmed.replacingOccurrences(of: "T", with: " ")
        let strippedFraction = normalized.split(separator: ".").first.map(String.init) ?? normalized
        if strippedFraction.count >= 19 {
            return String(strippedFraction.prefix(19))
        }
        return strippedFraction
    }

    private func signedDecimalValue(amountText: String, direction: String) -> Decimal {
        guard let parsed = decimalValue(amountText) else {
            return Decimal.zero
        }
        if parsed < 0 {
            return parsed
        }
        if direction.uppercased() == "DEBIT" {
            return -parsed
        }
        return parsed
    }

    private func decimalValue(_ value: String?) -> Decimal? {
        let trimmed = value?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !trimmed.isEmpty else {
            return nil
        }
        let normalized = trimmed
            .replacingOccurrences(of: ",", with: "")
            .replacingOccurrences(of: "＋", with: "+")
            .replacingOccurrences(of: "－", with: "-")
        return Decimal(string: normalized)
    }

    private func formatSignedMoney(_ value: Decimal) -> String {
        if value == Decimal.zero {
            return "0.00"
        }
        return formatMoney(value, useGrouping: false, forceSign: false)
    }

    private func formatMoney(_ value: Decimal, useGrouping: Bool, forceSign: Bool) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = useGrouping
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        if forceSign {
            formatter.positivePrefix = "+"
        }
        let number = NSDecimalNumber(decimal: value)
        if let text = formatter.string(from: number) {
            return text
        }
        return number.stringValue
    }
    }

private struct AssetBalanceDetailView: View {
    let userId: String
    let availableAmountDelta: Decimal
    let refreshNonce: Int
    let onBack: () -> Void

    @State private var overview: AssetOverviewData?
    @State private var changes: [AssetChangeItemData] = []
    @State private var isLoading = false
    @State private var errorMessage: String?
    @State private var selectedFilter: BalanceChangeFilter = .all
    private let balanceRequestTimeout: TimeInterval = 10

    private enum BalanceChangeFilter: String, CaseIterable, Identifiable {
        case all
        case expense
        case income

        var id: String { rawValue }

        var title: String {
            switch self {
            case .all:
                return "全部"
            case .expense:
                return "支出"
            case .income:
                return "收入"
            }
        }

        var emptyText: String {
            switch self {
            case .all:
                return "暂无余额变动记录"
            case .expense:
                return "暂无支出记录"
            case .income:
                return "暂无收入记录"
            }
        }
    }

    private struct BalanceChangeRow: Identifiable {
        let id: String
        let tradeType: String
        let direction: String
        let counterpartyUserId: String
        let counterpartyName: String
        let counterpartyAvatarUrl: String?
        let bankCode: String?
        let bankName: String?
        let title: String
        let occurredAtText: String
        let signedAmountValue: Decimal
        let signedAmountText: String
        let balanceAfterText: String

        var isIncome: Bool {
            signedAmountValue > .zero || direction == "CREDIT"
        }

        var isExpense: Bool {
            signedAmountValue < .zero || direction == "DEBIT"
        }

        var amountColor: Color {
            if isIncome {
                return Color(red: 1.0, green: 0.41, blue: 0.14)
            }
            return Color(red: 0.23, green: 0.24, blue: 0.26)
        }
    }

    var body: some View {
        GeometryReader { proxy in
            let windowTopInset = UIApplication.shared.activeKeyWindow?.safeAreaInsets.top ?? 0
            let windowBottomInset = UIApplication.shared.activeKeyWindow?.safeAreaInsets.bottom ?? 0
            let safeTopInset = max(proxy.safeAreaInsets.top, windowTopInset, 44)
            let safeBottomInset = max(proxy.safeAreaInsets.bottom, windowBottomInset)

            ZStack {
                Color(red: 243 / 255, green: 245 / 255, blue: 248 / 255)
                    .ignoresSafeArea()

                VStack(spacing: 0) {
                    navigationBar(topInset: safeTopInset)
                    filterTabs

                    if let errorMessage, allRows.isEmpty, !isLoading {
                        detailStatusView(
                            title: errorMessage,
                            showsRetry: true,
                            contentOffsetY: 0,
                            retryAction: {
                                Task {
                                    await refreshBalanceData(showLoading: true)
                                }
                            }
                        )
                    } else if isLoading && allRows.isEmpty {
                        detailStatusView(title: "加载中...", showsRetry: false, contentOffsetY: 20, retryAction: nil)
                    } else {
                        ScrollView(showsIndicators: false) {
                            VStack(spacing: 12) {
                                if let errorMessage, !errorMessage.isEmpty, !allRows.isEmpty {
                                    Text(errorMessage)
                                        .font(.system(size: 12, weight: .medium))
                                        .foregroundStyle(Color(red: 0.77, green: 0.25, blue: 0.24))
                                        .frame(maxWidth: .infinity, alignment: .leading)
                                }

                                if displayedRows.isEmpty {
                                    emptyStateCard(message: selectedFilter.emptyText)
                                } else {
                                    balanceChangeListCard
                                }
                            }
                            .padding(.horizontal, 12)
                            .padding(.top, 12)
                            .padding(.bottom, max(safeBottomInset, 12) + 12)
                        }
                        .refreshable {
                            await refreshBalanceData(showLoading: false)
                        }
                    }
                }
            }
        }
        .task(id: "\(userId)_\(refreshNonce)") {
            await refreshBalanceData(showLoading: true)
        }
    }

    private var effectiveAvailableAmount: Decimal? {
        guard let baseAmount = decimalValue(overview?.availableAmount) else {
            return nil
        }
        return max(.zero, baseAmount)
    }

    // 先基于完整流水计算每条记录的余额，再做 tab 过滤，避免过滤后把余额算错。
    private var allRows: [BalanceChangeRow] {
        var rows: [BalanceChangeRow] = []
        var runningBalance = effectiveAvailableAmount

        for (index, change) in changes.enumerated() {
            let signedValue = signedDecimalValue(amountText: change.signedAmount, direction: change.direction)
            let balanceAfterText: String
            if let balanceAfter = runningBalance {
                balanceAfterText = formatMoney(balanceAfter, useGrouping: false, forceSign: false)
            } else {
                balanceAfterText = "--"
            }

            rows.append(
                BalanceChangeRow(
                    id: "\(change.tradeNo)_\(index)",
                    tradeType: change.tradeType.uppercased(),
                    direction: change.direction.uppercased(),
                    counterpartyUserId: change.counterpartyUserId ?? "",
                    counterpartyName: resolveCounterpartyName(from: change),
                    counterpartyAvatarUrl: normalizedURLText(change.counterpartyAvatarUrl),
                    bankCode: normalizedText(change.bankCode),
                    bankName: normalizedText(change.bankName),
                    title: resolveDisplayTitle(from: change),
                    occurredAtText: normalizeOccurredAt(change.occurredAt),
                    signedAmountValue: signedValue,
                    signedAmountText: formatSignedMoney(signedValue),
                    balanceAfterText: balanceAfterText
                )
            )

            if var currentBalance = runningBalance {
                currentBalance -= signedValue
                runningBalance = currentBalance
            }
        }

        return rows
    }

    private var displayedRows: [BalanceChangeRow] {
        switch selectedFilter {
        case .all:
            return allRows
        case .expense:
            return allRows.filter(\.isExpense)
        case .income:
            return allRows.filter(\.isIncome)
        }
    }

