	        GeometryReader { proxy in
	            let scaleX = proxy.size.width / baseWidth
	            let scaleY = proxy.size.height / baseHeight

	            ZStack {
	                Image("BillDetailReference")
	                    .resizable()
	                    .interpolation(.high)
	                    .aspectRatio(contentMode: .fill)
	                    .frame(width: proxy.size.width, height: proxy.size.height)
	                    .clipped()

                billSearchInteractionOverlay(scaleX: scaleX, scaleY: scaleY)
                billReferenceStickerCleanupOverlay(scaleX: scaleX, scaleY: scaleY)
                    billTopRightMoreCleanupOverlay(scaleX: scaleX, scaleY: scaleY)
                    billMonthChevronCleanupOverlay(scaleX: scaleX, scaleY: scaleY)

	                billFilterTabsOverlay(scaleX: scaleX, scaleY: scaleY)

	                billListOverlay(viewSize: proxy.size, scaleX: scaleX, scaleY: scaleY)

	                if let section = activeSection {
	                    summaryHeaderOverlay(section: section, scaleX: scaleX, scaleY: scaleY)
	                }

	                Button(action: onBack) {
	                    Color.clear
	                        .frame(width: 68 * scaleX, height: 56 * scaleY)
                        .contentShape(Rectangle())
                }
                .buttonStyle(.plain)
                .position(x: 28 * scaleX, y: 52 * scaleY)
                .accessibilityIdentifier("bill_reference_back_button")
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .onChange(of: sections.map(\.id)) { _, _ in
            syncSelectedMonthIfNeeded()
        }
        .task(id: "\(userId)_\(refreshNonce)") {
            await refreshBillData(showLoading: true)
        }
    }

