	    private func billSearchInteractionOverlay(scaleX: CGFloat, scaleY: CGFloat) -> some View {
	        ZStack {
                if isSearchFieldFocused || !searchKeywordText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                    RoundedRectangle(cornerRadius: 10 * min(scaleX, scaleY), style: .continuous)
                        .fill(Color.white)
