                        .position(x: (115 + 2.0 / 3.0) * scaleX, y: 78 * scaleY)
                        .allowsHitTesting(false)
                }

                VerticallyCenteredTextField(
                    text: $searchKeywordText,
                    isFocused: $isSearchFieldFocused,
                    font: UIFont.systemFont(ofSize: 14 * min(scaleX, scaleY), weight: .regular),
                    textColor: UIColor(red: 0.24, green: 0.25, blue: 0.27, alpha: 1),
                    tintColor: AppTheme.palette.brandPrimaryUIColor,
                    returnKeyType: .search,
                    textInsets: UIEdgeInsets(top: -9 * scaleY, left: (44 + 2.0 / 3.0) * scaleX, bottom: 9 * scaleY, right: 8 * scaleX),
                    showsAccessoryToolbar: false,
                    onSubmit: applySearchKeyword
                )
                .frame(width: 232 * scaleX, height: 34 * scaleY)
                .background(Color.white.opacity(0.001))
                .contentShape(Rectangle())
                .position(x: 145 * scaleX, y: 86 * scaleY)
                .onChange(of: searchKeywordText) { _, newValue in
                    if newValue.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                        appliedSearchKeyword = ""
                        syncSelectedMonthIfNeeded()
                    }
                }

                Color.clear
                    .frame(width: 232 * scaleX, height: 34 * scaleY)
                    .contentShape(Rectangle())
                    .position(x: 145 * scaleX, y: 86 * scaleY)
                    .onTapGesture {
                        DispatchQueue.main.async {
                            isSearchFieldFocused = true
                        }
                    }

                // 清理搜索按钮最右侧残留的参考图小点。
                RoundedRectangle(cornerRadius: 3.5 * min(scaleX, scaleY), style: .continuous)
                    .fill(Color.white)
                    .frame(width: 9 * scaleX, height: 9 * scaleY)
                    .position(x: 307 * scaleX, y: 86 * scaleY)
                    .allowsHitTesting(false)

	            Button(action: applySearchKeyword) {
	                Color.clear
	                    .frame(width: 46 * scaleX, height: 34 * scaleY)
	                    .contentShape(Rectangle())
	            }
	            .buttonStyle(.plain)
	            .position(x: 286 * scaleX, y: 86 * scaleY)
	        }
	    }

