	    private var emptyStateText: String {
	        if !appliedSearchKeyword.isEmpty {
	            return "未找到相关交易记录"
	        }
	        return selectedFilter.emptyText
	    }

    private func updateVisibleMonth(with offsets: [String: CGFloat]) {
        let threshold: CGFloat = 20
        let orderedOffsets = sections.compactMap { section in
            offsets[section.id].map { (id: section.id, minY: $0) }
        }
        guard !orderedOffsets.isEmpty else {
            return
        }

        let resolvedMonthId: String
        if let visibleTopMonth = orderedOffsets
            .filter({ $0.minY <= threshold })
            .max(by: { $0.minY < $1.minY }) {
            resolvedMonthId = visibleTopMonth.id
        } else {
            resolvedMonthId = orderedOffsets.min(by: { $0.minY < $1.minY })?.id ?? orderedOffsets[0].id
        }

        if selectedMonthKey != resolvedMonthId {
            selectedMonthKey = resolvedMonthId
        }
    }

