    private func applySearchKeyword() {
        appliedSearchKeyword = searchKeywordText
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased()
        isSearchFieldFocused = false
        syncSelectedMonthIfNeeded()
    }

    @MainActor
    private func syncSelectedMonthIfNeeded() {
        let monthIds = sections.map(\.id)
        guard !monthIds.isEmpty else {
            selectedMonthKey = ""
            return
        }
        if !monthIds.contains(selectedMonthKey) {
            selectedMonthKey = monthIds[0]
        }
    }

    @MainActor
    private func refreshBillData(showLoading: Bool) async {
        let normalizedUserId = userId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedUserId.isEmpty else {
            changes = []
            redPacketStatusByTradeNo = [:]
            errorMessage = "未找到用户标识"
            isLoading = false
            syncSelectedMonthIfNeeded()
            return
        }

        let hasCachedData = !changes.isEmpty
        if showLoading {
            isLoading = true
            errorMessage = nil
        }
        do {
            let maxPages = showLoading ? 20 : 3
            let remoteChanges = try await fetchAllBillChanges(userId: normalizedUserId, maxPages: maxPages)
            let merged = mergedChanges(remote: remoteChanges)
            changes = merged
            redPacketStatusByTradeNo = await loadSentRedPacketStatusMap(for: merged, userId: normalizedUserId)
            errorMessage = nil
        } catch {
            if showLoading || !hasCachedData {
                changes = []
                redPacketStatusByTradeNo = [:]
            }
            errorMessage = "账单查询失败"
        }
        if showLoading {
            isLoading = false
        }
        syncSelectedMonthIfNeeded()
    }

    private func fetchAllBillChanges(userId: String, maxPages: Int) async throws -> [AssetChangeItemData] {
        let boundedPages = min(max(maxPages, 1), 30)
        var requestPageNo = 1
        var requestCursor: String? = nil
        var pageGuard = 0
        var allEntries: [AssetBillEntryItemData] = []

        while pageGuard < boundedPages {
            pageGuard += 1
            let billEntries = try await APIClient.shared.fetchAssetBillEntries(
                userId: userId,
                limit: 100,
                pageNo: requestPageNo,
                cursor: requestCursor
            )
            allEntries.append(contentsOf: billEntries.items)

            let currentCursor = requestCursor?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            let nextCursor = billEntries.nextCursor?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            if !nextCursor.isEmpty, nextCursor != currentCursor {
                requestCursor = nextCursor
                requestPageNo = max((billEntries.nextPageNo ?? (requestPageNo + 1)), requestPageNo + 1)
                if billEntries.items.isEmpty {
                    break
                }
                continue
            }

            if billEntries.hasMore == true,
               let nextPageNo = billEntries.nextPageNo,
               nextPageNo > requestPageNo {
                requestPageNo = nextPageNo
                requestCursor = nil
                if billEntries.items.isEmpty {
                    break
                }
                continue
            }
            break
        }

        return mapBillEntriesToChanges(allEntries)
    }

    private func mapBillEntriesToChanges(_ entries: [AssetBillEntryItemData]) -> [AssetChangeItemData] {
        var mappedChanges: [AssetChangeItemData] = []
        mappedChanges.reserveCapacity(entries.count)

        for (index, entry) in entries.enumerated() {
            let normalizedTradeNo = normalizedText(entry.tradeNo)
            let normalizedBizOrderNo = normalizedText(entry.bizOrderNo)
            let resolvedTradeNo = normalizedTradeNo
                ?? normalizedBizOrderNo
                ?? "BILL_\(normalizedText(entry.tradeTime) ?? "UNKNOWN_TIME")_\(index)"

            let rawAmount = normalizedText(entry.amount) ?? "0"
            let parsedAmount = decimalValue(rawAmount) ?? .zero
            let direction = normalizedBillEntryDirectionValue(entry.direction)
                ?? resolveBillEntryDirection(entry: entry, amount: parsedAmount)
            let normalizedAmountText = formatMoney(absolute(parsedAmount), useGrouping: false, forceSign: false)
            let displayTitle = normalizedText(entry.displayTitle)
                ?? normalizedText(entry.displaySubtitle)
                ?? "账单"
            let sceneCode = resolveBillEntrySceneCode(entry: entry)
            let tradeType = normalizedBillEntryTradeTypeValue(entry.tradeType)
                ?? resolveBillEntryTradeType(entry: entry, direction: direction)
            let occurredAt = normalizeOccurredAt(entry.tradeTime)
            let currencyCode = normalizedText(entry.currencyCode)?.uppercased() ?? "CNY"
            let couponDiscountAmount = normalizedText(entry.couponDiscountAmount)

            mappedChanges.append(
                AssetChangeItemData(
                    tradeNo: resolvedTradeNo,
                    tradeType: tradeType,
                    businessSceneCode: sceneCode,
                    direction: direction,
                    signedAmount: normalizedAmountText,
                    couponDiscountAmount: couponDiscountAmount,
                    currencyCode: currencyCode,
                    counterpartyUserId: nil,
                    counterpartyNickname: nil,
                    counterpartyAvatarUrl: nil,
                    displayTitle: displayTitle,
                    bankCode: nil,
                    bankName: nil,
                    bankCardTailNo: nil,
                    occurredAt: occurredAt
                )
            )
        }

        return mappedChanges
    }

    private func normalizedBillEntryDirectionValue(_ raw: String?) -> String? {
        let normalized = raw?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() ?? ""
        if normalized == "DEBIT" || normalized == "CREDIT" {
            return normalized
        }
        return nil
    }

    private func normalizedBillEntryTradeTypeValue(_ raw: String?) -> String? {
        let normalized = raw?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() ?? ""
        return normalized.isEmpty ? nil : normalized
    }

    private func resolveBillEntrySceneCode(entry: AssetBillEntryItemData) -> String {
        normalizedText(entry.businessType)
            ?? normalizedText(entry.productType)
            ?? normalizedText(entry.businessDomainCode)
            ?? "UNKNOWN"
    }

    private func resolveBillEntryTradeType(entry: AssetBillEntryItemData, direction: String) -> String {
        let normalizedBusinessType = (normalizedText(entry.businessType) ?? "").uppercased()
        let title = normalizedText(entry.displayTitle) ?? ""
        let normalizedTitle = title.uppercased()
        let normalizedSubtitle = (normalizedText(entry.displaySubtitle) ?? "").uppercased()
        let combined = "\(normalizedBusinessType) \(normalizedTitle) \(normalizedSubtitle)"

        if containsAny(combined, keywords: ["WITHDRAW"]) || title.contains("提现") {
            return "WITHDRAW"
        }
        if containsAny(combined, keywords: ["DEPOSIT"]) || (title.contains("充值") && !title.contains("话费")) {
            return "DEPOSIT"
        }
        if containsAny(combined, keywords: ["REFUND"]) || title.contains("退款") {
            return "REFUND"
        }
        if containsAny(combined, keywords: ["TRANSFER"]) || title.contains("转账") || title.contains("红包") {
            return "TRANSFER"
        }
        if containsAny(combined, keywords: ["LOAN"]) || title.contains("借款") || title.contains("放款") || title.contains("还款") {
            return "LOAN"
        }
        if containsAny(combined, keywords: ["FUND"]) || title.contains("爱存") {
            return "FUND"
        }
        if !normalizedBusinessType.isEmpty {
            return normalizedBusinessType
        }
        return direction == "CREDIT" ? "INCOME" : "PAY"
    }

    private func resolveBillEntryDirection(entry: AssetBillEntryItemData, amount: Decimal) -> String {
        if amount < .zero {
            return "DEBIT"
        }

        let normalizedBusinessType = (normalizedText(entry.businessType) ?? "").uppercased()
        let normalizedDomainCode = (normalizedText(entry.businessDomainCode) ?? "").uppercased()
        let title = normalizedText(entry.displayTitle) ?? ""
        let normalizedSubtitle = (normalizedText(entry.displaySubtitle) ?? "").uppercased()
        let combined = "\(normalizedBusinessType) \(title.uppercased()) \(normalizedSubtitle)"

        if containsAny(title, keywords: ["收到", "退款", "返还", "到账", "收益", "入账", "转入", "放款"])
            || containsAny(combined, keywords: ["TRANSFER_IN", "REFUND", "INCOME", "RECEIVE", "PROFIT", "YIELD", "DIVIDEND", "REDEEM"]) {
            return "CREDIT"
        }

        if (title.hasPrefix("向") && title.contains("转账"))
            || containsAny(title, keywords: ["还款", "支付", "消费", "扣款", "提现", "转出", "缴费", "话费充值"])
            || containsAny(combined, keywords: ["TRANSFER_OUT", "REPAY", "WITHDRAW", "PURCHASE", "CONSUME", "TOP_UP", "TOPUP", "CHARGE", "SUBSCRIBE"]) {
            return "DEBIT"
        }

        if title.contains("余额充值") || combined.contains("DEPOSIT") {
            return "CREDIT"
        }

        if normalizedDomainCode.contains("AILOAN") {
            if combined.contains("REPAY") || title.contains("还款") {
                return "DEBIT"
            }
            return "CREDIT"
        }

        let inferredTradeType = resolveBillEntryTradeType(entry: entry, direction: "DEBIT")
        if inferredTradeType == "DEPOSIT" || inferredTradeType == "REFUND" || inferredTradeType == "INCOME" {
            return "CREDIT"
        }
        return "DEBIT"
    }

    private func containsAny(_ source: String, keywords: [String]) -> Bool {
        for keyword in keywords where source.contains(keyword) {
            return true
        }
        return false
    }

    private func filterDuplicatedMobileTopUpOtherRows(_ rows: [BillRow]) -> [BillRow] {
        guard rows.count > 1 else {
            return rows
        }

        var normalizedRows = rows
        var removedIndexes = Set<Int>()
        for (index, row) in normalizedRows.enumerated() {
            guard isOtherCategoryBillRow(row) else {
                continue
            }
            guard row.isExpense else {
                continue
            }

            let preferredIndex = normalizedRows.indices.first { candidateIndex in
                guard candidateIndex != index, !removedIndexes.contains(candidateIndex) else {
                    return false
                }
                let candidate = normalizedRows[candidateIndex]
                guard isMobileTopUpBillRow(candidate) else {
                    return false
                }
                guard !isOtherCategoryBillRow(candidate) else {
                    return false
                }
                guard candidate.isExpense == row.isExpense else {
                    return false
                }
                guard belongsToSameMobileTopUpEvent(lhs: row, rhs: candidate) else {
                    return false
                }
                return isDuplicatedMobileTopUpCompanionAmount(otherRow: row, preferredRow: candidate)
            }

            if let preferredIndex {
                normalizedRows[preferredIndex] = mergeMobileTopUpPreferredRow(
                    preferredRow: normalizedRows[preferredIndex],
                    companionRow: row
                )
                removedIndexes.insert(index)
            }
        }

        guard !removedIndexes.isEmpty else {
            return normalizedRows
        }
        return normalizedRows.enumerated()
            .filter { !removedIndexes.contains($0.offset) }
            .map(\.element)
    }

    private func isOtherCategoryBillRow(_ row: BillRow) -> Bool {
        let normalizedCategory = row.categoryText.trimmingCharacters(in: .whitespacesAndNewlines)
        return normalizedCategory == "其他" || normalizedCategory == "其它"
    }

    private func isMobileTopUpBillRow(_ row: BillRow) -> Bool {
        let normalizedSceneCode = row.businessSceneCode.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let normalizedTradeType = row.tradeType.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let normalizedTitle = row.title.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()

        if normalizedSceneCode.contains("MOBILE_HALL_TOP_UP") || normalizedSceneCode.contains("APP_MOBILE") {
            return true
        }
        if normalizedTradeType.contains("MOBILE") || normalizedTradeType.contains("TOP_UP") || normalizedTradeType.contains("TOPUP") {
            return true
        }
        return normalizedTitle.contains("话费充值") || normalizedTitle.contains("MOBILE_HALL_TOP_UP")
    }

    private func belongsToSameMobileTopUpEvent(lhs: BillRow, rhs: BillRow) -> Bool {
        guard let lhsDate = parseOccurredAt(lhs.occurredAtRaw),
              let rhsDate = parseOccurredAt(rhs.occurredAtRaw) else {
            return false
        }
        guard abs(lhsDate.timeIntervalSince(rhsDate)) <= 300 else {
            return false
        }

        let lhsPhoneDigits = mobileTopUpPhoneDigits(from: lhs.title)
        let rhsPhoneDigits = mobileTopUpPhoneDigits(from: rhs.title)
        if let lhsPhoneDigits, let rhsPhoneDigits {
            return lhsPhoneDigits == rhsPhoneDigits
        }

        let lhsTitle = lhs.title.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let rhsTitle = rhs.title.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        guard !lhsTitle.isEmpty, !rhsTitle.isEmpty else {
            return false
        }
        return lhsTitle == rhsTitle
    }

    private func isDuplicatedMobileTopUpCompanionAmount(otherRow: BillRow, preferredRow: BillRow) -> Bool {
        let otherAmount = absolute(otherRow.signedAmountValue)
        let preferredAmount = absolute(preferredRow.signedAmountValue)
        if decimalsClose(otherAmount, preferredAmount) {
            return true
        }

        let preferredCoupon = max(preferredRow.couponDiscountAmount, .zero)
        if preferredCoupon > .zero,
           decimalsClose(otherAmount, preferredAmount + preferredCoupon) {
            return true
        }

        let otherCoupon = max(otherRow.couponDiscountAmount, .zero)
        if otherCoupon > .zero,
           decimalsClose(preferredAmount, otherAmount + otherCoupon) {
            return true
        }
        let amountDelta = absolute(otherAmount - preferredAmount)
        if amountDelta > .zero,
           amountDelta <= (Decimal(string: "100") ?? 100),
           isStrongMobileTopUpCompanionMatch(lhs: otherRow, rhs: preferredRow) {
            return true
        }
        return false
    }

    private func mobileTopUpPhoneDigits(from title: String) -> String? {
        let digits = title.filter(\.isNumber)
        guard digits.count >= 11 else {
            return nil
        }
        return String(digits.prefix(11))
    }

    private func isStrongMobileTopUpCompanionMatch(lhs: BillRow, rhs: BillRow) -> Bool {
        guard let lhsPhoneDigits = mobileTopUpPhoneDigits(from: lhs.title),
              let rhsPhoneDigits = mobileTopUpPhoneDigits(from: rhs.title),
              lhsPhoneDigits == rhsPhoneDigits else {
            return false
        }
        guard let lhsDate = parseOccurredAt(lhs.occurredAtRaw),
              let rhsDate = parseOccurredAt(rhs.occurredAtRaw) else {
            return false
        }
        return abs(lhsDate.timeIntervalSince(rhsDate)) <= 30
    }

    private func mergeMobileTopUpPreferredRow(preferredRow: BillRow, companionRow: BillRow) -> BillRow {
        let preferredCoupon = max(preferredRow.couponDiscountAmount, .zero)
        let companionCoupon = max(companionRow.couponDiscountAmount, .zero)
        var mergedCoupon = max(preferredCoupon, companionCoupon)
        if mergedCoupon <= .zero, isStrongMobileTopUpCompanionMatch(lhs: preferredRow, rhs: companionRow) {
            let preferredAmount = absolute(preferredRow.signedAmountValue)
            let companionAmount = absolute(companionRow.signedAmountValue)
            let amountDelta = absolute(companionAmount - preferredAmount)
            if amountDelta > .zero, amountDelta <= (Decimal(string: "100") ?? 100) {
                mergedCoupon = amountDelta
            }
        }
        if mergedCoupon <= preferredCoupon {
            return preferredRow
        }
        return BillRow(
            id: preferredRow.id,
            monthKey: preferredRow.monthKey,
            monthLabel: preferredRow.monthLabel,
            title: preferredRow.title,
            categoryText: preferredRow.categoryText,
            statusText: preferredRow.statusText,
            occurredAtRaw: preferredRow.occurredAtRaw,
            occurredAtText: preferredRow.occurredAtText,
            signedAmountValue: preferredRow.signedAmountValue,
            signedAmountText: preferredRow.signedAmountText,
            couponDiscountAmount: mergedCoupon,
            redPacketClaimPending: preferredRow.redPacketClaimPending,
            tradeType: preferredRow.tradeType,
            businessSceneCode: preferredRow.businessSceneCode,
            counterpartyName: preferredRow.counterpartyName,
            counterpartyAvatarUrl: preferredRow.counterpartyAvatarUrl,
            bankCode: preferredRow.bankCode,
            bankName: preferredRow.bankName
        )
    }

    private func mergedChanges(remote: [AssetChangeItemData]) -> [AssetChangeItemData] {
        let normalizedRemote = deduplicateRemoteRepeatedChanges(remote)
        return normalizedRemote.sorted { lhs, rhs in
            let leftDate = parseOccurredAt(lhs.occurredAt)
            let rightDate = parseOccurredAt(rhs.occurredAt)
            switch (leftDate, rightDate) {
            case let (l?, r?):
                return l > r
            case (.some, .none):
                return true
            case (.none, .some):
                return false
            default:
                return lhs.tradeNo > rhs.tradeNo
            }
        }
    }

    private func deduplicateRemoteRepeatedChanges(_ remote: [AssetChangeItemData]) -> [AssetChangeItemData] {
        guard !remote.isEmpty else {
            return remote
        }

        var seenTradeNos = Set<String>()
        var seenMobileTopUpSemanticKeys = Set<String>()
        var result: [AssetChangeItemData] = []
        result.reserveCapacity(remote.count)

        for change in remote {
            let normalizedTradeNo = change.tradeNo.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
            if !normalizedTradeNo.isEmpty, !seenTradeNos.insert(normalizedTradeNo).inserted {
                continue
            }

            if isDuplicateProneMobileTopUpChange(change) {
                let semanticKey = mobileTopUpSemanticDedupKey(change)
                if !seenMobileTopUpSemanticKeys.insert(semanticKey).inserted {
                    continue
                }
            }

            result.append(change)
        }

        return result
    }

    private func enrichMobileTopUpCouponDiscount(
        remote: [AssetChangeItemData],
        synthetic: [AssetChangeItemData]
    ) -> [AssetChangeItemData] {
        guard !remote.isEmpty, !synthetic.isEmpty else {
            return remote
        }

        var couponByTradeNo: [String: String] = [:]
        var couponBySemanticKey: [String: String] = [:]

        for syntheticChange in synthetic {
            guard isSpecificSyntheticMobileTopUpChange(syntheticChange) else {
                continue
            }
            guard let couponText = normalizedPositiveCouponText(from: syntheticChange) else {
                continue
            }

            let normalizedTradeNo = syntheticChange.tradeNo
                .trimmingCharacters(in: .whitespacesAndNewlines)
                .uppercased()
            if !normalizedTradeNo.isEmpty {
                couponByTradeNo[normalizedTradeNo] = couponText
            }

            let semanticKey = mobileTopUpCouponSemanticDedupKey(syntheticChange)
            if !semanticKey.isEmpty {
                couponBySemanticKey[semanticKey] = couponText
            }
        }

        guard !couponByTradeNo.isEmpty || !couponBySemanticKey.isEmpty else {
            return remote
        }

        return remote.map { remoteChange in
            guard isDuplicateProneMobileTopUpChange(remoteChange) else {
                return remoteChange
            }
            if normalizedPositiveCouponText(from: remoteChange) != nil {
                return remoteChange
            }

            let normalizedTradeNo = remoteChange.tradeNo
                .trimmingCharacters(in: .whitespacesAndNewlines)
                .uppercased()
            if !normalizedTradeNo.isEmpty, let couponText = couponByTradeNo[normalizedTradeNo] {
                return AssetChangeItemData(
                    tradeNo: remoteChange.tradeNo,
                    tradeType: remoteChange.tradeType,
                    businessSceneCode: remoteChange.businessSceneCode,
                    direction: remoteChange.direction,
                    signedAmount: remoteChange.signedAmount,
                    couponDiscountAmount: couponText,
                    currencyCode: remoteChange.currencyCode,
                    counterpartyUserId: remoteChange.counterpartyUserId,
                    counterpartyNickname: remoteChange.counterpartyNickname,
                    counterpartyAvatarUrl: remoteChange.counterpartyAvatarUrl,
                    displayTitle: remoteChange.displayTitle,
                    bankCode: remoteChange.bankCode,
                    bankName: remoteChange.bankName,
                    bankCardTailNo: remoteChange.bankCardTailNo,
                    occurredAt: remoteChange.occurredAt
                )
            }

            let semanticKey = mobileTopUpCouponSemanticDedupKey(remoteChange)
            if !semanticKey.isEmpty, let couponText = couponBySemanticKey[semanticKey] {
                return AssetChangeItemData(
                    tradeNo: remoteChange.tradeNo,
                    tradeType: remoteChange.tradeType,
                    businessSceneCode: remoteChange.businessSceneCode,
                    direction: remoteChange.direction,
                    signedAmount: remoteChange.signedAmount,
                    couponDiscountAmount: couponText,
                    currencyCode: remoteChange.currencyCode,
                    counterpartyUserId: remoteChange.counterpartyUserId,
                    counterpartyNickname: remoteChange.counterpartyNickname,
                    counterpartyAvatarUrl: remoteChange.counterpartyAvatarUrl,
                    displayTitle: remoteChange.displayTitle,
                    bankCode: remoteChange.bankCode,
                    bankName: remoteChange.bankName,
                    bankCardTailNo: remoteChange.bankCardTailNo,
                    occurredAt: remoteChange.occurredAt
                )
            }

            return remoteChange
        }
    }

    private func isDuplicateProneMobileTopUpChange(_ change: AssetChangeItemData) -> Bool {
        let sceneCode = normalizedSceneCode(change)
        if sceneCode.contains("MOBILE_HALL_TOP_UP") || sceneCode.contains("APP_MOBILE") {
            return true
        }
        let title = normalizeTitle(change.displayTitle).uppercased()
        return title.contains("话费充值") || title.contains("MOBILE_HALL_TOP_UP")
    }

    private func mobileTopUpSemanticDedupKey(_ change: AssetChangeItemData) -> String {
        let normalizedOccurredAt = normalizeOccurredAt(change.occurredAt)
        let occurredAtSecond = normalizedOccurredAt.count >= 19
            ? String(normalizedOccurredAt.prefix(19))
            : normalizedOccurredAt
        let normalizedDirection = normalizedDirection(change)
        let normalizedAmount = normalizedAbsoluteAmount(change)
            .map { formatMoney($0, useGrouping: false, forceSign: false) }
            ?? change.signedAmount.trimmingCharacters(in: .whitespacesAndNewlines)
        let normalizedTitle = normalizeTitle(change.displayTitle).uppercased()
        let digits = normalizedTitle.filter(\.isNumber)
        let phoneDigits = digits.count >= 11 ? String(digits.prefix(11)) : digits
        return [
            normalizedDirection,
            normalizedAmount,
            occurredAtSecond,
            phoneDigits,
            normalizedTitle
        ].joined(separator: "|")
    }

    private func mobileTopUpCouponSemanticDedupKey(_ change: AssetChangeItemData) -> String {
        let normalizedOccurredAt = normalizeOccurredAt(change.occurredAt)
        let occurredAtSecond = normalizedOccurredAt.count >= 19
            ? String(normalizedOccurredAt.prefix(19))
            : normalizedOccurredAt
        let normalizedDirection = normalizedDirection(change)
        let normalizedAmount = normalizedAbsoluteAmount(change)
            .map { formatMoney($0, useGrouping: false, forceSign: false) }
            ?? change.signedAmount.trimmingCharacters(in: .whitespacesAndNewlines)
        let normalizedTitle = normalizeTitle(change.displayTitle).uppercased()
        let digits = normalizedTitle.filter(\.isNumber)
        let phoneDigits = digits.count >= 11 ? String(digits.prefix(11)) : digits
        return [
            normalizedDirection,
            normalizedAmount,
            occurredAtSecond,
            phoneDigits
        ].joined(separator: "|")
    }

    private func normalizedPositiveCouponText(from change: AssetChangeItemData) -> String? {
        guard let rawCouponText = normalizedText(change.couponDiscountAmount) else {
            return nil
        }
        guard let parsedCoupon = decimalValue(rawCouponText), absolute(parsedCoupon) > .zero else {
            return nil
        }
        return formatMoney(absolute(parsedCoupon), useGrouping: false, forceSign: false)
    }

    private func filterDuplicatedGenericWithdrawChanges(
        remote: [AssetChangeItemData],
        synthetic: [AssetChangeItemData]
    ) -> [AssetChangeItemData] {
        let syntheticWithdraws = synthetic.filter { isSpecificSyntheticWithdrawChange($0) }
        guard !syntheticWithdraws.isEmpty else {
            return remote
        }

        var matchedSyntheticIndices = Set<Int>()
        return remote.enumerated().filter { _, remoteChange in
            guard isGenericRemoteWithdrawChange(remoteChange) else {
                return true
            }
            guard let remoteAmount = normalizedWithdrawAmount(remoteChange),
                  let remoteDate = parseOccurredAt(remoteChange.occurredAt) else {
                return true
            }

            for (syntheticIndex, syntheticChange) in syntheticWithdraws.enumerated() {
                if matchedSyntheticIndices.contains(syntheticIndex) {
                    continue
                }
                guard let syntheticAmount = normalizedWithdrawAmount(syntheticChange),
                      decimalsClose(remoteAmount, syntheticAmount),
                      let syntheticDate = parseOccurredAt(syntheticChange.occurredAt) else {
                    continue
                }

                let timeDelta = abs(remoteDate.timeIntervalSince(syntheticDate))
                if timeDelta <= 300 {
                    matchedSyntheticIndices.insert(syntheticIndex)
                    return false
                }
            }
            return true
        }.map(\.element)
    }

    private func filterDuplicatedGenericInternalTransferChanges(
        remote: [AssetChangeItemData],
        synthetic: [AssetChangeItemData]
    ) -> [AssetChangeItemData] {
        let syntheticTransfers = synthetic.filter { isSpecificSyntheticTransferChange($0) }
        guard !syntheticTransfers.isEmpty else {
            return remote
        }

        var matchedSyntheticIndices = Set<Int>()
        return remote.enumerated().filter { _, remoteChange in
            guard isGenericRemoteInternalTransferChange(remoteChange) else {
                return true
            }
            guard let remoteAmount = normalizedAbsoluteAmount(remoteChange),
                  let remoteDate = parseOccurredAt(remoteChange.occurredAt) else {
                return true
            }
            let remoteDirection = normalizedDirection(remoteChange)

            for (syntheticIndex, syntheticChange) in syntheticTransfers.enumerated() {
                if matchedSyntheticIndices.contains(syntheticIndex) {
                    continue
                }
                guard normalizedDirection(syntheticChange) == remoteDirection,
                      let syntheticAmount = normalizedAbsoluteAmount(syntheticChange),
                      decimalsClose(remoteAmount, syntheticAmount),
                      let syntheticDate = parseOccurredAt(syntheticChange.occurredAt) else {
                    continue
                }

                let timeDelta = abs(remoteDate.timeIntervalSince(syntheticDate))
                if timeDelta <= 300 {
                    matchedSyntheticIndices.insert(syntheticIndex)
                    return false
                }
            }
            return true
        }.map(\.element)
    }

    private func filterDuplicatedGenericMobileTopUpChanges(
        remote: [AssetChangeItemData],
        synthetic: [AssetChangeItemData]
    ) -> [AssetChangeItemData] {
        let syntheticTopUps = synthetic.filter { isSpecificSyntheticMobileTopUpChange($0) }
        guard !syntheticTopUps.isEmpty else {
            return remote
        }

        var matchedSyntheticIndices = Set<Int>()
        return remote.enumerated().filter { _, remoteChange in
            guard isGenericRemoteMobileTopUpChange(remoteChange) else {
                return true
            }
            guard let remoteAmount = normalizedAbsoluteAmount(remoteChange),
                  let remoteDate = parseOccurredAt(remoteChange.occurredAt) else {
                return true
            }
            let remoteDirection = normalizedDirection(remoteChange)

            for (syntheticIndex, syntheticChange) in syntheticTopUps.enumerated() {
                if matchedSyntheticIndices.contains(syntheticIndex) {
                    continue
                }
                guard normalizedDirection(syntheticChange) == remoteDirection,
                      let syntheticAmount = normalizedAbsoluteAmount(syntheticChange),
                      decimalsClose(remoteAmount, syntheticAmount),
                      let syntheticDate = parseOccurredAt(syntheticChange.occurredAt) else {
                    continue
                }

                let timeDelta = abs(remoteDate.timeIntervalSince(syntheticDate))
                if timeDelta <= 300 {
                    matchedSyntheticIndices.insert(syntheticIndex)
                    return false
                }
            }
            return true
        }.map(\.element)
    }

    private func isSpecificSyntheticWithdrawChange(_ change: AssetChangeItemData) -> Bool {
        let tradeNo = change.tradeNo.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        guard tradeNo.hasPrefix("LOCAL_WITHDRAW_") else {
            return false
        }
        return normalizeTitle(change.displayTitle).contains("提现到")
    }

    private func isSpecificSyntheticTransferChange(_ change: AssetChangeItemData) -> Bool {
        let tradeNo = change.tradeNo.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        guard tradeNo.hasPrefix("LOCAL_TRANSFER_") else {
            return false
        }
        let tradeType = normalizedTradeType(change)
        if tradeType.contains("TRANSFER") {
            return true
        }
        return normalizeTitle(change.displayTitle).contains("转账")
    }

    private func isSpecificSyntheticMobileTopUpChange(_ change: AssetChangeItemData) -> Bool {
        let sceneCode = normalizedSceneCode(change)
        guard sceneCode.contains("MOBILE_HALL_TOP_UP") else {
            return false
        }
        let title = normalizeTitle(change.displayTitle)
        return title.contains("话费充值")
    }

    private func isGenericRemoteWithdrawChange(_ change: AssetChangeItemData) -> Bool {
        let tradeNo = change.tradeNo.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        if tradeNo.hasPrefix("LOCAL_WITHDRAW_") {
            return false
        }
        guard isWithdrawChange(change) else {
            return false
        }
        let title = normalizeTitle(change.displayTitle)
        return title == "银行卡提现" || title == "余额提现" || title == "提现"
    }

    private func isGenericRemoteInternalTransferChange(_ change: AssetChangeItemData) -> Bool {
        let tradeNo = change.tradeNo.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        if tradeNo.hasPrefix("LOCAL_TRANSFER_") {
            return false
        }
        let normalizedTitle = normalizeTitle(change.displayTitle).uppercased()
        if tradeNo.hasPrefix("APP_INTERNAL") {
            return true
        }
        if normalizedTitle == "APP_INTERNAL_TRANSFER" || normalizedTitle == "APP_INTERNAL" {
            return true
        }
        return normalizedTitle.hasPrefix("APP_INTERNAL_")
    }

    private func isGenericRemoteMobileTopUpChange(_ change: AssetChangeItemData) -> Bool {
        let tradeNo = change.tradeNo.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        if tradeNo.hasPrefix("LOCAL_MOBILE_HALL_TOP_UP_") {
            return false
        }
        let sceneCode = normalizedSceneCode(change)
        guard sceneCode.contains("MOBILE_HALL_TOP_UP") else {
            return false
        }
        let title = normalizeTitle(change.displayTitle).uppercased()
        if title.hasPrefix("APP_MOBILE") {
            return true
        }
        if title.contains("MOBILE_HALL_TOP_UP") {
            return true
        }
        return false
    }

    private func isWithdrawChange(_ change: AssetChangeItemData) -> Bool {
        let tradeType = normalizedTradeType(change)
        if tradeType.contains("WITHDRAW") {
            return true
        }
        return normalizeTitle(change.displayTitle).contains("提现")
    }

    private func normalizedDirection(_ change: AssetChangeItemData) -> String {
        change.direction
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .uppercased()
    }

    private func normalizedWithdrawAmount(_ change: AssetChangeItemData) -> Decimal? {
        let signed = signedDecimalValue(amountText: change.signedAmount, direction: change.direction)
        return absolute(signed)
    }

    private func normalizedAbsoluteAmount(_ change: AssetChangeItemData) -> Decimal? {
        let signed = signedDecimalValue(amountText: change.signedAmount, direction: change.direction)
        return absolute(signed)
    }

    private func decimalsClose(_ lhs: Decimal, _ rhs: Decimal) -> Bool {
        let epsilon = Decimal(string: "0.005") ?? Decimal(0.005)
        return absolute(lhs - rhs) < epsilon
    }

    private func changeDedupKey(for change: AssetChangeItemData) -> String {
        let tradeNo = change.tradeNo.trimmingCharacters(in: .whitespacesAndNewlines)
        if !tradeNo.isEmpty {
            return tradeNo
        }
        return [
            change.tradeType.trimmingCharacters(in: .whitespacesAndNewlines),
            change.direction.trimmingCharacters(in: .whitespacesAndNewlines),
            change.signedAmount.trimmingCharacters(in: .whitespacesAndNewlines),
            change.occurredAt.trimmingCharacters(in: .whitespacesAndNewlines),
            change.displayTitle.trimmingCharacters(in: .whitespacesAndNewlines)
        ].joined(separator: "|")
    }

    private func resolveCounterpartyName(from change: AssetChangeItemData) -> String {
        if let nickname = normalizedText(change.counterpartyNickname) {
            return nickname
        }
        let title = normalizeTitle(change.displayTitle)
        if title.hasPrefix("向"), title.hasSuffix("转账"), title.count > 3 {
            let start = title.index(after: title.startIndex)
            let end = title.index(title.endIndex, offsetBy: -2)
            return String(title[start..<end])
        }
        if title.hasPrefix("收到"), title.hasSuffix("转账"), title.count > 4 {
            let start = title.index(title.startIndex, offsetBy: 2)
            let end = title.index(title.endIndex, offsetBy: -2)
            return String(title[start..<end])
        }
        if let fromRange = title.range(of: "来自"), let toRange = title.range(of: "的红包"), fromRange.upperBound < toRange.lowerBound {
            return String(title[fromRange.upperBound..<toRange.lowerBound])
        }
        return ""
    }

    private func resolveDisplayTitle(from change: AssetChangeItemData) -> String {
        if isAiCreditRepayChange(change) {
            return "爱花还款"
        }
        if isLoanRepayChange(change) {
            return "爱借还款"
        }
        if isLoanBorrowChange(change) {
            return resolveLoanBorrowDisplayTitle(from: change)
        }
        if isAiCashTransferInChange(change) {
            return aiCashSingleTransferInBillTitle
        }
        if isSentRedPacketChange(change) {
            return "发普通红包"
        }
        if isMobileHallTopUpChange(change) {
            return resolveMobileHallTopUpDisplayTitle(from: change)
        }
        let title = normalizeTitle(change.displayTitle)
        if let localizedTitle = localizedEnglishBillTitle(for: change, normalizedTitle: title) {
            return localizedTitle
        }
        if !title.isEmpty, title != "账单" {
            if looksLikeEnglishBillCode(title) {
                let signedValue = signedDecimalValue(amountText: change.signedAmount, direction: change.direction)
                return resolveCategoryText(from: change, signedValue: signedValue)
            }
            return title
        }
        let signedValue = signedDecimalValue(amountText: change.signedAmount, direction: change.direction)
        return resolveCategoryText(from: change, signedValue: signedValue)
    }

    private func resolveLoanBorrowDisplayTitle(from change: AssetChangeItemData) -> String {
        if let bankName = normalizedText(change.bankName) {
            let displayBankName = BankLogoCatalog.fullDisplayName(bankCode: change.bankCode, bankName: bankName)
            if !displayBankName.isEmpty, displayBankName != "银行卡" {
                return "爱借放款至\(displayBankName)"
            }
            return "爱借放款至\(bankName)"
        }
        if let bankCode = normalizedText(change.bankCode) {
            let displayBankName = BankLogoCatalog.fullDisplayName(bankCode: bankCode, bankName: nil)
            if !displayBankName.isEmpty, displayBankName != "银行卡" {
                return "爱借放款至\(displayBankName)"
            }
        }
        if let destination = resolveLoanBorrowDestinationFromDisplayText(change: change) {
            return "爱借放款至\(destination)"
        }
        return "爱借放款至余额"
    }

    private func resolveLoanBorrowDestinationFromDisplayText(change: AssetChangeItemData) -> String? {
        let candidates = [normalizeTitle(change.displayTitle)]
        for raw in candidates {
            let normalized = raw.trimmingCharacters(in: CharacterSet.whitespacesAndNewlines)
            if normalized.isEmpty {
                continue
            }
            if normalized.contains("余额") || normalized.uppercased().contains("WALLET") {
                return "余额"
            }
            var stripped = normalized
            while true {
                let next = stripped
                    .replacingOccurrences(of: "^爱借放款至", with: "", options: String.CompareOptions.regularExpression)
                    .replacingOccurrences(of: "^爱借放款到", with: "", options: String.CompareOptions.regularExpression)
                    .replacingOccurrences(of: "^爱借借款至", with: "", options: String.CompareOptions.regularExpression)
                    .replacingOccurrences(of: "^爱借借款到", with: "", options: String.CompareOptions.regularExpression)
                    .replacingOccurrences(of: "^放款至", with: "", options: String.CompareOptions.regularExpression)
                    .replacingOccurrences(of: "^放款到", with: "", options: String.CompareOptions.regularExpression)
                    .replacingOccurrences(of: "^借款至", with: "", options: String.CompareOptions.regularExpression)
                    .replacingOccurrences(of: "^借款到", with: "", options: String.CompareOptions.regularExpression)
                    .trimmingCharacters(in: CharacterSet.whitespacesAndNewlines)
                if next == stripped {
                    break
                }
                stripped = next
            }
            if stripped.isEmpty {
                continue
            }
            if stripped.contains("余额") || stripped.uppercased().contains("WALLET") {
                return "余额"
            }
            if stripped.contains("银行卡")
                || stripped.contains("银行")
                || stripped.contains("储蓄卡")
                || stripped.contains("借记卡")
                || stripped.contains("尾号") {
                if let bankName = extractBankNameForLoanBorrow(stripped) {
                    let displayBankName = BankLogoCatalog.fullDisplayName(bankCode: nil, bankName: bankName)
                    if !displayBankName.isEmpty, displayBankName != "银行卡" {
                        return displayBankName
                    }
                    return bankName
                }
                return "银行卡"
            }
        }
        return nil
    }

    private func extractBankNameForLoanBorrow(_ raw: String) -> String? {
        guard let regex = try? NSRegularExpression(pattern: "([A-Za-z0-9\\u4e00-\\u9fa5]{2,20}银行)") else {
            return nil
        }
        let nsRange = NSRange(raw.startIndex..<raw.endIndex, in: raw)
        let matches = regex.matches(in: raw, options: [], range: nsRange)
        let candidates: [String] = matches.compactMap { match in
            guard let range = Range(match.range(at: 1), in: raw) else {
                return nil
            }
            return String(raw[range]).trimmingCharacters(in: .whitespacesAndNewlines)
        }
        guard !candidates.isEmpty else {
            return nil
        }
        let resolved = candidates
            .sorted { $0.count > $1.count }
            .first { !$0.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty && $0 != "银行" }
        return resolved
    }

    private func localizedEnglishBillTitle(for change: AssetChangeItemData, normalizedTitle: String) -> String? {
        let code = normalizedTitle.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        guard !code.isEmpty else {
            return nil
        }

        switch code {
        case "APP_INTERNAL_TRANSFER", "APP_INTERNAL":
            let name = resolveCounterpartyName(from: change)
            if !name.isEmpty {
                return normalizedDirection(change) == "CREDIT" ? "收到\(name)转账" : "向\(name)转账"
            }
            return normalizedDirection(change) == "CREDIT" ? "转账收款" : "转账"
        case "APP_DEPOSIT":
            if let bankName = normalizedText(change.bankName) {
                return "余额充值-\(bankName)"
            }
            return "余额充值"
        case "APP_MOBILE_HALL_TOP_UP":
            return resolveMobileHallTopUpDisplayTitle(from: change)
        case "CHAT_RED_PACKET_SEND":
            return "发普通红包"
        case "CHAT_RED_PACKET_RECEIVE":
            return "收红包"
        case "FUND_SUBSCRIBE":
            return "爱存转入"
        case "FUND_REDEEM":
            return resolveAiCashRedeemDisplayTitle(from: change)
        case "FUND_FAST_REDEEM":
            return resolveAiCashRedeemDisplayTitle(from: change)
        case "FUND_PAY_FREEZE":
            return "爱存申购冻结"
        case "FUND_INCOME_SETTLE":
            return "爱存收益发放"
        case "APP_LOAN_ACCOUNT_CREDIT_REPAY":
            return "爱借还款"
        case "TRADE_PAY_LOAN_ACCOUNT":
            return "爱借借款"
        default:
            break
        }

        if code.hasPrefix("APP_MOBILE") || code.contains("MOBILE_HALL_TOP_UP") {
            return resolveMobileHallTopUpDisplayTitle(from: change)
        }

        if code.contains("RED_PACKET") {
            if code.contains("SEND") {
                return "发普通红包"
            }
            if code.contains("RECEIVE") {
                return "收红包"
            }
        }

        if code.contains("WITHDRAW") {
            if let bankName = normalizedText(change.bankName) {
                return "提现到\(bankName)"
            }
            if let tailNo = normalizedText(change.bankCardTailNo) {
                return "提现到尾号\(tailNo)"
            }
            return "银行卡提现"
        }

        if code.contains("DEPOSIT") || code.contains("RECHARGE") || code.contains("TOP_UP") || code.contains("TOPUP") {
            return "余额充值"
        }

        if code.contains("TRANSFER") {
            let name = resolveCounterpartyName(from: change)
            if !name.isEmpty {
                return normalizedDirection(change) == "CREDIT" ? "收到\(name)转账" : "向\(name)转账"
            }
            return normalizedDirection(change) == "CREDIT" ? "转账收款" : "转账"
        }

        if code.contains("REFUND") {
            return "退款"
        }

        if code.contains("FUND"), code.contains("INCOME") {
            return "爱存收益发放"
        }
        if code.contains("FUND"), code.contains("SUBSCRIBE") {
            return "爱存转入"
        }
        if code.contains("FUND"), code.contains("REDEEM") {
            return resolveAiCashRedeemDisplayTitle(from: change)
        }

        return nil
    }

    private func resolveAiCashRedeemDisplayTitle(from change: AssetChangeItemData) -> String {
        if let title = normalizedText(change.displayTitle) {
            let upperTitle = title.uppercased()
            if title.contains("余额") || upperTitle.contains("WALLET") {
                return "爱存转出至余额"
            }
        }
        if let bankName = normalizedText(change.bankName) {
            let normalizedBankName = normalizeAiCashRedeemBankName(bankName)
            let displayBankName = BankLogoCatalog.fullDisplayName(bankCode: change.bankCode, bankName: normalizedBankName)
            if !displayBankName.isEmpty, displayBankName != "银行卡" {
                return "爱存转出至\(displayBankName)"
            }
            return "爱存转出至\(normalizedBankName)"
        }
        return "爱存转出至余额"
    }

    private func normalizeAiCashRedeemBankName(_ raw: String) -> String {
        var stripped = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        while true {
            let next = stripped
                .replacingOccurrences(of: "^爱存转出至", with: "", options: .regularExpression)
                .replacingOccurrences(of: "^爱存转出到", with: "", options: .regularExpression)
                .replacingOccurrences(of: "^余额宝转出至", with: "", options: .regularExpression)
                .replacingOccurrences(of: "^余额宝转出到", with: "", options: .regularExpression)
                .replacingOccurrences(of: "^转出至", with: "", options: .regularExpression)
                .replacingOccurrences(of: "^转出到", with: "", options: .regularExpression)
                .replacingOccurrences(of: "^提现至", with: "", options: .regularExpression)
                .replacingOccurrences(of: "^提现到", with: "", options: .regularExpression)
                .trimmingCharacters(in: .whitespacesAndNewlines)
            if next == stripped {
                break
            }
            stripped = next
        }
        stripped = stripped
            .replacingOccurrences(of: "^[：:\\s]+", with: "", options: .regularExpression)
            .replacingOccurrences(of: "[：:\\s]+$", with: "", options: .regularExpression)
        if stripped.isEmpty || stripped == "银行" || stripped == "银行卡" {
            return raw.trimmingCharacters(in: .whitespacesAndNewlines)
        }
        return stripped
    }

    private func looksLikeEnglishBillCode(_ value: String) -> Bool {
        let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else {
            return false
        }
        if containsChineseCharacters(trimmed) {
            return false
        }
        return trimmed.range(of: "[A-Za-z]", options: .regularExpression) != nil
    }

    private func containsChineseCharacters(_ value: String) -> Bool {
        for scalar in value.unicodeScalars {
            if (0x4E00...0x9FFF).contains(Int(scalar.value)) {
                return true
            }
        }
        return false
    }

    private func isMobileHallTopUpChange(_ change: AssetChangeItemData) -> Bool {
        let sceneCode = change.businessSceneCode.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        return sceneCode.contains("MOBILE_HALL_TOP_UP")
    }

    private func resolveMobileHallTopUpDisplayTitle(from change: AssetChangeItemData) -> String {
        let title = normalizeTitle(change.displayTitle)
        if let maskedRange = title.range(of: "1[3-9][0-9]\\*{4}[0-9]{4}", options: .regularExpression) {
            let maskedPhone = String(title[maskedRange])
            return "为\(maskedPhone)话费充值"
        }
        let digitsInTitle = title.filter(\.isNumber)
        if digitsInTitle.count >= 11 {
            let phone = String(digitsInTitle.prefix(11))
            let masked = phone.prefix(3) + "****" + phone.suffix(4)
            return "为\(masked)话费充值"
        }
        if !title.isEmpty, title.contains("话费充值") {
            return title
        }
        return "话费充值"
    }

    private func resolveCategoryText(from change: AssetChangeItemData, signedValue: Decimal) -> String {
        let tradeType = change.tradeType.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let sceneCode = change.businessSceneCode.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let rawTitle = normalizeTitle(change.displayTitle).uppercased()
        let displayTitle = normalizeTitle(resolveDisplayTitle(from: change)).uppercased()

        if displayTitle.contains("发普通红包")
            || isSentRedPacketChange(change)
            || sceneCode.contains("RED_PACKET")
            || rawTitle.contains("红包")
            || displayTitle.contains("红包") {
            return "转账红包"
        }
        if displayTitle.contains("话费充值")
            || isMobileHallTopUpChange(change)
            || sceneCode.contains("MOBILE_HALL_TOP_UP")
            || sceneCode.contains("APP_MOBILE")
            || rawTitle.contains("话费充值") {
            return "充值缴费"
        }
        if isAiCreditRepayChange(change) || isLoanCreditChange(change) {
            return "信用借还"
        }
        if tradeType == "REFUND" || sceneCode.contains("REFUND") {
            return "退款"
        }
        if tradeType == "TRANSFER" || sceneCode.contains("TRANSFER") {
            return "转账"
        }
        if tradeType == "WITHDRAW" || sceneCode.contains("WITHDRAW") {
            return "提现"
        }
        if tradeType == "DEPOSIT"
            || sceneCode.contains("DEPOSIT")
            || sceneCode.contains("RECHARGE") {
            return "充值缴费"
        }
        if isAiCashTransferInChange(change)
            || sceneCode.contains("AICASH")
            || sceneCode.contains("AICASH")
            || sceneCode.contains("FUND")
            || tradeType.contains("FUND")
            || rawTitle.contains("爱存")
            || displayTitle.contains("爱存") {
            return "投资理财"
        }
        if rawTitle.contains("ICLOUD")
            || displayTitle.contains("ICLOUD")
            || sceneCode.contains("ENTERTAINMENT")
            || sceneCode.contains("CULTURE") {
            return "文化休闲"
        }
        if sceneCode.contains("FOOD") || sceneCode.contains("DINING") || sceneCode.contains("CATERING") {
            return "餐饮美食"
        }
        if sceneCode.contains("SHOP") || sceneCode.contains("ECOMMERCE") || sceneCode.contains("MALL") {
            return "网购"
        }
        if sceneCode.contains("QR") || sceneCode.contains("CODE") {
            return "二维码收款"
        }
        return signedValue < .zero ? "其他" : "收入"
    }

    private func resolveStatusText(from change: AssetChangeItemData) -> String {
        let title = normalizeTitle(change.displayTitle)
        if title.contains("自动扣款成功") {
            return "自动扣款成功"
        }
        return ""
    }

    private func shouldHideBillRow(_ row: BillRow) -> Bool {
        let normalizedSceneCode = row.businessSceneCode.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let normalizedTradeType = row.tradeType.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let normalizedTitle = row.title.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let normalizedCategory = row.categoryText.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()

        if normalizedSceneCode.contains("FUND_PAY_FREEZE") || normalizedTradeType.contains("FUND_PAY_FREEZE") {
            return true
        }
        if normalizedSceneCode.contains("PAY_FREEZE"),
           (normalizedSceneCode.contains("FUND") || normalizedSceneCode.contains("AICASH")) {
            return true
        }
        if normalizedTitle.contains("爱存申购冻结") || normalizedCategory.contains("申购冻结") {
            return true
        }
        return false
    }

    private func isSentRedPacketChange(_ change: AssetChangeItemData) -> Bool {
        let sceneCode = normalizedSceneCode(change)
        if sceneCode == "CHAT_RED_PACKET_SEND" || sceneCode.contains("RED_PACKET_SEND") {
            return true
        }
        let title = normalizeTitle(change.displayTitle).uppercased()
        if title.contains("发普通红包") || title.contains("发红包") {
            return true
        }
        return sceneCode.contains("RED_PACKET") && normalizedDirection(change) == "DEBIT"
    }

    private func isSentRedPacketClaimPending(_ change: AssetChangeItemData) -> Bool {
        guard isSentRedPacketChange(change) else {
            return false
        }
        guard let tradeNoKey = normalizedTradeNoKey(change.tradeNo),
              let normalizedStatus = normalizeRedPacketStatus(redPacketStatusByTradeNo[tradeNoKey]) else {
            return false
        }
        return normalizedStatus == "PENDING_CLAIM"
    }

    private func loadSentRedPacketStatusMap(
        for billChanges: [AssetChangeItemData],
        userId: String
    ) async -> [String: String] {
        guard let numericUserId = Int64(userId.trimmingCharacters(in: .whitespacesAndNewlines)),
              numericUserId > 0 else {
            return [:]
        }

        let currentYear = Calendar.current.component(.year, from: Date())
        let years = sentRedPacketHistoryYears(for: billChanges, fallbackYear: currentYear)
        guard !years.isEmpty else {
            return [:]
        }

        var statusByTradeNo: [String: String] = [:]
        for year in years {
            do {
                let history = try await APIClient.shared.fetchRedPacketHistory(
                    userId: numericUserId,
                    direction: "SENT",
                    year: year,
                    limit: 200
                )
                for item in history.items {
                    guard let tradeNoKey = normalizedTradeNoKey(item.tradeNo) else {
                        continue
                    }
                    if let normalizedStatus = normalizeRedPacketStatus(item.redPacketStatus)
                        ?? normalizeRedPacketStatus(item.messageStatus) {
                        statusByTradeNo[tradeNoKey] = normalizedStatus
                    }
                }
            } catch {
                if isCancellationLikeError(error) {
                    return statusByTradeNo
                }
            }
        }
        return statusByTradeNo
    }

    private func sentRedPacketHistoryYears(for billChanges: [AssetChangeItemData], fallbackYear: Int) -> [Int] {
        let years = Set(
            billChanges
                .filter { isSentRedPacketChange($0) }
                .compactMap { parseOccurredAt($0.occurredAt) }
                .map { Calendar.current.component(.year, from: $0) }
                .filter { $0 > 0 }
        )
        if years.isEmpty {
            return [fallbackYear]
        }
        return years.sorted(by: >)
    }

    private func normalizedTradeNoKey(_ raw: String?) -> String? {
        let normalized = raw?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() ?? ""
        return normalized.isEmpty ? nil : normalized
    }

    private func normalizeRedPacketStatus(_ raw: String?) -> String? {
        let normalized = raw?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() ?? ""
        return normalized.isEmpty ? nil : normalized
    }

    private func monthKeyText(_ date: Date?, raw: String) -> String {
        if let date {
            return Self.monthFormatter.string(from: date)
        }
        let normalized = normalizeOccurredAt(raw)
        if normalized.count >= 7 {
            return String(normalized.prefix(7))
        }
        return "0000-00"
    }

    private func monthLabelText(_ date: Date?, raw: String) -> String {
        if let date {
            return Self.monthLabelFormatter.string(from: date)
        }
        let normalized = normalizeOccurredAt(raw)
        if normalized.count >= 7 {
            let monthText = String(normalized.dropFirst(5).prefix(2))
            if let month = Int(monthText) {
                return "\(month)月"
            }
        }
        return "--"
    }

    private func shortOccurredAtText(_ date: Date?, raw: String) -> String {
        if let date {
            return Self.shortDateFormatter.string(from: date)
        }
        let normalized = normalizeOccurredAt(raw)
        if normalized.count >= 16 {
            let monthDay = String(normalized.dropFirst(5).prefix(5))
            let time = String(normalized.dropFirst(11).prefix(5))
            return "\(monthDay) \(time)"
        }
        return normalized
    }

    private func parseOccurredAt(_ raw: String) -> Date? {
        let trimmed = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else {
            return nil
        }
        let normalized = trimmed.replacingOccurrences(of: "T", with: " ").replacingOccurrences(of: "Z", with: "")
        if let parsed = Self.fullDateFormatter.date(from: normalized) {
            return parsed
        }
        if let parsed = Self.slashDateFormatter.date(from: normalized) {
            return parsed
        }
        if let parsed = Self.fallbackDateFormatter.date(from: trimmed) {
            return parsed
        }
        return nil
    }

    private func normalizeTitle(_ value: String) -> String {
        let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
        return trimmed.isEmpty ? "账单" : AppBranding.displayText(trimmed)
    }

    private func normalizeOccurredAt(_ value: String) -> String {
        let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
        if trimmed.isEmpty {
            return "--"
        }
        let normalized = trimmed.replacingOccurrences(of: "T", with: " ")
        let strippedFraction = normalized.split(separator: ".").first.map(String.init) ?? normalized
        if strippedFraction.count >= 19 {
            return String(strippedFraction.prefix(19))
        }
        return strippedFraction
    }

    private func normalizedBillSignedAmount(for change: AssetChangeItemData) -> Decimal {
        let signedValue = signedDecimalValue(amountText: change.signedAmount, direction: change.direction)
        if isAiCreditRepayChange(change) || isLoanCreditChange(change) || isAiCashSingleTransferInBillChange(change) {
            return absolute(signedValue)
        }
        return signedValue
    }

    private func normalizedCouponDiscountAmount(for change: AssetChangeItemData) -> Decimal {
        guard let raw = change.couponDiscountAmount else {
            return .zero
        }
        return absolute(decimalValue(raw) ?? .zero)
    }

    private func isAiCashSingleTransferInBillChange(_ change: AssetChangeItemData) -> Bool {
        if isAiCashTransferInChange(change) {
            return true
        }
        let normalizedTitle = normalizeTitle(change.displayTitle)
        if normalizedTitle == aiCashSingleTransferInBillTitle {
            return true
        }
        return normalizedTitle.contains("爱存") && normalizedTitle.contains("单次转入")
    }

    private func isLoanCreditChange(_ change: AssetChangeItemData) -> Bool {
        isLoanBorrowChange(change) || isLoanRepayChange(change)
    }

    private func isAiCreditRepayChange(_ change: AssetChangeItemData) -> Bool {
        let sceneCode = normalizedSceneCode(change)
        let tradeType = normalizedTradeType(change)
        let title = normalizeTitle(change.displayTitle)
        if sceneCode == "APP_CREDIT_REPAY"
            || sceneCode.contains("AICREDIT_REPAY")
            || (sceneCode.contains("CREDIT") && sceneCode.contains("REPAY")) {
            return true
        }
        if tradeType.contains("REPAY"), sceneCode.contains("CREDIT") {
            return true
        }
        if title.contains("爱花还款") {
            return true
        }
        if title.contains("爱花"), title.contains("还款") {
            return true
        }
        return false
    }

    private func isLoanBorrowChange(_ change: AssetChangeItemData) -> Bool {
        let sceneCode = normalizedSceneCode(change)
        let tradeType = normalizedTradeType(change)
        let title = normalizeTitle(change.displayTitle)
        if sceneCode.contains("TRADE_PAY_LOAN_ACCOUNT") {
            return true
        }
        if sceneCode.contains("LOAN_ACCOUNT"), !sceneCode.contains("REPAY") {
            return true
        }
        if tradeType.contains("LOAN"), !sceneCode.contains("REPAY"), !title.contains("还款") {
            return true
        }
        return title.contains("爱借放款") || title.contains("爱借借款")
    }

    private func isLoanRepayChange(_ change: AssetChangeItemData) -> Bool {
        let sceneCode = normalizedSceneCode(change)
        let tradeType = normalizedTradeType(change)
        let title = normalizeTitle(change.displayTitle)
        if sceneCode.contains("APP_LOAN_ACCOUNT_CREDIT_REPAY")
            || (sceneCode.contains("LOAN_ACCOUNT") && sceneCode.contains("REPAY")) {
            return true
        }
        if tradeType.contains("LOAN"), sceneCode.contains("REPAY") {
            return true
        }
        if title.contains("爱借还款") {
            return true
        }
        return title.contains("爱借") && title.contains("还款")
    }

    private func normalizedSceneCode(_ change: AssetChangeItemData) -> String {
        change.businessSceneCode
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .uppercased()
    }

    private func normalizedTradeType(_ change: AssetChangeItemData) -> String {
        change.tradeType
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .uppercased()
    }

    private func signedDecimalValue(amountText: String, direction: String) -> Decimal {
        guard let parsed = decimalValue(amountText) else {
            return Decimal.zero
        }
        if parsed < 0 {
            return parsed
        }
        if direction.uppercased() == "DEBIT" {
            return -parsed
        }
        return parsed
    }

    private func decimalValue(_ value: String?) -> Decimal? {
        let trimmed = value?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !trimmed.isEmpty else {
            return nil
        }
        let normalized = trimmed
            .replacingOccurrences(of: ",", with: "")
            .replacingOccurrences(of: "＋", with: "+")
            .replacingOccurrences(of: "－", with: "-")
        return Decimal(string: normalized)
    }

    private func normalizedText(_ raw: String?) -> String? {
        let trimmed = raw?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        return trimmed.isEmpty ? nil : trimmed
    }

    private func normalizedURLText(_ raw: String?) -> String? {
        let trimmed = raw?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !trimmed.isEmpty else {
            return nil
        }
        guard trimmed.hasPrefix("http://") || trimmed.hasPrefix("https://") else {
            return nil
        }
        return trimmed
    }

    private func absolute(_ value: Decimal) -> Decimal {
        value < .zero ? -value : value
    }

    private func avatarText(for name: String, fallback: String) -> String {
        let trimmedName = name.trimmingCharacters(in: .whitespacesAndNewlines)
        if let first = trimmedName.first {
            return String(first)
        }
        let trimmedFallback = fallback.trimmingCharacters(in: .whitespacesAndNewlines)
        if let first = trimmedFallback.first {
            return String(first)
        }
        return "账"
    }

    private func avatarColor(seed: Int64) -> Color {
        let palette: [Color] = [
            Color(red: 0.98, green: 0.45, blue: 0.29),
            AppTheme.palette.brandPrimaryLight,
            Color(red: 0.35, green: 0.74, blue: 0.52),
            AppTheme.palette.brandPrimaryLight,
            Color(red: 0.96, green: 0.71, blue: 0.21),
            Color(red: 0.22, green: 0.71, blue: 0.75)
        ]
        let index = Int(abs(seed) % Int64(palette.count))
        return palette[index]
    }

    private func formatSignedMoney(_ value: Decimal) -> String {
        formatMoney(value, useGrouping: false, forceSign: false)
    }

    private func formatMoney(_ value: Decimal, useGrouping: Bool, forceSign: Bool) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = useGrouping
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        let number = NSDecimalNumber(decimal: absolute(value))
        if let text = formatter.string(from: number) {
            if value < .zero {
                return "-" + text
            }
            return forceSign && value > .zero ? "+" + text : text
        }
        let raw = number.stringValue
        if value < .zero {
            return "-" + raw
        }
        return forceSign && value > .zero ? "+" + raw : raw
    }
}

private struct TotalAssetView: View {
    let totalAssetAmount: Decimal?
    let yesterdayIncome: Decimal?
    let queryErrorMessage: String?
    let isQuerying: Bool
    let onBack: () -> Void

    private let baseWidth: CGFloat = 402
    private let baseHeight: CGFloat = 874
    @State private var isAmountMasked = false

    var body: some View {
        GeometryReader { proxy in
            let scaleX = proxy.size.width / baseWidth
            let scaleY = proxy.size.height / baseHeight
            let fontScale = min(scaleX, scaleY)
            let normalizedQueryErrorMessage = queryErrorMessage?
                .trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            let isAssetQueryFailed = !normalizedQueryErrorMessage.isEmpty
            let isAssetQuerying = isQuerying || (!isAssetQueryFailed && totalAssetAmount == nil)
            let shouldShowPlaceholder = isAssetQuerying || isAssetQueryFailed
            let displayedTotalAssetAmount: Decimal? = shouldShowPlaceholder ? nil : totalAssetAmount
            let displayedYesterdayIncome: Decimal? = shouldShowPlaceholder ? nil : yesterdayIncome

            ZStack {
                Image("TotalAssetReference")
                    .resizable()
                    .interpolation(.high)
                    .aspectRatio(contentMode: .fill)
                    .frame(width: proxy.size.width, height: proxy.size.height)
                    .clipped()

                topStatusCleanupOverlay(scaleX: scaleX, scaleY: scaleY)
                headerTitleTextOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                headerBackArrowOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)

                totalAssetAmountOverlay(
                    amount: displayedTotalAssetAmount,
                    scaleX: scaleX,
                    scaleY: scaleY,
                    fontScale: fontScale
                )
                yesterdayIncomeOverlay(
                    amount: displayedYesterdayIncome,
                    scaleX: scaleX,
                    scaleY: scaleY,
                    fontScale: fontScale
                )
                activeAssetAmountOverlay(
                    amount: displayedTotalAssetAmount,
                    scaleX: scaleX,
                    scaleY: scaleY,
                    fontScale: fontScale
                )
                activeAssetYesterdayIncomeOverlay(
                    amount: displayedYesterdayIncome,
                    scaleX: scaleX,
                    scaleY: scaleY,
                    fontScale: fontScale
                )
                familyProtectionCountOverlay(
                    scaleX: scaleX,
                    scaleY: scaleY,
                    fontScale: fontScale
                )

                if isAssetQuerying {
                    assetQueryingOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                } else if isAssetQueryFailed {
                    assetQueryFailedOverlay(
                        message: normalizedQueryErrorMessage,
                        scaleX: scaleX,
                        scaleY: scaleY,
                        fontScale: fontScale
                    )
                }

                actionHotspot(
                    identifier: "total_asset_visibility_toggle",
                    centerX: 126 * scaleX,
                    centerY: 199 * scaleY,
                    width: 36 * scaleX,
                    height: 24 * scaleY,
                    action: {
                        isAmountMasked.toggle()
