                )

                actionHotspot(
                    identifier: "total_asset_back_button",
                    centerX: 22 * scaleX,
                    centerY: 77 * scaleY,
                    width: 56 * scaleX,
                    height: 48 * scaleY,
                    action: onBack
                )
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
    }

