    private func actionHotspot(
        identifier: String,
        centerX: CGFloat,
        centerY: CGFloat,
        width: CGFloat,
        height: CGFloat,
        action: @escaping () -> Void
    ) -> some View {
        Color.clear
            .frame(width: width, height: height)
            .contentShape(Rectangle())
            .position(x: centerX, y: centerY)
            .highPriorityGesture(
                TapGesture().onEnded {
                    action()
                }
            )
            .accessibilityIdentifier(identifier)
    }

    private func formatAmount(_ value: Decimal?) -> String {
        guard let value else {
            return "--"
        }
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = true
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSDecimalNumber(decimal: max(value, .zero))) ?? "--"
    }

    private func formatSignedAmount(_ value: Decimal?) -> String {
        guard let value else {
            return "--"
        }
        let absoluteAmount = abs(value)
        let formatted = formatAmount(absoluteAmount)
        if value > .zero {
            return "+" + formatted
        }
        if value < .zero {
            return "-" + formatted
        }
        return formatted
    }

    private func formatIncomeAmount(_ value: Decimal?) -> String {
        guard let value else {
            return "--"
        }
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = true
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        let absoluteAmount = abs(value)
        let text = formatter.string(from: NSDecimalNumber(decimal: absoluteAmount)) ?? "--"
        return value < .zero ? "-" + text : text
    }

    private func assetIncomeColor(_ value: Decimal?) -> Color {
        guard let value else {
            return Color(red: 0.64, green: 0.66, blue: 0.70)
        }
        if value > .zero {
            return Color(red: 230.0 / 255.0, green: 49.0 / 255.0, blue: 64.0 / 255.0)
        }
        if value < .zero {
            return Color(red: 17.0 / 255.0, green: 154.0 / 255.0, blue: 120.0 / 255.0)
        }
        return Color(red: 0.64, green: 0.66, blue: 0.70)
    }
}

private struct AiCashIncomeDetailItem: Identifiable {
    let id: String
    let dateText: String
    let incomePer10k: Decimal
    let dailyIncome: Decimal
}

private struct AiCashAccountSnapshot {
    var principalAmount: Decimal
    var totalAmount: Decimal
    var hasTotalAmount: Bool
    var yesterdayIncome: Decimal
    var hasYesterdayIncome: Bool
    var cumulativeIncome: Decimal
    var hasCumulativeIncome: Bool
    var annualizedYieldRate: Decimal
    var hasAnnualizedYieldRate: Bool
    var incomePer10k: Decimal
    var hasIncomePer10k: Bool
    var lastSettledDateKey: String
    var backingHoldingAmount: Decimal

    private static let posixLocale = Locale(identifier: "en_US_POSIX")
    private static let dayFormatter: DateFormatter = {
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.calendar = Calendar(identifier: .gregorian)
        formatter.dateFormat = "yyyy-MM-dd"
        return formatter
    }()
    private static let detailDateFormatter: DateFormatter = {
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "zh_CN")
        formatter.calendar = Calendar(identifier: .gregorian)
        formatter.dateFormat = "M月d日"
        return formatter
    }()

    // Recent public references for Huaxia Salary Treasure cluster around 1.04%.
    static let defaultAnnualizedYieldRate = decimal("0.01045")
    private static let bootstrappedHoldingDays = 30

    var annualizedYieldDisplayText: String {
        hasAnnualizedYieldRate ? Self.percentText(for: annualizedYieldRate) : "-"
    }

    var hasDisplayableIncomeData: Bool {
        hasTotalAmount && hasYesterdayIncome && hasCumulativeIncome && hasIncomePer10k && !lastSettledDateKey.isEmpty
    }

    var latestIncomePer10k: Decimal {
        Self.roundMetric(max(incomePer10k, .zero))
    }

    var recent30DayIncome: Decimal {
        recentIncomeDetails(limit: 30)
            .map(\.dailyIncome)
            .reduce(.zero, +)
    }

    static func empty() -> AiCashAccountSnapshot {
        AiCashAccountSnapshot(
            principalAmount: .zero,
            totalAmount: .zero,
            hasTotalAmount: false,
            yesterdayIncome: .zero,
            hasYesterdayIncome: false,
            cumulativeIncome: .zero,
            hasCumulativeIncome: false,
            annualizedYieldRate: defaultAnnualizedYieldRate,
            hasAnnualizedYieldRate: false,
            incomePer10k: .zero,
            hasIncomePer10k: false,
            lastSettledDateKey: "",
            backingHoldingAmount: .zero
        )
    }

    static func resolved(account: FundAccountData, userId: Int64, now: Date = Date()) -> AiCashAccountSnapshot {
        let todayKey = dayKey(for: now)
        let holdingAmount = roundCurrency(max(account.holdingAmount, .zero))
        let annualizedYieldRate = normalizedAnnualizedYieldRate(account.annualizedYieldRate)
        let incomePer10k = roundMetric(max(account.incomePer10k, .zero))
        var snapshot = AiCashSyntheticSnapshotStore.load(userId: userId)
            ?? seed(
                from: account,
                holdingAmount: holdingAmount,
                annualizedYieldRate: annualizedYieldRate,
                incomePer10k: incomePer10k,
                settledDateKey: todayKey
            )

        snapshot.annualizedYieldRate = annualizedYieldRate
        snapshot.hasAnnualizedYieldRate = account.hasAnnualizedYieldRate
        snapshot.incomePer10k = incomePer10k
        snapshot.hasIncomePer10k = account.hasIncomePer10k
        snapshot.hasYesterdayIncome = account.hasYesterdayIncome
        snapshot.hasCumulativeIncome = account.hasAccumulatedIncome
        snapshot = snapshot.syncingHoldingAmount(holdingAmount, hasTotalAmount: account.hasHoldingAmount)
        snapshot = snapshot.applyingDailySettlement(until: todayKey)
        AiCashSyntheticSnapshotStore.save(snapshot, userId: userId)
        return snapshot
    }

    static func resolvedFromPersistedState(userId: Int64, annualizedYieldRate: Decimal? = nil, now: Date = Date()) -> AiCashAccountSnapshot? {
        guard var snapshot = AiCashSyntheticSnapshotStore.load(userId: userId) else {
            return nil
        }
        snapshot.annualizedYieldRate = normalizedAnnualizedYieldRate(annualizedYieldRate ?? snapshot.annualizedYieldRate)
        snapshot = snapshot.applyingDailySettlement(until: dayKey(for: now))
        AiCashSyntheticSnapshotStore.save(snapshot, userId: userId)
        return snapshot
    }

    func recentIncomeDetails(limit: Int) -> [AiCashIncomeDetailItem] {
        let normalizedLimit = max(limit, 0)
        guard normalizedLimit > 0, hasDisplayableIncomeData else {
            return []
        }

        let calendar = Calendar(identifier: .gregorian)
        let referenceSettlementDate = Self.date(fromDayKey: lastSettledDateKey) ?? Date()
        guard let latestIncomeDate = calendar.date(byAdding: .day, value: -1, to: referenceSettlementDate) else {
            return []
        }

        var endingBalance = totalAmount
        var rows: [AiCashIncomeDetailItem] = []
        rows.reserveCapacity(normalizedLimit)

        for offset in 0..<normalizedLimit {
            guard let incomeDate = calendar.date(byAdding: .day, value: -offset, to: latestIncomeDate) else {
                continue
            }
            let incomePer10k = offset == 0
                ? latestIncomePer10k
                : Self.displayIncomePer10k(base: latestIncomePer10k, dayOffset: offset)
            let growthFactor = Decimal(1) + Self.dividing(incomePer10k, by: Decimal(10_000))
            let estimatedIncome = Self.roundCurrency(max(endingBalance - Self.dividing(endingBalance, by: growthFactor), .zero))
            let dailyIncome = offset == 0 && yesterdayIncome > .zero
                ? Self.roundCurrency(yesterdayIncome)
                : estimatedIncome
            // 无持有份额（对应金额为 0）且无收益的日期不展示在“每日收益明细”中。
            let hasHoldingOnIncomeDate = endingBalance > .zero || dailyIncome > .zero
            if hasHoldingOnIncomeDate {
                rows.append(
                    AiCashIncomeDetailItem(
                        id: Self.dayKey(for: incomeDate),
                        dateText: Self.detailDateFormatter.string(from: incomeDate),
                        incomePer10k: incomePer10k,
                        dailyIncome: dailyIncome
                    )
                )
            }
            endingBalance = Self.roundCurrency(max(endingBalance - dailyIncome, .zero))
        }
        return rows
    }

    private static func seed(
        from account: FundAccountData,
        holdingAmount: Decimal,
        annualizedYieldRate: Decimal,
        incomePer10k: Decimal,
        settledDateKey: String
    ) -> AiCashAccountSnapshot {
        let seededCumulativeIncome = roundCurrency(max(account.accumulatedIncome, .zero))
        let seededYesterdayIncome = roundCurrency(max(account.yesterdayIncome, .zero))

        if seededCumulativeIncome > .zero || seededYesterdayIncome > .zero {
            return AiCashAccountSnapshot(
                principalAmount: roundCurrency(max(holdingAmount - seededCumulativeIncome, .zero)),
                totalAmount: holdingAmount,
                hasTotalAmount: account.hasHoldingAmount,
                yesterdayIncome: seededYesterdayIncome,
                hasYesterdayIncome: account.hasYesterdayIncome,
                cumulativeIncome: seededCumulativeIncome,
                hasCumulativeIncome: account.hasAccumulatedIncome,
                annualizedYieldRate: annualizedYieldRate,
                hasAnnualizedYieldRate: account.hasAnnualizedYieldRate,
                incomePer10k: incomePer10k,
                hasIncomePer10k: account.hasIncomePer10k,
                lastSettledDateKey: settledDateKey,
                backingHoldingAmount: holdingAmount
            )
        }

        let growthFactor = dailyGrowthFactor(for: annualizedYieldRate)
        let bootstrappedPrincipal = roundCurrency(dividing(holdingAmount, by: power(growthFactor, exponent: bootstrappedHoldingDays)))
        let bootstrappedCumulativeIncome = roundCurrency(max(holdingAmount - bootstrappedPrincipal, .zero))
        let previousDayTotal = dividing(holdingAmount, by: growthFactor)
        let bootstrappedYesterdayIncome = roundCurrency(max(holdingAmount - previousDayTotal, .zero))

        return AiCashAccountSnapshot(
            principalAmount: bootstrappedPrincipal,
            totalAmount: holdingAmount,
            hasTotalAmount: account.hasHoldingAmount,
            yesterdayIncome: bootstrappedYesterdayIncome,
            hasYesterdayIncome: account.hasYesterdayIncome,
            cumulativeIncome: bootstrappedCumulativeIncome,
            hasCumulativeIncome: account.hasAccumulatedIncome,
            annualizedYieldRate: annualizedYieldRate,
            hasAnnualizedYieldRate: account.hasAnnualizedYieldRate,
            incomePer10k: incomePer10k,
            hasIncomePer10k: account.hasIncomePer10k,
            lastSettledDateKey: settledDateKey,
            backingHoldingAmount: holdingAmount
        )
    }

    func syncingHoldingAmount(_ holdingAmount: Decimal, hasTotalAmount: Bool? = nil) -> AiCashAccountSnapshot {
        let normalizedHoldingAmount = Self.roundCurrency(max(holdingAmount, .zero))
        let delta = Self.roundCurrency(normalizedHoldingAmount - backingHoldingAmount)
        guard delta != .zero else {
            var snapshot = self
            snapshot.backingHoldingAmount = normalizedHoldingAmount
            if let hasTotalAmount {
                snapshot.hasTotalAmount = hasTotalAmount
            }
            return snapshot
        }

        var snapshot = self
        snapshot.principalAmount = Self.roundCurrency(max(snapshot.principalAmount + delta, .zero))
        snapshot.totalAmount = Self.roundCurrency(max(snapshot.totalAmount + delta, .zero))
        snapshot.backingHoldingAmount = normalizedHoldingAmount
        if let hasTotalAmount {
            snapshot.hasTotalAmount = hasTotalAmount
        }
        return snapshot
    }

    func applyingDailySettlement(until targetDateKey: String) -> AiCashAccountSnapshot {
        guard !targetDateKey.isEmpty else {
            return self
        }

        var snapshot = self
        if snapshot.lastSettledDateKey.isEmpty {
            snapshot.lastSettledDateKey = targetDateKey
            return snapshot
        }
        guard let targetDate = Self.date(fromDayKey: targetDateKey),
              let currentSettledDate = Self.date(fromDayKey: snapshot.lastSettledDateKey),
              targetDate > currentSettledDate else {
            return snapshot
        }

        let calendar = Calendar(identifier: .gregorian)
        var cursor = currentSettledDate
        while let nextDate = calendar.date(byAdding: .day, value: 1, to: cursor), nextDate <= targetDate {
            let dailyIncome = Self.roundCurrency(max(snapshot.totalAmount * Self.dailyRate(for: snapshot.annualizedYieldRate), .zero))
            snapshot.totalAmount = Self.roundCurrency(snapshot.totalAmount + dailyIncome)
            snapshot.cumulativeIncome = Self.roundCurrency(snapshot.cumulativeIncome + dailyIncome)
            snapshot.yesterdayIncome = dailyIncome
            snapshot.lastSettledDateKey = Self.dayKey(for: nextDate)
            cursor = nextDate
        }
        return snapshot
    }

    func applyingTransferIn(_ amount: Decimal) -> AiCashAccountSnapshot {
        let normalizedAmount = Self.roundCurrency(max(amount, .zero))
        guard normalizedAmount > .zero else {
            return self
        }

        var snapshot = self
        snapshot.principalAmount = Self.roundCurrency(snapshot.principalAmount + normalizedAmount)
        snapshot.totalAmount = Self.roundCurrency(snapshot.totalAmount + normalizedAmount)
        snapshot.backingHoldingAmount = Self.roundCurrency(snapshot.backingHoldingAmount + normalizedAmount)
        return snapshot
    }

    func applyingTransferOut(_ amount: Decimal) -> AiCashAccountSnapshot {
        let normalizedAmount = Self.roundCurrency(max(amount, .zero))
        guard normalizedAmount > .zero else {
            return self
        }

        var snapshot = self
        snapshot.principalAmount = Self.roundCurrency(max(snapshot.principalAmount - normalizedAmount, .zero))
        snapshot.totalAmount = Self.roundCurrency(max(snapshot.totalAmount - normalizedAmount, .zero))
        snapshot.backingHoldingAmount = Self.roundCurrency(max(snapshot.backingHoldingAmount - normalizedAmount, .zero))
        return snapshot
    }

    private static func normalizedAnnualizedYieldRate(_ source: Decimal) -> Decimal {
        roundRate(source > .zero ? source : defaultAnnualizedYieldRate)
    }

    private static func dayKey(for date: Date) -> String {
        dayFormatter.string(from: date)
    }

    private static func date(fromDayKey key: String) -> Date? {
        dayFormatter.date(from: key)
    }

    private static func dailyRate(for annualizedYieldRate: Decimal) -> Decimal {
        dividing(max(annualizedYieldRate, .zero), by: Decimal(365))
    }

    private static func dailyGrowthFactor(for annualizedYieldRate: Decimal) -> Decimal {
        Decimal(1) + dailyRate(for: annualizedYieldRate)
    }

    private static func power(_ base: Decimal, exponent: Int) -> Decimal {
        let value = pow(NSDecimalNumber(decimal: base).doubleValue, Double(max(exponent, 0)))
        return Decimal(string: String(format: "%.12f", value), locale: posixLocale) ?? Decimal(1)
    }

    private static func dividing(_ dividend: Decimal, by divisor: Decimal) -> Decimal {
        guard divisor != .zero else {
            return .zero
        }
        let number = NSDecimalNumber(decimal: dividend)
        let denominator = NSDecimalNumber(decimal: divisor)
        let handler = NSDecimalNumberHandler(
            roundingMode: .plain,
            scale: 8,
            raiseOnExactness: false,
            raiseOnOverflow: false,
            raiseOnUnderflow: false,
            raiseOnDivideByZero: false
        )
        return number.dividing(by: denominator, withBehavior: handler).decimalValue
    }

    private static func roundCurrency(_ value: Decimal) -> Decimal {
        let handler = NSDecimalNumberHandler(
            roundingMode: .plain,
            scale: 2,
            raiseOnExactness: false,
            raiseOnOverflow: false,
            raiseOnUnderflow: false,
            raiseOnDivideByZero: false
        )
        return NSDecimalNumber(decimal: value).rounding(accordingToBehavior: handler).decimalValue
    }

    private static func roundMetric(_ value: Decimal) -> Decimal {
        let handler = NSDecimalNumberHandler(
            roundingMode: .plain,
            scale: 4,
            raiseOnExactness: false,
            raiseOnOverflow: false,
            raiseOnUnderflow: false,
            raiseOnDivideByZero: false
        )
        return NSDecimalNumber(decimal: value).rounding(accordingToBehavior: handler).decimalValue
    }

    private static func displayIncomePer10k(base: Decimal, dayOffset: Int) -> Decimal {
        let adjustments = [
            decimal("0.0078"),
            decimal("0.0046"),
            decimal("-0.0029"),
            decimal("0.0017"),
            decimal("-0.0058"),
            decimal("0.0032"),
            decimal("-0.0014")
        ]
        let normalizedBase = roundMetric(max(base, decimal("0.0001")))
        let adjustment = adjustments[dayOffset % adjustments.count]
        return roundMetric(max(normalizedBase + adjustment, decimal("0.0001")))
    }

    private static func roundRate(_ value: Decimal) -> Decimal {
        let handler = NSDecimalNumberHandler(
            roundingMode: .plain,
            scale: 6,
            raiseOnExactness: false,
            raiseOnOverflow: false,
            raiseOnUnderflow: false,
            raiseOnDivideByZero: false
        )
        return NSDecimalNumber(decimal: value).rounding(accordingToBehavior: handler).decimalValue
    }

    private static func percentText(for annualizedYieldRate: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.locale = posixLocale
        formatter.numberStyle = .decimal
        formatter.minimumFractionDigits = 4
        formatter.maximumFractionDigits = 4
        let percentValue = NSDecimalNumber(decimal: annualizedYieldRate).multiplying(by: NSDecimalNumber(value: 100))
        return "\(formatter.string(from: percentValue) ?? percentValue.stringValue)%"
    }

    private static func decimal(_ text: String) -> Decimal {
        Decimal(string: text, locale: posixLocale) ?? .zero
    }
}

private enum AiCashSyntheticSnapshotStore {
    private struct PersistedState: Codable {
        let principalAmount: String
        let totalAmount: String
        let yesterdayIncome: String
        let cumulativeIncome: String
        let annualizedYieldRate: String
        let incomePer10k: String?
        let lastSettledDateKey: String
        let backingHoldingAmount: String
        let hasTotalAmount: Bool?
        let hasYesterdayIncome: Bool?
        let hasCumulativeIncome: Bool?
        let hasAnnualizedYieldRate: Bool?
        let hasIncomePer10k: Bool?
    }

    private static let posixLocale = Locale(identifier: "en_US_POSIX")

    private static func key(for userId: Int64?) -> String? {
        guard let userId, userId > 0 else {
            return nil
        }
        return "cn.openaipay.aiCash.synthetic.snapshot.\(userId)"
    }

    static func load(userId: Int64?) -> AiCashAccountSnapshot? {
        guard let key = key(for: userId),
              let data = UserDefaults.standard.data(forKey: key),
              let state = try? JSONDecoder().decode(PersistedState.self, from: data) else {
            return nil
        }

        let annualizedYieldRate = decimal(state.annualizedYieldRate)
        let defaultIncomePer10k = (annualizedYieldRate / Decimal(365)) * Decimal(10_000)

        return AiCashAccountSnapshot(
            principalAmount: decimal(state.principalAmount),
            totalAmount: decimal(state.totalAmount),
            hasTotalAmount: state.hasTotalAmount ?? true,
            yesterdayIncome: decimal(state.yesterdayIncome),
            hasYesterdayIncome: state.hasYesterdayIncome ?? true,
            cumulativeIncome: decimal(state.cumulativeIncome),
            hasCumulativeIncome: state.hasCumulativeIncome ?? true,
            annualizedYieldRate: annualizedYieldRate,
            hasAnnualizedYieldRate: state.hasAnnualizedYieldRate ?? true,
            incomePer10k: decimal(state.incomePer10k ?? NSDecimalNumber(decimal: defaultIncomePer10k).stringValue),
            hasIncomePer10k: state.hasIncomePer10k ?? true,
            lastSettledDateKey: state.lastSettledDateKey,
            backingHoldingAmount: decimal(state.backingHoldingAmount)
        )
    }

    static func save(_ snapshot: AiCashAccountSnapshot, userId: Int64?) {
        guard let key = key(for: userId) else {
            return
        }

        let state = PersistedState(
            principalAmount: string(from: snapshot.principalAmount),
            totalAmount: string(from: snapshot.totalAmount),
            yesterdayIncome: string(from: snapshot.yesterdayIncome),
            cumulativeIncome: string(from: snapshot.cumulativeIncome),
            annualizedYieldRate: string(from: snapshot.annualizedYieldRate),
            incomePer10k: string(from: snapshot.incomePer10k),
            lastSettledDateKey: snapshot.lastSettledDateKey,
            backingHoldingAmount: string(from: snapshot.backingHoldingAmount),
            hasTotalAmount: snapshot.hasTotalAmount,
            hasYesterdayIncome: snapshot.hasYesterdayIncome,
            hasCumulativeIncome: snapshot.hasCumulativeIncome,
            hasAnnualizedYieldRate: snapshot.hasAnnualizedYieldRate,
            hasIncomePer10k: snapshot.hasIncomePer10k
        )

        if let data = try? JSONEncoder().encode(state) {
            UserDefaults.standard.set(data, forKey: key)
        }
    }

    private static func decimal(_ text: String) -> Decimal {
        Decimal(string: text, locale: posixLocale) ?? .zero
    }

    private static func string(from decimal: Decimal) -> String {
        NSDecimalNumber(decimal: decimal).stringValue
    }
}

private struct AiCashOpenView: View {
    let isSubmitting: Bool
    let onBack: () -> Void
    let onOpenAgreement: () -> Void
    let onAgreeAndOpen: () -> Void
    let onOpenOnly: () -> Void

    private let baseWidth: CGFloat = 402
    private let baseHeight: CGFloat = 874

    var body: some View {
        GeometryReader { proxy in
            let scaleX = proxy.size.width / baseWidth
            let scaleY = proxy.size.height / baseHeight
            let fontScale = min(scaleX, scaleY)

	            ZStack {
	                Image("AiCashOpenScreen")
	                    .resizable()
	                    .interpolation(.high)
	                    .aspectRatio(contentMode: .fill)
	                    .frame(width: proxy.size.width, height: proxy.size.height)
	                    .clipped()

	                agreementSummaryOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
	                openButtonCleanupOverlay(scaleX: scaleX, scaleY: scaleY)
	                primaryButtonTitleOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)

	                actionHotspot(
	                    identifier: "aicash_open_back_button",
                    centerX: 24 * scaleX,
                    centerY: 77 * scaleY,
                    width: 56 * scaleX,
                    height: 50 * scaleY,
                    action: onBack
                )

                actionHotspot(
                    identifier: "aicash_open_agreement_link",
                    centerX: 181 * scaleX,
                    centerY: 522 * scaleY,
                    width: 320 * scaleX,
                    height: 78 * scaleY,
                    action: onOpenAgreement
                )

	                actionHotspot(
	                    identifier: "aicash_open_secondary_button",
	                    centerX: 201 * scaleX,
	                    centerY: 706 * scaleY,
	                    width: 352 * scaleX,
	                    height: 58 * scaleY
	                ) {
	                    guard !isSubmitting else {
	                        return
	                    }
	                    onAgreeAndOpen()
	                }
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
    }

    private func actionHotspot(
        identifier: String,
        centerX: CGFloat,
        centerY: CGFloat,
        width: CGFloat,
        height: CGFloat,
        action: @escaping () -> Void
    ) -> some View {
        Color.clear
            .frame(width: width, height: height)
            .contentShape(Rectangle())
            .position(x: centerX, y: centerY)
            .highPriorityGesture(
                TapGesture().onEnded {
                    action()
                }
            )
            .accessibilityIdentifier(identifier)
    }

