private struct AiCashAgreementContentView: View {
    let onBack: () -> Void

    private let baseWidth: CGFloat = 402
    private let baseHeight: CGFloat = 874
    private static let versionLabelText = "20260325版本"
    private static let loadedAgreementText: String = {
        guard let dataAsset = NSDataAsset(name: "AiCashFundOpenAgreementText"),
              let rawText = String(data: dataAsset.data, encoding: .utf8) else {
            return "协议内容加载失败，请稍后重试。"
        }
        let normalizedText = rawText
            .replacingOccurrences(of: "\r\n", with: "\n")
            .trimmingCharacters(in: .whitespacesAndNewlines)
        return normalizedText.isEmpty ? "协议内容加载失败，请稍后重试。" : normalizedText
    }()
    private static let bodyText: String = {
        let lines = loadedAgreementText
            .components(separatedBy: .newlines)
            .drop { $0.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty }

        guard let firstLine = lines.first else {
            return loadedAgreementText
        }

        let normalizedFirstLine = firstLine.trimmingCharacters(in: .whitespacesAndNewlines)
        let remainingLines = lines.dropFirst()

        if normalizedFirstLine.hasSuffix("版本") {
            return remainingLines.joined(separator: "\n").trimmingCharacters(in: .whitespacesAndNewlines)
        }

        return loadedAgreementText
    }()
    private static let paragraphTexts: [String] = {
        bodyText
            .components(separatedBy: .newlines)
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
    }()

    var body: some View {
        GeometryReader { proxy in
            let scaleX = proxy.size.width / baseWidth
            let scaleY = proxy.size.height / baseHeight
            let fontScale = min(scaleX, scaleY)
            let topInset = 95 * scaleY
            let contentHeight = max(proxy.size.height - topInset, 0)

            ZStack {
                Image("AiCashAgreementContentScreen")
                    .resizable()
                    .interpolation(.high)
                    .aspectRatio(contentMode: .fill)
                    .frame(width: proxy.size.width, height: proxy.size.height)
                    .clipped()

                Rectangle()
                    .fill(Color.white)
                    .frame(width: proxy.size.width, height: contentHeight)
                    .position(x: proxy.size.width / 2, y: topInset + (contentHeight / 2))
                    .allowsHitTesting(false)

                ScrollView(.vertical, showsIndicators: true) {
                    LazyVStack(alignment: .leading, spacing: 8 * scaleY) {
                        HStack(spacing: 0) {
                            Spacer(minLength: 0)
                            Text(Self.versionLabelText)
                                .font(.system(size: 13.4 * fontScale, weight: .regular))
                                .foregroundStyle(Color(red: 0.52, green: 0.52, blue: 0.55))
                        }

                        ForEach(Array(Self.paragraphTexts.enumerated()), id: \.offset) { _, paragraph in
                            Text(verbatim: paragraph)
                                .font(.system(size: 14.2 * fontScale, weight: .regular))
                                .foregroundStyle(Color(red: 0.16, green: 0.16, blue: 0.18))
                                .lineSpacing(5 * fontScale)
                                .frame(maxWidth: .infinity, alignment: .leading)
                        }
                    }
                    .padding(.horizontal, 17 * scaleX)
                    .padding(.top, 12 * scaleY)
                    .padding(.bottom, 40 * scaleY)
                }
                .frame(width: proxy.size.width, height: contentHeight, alignment: .top)
                .position(x: proxy.size.width / 2, y: topInset + (contentHeight / 2))

                actionHotspot(
                    identifier: "aicash_agreement_content_back_button",
                    centerX: 24 * scaleX,
