    private func formatMoney(_ value: Decimal, useGrouping: Bool) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = useGrouping
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSDecimalNumber(decimal: value)) ?? NSDecimalNumber(decimal: value).stringValue
    }

    private func formatMetric(_ value: Decimal, fractionDigits: Int) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = false
        formatter.minimumFractionDigits = fractionDigits
        formatter.maximumFractionDigits = fractionDigits
        return formatter.string(from: NSDecimalNumber(decimal: value)) ?? NSDecimalNumber(decimal: value).stringValue
    }

    private func formatSignedMoney(_ value: Decimal) -> String {
        let normalizedValue = abs(value)
        let prefix: String
        if value > .zero {
            prefix = "+"
        } else if value < .zero {
            prefix = "-"
        } else {
            prefix = ""
        }
        return prefix + formatMoney(normalizedValue, useGrouping: false)
    }

    private func refreshStatusText(at date: Date) -> String {
        let dotPattern = [0, 1, 2, 3, 2, 1]
        let step = Int(date.timeIntervalSinceReferenceDate / 0.45)
        let dotCount = dotPattern[step % dotPattern.count]
        return "更新中" + String(repeating: ".", count: dotCount)
    }

    }

private struct LoanAccountOffer {
    let honorificName: String
    let availableLimit: Decimal
    let annualRate: Decimal
    let originalAnnualRate: Decimal

    private static let defaultAvailableLimit = Decimal(string: "880000", locale: Locale(identifier: "en_US_POSIX")) ?? .zero
    private static let defaultAnnualRate = Decimal(string: "3.24", locale: Locale(identifier: "en_US_POSIX")) ?? .zero
    private static let defaultOriginalAnnualRate = Decimal(string: "5.04", locale: Locale(identifier: "en_US_POSIX")) ?? .zero

    init(userProfile: UserProfile?, loanAccount: LoanAccountData?) {
        honorificName = Self.honorificName(from: userProfile)
        if let resolvedLimit = loanAccount?.availableLimit.amount {
            availableLimit = max(.zero, resolvedLimit)
        } else {
            availableLimit = Self.defaultAvailableLimit
        }
        if let rate = loanAccount?.annualRate, rate > .zero {
            annualRate = rate
        } else {
            annualRate = Self.defaultAnnualRate
        }
        if let rate = loanAccount?.originalAnnualRate, rate > .zero {
            originalAnnualRate = rate
        } else {
            originalAnnualRate = Self.defaultOriginalAnnualRate
        }
    }

    private static func honorificName(from userProfile: UserProfile?) -> String {
        let familyName = preferredFamilyName(from: userProfile)
        return familyName + salutation(for: userProfile?.gender)
    }

    private static func preferredFamilyName(from userProfile: UserProfile?) -> String {
        let candidates = [userProfile?.maskedRealName, userProfile?.nickname, userProfile?.loginId]
        for candidate in candidates {
            let normalized = candidate?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            if normalized.isEmpty {
                continue
            }
            let cleaned = normalized
                .replacingOccurrences(of: "*", with: "")
                .replacingOccurrences(of: "·", with: "")
                .replacingOccurrences(of: "•", with: "")
                .trimmingCharacters(in: .whitespacesAndNewlines)
            if let first = cleaned.first {
                return String(first)
            }
        }
        return "尊"
    }

    private static func salutation(for gender: String?) -> String {
        let normalized = gender?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() ?? ""
        if normalized == "FEMALE" || normalized == "F" || normalized == "WOMAN" {
            return "女士"
        }
        return "先生"
    }

    }

private enum LoanAccountBorrowStatus: Equatable {
    case processing
    case succeeded
}

private func generateLoanAccountBorrowId(borrowedAt: Date, amount: Decimal) -> String {
    let timestamp = Int64((borrowedAt.timeIntervalSince1970 * 1000).rounded())
    let amountToken = NSDecimalNumber(decimal: max(.zero, amount))
        .stringValue
        .replacingOccurrences(of: ".", with: "_")
    return "loan_\(timestamp)_\(amountToken)"
}

private struct LoanAccountBorrowResult: Equatable, Identifiable {
    let borrowId: String
    let amount: Decimal
    let remainingPrincipalAmount: Decimal
    let installmentText: String
    let receiveAccountText: String
    let annualRate: Decimal
    let isWalletReceiveAccount: Bool
    let receiveBankCode: String?
    let receiveBankName: String?
    let lendingInstitutionName: String
    let borrowedAt: Date
    let interestSettledThroughDate: Date?
    var status: LoanAccountBorrowStatus

    var id: String { borrowId }

    var isProcessing: Bool {
        status == .processing
    }

    var outstandingPrincipalAmount: Decimal {
        max(.zero, remainingPrincipalAmount)
    }
    }

private struct LoanAccountRepaymentSettlement: Equatable {
    let totalAmount: Decimal
    let principalAmount: Decimal
    let interestAmount: Decimal
    let didSettleAccruedInterest: Bool
    let occurredAt: Date
}

private enum LoanAccountRepaymentCalculator {
    struct InstallmentEntry: Equatable {
        let periodIndex: Int
        let paymentAmount: Decimal
        let interestAmount: Decimal
        let principalAmount: Decimal
        let remainingPrincipal: Decimal
    }

    struct Quote: Equatable {
        let outstandingPrincipal: Decimal
        let annualRatePercent: Decimal
        let monthlyRate: Decimal
        let termMonths: Int
        let monthlyPayment: Decimal
        let totalPayment: Decimal
        let totalInterest: Decimal
        let accruedInterest: Decimal
        let payoffAmount: Decimal
        let daysUsed: Int
        let schedule: [InstallmentEntry]
    }

    private static let posixLocale = Locale(identifier: "en_US_POSIX")
    private static let calendar = Calendar(identifier: .gregorian)
    private static let daysPerYear = Decimal(365)

    static func quote(
        currentPrincipal: Decimal,
        annualRatePercent: Decimal,
        installmentText: String?,
        borrowedAt: Date?,
        interestSettledThroughDate: Date? = nil,
        asOf: Date = Date()
    ) -> Quote {
        let normalizedPrincipal = max(.zero, currentPrincipal)
        let normalizedAnnualRatePercent = max(.zero, annualRatePercent)
        let termMonths = installmentCount(from: installmentText)
        let annualRateDecimal = normalizedAnnualRatePercent / Decimal(100)
        let monthlyRate = annualRateDecimal / Decimal(12)
        let schedule = buildSchedule(
            principal: normalizedPrincipal,
            monthlyRate: monthlyRate,
            termMonths: termMonths
        )
        let monthlyPayment = schedule.first?.paymentAmount ?? .zero
        let totalPayment = roundedMoney(schedule.reduce(.zero) { $0 + $1.paymentAmount })
        let totalInterest = roundedMoney(max(.zero, totalPayment - normalizedPrincipal))
        let daysUsed = accruedDaysUsed(
            from: borrowedAt,
            interestSettledThroughDate: interestSettledThroughDate,
            asOf: asOf,
            hasOutstandingPrincipal: normalizedPrincipal > .zero
        )
        let accruedInterest = roundedMoney(
            normalizedPrincipal * annualRateDecimal * Decimal(daysUsed) / daysPerYear
        )
        let payoffAmount = roundedMoney(normalizedPrincipal + accruedInterest)

        return Quote(
            outstandingPrincipal: normalizedPrincipal,
            annualRatePercent: normalizedAnnualRatePercent,
            monthlyRate: monthlyRate,
            termMonths: termMonths,
            monthlyPayment: monthlyPayment,
            totalPayment: totalPayment,
            totalInterest: totalInterest,
            accruedInterest: accruedInterest,
            payoffAmount: payoffAmount,
            daysUsed: daysUsed,
            schedule: schedule
        )
    }

    static func installmentCount(from installmentText: String?) -> Int {
        let source = installmentText?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let pattern = #"(\d+)"#
        guard let regex = try? NSRegularExpression(pattern: pattern),
              let match = regex.firstMatch(in: source, options: [], range: NSRange(source.startIndex..<source.endIndex, in: source)),
              let range = Range(match.range(at: 1), in: source),
              let value = Int(source[range]),
              value > 0 else {
            return 24
        }
        return value
    }

    static func remainingInstallmentCount(
        from installmentText: String?,
        borrowedAt: Date?,
        asOf: Date = Date()
    ) -> Int {
        let totalMonths = installmentCount(from: installmentText)
        guard totalMonths > 0 else {
            return 0
        }

        guard let borrowedAt else {
            return totalMonths
        }

        let start = calendar.startOfDay(for: borrowedAt)
        let end = calendar.startOfDay(for: asOf)
        guard end >= start else {
            return totalMonths
        }

        let elapsedMonths = max(calendar.dateComponents([.month], from: start, to: end).month ?? 0, 0)
        return max(1, totalMonths - elapsedMonths)
    }

    private static func buildSchedule(
        principal: Decimal,
        monthlyRate: Decimal,
        termMonths: Int
    ) -> [InstallmentEntry] {
        guard principal > .zero, termMonths > 0 else {
            return []
        }

        let rawMonthlyPayment = equalInstallmentPayment(
            principal: principal,
            monthlyRate: monthlyRate,
            termMonths: termMonths
        )
        let monthlyPayment = roundedMoney(rawMonthlyPayment)

        var remainingPrincipal = principal
        var entries: [InstallmentEntry] = []
        entries.reserveCapacity(termMonths)

        for periodIndex in 1...termMonths {
            let interestAmount = roundedMoney(remainingPrincipal * monthlyRate)
            var principalAmount = roundedMoney(monthlyPayment - interestAmount)

            if monthlyRate == .zero {
                principalAmount = roundedMoney(principal / Decimal(termMonths))
            }

            if periodIndex == termMonths || principalAmount > remainingPrincipal {
                principalAmount = roundedMoney(remainingPrincipal)
            }

            let paymentAmount = roundedMoney(principalAmount + interestAmount)
            remainingPrincipal = roundedMoney(max(.zero, remainingPrincipal - principalAmount))

            entries.append(
                InstallmentEntry(
                    periodIndex: periodIndex,
                    paymentAmount: paymentAmount,
                    interestAmount: interestAmount,
                    principalAmount: principalAmount,
                    remainingPrincipal: remainingPrincipal
                )
            )
        }

        return entries
    }

    private static func equalInstallmentPayment(
        principal: Decimal,
        monthlyRate: Decimal,
        termMonths: Int
    ) -> Decimal {
        guard principal > .zero, termMonths > 0 else {
            return .zero
        }

        if monthlyRate == .zero {
            return principal / Decimal(termMonths)
        }

        let onePlusRate = NSDecimalNumber(decimal: Decimal(1) + monthlyRate)
        let compounded = onePlusRate.raising(toPower: termMonths)
        let numerator = NSDecimalNumber(decimal: principal * monthlyRate).multiplying(by: compounded)
        let denominator = compounded.subtracting(NSDecimalNumber(value: 1))
        guard denominator != .zero else {
            return principal / Decimal(termMonths)
        }
        return numerator.dividing(by: denominator).decimalValue
    }

    private static func accruedDaysUsed(
        from borrowedAt: Date?,
        interestSettledThroughDate: Date?,
        asOf: Date,
        hasOutstandingPrincipal: Bool
    ) -> Int {
        guard hasOutstandingPrincipal else {
            return 0
        }

        guard let borrowedAt else {
            return 0
        }

        let start = calendar.startOfDay(for: borrowedAt)
        let end = calendar.startOfDay(for: asOf)
        guard end >= start else {
            return 0
        }

        if let interestSettledThroughDate {
            let settledDay = calendar.startOfDay(for: interestSettledThroughDate)
            if settledDay >= start {
                guard settledDay < end else {
                    return 0
                }
                return max(calendar.dateComponents([.day], from: settledDay, to: end).day ?? 0, 0)
            }
        }

        let elapsedDayCount = max(calendar.dateComponents([.day], from: start, to: end).day ?? 0, 0)
        return elapsedDayCount + 1
    }

    private static func roundedMoney(_ value: Decimal) -> Decimal {
        var working = value
        var rounded = Decimal()
        NSDecimalRound(&rounded, &working, 2, .plain)
        return rounded
    }
}

private enum LoanAccountSyntheticSnapshotStore {
    private struct PersistedBorrowItem: Codable {
        var borrowId: String
        var originalAmount: String
        var remainingPrincipalAmount: String
        var installmentText: String?
        var receiveAccountText: String?
        var annualRate: String?
        var isWalletReceiveAccount: Bool
        var receiveBankCode: String?
        var receiveBankName: String?
        var lendingInstitutionName: String?
        var borrowedAt: TimeInterval
        var interestSettledThroughAt: TimeInterval?
        var status: String?
    }

    private struct PersistedState: Codable {
        var accountNo: String
        var totalLimit: String
        var availableLimit: String
        var annualRate: String
        var originalAnnualRate: String
        var repayDayOfMonth: Int
        var latestBorrowAmount: String?
        var latestInstallmentText: String?
        var latestReceiveAccountText: String?
        var latestBorrowAnnualRate: String?
        var latestIsWalletReceiveAccount: Bool
        var latestReceiveBankCode: String?
        var latestReceiveBankName: String?
        var latestLendingInstitutionName: String?
        var latestBorrowedAt: TimeInterval?
        var latestBorrowStatus: String?
        var borrowItems: [PersistedBorrowItem]?
    }

    private static let posixLocale = Locale(identifier: "en_US_POSIX")
    private static let defaultTotalLimit = Decimal(string: "880000", locale: posixLocale) ?? .zero
    private static let defaultAnnualRate = Decimal(string: "3.24", locale: posixLocale) ?? .zero
    private static let defaultOriginalAnnualRate = Decimal(string: "5.04", locale: posixLocale) ?? .zero
    private static let snapshotKeyPrefix = "cn.openaipay.loan-account.synthetic.snapshot."

    private static func key(for userId: Int64?) -> String? {
        guard let userId, userId > 0 else {
            return nil
        }
        return snapshotKeyPrefix + String(userId)
    }

    static func loadAccount(userId: Int64?) -> LoanAccountData? {
        guard let userId, userId > 0,
              let state = loadState(userId: userId) else {
            return nil
        }
        return LoanAccountData(
            accountNo: state.accountNo,
            userId: userId,
            totalLimit: MoneyValueData(amount: decimal(state.totalLimit), currencyCode: "CNY"),
            availableLimit: MoneyValueData(amount: decimal(state.availableLimit), currencyCode: "CNY"),
            annualRate: decimal(state.annualRate),
            originalAnnualRate: decimal(state.originalAnnualRate),
            repayDayOfMonth: state.repayDayOfMonth,
            accountStatus: "NORMAL",
            payStatus: "NORMAL"
        )
    }

    static func saveAccount(_ account: LoanAccountData, userId: Int64?) {
        guard var state = loadState(userId: userId) ?? defaultState(userId: userId) else {
            return
        }
        state.accountNo = account.accountNo
        let normalizedTotalLimit = max(.zero, account.totalLimit.amount)
        let normalizedAvailableLimit = min(normalizedTotalLimit, max(.zero, account.availableLimit.amount))
        state.totalLimit = string(from: normalizedTotalLimit)
        state.availableLimit = string(from: normalizedAvailableLimit)
        state.annualRate = string(from: account.annualRate)
        state.originalAnnualRate = string(from: account.originalAnnualRate)
        state.repayDayOfMonth = account.repayDayOfMonth
        let borrowItems = loadActiveBorrowItems(from: state)
        if !borrowItems.isEmpty {
            reconcileBorrowItemsWithAuthoritativeAccount(
                &state,
                authoritativeTotalLimit: normalizedTotalLimit,
                authoritativeAvailableLimit: normalizedAvailableLimit
            )
        }
        saveState(state, userId: userId)
    }

    static func saveBorrowResult(_ result: LoanAccountBorrowResult, userId: Int64?) {
        guard var state = loadState(userId: userId) ?? defaultState(userId: userId) else {
            return
        }
        applyLatestPreviewFields(from: result, to: &state)
        saveState(state, userId: userId)
    }

    static func recordBorrow(_ result: LoanAccountBorrowResult, userId: Int64?) {
        guard var state = loadState(userId: userId) ?? defaultState(userId: userId) else {
            return
        }
        var borrowItems = loadActiveBorrowItems(from: state)
        let nextBorrowItem = persistedBorrowItem(from: result)
        borrowItems.removeAll { $0.borrowId == nextBorrowItem.borrowId }
        borrowItems.append(nextBorrowItem)
        borrowItems.sort { $0.borrowedAt > $1.borrowedAt }
        state.borrowItems = borrowItems
        syncAvailableLimit(&state, borrowItems: borrowItems)
        applyLatestStoredFields(from: borrowItems.first, to: &state)
        saveState(state, userId: userId)
    }

    static func applyRepayment(settlement: LoanAccountRepaymentSettlement, borrowId: String?, userId: Int64?) {
        guard var state = loadState(userId: userId) ?? defaultState(userId: userId) else {
            return
        }
        var borrowItems = loadActiveBorrowItems(from: state)
        let normalizedPrincipal = max(.zero, settlement.principalAmount)
        let didSettleAccruedInterest = settlement.didSettleAccruedInterest

        if borrowItems.isEmpty {
            let totalLimit = decimal(state.totalLimit)
            let availableLimit = min(totalLimit, max(.zero, decimal(state.availableLimit)))
            let currentOutstanding = max(.zero, totalLimit - availableLimit)
            let nextOutstanding = max(.zero, currentOutstanding - normalizedPrincipal)
            state.availableLimit = string(from: min(totalLimit, max(.zero, totalLimit - nextOutstanding)))
            if nextOutstanding > .zero {
                state.latestBorrowAmount = string(from: nextOutstanding)
                state.latestBorrowedAt = Date().timeIntervalSince1970
                state.latestBorrowStatus = "succeeded"
            } else {
                clearLatestBorrowFields(&state)
            }
            saveState(state, userId: userId)
            return
        }

        let selectedIndex = borrowId.flatMap { borrowId in
            borrowItems.firstIndex(where: { $0.borrowId == borrowId })
        } ?? 0

        if borrowItems.indices.contains(selectedIndex) {
            var selectedBorrowItem = borrowItems[selectedIndex]
            let nextRemainingPrincipal = max(.zero, decimal(selectedBorrowItem.remainingPrincipalAmount) - normalizedPrincipal)
            if nextRemainingPrincipal > .zero {
                selectedBorrowItem.remainingPrincipalAmount = string(from: nextRemainingPrincipal)
                if didSettleAccruedInterest {
                    selectedBorrowItem.interestSettledThroughAt = settlement.occurredAt.timeIntervalSince1970
                }
                selectedBorrowItem.status = "succeeded"
                borrowItems[selectedIndex] = selectedBorrowItem
            } else {
                borrowItems.remove(at: selectedIndex)
            }
        }

        borrowItems = borrowItems
            .filter { decimal($0.remainingPrincipalAmount) > .zero }
            .sorted { $0.borrowedAt > $1.borrowedAt }
        state.borrowItems = borrowItems.isEmpty ? nil : borrowItems
        syncAvailableLimit(&state, borrowItems: borrowItems)
        if let latestBorrowItem = borrowItems.first {
            applyLatestStoredFields(from: latestBorrowItem, to: &state)
        } else {
            clearLatestBorrowFields(&state)
        }
        saveState(state, userId: userId)
    }

    static func loadBorrowResult(userId: Int64?) -> LoanAccountBorrowResult? {
        if let previewBorrowResult = loadPreviewBorrowResult(userId: userId), previewBorrowResult.isProcessing {
            return previewBorrowResult
        }
        return loadBorrowResults(userId: userId).first ?? loadPreviewBorrowResult(userId: userId)
    }

    static func loadBorrowResult(userId: Int64?, borrowId: String?) -> LoanAccountBorrowResult? {
        guard let borrowId = normalizedOptionalText(borrowId) else {
            return nil
        }
        return loadBorrowResults(userId: userId).first(where: { $0.borrowId == borrowId })
    }

    static func loadBorrowResults(userId: Int64?) -> [LoanAccountBorrowResult] {
        guard let state = loadState(userId: userId) else {
            return []
        }
        return loadActiveBorrowItems(from: state).compactMap(buildBorrowResult(from:))
    }

    private static func loadPreviewBorrowResult(userId: Int64?) -> LoanAccountBorrowResult? {
        guard let state = loadState(userId: userId),
              let amountText = state.latestBorrowAmount,
              decimal(amountText) > .zero else {
            return nil
        }
        let borrowedAt = Date(timeIntervalSince1970: state.latestBorrowedAt ?? Date().timeIntervalSince1970)
        let status: LoanAccountBorrowStatus = state.latestBorrowStatus == "processing" ? .processing : .succeeded
        return LoanAccountBorrowResult(
            borrowId: generateLoanAccountBorrowId(borrowedAt: borrowedAt, amount: decimal(amountText)),
            amount: decimal(amountText),
            remainingPrincipalAmount: decimal(amountText),
            installmentText: normalizedDisplayText(state.latestInstallmentText, fallback: "24期"),
            receiveAccountText: normalizedDisplayText(state.latestReceiveAccountText, fallback: "账户余额"),
            annualRate: decimal(state.latestBorrowAnnualRate ?? state.annualRate),
            isWalletReceiveAccount: state.latestIsWalletReceiveAccount,
            receiveBankCode: normalizedOptionalText(state.latestReceiveBankCode),
            receiveBankName: normalizedOptionalText(state.latestReceiveBankName),
            lendingInstitutionName: normalizedDisplayText(state.latestLendingInstitutionName, fallback: "江苏银行"),
            borrowedAt: borrowedAt,
            interestSettledThroughDate: nil,
            status: status
        )
    }

    private static func loadActiveBorrowItems(from state: PersistedState) -> [PersistedBorrowItem] {
        return (state.borrowItems ?? [])
            .filter { decimal($0.remainingPrincipalAmount) > .zero }
            .sorted { $0.borrowedAt > $1.borrowedAt }
    }

    private static func persistedBorrowItem(from result: LoanAccountBorrowResult) -> PersistedBorrowItem {
        let originalAmount = max(.zero, result.amount)
        let remainingPrincipalAmount = max(.zero, result.remainingPrincipalAmount)
        return PersistedBorrowItem(
            borrowId: normalizedOptionalText(result.borrowId) ?? generateLoanAccountBorrowId(borrowedAt: result.borrowedAt, amount: originalAmount),
            originalAmount: string(from: originalAmount),
            remainingPrincipalAmount: string(from: remainingPrincipalAmount > .zero ? remainingPrincipalAmount : originalAmount),
            installmentText: normalizedOptionalText(result.installmentText),
            receiveAccountText: normalizedOptionalText(result.receiveAccountText),
            annualRate: string(from: result.annualRate),
            isWalletReceiveAccount: result.isWalletReceiveAccount,
            receiveBankCode: normalizedOptionalText(result.receiveBankCode),
            receiveBankName: normalizedOptionalText(result.receiveBankName),
            lendingInstitutionName: normalizedOptionalText(result.lendingInstitutionName),
            borrowedAt: result.borrowedAt.timeIntervalSince1970,
            interestSettledThroughAt: result.interestSettledThroughDate?.timeIntervalSince1970,
            status: result.status == .processing ? "processing" : "succeeded"
        )
    }

    private static func buildBorrowResult(from borrowItem: PersistedBorrowItem) -> LoanAccountBorrowResult? {
        let originalAmount = max(.zero, decimal(borrowItem.originalAmount))
        let remainingPrincipalAmount = max(.zero, decimal(borrowItem.remainingPrincipalAmount))
        guard originalAmount > .zero || remainingPrincipalAmount > .zero else {
            return nil
        }
        let borrowedAt = Date(timeIntervalSince1970: borrowItem.borrowedAt)
        let status: LoanAccountBorrowStatus = borrowItem.status == "processing" ? .processing : .succeeded
        return LoanAccountBorrowResult(
            borrowId: normalizedDisplayText(
                borrowItem.borrowId,
                fallback: generateLoanAccountBorrowId(borrowedAt: borrowedAt, amount: originalAmount)
            ),
            amount: originalAmount > .zero ? originalAmount : remainingPrincipalAmount,
            remainingPrincipalAmount: remainingPrincipalAmount > .zero ? remainingPrincipalAmount : originalAmount,
            installmentText: normalizedDisplayText(borrowItem.installmentText, fallback: "24期"),
            receiveAccountText: normalizedDisplayText(borrowItem.receiveAccountText, fallback: "账户余额"),
            annualRate: decimal(borrowItem.annualRate ?? string(from: defaultAnnualRate)),
            isWalletReceiveAccount: borrowItem.isWalletReceiveAccount,
            receiveBankCode: normalizedOptionalText(borrowItem.receiveBankCode),
            receiveBankName: normalizedOptionalText(borrowItem.receiveBankName),
            lendingInstitutionName: normalizedDisplayText(borrowItem.lendingInstitutionName, fallback: "江苏银行"),
            borrowedAt: borrowedAt,
            interestSettledThroughDate: borrowItem.interestSettledThroughAt.map(Date.init(timeIntervalSince1970:)),
            status: status
        )
    }

    private static func syncAvailableLimit(_ state: inout PersistedState, borrowItems: [PersistedBorrowItem]) {
        let totalLimit = decimal(state.totalLimit)
        let outstandingPrincipal = borrowItems.reduce(.zero) { partialResult, borrowItem in
            partialResult + max(.zero, decimal(borrowItem.remainingPrincipalAmount))
        }
        state.availableLimit = string(from: min(totalLimit, max(.zero, totalLimit - outstandingPrincipal)))
    }

    private static func reconcileBorrowItemsWithAuthoritativeAccount(
        _ state: inout PersistedState,
        authoritativeTotalLimit: Decimal,
        authoritativeAvailableLimit: Decimal
    ) {
        let normalizedTotalLimit = max(.zero, authoritativeTotalLimit)
        let normalizedAvailableLimit = min(
            normalizedTotalLimit,
            max(.zero, authoritativeAvailableLimit)
        )
        let authoritativeOutstandingPrincipal = max(.zero, normalizedTotalLimit - normalizedAvailableLimit)

        guard authoritativeOutstandingPrincipal > .zero else {
            state.borrowItems = nil
            clearLatestBorrowFields(&state)
            state.availableLimit = string(from: normalizedAvailableLimit)
            return
        }

        var remainingOutstandingPrincipal = authoritativeOutstandingPrincipal
        let sortedBorrowItems = loadActiveBorrowItems(from: state).sorted { $0.borrowedAt > $1.borrowedAt }
        var reconciledBorrowItems: [PersistedBorrowItem] = []
        reconciledBorrowItems.reserveCapacity(sortedBorrowItems.count)

        for borrowItem in sortedBorrowItems {
            if remainingOutstandingPrincipal <= .zero {
                break
            }

            let localOutstandingPrincipal = max(.zero, decimal(borrowItem.remainingPrincipalAmount))
            guard localOutstandingPrincipal > .zero else {
                continue
            }

            let retainedOutstandingPrincipal = min(localOutstandingPrincipal, remainingOutstandingPrincipal)
            guard retainedOutstandingPrincipal > .zero else {
                continue
            }

            var reconciledBorrowItem = borrowItem
            reconciledBorrowItem.remainingPrincipalAmount = string(from: retainedOutstandingPrincipal)
            reconciledBorrowItems.append(reconciledBorrowItem)
            remainingOutstandingPrincipal = max(.zero, remainingOutstandingPrincipal - retainedOutstandingPrincipal)
        }

        state.borrowItems = reconciledBorrowItems.isEmpty ? nil : reconciledBorrowItems
        state.availableLimit = string(from: normalizedAvailableLimit)
        if let latestBorrowItem = reconciledBorrowItems.first {
            applyLatestStoredFields(from: latestBorrowItem, to: &state)
        } else {
            clearLatestBorrowFields(&state)
        }
    }

    private static func applyLatestPreviewFields(from result: LoanAccountBorrowResult, to state: inout PersistedState) {
        state.latestBorrowAmount = string(from: max(.zero, result.amount))
        state.latestInstallmentText = normalizedOptionalText(result.installmentText)
        state.latestReceiveAccountText = normalizedOptionalText(result.receiveAccountText)
        state.latestBorrowAnnualRate = string(from: result.annualRate)
        state.latestIsWalletReceiveAccount = result.isWalletReceiveAccount
        state.latestReceiveBankCode = normalizedOptionalText(result.receiveBankCode)
        state.latestReceiveBankName = normalizedOptionalText(result.receiveBankName)
        state.latestLendingInstitutionName = normalizedOptionalText(result.lendingInstitutionName)
        state.latestBorrowedAt = result.borrowedAt.timeIntervalSince1970
        state.latestBorrowStatus = result.status == .processing ? "processing" : "succeeded"
    }

    private static func applyLatestStoredFields(from borrowItem: PersistedBorrowItem?, to state: inout PersistedState) {
        guard let borrowItem else {
            clearLatestBorrowFields(&state)
            return
        }
        state.latestBorrowAmount = normalizedOptionalText(borrowItem.originalAmount)
        state.latestInstallmentText = normalizedOptionalText(borrowItem.installmentText)
        state.latestReceiveAccountText = normalizedOptionalText(borrowItem.receiveAccountText)
        state.latestBorrowAnnualRate = normalizedOptionalText(borrowItem.annualRate)
        state.latestIsWalletReceiveAccount = borrowItem.isWalletReceiveAccount
        state.latestReceiveBankCode = normalizedOptionalText(borrowItem.receiveBankCode)
        state.latestReceiveBankName = normalizedOptionalText(borrowItem.receiveBankName)
        state.latestLendingInstitutionName = normalizedOptionalText(borrowItem.lendingInstitutionName)
        state.latestBorrowedAt = borrowItem.borrowedAt
        state.latestBorrowStatus = normalizedOptionalText(borrowItem.status) ?? "succeeded"
    }

    private static func clearLatestBorrowFields(_ state: inout PersistedState) {
        state.latestBorrowAmount = nil
        state.latestInstallmentText = nil
        state.latestReceiveAccountText = nil
        state.latestBorrowAnnualRate = nil
        state.latestReceiveBankCode = nil
        state.latestReceiveBankName = nil
        state.latestLendingInstitutionName = nil
        state.latestBorrowedAt = nil
        state.latestBorrowStatus = nil
    }

    private static func loadState(userId: Int64?) -> PersistedState? {
        guard let key = key(for: userId) else {
            return nil
        }
        return loadRawState(forKey: key)
    }

    private static func saveState(_ state: PersistedState, userId: Int64?) {
        guard let key = key(for: userId),
              let data = try? JSONEncoder().encode(state) else {
            return
        }
        UserDefaults.standard.set(data, forKey: key)
    }

    private static func loadRawState(forKey key: String) -> PersistedState? {
        guard let data = UserDefaults.standard.data(forKey: key),
              let state = try? JSONDecoder().decode(PersistedState.self, from: data) else {
            return nil
        }
        return state
    }

    private static func defaultState(userId: Int64?) -> PersistedState? {
        guard let userId, userId > 0 else {
            return nil
        }
        return PersistedState(
            accountNo: "LA\(userId)",
            totalLimit: string(from: defaultTotalLimit),
            availableLimit: string(from: defaultTotalLimit),
            annualRate: string(from: defaultAnnualRate),
            originalAnnualRate: string(from: defaultOriginalAnnualRate),
            repayDayOfMonth: 10,
            latestBorrowAmount: nil,
            latestInstallmentText: nil,
            latestReceiveAccountText: nil,
            latestBorrowAnnualRate: nil,
            latestIsWalletReceiveAccount: false,
            latestReceiveBankCode: nil,
            latestReceiveBankName: nil,
            latestLendingInstitutionName: nil,
            latestBorrowedAt: nil,
            latestBorrowStatus: nil,
            borrowItems: nil
        )
    }

    private static func decimal(_ text: String) -> Decimal {
        Decimal(string: text, locale: posixLocale) ?? .zero
    }

    private static func string(from decimal: Decimal) -> String {
        NSDecimalNumber(decimal: decimal).stringValue
    }

    private static func normalizedOptionalText(_ text: String?) -> String? {
        let trimmed = text?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        return trimmed.isEmpty ? nil : trimmed
    }

    private static func normalizedDisplayText(_ text: String?, fallback: String) -> String {
        normalizedOptionalText(text) ?? fallback
    }
}

private enum LoanAccountHint: String, Identifiable {
    case tradePay
    case limitManage

    var id: String { rawValue }

    var title: String {
        switch self {
        case .tradePay:
            return "统一支付链路已就绪"
        case .limitManage:
            return "额度管理建设中"
        }
    }

    var message: String {
        switch self {
        case .tradePay:
            return "爱借账户已经接入统一交易支付链路，可通过 trade-pay-loanAccount 作为付款账户继续接消费场景。"
        case .limitManage:
            return "额度管理入口已经预留，后续可以继续接公积金提额等能力。"
        }
    }
    }

private struct LoanAccountWaveLine: Shape {
    let baseY: CGFloat
    let amplitude: CGFloat
    let waveCount: CGFloat

    func path(in rect: CGRect) -> Path {
        var path = Path()
        guard rect.width > 0 else {
            return path
        }

        let step: CGFloat = 6
        path.move(to: CGPoint(x: 0, y: baseY))
        var currentX: CGFloat = 0
        while currentX <= rect.width + step {
            let progress = currentX / rect.width
            let y = baseY + sin(progress * .pi * waveCount) * amplitude
            path.addLine(to: CGPoint(x: currentX, y: y))
            currentX += step
        }
        return path
    }
    }

private struct LoanAccountBackdrop: View {
    var body: some View {
        GeometryReader { proxy in
            ZStack {
                LinearGradient(
                    colors: [
                        Color(red: 0.03, green: 0.05, blue: 0.22),
                        Color(red: 0.08, green: 0.10, blue: 0.42),
                        Color(red: 0.11, green: 0.12, blue: 0.56)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )

                ForEach(0..<30, id: \.self) { index in
                    LoanAccountWaveLine(
                        baseY: CGFloat(index) * 29 + 8,
                        amplitude: 4,
                        waveCount: index.isMultiple(of: 2) ? 7.0 : 8.2
                    )
                    .stroke(
                        Color.white.opacity(index.isMultiple(of: 3) ? 0.07 : 0.035),
                        lineWidth: 0.8
                    )
                }

                LinearGradient(
                    colors: [
                        Color.black.opacity(0.02),
                        Color.black.opacity(0.16)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .ignoresSafeArea()
    }
    }

private struct LoanAccountHomeView: View {
    let userId: Int64?
    let userProfile: UserProfile?
    let reopenBorrowDetailResult: LoanAccountBorrowResult?
    let onBack: () -> Void
    let onReturnHome: () -> Void
    let onOpenRecord: () -> Void
    let onRepay: (LoanAccountBorrowResult?) -> Void
    let onBorrowResultUpdated: (LoanAccountBorrowResult) -> Void
    let onConsumeReopenBorrowDetail: () -> Void

    @State private var loanAccount: LoanAccountData?
    @State private var activeHint: LoanAccountHint?
    @State private var isCashierPresented = false
    @State private var cashierAmountInput = ""
    @State private var receiveBankTools: [CashierPayToolData] = []
    @State private var selectedReceiveBankToolCode: String?
    @State private var isWalletReceiveAccountSelected = false
    @State private var receiveWalletAvailableAmountText: String = "--"
    @State private var receiveSceneConfiguration = CashierSceneConfiguration(
        supportedChannels: [.wallet, .bankCard],
        bankCardPolicy: .debitOnly,
        emptyBankCardText: "暂无可用借记卡"
    )
    @State private var isLoadingReceiveBankTools = false
    @State private var isLoadingReceiveWalletBalance = false
    @State private var borrowResult: LoanAccountBorrowResult?
    @State private var standaloneBorrowDetailResult: LoanAccountBorrowResult?
    @State private var isBorrowDetailPresented = false
    @State private var isSubmittingBorrow = false
    @State private var borrowSubmitErrorMessage: String?

    private let baseWidth: CGFloat = 402
    private let baseHeight: CGFloat = 874

    private var offer: LoanAccountOffer {
        LoanAccountOffer(userProfile: userProfile, loanAccount: loanAccount)
    }

    private var selectedReceiveBankTool: CashierPayToolData? {
        if let selectedReceiveBankToolCode {
            return receiveBankTools.first(where: { $0.toolCode == selectedReceiveBankToolCode })
        }
        return receiveBankTools.first(where: \.defaultSelected) ?? receiveBankTools.first
    }

    private var maxBorrowAmountText: String {
        formatMoney(offer.availableLimit, useGrouping: false)
    }

    var body: some View {
        GeometryReader { proxy in
            let scaleX = proxy.size.width / baseWidth
            let scaleY = proxy.size.height / baseHeight
            let fontScale = min(scaleX, scaleY)

            ZStack {
                if let borrowResult {
