                        onRepay: {
                            onRepay(standaloneBorrowDetailResult)
                        }
                    )
                    .transition(.opacity.combined(with: .move(edge: .trailing)))
                } else {
                    LoanAccountBackdrop()

                    VStack(spacing: 0) {
                    topBar(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                        .padding(.top, 48 * scaleY)
                        .padding(.horizontal, 18 * scaleX)

                    VStack(spacing: 12 * scaleY) {
                        Text("尊享人，\(offer.honorificName)")
