                            Text(formatMoney(offer.availableLimit, useGrouping: true))
                                .font(.system(size: 25 * fontScale, weight: .heavy, design: .rounded))
                                .foregroundStyle(Color(red: 0.99, green: 0.90, blue: 0.76))
                                .accessibilityIdentifier("loan_account_available_amount")

                            Text("元")
                                .font(.system(size: 16 * fontScale, weight: .medium, design: .rounded))
                                .foregroundStyle(Color.white.opacity(0.92))
                        }
                    }
                    .padding(.top, 24 * scaleY)

                    loanCard(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                        .padding(.top, 26 * scaleY)
                        .padding(.horizontal, 20 * scaleX)

                    recordEntryCard(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                        .padding(.top, 18 * scaleY)
                        .padding(.horizontal, 20 * scaleX)

                    repayEntryCard(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                        .padding(.top, 12 * scaleY)
                        .padding(.horizontal, 20 * scaleX)

                    Spacer(minLength: 16 * scaleY)
                }

                if isCashierPresented {
                    LoanAccountCashierSheetView(
                        scaleX: scaleX,
                        scaleY: scaleY,
                        fontScale: fontScale,
                        amountInput: cashierAmountInput,
                        maxBorrowAmountText: maxBorrowAmountText,
                        currentRateText: formatRate(offer.annualRate),
                        originalRateText: formatRate(offer.originalAnnualRate),
                        selectedBankTool: selectedReceiveBankTool,
                        sceneConfiguration: receiveSceneConfiguration,
                        bankTools: receiveBankTools,
                        selectedBankToolCode: selectedReceiveBankToolCode,
                        isWalletSelected: isWalletReceiveAccountSelected,
                        walletAvailableAmountText: receiveWalletAvailableAmountText,
                        isLoadingReceiveBankTools: isLoadingReceiveBankTools,
                        isLoadingWalletBalance: isLoadingReceiveWalletBalance,
                        onClose: {
                            isCashierPresented = false
                        },
                        onTakeAll: applyCashierMaxAmount,
                        onInput: handleCashierKeyInput,
                        onDelete: removeLastCashierInputCharacter,
                        onSelectWallet: {
                            isWalletReceiveAccountSelected = true
                        },
                        onSelectBankTool: { toolCode in
                            selectedReceiveBankToolCode = toolCode
                            isWalletReceiveAccountSelected = false
                        },
                        onConfirm: handleCashierConfirm
                    )
                    .transition(.move(edge: .bottom).combined(with: .opacity))
                    .zIndex(20)
                }

                if isSubmittingBorrow && borrowResult == nil {
                    Color.black.opacity(0.18)
                        .ignoresSafeArea()
                        .zIndex(29)

                    AILoadingIndicator(
                        text: "借款确认中",
                        accentColor: Color.white,
                        secondaryAccentColor: Color(red: 0.93, green: 0.74, blue: 0.58),
                        textColor: Color.white.opacity(0.92),
                        aiFontSize: 20 * fontScale,
                        dotSize: 6 * fontScale,
                        textFontSize: 15 * fontScale
                    )
                    .zIndex(30)
                }
                }
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .task(id: userId) {
            await refreshLoanAccount()
        }
        .task(id: reopenBorrowDetailResult?.borrowId ?? "") {
            applyReopenBorrowDetailIfNeeded()
        }
        .alert(item: $activeHint) { hint in
            Alert(
                title: Text(hint.title),
                message: Text(hint.message),
                dismissButton: .default(Text("知道了"))
            )
        }
        .alert(isPresented: Binding(
            get: { borrowSubmitErrorMessage != nil },
            set: { isPresented in
                if !isPresented {
                    borrowSubmitErrorMessage = nil
                }
            }
        )) {
            Alert(
                title: Text("爱借借款失败"),
                message: Text(borrowSubmitErrorMessage ?? ""),
                dismissButton: .default(Text("知道了")) {
                    borrowSubmitErrorMessage = nil
                }
            )
        }
    }

