    private var loanRepayEntrySubtitle: String {
        let day = loanAccount?.repayDayOfMonth ?? 10
        return "查看借款明细 · 还款日每月\(day)日"
    }

    private func presentCashier() {
        cashierAmountInput = ""
        borrowSubmitErrorMessage = nil
        withAnimation(.easeOut(duration: 0.2)) {
            isCashierPresented = true
        }
        Task {
            await loadLoanCashierPayToolsIfNeeded(force: receiveBankTools.isEmpty)
        }
    }

    @MainActor
    private func loadLoanCashierPayToolsIfNeeded(force: Bool) async {
        guard force || receiveBankTools.isEmpty else {
            return
        }
        guard let userId, userId > 0 else {
            receiveBankTools = []
            selectedReceiveBankToolCode = nil
            receiveWalletAvailableAmountText = "--"
            isWalletReceiveAccountSelected = false
            return
        }
        isLoadingReceiveBankTools = true
        do {
            let cashierView = try await APIClient.shared.fetchCashierView(userId: userId, sceneCode: "TRADE_PAY_LOAN_ACCOUNT")
            receiveSceneConfiguration = CashierSceneConfiguration.fromServerData(
                cashierView.sceneConfig,
                fallback: CashierSceneConfiguration(
                    supportedChannels: [.wallet, .bankCard],
                    bankCardPolicy: .debitOnly,
                    emptyBankCardText: "暂无可用借记卡"
                )
            )
            receiveBankTools = cashierView.payTools
            if let selectedReceiveBankToolCode,
               receiveBankTools.contains(where: { $0.toolCode == selectedReceiveBankToolCode }) {
                // keep current selection
            } else {
                selectedReceiveBankToolCode = receiveBankTools.first(where: \.defaultSelected)?.toolCode ?? receiveBankTools.first?.toolCode
            }
            if receiveBankTools.isEmpty {
                isWalletReceiveAccountSelected = true
            }
        } catch {
            receiveBankTools = []
            selectedReceiveBankToolCode = nil
            isWalletReceiveAccountSelected = true
        }
        isLoadingReceiveBankTools = false
        await loadLoanCashierWalletBalance(userId: userId)
    }

    @MainActor
    private func loadLoanCashierWalletBalance(userId: Int64) async {
        isLoadingReceiveWalletBalance = true
        do {
            let overview = try await APIClient.shared.fetchAssetOverview(userId: String(userId))
            receiveWalletAvailableAmountText = formatWalletAvailableAmount(overview.availableAmount)
        } catch {
            receiveWalletAvailableAmountText = "--"
        }
        isLoadingReceiveWalletBalance = false
    }

    private func handleCashierKeyInput(_ key: String) {
        guard key.allSatisfy(\.isNumber) else {
            return
        }
        let limitText = maxBorrowAmountText.filter(\.isNumber)
        let maxLength = max(limitText.count, 1)
        var next = cashierAmountInput + key
        while next.count > 1 && next.first == "0" {
            next.removeFirst()
        }
        if next.count > maxLength {
            next = String(next.prefix(maxLength))
        }
        if let nextValue = Decimal(string: next, locale: Locale(identifier: "en_US_POSIX")), nextValue > offer.availableLimit {
            cashierAmountInput = limitText
            return
        }
        cashierAmountInput = next
    }

    private func removeLastCashierInputCharacter() {
        guard !cashierAmountInput.isEmpty else {
            return
        }
        cashierAmountInput.removeLast()
    }

    private func applyCashierMaxAmount() {
        cashierAmountInput = maxBorrowAmountText.filter(\.isNumber)
    }

    private func handleCashierConfirm(amount: Decimal, installmentText: String, receiveAccountText: String) {
        Task {
            await submitBorrow(amount: amount, installmentText: installmentText, receiveAccountText: receiveAccountText)
        }
    }

    @MainActor
    private func submitBorrow(amount: Decimal, installmentText: String, receiveAccountText: String) async {
        guard !isSubmittingBorrow else {
            return
        }
        guard let userId, userId > 0 else {
            borrowSubmitErrorMessage = "未找到当前登录用户"
            return
        }
        guard amount > .zero else {
            borrowSubmitErrorMessage = "借款金额必须大于0"
            return
        }
        if !isWalletReceiveAccountSelected && selectedReceiveBankTool == nil {
            borrowSubmitErrorMessage = isLoadingReceiveBankTools ? "收款账户加载中，请稍后再试" : "请选择收款账户"
            return
        }

        isSubmittingBorrow = true
        borrowSubmitErrorMessage = nil
        presentBorrowProcessingResult(
            amount: amount,
            installmentText: installmentText,
            receiveAccountText: receiveAccountText
        )

        let requestStartedAt = Date()
        do {
            _ = try await APIClient.shared.createLoanAccountPayTrade(
                payerUserId: userId,
                payeeUserId: userId,
                amount: amount,
                metadata: buildLoanBorrowTradeMetadata(
                    installmentText: installmentText,
                    receiveAccountText: receiveAccountText
                )
            )

            let elapsed = Date().timeIntervalSince(requestStartedAt)
            if elapsed < 0.9 {
                let remaining = max(0, 0.9 - elapsed)
                try? await Task.sleep(nanoseconds: UInt64(remaining * 1_000_000_000))
            }

            completeBorrowProcessingResult()
            isSubmittingBorrow = false
            await refreshLoanAccount()
        } catch {
            isSubmittingBorrow = false
            withAnimation(.easeOut(duration: 0.2)) {
                isBorrowDetailPresented = false
                borrowResult = nil
            }
            borrowSubmitErrorMessage = userFacingErrorMessage(error)
        }
    }

    private func buildLoanBorrowTradeMetadata(installmentText: String, receiveAccountText: String) -> String {
        var metadata = [
            "borrowScene=loanAccount",
            "installment=\(sanitizeLoanBorrowMetadataValue(installmentText))",
            "receiveAccount=\(sanitizeLoanBorrowMetadataValue(receiveAccountText))",
            "annualRate=\(formatRate(offer.annualRate))"
        ]
        if isWalletReceiveAccountSelected {
            metadata.append("receiveChannel=WALLET")
        } else {
            metadata.append("receiveChannel=BANK_CARD")
            if let toolCode = selectedReceiveBankTool?.toolCode,
               !toolCode.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                metadata.append("receiveToolCode=\(sanitizeLoanBorrowMetadataValue(toolCode))")
            }
        }
        return metadata.joined(separator: ";")
    }

    private func sanitizeLoanBorrowMetadataValue(_ value: String) -> String {
        value
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .replacingOccurrences(of: ";", with: "，")
            .replacingOccurrences(of: "=", with: "-")
    }

    private func presentBorrowProcessingResult(amount: Decimal, installmentText: String, receiveAccountText: String) {
        let borrowedAt = Date()
        let nextResult = LoanAccountBorrowResult(
            borrowId: generateLoanAccountBorrowId(borrowedAt: borrowedAt, amount: amount),
            amount: amount,
            remainingPrincipalAmount: amount,
            installmentText: installmentText,
            receiveAccountText: receiveAccountText,
            annualRate: offer.annualRate,
            isWalletReceiveAccount: isWalletReceiveAccountSelected,
            receiveBankCode: selectedReceiveBankTool?.bankCode,
            receiveBankName: selectedReceiveBankTool?.toolName,
            lendingInstitutionName: "江苏银行",
            borrowedAt: borrowedAt,
            interestSettledThroughDate: nil,
            status: .processing
        )
        withAnimation(.easeOut(duration: 0.2)) {
            isCashierPresented = false
            isBorrowDetailPresented = false
            borrowResult = nextResult
        }
        onBorrowResultUpdated(nextResult)
    }

    private func completeBorrowProcessingResult() {
        guard var currentResult = borrowResult else {
            return
        }
        currentResult.status = .succeeded
        withAnimation(.easeInOut(duration: 0.25)) {
            borrowResult = currentResult
        }
        if let userId, userId > 0 {
            LoanAccountSyntheticSnapshotStore.recordBorrow(currentResult, userId: userId)
            if let syncedAccount = LoanAccountSyntheticSnapshotStore.loadAccount(userId: userId) {
                loanAccount = syncedAccount
            } else if let currentAccount = loanAccount {
                let normalizedTotalLimit = max(.zero, currentAccount.totalLimit.amount)
                let normalizedCurrentAvailableLimit = min(normalizedTotalLimit, max(.zero, currentAccount.availableLimit.amount))
                let nextAvailableLimit = max(.zero, normalizedCurrentAvailableLimit - max(.zero, currentResult.amount))
                loanAccount = LoanAccountData(
                    accountNo: currentAccount.accountNo,
                    userId: currentAccount.userId,
                    totalLimit: MoneyValueData(
                        amount: normalizedTotalLimit,
                        currencyCode: currentAccount.totalLimit.currencyCode
                    ),
                    availableLimit: MoneyValueData(
                        amount: nextAvailableLimit,
                        currencyCode: currentAccount.availableLimit.currencyCode
                    ),
                    annualRate: currentAccount.annualRate,
                    originalAnnualRate: currentAccount.originalAnnualRate,
                    repayDayOfMonth: currentAccount.repayDayOfMonth,
                    accountStatus: currentAccount.accountStatus,
                    payStatus: currentAccount.payStatus
                )
            }
        }
        onBorrowResultUpdated(currentResult)
    }

    private func dismissBorrowResult() {
        withAnimation(.easeOut(duration: 0.2)) {
            isBorrowDetailPresented = false
            standaloneBorrowDetailResult = nil
            borrowResult = nil
        }
    }

    private func presentBorrowDetail() {
        withAnimation(.easeOut(duration: 0.2)) {
            isBorrowDetailPresented = true
        }
    }

    private func dismissBorrowDetail() {
        withAnimation(.easeOut(duration: 0.2)) {
            isBorrowDetailPresented = false
        }
    }

    private func dismissStandaloneBorrowDetail() {
        withAnimation(.easeOut(duration: 0.2)) {
            standaloneBorrowDetailResult = nil
        }
    }

    private func applyReopenBorrowDetailIfNeeded() {
        guard let reopenBorrowDetailResult else {
            return
        }
        withAnimation(.easeOut(duration: 0.2)) {
            standaloneBorrowDetailResult = reopenBorrowDetailResult
        }
        onConsumeReopenBorrowDetail()
    }

    @MainActor
    private func refreshLoanAccount() async {
        guard let userId, userId > 0 else {
            loanAccount = nil
            return
        }

        do {
            let fetchedAccount = try await APIClient.shared.fetchLoanAccount(userId: userId)
            LoanAccountSyntheticSnapshotStore.saveAccount(fetchedAccount, userId: userId)
            loanAccount = LoanAccountSyntheticSnapshotStore.loadAccount(userId: userId) ?? fetchedAccount
        } catch {
            loanAccount = LoanAccountSyntheticSnapshotStore.loadAccount(userId: userId) ?? .demo(userId: userId)
        }
    }

    private func formatMoney(_ value: Decimal, useGrouping: Bool) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = useGrouping
        formatter.groupingSeparator = ","
        formatter.minimumFractionDigits = 0
        formatter.maximumFractionDigits = 0
        return formatter.string(from: NSDecimalNumber(decimal: value)) ?? NSDecimalNumber(decimal: value).stringValue
    }

    private func formatRate(_ value: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = false
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSDecimalNumber(decimal: value)) ?? "3.24"
    }

    private func formatWalletAvailableAmount(_ raw: String?) -> String {
        let trimmed = raw?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !trimmed.isEmpty,
              let decimal = Decimal(string: trimmed.replacingOccurrences(of: ",", with: ""), locale: Locale(identifier: "en_US_POSIX")) else {
            return "--"
        }
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "zh_CN")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = true
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        let number = NSDecimalNumber(decimal: decimal)
        return "¥" + (formatter.string(from: number) ?? number.stringValue)
    }
    }

private struct LoanAccountCashierSheetView: View {
    private enum InstallmentOption: String, CaseIterable, Identifiable {
        case month3 = "3"
        case month6 = "6"
        case month9 = "9"
        case month12 = "12"
        case month18 = "18"
        case month24Pro = "24"
        case month36Pro = "36"

        var id: String { rawValue }

        var months: String { rawValue }

        var title: String {
            "分\(months)个月"
        }

        var showsProBadge: Bool {
            self == .month24Pro || self == .month36Pro
        }
    }

    private struct BlinkingCaretView: View {
        let height: CGFloat
        let color: Color

        var body: some View {
            TimelineView(.periodic(from: .now, by: 0.5)) { context in
                let tick = Int(context.date.timeIntervalSinceReferenceDate / 0.5)
                RoundedRectangle(cornerRadius: 1, style: .continuous)
                    .fill(color)
                    .frame(width: 2, height: height)
                    .opacity(tick.isMultiple(of: 2) ? 1 : 0)
            }
        }
    }

    let scaleX: CGFloat
    let scaleY: CGFloat
    let fontScale: CGFloat
    let amountInput: String
    let maxBorrowAmountText: String
    let currentRateText: String
    let originalRateText: String
    let selectedBankTool: CashierPayToolData?
    let sceneConfiguration: CashierSceneConfiguration
    let bankTools: [CashierPayToolData]
    let selectedBankToolCode: String?
    let isWalletSelected: Bool
    let walletAvailableAmountText: String
    let isLoadingReceiveBankTools: Bool
    let isLoadingWalletBalance: Bool
    let onClose: () -> Void
    let onTakeAll: () -> Void
    let onInput: (String) -> Void
    let onDelete: () -> Void
    let onSelectWallet: () -> Void
    let onSelectBankTool: (String) -> Void
    let onConfirm: (Decimal, String, String) -> Void

    @State private var isAmountInputFocused = true
    @State private var isInstallmentMenuPresented = false
    @State private var isReceiveToolPickerPresented = false
    @State private var selectedInstallmentOption: InstallmentOption = .month24Pro
    @State private var isAgreementConfirmStepPresented = false
    @State private var isCouponDetailPresented = false

    private let keypadRows: [[String]] = [["1", "2", "3"], ["4", "5", "6"], ["7", "8", "9"], ["", "0", ""]]

    private var amountDecimalValue: Decimal? {
        Decimal(string: amountInput.trimmingCharacters(in: .whitespacesAndNewlines), locale: Locale(identifier: "en_US_POSIX"))
    }

    private var hasValidAmountInput: Bool {
        let trimmed = amountInput.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty,
              let decimal = Decimal(string: trimmed, locale: Locale(identifier: "en_US_POSIX")) else {
            return false
        }
        return decimal > .zero
    }

    private var isReceiveAccountLoading: Bool {
        !isWalletSelected && isLoadingReceiveBankTools
    }

    private var hasResolvedReceiveAccount: Bool {
        isWalletSelected || selectedBankTool != nil
    }

    private var isPrimaryConfirmEnabled: Bool {
        hasValidAmountInput && !isReceiveAccountLoading && hasResolvedReceiveAccount
    }

    private var activePrimaryButtonBackgroundColor: Color {
        if isPrimaryConfirmEnabled {
            return Color(red: 0.09, green: 0.09, blue: 0.36)
        }
        if hasValidAmountInput && (isReceiveAccountLoading || !hasResolvedReceiveAccount) {
            return Color(red: 0.90, green: 0.90, blue: 0.92)
        }
        return Color(red: 0.72, green: 0.70, blue: 0.84)
    }

    private var primaryButtonTextColor: Color {
        if isPrimaryConfirmEnabled {
            return Color(red: 0.95, green: 0.84, blue: 0.68)
        }
        if hasValidAmountInput && (isReceiveAccountLoading || !hasResolvedReceiveAccount) {
            return Color(red: 0.16, green: 0.16, blue: 0.20)
        }
        return Color(red: 0.20, green: 0.18, blue: 0.28)
    }

    private var selectedInstallmentDisplayText: String {
        if selectedInstallmentOption.showsProBadge {
            return selectedInstallmentOption.title + " Pro"
        }
        return selectedInstallmentOption.title
    }

    private var agreementInstallmentDetailText: String {
        let prefix = selectedInstallmentOption.showsProBadge ? "Pro " : ""
        return prefix + selectedInstallmentOption.title + "，首期还" + estimatedFirstRepaymentText
    }

    private var agreementDiscountAmountText: String {
        guard let amountDecimalValue, amountDecimalValue > .zero else {
            return "0.00"
        }
        let installmentText = selectedInstallmentOption.title
        let currentQuote = LoanAccountRepaymentCalculator.quote(
            currentPrincipal: amountDecimalValue,
            annualRatePercent: decimalFromString(currentRateText),
            installmentText: installmentText,
            borrowedAt: nil
        )
        let originalQuote = LoanAccountRepaymentCalculator.quote(
            currentPrincipal: amountDecimalValue,
            annualRatePercent: decimalFromString(originalRateText),
            installmentText: installmentText,
            borrowedAt: nil
        )
        let savings = max(.zero, originalQuote.totalInterest - currentQuote.totalInterest)
        return formatTwoDigitsMoney(savings)
    }

    private var agreementDiscountText: String {
        "省" + agreementDiscountAmountText
    }

    private var agreementBankNameText: String {
        "江苏银行"
    }

