    private func decimalFromString(_ text: String) -> Decimal {
        Decimal(string: text, locale: Locale(identifier: "en_US_POSIX")) ?? .zero
    }

    private func formatTwoDigitsMoney(_ amount: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = false
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSDecimalNumber(decimal: amount)) ?? "0.00"
    }

    private var estimatedFirstRepaymentText: String {
        guard let amountDecimalValue else {
            return "0.00"
        }
        let monthsDecimal = Decimal(string: selectedInstallmentOption.months, locale: Locale(identifier: "en_US_POSIX")) ?? 1
        let monthlyPrincipal = amountDecimalValue / monthsDecimal
        let monthlyInterest = amountDecimalValue * decimalFromString(currentRateText) / Decimal(100) / Decimal(12)
        return formatTwoDigitsMoney(monthlyPrincipal + monthlyInterest)
    }

