    private func bankTitle(for tool: CashierPayToolData) -> String {
        let tail = cardTailNo(from: tool)
        let cardName = simplifiedBankCardName(from: tool.toolName)
        if tail.isEmpty {
            return cardName
        }
        return cardName + "(\(tail))"
    }

    private func bankSubtitle(for tool: CashierPayToolData) -> String {
        let limit = singleLimitAmountText(from: tool)
        if limit == "0" {
            return tool.toolDescription.trimmingCharacters(in: .whitespacesAndNewlines)
        }
        return "银行单笔限额\(limit)元"
    }

    private func simplifiedBankCardName(from toolName: String) -> String {
        let original = cardNamePart(from: toolName)
        return BankLogoCatalog.fullDisplayName(bankCode: nil, bankName: original)
    }

    private func cardNamePart(from toolName: String) -> String {
        let normalized = toolName
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .replacingOccurrences(of: "（", with: "(")
            .replacingOccurrences(of: "）", with: ")")
        guard !normalized.isEmpty else {
            return "借记卡"
        }
        if let range = normalized.range(of: "(尾号") {
            return String(normalized[..<range.lowerBound])
        }
        return normalized
    }

    private func cardTailNo(from tool: CashierPayToolData) -> String {
        let normalized = tool.toolName
            .replacingOccurrences(of: "（", with: "(")
            .replacingOccurrences(of: "）", with: ")")
        if let range = normalized.range(of: "(尾号"),
           let closeIndex = normalized[range.upperBound...].firstIndex(of: ")") {
            let inner = normalized[range.upperBound..<closeIndex]
            let digits = inner.replacingOccurrences(of: "\\D", with: "", options: .regularExpression)
            if digits.count >= 4 {
                return String(digits.suffix(4))
            }
        }
        let codeDigits = tool.toolCode.replacingOccurrences(of: "\\D", with: "", options: .regularExpression)
        if codeDigits.count >= 4 {
            return String(codeDigits.suffix(4))
        }
        return ""
    }

    private func singleLimitAmountText(from tool: CashierPayToolData) -> String {
        let description = tool.toolDescription
        if let range = description.range(of: "单笔限额") {
            let suffix = description[range.upperBound...]
            let fragment = suffix.split(separator: "，", maxSplits: 1).first.map(String.init) ?? ""
            let number = fragment.replacingOccurrences(of: "^[^0-9]*([0-9]+(?:\\.[0-9]+)?)?.*$", with: "$1", options: .regularExpression)
            let trimmed = number.trimmingCharacters(in: .whitespacesAndNewlines)
            if !trimmed.isEmpty, let decimal = Decimal(string: trimmed) {
                let formatter = NumberFormatter()
                formatter.locale = Locale(identifier: "en_US_POSIX")
                formatter.numberStyle = .decimal
                formatter.usesGroupingSeparator = false
                formatter.minimumFractionDigits = 0
                formatter.maximumFractionDigits = 2
                let value = NSDecimalNumber(decimal: decimal)
                return formatter.string(from: value) ?? value.stringValue
            }
        }
        return "0"
    }

    private func toggleInstallmentMenu() {
        isAmountInputFocused = false
        withAnimation(.easeOut(duration: 0.2)) {
            isCouponDetailPresented = false
            isReceiveToolPickerPresented = false
            isInstallmentMenuPresented.toggle()
        }
    }

    private func openReceiveToolPicker() {
        isAmountInputFocused = false
        withAnimation(.easeOut(duration: 0.2)) {
            isCouponDetailPresented = false
            isInstallmentMenuPresented = false
            isReceiveToolPickerPresented = true
        }
    }

    private func focusAmountInput() {
        isAmountInputFocused = true
        withAnimation(.easeOut(duration: 0.2)) {
            isCouponDetailPresented = false
            isAgreementConfirmStepPresented = false
            isInstallmentMenuPresented = false
            isReceiveToolPickerPresented = false
        }
    }

    private func openCouponDetail() {
        isAmountInputFocused = false
        withAnimation(.easeOut(duration: 0.22)) {
            isInstallmentMenuPresented = false
            isReceiveToolPickerPresented = false
            isCouponDetailPresented = true
        }
    }

    private func cashierInfoRow<Content: View>(title: String, @ViewBuilder content: () -> Content) -> some View {
        HStack {
            Text(title)
                .font(.system(size: 16 * fontScale, weight: .medium))
                .foregroundStyle(Color(red: 0.27, green: 0.27, blue: 0.29))
            Spacer(minLength: 12 * scaleX)
            content()
        }
        .padding(.horizontal, 20 * scaleX)
        .frame(height: 42 * scaleY)
    }
    }


enum CashierChannelKind: String, Equatable {
    case wallet
    case fund
    case aiCredit = "aicredit"
    case bankCard

    init?(serverCode: String) {
        switch serverCode.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() {
        case "WALLET":
            self = .wallet
        case "FUND":
            self = .fund
        case "AICREDIT":
            self = .aiCredit
        case "BANK_CARD":
            self = .bankCard
        default:
            return nil
        }
    }

    var defaultTitle: String {
        switch self {
        case .wallet:
            return "账户余额"
        case .fund:
            return "爱存"
        case .aiCredit:
            return "爱花"
        case .bankCard:
            return "银行卡"
        }
    }
    }

enum CashierBankCardPolicy: Equatable {
    case allCards
    case debitOnly
    case creditOnly

    init?(serverCode: String) {
        switch serverCode.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() {
        case "ALL_CARDS", "ALL":
            self = .allCards
        case "DEBIT_ONLY", "DEBIT":
            self = .debitOnly
        case "CREDIT_ONLY", "CREDIT":
            self = .creditOnly
        default:
            return nil
        }
    }
    }

struct CashierSceneConfiguration: Equatable {
    let supportedChannels: [CashierChannelKind]
    let bankCardPolicy: CashierBankCardPolicy
    let emptyBankCardText: String

    // 转账收银台固定展示余额、爱存与借记卡，避免信用卡/爱花在该场景误展示。
    static let transfer = CashierSceneConfiguration(
        supportedChannels: [.wallet, .fund, .bankCard],
        bankCardPolicy: .debitOnly,
        emptyBankCardText: "暂无可用银行卡"
    )

    // 爱花还款收银台支持账户余额、爱存和借记卡三类渠道。
    static let creditRepay = CashierSceneConfiguration(
        supportedChannels: [.wallet, .fund, .bankCard],
        bankCardPolicy: .debitOnly,
        emptyBankCardText: "暂无可用银行卡"
    )

    // 红包收银台仅开放账户余额、爱存与储蓄卡，不展示爱花与信用卡。
    static let redPacketSend = CashierSceneConfiguration(
        supportedChannels: [.wallet, .fund, .bankCard],
        bankCardPolicy: .debitOnly,
        emptyBankCardText: "暂无可用银行卡"
    )

    static let mobileHallTopUp = CashierSceneConfiguration(
        supportedChannels: [.wallet, .fund, .aiCredit, .bankCard],
        bankCardPolicy: .allCards,
        emptyBankCardText: "暂无可用银行卡"
    )

    func supports(_ channelKind: CashierChannelKind) -> Bool {
        supportedChannels.contains(channelKind)
    }

    static func fromServerData(
        _ data: CashierSceneConfigurationData?,
        fallback: CashierSceneConfiguration
    ) -> CashierSceneConfiguration {
        guard let data else {
            return fallback
        }
        let supportedChannels = data.supportedChannels.compactMap(CashierChannelKind.init(serverCode:))
        let bankCardPolicy = data.bankCardPolicy.flatMap(CashierBankCardPolicy.init(serverCode:)) ?? fallback.bankCardPolicy
        let emptyBankCardText = data.emptyBankCardText?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false
            ? data.emptyBankCardText!.trimmingCharacters(in: .whitespacesAndNewlines)
            : fallback.emptyBankCardText
        return CashierSceneConfiguration(
            supportedChannels: supportedChannels.isEmpty ? fallback.supportedChannels : supportedChannels,
            bankCardPolicy: bankCardPolicy,
            emptyBankCardText: emptyBankCardText
        )
    }
    }

private enum CashierChannelAvailability {
    private static let unavailableFundStatuses: Set<String> = [
        "CLOSED",
        "INACTIVE",
        "FROZEN",
        "DISABLED",
        "UNOPENED",
        "NOT_OPEN"
    ]

    static func isFundAccountAvailable(_ account: FundAccountData?) -> Bool {
        guard let account else {
            return false
        }
        let normalizedStatus = account.accountStatus
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .uppercased()
        if normalizedStatus.isEmpty {
            return true
        }
        return !unavailableFundStatuses.contains(normalizedStatus)
    }

    static func filteredSceneConfiguration(
        _ sceneConfiguration: CashierSceneConfiguration,
        hasFundAvailable: Bool,
        hasAiCreditAvailable: Bool
    ) -> CashierSceneConfiguration {
        let filteredChannels = sceneConfiguration.supportedChannels.filter { channel in
            switch channel {
            case .fund:
                return hasFundAvailable
            case .aiCredit:
                return hasAiCreditAvailable
            case .wallet, .bankCard:
                return true
            }
        }
        return CashierSceneConfiguration(
            supportedChannels: filteredChannels,
            bankCardPolicy: sceneConfiguration.bankCardPolicy,
            emptyBankCardText: sceneConfiguration.emptyBankCardText
        )
    }
}

private struct CashierPaymentToolDescriptor: Identifiable {
    let id: String
    let channelKind: CashierChannelKind
    let title: String
    let detail: String
    let bankTool: CashierPayToolData?
    let accessibilityIdentifier: String
    }

enum CashierPresentationHelper {
    static func filteredBankTools(
        _ tools: [CashierPayToolData],
        policy: CashierBankCardPolicy
    ) -> [CashierPayToolData] {
        tools.filter { tool in
            isBankCardTool(tool) && matchesBankCardPolicy(tool, policy: policy)
        }
    }

    static func isBankCardTool(_ tool: CashierPayToolData) -> Bool {
        tool.toolType.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() == "BANK_CARD"
    }

    static func matchesBankCardPolicy(
        _ tool: CashierPayToolData,
        policy: CashierBankCardPolicy
    ) -> Bool {
        switch policy {
        case .allCards:
            return true
        case .debitOnly:
            let normalized = normalizedCardType(for: tool)
            return normalized.isEmpty || normalized == "DEBIT"
        case .creditOnly:
            return normalizedCardType(for: tool) == "CREDIT"
        }
    }

    static func normalizedCardType(for tool: CashierPayToolData) -> String {
        let explicitType = tool.cardType?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() ?? ""
        if !explicitType.isEmpty {
            return explicitType
        }
        let toolName = tool.toolName.trimmingCharacters(in: .whitespacesAndNewlines)
        if toolName.contains("信用卡") {
            return "CREDIT"
        }
        if toolName.contains("借记卡") || toolName.contains("储蓄卡") {
            return "DEBIT"
        }
        return ""
    }

    static func bankDisplayName(
        for tool: CashierPayToolData,
        replaceDebitWithSavings: Bool = false,
        stripCardTypeWords: Bool = false
    ) -> String {
        let rawName = tool.toolName
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .replacingOccurrences(of: "（", with: "(")
            .replacingOccurrences(of: "）", with: ")")
        guard !rawName.isEmpty else {
            return "银行卡"
        }

        var namePart = rawName
        var tail = ""
        if let range = rawName.range(of: "(尾号"),
           let closeIndex = rawName[range.upperBound...].firstIndex(of: ")") {
            namePart = String(rawName[..<range.lowerBound]).trimmingCharacters(in: .whitespacesAndNewlines)
            let inner = rawName[range.upperBound..<closeIndex]
            tail = inner.replacingOccurrences(of: "\\D", with: "", options: .regularExpression)
        } else if let openIndex = rawName.lastIndex(of: "("),
                  let closeIndex = rawName[openIndex...].firstIndex(of: ")"),
                  openIndex < closeIndex {
            namePart = String(rawName[..<openIndex]).trimmingCharacters(in: .whitespacesAndNewlines)
            let inner = rawName[rawName.index(after: openIndex)..<closeIndex]
            tail = inner.replacingOccurrences(of: "\\D", with: "", options: .regularExpression)
        }
        if tail.isEmpty {
            let codeDigits = tool.toolCode.replacingOccurrences(of: "\\D", with: "", options: .regularExpression)
            if codeDigits.count >= 4 {
                tail = String(codeDigits.suffix(4))
            }
        }

        var compactName = simplifiedBankName(from: namePart)
        if replaceDebitWithSavings {
            compactName = compactName.replacingOccurrences(of: "借记卡", with: "储蓄卡")
        }
        if stripCardTypeWords {
            compactName = compactName
                .replacingOccurrences(of: "储蓄卡", with: "")
                .replacingOccurrences(of: "借记卡", with: "")
                .replacingOccurrences(of: "信用卡", with: "")
        }
        compactName = compactName
            .replacingOccurrences(of: "银行卡", with: "")
            .trimmingCharacters(in: .whitespacesAndNewlines)

        if compactName.isEmpty {
            return tail.isEmpty ? "银行卡" : "银行卡(\(tail))"
        }
        return tail.isEmpty ? compactName : "\(compactName)(\(tail))"
    }

    static func bankSubtitle(
        for tool: CashierPayToolData,
        fallbackText: String = "银行卡"
    ) -> String {
        let limit = singleLimitAmountText(from: tool)
        if limit == "0" {
            let normalized = tool.toolDescription.trimmingCharacters(in: .whitespacesAndNewlines)
            return normalized.isEmpty ? fallbackText : normalized
        }
        return "银行单笔限额\(limit)元"
    }

    static func availableDetailText(
        availableAmountText: String,
        isLoading: Bool
    ) -> String {
        if isLoading {
            return "可用: 加载中..."
        }
        if availableAmountText == "--" {
            return "可用: --"
        }
        return "可用: \(availableAmountText)"
    }

    static func simplifiedBankName(from toolName: String) -> String {
        BankLogoCatalog.fullDisplayName(bankCode: nil, bankName: toolName)
    }

    static func singleLimitAmountText(from tool: CashierPayToolData) -> String {
        let description = tool.toolDescription
        if let range = description.range(of: "单笔限额") {
            let suffix = description[range.upperBound...]
            let fragment = suffix.split(separator: "，", maxSplits: 1).first.map(String.init) ?? ""
            let number = fragment.replacingOccurrences(
                of: #"^[^0-9]*([0-9]+(?:\.[0-9]+)?)?.*$"#,
                with: "$1",
                options: .regularExpression
            )
            let trimmed = number.trimmingCharacters(in: .whitespacesAndNewlines)
            if !trimmed.isEmpty, let decimal = Decimal(string: trimmed) {
                let formatter = NumberFormatter()
                formatter.locale = Locale(identifier: "en_US_POSIX")
                formatter.numberStyle = .decimal
                formatter.usesGroupingSeparator = false
                formatter.minimumFractionDigits = 0
                formatter.maximumFractionDigits = 2
                let value = NSDecimalNumber(decimal: decimal)
                return formatter.string(from: value) ?? value.stringValue
            }
        }
        return "0"
    }
    }

