                Image("RepayFundToolIcon")
                    .resizable()
                    .interpolation(.high)
                    .scaledToFit()
                    .frame(width: size * 0.75, height: size * 0.75)
            case .aiCredit:
                Image("AiCreditToolIcon")
                    .resizable()
                    .interpolation(.high)
