struct CashierReferenceBankRowsOverlayView: View {
    let bankTools: [CashierPayToolData]
    let selectedToolCode: String?
    let rowLayouts: [CashierReferenceBankRowLayout]
    let textCenterX: CGFloat
    let textWidth: CGFloat
    let textHeight: CGFloat
    let iconCenterX: CGFloat
    let iconSlotWidth: CGFloat
    let iconSlotHeight: CGFloat
    let iconSize: CGFloat
    let checkmarkCenterX: CGFloat
    let scaleX: CGFloat
    let scaleY: CGFloat
    let fontScale: CGFloat
    let fontProvider: (CGFloat) -> Font
    let textFormatter: (CashierPayToolData) -> String
    let textColor: Color
    let checkmarkColor: Color

    private var selectedRowIndex: Int? {
        guard let selectedToolCode else {
            return nil
        }
        let normalizedSelectedToolCode = selectedToolCode.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedSelectedToolCode.isEmpty else {
            return nil
        }
        return bankTools.firstIndex(where: { tool in
            tool.toolCode == normalizedSelectedToolCode
        })
    }

    var body: some View {
        ZStack {
            ForEach(Array(rowLayouts.enumerated()), id: \.element.id) { index, layout in
                let rowTool: CashierPayToolData? = bankTools.indices.contains(index) ? bankTools[index] : nil
                let isSelectedRow = rowTool != nil && selectedRowIndex == index

                ZStack {
                    if let iconBackgroundColor = layout.iconBackgroundColor {
                        RoundedRectangle(cornerRadius: 8 * fontScale, style: .continuous)
                            .fill(iconBackgroundColor)
                            .frame(width: iconSlotWidth * scaleX, height: iconSlotHeight * scaleY)
                    }

                    if let rowTool {
                        CashierChannelIconView(
                            channelKind: .bankCard,
                            bankTool: rowTool,
                            size: iconSize * min(scaleX, scaleY),
                            cornerRadius: 6 * fontScale
                        )
                    }
                }
                .frame(width: iconSlotWidth * scaleX, height: iconSlotHeight * scaleY)
                .position(x: iconCenterX * scaleX, y: layout.iconCenterY * scaleY)

                CashierReferenceTextReplacementSlotView(
                    text: rowTool.map(textFormatter) ?? "",
                    centerX: textCenterX,
                    centerY: layout.textCenterY,
                    width: textWidth,
                    height: textHeight,
                    scaleX: scaleX,
                    scaleY: scaleY,
                    font: fontProvider(layout.textFontSize * fontScale),
                    textColor: textColor,
                    backgroundColor: layout.textBackgroundColor,
                    horizontalPadding: 8,
                    isTrailingAligned: false
                )

                Rectangle()
                    .fill(layout.textBackgroundColor)
                    .frame(width: 62 * scaleX, height: textHeight * scaleY)
                    .position(x: checkmarkCenterX * scaleX, y: layout.checkmarkCenterY * scaleY)

                if isSelectedRow {
                    Image(systemName: "checkmark")
                        .font(.system(size: 20 * fontScale, weight: .semibold))
                        .foregroundStyle(checkmarkColor)
                        .frame(width: 24 * scaleX, height: 24 * scaleY)
                        .position(x: checkmarkCenterX * scaleX, y: layout.checkmarkCenterY * scaleY)
                }
            }
        }
    }
    }

