                                .foregroundStyle(Color(red: 0.32, green: 0.32, blue: 0.34))
                            Text(" ")
                            Text(originalRateText)
                                .font(.system(size: 13 * fontScale, weight: .medium))
                                .foregroundStyle(Color(red: 0.73, green: 0.73, blue: 0.75))
                                .strikethrough(true, color: Color(red: 0.73, green: 0.73, blue: 0.75))
                            Text("%")
                                .font(.system(size: 13 * fontScale, weight: .medium))
                                .foregroundStyle(Color(red: 0.73, green: 0.73, blue: 0.75))
                                .strikethrough(true, color: Color(red: 0.73, green: 0.73, blue: 0.75))
                        }

                        HStack(spacing: 0) {
                            Text("借")
                            Text(installmentText)
                            Text(" 省利息")
                            Text(savingsText)
                                .foregroundStyle(Color(red: 0.97, green: 0.46, blue: 0.20))
                        }
                        .font(.system(size: 13 * fontScale, weight: .medium))
                        .foregroundStyle(Color(red: 0.58, green: 0.58, blue: 0.60))

                        Text("有效期至" + expirationDateText)
                            .font(.system(size: 12 * fontScale, weight: .medium))
                            .foregroundStyle(Color(red: 0.66, green: 0.66, blue: 0.68))
                    }
                    .padding(.leading, 12 * scaleX)
                    .padding(.vertical, 14 * scaleY)

                    Spacer(minLength: 10 * scaleX)

                    Image(systemName: "checkmark.circle.fill")
                        .font(.system(size: 24 * fontScale, weight: .semibold))
                        .foregroundStyle(AppTheme.palette.brandBorder)
                        .padding(.trailing, 14 * scaleX)
                }
                .frame(height: 96 * scaleY)
                .background(
                    RoundedRectangle(cornerRadius: 10 * min(scaleX, scaleY), style: .continuous)
                        .fill(Color.white)
                )
                .padding(.top, 4 * scaleY)
                .padding(.horizontal, 12 * scaleX)

                Spacer(minLength: 0)
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .top)
        }
        .frame(maxWidth: .infinity)
        .frame(height: 654 * scaleY)
        .background(
            RoundedRectangle(cornerRadius: 24 * min(scaleX, scaleY), style: .continuous)
                .fill(Color(red: 0.97, green: 0.97, blue: 0.98))
        )
        .clipShape(RoundedRectangle(cornerRadius: 24 * min(scaleX, scaleY), style: .continuous))
        .transition(.move(edge: .bottom).combined(with: .opacity))
    }
}

private struct LoanAccountReceiveToolPickerSheetView: View {
    let scaleX: CGFloat
    let scaleY: CGFloat
    let fontScale: CGFloat
    let sceneConfiguration: CashierSceneConfiguration
    let bankTools: [CashierPayToolData]
    let selectedBankToolCode: String?
    let isWalletSelected: Bool
    let walletAvailableAmountText: String
    let fundAvailableAmountText: String = "--"
    let isLoadingWalletBalance: Bool
    let isLoadingFundBalance: Bool = false
    let isLoadingBankTools: Bool
    let onClose: () -> Void
    let onSelectWallet: () -> Void
    let onSelectBankTool: (String) -> Void


    var body: some View {
        ZStack(alignment: .bottom) {
            Color.black.opacity(0.18)
                .ignoresSafeArea()
                .onTapGesture(perform: onClose)

            VStack(spacing: 0) {
                HStack {
                    Text("选择收款账户")
                        .font(.system(size: 18 * fontScale, weight: .semibold))
                        .foregroundStyle(Color(red: 0.16, green: 0.16, blue: 0.17))
                    Spacer()
                    Button(action: onClose) {
                        Image(systemName: "xmark")
                            .font(.system(size: 16 * fontScale, weight: .regular))
                            .foregroundStyle(Color(red: 0.42, green: 0.43, blue: 0.45))
                            .frame(width: 28 * scaleX, height: 28 * scaleY)
                    }
                    .buttonStyle(.plain)
                }
                .padding(.horizontal, 18 * scaleX)
                .padding(.top, 18 * scaleY)
                .padding(.bottom, 12 * scaleY)

                ScrollView(showsIndicators: false) {
                    VStack(spacing: 0) {
                        walletRow
                        Divider().overlay(Color(red: 0.93, green: 0.93, blue: 0.95))

                        if isLoadingBankTools && bankTools.isEmpty {
                            Text("加载中...")
                                .font(.system(size: 15 * fontScale, weight: .medium))
                                .foregroundStyle(Color(red: 0.57, green: 0.57, blue: 0.58))
                                .frame(maxWidth: .infinity)
                                .frame(height: 68 * scaleY)
                        } else {
                            ForEach(Array(bankTools.enumerated()), id: \.offset) { index, tool in
                                bankRow(tool, index: index)
                                if index != bankTools.count - 1 {
                                    Divider().overlay(Color(red: 0.93, green: 0.93, blue: 0.95))
                                }
                            }
                        }
                    }
                }
                .frame(maxHeight: 316 * scaleY)
            }
            .frame(maxWidth: .infinity)
            .frame(height: 420 * scaleY)
            .background(
                RoundedRectangle(cornerRadius: 24 * min(scaleX, scaleY), style: .continuous)
                    .fill(Color.white)
            )
            .clipShape(RoundedRectangle(cornerRadius: 24 * min(scaleX, scaleY), style: .continuous))
        }
    }

    private var walletRow: some View {
        Button(action: onSelectWallet) {
            CashierPaymentToolRowView(
                descriptor: CashierPaymentToolDescriptor(
                    id: CashierChannelKind.wallet.rawValue,
                    channelKind: .wallet,
                    title: CashierChannelKind.wallet.defaultTitle,
                    detail: walletDetailText,
                    bankTool: nil,
                    accessibilityIdentifier: "loan_cashier_receive_wallet"
                ),
                isSelected: isWalletSelected,
                scaleX: scaleX,
                scaleY: scaleY,
                fontScale: fontScale
            )
        }
        .buttonStyle(.plain)
        .accessibilityIdentifier("loan_cashier_receive_wallet")
    }

    private func bankRow(_ tool: CashierPayToolData, index: Int) -> some View {
        Button(action: {
            onSelectBankTool(tool.toolCode)
        }) {
            CashierPaymentToolRowView(
                descriptor: CashierPaymentToolDescriptor(
                    id: tool.toolCode,
                    channelKind: .bankCard,
                    title: CashierPresentationHelper.bankDisplayName(for: tool),
                    detail: CashierPresentationHelper.bankSubtitle(for: tool, fallbackText: "银行卡"),
                    bankTool: tool,
                    accessibilityIdentifier: "loan_cashier_receive_bank_\(tool.toolCode)"
                ),
                isSelected: selectedBankRowIndex == index && !isWalletSelected,
                scaleX: scaleX,
                scaleY: scaleY,
                fontScale: fontScale
            )
        }
        .buttonStyle(.plain)
        .accessibilityIdentifier("loan_cashier_receive_bank_\(tool.toolCode)")
    }

    private var selectedBankRowIndex: Int? {
        guard let selectedBankToolCode else {
            return nil
        }
        let normalizedSelectedBankToolCode = selectedBankToolCode.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedSelectedBankToolCode.isEmpty else {
            return nil
        }
        return bankTools.firstIndex(where: { tool in
            tool.toolCode == normalizedSelectedBankToolCode
        })
    }

    private var walletDetailText: String {
        if isLoadingWalletBalance {
            return "可用: 加载中..."
        }
        if walletAvailableAmountText == "--" {
            return "可用: --"
        }
        return "可用: \(walletAvailableAmountText)"
    }

    @ViewBuilder
    private func walletIcon(size: CGFloat) -> some View {
        ZStack {
            Circle()
                .fill(
                    LinearGradient(
                        colors: [
                            AppTheme.palette.brandPrimaryLight,
                            AppTheme.palette.brandPrimary
                        ],
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    )
                )
                .frame(width: size, height: size)

            Text("余")
                .font(.system(size: max(12, size * 0.46), weight: .bold))
                .foregroundStyle(Color.white)
        }
    }

    private func bankTitle(for tool: CashierPayToolData) -> String {
        let tail = cardTailNo(from: tool)
        let cardName = simplifiedBankCardName(from: tool.toolName)
        if tail.isEmpty {
            return cardName
        }
        return cardName + "(\(tail))"
    }

    private func bankSubtitle(for tool: CashierPayToolData) -> String {
        let limit = singleLimitAmountText(from: tool)
        if limit == "0" {
            return tool.toolDescription.trimmingCharacters(in: .whitespacesAndNewlines)
        }
        return "银行单笔限额\(limit)元"
    }

    private func simplifiedBankCardName(from toolName: String) -> String {
        let original = cardNamePart(from: toolName)
        return BankLogoCatalog.fullDisplayName(bankCode: nil, bankName: original)
    }

    private func cardNamePart(from toolName: String) -> String {
        let normalized = toolName
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .replacingOccurrences(of: "（", with: "(")
            .replacingOccurrences(of: "）", with: ")")
        guard !normalized.isEmpty else {
            return "借记卡"
        }
        if let range = normalized.range(of: "(尾号") {
            return String(normalized[..<range.lowerBound])
        }
        return normalized
    }

    private func cardTailNo(from tool: CashierPayToolData) -> String {
        let normalized = tool.toolName
            .replacingOccurrences(of: "（", with: "(")
            .replacingOccurrences(of: "）", with: ")")
        if let range = normalized.range(of: "(尾号"),
           let closeIndex = normalized[range.upperBound...].firstIndex(of: ")") {
            let inner = normalized[range.upperBound..<closeIndex]
            let digits = inner.replacingOccurrences(of: "\\D", with: "", options: .regularExpression)
            if digits.count >= 4 {
                return String(digits.suffix(4))
            }
        }
        let codeDigits = tool.toolCode.replacingOccurrences(of: "\\D", with: "", options: .regularExpression)
        if codeDigits.count >= 4 {
            return String(codeDigits.suffix(4))
        }
        return ""
    }

    private func singleLimitAmountText(from tool: CashierPayToolData) -> String {
        let description = tool.toolDescription
        if let range = description.range(of: "单笔限额") {
            let suffix = description[range.upperBound...]
            let fragment = suffix.split(separator: "，", maxSplits: 1).first.map(String.init) ?? ""
            let number = fragment.replacingOccurrences(of: "^[^0-9]*([0-9]+(?:\\.[0-9]+)?)?.*$", with: "$1", options: .regularExpression)
            let trimmed = number.trimmingCharacters(in: .whitespacesAndNewlines)
            if !trimmed.isEmpty, let decimal = Decimal(string: trimmed) {
                let formatter = NumberFormatter()
                formatter.locale = Locale(identifier: "en_US_POSIX")
                formatter.numberStyle = .decimal
                formatter.usesGroupingSeparator = false
                formatter.minimumFractionDigits = 0
                formatter.maximumFractionDigits = 2
                let value = NSDecimalNumber(decimal: decimal)
                return formatter.string(from: value) ?? value.stringValue
            }
        }
        return "0"
    }
    }

