            VStack(spacing: 7 * fontScale) {
                ZStack {
                    Circle()
                        .fill(headerAmountColor)
                        .frame(width: 30 * fontScale, height: 30 * fontScale)

                    Image(systemName: result.isProcessing ? "clock.fill" : "checkmark")
                        .font(.system(size: 14 * fontScale, weight: .bold))
                        .foregroundStyle(statusBackgroundColor)
