                    LoanAccountProcessingTitleView(fontScale: fontScale, textColor: headerAmountColor)
                } else {
                    Text("借款已到账")
                        .font(.system(size: 17 * fontScale, weight: .semibold))
                        .foregroundStyle(headerAmountColor)
                }
