    private func detailLabel(
        text: String,
        centerY: CGFloat,
        scaleX: CGFloat,
        fontScale: CGFloat,
        color: Color
    ) -> some View {
        Text(text)
            .font(.system(size: 14 * fontScale, weight: .regular))
            .foregroundStyle(color)
            .frame(width: 128 * scaleX, alignment: .leading)
            .position(x: 83 * scaleX, y: centerY)
    }

    private var repaymentSummaryText: String {
        "该笔额度将分\(remainingInstallmentText)还完"
    }

    private var remainingInstallmentText: String {
        "\(LoanAccountRepaymentCalculator.remainingInstallmentCount(from: result.installmentText, borrowedAt: result.borrowedAt))期"
    }

    private var contractPeriodText: String {
        let calendar = Calendar(identifier: .gregorian)
        let startDate = calendar.startOfDay(for: result.borrowedAt)
        let installmentMonths = extractInstallmentMonths(from: result.installmentText)
        let endBaseDate = calendar.date(byAdding: .month, value: installmentMonths, to: startDate) ?? startDate
        let endDate = calendar.date(byAdding: .day, value: -7, to: endBaseDate) ?? endBaseDate
        return "\(formatDate(startDate)) 至 \(formatDate(endDate))"
    }

    private func extractInstallmentMonths(from text: String) -> Int {
        let pattern = #"(\d+)个月"#
        guard let regex = try? NSRegularExpression(pattern: pattern) else {
            return 24
        }
        let range = NSRange(text.startIndex..<text.endIndex, in: text)
        guard let match = regex.firstMatch(in: text, options: [], range: range),
              let valueRange = Range(match.range(at: 1), in: text),
              let months = Int(text[valueRange]),
              months > 0 else {
            return 24
        }
        return months
    }

    private func formatDate(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.timeZone = TimeZone(identifier: "Asia/Shanghai")
        formatter.dateFormat = "yyyy-MM-dd"
        return formatter.string(from: date)
    }

    private func formatAmountWithTwoFractions(_ amount: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = false
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        let number = NSDecimalNumber(decimal: amount)
        return formatter.string(from: number) ?? number.stringValue
    }
    }


