    private var displayBorrowResults: [LoanAccountBorrowResult] {
        borrowResults.sorted { $0.borrowedAt > $1.borrowedAt }
    }

    private var selectedBorrowResult: LoanAccountBorrowResult? {
        if let selectedBorrowId,
           let matchedBorrowResult = displayBorrowResults.first(where: { $0.borrowId == selectedBorrowId }) {
            return matchedBorrowResult
        }
        if let initialSelectedBorrowId,
           let matchedBorrowResult = displayBorrowResults.first(where: { $0.borrowId == initialSelectedBorrowId }) {
            return matchedBorrowResult
        }
        return displayBorrowResults.first
    }

    private var outstandingPrincipalAmount: Decimal? {
        let principal = repaymentQuote?.outstandingPrincipal ?? selectedBorrowResult?.outstandingPrincipalAmount ?? .zero
        return principal > .zero ? principal : nil
    }

    private var outstandingPrincipalAmountText: String {
        guard let outstandingPrincipalAmount else {
            return "--"
        }
        return formatMoney(outstandingPrincipalAmount, useGrouping: false)
    }

    private var repayInterestAmount: Decimal {
        repaymentQuote?.accruedInterest ?? .zero
    }

    private var repayTotalAmount: Decimal {
        (outstandingPrincipalAmount ?? .zero) + repayInterestAmount
    }

    private var periodSummaryText: String {
        guard selectedBorrowResult != nil else {
            return "暂无待还借款"
        }
        return "还剩 \(remainingInstallmentCount)期 可还完〉"
    }

    private var borrowDetailText: String {
        let amountText = selectedBorrowResult.map { formatMoney($0.amount, useGrouping: false) + "元" } ?? "--"
        return "\(borrowDateText) 借\(amountText) | 每月等额"
    }

    private var summaryText: String {
        guard outstandingPrincipalAmount != nil else {
            return "合计 -- 含利息 --"
        }
        return "合计 \(formatMoney(repayTotalAmount, useGrouping: false)) 含利息 \(formatMoney(repayInterestAmount, useGrouping: false))"
    }

    private var borrowDateText: String {
        guard let selectedBorrowResult else {
            return "--"
        }
        return formatBorrowDate(selectedBorrowResult.borrowedAt)
    }

    private var remainingInstallmentCount: Int {
        LoanAccountRepaymentCalculator.remainingInstallmentCount(
            from: selectedBorrowResult?.installmentText,
            borrowedAt: selectedBorrowResult?.borrowedAt
        )
    }

    private var repaymentQuote: LoanAccountRepaymentCalculator.Quote? {
        let resolvedPrincipal: Decimal
        if let selectedBorrowResult {
            resolvedPrincipal = max(.zero, selectedBorrowResult.outstandingPrincipalAmount)
        } else if let loanAccount {
            resolvedPrincipal = max(.zero, loanAccount.totalLimit.amount - loanAccount.availableLimit.amount)
        } else {
            resolvedPrincipal = .zero
        }

        guard resolvedPrincipal > .zero else {
            return nil
        }

        let resolvedRate = max(
            selectedBorrowResult?.annualRate ?? loanAccount?.annualRate ?? .zero,
            .zero
        )

        return LoanAccountRepaymentCalculator.quote(
            currentPrincipal: resolvedPrincipal,
            annualRatePercent: resolvedRate,
            installmentText: selectedBorrowResult?.installmentText,
            borrowedAt: selectedBorrowResult?.borrowedAt,
            interestSettledThroughDate: selectedBorrowResult?.interestSettledThroughDate
        )
    }

    private func syncSelectedBorrow() {
        let resolvedBorrowId: String?
        if let selectedBorrowId,
           displayBorrowResults.contains(where: { $0.borrowId == selectedBorrowId }) {
            resolvedBorrowId = selectedBorrowId
        } else if let initialSelectedBorrowId,
                  displayBorrowResults.contains(where: { $0.borrowId == initialSelectedBorrowId }) {
            resolvedBorrowId = initialSelectedBorrowId
        } else {
            resolvedBorrowId = displayBorrowResults.first?.borrowId
        }

        if selectedBorrowId != resolvedBorrowId {
            selectedBorrowId = resolvedBorrowId
        }
    }

