    private func formatBorrowDate(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "zh_CN")
        formatter.timeZone = TimeZone(identifier: "Asia/Shanghai")
        formatter.dateFormat = "yyyy年M月d日"
        return formatter.string(from: date)
    }

    @MainActor
    private func refreshLoanAccount() async {
        guard let userId, userId > 0 else {
            loanAccount = nil
            isLoading = false
            return
        }
        let loadingStart = Date()
        let minimumLoadingDuration: TimeInterval = 0.9
        let resultRevealDelay: TimeInterval = 0.12
        isLoading = true
        loanAccount = nil
        let resolvedAccount: LoanAccountData?
        do {
            let fetchedAccount = try await APIClient.shared.fetchLoanAccount(userId: userId)
            LoanAccountSyntheticSnapshotStore.saveAccount(fetchedAccount, userId: userId)
            resolvedAccount = LoanAccountSyntheticSnapshotStore.loadAccount(userId: userId) ?? fetchedAccount
        } catch {
            resolvedAccount = LoanAccountSyntheticSnapshotStore.loadAccount(userId: userId)
        }
        let elapsed = Date().timeIntervalSince(loadingStart)
        if elapsed < minimumLoadingDuration {
            let remaining = UInt64((minimumLoadingDuration - elapsed) * 1_000_000_000)
            try? await Task.sleep(nanoseconds: remaining)
        }
        isLoading = false
        guard let resolvedAccount else {
            loanAccount = nil
            return
        }
        try? await Task.sleep(nanoseconds: UInt64(resultRevealDelay * 1_000_000_000))
        loanAccount = resolvedAccount
    }

    private func formatMoney(_ value: Decimal, useGrouping: Bool) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = useGrouping
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSDecimalNumber(decimal: value)) ?? NSDecimalNumber(decimal: value).stringValue
    }
}


private func resolveCreditCurrentBillDueAmount(account: CreditAccountData?, billDetail: CreditCurrentBillDetailData?) -> Decimal {
    if let billDetail {
        return max(.zero, billDetail.dueAmount.amount)
    }
    guard let account else {
        return .zero
    }
    let outstandingAmount = max(.zero, account.totalOutstandingAmount)
    let nextMonthAccumulatedAmount = max(.zero, account.nextMonthBillAccumulatedAmount.amount)
    return max(.zero, outstandingAmount - nextMonthAccumulatedAmount)
}

private func resolveCreditStatementTotalAmount(account: CreditAccountData?, billDetail: CreditCurrentBillDetailData?) -> Decimal {
    if let billDetail {
        return max(.zero, billDetail.statementTotalAmount.amount)
    }
    return resolveCreditCurrentBillDueAmount(account: account, billDetail: billDetail)
}

private func roundCreditMoneyAmount(_ value: Decimal) -> Decimal {
    var working = max(.zero, value)
    var rounded = Decimal()
    NSDecimalRound(&rounded, &working, 2, .plain)
    return rounded
}

private func resolveCreditMinimumRepaymentThreshold(statementTotalAmount: Decimal) -> Decimal {
    roundCreditMoneyAmount(max(.zero, statementTotalAmount) * Decimal(string: "0.10")!)
}

private func resolveCreditRemainingMinimumRepaymentAmount(statementTotalAmount: Decimal, repaidAmount: Decimal) -> Decimal {
    let minimumThreshold = resolveCreditMinimumRepaymentThreshold(statementTotalAmount: statementTotalAmount)
    return roundCreditMoneyAmount(max(.zero, minimumThreshold - max(.zero, repaidAmount)))
}

private func resolveCreditStatementMonth(title: String?, repayDayOfMonth: Int?) -> Int {
    if let title {
        let monthText = title.prefix { $0 != "月" }
        if let parsedMonth = Int(monthText), parsedMonth > 0, parsedMonth <= 12 {
            return parsedMonth
        }
    }

    let calendar = Calendar(identifier: .gregorian)
    let today = Date()
    let repayDay = min(28, max(1, repayDayOfMonth ?? 10))
    guard let candidateStatementDate = calendar.date(bySetting: .day, value: repayDay, of: today) else {
        return calendar.component(.month, from: today)
    }
    let statementDate = today < candidateStatementDate
        ? (calendar.date(byAdding: .month, value: -1, to: candidateStatementDate) ?? candidateStatementDate)
        : candidateStatementDate
    return calendar.component(.month, from: statementDate)
}

private func sanitizeCreditBillTitle(_ title: String?) -> String {
    let normalized = (title ?? "")
        .trimmingCharacters(in: .whitespacesAndNewlines)
        .replacingOccurrences(of: "▼", with: "")
        .replacingOccurrences(of: "▾", with: "")
        .replacingOccurrences(of: "⌄", with: "")
        .trimmingCharacters(in: .whitespacesAndNewlines)
    return normalized
}

