    private func statusBanner(
        text: String,
        isError: Bool,
        scaleX: CGFloat,
        scaleY: CGFloat
    ) -> some View {
        Text(text)
            .font(.system(size: 13 * min(scaleX, scaleY), weight: .medium))
            .foregroundStyle(isError ? Color(red: 0.67, green: 0.20, blue: 0.20) : Color(red: 0.39, green: 0.31, blue: 0.20))
            .lineLimit(2)
            .multilineTextAlignment(.center)
            .frame(width: 312 * scaleX)
            .position(x: 201 * scaleX, y: 352 * scaleY)
