    private var currentBillDueAmount: Decimal {
        resolveCreditCurrentBillDueAmount(account: creditAccount, billDetail: currentBillDetail)
    }

    private var currentBillStatementMonth: Int {
        resolveCreditStatementMonth(title: currentBillDetail?.title, repayDayOfMonth: creditAccount?.repayDayOfMonth)
    }

    private var hasOutstandingBill: Bool {
        guard !isCreditBillQueryPending else {
            return false
        }
        return currentBillDueAmount > Decimal.zero
    }

    private var nextMonthAccumulatedAmount: Decimal {
        max(.zero, creditAccount?.nextMonthBillAccumulatedAmount.amount ?? .zero)
    }

    private var showsNextMonthAccumulatedEntry: Bool {
        !hasOutstandingBill && !isCreditBillQueryPending && nextMonthAccumulatedAmount > .zero
    }

    private var nextCreditStatementMonth: Int {
        currentBillStatementMonth == 12 ? 1 : currentBillStatementMonth + 1
    }

    private var hasCurrentStatementBill: Bool {
        guard !isCreditBillQueryPending else {
            return false
        }
        if let billDetail = currentBillDetail {
            return max(.zero, billDetail.statementTotalAmount.amount) > .zero || !billDetail.items.isEmpty
        }
        return resolveCreditStatementTotalAmount(account: creditAccount, billDetail: nil) > .zero
    }

    private var isCreditBillQueryPending: Bool {
        isLoading
    }

    private var repayHintText: String {
        if currentBillDueAmount > Decimal.zero {
            return "\(currentBillStatementMonth)月应还(元)"
        }
        if showsNextMonthAccumulatedEntry {
            return "\(nextCreditStatementMonth)月账单累计中(元)"
        }
        return "当前无待还账单"
    }

    private var repayAmountText: String {
        guard !isCreditBillQueryPending else {
            return "--.--"
        }
        guard creditAccount != nil || currentBillDetail != nil else {
            return "--.--"
        }
        if showsNextMonthAccumulatedEntry {
            return formatMoney(nextMonthAccumulatedAmount, useGrouping: true)
        }
        return formatMoney(currentBillDueAmount, useGrouping: true)
    }

    private var totalBillText: String {
        guard !isCreditBillQueryPending else {
            return "总计账单"
        }
        if hasOutstandingBill {
            return "总计账单"
        }
        return "\(currentBillStatementMonth)月账单"
    }

    private var repayDayText: String {
        if isCreditBillQueryPending {
            return ""
        }
        if !hasOutstandingBill {
            return hasCurrentStatementBill ? "已还清" : "无"
        }
        let day = creditAccount?.repayDayOfMonth ?? 10
        return "还款日每月\(day)日"
    }

    private var totalLimitText: String {
        return "总计额度"
    }

    private var availableLimitText: String {
        guard !isCreditBillQueryPending else {
            return "--可用"
        }
        guard let availableLimit = creditAccount?.availableLimit.amount else {
            return "--可用"
        }
        return "\(formatMoney(availableLimit, useGrouping: true))可用"
    }

    private func hotspot(
        identifier: String,
        centerX: CGFloat,
        centerY: CGFloat,
        width: CGFloat,
        height: CGFloat,
        isDisabled: Bool = false,
        action: @escaping () -> Void
    ) -> some View {
        Button(action: action) {
            Color.clear
                .frame(width: width, height: height)
                .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
        .accessibilityIdentifier(identifier)
        .position(x: centerX, y: centerY)
    }

    @MainActor
    private func refreshCreditHome(showLoading: Bool) async {
        guard let userId, userId > 0 else {
            creditAccount = nil
            currentBillDetail = nil
            errorMessage = "未找到当前登录用户"
            return
        }
        if showLoading {
            isLoading = true
            errorMessage = nil
            creditAccount = nil
            currentBillDetail = nil
        }
        do {
            // 爱花首页必须等“账户快照 + 当前账单明细”一起落屏，否则会先渲染一次
            // 按账户余额推导出来的旧账单态，出现“先闪 3 月再切 4 月”的错态。
            async let accountRequest = APIClient.shared.fetchCreditAccount(userId: userId)
            async let billDetailRequest = APIClient.shared.fetchCreditCurrentBillDetail(userId: userId)
            let account = try await accountRequest
            let billDetail = try? await billDetailRequest
            creditAccount = account
            currentBillDetail = billDetail
            errorMessage = nil
        } catch {
            if showLoading {
                creditAccount = nil
                currentBillDetail = nil
            }
            errorMessage = userFacingErrorMessage(error)
        }
        if showLoading {
            isLoading = false
        }
    }

    private func formatMoney(_ value: Decimal, useGrouping: Bool) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = useGrouping
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSDecimalNumber(decimal: value)) ?? NSDecimalNumber(decimal: value).stringValue
    }
    }

private struct CreditRepayView: View {
    private enum RepayOption {
        case full
        case minimum
    }

    let userId: Int64?
    let prefilledAmount: Decimal?
    let refreshTrigger: Int
    let repayBillMode: CreditRepayBillMode
    let layoutMode: CreditRepayLayoutMode
    let initialCreditAccount: CreditAccountData?
    let initialCurrentBillDetail: CreditCurrentBillDetailData?
    let shouldSkipInitialRefresh: Bool
    let onBillOverviewSnapshotChanged: ((CreditAccountData?, CreditCurrentBillDetailData?) -> Void)?
    let onBack: () -> Void
    let onOpenBillDetail: () -> Void
    let onOpenNextBillDetail: () -> Void
    let onOpenRepayForm: () -> Void
    let onRepayConfirm: (Decimal) -> Void


    @State private var creditAccount: CreditAccountData?
    @State private var currentBillDetail: CreditCurrentBillDetailData?
    @State private var isLoading = false
    @State private var errorMessage: String?
    @State private var repayAmountInput: String = ""
    @State private var hasInitializedRepayAmount = false
    @State private var isAmountEditorPresented = false
    @State private var shouldReplaceRepayAmountOnNextInput = true
    @State private var selectedRepayOption: RepayOption = .full

    private let baseWidth: CGFloat = 402
    private let baseHeight: CGFloat = 874

    init(
        userId: Int64?,
        prefilledAmount: Decimal?,
        refreshTrigger: Int,
        repayBillMode: CreditRepayBillMode,
        layoutMode: CreditRepayLayoutMode,
        initialCreditAccount: CreditAccountData?,
        initialCurrentBillDetail: CreditCurrentBillDetailData?,
        shouldSkipInitialRefresh: Bool,
        onBillOverviewSnapshotChanged: ((CreditAccountData?, CreditCurrentBillDetailData?) -> Void)?,
        onBack: @escaping () -> Void,
        onOpenBillDetail: @escaping () -> Void,
        onOpenNextBillDetail: @escaping () -> Void,
        onOpenRepayForm: @escaping () -> Void,
        onRepayConfirm: @escaping (Decimal) -> Void
    ) {
        self.userId = userId
        self.prefilledAmount = prefilledAmount
        self.refreshTrigger = refreshTrigger
        self.repayBillMode = repayBillMode
        self.layoutMode = layoutMode
        self.initialCreditAccount = initialCreditAccount
        self.initialCurrentBillDetail = initialCurrentBillDetail
        self.shouldSkipInitialRefresh = shouldSkipInitialRefresh
        self.onBillOverviewSnapshotChanged = onBillOverviewSnapshotChanged
        self.onBack = onBack
        self.onOpenBillDetail = onOpenBillDetail
        self.onOpenNextBillDetail = onOpenNextBillDetail
        self.onOpenRepayForm = onOpenRepayForm
        self.onRepayConfirm = onRepayConfirm
        _creditAccount = State(initialValue: initialCreditAccount)
        _currentBillDetail = State(initialValue: initialCurrentBillDetail)
    }

    private var isBillOverviewMode: Bool {
        layoutMode == .billOverview
    }

    private var isNextBillPrepaymentMode: Bool {
        repayBillMode == .next
    }

    var body: some View {
        GeometryReader { proxy in
            let scaleX = proxy.size.width / baseWidth
            let scaleY = proxy.size.height / baseHeight
            let fontScale = min(scaleX, scaleY)

            Group {
                if isBillOverviewMode {
                    billOverviewContent(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                } else {
                    repayFormContent(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                }
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .task(id: prefilledAmountKey) {
            if let prefilledAmount {
                repayAmountInput = formatMoney(max(prefilledAmount, .zero), useGrouping: false)
                hasInitializedRepayAmount = true
            } else {
                hasInitializedRepayAmount = false
                repayAmountInput = ""
            }
            isAmountEditorPresented = false
            shouldReplaceRepayAmountOnNextInput = true
            selectedRepayOption = .full
            if isBillOverviewMode && shouldSkipInitialRefresh && creditAccount != nil && currentBillDetail != nil {
                isLoading = false
                errorMessage = nil
                onBillOverviewSnapshotChanged?(creditAccount, currentBillDetail)
                return
            }
            await refreshCreditRepay(showLoading: true)
        }
    }

    private var prefilledAmountKey: String {
        let userKey = String(userId ?? 0)
        let amountKey = prefilledAmount.map { NSDecimalNumber(decimal: $0).stringValue } ?? "nil"
        return userKey + "|" + amountKey + "|" + String(refreshTrigger)
    }

    private func repayFormContent(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        let isLoadingRepayForm = isLoading && creditAccount == nil && currentBillDetail == nil

        return ZStack {
            Image("CreditRepayReference")
                .resizable()
                .interpolation(.high)
                .aspectRatio(contentMode: .fill)
                .frame(width: baseWidth * scaleX, height: baseHeight * scaleY)
                .clipped()

            repayOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)

            if isLoadingRepayForm {
                AILoadingIndicator(text: "账单查询中")
                    .position(x: 201 * scaleX, y: 468 * scaleY)
                    .allowsHitTesting(false)
            }

            repayHotspot(
                identifier: "credit_repay_back",
                centerX: 34 * scaleX,
                centerY: 78 * scaleY,
                width: 108 * scaleX,
                height: 60 * scaleY
            ) {
                onBack()
            }
            .zIndex(25)

            repayHotspot(
                identifier: "credit_repay_option_full_card",
                centerX: 201 * scaleX,
                centerY: 132 * scaleY,
                width: 362 * scaleX,
                height: 70 * scaleY
            ) {
                handleFullRepayTap()
            }
            .zIndex(23)

            repayHotspot(
                identifier: "credit_repay_option_full",
                centerX: 37 * scaleX,
                centerY: 132 * scaleY,
                width: 42 * scaleX,
                height: 42 * scaleY
            ) {
                handleFullRepayTap()
            }
            .zIndex(24)

            if showsMinimumRepayOption {
                repayHotspot(
                    identifier: "credit_repay_option_minimum_card",
                    centerX: 201 * scaleX,
                    centerY: 273 * scaleY,
                    width: 362 * scaleX,
                    height: 62 * scaleY
                ) {
                    applyRepayOption(.minimum)
                }
                .zIndex(23)

                repayHotspot(
                    identifier: "credit_repay_option_minimum",
                    centerX: 37 * scaleX,
                    centerY: 273 * scaleY,
                    width: 42 * scaleX,
                    height: 42 * scaleY
                ) {
                    applyRepayOption(.minimum)
                }
                .zIndex(24)
            }

            if !isAmountEditorPresented {
                repayHotspot(
                    identifier: "credit_repay_submit",
                    centerX: 201 * scaleX,
                    centerY: 819 * scaleY,
                    width: 354 * scaleX,
                    height: 60 * scaleY
                ) {
                    guard enteredRepayAmount > .zero else {
                        return
                    }
                    shouldReplaceRepayAmountOnNextInput = true
                    isAmountEditorPresented = false
                    onRepayConfirm(enteredRepayAmount)
                }
                .zIndex(24)
            }

            if isAmountEditorPresented {
                repayAmountKeyboard(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                    .zIndex(10)
            }
        }
    }

    private func billOverviewContent(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        let isLoadingBillOverview = isLoading && creditAccount == nil && currentBillDetail == nil

        return ZStack {
            Image("CreditBillOverviewReference")
                .resizable()
                .interpolation(.high)
                .aspectRatio(contentMode: .fill)
                .frame(width: baseWidth * scaleX, height: baseHeight * scaleY)
                .clipped()

            billOverviewCleanupOverlay(scaleX: scaleX, scaleY: scaleY)

            if isLoadingBillOverview {
                billOverviewLoadingMaskOverlay(scaleX: scaleX, scaleY: scaleY)
                billOverviewAccumulatedTitleOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                AILoadingIndicator(text: "查询中")
                    .position(x: 201 * scaleX, y: 235 * scaleY)
                    .allowsHitTesting(false)
            } else {
                if showsBillOverviewSettledState {
                    ZStack {
                        billOverviewSettledOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                        billOverviewSettledCollapsedRowsOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                    }
                    .mask {
                        // 已还清态仅允许在账单卡片区域内重绘，防止左侧白色清理块溢出污染底图。
                        // 按验收要求：3月账单已还清时，最下方边框上移 10px（保持顶部不变）。
                        RoundedRectangle(cornerRadius: 18 * min(scaleX, scaleY), style: .continuous)
                            .frame(width: 366 * scaleX, height: 302 * scaleY)
                            .position(x: 201 * scaleX, y: 257 * scaleY)
                    }
                } else {
                    billOverviewAccumulatedTitleOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                    billOverviewAmountOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                    billOverviewAccumulatedAmountOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                    billOverviewAllOutstandingAmountOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                }

                if currentBillDueAmount <= .zero {
                    billOverviewRepayButtonCleanupOverlay(scaleX: scaleX, scaleY: scaleY)
                        .allowsHitTesting(false)
                }
            }

            repayHotspot(
                identifier: "credit_bill_overview_back",
                centerX: 34 * scaleX,
                centerY: 78 * scaleY,
                width: 108 * scaleX,
                height: 60 * scaleY
            ) {
                onBack()
            }
            .zIndex(20)

            if !showsBillOverviewSettledState {
                repayHotspot(
                    identifier: "credit_bill_overview_detail",
                    centerX: 324 * scaleX,
                    centerY: 141 * scaleY,
                    width: 154 * scaleX,
                    height: 112 * scaleY
                ) {
                    onOpenBillDetail()
                }
                .zIndex(20)
            }

            if !isLoadingBillOverview {
                repayHotspot(
                    identifier: "credit_bill_overview_next_bill_entry",
                    centerX: 201 * scaleX,
                    centerY: billOverviewNextBillHotspotCenterY * scaleY,
                    width: 366 * scaleX,
                    height: 72 * scaleY
                ) {
                    onOpenNextBillDetail()
                }
                .zIndex(20)

                repayHotspot(
                    identifier: "credit_bill_overview_next_bill_detail",
                    centerX: 352 * scaleX,
                    centerY: billOverviewAccumulatedTitleCenterY * scaleY,
                    width: 92 * scaleX,
                    height: 42 * scaleY
                ) {
                    onOpenNextBillDetail()
                }
                .zIndex(22)
            }

            if !isLoadingBillOverview && currentBillDueAmount > .zero {
                repayHotspot(
                    identifier: "credit_bill_overview_repay_now",
                    centerX: 88 * scaleX,
                    centerY: 221 * scaleY,
                    width: 176 * scaleX,
                    height: 58 * scaleY
                ) {
                    openRepayFormFromBillOverview()
                }
                .zIndex(26)
            }
        }
    }

