    private func billOverviewCleanupOverlay(scaleX: CGFloat, scaleY: CGFloat) -> some View {
        let pageBackground = Color(red: 0.95, green: 0.95, blue: 0.96)
        let topBarBackground = Color(red: 0.96, green: 0.96, blue: 0.97)
        let cardSurfaceBackground = Color.white

        return ZStack {
            // 删除总账单页右上角客服按钮（静态截图图层）
            RoundedRectangle(cornerRadius: 10 * min(scaleX, scaleY), style: .continuous)
                .fill(topBarBackground)
                .frame(width: 64 * scaleX, height: 34 * scaleY)
                .position(x: 360 * scaleX, y: 79 * scaleY)

            Rectangle()
                .fill(pageBackground)
                .frame(width: 382 * scaleX, height: 84 * scaleY)
                .position(x: 201 * scaleX, y: 492 * scaleY)

            Rectangle()
                .fill(pageBackground)
                .frame(width: baseWidth * scaleX, height: 340 * scaleY)
                .position(x: 201 * scaleX, y: 690 * scaleY)

            // 擦除账单卡片底部外侧残留的浅白横条，避免污染底色。
            Rectangle()
                .fill(pageBackground)
                .frame(width: 402 * scaleX, height: 22 * scaleY)
                .position(x: 201 * scaleX, y: 444 * scaleY)

            // 进一步清理“全部待还”区域靠近底边线处的残留文字下半截。
            Rectangle()
                .fill(pageBackground)
                .frame(width: 402 * scaleX, height: 14 * scaleY)
                .position(x: 201 * scaleX, y: 432 * scaleY)

            // 兜底清理底边细横线残影。
            Rectangle()
                .fill(pageBackground)
                .frame(width: 402 * scaleX, height: 10 * scaleY)
                .position(x: 201 * scaleX, y: 451 * scaleY)

            // 统一擦除“含未入账金额等”静态提示，避免查询中和查询完成都出现残留。
            Rectangle()
                .fill(cardSurfaceBackground)
                .frame(width: 356 * scaleX, height: 24 * scaleY)
                .position(x: 201 * scaleX, y: 402 * scaleY)

            // 补擦“含未入账金额等”字样下半部分残留（仅覆盖底半区，避免影响上方动态文案）。
            Rectangle()
                .fill(cardSurfaceBackground)
                .frame(width: 356 * scaleX, height: 16 * scaleY)
                .position(x: 201 * scaleX, y: 410 * scaleY)

            // 已还清态底边上移后，原图“含未入账金额等”残字仍会出现在卡片左下角（y≈420）。
            // 在未被遮罩裁剪的清理层中做细粒度定点擦除，避免大面积块状痕迹。
            Rectangle()
                .fill(cardSurfaceBackground)
                .frame(width: 96 * scaleX, height: 12 * scaleY)
                .position(x: 71 * scaleX, y: 421 * scaleY)
        }
        .allowsHitTesting(false)
    }

