    private func openRepayFormFromBillOverview() {
        guard currentBillDueAmount > .zero else {
            return
        }
        selectedRepayOption = .full
        repayAmountInput = formatMoney(currentBillDueAmount, useGrouping: false)
        hasInitializedRepayAmount = true
        shouldReplaceRepayAmountOnNextInput = true
        isAmountEditorPresented = false
        onOpenRepayForm()
    }

