    private func repaySelectedIndicator(
        isSelected: Bool,
        centerX: CGFloat,
        centerY: CGFloat,
        scaleX: CGFloat,
        scaleY: CGFloat
    ) -> some View {
        return Circle()
            .fill(isSelected ? AppTheme.palette.brandPrimary : Color.white)
            .frame(width: 20 * min(scaleX, scaleY), height: 20 * min(scaleX, scaleY))
            .overlay(
                Circle()
                    .stroke(
                        isSelected ? AppTheme.palette.brandPrimary : Color(red: 0.84, green: 0.84, blue: 0.86),
                        lineWidth: max(1.2, 1.35 * min(scaleX, scaleY))
                    )
            )
            .overlay {
                if isSelected {
                    Image(systemName: "checkmark")
                        .font(.system(size: 9 * min(scaleX, scaleY), weight: .bold))
                        .foregroundStyle(Color.white)
                }
            }
            .position(x: centerX * scaleX, y: centerY * scaleY)
    }

