    private func repayAmountDisplay(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        return HStack(alignment: .center, spacing: 3 * scaleX) {
            Text(repayAmountDisplayText)
                .font(.system(size: 48 * fontScale, weight: .semibold))
                .foregroundStyle(Color(red: 0.16, green: 0.16, blue: 0.18))
                .lineLimit(1)
                .minimumScaleFactor(0.75)

            if isAmountEditorPresented {
                TimelineView(.periodic(from: .now, by: 0.52)) { context in
                    let tick = Int(context.date.timeIntervalSinceReferenceDate / 0.52)
                    Rectangle()
                        .fill(AppTheme.palette.brandPrimary)
                        .opacity(tick.isMultiple(of: 2) ? 0.96 : 0.18)
                }
                .frame(width: max(2, 2 * scaleX), height: 36 * scaleY)
            }
        }
        .frame(width: 236 * scaleX, height: 52 * scaleY, alignment: .leading)
        .clipped()
        .position(x: 202 * scaleX, y: 169.5 * scaleY)
        .accessibilityIdentifier("credit_repay_amount_input")
    }

    private func repayAmountKeyboard(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        let panelTop: CGFloat = 656
        let panelHeight: CGFloat = 218
        let leftWidth: CGFloat = 302
        let cellWidth = leftWidth / 3
        let cellHeight = panelHeight / 4
        let leftKeys: [[String]] = [
            ["1", "2", "3"],
            ["4", "5", "6"],
            ["7", "8", "9"],
            [".", "0", "⌨︎"]
        ]

        return ZStack {
            Rectangle()
                .fill(Color(red: 0.93, green: 0.93, blue: 0.94))
                .frame(width: 402 * scaleX, height: panelHeight * scaleY)
                .position(x: 201 * scaleX, y: (panelTop + panelHeight / 2) * scaleY)

            ForEach(0..<leftKeys.count, id: \.self) { row in
                ForEach(0..<leftKeys[row].count, id: \.self) { column in
                    let centerX = cellWidth * (CGFloat(column) + 0.5)
                    let centerY = panelTop + cellHeight * (CGFloat(row) + 0.5)
                    repayKeyboardKeyCell(
                        key: leftKeys[row][column],
                        centerX: centerX,
                        centerY: centerY,
                        width: cellWidth,
                        height: cellHeight,
                        scaleX: scaleX,
                        scaleY: scaleY,
                        fontScale: fontScale
                    )
                }
            }

            Button(action: removeLastRepayInputCharacter) {
                Image(systemName: "delete.left")
                    .font(.system(size: 25 * fontScale, weight: .regular))
                    .foregroundStyle(Color(red: 0.35, green: 0.35, blue: 0.36))
                    .frame(width: 100 * scaleX, height: cellHeight * scaleY)
                    .background(Color(red: 0.93, green: 0.93, blue: 0.94))
                    .overlay(
                        Rectangle()
                            .stroke(Color(red: 0.84, green: 0.84, blue: 0.85), lineWidth: 0.6 * min(scaleX, scaleY))
                    )
            }
            .buttonStyle(.plain)
            .position(x: 352 * scaleX, y: (panelTop + cellHeight * 1.5) * scaleY)
            .accessibilityIdentifier("credit_repay_keyboard_delete")

            Button(action: {
                isAmountEditorPresented = false
            }) {
                Text("确定")
                    .font(.system(size: 39 / 2 * fontScale, weight: .regular))
                    .foregroundStyle(Color.white)
                    .frame(width: 100 * scaleX, height: (cellHeight * 2) * scaleY)
                    .background(AppTheme.palette.brandPrimary)
            }
            .buttonStyle(.plain)
            .position(x: 352 * scaleX, y: (panelTop + cellHeight * 3) * scaleY)
            .accessibilityIdentifier("credit_repay_keyboard_confirm")
        }
    }

    private func repayKeyboardKeyCell(
        key: String,
        centerX: CGFloat,
        centerY: CGFloat,
        width: CGFloat,
        height: CGFloat,
        scaleX: CGFloat,
        scaleY: CGFloat,
        fontScale: CGFloat
    ) -> some View {
        Button(action: {
            handleRepayKeyboardInput(key)
        }) {
            ZStack {
                Rectangle()
                    .fill(Color(red: 0.95, green: 0.95, blue: 0.96))
                Rectangle()
                    .stroke(Color(red: 0.84, green: 0.84, blue: 0.85), lineWidth: 0.6 * min(scaleX, scaleY))

                if key == "⌨︎" {
                    Image(systemName: "keyboard")
                        .font(.system(size: 20 * fontScale, weight: .regular))
                        .foregroundStyle(Color(red: 0.32, green: 0.32, blue: 0.34))
                } else {
                    Text(key)
                        .font(.system(size: 39 / 2 * fontScale, weight: .regular))
                        .foregroundStyle(Color(red: 0.22, green: 0.22, blue: 0.23))
                }
            }
            .frame(width: width * scaleX, height: height * scaleY)
        }
        .buttonStyle(.plain)
        .position(x: centerX * scaleX, y: centerY * scaleY)
        .accessibilityIdentifier("credit_repay_keyboard_\(key)")
    }

    private func handleRepayKeyboardInput(_ key: String) {
        if key == "⌨︎" {
            isAmountEditorPresented = false
            return
        }
        hasInitializedRepayAmount = true
        selectedRepayOption = .full

        let next: String
        if key == "." {
            if shouldReplaceRepayAmountOnNextInput {
                next = "0."
                shouldReplaceRepayAmountOnNextInput = false
                repayAmountInput = sanitizeAmountInput(next)
                return
            }
            if repayAmountInput.contains(".") {
                return
            }
            if repayAmountInput.isEmpty {
                next = "0."
            } else {
                next = repayAmountInput + "."
            }
        } else {
            if repayAmountInput == "0" {
                next = key
            } else {
                if shouldReplaceRepayAmountOnNextInput {
                    next = key
                } else {
                    next = repayAmountInput + key
                }
            }
        }
        shouldReplaceRepayAmountOnNextInput = false
        repayAmountInput = sanitizeAmountInput(next)
    }

    private func removeLastRepayInputCharacter() {
        guard !repayAmountInput.isEmpty else {
            return
        }
        hasInitializedRepayAmount = true
        selectedRepayOption = .full
        shouldReplaceRepayAmountOnNextInput = false
        repayAmountInput.removeLast()
    }

    private func handleFullRepayTap() {
        if selectedRepayOption == .full {
            shouldReplaceRepayAmountOnNextInput = true
            isAmountEditorPresented = true
            return
        }
        applyRepayOption(.full)
    }

    private func applyRepayOption(_ option: RepayOption) {
        selectedRepayOption = option
        hasInitializedRepayAmount = true
        shouldReplaceRepayAmountOnNextInput = true
        isAmountEditorPresented = false
        switch option {
        case .full:
            repayAmountInput = formatMoney(currentBillDueAmount, useGrouping: false)
        case .minimum:
            repayAmountInput = minimumRepayText
        }
    }

