        return formatMoney(remainingMinimumRepayAmount, useGrouping: false)
    }


    private func sanitizeAmountInput(_ text: String) -> String {
        let filtered = text.filter { $0.isNumber || $0 == "." }
        if filtered.isEmpty {
            return ""
        }

        var result = ""
        var hasDot = false
        var fractionalCount = 0
        for ch in filtered {
            if ch == "." {
                if hasDot {
                    continue
                }
                hasDot = true
                if result.isEmpty {
                    result = "0"
                }
                result.append(ch)
                continue
            }

            if hasDot {
                if fractionalCount >= 2 {
                    continue
                }
                fractionalCount += 1
            }
            result.append(ch)
        }

        if result.hasPrefix("00"), !result.hasPrefix("0.") {
            while result.count > 1, result.first == "0", result.dropFirst().first != "." {
                result.removeFirst()
            }
        }
        return result
    }

    private func repayHotspot(
        identifier: String,
