            .contentShape(Rectangle())
            .position(x: centerX, y: centerY)
            .highPriorityGesture(
                TapGesture().onEnded {
                    action()
                }
            )
            .accessibilityIdentifier(identifier)
    }

    @MainActor
    private func refreshCreditRepay(showLoading: Bool) async {
        guard let userId, userId > 0 else {
            creditAccount = nil
            currentBillDetail = nil
            errorMessage = "未找到当前登录用户"
            return
        }
        if showLoading {
            isLoading = true
            errorMessage = nil
            creditAccount = nil
            currentBillDetail = nil
        }
        do {
            async let accountRequest = APIClient.shared.fetchCreditAccount(userId: userId)
            let account = try await accountRequest
            let billDetail: CreditCurrentBillDetailData?
            switch repayBillMode {
            case .current:
                billDetail = try? await APIClient.shared.fetchCreditCurrentBillDetail(userId: userId)
            case .next:
                billDetail = try? await APIClient.shared.fetchCreditNextBillDetail(userId: userId)
            }
            let defaultRepayAmount: Decimal
            switch repayBillMode {
            case .current:
                defaultRepayAmount = billDetail?.dueAmount.amount
                    ?? resolveCreditCurrentBillDueAmount(account: account, billDetail: nil)
            case .next:
                defaultRepayAmount = billDetail?.dueAmount.amount
                    ?? max(.zero, account.nextMonthBillAccumulatedAmount.amount)
            }
            let minimumRepayAmount: Decimal
            if isNextBillPrepaymentMode {
                minimumRepayAmount = .zero
            } else {
                minimumRepayAmount = resolveCreditRemainingMinimumRepaymentAmount(
                    statementTotalAmount: resolveCreditStatementTotalAmount(account: account, billDetail: billDetail),
                    repaidAmount: billDetail?.repaidAmount.amount ?? .zero
                )
            }
            creditAccount = account
            currentBillDetail = billDetail
            errorMessage = nil
            if isBillOverviewMode {
                onBillOverviewSnapshotChanged?(account, billDetail)
            }
            if !hasInitializedRepayAmount {
                repayAmountInput = formatMoney(defaultRepayAmount, useGrouping: false)
                hasInitializedRepayAmount = true
            }
            if minimumRepayAmount <= .zero, selectedRepayOption == .minimum {
                selectedRepayOption = .full
                repayAmountInput = formatMoney(defaultRepayAmount, useGrouping: false)
                shouldReplaceRepayAmountOnNextInput = true
            }
        } catch {
            if showLoading {
                creditAccount = nil
                currentBillDetail = nil
            }
            errorMessage = userFacingErrorMessage(error)
        }
        if showLoading {
            isLoading = false
        }
    }

    private func formatMoney(_ value: Decimal, useGrouping: Bool) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = useGrouping
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSDecimalNumber(decimal: value)) ?? NSDecimalNumber(decimal: value).stringValue
    }
    }

private struct LoanAccountRepayCashierView: View {
    let payerUserId: Int64?
    let borrowResult: LoanAccountBorrowResult?
    let fullRepayAmount: Decimal
    let onRepayAmountSelected: (Decimal) -> Void
    let onPaySubmitting: (String) -> Void
    let onPaySucceeded: (String, LoanAccountRepaymentSettlement) -> Void
    let onPayFailed: (String, String) -> Void
    let onBack: () -> Void

    @State private var loanAccount: LoanAccountData?
    @State private var amountInput: String = ""
    @State private var isAmountInputFocused = true
    @State private var isPaymentToolsExpanded = false
    @State private var isInterestExplanationPresented = false
    @State private var payTools: [CashierPayToolData] = []
    @State private var selectedBankToolCode: String?
    @State private var selectedPaymentMethodType: RepayPaymentMethodType = .bankCard
    @State private var walletAvailableAmountText: String = "--"
    @State private var fundAvailableAmountText: String = "--"
    @State private var isLoadingWalletBalance = false
    @State private var isLoadingFundBalance = false
    @State private var isLoadingPayTools = false
    @State private var isSubmitting = false
    @State private var payToolsErrorMessage: String?
    @State private var submitMessage: String?
    @State private var sceneConfiguration: CashierSceneConfiguration = CashierChannelAvailability.filteredSceneConfiguration(
        .creditRepay,
        hasFundAvailable: false,
        hasAiCreditAvailable: false
    )
    @State private var hasFundAvailable = false

    private let baseWidth: CGFloat = 402
    private let baseHeight: CGFloat = 874
    private let keypadHeight: CGFloat = 260
    private let keypadBottomInset: CGFloat = 35
    private let keypadRows: [[String]] = [["1", "2", "3"], ["4", "5", "6"], ["7", "8", "9"], [".", "0", ""]]

    private var displayedFullRepayAmount: Decimal {
        repaymentQuote?.payoffAmount ?? max(fullRepayAmount, .zero)
    }

    private var outstandingPrincipalAmount: Decimal {
        repaymentQuote?.outstandingPrincipal ?? max(fullRepayAmount, .zero)
    }

    private var displayedInterestAmount: Decimal {
        repaymentQuote?.accruedInterest ?? max(.zero, displayedFullRepayAmount - outstandingPrincipalAmount)
    }

    private var currentRepayAmount: Decimal {
        max(.zero, enteredRepayAmount ?? .zero)
    }

    private var enteredPrincipalAmount: Decimal {
        min(outstandingPrincipalAmount, currentRepayAmount)
    }

    private var enteredInterestAmount: Decimal {
        let remainingAfterPrincipal = max(.zero, currentRepayAmount - enteredPrincipalAmount)
        return min(displayedInterestAmount, remainingAfterPrincipal)
    }

    private var repaymentQuote: LoanAccountRepaymentCalculator.Quote? {
        let resolvedPrincipal: Decimal
        if let borrowResult {
            resolvedPrincipal = max(.zero, borrowResult.outstandingPrincipalAmount)
        } else if let loanAccount {
            resolvedPrincipal = max(.zero, loanAccount.totalLimit.amount - loanAccount.availableLimit.amount)
        } else {
            resolvedPrincipal = max(.zero, fullRepayAmount)
        }

        guard resolvedPrincipal > .zero else {
            return nil
        }

        let resolvedRate = max(
            borrowResult?.annualRate ?? loanAccount?.annualRate ?? .zero,
            .zero
        )

        return LoanAccountRepaymentCalculator.quote(
            currentPrincipal: resolvedPrincipal,
            annualRatePercent: resolvedRate,
            installmentText: borrowResult?.installmentText,
            borrowedAt: borrowResult?.borrowedAt,
            interestSettledThroughDate: borrowResult?.interestSettledThroughDate
        )
    }

    private var normalizedAmountInput: String {
        let trimmed = amountInput.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else {
            return ""
        }
        if trimmed.hasSuffix(".") {
            return String(trimmed.dropLast())
        }
        return trimmed
    }

    private var enteredRepayAmount: Decimal? {
        let normalized = normalizedAmountInput
        guard !normalized.isEmpty else {
            return nil
        }
        return Decimal(string: normalized, locale: Locale(identifier: "en_US_POSIX"))
    }

    private var hasEnteredAmount: Bool {
        !amountInput.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
    }

    private var canSubmitAmount: Bool {
        guard let enteredRepayAmount else {
            return false
        }
        guard enteredRepayAmount > .zero else {
            return false
        }
        return displayedFullRepayAmount == .zero || enteredRepayAmount <= displayedFullRepayAmount
    }

    private var filteredBankTools: [CashierPayToolData] {
        CashierPresentationHelper.filteredBankTools(payTools, policy: sceneConfiguration.bankCardPolicy)
    }

    private var selectedBankTool: CashierPayToolData? {
        if let selectedBankToolCode {
            return filteredBankTools.first(where: { $0.toolCode == selectedBankToolCode })
        }
        return filteredBankTools.first(where: \.defaultSelected) ?? filteredBankTools.first
    }

    private var selectedPaymentMethodTitle: String {
        switch selectedPaymentMethodType {
        case .wallet, .fund:
            return selectedPaymentMethodType.defaultTitle
        case .aiCredit:
            return "爱花"
        case .bankCard:
            guard let selectedBankTool else {
                return "银行卡"
            }
            return CashierPresentationHelper.bankDisplayName(for: selectedBankTool, replaceDebitWithSavings: true)
        }
    }

    private var selectedPaymentMethodSubtitle: String {
        switch selectedPaymentMethodType {
        case .wallet:
            return CashierPresentationHelper.availableDetailText(
                availableAmountText: walletAvailableAmountText,
                isLoading: isLoadingWalletBalance
            )
        case .fund:
            return CashierPresentationHelper.availableDetailText(
                availableAmountText: fundAvailableAmountText,
                isLoading: isLoadingFundBalance
            )
        case .aiCredit:
            return "当前场景暂不支持爱花付款"
        case .bankCard:
            guard let selectedBankTool else {
                return isLoadingPayTools ? "加载付款方式中..." : "请选择银行卡"
            }
            let normalized = selectedBankTool.toolDescription.trimmingCharacters(in: .whitespacesAndNewlines)
            if !normalized.isEmpty {
                return normalized
            }
            return CashierPresentationHelper.bankSubtitle(for: selectedBankTool, fallbackText: "银行卡")
        }
    }

    private var selectedPaymentMethodDisplayText: String {
        switch selectedPaymentMethodType {
        case .wallet, .fund:
            return selectedPaymentMethodType.defaultTitle
        case .aiCredit:
            return "爱花"
        case .bankCard:
            guard let selectedBankTool else {
                return "银行卡"
            }
            return CashierPresentationHelper.bankDisplayName(for: selectedBankTool, replaceDebitWithSavings: true)
        }
    }

    private var statusBannerText: String? {
        if let submitMessage, !submitMessage.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            return submitMessage
        }
        if isSubmitting {
            return "还款处理中"
        }
        if isLoadingPayTools || isLoadingWalletBalance || isLoadingFundBalance {
            return nil
        }
        if selectedPaymentMethodType == .bankCard,
           let payToolsErrorMessage,
           !payToolsErrorMessage.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            return payToolsErrorMessage
        }
        return nil
    }

    private var statusBannerColor: Color {
        if submitMessage != nil || (selectedPaymentMethodType == .bankCard && payToolsErrorMessage != nil) {
            return Color(red: 0.77, green: 0.20, blue: 0.20)
        }
        return Color(red: 0.48, green: 0.49, blue: 0.52)
    }

    var body: some View {
        GeometryReader { proxy in
            let scaleX = proxy.size.width / baseWidth
            let scaleY = proxy.size.height / baseHeight
            let fontScale = min(scaleX, scaleY)

            ZStack(alignment: .bottom) {
                Image(hasEnteredAmount ? "LoanAccountRepayAfterAmountReference" : "LoanAccountRepayCashierReference")
                    .resizable()
                    .interpolation(.high)
                    .aspectRatio(contentMode: .fill)
                    .frame(width: proxy.size.width, height: proxy.size.height)
                    .clipped()

                repaySummaryOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                amountInputOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)

                if hasEnteredAmount {
                    enteredAmountDetailsOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                }

                hotspots(scaleX: scaleX, scaleY: scaleY)
                keypadOverlay(scaleX: scaleX, scaleY: scaleY)

                if isPaymentToolsExpanded {
                    RepayPaymentToolPickerSheetView(
                        scaleX: scaleX,
                        scaleY: scaleY,
                        fontScale: fontScale,
                        sheetTitle: "选择付款方式",
                        accessibilityPrefix: "loan_repay_cashier",
                        backdropOpacity: 0.01,
                        prefersLeadingCloseButton: false,
                        sceneConfiguration: sceneConfiguration,
                        bankTools: filteredBankTools,
                        selectedBankToolCode: selectedBankToolCode,
                        selectedPaymentMethodType: selectedPaymentMethodType,
                        walletAvailableAmountText: walletAvailableAmountText,
                        fundAvailableAmountText: fundAvailableAmountText,
                        isLoadingWalletBalance: isLoadingWalletBalance,
                        isLoadingFundBalance: isLoadingFundBalance,
                        isLoadingBankTools: isLoadingPayTools,
                        bankToolsErrorMessage: payToolsErrorMessage,
                        onClose: {
                            isPaymentToolsExpanded = false
                        },
                        onSelectWallet: {
                            selectedPaymentMethodType = .wallet
                            isPaymentToolsExpanded = false
                        },
                        onSelectFund: {
                            selectedPaymentMethodType = .fund
                            isPaymentToolsExpanded = false
                        },
                        onSelectAiCredit: {},
                        onSelectBankTool: { toolCode in
                            selectedPaymentMethodType = .bankCard
                            selectedBankToolCode = toolCode
                            isPaymentToolsExpanded = false
                        }
                    )
                    .zIndex(20)
                }

                if isInterestExplanationPresented {
                    interestExplanationOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                        .zIndex(30)
                }
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .ignoresSafeArea()
        .task(id: payerUserId ?? 0) {
            await refreshLoanRepayCashierData()
        }
    }

