    private func keypadOverlay(scaleX: CGFloat, scaleY: CGFloat) -> some View {
        let keypadGridHeight = keypadHeight - keypadBottomInset
        let keypadRowHeight = keypadGridHeight / 4
        let rightDeleteHeight = keypadRowHeight
        let rightConfirmHeight = keypadRowHeight * 3
        let rightBottomInset = keypadBottomInset

        return HStack(spacing: 0) {
            LazyVGrid(columns: Array(repeating: GridItem(.flexible(), spacing: 0), count: 3), spacing: 0) {
                ForEach(Array(keypadRows.flatMap { $0 }.enumerated()), id: \.offset) { _, key in
                    if key.isEmpty {
