    private func handleKeyInput(_ key: String) {
        guard key.count == 1 else {
            return
        }
        isAmountInputFocused = true
        isInterestExplanationPresented = false
        submitMessage = nil

        var next = amountInput
        if key == "." {
            if next.contains(".") {
                return
            }
            if next.isEmpty {
                next = "0."
            } else {
                next.append(".")
            }
        } else {
            if next == "0" {
                next = key == "0" ? next : key
            } else {
                next.append(key)
            }
        }

        next = sanitizeAmountInput(next)
        if let amount = decimalValue(from: next), displayedFullRepayAmount > .zero, amount > displayedFullRepayAmount {
            amountInput = formatAmountFixed2(displayedFullRepayAmount)
            return
        }
        amountInput = next
    }

    private func removeLastInputCharacter() {
        isAmountInputFocused = true
        isInterestExplanationPresented = false
        guard !amountInput.isEmpty else {
            return
        }
        amountInput.removeLast()
    }

    private func clearAmountInput() {
        amountInput = ""
        isInterestExplanationPresented = false
        submitMessage = nil
        isAmountInputFocused = true
    }

    private func applyFullRepaymentAmount() {
        amountInput = formatAmountFixed2(displayedFullRepayAmount)
        isInterestExplanationPresented = false
        submitMessage = nil
        isAmountInputFocused = true
    }

    private func sanitizeAmountInput(_ text: String) -> String {
        let filtered = text.filter { $0.isNumber || $0 == "." }
        if filtered.isEmpty {
            return ""
        }

        var result = ""
        var hasDot = false
        var fractionalCount = 0
        for ch in filtered {
            if ch == "." {
                if hasDot {
                    continue
                }
                hasDot = true
                if result.isEmpty {
                    result = "0"
                }
                result.append(ch)
                continue
            }

            if hasDot {
                if fractionalCount >= 2 {
                    continue
                }
                fractionalCount += 1
            }
            result.append(ch)
        }

        if result.hasPrefix("00"), !result.hasPrefix("0.") {
            while result.count > 1, result.first == "0", result.dropFirst().first != "." {
                result.removeFirst()
            }
        }
        return result
    }

    private func decimalValue(from text: String) -> Decimal? {
        let normalized = text.hasSuffix(".") ? String(text.dropLast()) : text
        guard !normalized.isEmpty else {
            return nil
        }
        return Decimal(string: normalized, locale: Locale(identifier: "en_US_POSIX"))
    }

    private func resolvedPaymentMethodType(
        preferred: RepayPaymentMethodType,
        sceneConfiguration: CashierSceneConfiguration,
        hasBankTools: Bool
    ) -> RepayPaymentMethodType {
        if preferred == .bankCard {
            if sceneConfiguration.supports(.bankCard), hasBankTools {
                return .bankCard
            }
        } else if preferred != .aiCredit, sceneConfiguration.supports(preferred) {
            return preferred
        }

        if sceneConfiguration.supports(.wallet) {
            return .wallet
        }
        if sceneConfiguration.supports(.fund) {
            return .fund
        }
        if sceneConfiguration.supports(.bankCard), hasBankTools {
            return .bankCard
        }
        return .bankCard
    }

    private func submitLoanRepayment() {
        guard canSubmitAmount, let repayAmount = enteredRepayAmount else {
            return
        }
        isAmountInputFocused = false
        onRepayAmountSelected(repayAmount)
        Task {
            await performLoanRepayment(repayAmount: repayAmount)
        }
    }

    @MainActor
    private func refreshLoanRepayCashierData() async {
        await refreshLoanAccount()
        await loadRepayFundBalance()
        await loadLoanRepayCashierPayTools()
        await loadRepayWalletBalance()
    }

    @MainActor
    private func refreshLoanAccount() async {
        guard let payerUserId, payerUserId > 0 else {
            loanAccount = nil
            return
        }
        do {
            let fetchedAccount = try await APIClient.shared.fetchLoanAccount(userId: payerUserId)
            LoanAccountSyntheticSnapshotStore.saveAccount(fetchedAccount, userId: payerUserId)
            loanAccount = LoanAccountSyntheticSnapshotStore.loadAccount(userId: payerUserId) ?? fetchedAccount
        } catch {
            loanAccount = LoanAccountSyntheticSnapshotStore.loadAccount(userId: payerUserId)
        }
    }

    @MainActor
    private func loadLoanRepayCashierPayTools() async {
        guard let payerUserId, payerUserId > 0 else {
            payTools = []
            selectedBankToolCode = nil
            payToolsErrorMessage = "未找到当前登录用户"
            return
        }

        isLoadingPayTools = true
        payToolsErrorMessage = nil
        do {
            let cashierView = try await APIClient.shared.fetchCashierView(userId: payerUserId, sceneCode: "PAY")
            let resolvedSceneConfiguration = CashierSceneConfiguration.fromServerData(
                cashierView.sceneConfig,
                fallback: .creditRepay
            )
            let baseSceneConfiguration = CashierSceneConfiguration(
                supportedChannels: resolvedSceneConfiguration.supportedChannels.filter { $0 != .aiCredit },
                bankCardPolicy: resolvedSceneConfiguration.bankCardPolicy,
                emptyBankCardText: resolvedSceneConfiguration.emptyBankCardText
            )
            let filteredSceneConfiguration = CashierChannelAvailability.filteredSceneConfiguration(
                baseSceneConfiguration,
                hasFundAvailable: hasFundAvailable,
                hasAiCreditAvailable: false
            )
            sceneConfiguration = filteredSceneConfiguration
            let bankTools = CashierPresentationHelper.filteredBankTools(
                cashierView.payTools,
                policy: filteredSceneConfiguration.bankCardPolicy
            )
            payTools = bankTools
            if let selectedBankToolCode,
               bankTools.contains(where: { $0.toolCode == selectedBankToolCode }) {
                // keep current selection
            } else {
                selectedBankToolCode = bankTools.first(where: \.defaultSelected)?.toolCode ?? bankTools.first?.toolCode
            }
            if bankTools.isEmpty {
                payToolsErrorMessage = filteredSceneConfiguration.emptyBankCardText
            }
            selectedPaymentMethodType = resolvedPaymentMethodType(
                preferred: selectedPaymentMethodType,
                sceneConfiguration: filteredSceneConfiguration,
                hasBankTools: !bankTools.isEmpty
            )
        } catch {
            payTools = []
            selectedBankToolCode = nil
            payToolsErrorMessage = userFacingErrorMessage(error)
            selectedPaymentMethodType = resolvedPaymentMethodType(
                preferred: selectedPaymentMethodType,
                sceneConfiguration: sceneConfiguration,
                hasBankTools: false
            )
        }
        isLoadingPayTools = false
    }

    @MainActor
    private func loadRepayWalletBalance() async {
        guard let payerUserId, payerUserId > 0 else {
            walletAvailableAmountText = "--"
            return
        }

        isLoadingWalletBalance = true
        do {
            let overview = try await APIClient.shared.fetchAssetOverview(userId: String(payerUserId))
            let normalized = overview.availableAmount.trimmingCharacters(in: .whitespacesAndNewlines)
            if normalized.isEmpty {
                walletAvailableAmountText = formatAvailableAmount(.zero)
            } else if let decimal = Decimal(string: normalized.replacingOccurrences(of: ",", with: ""), locale: Locale(identifier: "en_US_POSIX")) {
                walletAvailableAmountText = formatAvailableAmount(decimal)
            } else {
                walletAvailableAmountText = "--"
            }
        } catch {
            walletAvailableAmountText = "--"
        }
        isLoadingWalletBalance = false
    }

    @MainActor
    private func loadRepayFundBalance() async {
        guard let payerUserId, payerUserId > 0 else {
            fundAvailableAmountText = "--"
            hasFundAvailable = false
            return
        }

        isLoadingFundBalance = true
        do {
            let account = try await APIClient.shared.fetchFundAccount(userId: payerUserId)
            hasFundAvailable = CashierChannelAvailability.isFundAccountAvailable(account)
            fundAvailableAmountText = hasFundAvailable ? formatAvailableAmount(account.availableAmount) : "--"
        } catch {
            fundAvailableAmountText = "--"
            hasFundAvailable = false
        }
        isLoadingFundBalance = false
    }

    @MainActor
    private func performLoanRepayment(repayAmount: Decimal) async {
        guard let payerUserId, payerUserId > 0 else {
            submitMessage = "未找到当前登录用户"
            return
        }

        let paymentMethod: String
        let paymentToolCode: String?
        switch selectedPaymentMethodType {
        case .wallet:
            paymentMethod = "WALLET"
            paymentToolCode = nil
        case .fund:
            paymentMethod = "FUND_ACCOUNT"
            paymentToolCode = nil
        case .aiCredit:
            submitMessage = "当前场景暂不支持爱花付款"
            return
        case .bankCard:
            guard let selectedBankTool else {
                submitMessage = payToolsErrorMessage ?? "请选择银行卡"
                return
            }
            paymentMethod = "BANK_CARD"
            paymentToolCode = selectedBankTool.toolCode
        }

        let selectedPaymentMethodText = selectedPaymentMethodDisplayText
        let repayMode = repayAmount == displayedFullRepayAmount ? "full" : "partial"
        let metadata = [
            "creditRepay=true",
            "loanAccount=true",
            "loanRepay=true",
            "repayMode=\(repayMode)"
        ].joined(separator: ";")

        isSubmitting = true
        submitMessage = nil
        onPaySubmitting(selectedPaymentMethodText)
        do {
            _ = try await APIClient.shared.createPayTrade(
                payerUserId: payerUserId,
                payeeUserId: payerUserId,
                amount: repayAmount,
                paymentMethod: paymentMethod,
                paymentToolCode: paymentToolCode,
                businessSceneCode: "APP_LOAN_ACCOUNT_CREDIT_REPAY",
                metadata: metadata
            )
            isSubmitting = false
            let settlement = LoanAccountRepaymentSettlement(
                totalAmount: max(.zero, repayAmount),
                principalAmount: enteredPrincipalAmount,
                interestAmount: enteredInterestAmount,
                didSettleAccruedInterest: displayedInterestAmount > .zero && enteredInterestAmount >= displayedInterestAmount,
                occurredAt: Date()
            )
            onPaySucceeded(selectedPaymentMethodText, settlement)
        } catch {
            let message = userFacingErrorMessage(error)
            isSubmitting = false
            submitMessage = message
            onPayFailed(selectedPaymentMethodText, message)
        }
    }

    private func formatAmountFixed2(_ amount: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = false
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSDecimalNumber(decimal: amount)) ?? "0.00"
    }

    private func formatAmountWithGrouping(_ amount: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "zh_CN")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = true
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        let number = NSDecimalNumber(decimal: amount)
        return formatter.string(from: number) ?? number.stringValue
    }

    private func formatAvailableAmount(_ amount: Decimal) -> String {
        "¥" + formatAmountWithGrouping(max(.zero, amount))
    }

    private func hotspot(
        identifier: String,
        centerX: CGFloat,
        centerY: CGFloat,
        width: CGFloat,
        height: CGFloat,
        isDisabled: Bool = false,
        action: @escaping () -> Void
    ) -> some View {
        Button(action: action) {
            Color.clear
                .frame(width: width, height: height)
                .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
        .disabled(isDisabled)
        .accessibilityIdentifier(identifier)
        .position(x: centerX, y: centerY)
    }

    private struct BlinkingCaretView: View {
        let height: CGFloat
        let color: Color

        var body: some View {
            TimelineView(.periodic(from: .now, by: 0.5)) { context in
                let tick = Int(context.date.timeIntervalSinceReferenceDate / 0.5)
                RoundedRectangle(cornerRadius: 1, style: .continuous)
                    .fill(color)
                    .frame(width: 2, height: height)
                    .opacity(tick.isMultiple(of: 2) ? 1 : 0)
            }
        }
    }
}

