    private var selectedBankTool: CashierPayToolData? {
        if let selectedBankToolCode {
            return payTools.first(where: { $0.toolCode == selectedBankToolCode })
        }
        return payTools.first(where: \.defaultSelected) ?? payTools.first
    }

    private var selectedExpandedBankRowIndex: Int? {
        guard selectedPaymentMethodType == .bankCard,
              let selectedBankToolCode else {
            return nil
        }
        let normalizedSelectedBankToolCode = selectedBankToolCode.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedSelectedBankToolCode.isEmpty else {
            return nil
        }
        return visibleExpandedBankTools.firstIndex(where: { tool in
            tool.toolCode == normalizedSelectedBankToolCode
        })
    }

    private var selectedPaymentMethodTitle: String {
        switch selectedPaymentMethodType {
        case .wallet, .fund, .aiCredit:
            return selectedPaymentMethodType.defaultTitle
        case .bankCard:
            guard let selectedBankTool else {
                return "银行卡"
            }
            return CashierPresentationHelper.bankDisplayName(for: selectedBankTool, replaceDebitWithSavings: true)
        }
    }

    private var selectedPaymentMethodDisplayText: String {
        switch selectedPaymentMethodType {
        case .wallet, .fund, .aiCredit:
            return selectedPaymentMethodType.defaultTitle
        case .bankCard:
            guard let selectedBankTool else {
                return "银行卡"
            }
            return CashierPresentationHelper.bankDisplayName(for: selectedBankTool, replaceDebitWithSavings: true)
        }
    }

    private func resolvedRepayPaymentMethodType(
        preferred: RepayPaymentMethodType,
        sceneConfiguration: CashierSceneConfiguration,
        hasBankTools: Bool
    ) -> RepayPaymentMethodType {
        if preferred == .bankCard {
            if sceneConfiguration.supports(.bankCard), hasBankTools {
                return .bankCard
            }
        } else if sceneConfiguration.supports(preferred) {
            return preferred
        }

        if sceneConfiguration.supports(.wallet) {
            return .wallet
        }
        if sceneConfiguration.supports(.fund) {
            return .fund
        }
        if sceneConfiguration.supports(.aiCredit) {
            return .aiCredit
        }
        if sceneConfiguration.supports(.bankCard), hasBankTools {
            return .bankCard
        }
        return .bankCard
    }

    private var walletExpandedDetailText: String {
        CashierPresentationHelper.availableDetailText(
            availableAmountText: walletAvailableAmountText,
            isLoading: isLoadingWalletBalance
        )
