    private var fundExpandedDetailText: String {
        CashierPresentationHelper.availableDetailText(
            availableAmountText: fundAvailableAmountText,
            isLoading: isLoadingFundBalance
        )
    }

    private var visibleExpandedBankTools: [CashierPayToolData] {
        Array(payTools.prefix(3))
    }

    private var statusBannerText: String? {
        if let submitMessage, !submitMessage.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            return submitMessage
        }
        if isSubmitting {
            return "还款处理中"
        }
        if isLoadingPayTools || isLoadingWalletBalance || isLoadingFundBalance {
            return "支付方式加载中"
        }
        if selectedPaymentMethodType == .bankCard,
           let payToolsErrorMessage,
           !payToolsErrorMessage.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            return payToolsErrorMessage
        }
        return nil
    }

    private var statusBannerColor: Color {
        if submitMessage != nil || (selectedPaymentMethodType == .bankCard && payToolsErrorMessage != nil) {
            return Color(red: 0.77, green: 0.20, blue: 0.20)
        }
        return Color(red: 0.48, green: 0.49, blue: 0.52)
    }

