    private func yaHeiRegularFont(size: CGFloat) -> Font {
        let candidates = [
            "MicrosoftYaHei",
            "Microsoft YaHei",
            "MicrosoftYaHei-Light",
            "MicrosoftYaHeiUI",
            "Microsoft YaHei UI",
            "微软雅黑",
            "PingFangSC-Regular"
        ]
        for name in candidates where UIFont(name: name, size: size) != nil {
            return .custom(name, size: size)
        }
        return .system(size: size, weight: .regular)
    }

    private func heiTiFont(size: CGFloat) -> Font {
        let candidates = [
            "STHeitiSC-Medium",
            "STHeitiSC-Light",
            "Heiti SC",
            "PingFangSC-Semibold"
        ]
        for name in candidates where UIFont(name: name, size: size) != nil {
            return .custom(name, size: size)
        }
        return .system(size: size, weight: .semibold)
    }

    private func replacementSlot(
        text: String,
        centerX: CGFloat,
        centerY: CGFloat,
        width: CGFloat,
        height: CGFloat,
        scaleX: CGFloat,
        scaleY: CGFloat,
        font: Font,
        textColor: Color,
        backgroundColor: Color = .clear,
        horizontalPadding: CGFloat = 2
    ) -> some View {
        ZStack(alignment: .leading) {
            Rectangle()
                .fill(backgroundColor)

            if !text.isEmpty {
                Text(text)
                    .font(font)
                    .foregroundStyle(textColor)
                    .lineLimit(1)
                    .minimumScaleFactor(0.72)
                    .padding(.leading, horizontalPadding * min(scaleX, scaleY))
            }
        }
        .frame(width: width * scaleX, height: height * scaleY, alignment: .leading)
        .position(x: centerX * scaleX, y: centerY * scaleY)
    }

    @MainActor
    private func refreshRepayCashierData() async {
        await loadRepayFundBalance()
        await loadRepayCashierPayTools()
        await loadRepayWalletBalance()
        await loadRepayCurrentBillDueSnapshot()
    }

    @MainActor
    private func loadRepayCashierPayTools() async {
        guard let payerUserId, payerUserId > 0 else {
            payTools = []
            selectedBankToolCode = nil
            payToolsErrorMessage = "未找到当前登录用户"
            return
        }

        isLoadingPayTools = true
        payToolsErrorMessage = nil
        do {
            let cashierView = try await APIClient.shared.fetchCashierView(userId: payerUserId, sceneCode: "PAY")
            let baseSceneConfiguration = CashierSceneConfiguration.fromServerData(
                cashierView.sceneConfig,
                fallback: .creditRepay
            )
            let resolvedSceneConfiguration = CashierChannelAvailability.filteredSceneConfiguration(
                baseSceneConfiguration,
                hasFundAvailable: hasFundAvailable,
                hasAiCreditAvailable: baseSceneConfiguration.supports(.aiCredit)
            )
            sceneConfiguration = resolvedSceneConfiguration
            let bankTools = cashierView.payTools
            payTools = bankTools
            if let selectedBankToolCode,
               bankTools.contains(where: { $0.toolCode == selectedBankToolCode }) {
                // 保留用户当前选择。
            } else {
                selectedBankToolCode = bankTools.first(where: \.defaultSelected)?.toolCode ?? bankTools.first?.toolCode
            }
            if bankTools.isEmpty {
                payToolsErrorMessage = resolvedSceneConfiguration.emptyBankCardText
            }
            selectedPaymentMethodType = self.resolvedRepayPaymentMethodType(
                preferred: selectedPaymentMethodType,
                sceneConfiguration: resolvedSceneConfiguration,
                hasBankTools: !bankTools.isEmpty
            )
        } catch {
            payTools = []
            selectedBankToolCode = nil
            payToolsErrorMessage = userFacingErrorMessage(error)
            selectedPaymentMethodType = self.resolvedRepayPaymentMethodType(
                preferred: selectedPaymentMethodType,
                sceneConfiguration: sceneConfiguration,
                hasBankTools: false
            )
        }
        isLoadingPayTools = false
    }

    @MainActor
    private func loadRepayWalletBalance() async {
        guard let payerUserId, payerUserId > 0 else {
            walletAvailableAmountText = "--"
            return
        }

        isLoadingWalletBalance = true
        do {
            let overview = try await APIClient.shared.fetchAssetOverview(userId: String(payerUserId))
            let normalized = overview.availableAmount.trimmingCharacters(in: .whitespacesAndNewlines)
            if normalized.isEmpty {
                walletAvailableAmountText = formatAvailableAmount(.zero)
            } else if let decimal = Decimal(string: normalized.replacingOccurrences(of: ",", with: ""), locale: Locale(identifier: "en_US_POSIX")) {
                walletAvailableAmountText = formatAvailableAmount(decimal)
            } else {
                walletAvailableAmountText = "--"
            }
        } catch {
            walletAvailableAmountText = "--"
        }
        isLoadingWalletBalance = false
    }

    @MainActor
    private func loadRepayFundBalance() async {
        guard let payerUserId, payerUserId > 0 else {
            fundAvailableAmountText = "--"
            hasFundAvailable = false
            return
        }

        isLoadingFundBalance = true
        do {
            let account = try await APIClient.shared.fetchFundAccount(userId: payerUserId)
            hasFundAvailable = CashierChannelAvailability.isFundAccountAvailable(account)
            fundAvailableAmountText = hasFundAvailable ? formatAvailableAmount(account.availableAmount) : "--"
        } catch {
            fundAvailableAmountText = "--"
            hasFundAvailable = false
        }
        isLoadingFundBalance = false
    }

    @MainActor
    private func loadRepayCurrentBillDueSnapshot() async {
        guard let payerUserId, payerUserId > 0 else {
            currentBillDueAmountSnapshot = nil
            return
        }
        do {
            let billDetail = try await fetchRepayTargetBillDetail(userId: payerUserId)
            currentBillDueAmountSnapshot = max(.zero, billDetail.dueAmount.amount)
        } catch {
            currentBillDueAmountSnapshot = nil
        }
    }

    @MainActor
    private func resolveLatestRepayCurrentBillDueAmount() async -> Decimal? {
        guard let payerUserId, payerUserId > 0 else {
            currentBillDueAmountSnapshot = nil
            return nil
        }
        do {
            let billDetail = try await fetchRepayTargetBillDetail(userId: payerUserId)
            let latestDueAmount = max(.zero, billDetail.dueAmount.amount)
            currentBillDueAmountSnapshot = latestDueAmount
            return latestDueAmount
        } catch {
            return currentBillDueAmountSnapshot
        }
    }

    private func fetchRepayTargetBillDetail(userId: Int64) async throws -> CreditCurrentBillDetailData {
        switch repayBillMode {
        case .current:
            return try await APIClient.shared.fetchCreditCurrentBillDetail(userId: userId)
        case .next:
            return try await APIClient.shared.fetchCreditNextBillDetail(userId: userId)
        }
    }

    @MainActor
    private func submitRepayment() async {
        guard let payerUserId, payerUserId > 0 else {
            submitMessage = "未找到当前登录用户"
            return
        }
        guard repayAmount > .zero else {
            submitMessage = "还款金额必须大于0"
            return
        }

        let paymentMethod: String
        let paymentToolCode: String?
        switch selectedPaymentMethodType {
        case .wallet:
            paymentMethod = "WALLET"
            paymentToolCode = nil
        case .fund:
            paymentMethod = "FUND_ACCOUNT"
            paymentToolCode = nil
        case .aiCredit:
            submitMessage = "当前场景暂不支持爱花付款"
            return
        case .bankCard:
            guard let selectedBankTool else {
                submitMessage = payToolsErrorMessage ?? "请选择银行卡"
                return
            }
            paymentMethod = "BANK_CARD"
            paymentToolCode = selectedBankTool.toolCode
        }

        let selectedPaymentMethodText = selectedPaymentMethodDisplayText
        let latestCurrentBillDueAmount = await resolveLatestRepayCurrentBillDueAmount()
        let expectedRemainingDueAmount = latestCurrentBillDueAmount.map { dueAmount in
            max(.zero, dueAmount - max(.zero, repayAmount))
        }
        let creditRepayMetadata = repayBillMode == .next
                ? "creditRepay=true;repayBillMode=next"
                : "creditRepay=true;repayBillMode=current"
        isSubmitting = true
        submitMessage = nil
        onPaySubmitting(selectedPaymentMethodText)
        do {
            _ = try await APIClient.shared.createPayTrade(
                payerUserId: payerUserId,
                payeeUserId: payerUserId,
                amount: repayAmount,
                paymentMethod: paymentMethod,
                paymentToolCode: paymentToolCode,
                businessSceneCode: "APP_CREDIT_REPAY",
                metadata: creditRepayMetadata
            )
            isSubmitting = false
            onPaySucceeded(selectedPaymentMethodText, expectedRemainingDueAmount)
        } catch {
            let message = userFacingErrorMessage(error)
            isSubmitting = false
            submitMessage = message
            onPayFailed(selectedPaymentMethodText, message)
        }
    }

    private func formatAmountFixed2(_ amount: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = false
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSDecimalNumber(decimal: amount)) ?? "0.00"
    }

    private func hotspot(
        identifier: String,
        centerX: CGFloat,
        centerY: CGFloat,
        width: CGFloat,
        height: CGFloat,
        isDisabled: Bool = false,
        action: @escaping () -> Void
    ) -> some View {
        Button(action: action) {
            Color.clear
                .frame(width: width, height: height)
                .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
        .disabled(isDisabled)
        .accessibilityIdentifier(identifier)
        .position(x: centerX, y: centerY)
    }
    }


fileprivate struct MobileHallCashierView: View {
    let userId: Int64?
    let amount: Decimal
    let topUpMobile: String?
    let availableCoupons: [HomeView.MobileTopUpRewardCoupon]
    let selectedCouponNo: String?
    let onSelectCoupon: (String?) -> Void
    let onBack: () -> Void
    let onCouponConsumed: (String) -> Void
    let onPaySubmitting: (Decimal, String, Decimal) -> Void
    let onPaySucceeded: (Decimal, String, Decimal, TransferTradeData) -> Void
    let onPayFailed: (Decimal, String, String) -> Void

    @State private var isPaymentToolsExpanded = false
    @State private var isCouponPickerPresented = false
    @State private var isSubmittingPayment = false
    @State private var submitErrorMessage: String?
    @State private var sceneConfiguration: CashierSceneConfiguration = CashierChannelAvailability.filteredSceneConfiguration(
        .mobileHallTopUp,
        hasFundAvailable: false,
        hasAiCreditAvailable: false
    )
    @State private var payTools: [CashierPayToolData] = []
    @State private var selectedBankToolCode: String?
    @State private var selectedPaymentMethodType: RepayPaymentMethodType = .aiCredit
    @State private var walletAvailableAmountText: String = "--"
    @State private var fundAvailableAmountText: String = "--"
    @State private var aiCreditAvailableAmountText: String = "--"
    @State private var isLoadingWalletBalance = false
    @State private var isLoadingFundBalance = false
    @State private var isLoadingPayTools = false
    @State private var isLoadingAiCredit = false
    @State private var payToolsErrorMessage: String?
    @State private var hasAiCreditAvailable = true
    @State private var hasFundAvailable = false

    private let baseWidth: CGFloat = 402
    private let baseHeight: CGFloat = 874
    private let sheetTopY: CGFloat = 1372.0 / 3.0
    private let sheetHeight: CGFloat = (2622.0 - 1372.0) / 3.0
    private let paymentRowBackgroundColor = Color(red: 252 / 255, green: 252 / 255, blue: 252 / 255)
    private let mobileHallPayeeUserId: Int64 = 880201069206400001

    private var normalizedSelectedCouponNo: String? {
        let normalized = selectedCouponNo?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        return normalized.isEmpty ? nil : normalized
    }

    private var sortedAvailableCoupons: [HomeView.MobileTopUpRewardCoupon] {
        availableCoupons.sorted { lhs, rhs in
            if lhs.amount != rhs.amount {
                return lhs.amount > rhs.amount
            }
            let lhsDate = lhs.expireDateText ?? "9999-12-31"
            let rhsDate = rhs.expireDateText ?? "9999-12-31"
            if lhsDate != rhsDate {
                return lhsDate < rhsDate
            }
            return lhs.couponNo < rhs.couponNo
        }
    }

    private var selectedCoupon: HomeView.MobileTopUpRewardCoupon? {
        if let normalizedSelectedCouponNo,
           let matched = sortedAvailableCoupons.first(where: { $0.couponNo == normalizedSelectedCouponNo }) {
            return matched
        }
        return sortedAvailableCoupons.first
    }

    private var appliedCouponAmount: Decimal {
        max(selectedCoupon?.amount ?? .zero, .zero)
    }

    private var payableAmount: Decimal {
        max(.zero, amount - appliedCouponAmount)
    }

    private var hasAppliedCoupon: Bool {
        appliedCouponAmount > .zero
    }

    private var hasAvailableCoupons: Bool {
        !sortedAvailableCoupons.isEmpty
    }

    private var mobileHallTopUpTradeMetadata: String {
        var metadataItems = [
            "entry=mobile-hall-top-up",
            "operator=CHINA_MOBILE",
            "product=PHONE_BILL",
        ]
        if let normalizedMobile = normalizedMainlandMobile(topUpMobile) {
            metadataItems.append("mobile=\(normalizedMobile)")
        }
        return metadataItems.joined(separator: ";")
    }

    private var couponSelectionSyncKey: String {
        let couponKey = sortedAvailableCoupons.map(\.couponNo).joined(separator: ",")
        let selectedKey = normalizedSelectedCouponNo ?? "none"
        return selectedKey + "|" + couponKey
    }

    private var walletAvailableAmountValue: Decimal? {
        parseAmountText(walletAvailableAmountText)
    }

    private var isWalletBalanceInsufficientForTopUp: Bool {
        guard let availableAmount = walletAvailableAmountValue else {
            return false
        }
        return payableAmount > max(availableAmount, .zero)
    }

    private var walletDetailTextOverrideForTopUp: String? {
        guard isWalletBalanceInsufficientForTopUp else {
            return nil
        }
        let normalizedAmountText = walletAvailableAmountText.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedAmountText.isEmpty, normalizedAmountText != "--" else {
            return nil
        }
        return "可用: \(normalizedAmountText) 余额不足"
    }

    var body: some View {
        GeometryReader { proxy in
            let scaleX = proxy.size.width / baseWidth
            let scaleY = proxy.size.height / baseHeight
            let fontScale = min(scaleX, scaleY)

            ZStack {
                Color.black
                    .opacity(isPaymentToolsExpanded ? 0.42 : 0.34)
                    .ignoresSafeArea()
                    .contentShape(Rectangle())
                    .onTapGesture {
                        if isCouponPickerPresented {
                            withAnimation(.easeOut(duration: 0.2)) {
                                isCouponPickerPresented = false
                            }
                        } else if isPaymentToolsExpanded {
                            isPaymentToolsExpanded = false
                        } else {
                            onBack()
                        }
                    }

                Image("MobileHallCashierCollapsedSheet")
                    .resizable()
                    .interpolation(.high)
                    .frame(width: baseWidth * scaleX, height: sheetHeight * scaleY)
                    .position(
                        x: 201 * scaleX,
                        y: (sheetTopY + sheetHeight / 2) * scaleY
                    )

                collapsedOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)

                if !isPaymentToolsExpanded && !isCouponPickerPresented {
                    hotspot(
                        identifier: "mobile_hall_cashier_close",
                        centerX: 33 * scaleX,
                        centerY: 478 * scaleY,
                        width: 52 * scaleX,
                        height: 52 * scaleY,
                        isDisabled: isSubmittingPayment,
                        action: onBack
                    )

                    hotspot(
                        identifier: "mobile_hall_cashier_change_payment_method",
                        centerX: 328 * scaleX,
                        centerY: 478 * scaleY,
                        width: 126 * scaleX,
                        height: 40 * scaleY,
                        isDisabled: isSubmittingPayment
                    ) {
                        isPaymentToolsExpanded = true
                    }

                    hotspot(
                        identifier: "mobile_hall_cashier_payment_row",
                        centerX: 201 * scaleX,
                        centerY: 690 * scaleY,
                        width: 344 * scaleX,
                        height: 74 * scaleY,
                        isDisabled: isSubmittingPayment
                    ) {
                        isPaymentToolsExpanded = true
                    }

                    if hasAvailableCoupons {
                        hotspot(
                            identifier: "mobile_hall_cashier_coupon_selector",
                            centerX: 201 * scaleX,
                            centerY: 607 * scaleY,
                            width: 256 * scaleX,
                            height: 32 * scaleY,
                            isDisabled: isSubmittingPayment
                        ) {
                            withAnimation(.easeOut(duration: 0.2)) {
                                isCouponPickerPresented = true
                            }
                        }
                    }

                    hotspot(
                        identifier: "mobile_hall_cashier_submit",
                        centerX: 201 * scaleX,
                        centerY: 776 * scaleY,
                        width: 258 * scaleX,
                        height: 62 * scaleY,
                        isDisabled: isSubmittingPayment
                    ) {
                        Task {
                            await submitPayment()
                        }
                    }
                }

                if isPaymentToolsExpanded {
                    RepayPaymentToolPickerSheetView(
                        scaleX: scaleX,
                        scaleY: scaleY,
                        fontScale: fontScale,
                        accessibilityPrefix: "mobile_hall_cashier",
                        backdropOpacity: 0.001,
                        sceneConfiguration: sceneConfiguration,
                        bankTools: payTools,
                        selectedBankToolCode: selectedBankToolCode,
                        selectedPaymentMethodType: selectedPaymentMethodType,
                        walletAvailableAmountText: walletAvailableAmountText,
                        fundAvailableAmountText: fundAvailableAmountText,
                        isLoadingWalletBalance: isLoadingWalletBalance,
                        isLoadingFundBalance: isLoadingFundBalance,
                        walletDetailTextOverride: walletDetailTextOverrideForTopUp,
                        isWalletSelectable: !isWalletBalanceInsufficientForTopUp,
                        isLoadingBankTools: isLoadingPayTools,
                        bankToolsErrorMessage: payToolsErrorMessage,
                        onClose: {
                            isPaymentToolsExpanded = false
                        },
                        onSelectWallet: {
                            guard !isWalletBalanceInsufficientForTopUp else {
                                return
                            }
                            selectedPaymentMethodType = .wallet
                            isPaymentToolsExpanded = false
                        },
                        onSelectFund: {
                            selectedPaymentMethodType = .fund
                            isPaymentToolsExpanded = false
                        },
                        onSelectAiCredit: {
                            selectedPaymentMethodType = .aiCredit
                            isPaymentToolsExpanded = false
                        },
                        onSelectBankTool: { toolCode in
                            selectedPaymentMethodType = .bankCard
                            selectedBankToolCode = toolCode
                            isPaymentToolsExpanded = false
                        }
                    )
                    .zIndex(40)
                }

                if isCouponPickerPresented {
                    couponPickerSheet(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                        .transition(.move(edge: .bottom).combined(with: .opacity))
                        .zIndex(45)
                }
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .ignoresSafeArea()
        .task(id: userId) {
            await refreshCashierData()
        }
        .task(id: couponSelectionSyncKey) {
            await MainActor.run {
                ensureSelectedCouponIfNeeded()
                ensurePaymentMethodAvailabilityAfterCouponChange()
            }
        }
        .alert("支付失败", isPresented: Binding(
            get: { submitErrorMessage != nil },
            set: { if !$0 { submitErrorMessage = nil } }
        )) {
            Button("知道了", role: .cancel) {
                submitErrorMessage = nil
            }
        } message: {
            Text(submitErrorMessage ?? "")
        }
    }

    private func ensureSelectedCouponIfNeeded() {
        guard hasAvailableCoupons else {
            if normalizedSelectedCouponNo != nil {
                onSelectCoupon(nil)
            }
            return
        }
        guard let normalizedSelectedCouponNo,
              sortedAvailableCoupons.contains(where: { $0.couponNo == normalizedSelectedCouponNo }) else {
            onSelectCoupon(sortedAvailableCoupons.first?.couponNo)
            return
        }
    }

    private func ensurePaymentMethodAvailabilityAfterCouponChange() {
        guard selectedPaymentMethodType == .wallet,
              isWalletBalanceInsufficientForTopUp else {
            return
        }
        selectedPaymentMethodType = resolvedPaymentMethodType(
            preferred: .aiCredit,
            hasBankTools: !payTools.isEmpty,
            hasFundAvailable: hasFundAvailable,
            hasAiCreditAvailable: hasAiCreditAvailable,
            isWalletSelectable: false
        )
    }

