                .frame(width: 236 * scaleX, alignment: .center)
                .position(x: 201 * scaleX, y: 566.2 * scaleY)

            if hasAppliedCoupon {
                HStack(spacing: 5 * scaleX) {
                    Text("¥\(formatAmountFixed2(amount))")
                        .font(.system(size: 13 * fontScale, weight: .medium))
