    private func couponPickerSheet(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        VStack(spacing: 0) {
            Capsule(style: .continuous)
                .fill(Color(red: 0.86, green: 0.86, blue: 0.89))
                .frame(width: 42 * scaleX, height: 5 * scaleY)
                .padding(.top, 10 * scaleY)

            HStack {
                Spacer()
                Text("其他优惠")
                    .font(.system(size: 17 * fontScale, weight: .semibold))
                    .foregroundStyle(Color(red: 0.18, green: 0.18, blue: 0.21))
                Spacer()
            }
            .padding(.top, 12 * scaleY)
            .padding(.bottom, 8 * scaleY)

            ScrollView(showsIndicators: false) {
                VStack(spacing: 0) {
                    if sortedAvailableCoupons.isEmpty {
                        Text("暂无可用优惠")
                            .font(.system(size: 14 * fontScale, weight: .regular))
