    private func couponExpireDisplayText(_ coupon: HomeView.MobileTopUpRewardCoupon) -> String {
        let normalizedDate = coupon.expireDateText?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if normalizedDate.isEmpty {
            return "有效期：长期有效"
        }
        return "有效期至 \(normalizedDate)"
    }

