    private var selectedBankTool: CashierPayToolData? {
        payTools.first(where: { $0.toolCode == selectedBankToolCode }) ?? payTools.first
    }

    private var selectedPaymentMethodTitle: String {
        switch selectedPaymentMethodType {
        case .wallet:
            return CashierChannelKind.wallet.defaultTitle
        case .fund:
            return CashierChannelKind.fund.defaultTitle
        case .aiCredit:
            return CashierChannelKind.aiCredit.defaultTitle
        case .bankCard:
            if let selectedBankTool {
                return CashierPresentationHelper.bankDisplayName(for: selectedBankTool, replaceDebitWithSavings: true)
            }
            return CashierChannelKind.bankCard.defaultTitle
        }
    }

    private var selectedPaymentMethodSubtitle: String {
        switch selectedPaymentMethodType {
        case .wallet:
            if isWalletBalanceInsufficientForTopUp {
                return "可用余额不足以支付本次充值"
            }
            return "本场景支持余额支付"
        case .fund:
            return "本场景支持爱存支付"
        case .aiCredit:
            return "本场景支持信用支付"
        case .bankCard:
            if let selectedBankTool {
                return CashierPresentationHelper.bankSubtitle(for: selectedBankTool, fallbackText: "银行卡")
            }
            return payToolsErrorMessage ?? sceneConfiguration.emptyBankCardText
        }
    }

    private var selectedPaymentMethodDisplayText: String {
        selectedPaymentMethodTitle.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
            ? "爱花"
            : selectedPaymentMethodTitle.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private var selectedPaymentToolCode: String? {
        switch selectedPaymentMethodType {
        case .bankCard:
            return selectedBankTool?.toolCode
        default:
            return nil
        }
    }

    private var selectedPaymentMethodRequestCode: String {
        switch selectedPaymentMethodType {
        case .wallet:
            return "WALLET"
        case .fund:
            return "FUND_ACCOUNT"
        case .aiCredit:
            return "AICREDIT"
        case .bankCard:
            return "BANK_CARD"
        }
    }

    @MainActor
    private func submitPayment() async {
        guard !isSubmittingPayment else {
            return
        }
        guard let userId, userId > 0 else {
            submitErrorMessage = "未找到当前登录用户，请重新登录"
            return
        }

        isSubmittingPayment = true
        submitErrorMessage = nil
        defer { isSubmittingPayment = false }

        if let insufficientMessage = await insufficientBalanceMessageIfNeeded(userId: userId) {
            submitErrorMessage = insufficientMessage
            return
        }

        let paymentMethodText = selectedPaymentMethodDisplayText
        let normalizedCouponNo = selectedCoupon?.couponNo.trimmingCharacters(in: .whitespacesAndNewlines)
        let hasAppliedCoupon = (normalizedCouponNo?.isEmpty == false) && appliedCouponAmount > .zero
        let couponDiscountAmount = hasAppliedCoupon ? appliedCouponAmount : .zero
        onPaySubmitting(amount, paymentMethodText, couponDiscountAmount)

        do {
            let trade = try await APIClient.shared.createPayTrade(
                payerUserId: userId,
                payeeUserId: mobileHallPayeeUserId,
                amount: amount,
                paymentMethod: selectedPaymentMethodRequestCode,
                paymentToolCode: selectedPaymentToolCode,
                couponNo: hasAppliedCoupon ? normalizedCouponNo : nil,
                businessSceneCode: "APP_MOBILE_HALL_TOP_UP",
                metadata: mobileHallTopUpTradeMetadata
            )
            if hasAppliedCoupon, let normalizedCouponNo {
                onCouponConsumed(normalizedCouponNo)
            }
            onPaySucceeded(amount, paymentMethodText, couponDiscountAmount, trade)
        } catch {
            let message = userFacingErrorMessage(error)
            submitErrorMessage = message
            onPayFailed(amount, paymentMethodText, message)
        }
    }

    @MainActor
    private func refreshCashierData() async {
        guard let userId, userId > 0 else {
            payTools = []
            selectedBankToolCode = nil
            walletAvailableAmountText = "--"
            fundAvailableAmountText = "--"
            aiCreditAvailableAmountText = "--"
            hasAiCreditAvailable = false
            hasFundAvailable = false
            sceneConfiguration = resolvedSceneConfiguration(
                hasFundAvailable: false,
                hasAiCreditAvailable: false
            )
            selectedPaymentMethodType = .wallet
            payToolsErrorMessage = nil
            return
        }

        isLoadingWalletBalance = true
        isLoadingFundBalance = true
        isLoadingPayTools = true
        isLoadingAiCredit = true
        payToolsErrorMessage = nil
        walletAvailableAmountText = "--"
        fundAvailableAmountText = "--"

        let walletOverview = try? await APIClient.shared.fetchAssetOverview(userId: String(userId))
        let fundAccount = try? await APIClient.shared.fetchFundAccount(userId: userId)
        let creditAccount = try? await APIClient.shared.fetchCreditAccount(userId: userId)
        let cashierView = try? await APIClient.shared.fetchCashierView(userId: userId, sceneCode: "MOBILE_TOPUP")

        walletAvailableAmountText = formattedCurrency(amountText: walletOverview?.availableAmount)
        let nextFundAvailable = CashierChannelAvailability.isFundAccountAvailable(fundAccount)
        hasFundAvailable = nextFundAvailable
        fundAvailableAmountText = nextFundAvailable ? formattedCurrency(fundAccount?.availableAmount) : "--"

        let nextAiCreditAvailable = isCreditAccountAvailable(creditAccount)
        hasAiCreditAvailable = nextAiCreditAvailable
        aiCreditAvailableAmountText = nextAiCreditAvailable ? formattedCurrency(creditAccount?.availableLimit.amount) : "--"

        let bankTools = CashierPresentationHelper.filteredBankTools(
            cashierView?.payTools ?? [],
            policy: .allCards
        )
        payTools = bankTools
        if let selectedBankToolCode,
           bankTools.contains(where: { $0.toolCode == selectedBankToolCode }) {
        } else {
            selectedBankToolCode = bankTools.first(where: \.defaultSelected)?.toolCode ?? bankTools.first?.toolCode
        }
        if bankTools.isEmpty {
            payToolsErrorMessage = CashierSceneConfiguration.mobileHallTopUp.emptyBankCardText
        }

        sceneConfiguration = resolvedSceneConfiguration(
            hasFundAvailable: hasFundAvailable,
            hasAiCreditAvailable: hasAiCreditAvailable
        )
        selectedPaymentMethodType = resolvedPaymentMethodType(
            preferred: selectedPaymentMethodType,
            hasBankTools: !bankTools.isEmpty,
            hasFundAvailable: hasFundAvailable,
            hasAiCreditAvailable: hasAiCreditAvailable,
            isWalletSelectable: !isWalletBalanceInsufficientForTopUp
        )

        isLoadingWalletBalance = false
        isLoadingFundBalance = false
        isLoadingPayTools = false
        isLoadingAiCredit = false
    }

    @MainActor
    private func insufficientBalanceMessageIfNeeded(userId: Int64) async -> String? {
        switch selectedPaymentMethodType {
        case .wallet:
            guard let overview = try? await APIClient.shared.fetchAssetOverview(userId: String(userId)) else {
                return nil
            }
            let available = parseAmountText(overview.availableAmount) ?? .zero
            if payableAmount > max(available, .zero) {
                return "账户余额不足"
            }
        case .fund:
            guard let fundAccount = try? await APIClient.shared.fetchFundAccount(userId: userId) else {
                return nil
            }
            let available = max(fundAccount.availableAmount, .zero)
            if payableAmount > available {
                return "爱存余额不足"
            }
        case .aiCredit:
            guard let creditAccount = try? await APIClient.shared.fetchCreditAccount(userId: userId) else {
                return nil
            }
            let available = max(creditAccount.availableLimit.amount, .zero)
            if payableAmount > available {
                return "爱花可用额度不足"
            }
        case .bankCard:
            break
        }
        return nil
    }

    private func resolvedSceneConfiguration(
        hasFundAvailable: Bool,
        hasAiCreditAvailable: Bool
    ) -> CashierSceneConfiguration {
        CashierChannelAvailability.filteredSceneConfiguration(
            CashierSceneConfiguration(
                supportedChannels: [.wallet, .fund, .aiCredit, .bankCard],
                bankCardPolicy: .allCards,
                emptyBankCardText: "暂无可用银行卡"
            ),
            hasFundAvailable: hasFundAvailable,
            hasAiCreditAvailable: hasAiCreditAvailable
        )
    }

    private func resolvedPaymentMethodType(
        preferred: RepayPaymentMethodType,
        hasBankTools: Bool,
        hasFundAvailable: Bool,
        hasAiCreditAvailable: Bool,
        isWalletSelectable: Bool
    ) -> RepayPaymentMethodType {
        switch preferred {
        case .aiCredit where hasAiCreditAvailable:
            return .aiCredit
        case .wallet where isWalletSelectable:
            return .wallet
        case .fund where hasFundAvailable:
            return .fund
        case .bankCard where hasBankTools:
            return .bankCard
        default:
            break
        }

        if hasAiCreditAvailable {
            return .aiCredit
        }
        if hasFundAvailable {
            return .fund
        }
        if hasBankTools {
            return .bankCard
        }
        if isWalletSelectable, sceneConfiguration.supports(.wallet) {
            return .wallet
        }
        return .bankCard
    }

    private func isCreditAccountAvailable(_ account: CreditAccountData?) -> Bool {
        guard let account else {
            return false
        }
        return account.totalLimit.amount > .zero
            && account.accountStatus.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() != "CLOSED"
    }

    private func formattedCurrency(_ amount: Decimal?) -> String {
        guard let amount else {
            return "--"
        }
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "zh_CN")
        formatter.numberStyle = .currency
        formatter.currencySymbol = "¥"
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSDecimalNumber(decimal: amount)) ?? "¥0.00"
    }

    private func formattedCurrency(amountText: String?) -> String {
        guard let amountText else {
            return "--"
        }
        let normalized = amountText
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .replacingOccurrences(of: ",", with: "")
        if normalized.isEmpty {
            return "¥0.00"
        }
        guard let amount = Decimal(string: normalized, locale: Locale(identifier: "en_US_POSIX")) else {
            return "--"
        }
        return formattedCurrency(amount)
    }

    private func formatAmountFixed2(_ amount: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = false
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSDecimalNumber(decimal: amount)) ?? "0.00"
    }

    private func parseAmountText(_ raw: String?) -> Decimal? {
        let normalized = raw?
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .replacingOccurrences(of: "¥", with: "")
            .replacingOccurrences(of: "￥", with: "")
            .replacingOccurrences(of: ",", with: "") ?? ""
        guard !normalized.isEmpty else {
            return nil
        }
        return Decimal(string: normalized, locale: Locale(identifier: "en_US_POSIX"))
    }

    private func normalizedMainlandMobile(_ raw: String?) -> String? {
        guard let raw else {
            return nil
        }
        let digits = raw.replacingOccurrences(of: "[^0-9]", with: "", options: .regularExpression)
        guard digits.range(of: "^1[3-9][0-9]{9}$", options: .regularExpression) != nil else {
            return nil
        }
        return digits
    }

    private func hotspot(
        identifier: String,
        centerX: CGFloat,
        centerY: CGFloat,
        width: CGFloat,
        height: CGFloat,
        isDisabled: Bool = false,
        action: @escaping () -> Void
    ) -> some View {
        Button(action: action) {
            Color.clear
                .frame(width: width, height: height)
                .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
        .disabled(isDisabled)
        .accessibilityIdentifier(identifier)
        .position(x: centerX, y: centerY)
    }
}

private struct MobileHallTopUpSuccessView: View {
    let rechargeAmount: Decimal
    let paymentMethodText: String
    let couponDiscountAmount: Decimal
    let resultState: DepositResultState
    let onBackHome: () -> Void
    let onDone: () -> Void

    private let baseWidth: CGFloat = 402
    private let baseHeight: CGFloat = 874
    private let statusMaskColor = AppTheme.palette.brandPrimary
    private let textVerticalOffset: CGFloat = 20

    var body: some View {
        GeometryReader { proxy in
            let scaleX = proxy.size.width / baseWidth
            let scaleY = proxy.size.height / baseHeight
            let fontScale = min(scaleX, scaleY)

            ZStack {
                Image(backgroundAssetName)
                    .resizable()
                    .interpolation(.high)
                    .aspectRatio(contentMode: .fill)
                    .frame(width: proxy.size.width, height: proxy.size.height)
                    .clipped()

                dynamicOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)

                hotspot(
                    identifier: "mobile_hall_topup_success_back_home",
                    centerX: 346 * scaleX,
                    centerY: 73 * scaleY,
                    width: 74 * scaleX,
                    height: 32 * scaleY,
                    isDisabled: resultState == .processing,
                    action: onBackHome
                )

                hotspot(
                    identifier: "mobile_hall_topup_success_done",
                    centerX: 201 * scaleX,
                    centerY: 821 * scaleY,
                    width: 266 * scaleX,
                    height: 62 * scaleY,
                    isDisabled: resultState == .processing,
                    action: onDone
                )
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .ignoresSafeArea()
    }

    @ViewBuilder
    private func dynamicOverlay(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        switch resultState {
        case .processing:
            processingOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
        case .succeeded:
            successOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
        case .failed(let message):
            failureOverlay(message: message, scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
        }
    }


    private var backgroundAssetName: String {
        switch resultState {
        case .processing:
            return "MobileHallTopUpSuccessReference"
        case .succeeded:
            return "MobileHallTopUpSuccessReference"
        case .failed:
            return "MobileHallTopUpProcessingReference"
        }
    }

    private func successOverlay(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        ZStack {
            valueOverlay(
                scaleX: scaleX,
                scaleY: scaleY,
                fontScale: fontScale,
                showsRechargeOrderTitle: false,
                showsPaymentSummary: false
            )
            paymentSummaryOverlay(
                scaleX: scaleX,
                scaleY: scaleY,
                fontScale: fontScale,
                extraVerticalOffset: 0,
                showsCouponSummary: hasCouponDiscountSummary
            )
            successStatusOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
        }
        .allowsHitTesting(false)
    }

    private func processingOverlay(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        ZStack {
            valueOverlay(
                scaleX: scaleX,
                scaleY: scaleY,
                fontScale: fontScale,
                showsRechargeOrderTitle: false,
                showsPaymentSummary: false
            )
            paymentSummaryOverlay(
                scaleX: scaleX,
                scaleY: scaleY,
                fontScale: fontScale,
                extraVerticalOffset: 0,
                showsCouponSummary: hasCouponDiscountSummary
            )
            processingStatusOverlay(
                title: "充值中",
                subtitle: "正在等待充值结果...",
                scaleX: scaleX,
                scaleY: scaleY,
                fontScale: fontScale,
                showsSpinner: true
            )
        }
        .allowsHitTesting(false)
    }

    private func failureOverlay(message: String, scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        ZStack {
            valueOverlay(
                scaleX: scaleX,
                scaleY: scaleY,
                fontScale: fontScale,
                showsRechargeOrderTitle: false,
                showsPaymentSummary: false
            )
            processingStatusOverlay(
                title: "充值失败",
                subtitle: failureDescriptionText(message),
                scaleX: scaleX,
                scaleY: scaleY,
                fontScale: fontScale,
                showsSpinner: false
            )
        }
        .allowsHitTesting(false)
    }

    private func paymentSummaryOverlay(
