            Text("订单金额")
                .font(.system(size: 15.2 * fontScale, weight: .regular))
                .foregroundStyle(Color.white.opacity(0.88))
                .lineLimit(1)
                .minimumScaleFactor(0.72)
                .frame(width: 98 * scaleX, alignment: .leading)
                .position(x: 90 * scaleX, y: orderRowY)

            if showsCouponSummary {
