                    .font(.system(size: 15.2 * fontScale, weight: .regular))
                    .foregroundStyle(Color.white.opacity(0.88))
                    .lineLimit(1)
                    .minimumScaleFactor(0.72)
                    .frame(width: 98 * scaleX, alignment: .leading)
                    .position(x: 90 * scaleX, y: couponRowY)
            }

            Text("交易方式")
                .font(.system(size: 15.2 * fontScale, weight: .regular))
                .foregroundStyle(Color.white.opacity(0.88))
                .lineLimit(1)
                .minimumScaleFactor(0.72)
                .frame(width: 98 * scaleX, alignment: .leading)
                .position(x: 90 * scaleX, y: paymentMethodRowY)

            Text("¥ \(formatAmountFixed2(rechargeAmount))")
                .font(.system(size: 17.5 * fontScale, weight: .semibold))
                .foregroundStyle(Color.white.opacity(0.96))
                .lineLimit(1)
                .minimumScaleFactor(0.72)
                .frame(width: 92 * scaleX, alignment: .trailing)
                .position(x: 332 * scaleX, y: orderRowY)

            if showsCouponSummary {
                Text(formatCouponDiscountText())
                    .font(.system(size: 16 * fontScale, weight: .semibold))
                    .foregroundStyle(Color.white.opacity(0.96))
                    .lineLimit(1)
                    .minimumScaleFactor(0.72)
                    .frame(width: 92 * scaleX, alignment: .trailing)
                    .position(x: 332 * scaleX, y: couponRowY)
            }

            Text(displayPaymentMethodText)
                .font(.system(size: 15.6 * fontScale, weight: .semibold))
                .foregroundStyle(Color.white.opacity(0.98))
                .lineLimit(1)
                .minimumScaleFactor(0.55)
                .frame(width: 76 * scaleX, alignment: .trailing)
                .position(x: 340 * scaleX, y: paymentMethodRowY)
        }
    }

    private func successStatusOverlay(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        let titleY = 92 * scaleY
        let subtitleY = 188 * scaleY
        return ZStack {
            HStack(spacing: 7 * scaleX) {
                Image(systemName: "checkmark.circle")
                    .font(.system(size: 14.5 * fontScale, weight: .semibold))
                    .foregroundStyle(Color.white.opacity(0.98))

                Text("充值成功")
                    .font(.system(size: 17 * fontScale, weight: .semibold))
                    .foregroundStyle(Color.white.opacity(0.98))
                    .lineLimit(1)
            }
            .frame(width: 150 * scaleX, alignment: .center)
            .position(x: 201 * scaleX, y: titleY)

            Text("话费已到账")
                .font(.system(size: 12.8 * fontScale, weight: .regular))
                .foregroundStyle(Color.white.opacity(0.9))
                .lineLimit(1)
                .minimumScaleFactor(0.72)
                .frame(width: 122 * scaleX, alignment: .center)
                .position(x: 201 * scaleX, y: subtitleY)
        }
    }


    private func paymentMethodArtifactsCleanupOverlay(scaleX: CGFloat, scaleY: CGFloat) -> some View {
        // 清理“交易方式”下方残留的底图图标，保持顶部蓝色渐变连续。
        LinearGradient(
            colors: [
                AppTheme.palette.brandPrimary,
                AppTheme.palette.brandPrimaryPressed
            ],
            startPoint: .leading,
            endPoint: .trailing
        )
        .frame(width: 270 * scaleX, height: 44 * scaleY)
        .clipShape(RoundedRectangle(cornerRadius: 10 * min(scaleX, scaleY), style: .continuous))
        .position(x: 205 * scaleX, y: 314 * scaleY)
    }

    private func valueOverlay(
        scaleX: CGFloat,
        scaleY: CGFloat,
        fontScale: CGFloat,
        showsRechargeOrderTitle: Bool = true,
        showsPaymentSummary: Bool = true
    ) -> some View {
        let textYOffset = textVerticalOffset * scaleY
        return ZStack {
            Text("¥\(formatAmountFixed2(rechargeAmount))")
                .font(.system(size: 56 * fontScale, weight: .semibold))
                .foregroundStyle(Color.white.opacity(0.98))
                .lineLimit(1)
                .minimumScaleFactor(0.58)
                .frame(width: 250 * scaleX, alignment: .center)
                .position(x: 201 * scaleX, y: 128 * scaleY + textYOffset)

            if showsRechargeOrderTitle {
                Text(rechargeOrderTitle)
                    .font(.system(size: 15.8 * fontScale, weight: .medium))
                    .foregroundStyle(Color.white.opacity(0.96))
                    .lineLimit(1)
                    .minimumScaleFactor(0.72)
                    .frame(width: 148 * scaleX, alignment: .leading)
                    .position(x: 185 * scaleX, y: 208 * scaleY + textYOffset)
            }

            if showsPaymentSummary {
                Text("¥ \(formatAmountFixed2(rechargeAmount))")
                    .font(.system(size: 17.5 * fontScale, weight: .semibold))
                    .foregroundStyle(Color.white.opacity(0.96))
                    .lineLimit(1)
                    .minimumScaleFactor(0.72)
                    .frame(width: 92 * scaleX, alignment: .trailing)
                    .position(x: 342 * scaleX, y: 247 * scaleY + textYOffset)

                Text(displayPaymentMethodText)
                    .font(.system(size: 15.6 * fontScale, weight: .semibold))
                    .foregroundStyle(Color.white.opacity(0.98))
                    .lineLimit(1)
                    .minimumScaleFactor(0.55)
                    .frame(width: 76 * scaleX, alignment: .trailing)
                    .position(x: 350 * scaleX, y: 269 * scaleY + textYOffset)
            }
        }
    }

    private func processingStatusOverlay(
        title: String,
        subtitle: String,
        scaleX: CGFloat,
        scaleY: CGFloat,
        fontScale: CGFloat,
        showsSpinner: Bool
    ) -> some View {
        let titleY = 92 * scaleY
        let subtitleY = 188 * scaleY
        return ZStack {
            HStack(spacing: 8 * scaleX) {
                if showsSpinner {
                    ProgressView()
                        .progressViewStyle(.circular)
                        .tint(.white)
                        .scaleEffect(max(0.7, min(1.0, fontScale * 0.85)))
                }

                Text(title)
                    .font(.system(size: 17 * fontScale, weight: .semibold))
                    .foregroundStyle(Color.white.opacity(0.98))
                    .lineLimit(1)
            }
            .frame(width: 160 * scaleX, alignment: .center)
            .position(x: 201 * scaleX, y: titleY)

            Text(subtitle)
                .font(.system(size: 12.6 * fontScale, weight: .regular))
                .foregroundStyle(Color.white.opacity(0.9))
                .lineLimit(1)
                .minimumScaleFactor(0.72)
                .frame(width: 180 * scaleX, alignment: .center)
                .position(x: 201 * scaleX, y: subtitleY)
        }
    }

    private var displayPaymentMethodText: String {
        let normalized = paymentMethodText.trimmingCharacters(in: .whitespacesAndNewlines)
        return normalized.isEmpty ? "爱花" : normalized
    }

    private var hasCouponDiscountSummary: Bool {
        couponDiscountAmount > .zero
    }

    private var rechargeOrderTitle: String {
        "浙江移动充值\(formatRechargeAmountLabel(rechargeAmount))元"
    }

    private func formatRechargeAmountLabel(_ amount: Decimal) -> String {
        let integer = NSDecimalNumber(decimal: amount).intValue
        if Decimal(integer) == amount {
            return String(integer)
        }
        return formatAmountFixed2(amount)
    }

    private func formatAmountFixed2(_ amount: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = false
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSDecimalNumber(decimal: amount)) ?? "0.00"
    }

    private func formatCouponDiscountText() -> String {
        "-￥\(formatAmountFixed2(max(couponDiscountAmount, .zero)))"
    }

    private func failureDescriptionText(_ message: String) -> String {
        let normalized = message.trimmingCharacters(in: .whitespacesAndNewlines)
        if !normalized.isEmpty {
            return normalized
        }
        return "充值暂未完成，请稍后重试"
    }

    private func hotspot(
        identifier: String,
        centerX: CGFloat,
        centerY: CGFloat,
        width: CGFloat,
        height: CGFloat,
        isDisabled: Bool = false,
        action: @escaping () -> Void
    ) -> some View {
        Button(action: action) {
            Color.clear
                .frame(width: width, height: height)
                .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
        .disabled(isDisabled)
        .accessibilityIdentifier(identifier)
        .position(x: centerX, y: centerY)
    }
}


struct RepayPaymentToolPickerSheetView: View {
    let scaleX: CGFloat
    let scaleY: CGFloat
    let fontScale: CGFloat
    let sheetTitle: String
    let accessibilityPrefix: String
    let backdropOpacity: Double
    let prefersLeadingCloseButton: Bool
    let dividerColor: Color
    let sheetHeight: CGFloat
    let sceneConfiguration: CashierSceneConfiguration
    let bankTools: [CashierPayToolData]
    let selectedBankToolCode: String?
    let selectedPaymentMethodType: RepayPaymentMethodType
    let walletAvailableAmountText: String
    let fundAvailableAmountText: String
    let isLoadingWalletBalance: Bool
    let isLoadingFundBalance: Bool
    let walletDetailTextOverride: String?
    let fundDetailTextOverride: String?
    let isWalletSelectable: Bool
    let isLoadingBankTools: Bool
    let bankToolsErrorMessage: String?
    let onClose: () -> Void
    let onSelectWallet: () -> Void
    let onSelectFund: () -> Void
    let onSelectAiCredit: () -> Void
    let onSelectBankTool: (String) -> Void

    init(
        scaleX: CGFloat,
        scaleY: CGFloat,
        fontScale: CGFloat,
        sheetTitle: String = "选择付款方式",
        accessibilityPrefix: String = "repay_cashier",
        backdropOpacity: Double = 0.001,
        prefersLeadingCloseButton: Bool = false,
        dividerColor: Color = Color(red: 233 / 255, green: 235 / 255, blue: 239 / 255),
        sheetHeight: CGFloat = 468,
        sceneConfiguration: CashierSceneConfiguration,
        bankTools: [CashierPayToolData],
        selectedBankToolCode: String?,
        selectedPaymentMethodType: RepayPaymentMethodType,
        walletAvailableAmountText: String,
        fundAvailableAmountText: String,
        isLoadingWalletBalance: Bool,
        isLoadingFundBalance: Bool,
        walletDetailTextOverride: String? = nil,
        fundDetailTextOverride: String? = nil,
        isWalletSelectable: Bool = true,
        isLoadingBankTools: Bool,
        bankToolsErrorMessage: String?,
        onClose: @escaping () -> Void,
        onSelectWallet: @escaping () -> Void,
        onSelectFund: @escaping () -> Void,
        onSelectAiCredit: @escaping () -> Void,
        onSelectBankTool: @escaping (String) -> Void
    ) {
        self.scaleX = scaleX
        self.scaleY = scaleY
        self.fontScale = fontScale
        self.sheetTitle = sheetTitle
        self.accessibilityPrefix = accessibilityPrefix
        self.backdropOpacity = backdropOpacity
        self.prefersLeadingCloseButton = prefersLeadingCloseButton
        self.dividerColor = dividerColor
        self.sheetHeight = sheetHeight
        self.sceneConfiguration = sceneConfiguration
        self.bankTools = bankTools
        self.selectedBankToolCode = selectedBankToolCode
        self.selectedPaymentMethodType = selectedPaymentMethodType
        self.walletAvailableAmountText = walletAvailableAmountText
        self.fundAvailableAmountText = fundAvailableAmountText
        self.isLoadingWalletBalance = isLoadingWalletBalance
        self.isLoadingFundBalance = isLoadingFundBalance
        self.walletDetailTextOverride = walletDetailTextOverride
        self.fundDetailTextOverride = fundDetailTextOverride
        self.isWalletSelectable = isWalletSelectable
        self.isLoadingBankTools = isLoadingBankTools
        self.bankToolsErrorMessage = bankToolsErrorMessage
        self.onClose = onClose
        self.onSelectWallet = onSelectWallet
        self.onSelectFund = onSelectFund
        self.onSelectAiCredit = onSelectAiCredit
        self.onSelectBankTool = onSelectBankTool
    }

    private var showsWalletRow: Bool {
        sceneConfiguration.supports(.wallet)
    }

    private var showsFundRow: Bool {
        sceneConfiguration.supports(.fund)
    }

    private var showsAiCreditRow: Bool {
        sceneConfiguration.supports(.aiCredit)
    }

    private var showsBankSection: Bool {
        sceneConfiguration.supports(.bankCard)
    }

    private var closeButton: some View {
        Button(action: onClose) {
            Image(systemName: "xmark")
                .font(.system(size: 16 * fontScale, weight: .regular))
                .foregroundStyle(Color(red: 0.42, green: 0.43, blue: 0.45))
                .frame(width: 28 * scaleX, height: 28 * scaleY)
        }
        .buttonStyle(.plain)
        .accessibilityIdentifier("\(accessibilityPrefix)_close_payment_tools")
    }

    var body: some View {
        ZStack(alignment: .bottom) {
            Color.black.opacity(backdropOpacity)
                .ignoresSafeArea()
                .contentShape(Rectangle())
                .onTapGesture(perform: onClose)

            VStack(spacing: 0) {
                Group {
                    if prefersLeadingCloseButton {
                        ZStack {
                            Text(sheetTitle)
                                .font(.system(size: 18 * fontScale, weight: .semibold))
                                .foregroundStyle(Color(red: 0.16, green: 0.16, blue: 0.17))
                                .frame(maxWidth: .infinity, alignment: .center)

                            HStack {
                                closeButton
                                    .padding(.leading, 6 * scaleX)
                                Spacer()
                            }
                        }
                    } else {
                        HStack {
                            Text(sheetTitle)
                                .font(.system(size: 18 * fontScale, weight: .semibold))
                                .foregroundStyle(Color(red: 0.16, green: 0.16, blue: 0.17))
                            Spacer()
                            closeButton
                        }
                    }
                }
                .padding(.horizontal, 18 * scaleX)
                .padding(.top, 18 * scaleY)
                .padding(.bottom, 12 * scaleY)

                ScrollView(showsIndicators: false) {
                    VStack(spacing: 0) {
                        if showsWalletRow {
                            walletRow
                            if showsFundRow || showsAiCreditRow || showsBankSection {
                                Divider().overlay(dividerColor)
                            }
                        }

                        if showsFundRow {
                            fundRow
                            if showsAiCreditRow || showsBankSection {
                                Divider().overlay(dividerColor)
                            }
                        }

                        if showsAiCreditRow {
                            aiCreditRow
                            if showsBankSection {
                                Divider().overlay(dividerColor)
                            }
                        }

                        if showsBankSection {
                            if isLoadingBankTools && bankTools.isEmpty {
                                Text("加载中...")
                                    .font(.system(size: 15 * fontScale, weight: .medium))
                                    .foregroundStyle(Color(red: 0.57, green: 0.57, blue: 0.58))
                                    .frame(maxWidth: .infinity)
                                    .frame(height: 68 * scaleY)
                            } else if bankTools.isEmpty {
                                Text(emptyBankToolsText)
                                    .font(.system(size: 14 * fontScale, weight: .medium))
                                    .foregroundStyle(Color(red: 0.57, green: 0.57, blue: 0.58))
                                    .multilineTextAlignment(.center)
                                    .frame(maxWidth: .infinity)
                                    .padding(.horizontal, 18 * scaleX)
                                    .frame(height: 72 * scaleY)
                            } else {
                                ForEach(Array(bankTools.enumerated()), id: \.offset) { index, tool in
                                    bankRow(tool, index: index)
                                    if index != bankTools.count - 1 {
                                        Divider().overlay(dividerColor)
                                    }
                                }
                            }
                        }
                    }
                    .frame(maxWidth: .infinity, alignment: .leading)
                }
                .frame(maxHeight: 360 * scaleY)
            }
            .frame(maxWidth: .infinity)
            .frame(height: sheetHeight * scaleY)
            .background(
                RoundedRectangle(cornerRadius: 24 * min(scaleX, scaleY), style: .continuous)
                    .fill(Color.white)
            )
            .clipShape(RoundedRectangle(cornerRadius: 24 * min(scaleX, scaleY), style: .continuous))
        }
    }

    private var walletRow: some View {
        Button(action: onSelectWallet) {
            CashierPaymentToolRowView(
                descriptor: CashierPaymentToolDescriptor(
                    id: CashierChannelKind.wallet.rawValue,
                    channelKind: .wallet,
                    title: CashierChannelKind.wallet.defaultTitle,
                    detail: walletDetailText,
                    bankTool: nil,
                    accessibilityIdentifier: "\(accessibilityPrefix)_select_wallet"
                ),
                isSelected: selectedPaymentMethodType == .wallet,
                scaleX: scaleX,
                scaleY: scaleY,
                fontScale: fontScale
            )
            .frame(maxWidth: .infinity, alignment: .leading)
            .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
        .frame(maxWidth: .infinity, alignment: .leading)
        .background(Color.white.opacity(0.001))
        .contentShape(Rectangle())
        .disabled(!isWalletSelectable)
        .opacity(isWalletSelectable ? 1 : 0.62)
        .accessibilityIdentifier("\(accessibilityPrefix)_select_wallet")
    }

    private var fundRow: some View {
        Button(action: onSelectFund) {
            CashierPaymentToolRowView(
                descriptor: CashierPaymentToolDescriptor(
                    id: CashierChannelKind.fund.rawValue,
                    channelKind: .fund,
                    title: CashierChannelKind.fund.defaultTitle,
                    detail: fundDetailText,
                    bankTool: nil,
                    accessibilityIdentifier: "\(accessibilityPrefix)_select_fund"
                ),
                isSelected: selectedPaymentMethodType == .fund,
                scaleX: scaleX,
                scaleY: scaleY,
                fontScale: fontScale
            )
            .frame(maxWidth: .infinity, alignment: .leading)
            .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
        .frame(maxWidth: .infinity, alignment: .leading)
        .background(Color.white.opacity(0.001))
        .contentShape(Rectangle())
        .accessibilityIdentifier("\(accessibilityPrefix)_select_fund")
    }

    private var aiCreditRow: some View {
        Button(action: onSelectAiCredit) {
            CashierPaymentToolRowView(
                descriptor: CashierPaymentToolDescriptor(
                    id: CashierChannelKind.aiCredit.rawValue,
                    channelKind: .aiCredit,
                    title: CashierChannelKind.aiCredit.defaultTitle,
                    detail: "本场景支持信用支付",
                    bankTool: nil,
                    accessibilityIdentifier: "\(accessibilityPrefix)_select_aicredit"
                ),
                isSelected: selectedPaymentMethodType == .aiCredit,
                scaleX: scaleX,
                scaleY: scaleY,
                fontScale: fontScale
            )
            .frame(maxWidth: .infinity, alignment: .leading)
            .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
        .frame(maxWidth: .infinity, alignment: .leading)
        .background(Color.white.opacity(0.001))
        .contentShape(Rectangle())
        .accessibilityIdentifier("\(accessibilityPrefix)_select_aicredit")
    }

    private func bankRow(_ tool: CashierPayToolData, index: Int) -> some View {
        Button(action: {
            onSelectBankTool(tool.toolCode)
        }) {
            CashierPaymentToolRowView(
                descriptor: CashierPaymentToolDescriptor(
                    id: tool.toolCode,
                    channelKind: .bankCard,
                    title: CashierPresentationHelper.bankDisplayName(for: tool, replaceDebitWithSavings: true),
                    detail: CashierPresentationHelper.bankSubtitle(for: tool, fallbackText: "银行卡"),
                    bankTool: tool,
                    accessibilityIdentifier: "\(accessibilityPrefix)_select_bank_\(tool.toolCode)"
                ),
                isSelected: selectedBankRowIndex == index,
                scaleX: scaleX,
                scaleY: scaleY,
                fontScale: fontScale
            )
            .frame(maxWidth: .infinity, alignment: .leading)
            .contentShape(Rectangle())
        }
