                    .resizable()
                    .interpolation(.high)
                    .aspectRatio(contentMode: .fill)
                    .frame(width: proxy.size.width, height: proxy.size.height)
                    .clipped()

                detailTopRightCleanupOverlay(scaleX: scaleX, scaleY: scaleY)
                    .allowsHitTesting(false)

                detailHeaderOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                    .allowsHitTesting(false)

                detailOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
