                if showsPrepaymentFooter {
                    detailPrepaymentFooter(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale) {
                        onRepay(max(.zero, dueAmount))
                    }
                } else if showsRepayButton {
                    detailRepayButton(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale) {
                        if dueAmount > .zero {
