    private struct DetailBillSection: Identifiable {
        let dateText: String
        let items: [CreditCurrentBillDetailItemData]

        var id: String { dateText }
    }

    private var detailBillSections: [DetailBillSection] {
        let sortedItems = (billDetail?.items ?? [])
            .enumerated()
            .sorted { lhs, rhs in
                let leftKey = detailDateSortKey(lhs.element.dateText)
                let rightKey = detailDateSortKey(rhs.element.dateText)
                if leftKey != rightKey {
                    return leftKey > rightKey
                }
                return lhs.offset < rhs.offset
            }
            .map { normalizedDetailBillItem($0.element) }

        var sections: [DetailBillSection] = []
        for item in sortedItems {
            if let last = sections.last, last.dateText == item.dateText {
                sections[sections.count - 1] = DetailBillSection(
                    dateText: last.dateText,
                    items: last.items + [item]
                )
            } else {
                sections.append(DetailBillSection(dateText: item.dateText, items: [item]))
            }
        }
        return sections
    }

    private func normalizedDetailBillItem(_ item: CreditCurrentBillDetailItemData) -> CreditCurrentBillDetailItemData {
        guard isAiCreditRepayDetailItem(item) else {
            return item
        }
        let normalizedAmount = item.amount.amount < .zero ? -item.amount.amount : item.amount.amount
        return CreditCurrentBillDetailItemData(
            dateText: item.dateText,
            displayTitle: "爱花还款",
            displaySubtitle: "信用借还",
            amount: MoneyValueData(amount: normalizedAmount, currencyCode: item.amount.currencyCode),
            businessNo: item.businessNo
        )
    }

    private func isAiCreditRepayDetailItem(_ item: CreditCurrentBillDetailItemData) -> Bool {
        let normalizedTitle = item.displayTitle.trimmingCharacters(in: .whitespacesAndNewlines)
        let normalizedSubtitle = item.displaySubtitle.trimmingCharacters(in: .whitespacesAndNewlines)
        let normalizedBusinessNo = item.businessNo
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .uppercased()
        if normalizedTitle.contains("还款") || normalizedSubtitle.contains("还款") {
            return true
        }
        if normalizedBusinessNo.contains("REPAY") {
            return true
        }
        return false
    }

    private func detailDateSortKey(_ dateText: String) -> Int {
        let digits = dateText
            .replacingOccurrences(of: "月", with: "-")
            .replacingOccurrences(of: "日", with: "")
            .split(separator: "-")
            .compactMap { Int($0) }
        guard digits.count == 2 else {
            return 0
        }
        return digits[0] * 100 + digits[1]
    }

