    private func detailBillTypeText(_ subtitle: String) -> String {
        let normalizedSubtitle = subtitle.trimmingCharacters(in: .whitespacesAndNewlines)
        return normalizedSubtitle.isEmpty ? "账单消费" : normalizedSubtitle
    }

    private func detailBillDateTimeText(_ rawDateText: String) -> String {
        let normalizedText = rawDateText
            .replacingOccurrences(of: "月", with: "-")
            .replacingOccurrences(of: "日", with: "")
            .replacingOccurrences(of: "/", with: "-")
            .replacingOccurrences(of: "：", with: ":")
            .trimmingCharacters(in: .whitespacesAndNewlines)

        guard !normalizedText.isEmpty else {
            return "-- --:--"
        }

        for formatter in Self.detailBillInputDateFormatters {
            if let date = formatter.date(from: normalizedText) {
                return Self.detailBillOutputDateFormatter.string(from: date)
            }
        }

        return normalizedText
    }

    private static let detailBillOutputDateFormatter: DateFormatter = {
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.timeZone = .current
        formatter.dateFormat = "MM-dd HH:mm"
        return formatter
    }()

    private static let detailBillInputDateFormatters: [DateFormatter] = {
        let formats = [
            "yyyy-M-d HH:mm:ss",
            "yyyy-M-d HH:mm",
            "yyyy-M-dHH:mm:ss",
            "yyyy-M-dHH:mm",
            "M-d HH:mm:ss",
            "M-d HH:mm",
            "M-dHH:mm:ss",
            "M-dHH:mm",
            "yyyy-M-d",
            "M-d"
        ]
        return formats.map { format in
            let formatter = DateFormatter()
            formatter.locale = Locale(identifier: "en_US_POSIX")
            formatter.timeZone = .current
            formatter.dateFormat = format
            return formatter
        }
    }()

    private func detailRepayButton(
        scaleX: CGFloat,
        scaleY: CGFloat,
        fontScale: CGFloat,
        action: @escaping () -> Void
    ) -> some View {
        Button(action: action) {
            ZStack {
                RoundedRectangle(cornerRadius: 12 * fontScale, style: .continuous)
                    .fill(
                        LinearGradient(
                            colors: [
                                AppTheme.palette.brandPrimaryPressed,
                                AppTheme.palette.brandPrimaryPressed
