    private func detailHotspot(
        identifier: String,
        centerX: CGFloat,
        centerY: CGFloat,
        width: CGFloat,
        height: CGFloat,
        action: @escaping () -> Void
    ) -> some View {
        Button(action: action) {
            Color.black.opacity(0.012)
                .frame(width: width, height: height)
                .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
        .accessibilityIdentifier(identifier)
        .position(x: centerX, y: centerY)
    }

    private func detailFirstSectionRowCenterY(_ index: Int) -> CGFloat {
        switch index {
        case 0: return 422
        case 1: return 516
        default: return 610
        }
    }

    private func detailSecondSectionRowCenterY(_ index: Int) -> CGFloat {
        730 + CGFloat(index * 94)
    }

    private var dueAmount: Decimal {
        max(.zero, billDetail?.dueAmount.amount ?? .zero)
    }

    private var dueAmountDisplayText: String {
        guard billDetail != nil else {
            return "--"
        }
        return formatMoney(dueAmount, useGrouping: true)
    }

    private var detailTitleText: String {
        let resolvedTitle = sanitizeCreditBillTitle(billDetail?.title)
        return resolvedTitle.isEmpty ? fallbackTitle : resolvedTitle
    }

    private var detailPeriodText: String {
        billDetail?.periodText ?? fallbackPeriodText
    }

    private var detailStatementMonth: Int {
        resolveCreditStatementMonth(title: detailTitleText, repayDayOfMonth: 10)
    }

    private var detailSummaryTitleText: String {
        "\(detailStatementMonth)月账单总计"
    }

    private var detailDueHintText: String {
        "\(detailStatementMonth)月10日前应还(元)"
    }

    private var showsRepayButton: Bool {
        detailMode == .current && dueAmount > .zero
    }

    private var showsPrepaymentFooter: Bool {
        detailMode == .next && dueAmount > .zero
    }

    private var detailPrepaymentDateText: String {
        "还款日\(detailStatementMonth)月10日"
    }

    private var statementTotalAmount: Decimal {
        billDetail?.statementTotalAmount.amount ?? dueAmount
    }

    private var statementTotalAmountDisplayText: String {
        guard billDetail != nil else {
            return "--"
        }
        return formatMoney(statementTotalAmount, useGrouping: true)
    }

    private var refundedAmount: Decimal {
        billDetail?.refundedAmount.amount ?? .zero
    }

    private var refundedAmountDisplayText: String {
        guard billDetail != nil else {
            return "--"
        }
        return signedSummaryText(refundedAmount, useGrouping: true)
    }

    private var repaidAmount: Decimal {
        billDetail?.repaidAmount.amount ?? max(.zero, statementTotalAmount - refundedAmount - dueAmount)
    }

    private var repaidAmountDisplayText: String {
        guard billDetail != nil else {
            return "--"
        }
        return formatMoney(repaidAmount, useGrouping: true)
    }

    private var repaidSummaryHintText: String? {
        guard detailMode == .current, repaidAmount > .zero else {
            return nil
        }
        let repaidText = "已还款\(formatMoney(repaidAmount, useGrouping: true))元"
        if hasReachedMinimumRepayment {
            return repaidText + "，已还最低还款金额"
        }
        return repaidText
    }

    private var hasReachedMinimumRepayment: Bool {
        guard detailMode == .current else {
            return false
        }
        let threshold = resolveCreditMinimumRepaymentThreshold(statementTotalAmount: statementTotalAmount)
        return threshold > .zero && repaidAmount >= threshold
    }

    @MainActor
    private func refreshBillDetail() async {
        guard let userId, userId > 0 else {
            errorMessage = "未找到当前登录用户"
            return
        }
        isLoading = true
        errorMessage = nil
        do {
            switch detailMode {
            case .current:
                billDetail = try await APIClient.shared.fetchCreditCurrentBillDetail(userId: userId)
            case .next:
                billDetail = try await APIClient.shared.fetchCreditNextBillDetail(userId: userId)
            }
            if detailMode == .current, let billDetail {
                onBillDetailLoaded?(billDetail)
            }
        } catch {
            billDetail = nil
            errorMessage = userFacingErrorMessage(error)
        }
        isLoading = false
    }

    private func formatMoney(_ value: Decimal, useGrouping: Bool) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = useGrouping
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSDecimalNumber(decimal: value)) ?? NSDecimalNumber(decimal: value).stringValue
    }

    private func signedSummaryText(_ value: Decimal, useGrouping: Bool) -> String {
        let normalized = max(.zero, value)
        return normalized > .zero ? "-" + formatMoney(normalized, useGrouping: useGrouping) : "0.00"
    }
}

private struct LoanAccountRepayResultView: View {
    let repayAmount: Decimal
    let fullRepayAmount: Decimal
    let outstandingPrincipalAmount: Decimal?
    let resultState: DepositResultState
    let onBorrowAgain: () -> Void
    let onDone: () -> Void

    private let baseWidth: CGFloat = 402
    private let baseHeight: CGFloat = 874
    private let sheetTopY: CGFloat = 360
    private let sheetHeight: CGFloat = 514
    private let amountTextColor = Color(red: 0.23, green: 0.23, blue: 0.25)
    private let primaryBlue = AppTheme.palette.brandPrimaryPressed
    private let secondaryTextColor = Color(red: 0.62, green: 0.62, blue: 0.65)

    var body: some View {
        GeometryReader { proxy in
            let scaleX = proxy.size.width / baseWidth
            let scaleY = proxy.size.height / baseHeight
            let fontScale = min(scaleX, scaleY)
            let sheetCenterY = (sheetTopY + sheetHeight / 2) * scaleY

            ZStack {
                LoanAccountRepayResultBackdropView(
                    repayAmount: repayAmount,
                    fullRepayAmount: fullRepayAmount,
                    outstandingPrincipalAmount: outstandingPrincipalAmount
                )
                .frame(width: proxy.size.width, height: proxy.size.height)

                Color.black.opacity(0.24)
                    .ignoresSafeArea()

                switch resultState {
                case .processing:
                    processingSheet(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale, centerY: sheetCenterY)
                case .succeeded:
                    successSheet(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale, centerY: sheetCenterY)
                case .failed(let message):
                    failureSheet(message: message, scaleX: scaleX, scaleY: scaleY, fontScale: fontScale, centerY: sheetCenterY)
                }

                if case .succeeded = resultState {
                    actionHitArea(width: 44 * scaleX, height: 44 * scaleY, action: onDone)
                        .position(x: 384 * scaleX, y: 377 * scaleY)
                        .accessibilityIdentifier("loan_account_repay_result_close")

                    actionHitArea(width: 318 * scaleX, height: 58 * scaleY, action: onBorrowAgain)
                        .position(x: 201 * scaleX, y: 765 * scaleY)
                        .accessibilityIdentifier("loan_account_repay_result_borrow_again")
                } else if case .failed = resultState {
                    actionHitArea(width: 44 * scaleX, height: 44 * scaleY, action: onDone)
                        .position(x: 384 * scaleX, y: 377 * scaleY)
                        .accessibilityIdentifier("loan_account_repay_result_close")
                }
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .ignoresSafeArea()
        .accessibilityIdentifier("loan_account_repay_result_page")
    }

    private func successSheet(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat, centerY: CGFloat) -> some View {
        ZStack {
            Image("LoanAccountRepayResultSheetReference")
                .resizable()
                .interpolation(.high)
                .frame(width: baseWidth * scaleX, height: sheetHeight * scaleY)
                .position(x: 201 * scaleX, y: centerY)

            Rectangle()
                .fill(Color.white)
                .frame(width: 236 * scaleX, height: 42 * scaleY)
                .position(x: 201 * scaleX, y: 477 * scaleY)

            Rectangle()
                .fill(Color.white)
                .frame(width: 248 * scaleX, height: 102 * scaleY)
                .position(x: 201 * scaleX, y: 531 * scaleY)

            Text("还款成功")
                .font(.system(size: 20 * fontScale, weight: .semibold))
                .foregroundStyle(amountTextColor)
                .lineLimit(1)
                .minimumScaleFactor(0.72)
                .frame(width: 168 * scaleX)
                .position(x: 201 * scaleX, y: 477 * scaleY)

            Text("¥\(formatAmount(repayAmount))")
                .font(.system(size: 31 * fontScale, weight: .semibold))
                .foregroundStyle(amountTextColor)
                .lineLimit(1)
                .minimumScaleFactor(0.72)
                .frame(width: 236 * scaleX)
                .position(x: 201 * scaleX, y: 548 * scaleY)
        }
    }

    private func processingSheet(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat, centerY: CGFloat) -> some View {
        ZStack {
            UnevenRoundedRectangle(
                topLeadingRadius: 18 * min(scaleX, scaleY),
                bottomLeadingRadius: 0,
                bottomTrailingRadius: 0,
                topTrailingRadius: 18 * min(scaleX, scaleY),
                style: .continuous
            )
            .fill(Color.white)
            .frame(width: baseWidth * scaleX, height: sheetHeight * scaleY)
            .position(x: 201 * scaleX, y: centerY)

            Circle()
                .fill(primaryBlue)
                .frame(width: 34 * fontScale, height: 34 * fontScale)
                .position(x: 201 * scaleX, y: 429 * scaleY)

            Image(systemName: "clock.fill")
                .font(.system(size: 15 * fontScale, weight: .semibold))
                .foregroundStyle(Color.white)
                .position(x: 201 * scaleX, y: 429 * scaleY)

            TimelineView(.periodic(from: .now, by: 0.4)) { context in
                let phase = Int(context.date.timeIntervalSinceReferenceDate / 0.4) % 3 + 1
                Text("还款中\(String(repeating: ".", count: phase))")
                    .font(.system(size: 20 * fontScale, weight: .semibold))
                    .foregroundStyle(amountTextColor)
                    .frame(width: 220 * scaleX)
                    .position(x: 201 * scaleX, y: 494 * scaleY)
            }

            Text("请稍候，正在处理您的提前还款")
                .font(.system(size: 13.5 * fontScale, weight: .regular))
                .foregroundStyle(secondaryTextColor)
                .frame(width: 250 * scaleX)
                .position(x: 201 * scaleX, y: 532 * scaleY)
        }
    }

    private func failureSheet(message: String, scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat, centerY: CGFloat) -> some View {
        let description = message.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ? "提前还款暂未完成，请稍后重试" : message

        return ZStack {
            UnevenRoundedRectangle(
                topLeadingRadius: 18 * min(scaleX, scaleY),
                bottomLeadingRadius: 0,
                bottomTrailingRadius: 0,
                topTrailingRadius: 18 * min(scaleX, scaleY),
                style: .continuous
            )
            .fill(Color.white)
            .frame(width: baseWidth * scaleX, height: sheetHeight * scaleY)
            .position(x: 201 * scaleX, y: centerY)

            Image(systemName: "xmark.circle.fill")
                .font(.system(size: 34 * fontScale, weight: .semibold))
                .foregroundStyle(Color(red: 0.93, green: 0.34, blue: 0.34))
                .position(x: 201 * scaleX, y: 429 * scaleY)

            Text("还款失败")
                .font(.system(size: 20 * fontScale, weight: .semibold))
                .foregroundStyle(amountTextColor)
                .frame(width: 220 * scaleX)
                .position(x: 201 * scaleX, y: 494 * scaleY)

            Text(description)
                .font(.system(size: 13.5 * fontScale, weight: .regular))
                .foregroundStyle(secondaryTextColor)
                .multilineTextAlignment(.center)
                .lineLimit(3)
                .frame(width: 286 * scaleX)
                .position(x: 201 * scaleX, y: 538 * scaleY)
        }
    }

    private func formatAmount(_ amount: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = false
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSDecimalNumber(decimal: amount)) ?? "0.00"
    }

    private func actionHitArea(width: CGFloat, height: CGFloat, action: @escaping () -> Void) -> some View {
        Button(action: action) {
            Color.clear
                .frame(width: width, height: height)
                .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
    }
}

private struct LoanAccountRepayResultBackdropView: View {
    let repayAmount: Decimal
    let fullRepayAmount: Decimal
    let outstandingPrincipalAmount: Decimal?

    private let baseWidth: CGFloat = 402
    private let baseHeight: CGFloat = 874

    var body: some View {
        GeometryReader { proxy in
            let scaleX = proxy.size.width / baseWidth
            let scaleY = proxy.size.height / baseHeight
            let fontScale = min(scaleX, scaleY)

            ZStack {
                Image("LoanAccountRepayAfterAmountReference")
                    .resizable()
                    .interpolation(.high)
                    .aspectRatio(contentMode: .fill)
                    .frame(width: proxy.size.width, height: proxy.size.height)
                    .clipped()

                summaryOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                amountInputOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .ignoresSafeArea()
        .allowsHitTesting(false)
    }

    private func summaryOverlay(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        let backgroundColor = Color.white
        let labelColor = Color(red: 0.67, green: 0.68, blue: 0.71)
        let valueColor = AppTheme.palette.brandPrimary
        let interest = max(.zero, max(fullRepayAmount, .zero) - max(outstandingPrincipalAmount ?? fullRepayAmount, .zero))

        return ZStack(alignment: .leading) {
            Rectangle()
                .fill(backgroundColor)
                .frame(width: 320 * scaleX, height: 22 * scaleY)

            if interest > .zero {
                HStack(alignment: .firstTextBaseline, spacing: 0) {
                    Text("未还总额")
                        .font(.system(size: 12.8 * fontScale, weight: .regular))
                        .foregroundStyle(labelColor)
                    Text(formatAmountFixed2(fullRepayAmount))
                        .font(.system(size: 13 * fontScale, weight: .medium))
                        .foregroundStyle(valueColor)
                    Text(" (含利息\(formatAmountFixed2(interest)))，支持部分还")
                        .font(.system(size: 12.5 * fontScale, weight: .regular))
                        .foregroundStyle(labelColor)
                }
                .lineLimit(1)
                .minimumScaleFactor(0.72)
                .frame(width: 314 * scaleX, alignment: .leading)
                .padding(.leading, 2 * scaleX)
            } else {
                HStack(alignment: .firstTextBaseline, spacing: 0) {
                    Text("未还总额")
                        .font(.system(size: 12.8 * fontScale, weight: .regular))
                        .foregroundStyle(labelColor)
                    Text(formatAmountFixed2(fullRepayAmount))
                        .font(.system(size: 13 * fontScale, weight: .medium))
                        .foregroundStyle(valueColor)
                    Text("，支持部分还")
                        .font(.system(size: 12.5 * fontScale, weight: .regular))
                        .foregroundStyle(labelColor)
                }
                .lineLimit(1)
                .minimumScaleFactor(0.72)
                .frame(width: 314 * scaleX, alignment: .leading)
                .padding(.leading, 2 * scaleX)
            }
        }
        .position(x: 179 * scaleX, y: 245 * scaleY)
    }

    private func amountInputOverlay(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        ZStack(alignment: .leading) {
            Rectangle()
                .fill(Color.white)
                .frame(width: 242 * scaleX, height: 62 * scaleY)

            HStack(alignment: .bottom, spacing: 4 * scaleX) {
                Text("¥")
                    .font(.system(size: 27 * fontScale, weight: .medium))
                    .foregroundStyle(Color(red: 0.17, green: 0.17, blue: 0.19))
                    .padding(.bottom, 3 * scaleY)

                Text(formatAmountEditable(repayAmount))
                    .font(.system(size: 31 * fontScale, weight: .semibold))
                    .foregroundStyle(Color(red: 0.17, green: 0.17, blue: 0.19))
                    .lineLimit(1)
                    .minimumScaleFactor(0.72)
                    .padding(.bottom, 1 * scaleY)

                Spacer(minLength: 0)
            }
            .frame(width: 224 * scaleX, height: 44 * scaleY, alignment: .bottomLeading)
            .padding(.leading, 8 * scaleX)
        }
        .position(x: 136 * scaleX, y: 183 * scaleY)
    }

    private func formatAmountFixed2(_ amount: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = false
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSDecimalNumber(decimal: max(.zero, amount))) ?? NSDecimalNumber(decimal: max(.zero, amount)).stringValue
    }

    private func formatAmountEditable(_ amount: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = false
        formatter.minimumFractionDigits = 0
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSDecimalNumber(decimal: max(.zero, amount))) ?? NSDecimalNumber(decimal: max(.zero, amount)).stringValue
    }
}

private struct RepaySuccessView: View {
    let userId: Int64?
    let repayAmount: Decimal
    let repayBillMode: CreditRepayBillMode
    let paymentMethodText: String
    let optimisticRemainingOutstandingAmount: Decimal?
    let resultState: DepositResultState
    let onContinueRepay: (Bool) -> Void
    let onDone: () -> Void

    @State private var remainingOutstandingAmountText: String = "--"
    @State private var currentBillDetail: CreditCurrentBillDetailData?
    @State private var isLoadingRemainingOutstandingAmount: Bool = false

    private let baseWidth: CGFloat = 402
    private let baseHeight: CGFloat = 874

    var body: some View {
        GeometryReader { proxy in
            let scaleX = proxy.size.width / baseWidth
            let scaleY = proxy.size.height / baseHeight
            let fontScale = min(scaleX, scaleY)

            ZStack {
                Image(backgroundAssetName)
                    .resizable()
                    .interpolation(.high)
                    .aspectRatio(contentMode: .fill)
                    .frame(width: proxy.size.width, height: proxy.size.height)
                    .clipped()

                dynamicOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)

                if case .succeeded = resultState {
                    ScreenshotStatusMaskView(
                        referenceAssetName: backgroundAssetName,
                        maskHeight: 56
                    )
                }

                hotspot(
                    identifier: "credit_repay_success_top_done",
                    centerX: 370 * scaleX,
                    centerY: 73 * scaleY,
                    width: 54 * scaleX,
                    height: 34 * scaleY,
                    isDisabled: resultState == .processing,
                    action: onDone
                )

                if shouldShowContinueRepay {
                    hotspot(
                        identifier: "credit_repay_success_continue",
                        centerX: 201 * scaleX,
                        centerY: 392 * scaleY,
                        width: 322 * scaleX,
                        height: 62 * scaleY,
                        action: {
                            onContinueRepay(hasRemainingOutstandingAmount)
                        }
                    )
                }

                hotspot(
                    identifier: "credit_repay_success_done",
                    centerX: 201 * scaleX,
                    centerY: 801 * scaleY,
                    width: 252 * scaleX,
                    height: 62 * scaleY,
                    isDisabled: resultState == .processing,
                    action: onDone
                )
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .ignoresSafeArea()
        .task(id: refreshTaskKey) {
            await refreshRemainingOutstandingAmount()
        }
    }

    @ViewBuilder
    private func dynamicOverlay(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        ZStack {
            switch resultState {
            case .processing:
                processingOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
            case .succeeded:
                successOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
            case .failed(let message):
                failureOverlay(message: message, scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
            }
        }
    }

    private var backgroundAssetName: String {
        switch resultState {
        case .processing:
            return "CreditRepayProcessingBackground"
        case .succeeded, .failed:
            return "CreditRepaySuccessBackground"
        }
    }

    private func successOverlay(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
