    private func repayBrandLabelOverlay(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        ZStack {
            overlayText(
                "爱花",
                centerX: 46,
                centerY: 383,
                width: 44,
