    }

    private var refreshTaskKey: String {
        "\(userId ?? 0)-\(resultStateKey)-\(repayBillMode == .next ? "next" : "current")-\(formatAmount(repayAmount))-\(optimisticRemainingOutstandingAmount.map(formatAmount) ?? "nil")"
    }

    private var resultStateKey: String {
        switch resultState {
        case .processing:
            return "processing"
        case .succeeded:
            return "succeeded"
        case .failed:
            return "failed"
        }
    }

    private var repaySuccessTitleText: String {
        "\(formatAmount(repayAmount))元还款成功"
    }

    private var remainingOutstandingAmountDecimal: Decimal {
        let normalized = remainingOutstandingAmountText.trimmingCharacters(in: .whitespacesAndNewlines)
        guard normalized != "--",
              let remaining = Decimal(string: normalized, locale: Locale(identifier: "en_US_POSIX")) else {
            return Decimal.zero
        }
        return remaining
    }

    private var targetBillStatementMonth: Int {
        let currentStatementMonth = resolveCreditStatementMonth(title: nil, repayDayOfMonth: 10)
        if repayBillMode == .next {
            return currentStatementMonth == 12 ? 1 : currentStatementMonth + 1
        }
        if let currentBillDetail {
            return resolveCreditStatementMonth(title: currentBillDetail.title, repayDayOfMonth: 10)
        }
        return currentStatementMonth
    }

    private var repayResultBillTitleText: String {
        "\(targetBillStatementMonth)月账单"
    }

    private var repayResultBillTitleCenterX: CGFloat {
        repayBillMode == .next ? 84 : 79
    }

    private var repayResultBillTitleMaskCenterX: CGFloat {
        repayBillMode == .next ? 86 : 78
    }

    private var repayResultBillTitleMaskWidth: CGFloat {
        0
    }

    private var repayResultBillTitleMaskColor: Color {
        .clear
    }

    private var repayResultBillStatusMaskCenterX: CGFloat {
        repayBillMode == .next ? 304 : 322
    }

    private var repayResultBillStatusMaskWidth: CGFloat {
        repayBillMode == .next ? 152 : 0
    }

    private var repayResultBillStatusMaskColor: Color {
        if repayBillMode == .next {
            return Color(red: 0.95, green: 0.95, blue: 0.95)
        }
        return .clear
    }

    private var hasClearedTargetBill: Bool {
        let normalized = remainingOutstandingAmountText.trimmingCharacters(in: .whitespacesAndNewlines)
        guard normalized != "--" else {
            return false
        }
        return remainingOutstandingAmountDecimal <= .zero
    }

    private var hasReachedMinimumRepaymentForTargetBill: Bool {
        guard repayBillMode == .current,
              let targetBillAmountBeforeRepayment = targetBillAmountBeforeRepayment,
              targetBillAmountBeforeRepayment > .zero else {
            return false
        }
        // 还款成功页的“已还最低金额”只反馈本次这笔还款是否达到当前待还账单 10% 门槛，
        // 避免把历史已还金额带进来后，把一次小额还款误判成“已还最低金额”。
        let minimumThreshold = resolveCreditMinimumRepaymentThreshold(statementTotalAmount: targetBillAmountBeforeRepayment)
        return minimumThreshold > .zero && max(.zero, repayAmount) >= minimumThreshold
    }

    private var repayResultBillStatusText: String {
        if repayBillMode == .next {
            return ""
        }
        if isLoadingRemainingOutstandingAmount && remainingOutstandingAmountText == "--" {
            return ""
        }
        if hasClearedTargetBill {
            return "已还清"
        }
        if hasReachedMinimumRepaymentForTargetBill {
            return "已还最低金额"
        }
        return "待还款"
    }

    private var repayResultBillStatusTextCenterX: CGFloat {
        switch repayResultBillStatusText {
        case "已还最低金额", "待还款", "查询中":
            return 312
        default:
            return 322
        }
    }

    private var repayResultRemainingSummaryWidth: CGFloat {
        150
    }

    private var repayResultRemainingSummaryCenterX: CGFloat {
        let statusRightEdgeX = repayResultBillStatusTextCenterX + 73
        return statusRightEdgeX - repayResultRemainingSummaryWidth / 2 - 5
    }

    private var targetBillAmountBeforeRepayment: Decimal? {
        guard repayBillMode == .current else {
            return nil
        }
        let normalizedRepayAmount = max(.zero, repayAmount)
        if let optimisticRemainingOutstandingAmount {
            return max(.zero, optimisticRemainingOutstandingAmount) + normalizedRepayAmount
        }
        let normalizedRemainingText = remainingOutstandingAmountText.trimmingCharacters(in: .whitespacesAndNewlines)
        if normalizedRemainingText != "--",
           let remainingAmount = Decimal(string: normalizedRemainingText, locale: Locale(identifier: "en_US_POSIX")) {
            return max(.zero, remainingAmount) + normalizedRepayAmount
        }
        if let currentBillDetail {
            return max(.zero, currentBillDetail.dueAmount.amount) + normalizedRepayAmount
        }
        return nil
    }

    private var shouldShowRemainingSummaryLine: Bool {
        let normalized = remainingOutstandingAmountText.trimmingCharacters(in: .whitespacesAndNewlines)
        return !isLoadingRemainingOutstandingAmount
            && normalized != "--"
            && !hasClearedTargetBill
    }

    private var remainingRepaymentSummaryText: String {
        let normalized = remainingOutstandingAmountText.trimmingCharacters(in: .whitespacesAndNewlines)
        guard normalized != "--" else {
            return "剩余--元"
        }
        return "剩余\(normalized)元"
    }

    private var repaySuccessSubtitleText: String {
        let remaining = remainingOutstandingAmountText == "--" ? "--" : remainingOutstandingAmountText
        return "本月剩余应还\(remaining)元"
    }

    private var billRemainingHeaderText: String {
        let remaining = remainingOutstandingAmountText == "--" ? "--" : remainingOutstandingAmountText
        return "剩余应还\(remaining)元"
    }

    private var billRemainingDetailText: String {
        let remaining = remainingOutstandingAmountText == "--" ? "--" : remainingOutstandingAmountText
        return "剩余\(remaining)元"
    }

    private var paymentMethodDisplayText: String {
        let normalized = paymentMethodText.trimmingCharacters(in: .whitespacesAndNewlines)
        return normalized.isEmpty ? "支付方式" : normalized
    }

    private var hasRemainingOutstandingAmount: Bool {
        let normalized = remainingOutstandingAmountText.trimmingCharacters(in: .whitespacesAndNewlines)
        guard normalized != "--",
              let remaining = Decimal(string: normalized, locale: Locale(identifier: "en_US_POSIX")) else {
            return false
        }
        return remaining > Decimal.zero
    }

    private var shouldShowContinueRepay: Bool {
        guard case .succeeded = resultState else {
            return false
        }
        return !isLoadingRemainingOutstandingAmount && hasRemainingOutstandingAmount
    }

    private func failureDescriptionText(message: String) -> String {
        let normalized = message.trimmingCharacters(in: .whitespacesAndNewlines)
        if !normalized.isEmpty {
            return normalized
        }
        return "\(paymentMethodDisplayText)还款暂未完成，请稍后重试"
    }

    private func formatAmount(_ amount: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = false
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSDecimalNumber(decimal: amount)) ?? "0.00"
    }

    private func overlayText(
        _ text: String,
        centerX: CGFloat,
        centerY: CGFloat,
        width: CGFloat,
        scaleX: CGFloat,
        scaleY: CGFloat,
        font: Font,
        textColor: Color,
        alignment: Alignment = .center,
        lineLimit: Int = 1
    ) -> some View {
        Text(text)
            .font(font)
            .foregroundStyle(textColor)
            .lineLimit(lineLimit)
            .minimumScaleFactor(0.72)
            .multilineTextAlignment(.center)
            .frame(width: width * scaleX, alignment: alignment)
            .position(x: centerX * scaleX, y: centerY * scaleY)
    }

    @MainActor
    private func refreshRemainingOutstandingAmount() async {
        guard case .succeeded = resultState else {
            isLoadingRemainingOutstandingAmount = false
            remainingOutstandingAmountText = "--"
            return
        }
        isLoadingRemainingOutstandingAmount = true
        defer {
            isLoadingRemainingOutstandingAmount = false
        }
        await loadRemainingOutstandingAmount()
    }

    @MainActor
    private func loadRemainingOutstandingAmount() async {
        guard let userId, userId > 0 else {
            remainingOutstandingAmountText = "--"
            currentBillDetail = nil
            return
        }

        let optimisticTargetRemainingAmount = optimisticRemainingOutstandingAmount.map { max(.zero, $0) }
        let remainingTolerance = NSDecimalNumber(string: "0.01").decimalValue
        let maxAttempts = optimisticTargetRemainingAmount == nil ? 12 : 24
        var latestBillDetail: CreditCurrentBillDetailData?
        for attempt in 1...maxAttempts {
            if Task.isCancelled {
                return
            }
            do {
                let billDetail = try await fetchRepayResultTargetBillDetail(userId: userId)
                latestBillDetail = billDetail
                let serverRemainingAmount = max(billDetail.dueAmount.amount, .zero)
                if serverRemainingAmount <= .zero {
                    break
                }
                if let optimisticTargetRemainingAmount,
                   serverRemainingAmount <= optimisticTargetRemainingAmount + remainingTolerance {
                    break
                }
            } catch {
                if attempt == maxAttempts {
                    break
                }
            }
            if attempt < maxAttempts {
                try? await Task.sleep(nanoseconds: 600_000_000)
            }
        }

        guard let latestBillDetail else {
            if let optimisticTargetRemainingAmount {
                remainingOutstandingAmountText = formatAmount(optimisticTargetRemainingAmount)
            } else {
                remainingOutstandingAmountText = "--"
            }
            currentBillDetail = nil
            return
        }

        let serverRemainingAmount = max(latestBillDetail.dueAmount.amount, .zero)
        let displayRemainingAmount = resolvedDisplayRemainingAmount(serverRemainingAmount)
        remainingOutstandingAmountText = formatAmount(displayRemainingAmount)
        currentBillDetail = latestBillDetail
    }

    private func fetchRepayResultTargetBillDetail(userId: Int64) async throws -> CreditCurrentBillDetailData {
        switch repayBillMode {
        case .current:
            return try await APIClient.shared.fetchCreditCurrentBillDetail(userId: userId)
        case .next:
            return try await APIClient.shared.fetchCreditNextBillDetail(userId: userId)
        }
    }

    private func resolvedDisplayRemainingAmount(_ serverRemainingAmount: Decimal) -> Decimal {
        let normalizedServerRemainingAmount = max(.zero, serverRemainingAmount)
        guard let optimisticRemainingOutstandingAmount else {
            return normalizedServerRemainingAmount
        }
        let normalizedOptimisticRemainingAmount = max(.zero, optimisticRemainingOutstandingAmount)
        if normalizedServerRemainingAmount <= normalizedOptimisticRemainingAmount {
            return normalizedServerRemainingAmount
        }
        return normalizedOptimisticRemainingAmount
    }

    private func hotspot(
        identifier: String,
        centerX: CGFloat,
        centerY: CGFloat,
        width: CGFloat,
        height: CGFloat,
        isDisabled: Bool = false,
        action: @escaping () -> Void
    ) -> some View {
        Button(action: action) {
            Color.clear
                .frame(width: width, height: height)
                .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
        .disabled(isDisabled)
        .accessibilityIdentifier(identifier)
        .position(x: centerX, y: centerY)
    }
    }

struct AiPayReceiveCodePayload {
    let qrPayload: String
}

struct AiPayResolvedReceiveCode {
    let userId: Int64
    let timeWindow: Int64
    let qrPayload: String
}

enum AiPayReceiveCodeFactory {
    private static let allowedWindowDriftMinutes: Int64 = 10

    static func makePayload(userId: Int64?, now: Date = Date()) -> AiPayReceiveCodePayload {
        let resolvedUserId = max(userId ?? 0, 0)
        let timeWindow = currentTimeWindow(for: now)
        let compactUserId = base36String(for: resolvedUserId)
        let compactWindow = base36String(for: timeWindow)
        let signature = signature(userId: resolvedUserId, timeWindow: timeWindow)
        let qrPayload = ["AR1", compactUserId, compactWindow, signature].joined(separator: "|")
        return AiPayReceiveCodePayload(qrPayload: qrPayload)
    }

    static func isAiPayPersonalPayload(_ raw: String) -> Bool {
        raw.trimmingCharacters(in: .whitespacesAndNewlines).uppercased().hasPrefix("AR1|")
    }

    static func resolvePayload(_ raw: String, now: Date = Date()) -> AiPayResolvedReceiveCode? {
        let trimmed = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        let parts = trimmed.split(separator: "|", omittingEmptySubsequences: false).map(String.init)
        guard parts.count == 4, parts[0].uppercased() == "AR1" else {
            return nil
        }
        guard let userId = base36Value(from: parts[1]), userId > 0,
              let timeWindow = base36Value(from: parts[2]) else {
            return nil
        }
        guard signature(userId: userId, timeWindow: timeWindow) == parts[3].uppercased() else {
            return nil
        }
        let currentWindow = currentTimeWindow(for: now)
        guard abs(currentWindow - timeWindow) <= allowedWindowDriftMinutes else {
            return nil
        }
        return AiPayResolvedReceiveCode(userId: userId, timeWindow: timeWindow, qrPayload: trimmed)
    }

    private static func base36String(for value: Int64) -> String {
        let charset = Array("0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ")
        if value <= 0 {
            return "0"
        }
        var workingValue = value
        var characters: [Character] = []
        while workingValue > 0 {
            characters.append(charset[Int(workingValue % 36)])
            workingValue /= 36
        }
        return String(characters.reversed())
    }

    private static func base36Value(from text: String) -> Int64? {
        let normalized = text.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        guard !normalized.isEmpty else {
            return nil
        }
        var result: Int64 = 0
        for character in normalized {
            guard let scalar = character.unicodeScalars.first else {
                return nil
            }
            let value: Int64
            switch scalar.value {
            case 48...57:
                value = Int64(scalar.value - 48)
            case 65...90:
                value = Int64(scalar.value - 55)
            default:
                return nil
            }
            result = result * 36 + value
        }
        return result
    }

    private static func currentTimeWindow(for date: Date) -> Int64 {
        Int64(date.timeIntervalSince1970) / 60
    }

    private static func signature(userId: Int64, timeWindow: Int64) -> String {
        let signatureSeed = "AIPAY|RECEIVE_CODE|\(userId)|\(timeWindow)"
        let digestHex = SHA256.hash(data: Data(signatureSeed.utf8)).map { String(format: "%02x", $0) }.joined()
        return String(digestHex.prefix(12)).uppercased()
    }
}

private struct ReceiveCodeCenterAvatarView: View {
    let avatarImage: UIImage?
    let avatarUrl: String?
    let avatarAssetName: String?
    let avatarText: String
    let avatarColor: Color
    let size: CGFloat

    var body: some View {
        Group {
            if let avatarImage {
                Image(uiImage: avatarImage)
                    .resizable()
                    .aspectRatio(contentMode: .fill)
            } else if let resolvedAssetName = avatarAssetName?.trimmingCharacters(in: .whitespacesAndNewlines),
               !resolvedAssetName.isEmpty,
               UIImage(named: resolvedAssetName) != nil {
                Image(resolvedAssetName)
                    .resizable()
                    .aspectRatio(contentMode: .fill)
            } else if let resolvedAssetName = demoAvatarAssetName(for: avatarUrl),
                      UIImage(named: resolvedAssetName) != nil {
                Image(resolvedAssetName)
                    .resizable()
                    .aspectRatio(contentMode: .fill)
            } else if let raw = avatarUrl?.trimmingCharacters(in: .whitespacesAndNewlines),
                      !raw.isEmpty,
                      let url = URL(string: raw) {
                AvatarRemoteImage(url: url) { image in
                    image
                        .resizable()
                        .aspectRatio(contentMode: .fill)
                } placeholder: {
                    fallbackAvatar
                }
            } else {
                fallbackAvatar
            }
        }
        .frame(width: size, height: size)
        .clipShape(RoundedRectangle(cornerRadius: max(10, size * 0.22), style: .continuous))
    }

    private var fallbackAvatar: some View {
        RoundedRectangle(cornerRadius: max(10, size * 0.22), style: .continuous)
            .fill(avatarColor)
            .overlay(
                Text(avatarText)
                    .font(.system(size: max(14, size * 0.36), weight: .bold))
                    .foregroundStyle(.white)
            )
    }
}

