                    .foregroundStyle(Color(red: 166.0 / 255.0, green: 166.0 / 255.0, blue: 170.0 / 255.0))
                    .lineLimit(1)
                    .minimumScaleFactor(0.85)
                    .frame(maxWidth: .infinity)

                Spacer(minLength: 0)
            }
            .padding(.horizontal, 40)
            .padding(.vertical, 44)
        }
        .frame(width: 360, height: 460)
    }
}

