    private func redPacketRecipientOverlay(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        let displayText: String
        if let selectedRecipient {
            displayText = selectedRecipient.listDisplayName
        } else {
            displayText = isRecipientEditable ? "选择好友 >" : "选择好友"
        }
        let textColor = selectedRecipient == nil
            ? Color(red: 0.63, green: 0.64, blue: 0.66)
            : Color(red: 0.46, green: 0.47, blue: 0.49)

        return Text(displayText)
            .font(yaHeiRegularFont(size: 17 * fontScale))
            .foregroundStyle(textColor)
            .lineLimit(1)
            .minimumScaleFactor(0.72)
            .frame(width: 118 * scaleX, height: 24 * scaleY, alignment: .trailing)
    }

    private func amountInputOverlay(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        ZStack(alignment: .trailing) {
            if amountText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty && !isAmountFieldFocused {
                Text("0.00")
                    .font(.system(size: 15 * fontScale, weight: .regular))
                    .foregroundStyle(Color(red: 0.66, green: 0.67, blue: 0.69))
                    .allowsHitTesting(false)
            }

            VerticallyCenteredTextField(
                text: $amountText,
                isFocused: $isAmountFieldFocused,
                font: UIFont.systemFont(ofSize: 15 * fontScale, weight: .regular),
                textColor: UIColor(red: 0.29, green: 0.30, blue: 0.31, alpha: 1),
                tintColor: AppTheme.palette.brandPrimaryUIColor,
                keyboardType: .decimalPad,
                returnKeyType: .done,
                textAlignment: .right,
                textInsets: UIEdgeInsets(top: 0, left: 0, bottom: 0, right: 8 * scaleX)
            )
            .frame(width: 50 * scaleX, height: 24 * scaleY)
            .accessibilityIdentifier("red_packet_amount_input")
        }
        .frame(width: 50 * scaleX, height: 28 * scaleY)
        .contentShape(Rectangle())
        .onTapGesture {
            isBlessingFieldFocused = false
            isAmountFieldFocused = true
        }
        .onChange(of: amountText) { oldValue, newValue in
            let sanitized = sanitizeAmountInput(newValue)
            if let amount = Decimal(string: sanitized, locale: Locale(identifier: "en_US_POSIX")),
               amount > maxRedPacketAmount {
                validationMessage = "单个红包最多10000元"
                if amountText != oldValue {
                    amountText = oldValue
                }
                return
            }
            if sanitized != newValue {
                amountText = sanitized
            }
        }
    }

    private func blessingInputOverlay(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        ZStack(alignment: .leading) {
            if blessingText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty && !isBlessingFieldFocused {
                Text(defaultRedPacketBlessingText)
                    .font(yaHeiRegularFont(size: 15 * fontScale))
                    .foregroundStyle(Color(red: 0.66, green: 0.67, blue: 0.69))
                    .allowsHitTesting(false)
            }

            VerticallyCenteredTextField(
                text: $blessingText,
                isFocused: $isBlessingFieldFocused,
                font: UIFont.systemFont(ofSize: 15 * fontScale, weight: .regular),
                textColor: UIColor(red: 0.29, green: 0.30, blue: 0.31, alpha: 1),
                tintColor: AppTheme.palette.brandPrimaryUIColor,
                keyboardType: .default,
                returnKeyType: .done,
                textAlignment: .left
            )
            .frame(width: 132 * scaleX, height: 24 * scaleY)
            .accessibilityIdentifier("red_packet_blessing_input")
        }
        .frame(width: 132 * scaleX, height: 28 * scaleY, alignment: .leading)
        .contentShape(Rectangle())
        .onTapGesture {
            isAmountFieldFocused = false
            isBlessingFieldFocused = true
        }
    }

    private func redPacketCoverThumbnailOverlay(scaleX: CGFloat, scaleY: CGFloat) -> some View {
        RedPacketGeneratedCoverCardView(
            option: selectedCover,
            isSelected: false,
            compact: true,
            fontScale: min(scaleX, scaleY)
        )
        .frame(width: 35 * scaleX, height: 43 * scaleY)
    }

    private func totalAmountOverlay(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        (
            Text("¥")
                .font(.system(size: 24 * fontScale, weight: .semibold))
            + Text(displayTotalAmountDigitsText)
                .font(.system(size: 29 * fontScale, weight: .semibold))
        )
        .foregroundStyle(Color(red: 0.23, green: 0.23, blue: 0.24))
        .minimumScaleFactor(0.65)
        .lineLimit(1)
        .frame(width: 184 * scaleX, height: 52 * scaleY)
    }

    private func sanitizeAmountInput(_ raw: String) -> String {
        var result = ""
        var hasDecimalSeparator = false
        var fractionDigits = 0

        for character in raw {
            if character.isWholeNumber {
                if hasDecimalSeparator {
                    guard fractionDigits < 2 else {
                        continue
                    }
                    fractionDigits += 1
                }
                if result == "0" && !hasDecimalSeparator {
                    result = String(character)
                } else {
                    result.append(character)
                }
                continue
            }

            if character == "." {
                guard !hasDecimalSeparator else {
                    continue
                }
                hasDecimalSeparator = true
                if result.isEmpty {
                    result = "0"
                }
                result.append(character)
            }
        }

        return result
    }

    private func handleSendTap() {
        guard selectedRecipient != nil else {
            validationMessage = isRecipientEditable ? "请先选择发给谁" : "请选择领取人"
            return
        }

        let normalized = amountText
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .replacingOccurrences(of: ",", with: "")

        guard !normalized.isEmpty,
              let amount = Decimal(string: normalized, locale: Locale(identifier: "en_US_POSIX")),
              amount > .zero else {
            validationMessage = "请先填写红包金额"
            return
        }

        if amount > maxRedPacketAmount {
            validationMessage = "单个红包最多10000元"
            return
        }
        onSend()
    }
}

