                }
                .frame(width: 328 * scaleX)
                .padding(.top, 6 * scaleY)

                Text("\(selectedDirection.summaryPrefix)\(totalCountText)个红包，共")
                    .font(yaHeiRegularFont(size: 13.8 * fontScale))
                    .foregroundStyle(Color(red: 0.46, green: 0.45, blue: 0.43))
                    .frame(maxWidth: .infinity)

                HStack(alignment: .firstTextBaseline, spacing: 0) {
                    Text(totalAmountText)
                        .font(.system(size: 35 * fontScale, weight: .semibold))
                        .foregroundStyle(Color(red: 0.22, green: 0.22, blue: 0.23))
                    Text("元")
                        .font(yaHeiRegularFont(size: 18 * fontScale))
                        .foregroundStyle(Color(red: 0.22, green: 0.22, blue: 0.23))
                }
                .minimumScaleFactor(0.6)
                .lineLimit(1)

                Spacer(minLength: 0)
            }
            .frame(width: 344 * scaleX, height: 126 * scaleY)
        }
        .frame(width: baseWidth * scaleX, height: 136 * scaleY)
    }

    private func listPanel(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        ZStack {
            Rectangle()
                .fill(panelBackgroundColor)

            if isLoading {
                AILoadingIndicator(text: "正在加载红包记录", textFontSize: 12.5 * fontScale)
            } else if let loadErrorMessage,
                      !loadErrorMessage.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty,
                      items.isEmpty {
                VStack(spacing: 12 * scaleY) {
                    Text(loadErrorMessage)
                        .font(yaHeiRegularFont(size: 13.5 * fontScale))
                        .foregroundStyle(Color(red: 0.52, green: 0.52, blue: 0.54))
                        .multilineTextAlignment(.center)
                    Button(action: {
                        Task { await onRetry() }
                    }) {
                        Text("重新加载")
                            .font(yaHeiRegularFont(size: 13.5 * fontScale))
                            .foregroundStyle(Color(red: 0.95, green: 0.34, blue: 0.24))
                    }
                    .buttonStyle(.plain)
                }
                .frame(width: 320 * scaleX)
            } else if items.isEmpty {
                Text("暂无红包记录")
                    .font(yaHeiRegularFont(size: 13.5 * fontScale))
                    .foregroundStyle(Color(red: 0.52, green: 0.52, blue: 0.54))
            } else {
                ScrollView(showsIndicators: false) {
                    LazyVStack(spacing: 12 * scaleY) {
                        ForEach(items) { item in
                            historyRow(item: item, scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                        }
                        Color.clear.frame(height: 20 * scaleY)
                    }
                    .padding(.top, 12 * scaleY)
                    .padding(.horizontal, 12 * scaleX)
                }
            }
        }
        .frame(width: baseWidth * scaleX, height: 572 * scaleY)
    }

    private func historyRow(item: RedPacketHistoryItemData,
                            scaleX: CGFloat,
                            scaleY: CGFloat,
                            fontScale: CGFloat) -> some View {
        HStack(spacing: 12 * scaleX) {
            RoundedRectangle(cornerRadius: 11 * fontScale, style: .continuous)
                .fill(
                    LinearGradient(
                        colors: [
                            Color(red: 0.98, green: 0.41, blue: 0.31),
                            Color(red: 0.96, green: 0.29, blue: 0.23)
                        ],
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    )
                )
                .frame(width: 40 * scaleX, height: 40 * scaleY)
                .overlay(
                    Text("普")
                        .font(yaHeiRegularFont(size: 17 * fontScale))
                        .foregroundStyle(.white)
                )

            VStack(alignment: .leading, spacing: 5 * scaleY) {
                Text("普通红包")
                    .font(yaHeiRegularFont(size: 15.5 * fontScale))
                    .foregroundStyle(Color(red: 0.16, green: 0.16, blue: 0.17))
                Text("1个红包  \(Self.formatHistoryDate(item.createdAt))")
                    .font(yaHeiRegularFont(size: 12.5 * fontScale))
                    .foregroundStyle(Color(red: 0.59, green: 0.58, blue: 0.56))
            }

            Spacer(minLength: 8 * scaleX)

            VStack(alignment: .trailing, spacing: 5 * scaleY) {
                Text(Self.formatAmountDigits(item.amount) + "元")
                    .font(.system(size: 15.5 * fontScale, weight: .regular))
                    .foregroundStyle(Color(red: 0.25, green: 0.25, blue: 0.26))
                Text(Self.statusText(for: item, direction: selectedDirection))
                    .font(yaHeiRegularFont(size: 12.5 * fontScale))
                    .foregroundStyle(Color(red: 0.58, green: 0.58, blue: 0.60))
            }
        }
        .padding(.horizontal, 14 * scaleX)
        .frame(width: 356 * scaleX, height: 82 * scaleY)
        .background(cardBackgroundColor)
        .clipShape(RoundedRectangle(cornerRadius: 18 * fontScale, style: .continuous))
        .overlay(
            RoundedRectangle(cornerRadius: 18 * fontScale, style: .continuous)
                .stroke(dividerColor, lineWidth: max(0.8, 1 * fontScale))
        )
    }

    private static func statusText(for item: RedPacketHistoryItemData, direction: RedPacketHistoryDirection) -> String {
        let normalized = item.messageStatus.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        if normalized == "SENT" || normalized.isEmpty {
            return direction == .sent ? "已发出" : "已收到"
        }
        if normalized == "FAILED" { return "失败" }
        if normalized == "PROCESSING" { return "处理中" }
        return item.messageStatus
    }

    private static func formatAmountDigits(_ amount: MessageAmountData?) -> String {
        guard let amount = amount?.amount else { return "0.00" }
        let number = NSDecimalNumber(decimal: amount)
        return String(format: "%.2f", number.doubleValue)
    }

    private static func formatHistoryDate(_ raw: String?) -> String {
        guard let date = parseDate(raw) else { return "" }
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "zh_CN")
        formatter.timeZone = TimeZone.current
        if Calendar.current.isDateInToday(date) {
            formatter.dateFormat = "HH:mm"
            return "今天 " + formatter.string(from: date)
        }
        formatter.dateFormat = "MM-dd"
        return formatter.string(from: date)
    }

    private static func parseDate(_ raw: String?) -> Date? {
        guard let raw = raw?.trimmingCharacters(in: .whitespacesAndNewlines), !raw.isEmpty else {
            return nil
        }
        let parser = DateFormatter()
        parser.locale = Locale(identifier: "en_US_POSIX")
        parser.timeZone = TimeZone.current
        for format in ["yyyy-MM-dd'T'HH:mm:ss.SSSSSS", "yyyy-MM-dd'T'HH:mm:ss.SSS", "yyyy-MM-dd'T'HH:mm:ss"] {
            parser.dateFormat = format
            if let date = parser.date(from: raw) {
                return date
            }
        }
        return nil
    }
}

private struct RedPacketCashierReferenceView: View {
    let payerUserId: Int64?
    let selectedRecipient: TransferRecentContact?
    let isRecipientEditable: Bool
    let selectedCover: RedPacketCoverOption
    let amountText: String
    let blessingText: String
    let amount: Decimal
    let onClose: () -> Void
    let onConfirmPay: @MainActor (MessageData) async -> Void

    @State private var isPaymentToolsExpanded = false
    @State private var selectedPaymentMethodType: RepayPaymentMethodType = .wallet
    @State private var payTools: [CashierPayToolData] = []
    @State private var selectedBankToolCode: String?
    @State private var walletAvailableAmountText: String = "--"
    @State private var fundAvailableAmountText: String = "--"
    @State private var isLoadingWalletBalance = false
    @State private var isLoadingFundBalance = false
    @State private var isLoadingPayTools = false
    @State private var isSubmittingPayment = false
    @State private var payToolsErrorMessage: String?
    @State private var submitErrorMessage: String?
    @State private var hasFundAvailable = false
    @State private var sceneConfiguration: CashierSceneConfiguration = CashierChannelAvailability.filteredSceneConfiguration(
        .redPacketSend,
        hasFundAvailable: false,
        hasAiCreditAvailable: false
    )

    private let baseWidth: CGFloat = 402
    private let baseHeight: CGFloat = 874
    private let sheetChromeTopY: CGFloat = 262
    private let paymentToolsCardBackgroundColor = Color(red: 247 / 255, green: 248 / 255, blue: 249 / 255)
    private let paymentToolsDividerColor = Color(red: 239 / 255, green: 241 / 255, blue: 244 / 255)
    private let paymentToolsBottomMaskColor = Color(red: 247 / 255, green: 248 / 255, blue: 249 / 255)
    private let serviceHintMaskColor = Color.white
    private let titleTextColor = Color(red: 0.18, green: 0.19, blue: 0.20)
    private let selectedColor = AppTheme.palette.brandPrimary

    init(
        payerUserId: Int64?,
        selectedRecipient: TransferRecentContact?,
        isRecipientEditable: Bool,
        selectedCover: RedPacketCoverOption,
        amountText: String,
        blessingText: String,
        amount: Decimal,
        onClose: @escaping () -> Void,
        onConfirmPay: @escaping @MainActor (MessageData) async -> Void
    ) {
        self.payerUserId = payerUserId
        self.selectedRecipient = selectedRecipient
        self.isRecipientEditable = isRecipientEditable
        self.selectedCover = selectedCover
        self.amountText = amountText
        self.blessingText = blessingText
        self.amount = amount
        self.onClose = onClose
        self.onConfirmPay = onConfirmPay
    }

    var body: some View {
        GeometryReader { proxy in
            let scaleX = proxy.size.width / baseWidth
            let scaleY = proxy.size.height / baseHeight
            let fontScale = min(scaleX, scaleY)

            ZStack {
                cashierBackdrop()
                    .frame(width: proxy.size.width, height: proxy.size.height)

                cashierSheetChrome(scaleX: scaleX, scaleY: scaleY)

                dynamicOverlay(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                serviceHintMaskOverlay(scaleX: scaleX, scaleY: scaleY)

                if !isPaymentToolsExpanded {
                    Button(action: onClose) {
                        Color.clear
                            .frame(width: 64 * scaleX, height: 44 * scaleY)
                            .contentShape(Rectangle())
                    }
                    .buttonStyle(.plain)
                    .accessibilityIdentifier("red_packet_cashier_close")
                    .position(x: 30 * scaleX, y: 287 * scaleY)

                    Button(action: {
                        selectedPaymentMethodType = .wallet
                    }) {
                        Color.clear
                            .frame(width: 344 * scaleX, height: 48 * scaleY)
                            .contentShape(Rectangle())
                    }
                    .buttonStyle(.plain)
                    .accessibilityIdentifier("red_packet_cashier_select_wallet")
                    .position(x: 201 * scaleX, y: 503 * scaleY)

                    if sceneConfiguration.supports(.fund) {
                        Button(action: {
                            selectedPaymentMethodType = .fund
                        }) {
                            Color.clear
                                .frame(width: 344 * scaleX, height: 48 * scaleY)
                                .contentShape(Rectangle())
                        }
                        .buttonStyle(.plain)
                        .accessibilityIdentifier("red_packet_cashier_select_fund")
                        .position(x: 201 * scaleX, y: 548 * scaleY)
                    }

                    Button(action: {
                        if displayedBankTool != nil {
                            selectedPaymentMethodType = .bankCard
                        } else {
                            isPaymentToolsExpanded = true
                        }
                    }) {
                        Color.clear
                            .frame(width: 344 * scaleX, height: 48 * scaleY)
                            .contentShape(Rectangle())
                    }
                    .buttonStyle(.plain)
                    .accessibilityIdentifier("red_packet_cashier_select_bank")
                    .position(x: 201 * scaleX, y: collapsedBankRowCenterY * scaleY)

                    Button(action: {
                        isPaymentToolsExpanded = true
                    }) {
                        Color.clear
                            .frame(width: 140 * scaleX, height: 36 * scaleY)
                            .contentShape(Rectangle())
                    }
                    .buttonStyle(.plain)
                    .accessibilityIdentifier("red_packet_cashier_expand_payment_tools")
                    .position(x: 201 * scaleX, y: collapsedExpandButtonCenterY * scaleY)

                    Button(action: {
                        Task {
                            await submitPayment()
                        }
                    }) {
                        Color.clear
                            .frame(width: 362 * scaleX, height: 58 * scaleY)
                            .contentShape(Rectangle())
                    }
                    .buttonStyle(.plain)
                    .disabled(isSubmittingPayment)
                    .accessibilityIdentifier("red_packet_cashier_confirm")
                    .position(x: 201 * scaleX, y: 778 * scaleY)
                }

                if isPaymentToolsExpanded {
                    RepayPaymentToolPickerSheetView(
                        scaleX: scaleX,
                        scaleY: scaleY,
                        fontScale: fontScale,
                        accessibilityPrefix: "red_packet_cashier",
                        backdropOpacity: 0,
                        dividerColor: paymentToolsDividerColor,
                        sheetHeight: 440,
                        sceneConfiguration: sceneConfiguration,
                        bankTools: payTools,
                        selectedBankToolCode: selectedBankToolCode,
                        selectedPaymentMethodType: selectedPaymentMethodType,
                        walletAvailableAmountText: walletAvailableAmountText,
                        fundAvailableAmountText: fundAvailableAmountText,
                        isLoadingWalletBalance: isLoadingWalletBalance,
                        isLoadingFundBalance: isLoadingFundBalance,
                        isLoadingBankTools: isLoadingPayTools,
                        bankToolsErrorMessage: payToolsErrorMessage,
                        onClose: {
                            isPaymentToolsExpanded = false
                        },
                        onSelectWallet: {
                            selectedPaymentMethodType = .wallet
                            isPaymentToolsExpanded = false
                        },
                        onSelectFund: {
                            selectedPaymentMethodType = .fund
                            isPaymentToolsExpanded = false
                        },
                        onSelectAiCredit: {},
                        onSelectBankTool: { toolCode in
                            selectedPaymentMethodType = .bankCard
                            selectedBankToolCode = toolCode
                            isPaymentToolsExpanded = false
                        }
                    )
                    .zIndex(20)
                }

                if isSubmittingPayment {
                    AILoadingIndicator(
                        text: "正在包红包",
                        accentColor: Color(red: 0.95, green: 0.34, blue: 0.24),
                        secondaryAccentColor: Color(red: 0.98, green: 0.64, blue: 0.20),
                        textColor: Color(red: 0.23, green: 0.24, blue: 0.27)
                    )
                    .padding(.horizontal, 22)
                    .padding(.vertical, 16)
                    .background(.ultraThinMaterial, in: RoundedRectangle(cornerRadius: 14, style: .continuous))
                    .zIndex(30)
                }
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .ignoresSafeArea()
        .task(id: payerUserId) {
            await refreshCashierData()
        }
        .alert("支付失败", isPresented: Binding(
            get: { submitErrorMessage != nil },
            set: { if !$0 { submitErrorMessage = nil } }
        )) {
            Button("知道了", role: .cancel) {
                submitErrorMessage = nil
            }
        } message: {
            Text(submitErrorMessage ?? "")
        }
    }

