    private var collapsedPaymentToolsCardHeight: CGFloat {
        // 保持覆盖层高度与参考卡片一致，避免底图残留出第二个无效箭头行。
        173
    }

    private var collapsedPaymentToolsCardCenterY: CGFloat {
        566.5
    }

    private var collapsedPaymentToolsDividerOffsets: [CGFloat] {
        hasCollapsedFundRow ? [44, 90, 137] : [44, 90]
    }

    private var collapsedChevronOffsetY: CGFloat {
        hasCollapsedFundRow ? 156 : 111
    }

    private func formatAmountFixed2(_ amount: Decimal) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .decimal
        formatter.usesGroupingSeparator = false
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSDecimalNumber(decimal: amount)) ?? "0.00"
    }

    private func formattedCurrency(_ amount: Decimal?) -> String {
        guard let amount else {
            return "--"
        }
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "zh_CN")
        formatter.numberStyle = .currency
        formatter.currencySymbol = "¥"
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSDecimalNumber(decimal: amount)) ?? "¥0.00"
    }

    private func formattedCurrency(amountText: String?) -> String {
        guard let amountText else {
            return "--"
        }
        let normalized = amountText
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .replacingOccurrences(of: ",", with: "")
        if normalized.isEmpty {
            return "¥0.00"
        }
        guard let amount = Decimal(string: normalized, locale: Locale(identifier: "en_US_POSIX")) else {
            return "--"
        }
        return formattedCurrency(amount)
    }

    @MainActor
    private func refreshCashierData() async {
        guard let payerUserId, payerUserId > 0 else {
            payTools = []
            selectedBankToolCode = nil
            walletAvailableAmountText = "--"
            fundAvailableAmountText = "--"
            hasFundAvailable = false
            sceneConfiguration = CashierChannelAvailability.filteredSceneConfiguration(
                .redPacketSend,
                hasFundAvailable: false,
                hasAiCreditAvailable: false
            )
            payToolsErrorMessage = "未找到当前登录用户"
            selectedPaymentMethodType = .wallet
            return
        }

        isLoadingWalletBalance = true
        isLoadingFundBalance = true
        isLoadingPayTools = true
        payToolsErrorMessage = nil

        let walletOverview = try? await APIClient.shared.fetchAssetOverview(userId: String(payerUserId))
        let fundAccount = try? await APIClient.shared.fetchFundAccount(userId: payerUserId)

        walletAvailableAmountText = formattedCurrency(amountText: walletOverview?.availableAmount)
        hasFundAvailable = CashierChannelAvailability.isFundAccountAvailable(fundAccount)
        fundAvailableAmountText = hasFundAvailable ? formattedCurrency(fundAccount?.holdingAmount) : "--"
        sceneConfiguration = CashierChannelAvailability.filteredSceneConfiguration(
            .redPacketSend,
            hasFundAvailable: hasFundAvailable,
            hasAiCreditAvailable: false
        )

        let debitTools: [CashierPayToolData]
        do {
            let cashierView = try await APIClient.shared.fetchCashierView(userId: payerUserId, sceneCode: "PAY")
            debitTools = CashierPresentationHelper.filteredBankTools(
                cashierView.payTools,
                policy: sceneConfiguration.bankCardPolicy
            )
        } catch {
            debitTools = []
            payToolsErrorMessage = "银行卡加载失败，请重试"
        }
        payTools = debitTools
        if let selectedBankToolCode,
           debitTools.contains(where: { $0.toolCode == selectedBankToolCode }) {
            // keep current selection
        } else {
            selectedBankToolCode = debitTools.first(where: \.defaultSelected)?.toolCode ?? debitTools.first?.toolCode
        }

        if debitTools.isEmpty, payToolsErrorMessage == nil {
            payToolsErrorMessage = sceneConfiguration.emptyBankCardText
            if selectedPaymentMethodType == .bankCard {
                selectedPaymentMethodType = .wallet
            }
        }

        if selectedPaymentMethodType == .bankCard && selectedBankToolCode == nil {
            selectedPaymentMethodType = .wallet
        }
        if selectedPaymentMethodType == .fund && !sceneConfiguration.supports(.fund) {
            selectedPaymentMethodType = .wallet
        }

        isLoadingWalletBalance = false
        isLoadingFundBalance = false
        isLoadingPayTools = false
    }

    @MainActor
    private func submitPayment() async {
        guard !isSubmittingPayment else {
            return
        }
        guard let payerUserId, payerUserId > 0 else {
            submitErrorMessage = "未找到当前登录用户，请重新登录"
            return
        }
        guard let selectedRecipient else {
            submitErrorMessage = "请选择领取人"
            return
        }
        guard amount > .zero else {
            submitErrorMessage = "红包金额必须大于0"
            return
        }
        guard amount <= maxRedPacketAmount else {
            submitErrorMessage = "单个红包最多10000元"
            return
        }
        if selectedPaymentMethodType == .bankCard && displayedBankTool == nil {
            submitErrorMessage = "请选择银行卡"
            return
        }

        isSubmittingPayment = true
        submitErrorMessage = nil
        let submitStartedAt = Date()
        defer {
            isSubmittingPayment = false
        }

        do {
            let message = try await APIClient.shared.sendRedPacketMessage(
                senderUserId: payerUserId,
                receiverUserId: selectedRecipient.payeeUserId,
                amount: amount,
                paymentMethod: selectedPaymentMethodRequestCode,
                extPayload: buildRedPacketExtPayload()
            )
            let minimumPromptDuration: TimeInterval = 0.45
            let elapsed = Date().timeIntervalSince(submitStartedAt)
            if elapsed < minimumPromptDuration {
                try? await Task.sleep(nanoseconds: UInt64((minimumPromptDuration - elapsed) * 1_000_000_000))
            }
            await onConfirmPay(message)
        } catch {
            submitErrorMessage = userFacingErrorMessage(error)
        }
    }

    private func buildRedPacketExtPayload() -> String? {
        var payload: [String: Any] = [
            "source": "ios-red-packet",
            "coverId": selectedCover.id,
            "coverTitle": selectedCover.title,
            "blessingText": effectiveBlessingText
        ]
        guard let data = try? JSONSerialization.data(withJSONObject: payload, options: []) else {
            return nil
        }
        return String(data: data, encoding: .utf8)
    }

    private func yaHeiRegularFont(size: CGFloat) -> Font {
        let candidates = [
            "MicrosoftYaHei",
            "Microsoft YaHei",
            "MicrosoftYaHei-Light",
            "MicrosoftYaHeiUI",
            "Microsoft YaHei UI",
            "微软雅黑",
            "PingFangSC-Regular"
        ]
        for name in candidates where UIFont(name: name, size: size) != nil {
            return .custom(name, size: size)
        }
        return .system(size: size, weight: .regular)
    }
}

private struct RedPacketPackedReferenceView: View {
    let selectedCover: RedPacketCoverOption
    let recipientDisplayName: String
    let onBack: () -> Void
    let onClose: () -> Void
    let onShareToFriend: () -> Void

    @State private var toastMessage: String?

    private let baseWidth: CGFloat = 402
    private let baseHeight: CGFloat = 874
    private let posterWidth: CGFloat = 309
    private let posterHeight: CGFloat = 501.33

    var body: some View {
        GeometryReader { proxy in
            let scaleX = proxy.size.width / baseWidth
            let scaleY = proxy.size.height / baseHeight
            let fontScale = min(scaleX, scaleY)

            ZStack {
                Image("RedPacketPackedReference")
                    .resizable()
                    .interpolation(.high)
                    .aspectRatio(contentMode: .fill)
                    .frame(width: baseWidth * scaleX, height: baseHeight * scaleY)
                    .clipped()

                RedPacketPackedPosterView(
                    option: selectedCover,
                    fontScale: fontScale
                )
                .frame(width: posterWidth * scaleX, height: posterHeight * scaleY)
                .position(x: 201 * scaleX, y: 482.83 * scaleY)

                if !recipientDisplayName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                    Text(recipientDisplayName)
                        .font(.system(size: 17 * fontScale, weight: .semibold))
                        .foregroundStyle(Color.white)
                        .lineLimit(1)
                        .minimumScaleFactor(0.62)
                        .frame(width: 96 * scaleX, height: 24 * scaleY, alignment: .trailing)
                        .position(x: 322 * scaleX, y: 209 * scaleY)
                        .allowsHitTesting(false)
                }

                Button(action: onBack) {
                    Color.clear
                        .frame(width: 48 * scaleX, height: 44 * scaleY)
                        .contentShape(Rectangle())
                }
                .buttonStyle(.plain)
                .accessibilityIdentifier("red_packet_packed_back")
                .position(x: 22 * scaleX, y: 68 * scaleY)

                Button(action: onClose) {
                    Color.clear
                        .frame(width: 40 * scaleX, height: 36 * scaleY)
                        .contentShape(Rectangle())
                }
                .buttonStyle(.plain)
                .accessibilityIdentifier("red_packet_packed_close")
                .position(x: 377 * scaleX, y: 67 * scaleY)

                Button(action: downloadPoster) {
                    Color.clear
                        .frame(width: 186 * scaleX, height: 56 * scaleY)
                        .contentShape(Rectangle())
                }
                .buttonStyle(.plain)
                .accessibilityIdentifier("red_packet_packed_save")
                .position(x: 201 * scaleX, y: 823.33 * scaleY)

                if let toastMessage {
                    toastView(text: toastMessage)
                        .position(x: 201 * scaleX, y: 760 * scaleY)
                        .transition(.opacity)
                        .zIndex(10)
                }
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .ignoresSafeArea()
    }

    @MainActor
    private func downloadPoster() {
        let status = PHPhotoLibrary.authorizationStatus(for: .addOnly)
        switch status {
        case .authorized, .limited:
            saveRenderedPoster()
        case .notDetermined:
            PHPhotoLibrary.requestAuthorization(for: .addOnly) { authorizationStatus in
                Task { @MainActor in
                    switch authorizationStatus {
                    case .authorized, .limited:
                        saveRenderedPoster()
                    default:
                        showToast("未获得相册权限")
                    }
                }
            }
        default:
            showToast("未获得相册权限")
        }
    }

    @MainActor
    private func saveRenderedPoster() {
        guard let rendered = renderPosterImage() else {
            showToast("生成海报失败")
            return
        }
        guard let imageData = rendered.pngData() else {
            showToast("生成海报失败")
            return
        }

        PHPhotoLibrary.shared().performChanges({
            let creationRequest = PHAssetCreationRequest.forAsset()
            creationRequest.addResource(with: .photo, data: imageData, options: nil)
        }) { success, _ in
            Task { @MainActor in
                showToast(success ? "海报已保存" : "保存失败，请稍后重试")
            }
        }
    }

    @MainActor
    private func renderPosterImage() -> UIImage? {
        let renderer = ImageRenderer(
            content: RedPacketPackedPosterView(
                option: selectedCover,
                fontScale: 1
            )
            .frame(width: posterWidth, height: posterHeight)
        )
        renderer.scale = UIScreen.main.scale
        return renderer.uiImage
    }

    private func showToast(_ message: String) {
        withAnimation(.easeInOut(duration: 0.18)) {
            toastMessage = message
        }
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.6) {
            guard toastMessage == message else {
                return
            }
            withAnimation(.easeInOut(duration: 0.18)) {
                toastMessage = nil
            }
        }
    }

    private func toastView(text: String) -> some View {
        Text(text)
            .font(.system(size: 13, weight: .medium))
            .foregroundStyle(.white)
            .padding(.horizontal, 14)
            .padding(.vertical, 9)
            .background(Color.black.opacity(0.72))
            .clipShape(Capsule())
    }
}

private struct RedPacketPackedPosterView: View {
    let option: RedPacketCoverOption
    let fontScale: CGFloat

    private var qrPayload: String {
        ["AHB1", option.id, option.title, option.expiryText].joined(separator: "|")
    }

    var body: some View {
        GeometryReader { proxy in
            let size = proxy.size
            let cornerRadius = 10 * fontScale
            let footerHeight = size.height * (132.33 / 501.33)
            let artworkHeight = size.height - footerHeight
            let qrCardSize = min(size.width * 0.38, 117.33 * fontScale)
            let qrSize = min(size.width * 0.34, 103.67 * fontScale)
            let qrCenterY = size.height * (375.83 / 501.33)
            let qrImage = AiPayCodeImageRenderer.makeQRCodeImage(
                payload: qrPayload,
                targetSize: CGSize(width: 240, height: 240)
            )

            ZStack(alignment: .top) {
                RoundedRectangle(cornerRadius: cornerRadius, style: .continuous)
                    .fill(Color(red: 0.98, green: 0.95, blue: 0.90))

                VStack(spacing: 0) {
                    RedPacketGeneratedCoverArtworkView(
                        option: option,
                        compact: false,
                        fontScale: fontScale * 0.9
                    )
                    .frame(height: artworkHeight)
                    .clipped()

                    Rectangle()
                        .fill(Color(red: 0.96, green: 0.31, blue: 0.25))
                        .frame(height: footerHeight)
                }
                .clipShape(
                    RoundedRectangle(cornerRadius: cornerRadius, style: .continuous)
                )

                Ellipse()
                    .fill(Color(red: 0.99, green: 0.86, blue: 0.64).opacity(0.85))
                    .frame(width: size.width * 0.95, height: size.width * 0.18)
                    .offset(y: artworkHeight - size.width * 0.09)

                if let qrImage {
                    RoundedRectangle(cornerRadius: 7 * fontScale, style: .continuous)
                        .fill(Color.white)
                        .frame(width: qrCardSize, height: qrCardSize)
                        .position(x: size.width / 2, y: qrCenterY)

                    Image(uiImage: qrImage)
                        .resizable()
                        .interpolation(.none)
                        .scaledToFit()
                        .frame(width: qrSize, height: qrSize)
                        .position(x: size.width / 2, y: qrCenterY)
                }

                Text("爱付扫码 开红包")
                    .font(.system(size: 12.5 * fontScale, weight: .medium))
                    .foregroundStyle(Color.white)
                    .position(x: size.width / 2, y: size.height - 37 * fontScale)
            }
            .clipShape(RoundedRectangle(cornerRadius: cornerRadius, style: .continuous))
        }
        .allowsHitTesting(false)
    }
}

private struct ConversationRedPacketOpenView: View {
    let detail: RedPacketDetailData
    let currentUserId: Int64
    let coverOption: RedPacketCoverOption
    let isClaiming: Bool
    let onClose: () -> Void
    let onOpen: () -> Void

    private var isReceiver: Bool {
        detail.receiverUserId == currentUserId
    }

    private var presenterName: String {
        isReceiver ? detail.senderNickname : detail.receiverNickname
    }

    private var avatarURL: String? {
        isReceiver ? detail.senderAvatarUrl : detail.receiverAvatarUrl
    }

    private var statusText: String {
        switch detail.status.uppercased() {
        case "CLAIMED":
            return isReceiver ? "红包已存入余额" : "对方已领取"
        case "PENDING_CLAIM":
            return isReceiver ? "点击下方按钮领取红包" : "等待对方领取"
        default:
            return "红包当前不可领取"
        }
    }

    private var amountText: String {
        let amount = detail.amount?.amount ?? .zero
        return "¥" + String(format: "%.2f", NSDecimalNumber(decimal: amount).doubleValue)
    }

    private var statusTextOffsetY: CGFloat {
        if detail.status.uppercased() == "PENDING_CLAIM", isReceiver {
            return 3
        }
        return 0
    }

    private var shouldShowClaimedConfirmButton: Bool {
        detail.status.uppercased() == "CLAIMED" && isReceiver
    }

    private var claimedContentOffsetY: CGFloat {
        detail.status.uppercased() == "CLAIMED" ? 25 : 0
    }

    var body: some View {
        ZStack {
            LinearGradient(
                colors: [
                    Color(red: 0.78, green: 0.10, blue: 0.12),
                    Color(red: 0.92, green: 0.22, blue: 0.17),
                    Color(red: 0.98, green: 0.44, blue: 0.18)
                ],
                startPoint: .topLeading,
                endPoint: .bottomTrailing
            )
            .ignoresSafeArea()

            VStack(spacing: 0) {
                HStack {
                    Spacer(minLength: 0)
                    Button(action: onClose) {
                        Image(systemName: "xmark")
                            .font(.system(size: 17, weight: .semibold))
                            .foregroundStyle(Color.white.opacity(0.92))
                            .frame(width: 40, height: 40)
                    }
                    .buttonStyle(.plain)
                }
                .padding(.horizontal, 14)
                .padding(.top, 56)

                Spacer(minLength: 22)

                VStack(spacing: 16) {
                    ContactAvatarView(
                        avatarUrl: avatarURL,
                        avatarAssetName: nil,
                        avatarText: String(presenterName.prefix(1)),
                        avatarColor: Color(red: 0.97, green: 0.73, blue: 0.31),
                        size: 58
                    )

                    VStack(spacing: 6) {
                        Text("\(presenterName)的红包")
                            .font(.system(size: 25, weight: .semibold))
                            .foregroundStyle(Color.white)
                        if let blessingText = detail.blessingText?.trimmingCharacters(in: .whitespacesAndNewlines),
                           !blessingText.isEmpty {
                            Text(blessingText)
                                .font(.system(size: 16, weight: .regular))
                                .foregroundStyle(Color.white.opacity(0.9))
                                .multilineTextAlignment(.center)
                                .padding(.horizontal, 24)
                        }
                    }
                }

                Spacer(minLength: 26)

                ZStack(alignment: .bottom) {
                    RoundedRectangle(cornerRadius: 24, style: .continuous)
                        .fill(Color(red: 0.95, green: 0.18, blue: 0.16))
                        .frame(width: 314, height: 432)
                        .shadow(color: Color.black.opacity(0.15), radius: 22, x: 0, y: 10)

                    VStack(spacing: 0) {
                        RedPacketGeneratedCoverArtworkView(
                            option: coverOption,
                            compact: false,
                            fontScale: 0.92
                        )
                        .frame(width: 282, height: 244)
                        .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
                        .padding(.top, 18)

                        Spacer(minLength: 0)
                    }
                    .frame(width: 314, height: 432, alignment: .top)

                    VStack(spacing: 16) {
                        if detail.status.uppercased() == "CLAIMED" {
                            Text(amountText)
                                .font(.system(size: 34, weight: .bold))
                                .foregroundStyle(Color(red: 0.40, green: 0.11, blue: 0.07))
                                .offset(y: claimedContentOffsetY)
                            Text(statusText)
                                .font(.system(size: 15, weight: .regular))
                                .foregroundStyle(Color(red: 0.50, green: 0.24, blue: 0.16))
                                .offset(y: statusTextOffsetY + claimedContentOffsetY)
                        } else {
                            Text(statusText)
                                .font(.system(size: 15, weight: .regular))
                                .foregroundStyle(Color(red: 0.50, green: 0.24, blue: 0.16))
                                .offset(y: statusTextOffsetY)
                        }

                        if shouldShowClaimedConfirmButton {
                            Button(action: onClose) {
                                Text("确认")
                                    .font(.system(size: 18, weight: .semibold))
                                    .foregroundStyle(Color(red: 0.41, green: 0.15, blue: 0.10))
                                    .frame(width: 178, height: 44)
                                    .background(
                                        RoundedRectangle(cornerRadius: 22, style: .continuous)
                                            .fill(Color(red: 0.99, green: 0.84, blue: 0.62))
                                    )
                            }
                            .buttonStyle(.plain)
                            .offset(y: claimedContentOffsetY)
                        }

                        if detail.claimableByViewer {
                            Button(action: onOpen) {
                                ZStack {
                                    Circle()
                                        .fill(Color(red: 0.98, green: 0.76, blue: 0.22))
                                        .frame(width: 96, height: 96)
                                    Text(isClaiming ? "..." : "開")
                                        .font(.system(size: 42, weight: .bold))
                                        .foregroundStyle(Color(red: 0.33, green: 0.15, blue: 0.08))
                                }
                            }
                            .buttonStyle(.plain)
                            .disabled(isClaiming)
                        }
                    }
                    .padding(.bottom, detail.claimableByViewer ? 42 : 58)
                    .frame(width: 314)
                }

                Spacer(minLength: 48)
            }
        }
    }
}

