private enum RedPacketCoverArtworkLayout {
    case meadow
    case wealth
    case starlight
    case garden
    case celebration
    case voyage
}

private struct RedPacketCoverOption: Identifiable, Equatable {
    let id: String
    let title: String
    let expiryText: String
    let badgeText: String?
    let artworkHeadline: String
    let artworkSubtitle: String
    let primaryColors: [Color]
    let accentColor: Color
    let footerColor: Color
    let artworkTextColor: Color
    let secondaryTextColor: Color
    let mainSymbolName: String
