            secondarySymbolName: "gift.fill",
            layout: .celebration
        )
    ]

    static let defaultOption = options[0]

    static func option(for id: String?) -> RedPacketCoverOption {
        guard let normalizedId = id?.trimmingCharacters(in: .whitespacesAndNewlines),
              !normalizedId.isEmpty,
              let matched = options.first(where: { $0.id == normalizedId }) else {
            return defaultOption
        }
        return matched
    }
}

private struct RedPacketGeneratedCoverCardView: View {
    let option: RedPacketCoverOption
    let isSelected: Bool
    let compact: Bool
    let fontScale: CGFloat

    var body: some View {
        GeometryReader { proxy in
            let size = proxy.size
            let cornerRadius = compact ? 6 * fontScale : 12 * fontScale
            let footerHeight = compact ? size.height * 0.27 : size.height * 0.35
            let artworkHeight = max(size.height - footerHeight, size.height * 0.55)

            ZStack(alignment: .topLeading) {
                RoundedRectangle(cornerRadius: cornerRadius, style: .continuous)
                    .fill(Color.white)

                VStack(spacing: 0) {
                    RedPacketGeneratedCoverArtworkView(option: option, compact: compact, fontScale: fontScale)
                        .frame(height: artworkHeight)

                    footerView(width: size.width, height: footerHeight)
                }

                if let badgeText = option.badgeText, !compact {
                    Text(badgeText)
                        .font(.system(size: 11 * fontScale, weight: .semibold))
                        .foregroundStyle(Color(red: 0.71, green: 0.34, blue: 0.11))
                        .padding(.horizontal, 8 * fontScale)
                        .padding(.vertical, 4 * fontScale)
                        .background(
                            Capsule(style: .continuous)
                                .fill(Color(red: 0.98, green: 0.92, blue: 0.72))
                        )
                        .padding(.top, 8 * fontScale)
                        .padding(.leading, 8 * fontScale)
                }
            }
            .clipShape(RoundedRectangle(cornerRadius: cornerRadius, style: .continuous))
            .overlay(
                RoundedRectangle(cornerRadius: cornerRadius, style: .continuous)
                    .stroke(
                        isSelected && !compact
                            ? AppTheme.palette.brandPrimary
                            : Color.black.opacity(compact ? 0.04 : 0.06),
                        lineWidth: isSelected && !compact ? 2 * fontScale : max(1, 0.8 * fontScale)
                    )
            )
            .shadow(color: Color.black.opacity(compact ? 0.0 : 0.06), radius: compact ? 0 : 10 * fontScale, x: 0, y: compact ? 0 : 4 * fontScale)
        }
    }

    private func footerView(width: CGFloat, height: CGFloat) -> some View {
        ZStack(alignment: .top) {
            Rectangle()
                .fill(option.footerColor)

            VStack(spacing: compact ? 3 * fontScale : 6 * fontScale) {
                Capsule(style: .continuous)
                    .fill(Color.white)
                    .frame(width: compact ? width * 0.34 : width * 0.36, height: compact ? height * 0.18 : height * 0.16)
                    .overlay(
                        Text(isSelected && !compact ? "已选" : "使用")
                            .font(.system(size: compact ? 6.5 * fontScale : 14 * fontScale, weight: .semibold))
                            .foregroundStyle(isSelected && !compact ? AppTheme.palette.brandPrimary : Color(red: 0.36, green: 0.17, blue: 0.12))
                    )
                    .padding(.top, compact ? 4 * fontScale : 7 * fontScale)

                if !compact {
                    Text(option.title)
                        .font(.system(size: 18 * fontScale, weight: .bold))
                        .foregroundStyle(Color.white)
                        .lineLimit(1)
                        .minimumScaleFactor(0.78)

                    Text(option.expiryText)
                        .font(.system(size: 12 * fontScale, weight: .medium))
                        .foregroundStyle(Color.white.opacity(0.84))
                        .lineLimit(1)
                        .minimumScaleFactor(0.84)
                }
            }
            .padding(.horizontal, 10 * fontScale)
            .frame(width: width, height: height, alignment: .top)
        }
    }
}

private struct RedPacketGeneratedCoverArtworkView: View {
    let option: RedPacketCoverOption
    let compact: Bool
    let fontScale: CGFloat

    var body: some View {
        GeometryReader { proxy in
            let width = proxy.size.width
            let height = proxy.size.height

            ZStack {
                LinearGradient(
                    colors: option.primaryColors,
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )

                Circle()
                    .fill(option.accentColor.opacity(0.30))
                    .frame(width: width * 0.74, height: width * 0.74)
                    .blur(radius: compact ? 0 : 10 * fontScale)
                    .offset(x: -width * 0.20, y: height * 0.18)

                Circle()
                    .fill(Color.white.opacity(0.13))
                    .frame(width: width * 0.36, height: width * 0.36)
                    .offset(x: width * 0.24, y: -height * 0.18)

                artworkDecorations(width: width, height: height)

                VStack(alignment: .leading, spacing: compact ? 2 * fontScale : 5 * fontScale) {
                    Text(option.artworkHeadline)
                        .font(.system(size: compact ? 5.5 * fontScale : 24 * fontScale, weight: .bold, design: .rounded))
                        .foregroundStyle(option.artworkTextColor)
                        .lineSpacing(compact ? 0 : 2 * fontScale)
                        .minimumScaleFactor(0.65)

                    if !compact {
                        Text(option.artworkSubtitle)
                            .font(.system(size: 11 * fontScale, weight: .medium))
                            .foregroundStyle(option.secondaryTextColor)
                            .lineLimit(1)
                    }
                }
                .padding(.horizontal, compact ? 4 * fontScale : 14 * fontScale)
                .padding(.bottom, compact ? 4 * fontScale : 12 * fontScale)
                .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .bottomLeading)
            }
            .clipped()
        }
    }

    @ViewBuilder
    private func artworkDecorations(width: CGFloat, height: CGFloat) -> some View {
        switch option.layout {
        case .meadow:
            Ellipse()
                .fill(Color.white.opacity(0.22))
                .frame(width: width * 1.08, height: height * 0.24)
                .offset(y: height * 0.30)

            Ellipse()
                .fill(option.accentColor.opacity(0.55))
                .frame(width: width * 0.92, height: height * 0.22)
                .offset(x: -width * 0.10, y: height * 0.36)

            Image(systemName: option.mainSymbolName)
                .font(.system(size: compact ? width * 0.14 : width * 0.18, weight: .semibold))
                .foregroundStyle(Color.white.opacity(0.92))
                .offset(x: width * 0.26, y: height * 0.12)

            sparkleCluster(width: width, height: height)

        case .wealth:
            Image(systemName: option.mainSymbolName)
                .font(.system(size: compact ? width * 0.34 : width * 0.40, weight: .black))
                .foregroundStyle(option.accentColor.opacity(0.95))
                .offset(x: -width * 0.04, y: height * 0.04)

            ForEach(0..<4, id: \.self) { index in
                Circle()
                    .fill(Color.white.opacity(0.22))
                    .frame(width: width * 0.14, height: width * 0.14)
                    .overlay(
                        Image(systemName: option.secondarySymbolName)
                            .font(.system(size: width * 0.05, weight: .bold))
                            .foregroundStyle(option.accentColor.opacity(0.92))
                    )
                    .offset(
                        x: [-width * 0.26, width * 0.24, width * 0.18, -width * 0.10][index],
                        y: [-height * 0.10, -height * 0.18, height * 0.18, height * 0.28][index]
                    )
            }

        case .starlight:
            ForEach(0..<8, id: \.self) { index in
                Circle()
                    .fill(Color.white.opacity(index.isMultiple(of: 2) ? 0.32 : 0.18))
                    .frame(width: width * 0.03, height: width * 0.03)
                    .offset(
                        x: [-width * 0.34, -width * 0.12, width * 0.08, width * 0.28, -width * 0.22, width * 0.17, width * 0.31, -width * 0.04][index],
                        y: [-height * 0.28, -height * 0.12, -height * 0.22, -height * 0.08, height * 0.04, height * 0.18, height * 0.28, height * 0.10][index]
                    )
            }

            Image(systemName: option.mainSymbolName)
                .font(.system(size: compact ? width * 0.22 : width * 0.26, weight: .regular))
                .foregroundStyle(option.accentColor)
                .offset(x: -width * 0.20, y: height * 0.08)

            Image(systemName: option.secondarySymbolName)
                .font(.system(size: compact ? width * 0.14 : width * 0.16, weight: .semibold))
                .foregroundStyle(Color.white.opacity(0.94))
                .offset(x: width * 0.22, y: -height * 0.08)

        case .garden:
            Circle()
                .fill(option.accentColor.opacity(0.58))
                .frame(width: width * 0.34, height: width * 0.34)
                .offset(x: width * 0.20, y: -height * 0.16)

            RoundedRectangle(cornerRadius: 22 * fontScale, style: .continuous)
                .fill(Color.white.opacity(0.18))
                .frame(width: width * 0.80, height: height * 0.14)
                .offset(y: height * 0.20)

            Image(systemName: option.mainSymbolName)
                .font(.system(size: compact ? width * 0.20 : width * 0.24, weight: .semibold))
                .foregroundStyle(Color.white.opacity(0.86))
                .offset(x: width * 0.18, y: height * 0.18)

            Image(systemName: option.secondarySymbolName)
                .font(.system(size: compact ? width * 0.14 : width * 0.18, weight: .regular))
                .foregroundStyle(option.accentColor)
                .offset(x: width * 0.02, y: -height * 0.10)

        case .celebration:
            ForEach(0..<7, id: \.self) { index in
                RoundedRectangle(cornerRadius: 5 * fontScale, style: .continuous)
                    .fill(index.isMultiple(of: 2) ? Color.white.opacity(0.22) : option.accentColor.opacity(0.65))
                    .frame(width: width * 0.08, height: height * 0.03)
                    .rotationEffect(.degrees(Double(index * 24)))
                    .offset(
                        x: [-width * 0.30, -width * 0.10, width * 0.18, width * 0.32, -width * 0.24, width * 0.04, width * 0.22][index],
                        y: [-height * 0.12, -height * 0.26, -height * 0.14, 0, height * 0.16, height * 0.22, height * 0.30][index]
                    )
            }

            Image(systemName: option.mainSymbolName)
                .font(.system(size: compact ? width * 0.24 : width * 0.28, weight: .black))
                .foregroundStyle(Color.white.opacity(0.92))
                .offset(x: 0, y: height * 0.08)

        case .voyage:
            Capsule(style: .continuous)
                .fill(Color.white.opacity(0.20))
                .frame(width: width * 0.74, height: height * 0.10)
                .rotationEffect(.degrees(-18))
                .offset(x: -width * 0.08, y: height * 0.08)

            Capsule(style: .continuous)
                .fill(option.accentColor.opacity(0.48))
                .frame(width: width * 0.52, height: height * 0.08)
                .rotationEffect(.degrees(22))
                .offset(x: width * 0.12, y: -height * 0.10)

            Image(systemName: option.mainSymbolName)
                .font(.system(size: compact ? width * 0.22 : width * 0.26, weight: .semibold))
                .foregroundStyle(Color.white.opacity(0.94))
                .offset(x: width * 0.10, y: height * 0.03)

            Image(systemName: option.secondarySymbolName)
                .font(.system(size: compact ? width * 0.15 : width * 0.17, weight: .medium))
                .foregroundStyle(option.accentColor)
                .offset(x: -width * 0.22, y: height * 0.16)
        }
    }

    private func sparkleCluster(width: CGFloat, height: CGFloat) -> some View {
        ZStack {
            ForEach(0..<4, id: \.self) { index in
                Image(systemName: option.secondarySymbolName)
                    .font(.system(size: compact ? width * 0.07 : width * 0.08, weight: .semibold))
                    .foregroundStyle(Color.white.opacity(index.isMultiple(of: 2) ? 0.72 : 0.38))
                    .offset(
                        x: [-width * 0.18, width * 0.04, width * 0.22, -width * 0.02][index],
                        y: [-height * 0.14, -height * 0.24, -height * 0.04, height * 0.08][index]
                    )
            }
        }
    }
}

private struct RedPacketCoverSelectionReferenceView: View {
    let selectedCover: RedPacketCoverOption
    let onBack: () -> Void
    let onClose: () -> Void
    let onSelectCover: (RedPacketCoverOption) -> Void

    private let baseWidth: CGFloat = 402
    private let baseHeight: CGFloat = 874
    private let coverPanelTop: CGFloat = 132

    var body: some View {
        GeometryReader { proxy in
            let scaleX = proxy.size.width / baseWidth
            let scaleY = proxy.size.height / baseHeight
            let fontScale = min(scaleX, scaleY)

            ZStack {
                Image("RedPacketCoverSelectionReference")
                    .resizable()
                    .interpolation(.high)
                    .aspectRatio(contentMode: .fill)
                    .frame(width: baseWidth * scaleX, height: baseHeight * scaleY)
                    .clipped()

                coverPanel(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                    .frame(width: baseWidth * scaleX, height: (baseHeight - coverPanelTop) * scaleY)
                    .position(
                        x: (baseWidth / 2) * scaleX,
                        y: (coverPanelTop + (baseHeight - coverPanelTop) / 2) * scaleY
                    )

                Button(action: onBack) {
                    Color.clear
                        .frame(width: 48 * scaleX, height: 44 * scaleY)
                        .contentShape(Rectangle())
                }
                .buttonStyle(.plain)
                .accessibilityIdentifier("red_packet_cover_back")
                .position(x: 20 * scaleX, y: 67 * scaleY)

                Button(action: {}) {
                    Color.clear
                        .frame(width: 36 * scaleX, height: 36 * scaleY)
                        .contentShape(Rectangle())
                }
                .buttonStyle(.plain)
                .accessibilityIdentifier("red_packet_cover_more")
                .position(x: 338 * scaleX, y: 67 * scaleY)

                Button(action: onClose) {
                    Color.clear
                        .frame(width: 36 * scaleX, height: 36 * scaleY)
                        .contentShape(Rectangle())
                }
                .buttonStyle(.plain)
                .accessibilityIdentifier("red_packet_cover_close")
                .position(x: 376 * scaleX, y: 67 * scaleY)
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .ignoresSafeArea()
    }

    private func coverPanel(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        let columns = [
            GridItem(.flexible(), spacing: 12 * scaleX),
            GridItem(.flexible(), spacing: 12 * scaleX)
        ]

        return ZStack(alignment: .topLeading) {
            Rectangle()
                .fill(Color(red: 245.0 / 255.0, green: 245.0 / 255.0, blue: 245.0 / 255.0))

            ScrollView(showsIndicators: false) {
                LazyVGrid(columns: columns, spacing: 14 * scaleY) {
                    ForEach(RedPacketCoverOption.options) { option in
                        Button(action: {
                            onSelectCover(option)
                        }) {
                            RedPacketGeneratedCoverCardView(
                                option: option,
                                isSelected: option == selectedCover,
                                compact: false,
                                fontScale: fontScale
                            )
                            .aspectRatio(183 / 294, contentMode: .fit)
                        }
                        .buttonStyle(.plain)
                        .accessibilityIdentifier("red_packet_cover_option_\(option.id)")
                    }
                }
                .padding(.top, 0)
                .padding(.bottom, 30 * scaleY)
            }
            .padding(.horizontal, 8 * scaleX)
        }
    }
}

private struct RedPacketRecipientSelectionReferenceView: View {
    let contacts: [TransferRecentContact]
    let selectedRecipient: TransferRecentContact?
    let isLoading: Bool
    let loadErrorMessage: String?
    let hasMoreContacts: Bool
    let onBack: () -> Void
    let onLoadMore: @MainActor () async -> Void
    let onEnsureContactsLoaded: @MainActor () async -> Void
    let onSelect: (TransferRecentContact) -> Void
    let onConfirm: () -> Void

    @State private var searchKeyword = ""
    @State private var isSearchFieldFocused = false
    @State private var isTriggeringLoadMore = false
    @State private var hasRequestedInitialLoad = false

    private let baseWidth: CGFloat = 402
    private let baseHeight: CGFloat = 874
    private let listWidth: CGFloat = 332
    private let listHeight: CGFloat = 520
    private let rowHeight: CGFloat = 66

    private var normalizedSearchKeyword: String {
        searchKeyword.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private var filteredContacts: [TransferRecentContact] {
        let ordered = contacts.sorted { lhs, rhs in
            let lhsDate = lhs.lastInteractionAt ?? ""
            let rhsDate = rhs.lastInteractionAt ?? ""
            if lhsDate != rhsDate {
                return lhsDate > rhsDate
            }
            if lhs.interactionCount != rhs.interactionCount {
                return lhs.interactionCount > rhs.interactionCount
            }
            return lhs.payeeUserId < rhs.payeeUserId
        }
        guard !normalizedSearchKeyword.isEmpty else {
            return ordered
        }
        return ordered.filter { contact in
            let haystacks = [contact.displayName, contact.listDisplayName, contact.accountHint]
            return haystacks.contains { $0.localizedCaseInsensitiveContains(normalizedSearchKeyword) }
        }
    }

    private var shouldShowLoadingState: Bool {
        if !filteredContacts.isEmpty {
            return false
        }
        if isLoading {
            return true
        }
        return !hasRequestedInitialLoad && normalizedSearchKeyword.isEmpty && loadErrorMessage == nil
    }

    private var emptyStateText: String {
        if !normalizedSearchKeyword.isEmpty {
            return "未找到相关联系人"
        }
        return loadErrorMessage ?? "暂无好友"
    }

    var body: some View {
        GeometryReader { proxy in
            let scaleX = proxy.size.width / baseWidth
            let scaleY = proxy.size.height / baseHeight
            let fontScale = min(scaleX, scaleY)

            ZStack {
                Image("RedPacketRecipientSelectionReference")
                    .resizable()
                    .interpolation(.high)
                    .aspectRatio(contentMode: .fill)
                    .frame(width: baseWidth * scaleX, height: baseHeight * scaleY)
                    .clipped()

                sheetHeader(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                    .zIndex(9)

                searchBar(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                    .position(x: 201 * scaleX, y: 259 * scaleY)
                    .accessibilityIdentifier("red_packet_recipient_search_focus")

                contactList(scaleX: scaleX, scaleY: scaleY, fontScale: fontScale)
                    .frame(width: listWidth * scaleX, height: listHeight * scaleY)
                    .position(x: 197 * scaleX, y: 542 * scaleY)

                Button(action: onBack) {
                    Color.clear
                        .frame(width: 110 * scaleX, height: 44 * scaleY)
                        .contentShape(Rectangle())
                }
                .buttonStyle(.plain)
                .accessibilityIdentifier("red_packet_select_recipient_back")
                .position(x: 48 * scaleX, y: 202 * scaleY)
                .zIndex(10)
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .ignoresSafeArea()
        .task {
            guard !hasRequestedInitialLoad else {
                return
            }
            hasRequestedInitialLoad = true
            await onEnsureContactsLoaded()
        }
    }

    private func sheetHeader(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        ZStack {
            Text("选择领取人")
                .font(.system(size: 17 * fontScale, weight: .semibold))
                .foregroundStyle(Color(red: 0.10, green: 0.10, blue: 0.11))
                .position(x: 197 * scaleX, y: 196 * scaleY)

            HStack(spacing: 2 * scaleX) {
                Image(systemName: "chevron.left")
                    .font(.system(size: 15 * fontScale, weight: .medium))
                    .foregroundStyle(AppTheme.palette.brandPrimary)

                Text("返回")
                    .font(yaHeiRegularFont(size: 17 * fontScale))
                    .foregroundStyle(AppTheme.palette.brandPrimary)
            }
            .position(x: 34 * scaleX, y: 196 * scaleY)
        }
    }

    private func searchBar(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        let hasSearchKeyword = !normalizedSearchKeyword.isEmpty

        return ZStack(alignment: .leading) {
            RoundedRectangle(cornerRadius: 8 * fontScale, style: .continuous)
                .fill(Color.white)
                .overlay(
                    RoundedRectangle(cornerRadius: 8 * fontScale, style: .continuous)
                        .stroke(Color(red: 231 / 255, green: 232 / 255, blue: 235 / 255), lineWidth: max(1, 0.8 * fontScale))
                )

            HStack(spacing: 8 * scaleX) {
                Image(systemName: "magnifyingglass")
                    .font(.system(size: 14 * fontScale, weight: .regular))
                    .foregroundStyle(Color(red: 0.74, green: 0.75, blue: 0.77))

                ZStack(alignment: .leading) {
                    if !hasSearchKeyword && !isSearchFieldFocused {
                        Text("输入手机号/邮箱、联系人姓名发红包")
                            .font(yaHeiRegularFont(size: 14.2 * fontScale))
                            .foregroundStyle(Color(red: 0.75, green: 0.76, blue: 0.78))
                            .lineLimit(1)
                            .allowsHitTesting(false)
                    }

                    VerticallyCenteredTextField(
                        text: $searchKeyword,
                        isFocused: $isSearchFieldFocused,
                        font: UIFont.systemFont(ofSize: 14.2 * fontScale, weight: .regular),
                        textColor: UIColor(red: 0.29, green: 0.30, blue: 0.31, alpha: 1),
                        tintColor: AppTheme.palette.brandPrimaryUIColor
                    )
                    .frame(width: 270 * scaleX, height: 22 * scaleY, alignment: .leading)
                }

                Spacer(minLength: 0)
            }
            .padding(.horizontal, 14 * scaleX)
        }
        .frame(width: 332 * scaleX, height: 34 * scaleY)
        .contentShape(Rectangle())
        .onTapGesture {
            isSearchFieldFocused = true
        }
    }

    private func contactList(scaleX: CGFloat, scaleY: CGFloat, fontScale: CGFloat) -> some View {
        ZStack(alignment: .top) {
            Color.white

            if shouldShowLoadingState {
                VStack(spacing: 10 * scaleY) {
                    ProgressView()
                        .progressViewStyle(.circular)
                        .tint(Color(red: 0.53, green: 0.55, blue: 0.59))
                        .scaleEffect(1.05 * fontScale)

                    Text("加载中")
                        .font(.system(size: 13 * fontScale, weight: .regular))
                        .foregroundStyle(Color(red: 0.64, green: 0.65, blue: 0.68))
                }
                .padding(.top, 28 * scaleY)
                .accessibilityIdentifier("red_packet_recipient_loading")
            } else if filteredContacts.isEmpty {
                Text(emptyStateText)
                    .font(.system(size: 13 * fontScale, weight: .regular))
                    .foregroundStyle(Color(red: 0.64, green: 0.65, blue: 0.68))
                    .padding(.top, 28 * scaleY)
                    .accessibilityIdentifier("red_packet_recipient_empty")
            } else {
                ScrollView(showsIndicators: false) {
                    LazyVStack(spacing: 0) {
                        Color.clear
                            .frame(height: 2 * scaleY)

                        ForEach(Array(filteredContacts.enumerated()), id: \.element.id) { index, contact in
                            Button {
                                onSelect(contact)
                            } label: {
                                contactRow(
                                    contact: contact,
                                    fontScale: fontScale,
                                    showDivider: index < filteredContacts.count - 1
                                )
                                .frame(width: listWidth * scaleX, height: rowHeight * scaleY)
                            }
                            .buttonStyle(.plain)
                            .accessibilityIdentifier("red_packet_recipient_row_\(contact.id)")
                            .onAppear {
                                triggerLoadMoreIfNeeded(index: index)
                            }
                        }

                        if isLoading {
                            HStack(spacing: 8 * scaleX) {
                                ProgressView()
                                    .progressViewStyle(.circular)
                                    .scaleEffect(0.85 * fontScale)
                                    .tint(Color(red: 0.53, green: 0.55, blue: 0.59))

                                Text("加载中")
                                    .font(.system(size: 12.5 * fontScale, weight: .regular))
                                    .foregroundStyle(Color(red: 0.64, green: 0.65, blue: 0.68))
                            }
                            .frame(maxWidth: .infinity)
                            .padding(.vertical, 12 * scaleY)
                            .accessibilityIdentifier("red_packet_recipient_load_more")
                        } else {
                            Color.clear
                                .frame(height: 10 * scaleY)
                        }
                    }
                }
            }
        }
        .clipped()
    }

    private func triggerLoadMoreIfNeeded(index: Int) {
        guard hasMoreContacts else {
            return
        }
        guard !isLoading else {
            return
        }
        guard !isTriggeringLoadMore else {
            return
        }
        guard index >= max(filteredContacts.count - 2, 0) else {
            return
        }

        isTriggeringLoadMore = true
        Task {
            await onLoadMore()
            await MainActor.run {
                isTriggeringLoadMore = false
            }
        }
    }

    private func contactRow(contact: TransferRecentContact, fontScale: CGFloat, showDivider: Bool) -> some View {
        HStack(spacing: 13) {
            ContactAvatarView(
                avatarUrl: contact.avatarUrl,
                avatarAssetName: contact.avatarAssetName,
                avatarText: contact.avatarText,
                avatarColor: contact.avatarColor,
                size: 40
            )

            VStack(alignment: .leading, spacing: 5) {
                Text(contact.listDisplayName)
                    .font(.system(size: 16 * fontScale, weight: .medium))
                    .foregroundStyle(Color(red: 0.15, green: 0.15, blue: 0.16))
                    .lineLimit(1)

                Text(contact.accountHint)
                    .font(.system(size: 12.5 * fontScale, weight: .regular))
                    .foregroundStyle(Color(red: 0.60, green: 0.60, blue: 0.62))
                    .lineLimit(1)
            }

            Spacer(minLength: 0)
        }
        .padding(.horizontal, 14)
        .padding(.vertical, 12)
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .background(Color.white)
        .overlay(alignment: .bottom) {
            if showDivider {
                Rectangle()
                    .fill(Color(red: 0.88, green: 0.90, blue: 0.93))
                    .frame(height: max(1, 0.8 * fontScale))
                    .padding(.leading, 67)
                    .padding(.trailing, 14)
            }
        }
    }
}



